// tarot-interactions.js
// Expanded CARD_INTERACTIONS_MAP: object-based pair lookup
// Key format: "smallerId_largerId" (IDs from DECK array in tarot-example.html)
// Each entry: { vi: "...", en: "..." } — one concise sentence (20-40 words per language)
//
// Card ID ranges:
//   Major Arcana:      0–21
//   Wands Ace–10:     22–31 | Wands Courts: 32–35
//   Cups  Ace–10:     36–45 | Cups  Courts: 46–49
//   Swords Ace–10:    50–59 | Swords Courts: 60–63
//   Pentacles Ace–10: 64–73 | Pentacles Courts: 74–77

const CARD_INTERACTIONS_MAP = {

  // ─── TIER 1: Major × Major (231 pairs) ─────────────────────────────────────
  // Fool (0) pairs
  "0_1":  { vi: "Kẻ Ngốc gặp Pháp Sư: tiềm năng thuần túy gặp ý chí có chủ đích — hãy biến sự hồn nhiên thành hành động có chủ ý trước khi nó tan vào mơ mộng.", en: "The Fool meets the Magician: pure potential encounters focused will — channel your innocence into intentional action before it dissipates into daydream." },
  "0_2":  { vi: "Kẻ Ngốc và Thầy Tư Tế Nữ: bước nhảy được ẩn thức dẫn lối — hãy tin vào điều bạn biết trong chiều sâu trước khi lý trí có thể giải thích nó.", en: "The Fool and The High Priestess: your leap is guided by unseen wisdom — trust what you know in your depths before logic can explain it." },
  "0_3":  { vi: "Kẻ Ngốc và Nữ Hoàng: khởi đầu mới được nuôi dưỡng bởi sự phong phú — để bản năng sáng tạo nảy mầm trong đất màu mỡ của sự kiên nhẫn.", en: "The Fool and The Empress: new beginnings are nurtured by abundance — let your creative instinct take root in the fertile soil of patience." },
  "0_4":  { vi: "Kẻ Ngốc và Hoàng Đế: tự do cần cấu trúc để thành hiện thực — xây dựng khung cho hành trình mà không để nó bóp nghẹt tinh thần phiêu lưu.", en: "The Fool and The Emperor: freedom needs structure to become real — build a framework for your journey without letting it strangle the adventurous spirit." },
  "0_5":  { vi: "Kẻ Ngốc và Giáo Hoàng: con đường mới gặp trí tuệ truyền thống — học từ những gì đã được chứng minh trước khi tự tạo lại bánh xe.", en: "The Fool and The Hierophant: a new path encounters established wisdom — learn from what has been proven before you reinvent every wheel." },
  "0_6":  { vi: "Kẻ Ngốc và Người Yêu Nhau: bước nhảy đặt ra một lựa chọn về trái tim — hành trình này đòi hỏi bạn chọn dựa trên giá trị, không chỉ sự hứng khởi.", en: "The Fool and The Lovers: your leap poses a choice of the heart — the journey you are starting requires choosing from your values, not just your excitement." },
  "0_7":  { vi: "Kẻ Ngốc và Chiến Xa: tinh thần khởi đầu gặp quyết tâm chiến thắng — mang cả sự vô tư lẫn ý chí sắt đá vào thử thách phía trước.", en: "The Fool and The Chariot: beginner's spirit meets conquering will — bring both your innocence and your iron determination to the challenge ahead." },
  "0_8":  { vi: "Kẻ Ngốc và Sức Mạnh: sự táo bạo gặp lòng can đảm nhẹ nhàng — bước nhảy không cần sức mạnh thô; nó cần sự kiên nhẫn và trái tim dũng cảm.", en: "The Fool and Strength: boldness meets gentle courage — your leap doesn't need brute force; it needs patience and a brave heart." },
  "0_9":  { vi: "Kẻ Ngốc và Ẩn Sĩ: hành trình mới bắt đầu bằng việc quay vào bên trong — trước khi bước ra ngoài, hãy dành thời gian thật sự tìm ánh sáng của chính mình.", en: "The Fool and The Hermit: a new journey begins with turning inward — before stepping outward, spend real time finding your own inner light." },
  "0_10": { vi: "Kẻ Ngốc và Bánh Xe Số Phận: bước nhảy gặp điểm xoay của số phận — thời điểm này không phải ngẫu nhiên; bạn đang bước qua đúng cánh cửa của một chu kỳ lớn hơn.", en: "The Fool and The Wheel of Fortune: a leap meets a turning point of fate — this moment is not accidental; you are stepping through the right doorway of a larger cycle." },
  "0_11": { vi: "Kẻ Ngốc và Công Lý: hành động ngây thơ gặp hậu quả cân bằng — hãy bước đi với lương tâm trong sáng, vì những gì bạn gieo sẽ được gặt về.", en: "The Fool and Justice: innocent action meets balanced consequence — step forward with a clear conscience, because what you sow will return to you." },
  "0_12": { vi: "Kẻ Ngốc và Người Treo Ngược: bước nhảy về phía trước gặp sự tạm dừng để nhìn khác đi — đôi khi con đường khôn ngoan nhất là không tiếp tục bằng mọi giá.", en: "The Fool and The Hanged Man: the leap forward meets a pause for new perspective — sometimes the wisest path is not to keep moving at any cost." },
  "0_13": { vi: "Kẻ Ngốc và Thần Chết: khởi đầu và kết thúc là hai mặt của một đồng tiền — hành trình bạn bắt đầu đòi hỏi bạn để lại điều gì đó phía sau.", en: "The Fool and Death: beginning and ending are two faces of the same coin — the journey you are starting requires you to leave something behind." },
  "0_14": { vi: "Kẻ Ngốc và Điều Độ: sự bốc đồng gặp sự kiên nhẫn chảy nhẹ nhàng — hãy mang nhiệt huyết nhưng để thời gian dẫn đường, không phải sự vội vàng.", en: "The Fool and Temperance: impulsive energy meets gently flowing patience — bring enthusiasm but let timing guide you, not urgency." },
  "0_15": { vi: "Kẻ Ngốc và Ác Quỷ: sự ngây thơ gặp cám dỗ và bóng tối — hành trình này đòi hỏi bạn nhận ra cái bẫy trước khi bước vào.", en: "The Fool and The Devil: innocence meets temptation and shadow — this journey asks you to recognise the trap before you step into it." },
  "0_16": { vi: "Kẻ Ngốc và Tháp: khởi đầu mới xuất hiện sau sự đổ vỡ đột ngột — đây là cơ hội bước đi tự do trên nền đất mới.", en: "The Fool and The Tower: a new beginning emerges after sudden collapse — this is the chance to step forward freely on cleared ground." },
  "0_17": { vi: "Kẻ Ngốc và Ngôi Sao: bước nhảy dẫn thẳng đến sự hy vọng và chữa lành — hãy tin rằng con đường bạn đang chọn hướng đến điều tốt hơn.", en: "The Fool and The Star: the leap leads directly toward hope and renewal — trust that the path you are choosing moves toward something better." },
  "0_18": { vi: "Kẻ Ngốc và Mặt Trăng: hành trình ngây thơ vào vùng đất huyền bí và không chắc chắn — hãy tin vào bản năng hơn là con mắt trong bóng tối này.", en: "The Fool and The Moon: an innocent journey into mysterious and uncertain territory — trust instinct over eyesight in this darkness." },
  "0_19": { vi: "Kẻ Ngốc và Mặt Trời: khởi đầu tinh khiết trong ánh sáng rực rỡ nhất — năng lượng này mời bạn bước đi với sự vui mừng và không chút nghi ngờ.", en: "The Fool and The Sun: a pure beginning in the most radiant light — this energy invites you to step forward with joy and without hesitation." },
  "0_20": { vi: "Kẻ Ngốc và Phán Xét: một khởi đầu mới sau lời gọi thức tỉnh — bạn không trở lại như cũ; bạn bước vào phiên bản đã được đánh thức của chính mình.", en: "The Fool and Judgement: a new beginning following the call to awaken — you are not returning to who you were; you are stepping into the awakened version of yourself." },
  "0_21": { vi: "Kẻ Ngốc và Thế Giới: điểm khởi đầu và điểm kết thúc của hành trình vĩ đại — mọi bước nhảy cuối cùng dẫn về đây.", en: "The Fool and The World: the beginning and the completion of the great journey — every leap ultimately leads back to this." },

  // Magician (1) pairs
  "1_2":  { vi: "Pháp Sư và Thầy Tư Tế Nữ: ý chí chủ động gặp trí tuệ thụ nhận — hành động mạnh nhất khi nó bắt nguồn từ chiều sâu của sự im lặng nội tâm.", en: "The Magician and The High Priestess: active will meets receptive wisdom — the most powerful action rises from the depths of inner stillness." },
  "1_3":  { vi: "Pháp Sư và Nữ Hoàng: ý định có chủ đích gặp sự phong phú màu mỡ — hãy trồng hạt giống ý tưởng vào đất tốt và để tự nhiên làm phần còn lại.", en: "The Magician and The Empress: focused intention meets fertile abundance — plant the seed of your idea in good soil and let nature do the rest." },
  "1_4":  { vi: "Pháp Sư và Hoàng Đế: kỹ năng sắc bén gặp thẩm quyền cấu trúc — đây là sự kết hợp của biết cách và có quyền; hãy dùng cả hai một cách có trách nhiệm.", en: "The Magician and The Emperor: sharp skill meets structured authority — this is the combination of knowing how and having the right; use both responsibly." },
  "1_5":  { vi: "Pháp Sư và Giáo Hoàng: năng lực cá nhân gặp trí tuệ truyền thống — hãy học hỏi từ truyền thống nhưng đừng để nó thay thế khả năng tư duy độc lập của bạn.", en: "The Magician and The Hierophant: personal power meets traditional wisdom — learn from the established path but don't let it replace your own discernment." },
  "1_6":  { vi: "Pháp Sư và Người Yêu Nhau: ý chí sáng tạo gặp lựa chọn từ trái tim — kỹ năng của bạn phục vụ tốt nhất khi nó được hướng dẫn bởi điều bạn thực sự yêu.", en: "The Magician and The Lovers: creative will meets a heartfelt choice — your skill serves best when guided by what you genuinely love." },
  "1_7":  { vi: "Pháp Sư và Chiến Xa: kỹ năng có chủ đích gặp quyết tâm không gì cản được — đây là sự kết hợp của biết làm và làm không ngừng.", en: "The Magician and The Chariot: focused skill meets unstoppable determination — this is the combination of knowing what to do and doing it without stopping." },
  "1_8":  { vi: "Pháp Sư và Sức Mạnh: năng lực trí tuệ gặp lòng can đảm thầm lặng — kỹ năng và sự kiên nhẫn cùng nhau tạo ra kết quả mà nỗ lực thô không thể đạt được.", en: "The Magician and Strength: mental mastery meets quiet inner courage — skill and patience together create what brute effort alone cannot." },
  "1_9":  { vi: "Pháp Sư và Ẩn Sĩ: sự biểu hiện tích cực gặp trí tuệ cô đơn — hãy dành thời gian một mình để nạp lại và làm sắc nét những gì bạn đang tạo ra.", en: "The Magician and The Hermit: active manifestation meets solitary wisdom — take time alone to recharge and sharpen what you are creating." },
  "1_10": { vi: "Pháp Sư và Bánh Xe Số Phận: kỹ năng gặp sự xoay vần của số phận — hãy sử dụng tài năng ngay bây giờ, vì cơ hội không chờ đợi lâu.", en: "The Magician and The Wheel of Fortune: skill meets the turning of fate — use your talent now, because opportunity does not wait long." },
  "1_11": { vi: "Pháp Sư và Công Lý: hành động có chủ ý gặp sự cân bằng của hậu quả — hãy sử dụng kỹ năng một cách công bằng, vì kết quả sẽ phản chiếu ngược lại bạn.", en: "The Magician and Justice: intentional action meets the balance of consequence — use your skill fairly, because the outcome will mirror back exactly what you put in." },
  "1_12": { vi: "Pháp Sư và Người Treo Ngược: năng động muốn làm gặp sự cần thiết phải buông — đôi khi sự kiểm soát tốt nhất là biết khi nào không cần kiểm soát.", en: "The Magician and The Hanged Man: the drive to do meets the necessity to release — sometimes the greatest mastery is knowing when not to act." },
  "1_13": { vi: "Pháp Sư và Thần Chết: năng lực sáng tạo gặp sự biến đổi không thể tránh — hãy để những gì cũ tan đi để năng lực của bạn tìm thấy mục đích mới.", en: "The Magician and Death: creative power meets unavoidable transformation — let what is old dissolve so your abilities find a new and truer purpose." },
  "1_14": { vi: "Pháp Sư và Điều Độ: kỹ năng sắc nét cần được điều chỉnh bởi sự kiên nhẫn — hành động nhanh nhưng hãy đảm bảo nhịp độ của bạn bền vững.", en: "The Magician and Temperance: sharp skill needs tempering with patience — act swiftly but ensure your pace is sustainable." },
  "1_15": { vi: "Pháp Sư và Ác Quỷ: năng lực có thể phục vụ hoặc trói buộc — hãy xem xét bạn đang dùng kỹ năng của mình để phục vụ điều gì và cho ai.", en: "The Magician and The Devil: power can serve or entrap — examine honestly what you are using your skill to serve, and for whose benefit." },
  "1_16": { vi: "Pháp Sư và Tháp: kế hoạch và kỹ năng bị phá vỡ bởi điều bất ngờ — hãy thích nghi nhanh chóng; tài năng thực sự thể hiện ở khả năng xoay sở trong hỗn loạn.", en: "The Magician and The Tower: skill and plans disrupted by the unexpected — adapt quickly; true talent shows in the ability to pivot within chaos." },
  "1_17": { vi: "Pháp Sư và Ngôi Sao: ý chí chủ động được soi sáng bởi hy vọng thực sự — hãy hành động với cả năng lực lẫn niềm tin rằng điều tốt đẹp đang đến.", en: "The Magician and The Star: active intention illuminated by genuine hope — act with both skill and the belief that something good is on its way." },
  "1_18": { vi: "Pháp Sư và Mặt Trăng: ý chí tập trung đang điều hướng sự không chắc chắn sâu sắc — hãy tin vào kỹ năng của bạn ngay cả khi đường đi không rõ ràng.", en: "The Magician and The Moon: focused will navigates deep uncertainty — trust your skill even when the path ahead is not yet visible." },
  "1_19": { vi: "Pháp Sư và Mặt Trời: kỹ năng toả sáng rực rỡ nhất trong sự rõ ràng và niềm vui — đây là thời điểm tốt nhất để hành động và biểu hiện.", en: "The Magician and The Sun: skill shines brightest in clarity and joy — this is your most powerful moment to act and manifest." },
  "1_20": { vi: "Pháp Sư và Phán Xét: tài năng được gọi đến một mục đích cao hơn — đã đến lúc dùng kỹ năng của bạn không chỉ cho bản thân mà cho điều lớn hơn.", en: "The Magician and Judgement: skill called to a higher purpose — it is time to use your abilities not just for yourself but for something larger." },
  "1_21": { vi: "Pháp Sư và Thế Giới: kỹ năng được thuần thục đến mức hoàn toàn — bạn đã học tất cả những gì cần học; hãy thể hiện sự thành thạo đó đầy đủ.", en: "The Magician and The World: skill fully mastered and expressed — you have learned what you needed to learn; now embody that mastery completely." },

  // High Priestess (2) pairs
  "2_3":  { vi: "Thầy Tư Tế Nữ và Nữ Hoàng: trí tuệ nội tâm gặp sự phong phú bên ngoài — tin vào những gì bạn cảm nhận trong sâu thẳm và để nó hướng dẫn cách bạn sáng tạo.", en: "The High Priestess and The Empress: inner knowing meets outward abundance — trust what you feel in your depths and let it guide how you create." },
  "2_4":  { vi: "Thầy Tư Tế Nữ và Hoàng Đế: trực giác gặp thẩm quyền lý trí — hãy để trí tuệ nội tâm kiểm tra những gì quyền lực bên ngoài yêu cầu bạn chấp nhận.", en: "The High Priestess and The Emperor: intuition meets rational authority — let inner wisdom audit what outer authority is asking you to accept." },
  "2_5":  { vi: "Thầy Tư Tế Nữ và Giáo Hoàng: trí tuệ nội tâm gặp trí tuệ truyền thống — cả hai đều chứa đựng sự thật; câu hỏi là bạn tin vào cái nào sâu hơn.", en: "The High Priestess and The Hierophant: inner wisdom meets outer tradition — both hold truth; the question is which you trust more deeply." },
  "2_6":  { vi: "Thầy Tư Tế Nữ và Người Yêu Nhau: hiểu biết nội tâm chiếu sáng lựa chọn quan trọng — hãy để trực giác của bạn cắt qua sự nhiễu loạn cảm xúc để tìm sự thật.", en: "The High Priestess and The Lovers: inner knowing illuminates a crucial choice — let your intuition cut through the emotional noise to find the truth." },
  "2_7":  { vi: "Thầy Tư Tế Nữ và Chiến Xa: dòng chảy yên lặng chạy sâu bên dưới hành động quyết đoán — hãy dừng lại để lắng nghe trước khi bạn tiến về phía trước.", en: "The High Priestess and The Chariot: still waters run deep beneath driven action — pause and listen before you charge forward." },
  "2_8":  { vi: "Thầy Tư Tế Nữ và Sức Mạnh: hiểu biết thầm lặng và lòng can đảm thầm lặng — hai nguồn sức mạnh bên trong này cùng nhau tạo ra sự thông thái không thể bị lay chuyển.", en: "The High Priestess and Strength: quiet knowing and silent courage — these two inner powers together form a wisdom that cannot be shaken." },
  "2_9":  { vi: "Thầy Tư Tế Nữ và Ẩn Sĩ: hai hình thức tìm kiếm bên trong — một cái nhìn vào chiều sâu của bí ẩn, cái kia mang đèn vào bóng tối để soi đường.", en: "The High Priestess and The Hermit: two forms of inward seeking — one gazes into mystery, the other carries a lantern into the dark to light the way." },
  "2_10": { vi: "Thầy Tư Tế Nữ và Bánh Xe Số Phận: bí ẩn gặp các chu kỳ không thể tránh của số phận — những gì ẩn giấu đang xoay chuyển ngay cả khi bạn không nhìn thấy nó.", en: "The High Priestess and The Wheel of Fortune: mystery meets the inevitable cycles of fate — what is hidden is turning even when you cannot see it." },
  "2_11": { vi: "Thầy Tư Tế Nữ và Công Lý: sự thật ẩn giấu gặp sự thật được phơi bày — những gì bạn biết trong chiều sâu sẽ được xác nhận bởi những gì được cân nhắc công khai.", en: "The High Priestess and Justice: hidden truth meets revealed truth — what you know in your depths will be confirmed by what is weighed in the open." },
  "2_12": { vi: "Thầy Tư Tế Nữ và Người Treo Ngược: cả hai đều mời bạn dừng lại và nhận — đây là thời điểm để hoàn toàn buông bỏ và cho phép sự thật nổi lên.", en: "The High Priestess and The Hanged Man: both invite you to stop and receive — this is the moment to fully let go and allow truth to surface." },
  "2_13": { vi: "Thầy Tư Tế Nữ và Thần Chết: điều chưa được nhìn thấy trở nên không thể tránh — sự thật mà bạn đã cảm nhận đang đòi hỏi được thừa nhận và chuyển hóa.", en: "The High Priestess and Death: the unseen becomes the unavoidable — the truth you have been sensing is now demanding acknowledgement and transformation." },
  "2_14": { vi: "Thầy Tư Tế Nữ và Điều Độ: trí tuệ kiên nhẫn chảy qua sự cân bằng được đo lường — hãy tin tưởng vào quá trình chậm và đầy bí ẩn đang diễn ra.", en: "The High Priestess and Temperance: patient wisdom flows through measured balance — trust the slow and mysterious process that is already underway." },
  "2_15": { vi: "Thầy Tư Tế Nữ và Ác Quỷ: kiến thức bóng tối và những gì chúng ta che giấu trong chính mình — đã đến lúc nhìn vào những gì bạn biết nhưng đã tránh né.", en: "The High Priestess and The Devil: shadow knowledge and what we conceal within ourselves — it is time to face what you have known but been avoiding." },
  "2_16": { vi: "Thầy Tư Tế Nữ và Tháp: bí mật bị phơi bày bởi sự đổ vỡ đột ngột — những gì đã được giữ kín đang bị đưa ra ánh sáng dù bạn muốn hay không.", en: "The High Priestess and The Tower: secrets exposed by sudden collapse — what has been held in the dark is being brought into light whether or not you are ready." },
  "2_17": { vi: "Thầy Tư Tế Nữ và Ngôi Sao: trí tuệ nội tâm hòa mình vào hy vọng bên ngoài — hãy tin rằng những gì bạn cảm nhận sâu trong lòng đang dẫn bạn đến sự chữa lành.", en: "The High Priestess and The Star: inner knowing aligns with outer hope — trust that what you feel deeply is guiding you toward genuine healing." },
  "2_18": { vi: "Thầy Tư Tế Nữ và Mặt Trăng: những lớp sâu nhất của vô thức — đây là vùng lãnh thổ của giấc mơ, trực giác và những điều không thể nói thành lời.", en: "The High Priestess and The Moon: the deepest layers of the unconscious — this is the territory of dreams, intuition, and what cannot be put into words." },
  "2_19": { vi: "Thầy Tư Tế Nữ và Mặt Trời: trực giác được chiếu sáng bởi sự rõ ràng — những gì bạn biết trong bóng tối cuối cùng được xác nhận trong ánh sáng ban ngày.", en: "The High Priestess and The Sun: intuition illuminated by clarity — what you knew in the dark is finally confirmed in the full light of day." },
  "2_20": { vi: "Thầy Tư Tế Nữ và Phán Xét: sự thật sâu sắc nổi lên mặt nước để được nghe — những gì đã im lặng trong lòng bạn đang được gọi lên để được thừa nhận.", en: "The High Priestess and Judgement: deep truth rises to the surface to be heard — what has been silent within you is being called up to be acknowledged." },
  "2_21": { vi: "Thầy Tư Tế Nữ và Thế Giới: mọi bí ẩn được chứa đựng trong sự trọn vẹn — trí tuệ bạn đã tích lũy trong im lặng bây giờ là một phần không thể thiếu của toàn thể.", en: "The High Priestess and The World: all mystery held within wholeness — the wisdom you gathered in silence is now an inseparable part of the complete picture." },

  // Empress (3) pairs
  "3_4":  { vi: "Nữ Hoàng và Hoàng Đế: sự nuôi dưỡng gặp cấu trúc — cái tốt nhất được tạo ra khi sức sáng tạo có nơi để bén rễ và lớn lên.", en: "The Empress and The Emperor: nurturing meets structure — the best things are created when creative energy has a place to take root and grow." },
  "3_5":  { vi: "Nữ Hoàng và Giáo Hoàng: sự phong phú tự nhiên gặp trí tuệ có tổ chức — hãy tìm cách để sự phát triển của bạn được hỗ trợ bởi một cộng đồng hoặc truyền thống.", en: "The Empress and The Hierophant: natural abundance meets organised wisdom — find a way for your growth to be supported by a community or tradition." },
  "3_6":  { vi: "Nữ Hoàng và Người Yêu Nhau: tình yêu trong đỉnh cao nở rộ với một lựa chọn ở trung tâm — hãy nuôi dưỡng điều bạn yêu thương và sau đó hành động vì nó.", en: "The Empress and The Lovers: love in full bloom with a choice at its centre — nurture what you love, then act for it." },
  "3_7":  { vi: "Nữ Hoàng và Chiến Xa: năng lượng sáng tạo được định hướng với sự quyết đoán — hãy nuôi dưỡng tầm nhìn của bạn và sau đó thúc đẩy nó về phía trước.", en: "The Empress and The Chariot: creative energy channelled with determination — nurture your vision and then drive it forward." },
  "3_8":  { vi: "Nữ Hoàng và Sức Mạnh: sự phong phú nhẹ nhàng và sự kiên nhẫn điềm tĩnh — đây là sự kết hợp của sự nuôi dưỡng và sức chịu đựng, hai điều cần thiết cho bất kỳ hành trình dài nào.", en: "The Empress and Strength: gentle abundance and quiet resilience — this is the combination of nurturing and endurance needed for any long journey." },
  "3_9":  { vi: "Nữ Hoàng và Ẩn Sĩ: sự nở rộ bên ngoài kết hợp với sự rút lui bên trong — hãy cho phép bản thân hướng vào bên trong để tiếp tục nuôi dưỡng những gì đang phát triển.", en: "The Empress and The Hermit: outward flourishing paired with inward withdrawal — allow yourself to turn inward to continue nourishing what is growing." },
  "3_10": { vi: "Nữ Hoàng và Bánh Xe Số Phận: các chu kỳ của thiên nhiên gặp các chu kỳ của số phận — điều bạn đang gieo trồng sẽ được thu hoạch theo đúng thời điểm của nó.", en: "The Empress and The Wheel of Fortune: nature's cycles meet fate's cycles — what you are planting will be harvested in its own right season." },
  "3_11": { vi: "Nữ Hoàng và Công Lý: sự sáng tạo phong phú đòi hỏi sự công bằng trong cách phân phối — hãy chắc chắn rằng bạn đang chia sẻ những gì bạn xây dựng một cách bình đẳng.", en: "The Empress and Justice: creative abundance paired with fairness in how it flows — ensure what you are building is being shared and balanced equitably." },
  "3_12": { vi: "Nữ Hoàng và Người Treo Ngược: tăng trưởng đòi hỏi sự kiên nhẫn và một góc nhìn mới — đôi khi bạn phải tạm dừng để nuôi dưỡng điều gì đó thực sự.",  en: "The Empress and The Hanged Man: growth requires patience and a different view — sometimes you have to pause the doing to truly nourish something." },
  "3_13": { vi: "Nữ Hoàng và Thần Chết: sự sống, cái chết và đất màu của sự chuyển hóa — những kết thúc chỉ làm cho tái sinh trở nên có thể.", en: "The Empress and Death: life, death, and the fertile ground of transformation — endings only make rebirth possible." },
  "3_14": { vi: "Nữ Hoàng và Điều Độ: sự phong phú chảy tốt nhất khi được điều tiết — hãy nuôi dưỡng những gì bạn đang xây dựng với sự kiên nhẫn, không phải sự vội vàng.", en: "The Empress and Temperance: abundance flows best when it is regulated — nurture what you are building with patience, not urgency." },
  "3_15": { vi: "Nữ Hoàng và Ác Quỷ: niềm vui tự nhiên có thể trở thành sự thái quá hay phụ thuộc — hãy nhận ra khi sự nuôi dưỡng trở thành sự buông thả không lành mạnh.", en: "The Empress and The Devil: natural pleasure can become excess or dependency — notice when nurturing turns into unhealthy indulgence." },
  "3_16": { vi: "Nữ Hoàng và Tháp: những gì đang phát triển bị gián đoạn đột ngột — hãy tin tưởng rằng sự sống sẽ tìm lại con đường của mình ngay cả sau sự đổ vỡ.", en: "The Empress and The Tower: what was growing is suddenly disrupted — trust that life will find its way again even after collapse." },
  "3_17": { vi: "Nữ Hoàng và Ngôi Sao: năng lượng nuôi dưỡng hòa nhịp với hy vọng được đổi mới — hãy chăm sóc bản thân và những gì bạn yêu thương; sự chữa lành đang đến.", en: "The Empress and The Star: nurturing energy aligned with renewed hope — care for yourself and what you love; healing is on its way." },
  "3_18": { vi: "Nữ Hoàng và Mặt Trăng: chiều sâu cảm xúc gặp bí ẩn của sự sáng tạo — những gì bạn đang tạo ra đang được định hình bởi những điều sâu hơn mà bạn có thể chưa nhận ra.", en: "The Empress and The Moon: emotional depths meet the mystery of creation — what you are creating is being shaped by deeper forces than you may yet recognise." },
  "3_19": { vi: "Nữ Hoàng và Mặt Trời: năng lượng phong phú nhất và hân hoan nhất có thể — đây là thời điểm để tạo ra, yêu thương và hưởng thụ sự sống đầy đủ.", en: "The Empress and The Sun: the most abundant and joyful energy possible — this is the moment to create, love, and enjoy life fully." },
  "3_20": { vi: "Nữ Hoàng và Phán Xét: những gì được nuôi dưỡng được gọi lên để đứng dậy — những gì bạn đã chăm sóc trong im lặng bây giờ sẵn sàng được nhìn nhận.", en: "The Empress and Judgement: what has been nurtured is called to rise — what you have tended quietly is now ready to be acknowledged." },
  "3_21": { vi: "Nữ Hoàng và Thế Giới: sự sáng tạo phong phú trong vòng tròn của sự trọn vẹn — tất cả những gì bạn đã nuôi dưỡng bây giờ có mặt trong một hình dạng đầy đủ.", en: "The Empress and The World: full creative abundance within the circle of wholeness — all that you have nurtured is now present in its complete form." },

  // Emperor (4) pairs
  "4_5":  { vi: "Hoàng Đế và Giáo Hoàng: hai trụ cột của quyền lực thế tục và tinh thần — hãy tìm hiểu xem bạn đang bị điều hướng bởi ý chí bên trong hay bởi kỳ vọng bên ngoài.", en: "The Emperor and The Hierophant: two pillars of worldly and spiritual authority — examine whether you are being guided by inner will or outer expectation." },
  "4_6":  { vi: "Hoàng Đế và Người Yêu Nhau: cấu trúc phải tạo chỗ cho lựa chọn từ trái tim — không ai có thể xây dựng điều gì lâu dài nếu từ bỏ điều mình thực sự yêu.", en: "The Emperor and The Lovers: structure must leave room for a heart-led choice — nothing lasting can be built by abandoning what you truly love." },
  "4_7":  { vi: "Hoàng Đế và Chiến Xa: quyền lực kép và sự tiến bước không thể ngăn cản — đây là sức mạnh để hoàn thành bất cứ điều gì bạn bắt đầu.", en: "The Emperor and The Chariot: double authority and unstoppable forward drive — this is the power to complete whatever you have started." },
  "4_8":  { vi: "Hoàng Đế và Sức Mạnh: kiểm soát bên ngoài mạnh mẽ gặp sức mạnh bên trong thầm lặng — hãy cai trị bằng sự điềm tĩnh, không phải bằng lực.", en: "The Emperor and Strength: firm outer control meets quiet inner strength — lead with composure, not force." },
  "4_9":  { vi: "Hoàng Đế và Ẩn Sĩ: thẩm quyền bên ngoài kết hợp với lời khuyên bên trong — hãy tham khảo trí tuệ thầm lặng của bạn trước khi đưa ra quyết định.", en: "The Emperor and The Hermit: outer authority paired with inward counsel — consult your quiet inner wisdom before issuing a decision." },
  "4_10": { vi: "Hoàng Đế và Bánh Xe Số Phận: ngay cả những cấu trúc vĩ đại nhất cũng khuất phục trước các chu kỳ — hãy nắm giữ quyền lực một cách nhẹ nhàng vì nó không phải mãi mãi.", en: "The Emperor and The Wheel of Fortune: even the mightiest structures yield to cycles — hold power lightly because it is never permanent." },
  "4_11": { vi: "Hoàng Đế và Công Lý: thẩm quyền được cân bằng với sự công bằng — hãy lãnh đạo theo nguyên tắc, không phải theo ý muốn cá nhân.", en: "The Emperor and Justice: authority aligned with fairness — lead by principle, not by personal preference." },
  "4_12": { vi: "Hoàng Đế và Người Treo Ngược: sự kiểm soát cứng nhắc cần sự buông bỏ — hãy tự hỏi điều gì xảy ra nếu bạn tạm thời dừng việc kiểm soát mọi thứ.", en: "The Emperor and The Hanged Man: rigid control needs the release of surrender — ask yourself what might happen if you stopped controlling everything for a moment." },
  "4_13": { vi: "Hoàng Đế và Thần Chết: những cấu trúc bạn xây dựng đang đối mặt với sự chuyển hóa — không phải mọi thứ có thể được bảo tồn; hãy để những gì cần biến đổi được biến đổi.", en: "The Emperor and Death: the structures you have built are facing transformation — not everything can be preserved; let what needs to change, change." },
  "4_14": { vi: "Hoàng Đế và Điều Độ: thẩm quyền kiên định được hưởng lợi từ sự kiên nhẫn được đo lường — hãy lãnh đạo với sự nhất quán, không phải sự vội vã.", en: "The Emperor and Temperance: firm authority benefits from measured patience — lead with consistency, not with haste." },
  "4_15": { vi: "Hoàng Đế và Ác Quỷ: quyền lực không có lương tâm trở thành sự thống trị — hãy kiểm tra xem bạn đang sử dụng thẩm quyền để xây dựng hay để kiểm soát.", en: "The Emperor and The Devil: power without conscience becomes domination — examine whether you are using authority to build or to control." },
  "4_16": { vi: "Hoàng Đế và Tháp: trật tự đã được thiết lập đối mặt với sự sụp đổ đột ngột — những gì không được xây dựng trên nền vững chắc cuối cùng sẽ ngã.", en: "The Emperor and The Tower: established order faces sudden collapse — what was not built on solid foundations will eventually fall." },
  "4_17": { vi: "Hoàng Đế và Ngôi Sao: cấu trúc mềm dần trong ánh sáng của hy vọng được đổi mới — hãy để tầm nhìn của bạn mở ra thay vì chỉ bảo vệ những gì đã có.", en: "The Emperor and The Star: structure softens in the light of renewed hope — let your vision open outward rather than only protecting what already exists." },
  "4_18": { vi: "Hoàng Đế và Mặt Trăng: kiểm soát hợp lý đối mặt với chiều sâu phi lý — không phải mọi thứ đều có thể được quản lý; hãy học cách ở yên với sự không chắc chắn.", en: "The Emperor and The Moon: rational control confronts irrational depths — not everything can be managed; learn to sit with uncertainty." },
  "4_19": { vi: "Hoàng Đế và Mặt Trời: thẩm quyền toả sáng trong hình thức nuôi dưỡng nhất của nó — hãy lãnh đạo theo cách mang lại niềm vui và sự rõ ràng cho những người xung quanh.", en: "The Emperor and The Sun: authority in its most life-giving form — lead in a way that brings joy and clarity to those around you." },
  "4_20": { vi: "Hoàng Đế và Phán Xét: những cấu trúc được xây dựng được gọi đến một sự tính toán cao hơn — hãy đánh giá liệu những gì bạn xây dựng có còn phục vụ mục đích ban đầu không.", en: "The Emperor and Judgement: the structures built are called to a higher reckoning — assess honestly whether what you have built still serves its original purpose." },
  "4_21": { vi: "Hoàng Đế và Thế Giới: thẩm quyền được hoàn thành và lĩnh vực được hoàn tất — đây là sự lãnh đạo đến đỉnh điểm của nó.", en: "The Emperor and The World: authority fulfilled and the domain complete — this is leadership arrived at its fullest expression." },

  // Hierophant (5) pairs
  "5_6":  { vi: "Giáo Hoàng và Người Yêu Nhau: truyền thống và quy ước gặp lựa chọn sâu sắc mang tính cá nhân — hãy tôn trọng những gì đi trước nhưng đừng để nó thay thế trái tim bạn.", en: "The Hierophant and The Lovers: tradition meets a deeply personal choice — honour what came before but don't let it replace your own heart." },
  "5_7":  { vi: "Giáo Hoàng và Chiến Xa: trí tuệ được thiết lập thúc đẩy sự chuyển động có mục đích — hành động với sự tin tưởng khi bạn đứng trên nền tảng vững chắc.", en: "The Hierophant and The Chariot: established wisdom drives purposeful forward movement — act with confidence when you stand on solid foundation." },
  "5_8":  { vi: "Giáo Hoàng và Sức Mạnh: truyền thống tâm linh kết hợp với lòng can đảm nội tâm thầm lặng — niềm tin thực sự không cần sức mạnh thô; nó cần sự kiên định.", en: "The Hierophant and Strength: spiritual tradition paired with quiet inner courage — true faith doesn't need brute force; it needs steadiness." },
  "5_9":  { vi: "Giáo Hoàng và Ẩn Sĩ: trí tuệ thể chế gặp sự tìm kiếm cô đơn bên trong — đôi khi chúng ta phải rời khỏi nhà thờ để tìm thấy Chúa.", en: "The Hierophant and The Hermit: institutional wisdom meets solitary inner seeking — sometimes we must leave the temple to find what we are looking for." },
  "5_10": { vi: "Giáo Hoàng và Bánh Xe Số Phận: các giáo lý được kiểm tra bởi sự xoay chuyển của số phận — hãy xem niềm tin nào vẫn đứng vững khi cuộc sống thay đổi.", en: "The Hierophant and The Wheel of Fortune: teachings are tested by the turning of fate — see which beliefs still stand when life changes around you." },
  "5_11": { vi: "Giáo Hoàng và Công Lý: luật đạo đức hòa hợp với sự cân bằng phổ quát — hành động theo nguyên tắc khi cả truyền thống và lương tâm đồng thuận.", en: "The Hierophant and Justice: moral law aligns with universal balance — act on principle when both tradition and conscience agree." },
  "5_12": { vi: "Giáo Hoàng và Người Treo Ngược: học thuyết đôi khi phải được buông bỏ để có một góc nhìn mới — hãy thách thức những gì bạn được dạy và xem điều gì vẫn đúng.", en: "The Hierophant and The Hanged Man: doctrine must sometimes be released for a new view — challenge what you were taught and see what still holds true." },
  "5_13": { vi: "Giáo Hoàng và Thần Chết: truyền thống biến đổi; chỉ có những gì cốt lõi còn lại — hãy để đi những hình thức đã lỗi thời và giữ lại trí tuệ sống động.", en: "The Hierophant and Death: tradition transforms; only what is essential survives — release the outdated forms and keep the living wisdom." },
  "5_14": { vi: "Giáo Hoàng và Điều Độ: kỷ luật tâm linh và sự cân bằng nội tâm được đo lường — hãy thực hành niềm tin của bạn theo cách nuôi dưỡng và không kiệt sức.", en: "The Hierophant and Temperance: spiritual discipline and measured inner balance — practise your beliefs in a way that nourishes rather than depletes." },
  "5_15": { vi: "Giáo Hoàng và Ác Quỷ: thẩm quyền thể chế gặp bóng tối và sự ràng buộc — hãy xem xét xem những gì bạn đã được dạy đang giải phóng hay giam cầm bạn.", en: "The Hierophant and The Devil: institutional authority meets shadow and bondage — examine whether what you have been taught is freeing or imprisoning you." },
  "5_16": { vi: "Giáo Hoàng và Tháp: niềm tin đã được thiết lập bị phá vỡ bởi sự khải thị — những gì sụp đổ có thể là cái vỏ; trí tuệ thực sự vẫn còn sống.", en: "The Hierophant and The Tower: established beliefs shattered by revelation — what collapses may be the shell; the real wisdom is still alive." },
  "5_17": { vi: "Giáo Hoàng và Ngôi Sao: trí tuệ truyền thống được đổi mới bởi hy vọng thực sự — hãy để niềm tin của bạn tiến hóa thay vì bảo vệ hình thức cũ của chúng.", en: "The Hierophant and The Star: traditional wisdom renewed by genuine hope — let your beliefs evolve rather than defending their old forms." },
  "5_18": { vi: "Giáo Hoàng và Mặt Trăng: cấu trúc tôn giáo đối mặt với những gì không thể lý giải — không phải mọi điều thiêng liêng đều có thể được đưa vào giáo điều.", en: "The Hierophant and The Moon: religious structure confronts the irrational and mysterious — not everything sacred can be contained in doctrine." },
  "5_19": { vi: "Giáo Hoàng và Mặt Trời: giáo lý tâm linh được chiếu sáng bởi niềm vui và sự rõ ràng — niềm tin thực sự mang lại ánh sáng, không phải bóng tối.", en: "The Hierophant and The Sun: spiritual teaching illuminated by joy and clarity — genuine faith brings light, not shadow." },
  "5_20": { vi: "Giáo Hoàng và Phán Xét: người thầy và lời gọi thức tỉnh với sự thật — đã đến lúc nghe giọng nói sâu hơn bên trong bạn chứ không chỉ giọng nói của truyền thống.", en: "The Hierophant and Judgement: the teacher and the call to awaken to truth — it is time to listen to the deeper voice within you, not only the voice of tradition." },
  "5_21": { vi: "Giáo Hoàng và Thế Giới: trí tuệ đạt đến biểu hiện trọn vẹn và hoàn chỉnh nhất — những gì được dạy đã được sống và tích hợp đầy đủ.", en: "The Hierophant and The World: wisdom reaches its most complete and whole expression — what was taught has been fully lived and integrated." },

  // Lovers (6) pairs
  "6_7":  { vi: "Người Yêu Nhau và Chiến Xa: lựa chọn dựa trên giá trị thúc đẩy hành động quyết đoán về phía trước — hãy quyết định từ tâm và sau đó tiến bước không do dự.", en: "The Lovers and The Chariot: a value-based choice drives determined action forward — decide from the heart and then move without hesitation." },
  "6_8":  { vi: "Người Yêu Nhau và Sức Mạnh: tình yêu và lòng can đảm — trái tim được làm dũng cảm bởi điều nó yêu thương.", en: "The Lovers and Strength: love and courage — the heart made brave by what it loves." },
  "6_9":  { vi: "Người Yêu Nhau và Ẩn Sĩ: một mối quan hệ hay lựa chọn được xem xét trong sự cô đơn — hãy dành thời gian một mình để nghe rõ tiếng lòng mình trước khi trả lời.", en: "The Lovers and The Hermit: a relationship or choice examined in solitude — take time alone to hear your own heart clearly before responding." },
  "6_10": { vi: "Người Yêu Nhau và Bánh Xe Số Phận: lựa chọn từ trái tim gặp sự xoay chuyển của số phận — hãy chọn điều bạn yêu và tin tưởng rằng thời điểm đúng đắn sẽ đến.", en: "The Lovers and The Wheel of Fortune: a heartfelt choice meets the turning of fate — choose what you love and trust that the right timing will come." },
  "6_11": { vi: "Người Yêu Nhau và Công Lý: lựa chọn được đưa ra từ trái tim phải được cân bằng bởi sự công bằng — hãy chọn theo tình yêu nhưng đừng bỏ qua hậu quả.", en: "The Lovers and Justice: a choice made from the heart must be balanced by fairness — choose by love but do not ignore the consequences." },
  "6_12": { vi: "Người Yêu Nhau và Người Treo Ngược: một quyết định bị treo lơ lửng, nhìn từ góc độ mới — đôi khi không chọn cũng là một lựa chọn cần được nhìn nhận.", en: "The Lovers and The Hanged Man: a decision suspended, seen from a new angle — sometimes not choosing is itself a choice that needs to be examined." },
  "6_13": { vi: "Người Yêu Nhau và Thần Chết: một mối quan hệ hay lựa chọn đến điểm kết thúc cần thiết — hãy để điều đã hoàn thành nhiệm vụ của nó được buông đi với lòng biết ơn.", en: "The Lovers and Death: a relationship or choice reaches its necessary ending — let what has served its purpose be released with gratitude." },
  "6_14": { vi: "Người Yêu Nhau và Điều Độ: lựa chọn yêu thương được điều tiết bởi sự kiên nhẫn và trí tuệ — hãy hành động từ trái tim nhưng theo nhịp độ bền vững.", en: "The Lovers and Temperance: a loving choice tempered with patience and wisdom — act from the heart but at a sustainable pace." },
  "6_15": { vi: "Người Yêu Nhau và Ác Quỷ: sức hút và tình yêu bị che khuất bởi cám dỗ hay sự ràng buộc không lành mạnh — hãy hỏi liệu điều bạn muốn có thực sự tự do không.", en: "The Lovers and The Devil: attraction shadowed by temptation or unhealthy bonds — ask whether what you desire is truly free or entangled in something that limits you." },
  "6_16": { vi: "Người Yêu Nhau và Tháp: một mối quan hệ hay lựa chọn bị gián đoạn bởi sự khải thị đột ngột — những gì được phơi bày là sự thật bạn cần biết.", en: "The Lovers and The Tower: a relationship or choice disrupted by sudden revelation — what is exposed is the truth you needed to know." },
  "6_17": { vi: "Người Yêu Nhau và Ngôi Sao: lựa chọn từ trái tim được dẫn dắt bởi hy vọng được đổi mới — hãy tin tưởng rằng tình yêu và sự chữa lành đang hướng dẫn bạn đúng hướng.", en: "The Lovers and The Star: a heartfelt choice guided by renewed hope — trust that love and healing are pointing you in the right direction." },
  "6_18": { vi: "Người Yêu Nhau và Mặt Trăng: lựa chọn bị làm phức tạp bởi ảo giác, sợ hãi hay cảm xúc sâu — hãy tìm sự rõ ràng trước khi cam kết.", en: "The Lovers and The Moon: a choice complicated by illusion, fear, or deep emotion — seek clarity before you commit." },
  "6_19": { vi: "Người Yêu Nhau và Mặt Trời: tình yêu và lựa chọn trong hình thức vui tươi và rõ ràng nhất — đây là sự kết hợp của trái tim mở và ánh sáng rực rỡ.", en: "The Lovers and The Sun: love and choice in their most joyful and clear form — this is the combination of an open heart and brilliant light." },
  "6_20": { vi: "Người Yêu Nhau và Phán Xét: một mối quan hệ hay lựa chọn được gọi đến sự thật cao hơn — hãy hỏi điều gì thực sự đang được kêu gọi ở đây, vượt ra ngoài mong muốn tức thời.", en: "The Lovers and Judgement: a relationship or choice called to a higher truth — ask what is truly being called for here, beyond immediate desire." },
  "6_21": { vi: "Người Yêu Nhau và Thế Giới: tình yêu và lựa chọn trong hình thức hoàn chỉnh và tích hợp — điều bạn yêu thương đã trở thành một phần không thể thiếu của bạn.", en: "The Lovers and The World: love and choice in their most complete and integrated form — what you have loved has become an inseparable part of who you are." },

  // Chariot (7) pairs
  "7_8":  { vi: "Chiến Xa và Sức Mạnh: hai hình thức quyền lực — sức mạnh bên ngoài quyết đoán và sức mạnh bên trong thầm lặng — mạnh nhất khi kết hợp cùng nhau.", en: "The Chariot and Strength: two forms of power — outer driven force and inner quiet strength — most powerful when combined." },
  "7_9":  { vi: "Chiến Xa và Ẩn Sĩ: sự chuyển động về phía trước đòi hỏi lời khuyên nội tâm định kỳ — hãy dừng lại đủ lâu để đảm bảo bạn đang tiến đến đúng nơi.", en: "The Chariot and The Hermit: driven forward movement requires periodic inward counsel — pause long enough to ensure you are heading in the right direction." },
  "7_10": { vi: "Chiến Xa và Bánh Xe Số Phận: quyết tâm gặp sự xoay chuyển không thể đoán trước của số phận — hãy điều hướng linh hoạt, không chỉ quyết tâm.", en: "The Chariot and The Wheel of Fortune: determination meets the unpredictable turning of fate — navigate flexibly, not just with resolve." },
  "7_11": { vi: "Chiến Xa và Công Lý: chiến thắng phải đạt được bằng phương tiện công bằng và nguyên tắc — tốc độ không biện minh cho sự không trung thực.", en: "The Chariot and Justice: victory must be achieved through fair and principled means — speed does not justify dishonesty." },
  "7_12": { vi: "Chiến Xa và Người Treo Ngược: sự tiến bước mạnh mẽ bị dừng lại để có sự tạm dừng cần thiết — đây không phải thất bại; đây là điều chỉnh hướng đi.", en: "The Chariot and The Hanged Man: driven forward momentum halted for a necessary pause — this is not failure; this is course correction." },
  "7_13": { vi: "Chiến Xa và Thần Chết: sự thúc đẩy về phía trước gặp sự chuyển hóa không thể tránh — hãy tiếp tục di chuyển nhưng biết rằng những gì bạn đến sẽ khác với những gì bạn mang đi.", en: "The Chariot and Death: driven forward momentum meets unavoidable transformation — keep moving but know that what you arrive at will differ from what you carried here." },
  "7_14": { vi: "Chiến Xa và Điều Độ: quyết tâm nhanh chóng cần được điều chỉnh bởi sự kiên nhẫn — tốc độ và dòng chảy cùng nhau tốt hơn là tốc độ một mình.", en: "The Chariot and Temperance: fast-moving determination needs tempering by patience — speed and flow together work better than speed alone." },
  "7_15": { vi: "Chiến Xa và Ác Quỷ: sự thúc đẩy và ý chí bị che khuất bởi cái tôi hay sự cưỡng bức không lành mạnh — hãy kiểm tra điều gì đang thực sự thúc đẩy bạn.", en: "The Chariot and The Devil: drive and willpower shadowed by ego or unhealthy compulsion — examine what is truly driving you." },
  "7_16": { vi: "Chiến Xa và Tháp: lực không thể ngăn cản gặp sự gián đoạn không thể cưỡng lại — hãy thích nghi ngay; sức kháng cự chỉ kéo dài thiệt hại.", en: "The Chariot and The Tower: unstoppable force meets an irresistible disruption — adapt immediately; resistance only prolongs the damage." },
  "7_17": { vi: "Chiến Xa và Ngôi Sao: sự quyết tâm được dẫn dắt về phía trước bởi hy vọng và tầm nhìn được đổi mới — hãy tiến bước với cả sức mạnh và niềm tin.", en: "The Chariot and The Star: determination guided forward by hope and renewed vision — move with both strength and faith." },
  "7_18": { vi: "Chiến Xa và Mặt Trăng: sự tiến bước quyết đoán vào lãnh thổ sâu sắc và không chắc chắn — hãy tin vào hướng đi ngay cả khi không thể nhìn rõ con đường.", en: "The Chariot and The Moon: forward drive into deeply uncertain territory — trust your direction even when you cannot see the road clearly." },
  "7_19": { vi: "Chiến Xa và Mặt Trời: chiến thắng trong hình thức vui tươi, huy hoàng và rõ ràng nhất — hãy ăn mừng những gì bạn đã đạt được.", en: "The Chariot and The Sun: victory in its most joyful, triumphant, and clear form — celebrate what you have achieved." },
  "7_20": { vi: "Chiến Xa và Phán Xét: hành trình quyết đoán đến được khoảnh khắc thức tỉnh sâu sắc — mọi nỗ lực dẫn đến đây; hãy nghe điều được gọi.", en: "The Chariot and Judgement: a driven journey arrives at a moment of profound awakening — all the effort led to this; listen to what is being called." },
  "7_21": { vi: "Chiến Xa và Thế Giới: hành trình được thúc đẩy đến điểm hoàn thành huy hoàng nhất — bạn đã đến nơi bạn cần đến.", en: "The Chariot and The World: the driven journey arrives at its most complete and triumphant end — you have arrived where you needed to be." },

  // Strength (8) pairs
  "8_9":  { vi: "Sức Mạnh và Ẩn Sĩ: lòng can đảm nội tâm thầm lặng và trí tuệ cô đơn sâu sắc — hai nguồn sức mạnh bên trong này cùng nhau là bất khả chiến bại.", en: "Strength and The Hermit: quiet inner courage and deep solitary wisdom — these two inner resources together are unbeatable." },
  "8_10": { vi: "Sức Mạnh và Bánh Xe Số Phận: sự kiên nhẫn bên trong gặp sự xoay chuyển không thể tránh của các chu kỳ — hãy giữ vững trung tâm khi mọi thứ xung quanh thay đổi.", en: "Strength and The Wheel of Fortune: inner resilience meets the inevitable turning of cycles — hold your centre as everything around you shifts." },
  "8_11": { vi: "Sức Mạnh và Công Lý: lòng can đảm thầm lặng của trái tim được cân bằng bởi sự thật — hãy hành động với cả sự dũng cảm và tính ngay thẳng.", en: "Strength and Justice: the quiet courage of the heart aligned with balanced truth — act with both bravery and integrity." },
  "8_12": { vi: "Sức Mạnh và Người Treo Ngược: lòng can đảm nội tâm tìm thấy chiều sâu mới trong sự buông bỏ sẵn lòng — đôi khi sức mạnh thật sự là biết khi nào nên ngừng cố gắng.", en: "Strength and The Hanged Man: inner courage finds new depth in willing surrender — sometimes true strength is knowing when to stop pushing." },
  "8_13": { vi: "Sức Mạnh và Thần Chết: lòng can đảm nhẹ nhàng điều hướng sự chuyển hóa sâu sắc nhất — hãy đối mặt với những kết thúc với sự kiên định và trái tim rộng mở.", en: "Strength and Death: gentle courage navigates the most profound transformation — face endings with steadiness and an open heart." },
  "8_14": { vi: "Sức Mạnh và Điều Độ: hai lá bài của sự làm chủ bên trong — sự kiên nhẫn chồng lên sự kiên nhẫn, tạo ra sự bình thản không thể bị lay chuyển.", en: "Strength and Temperance: two cards of inner mastery — patience layered upon patience, creating an unshakeable equanimity." },
  "8_15": { vi: "Sức Mạnh và Ác Quỷ: lòng can đảm nội tâm đối mặt với bóng tối và những gì chúng ta từ chối thấy — đây là bài kiểm tra thực sự của sức mạnh.", en: "Strength and The Devil: inner courage faces the shadow and what we refuse to see — this is the true test of strength." },
  "8_16": { vi: "Sức Mạnh và Tháp: sự kiên nhẫn bên trong được kiểm tra bởi sự đổ vỡ đột ngột và kịch tính — hãy ở lại trong tâm; đây là nơi bạn tìm thấy mình sau đó.", en: "Strength and The Tower: inner resilience tested by sudden and dramatic upheaval — stay in your centre; this is where you find yourself afterward." },
  "8_17": { vi: "Sức Mạnh và Ngôi Sao: lòng can đảm thầm lặng được đổi mới bởi hy vọng thực sự sau khó khăn — sức mạnh và sự chữa lành không đối lập; chúng bổ sung cho nhau.", en: "Strength and The Star: quiet courage renewed by genuine hope after difficulty — strength and healing are not opposites; they complement each other." },
  "8_18": { vi: "Sức Mạnh và Mặt Trăng: lòng dũng cảm nội tâm điều hướng nỗi sợ hãi sâu sắc của vô thức — hãy tiến về phía những gì bạn sợ với sự kiên định, không phải sự cứng nhắc.", en: "Strength and The Moon: inner bravery navigating the deep fears of the unconscious — move toward what you fear with steadiness, not rigidity." },
  "8_19": { vi: "Sức Mạnh và Mặt Trời: sức mạnh nội tâm thầm lặng được biểu hiện trong hình thức vui tươi và rực rỡ nhất — đây là sức mạnh tỏa sáng từ bên trong ra.", en: "Strength and The Sun: quiet inner strength expressed in its most joyful and radiant form — this is power that shines from the inside out." },
  "8_20": { vi: "Sức Mạnh và Phán Xét: lòng can đảm của trái tim trả lời lời gọi cao hơn — bạn đã đủ mạnh để nghe và hành động theo điều đang được kêu gọi.", en: "Strength and Judgement: the courage of the heart answering a higher calling — you are strong enough to hear and act on what is being called." },
  "8_21": { vi: "Sức Mạnh và Thế Giới: sự làm chủ bên trong hoàn chỉnh, tích hợp và toàn vẹn — sức mạnh bạn phát triển là một phần không thể thiếu của bạn bây giờ.", en: "Strength and The World: inner mastery complete, integrated, and whole — the strength you have cultivated is now an inseparable part of who you are." },

  // Hermit (9) pairs
  "9_10": { vi: "Ẩn Sĩ và Bánh Xe Số Phận: sự tìm kiếm cô đơn gặp sự xoay chuyển không thể ngăn cản của các chu kỳ — hãy tìm trí tuệ bên trong ngay cả khi mọi thứ bên ngoài đang thay đổi.", en: "The Hermit and The Wheel of Fortune: solitary seeking meets the unstoppable turning of cycles — find inner wisdom even as everything outside is changing." },
  "9_11": { vi: "Ẩn Sĩ và Công Lý: tìm kiếm sự thật bên trong hòa mình vào sự cân bằng và nguyên tắc bên ngoài — những gì bạn tìm thấy trong im lặng sẽ được xác nhận bởi sự công bằng.", en: "The Hermit and Justice: inner truth-seeking aligns with outer balance and principle — what you find in silence will be confirmed by fairness." },
  "9_12": { vi: "Ẩn Sĩ và Người Treo Ngược: hai lá bài của sự rút lui — sự rút lui nội tâm sâu sắc nhất có thể — hãy dành thời gian thật sự một mình và trong im lặng.", en: "The Hermit and The Hanged Man: two cards of withdrawal — the deepest possible inward retreat — spend real time alone and in silence." },
  "9_13": { vi: "Ẩn Sĩ và Thần Chết: một giai đoạn tìm kiếm cô đơn kết thúc trong sự chuyển hóa sâu sắc — những gì bạn khám phá bên trong sẽ thay đổi những gì bạn mang ra bên ngoài.", en: "The Hermit and Death: a period of solitary seeking ends in profound transformation — what you discover within will change what you bring back out." },
  "9_14": { vi: "Ẩn Sĩ và Điều Độ: trí tuệ nội tâm được tinh lọc qua thực hành kiên nhẫn và được đo lường — đây là con đường của sự phát triển chậm và thực sự.", en: "The Hermit and Temperance: inner wisdom refined through patient and measured practice — this is the path of slow and genuine growth." },
  "9_15": { vi: "Ẩn Sĩ và Ác Quỷ: sự phản chiếu cô đơn đối mặt với bóng tối, xiềng xích và các mô thức ẩn giấu — hãy dũng cảm nhìn thẳng vào những gì bạn thường tránh.", en: "The Hermit and The Devil: solitary reflection confronts shadow, chains, and hidden patterns — be brave enough to look directly at what you usually avoid." },
  "9_16": { vi: "Ẩn Sĩ và Tháp: sự ẩn dật của Ẩn Sĩ bị gián đoạn bởi sự khải thị đột ngột, không thể tránh — đôi khi sự thức tỉnh đến không theo đúng lịch trình của chúng ta.", en: "The Hermit and The Tower: the hermit's retreat disrupted by sudden, unavoidable revelation — sometimes awakening does not arrive on our own schedule." },
  "9_17": { vi: "Ẩn Sĩ và Ngôi Sao: sự tìm kiếm cô đơn tìm được con đường đến hy vọng và sự chữa lành được đổi mới — ánh sáng bạn đang mang sẽ gặp ánh sáng đang chờ bạn.", en: "The Hermit and The Star: solitary seeking finds its way to renewed hope and healing — the light you carry will meet the light that is waiting for you." },
  "9_18": { vi: "Ẩn Sĩ và Mặt Trăng: hình thức tìm kiếm bên trong sâu sắc nhất trong lãnh thổ vô thức — đây là hành trình vào nơi không ai có thể đi cùng bạn.", en: "The Hermit and The Moon: the deepest form of inward seeking within the unconscious realm — this is a journey into where no one else can accompany you." },
  "9_19": { vi: "Ẩn Sĩ và Mặt Trời: trí tuệ cô đơn được đưa vào ánh sáng của sự rõ ràng và niềm vui — những gì bạn học được trong bóng tối bây giờ có thể được chia sẻ.", en: "The Hermit and The Sun: solitary wisdom brought into the light of clarity and joy — what you learned in the dark can now be shared." },
  "9_20": { vi: "Ẩn Sĩ và Phán Xét: một giai đoạn rút lui kết thúc trong lời gọi thức tỉnh và triệu hồi sâu sắc — sự im lặng đã chuẩn bị bạn để nghe.", en: "The Hermit and Judgement: a period of withdrawal ends in a profound awakening and call — the silence has prepared you to hear." },
  "9_21": { vi: "Ẩn Sĩ và Thế Giới: sự tìm kiếm cô đơn đến được sự trọn vẹn của sự tích hợp — ánh sáng bạn tìm thấy trong cô đơn bây giờ chiếu sáng toàn bộ vòng tròn.", en: "The Hermit and The World: solitary seeking arrives at the fullness of integration — the light you found in solitude now illuminates the complete circle." },

  // Wheel of Fortune (10) pairs
  "10_11": { vi: "Bánh Xe Số Phận và Công Lý: các chu kỳ của số phận được cân bằng bởi nguyên tắc — những gì xoay chuyển không phải ngẫu nhiên; nó phản chiếu những gì đã được đưa vào.", en: "The Wheel of Fortune and Justice: fate's cycles aligned with principle — what turns is not random; it reflects what has been put in." },
  "10_12": { vi: "Bánh Xe Số Phận và Người Treo Ngược: bánh xe tạm dừng — điều gì đó phải được buông bỏ trước khi nó xoay tiếp — hãy để đi để chu kỳ tiếp theo có thể bắt đầu.", en: "The Wheel of Fortune and The Hanged Man: the wheel pauses — something must be released before it turns again — let go so the next cycle can begin." },
  "10_13": { vi: "Bánh Xe Số Phận và Thần Chết: hai trong những lực lượng thay đổi mạnh mẽ nhất trong bộ bài — sự chuyển hóa là không thể tránh; hãy làm việc với nó thay vì chống lại nó.", en: "The Wheel of Fortune and Death: two of the most powerful forces of change in the deck — transformation is inevitable; work with it rather than against it." },
  "10_14": { vi: "Bánh Xe Số Phận và Điều Độ: sự xoay chuyển của số phận được điều tiết bởi sự kiên nhẫn và dòng chảy khôn ngoan — hãy để thời gian và nhịp điệu tự nhiên dẫn bạn.", en: "The Wheel of Fortune and Temperance: fate's turning moderated by patience and wise flow — let time and natural rhythm guide you." },
  "10_15": { vi: "Bánh Xe Số Phận và Ác Quỷ: chu kỳ của số phận bị vướng vào bóng tối hay các mô thức không lành mạnh — hãy hỏi xem những gì đang xoay chuyển là do số phận hay do thói quen của bạn.", en: "The Wheel of Fortune and The Devil: fate's cycle entangled with shadow or unhealthy patterns — ask whether what is turning is fate or your own repeated habit." },
  "10_16": { vi: "Bánh Xe Số Phận và Tháp: hai lực lượng thay đổi đột ngột — hãy chuẩn bị cho sự đảo lộn nhanh chóng và giữ lấy những gì thực sự quan trọng.", en: "The Wheel of Fortune and The Tower: two forces of sudden change — prepare for rapid upheaval and hold onto what truly matters." },
  "10_17": { vi: "Bánh Xe Số Phận và Ngôi Sao: bánh xe xoay về phía sự đổi mới, hy vọng và sự chữa lành — đây là chu kỳ đang chuyển sang điều tốt hơn.", en: "The Wheel of Fortune and The Star: the wheel turning toward renewal, hope, and healing — this is the cycle shifting toward something better." },
  "10_18": { vi: "Bánh Xe Số Phận và Mặt Trăng: sự xoay chuyển của số phận sâu trong những vùng biển bí ẩn và không chắc chắn — hãy tin vào quá trình ngay cả khi bạn không thể nhìn thấy nó rõ ràng.", en: "The Wheel of Fortune and The Moon: fate turning deep within uncertain and mysterious waters — trust the process even when you cannot see it clearly." },
  "10_19": { vi: "Bánh Xe Số Phận và Mặt Trời: bánh xe may mắn xoay đến kết quả vui mừng nhất — đây là chu kỳ đang hướng đến sự rõ ràng và niềm vui.", en: "The Wheel of Fortune and The Sun: the wheel of fortune turning to its most joyful outcome — this is the cycle heading toward clarity and joy." },
  "10_20": { vi: "Bánh Xe Số Phận và Phán Xét: điểm xoay quyết định của số phận đến cùng với sự thức tỉnh sâu sắc — đây không phải ngẫu nhiên; mọi thứ đã dẫn đến khoảnh khắc này.", en: "The Wheel of Fortune and Judgement: a fateful turning point arriving alongside a profound awakening — this is not random; everything led to this moment." },
  "10_21": { vi: "Bánh Xe Số Phận và Thế Giới: chu kỳ vĩ đại của số phận hoàn thành vòng quay đầy đủ — những gì bắt đầu từ rất lâu đã đến điểm hoàn thành của nó.", en: "The Wheel of Fortune and The World: the great cycle of fate completing its full turn — what began long ago has reached its point of completion." },

  // Justice (11) pairs
  "11_12": { vi: "Công Lý và Người Treo Ngược: nhu cầu về sự thật và cân bằng kết hợp với sự tạm dừng và góc nhìn mới — đôi khi sự công bằng đòi hỏi bạn phải nhìn từ phía khác trước.", en: "Justice and The Hanged Man: the need for truth alongside a pause for new perspective — sometimes fairness requires seeing from the other side first." },
  "11_13": { vi: "Công Lý và Thần Chết: kết thúc công bằng, không thể tránh và đúng thời điểm — mọi kết thúc đều có lý do của nó; hãy chấp nhận nó với sự tôn trọng.", en: "Justice and Death: the ending that is fair, inevitable, and perfectly timed — every ending has its reason; accept it with dignity." },
  "11_14": { vi: "Công Lý và Điều Độ: sự thật và cân bằng chảy hài hòa qua sự kiên nhẫn được đo lường — hai lá bài này cùng nhau tạo ra sự rõ ràng không thể lay chuyển.", en: "Justice and Temperance: truth and balance flowing in harmony through measured patience — these two cards together create an unshakeable clarity." },
  "11_15": { vi: "Công Lý và Ác Quỷ: bóng tối và sự ràng buộc không thể che giấu khỏi nguyên tắc của sự thật — những gì bị giữ kín sẽ được cân nhắc và phán xét.", en: "Justice and The Devil: shadow and bondage cannot hide from the principle of truth — what is being concealed will eventually be weighed and judged." },
  "11_16": { vi: "Công Lý và Tháp: sự thật sẽ được phơi bày, kể cả khi cần một sự sụp đổ để làm điều đó — đây là sự cân bằng đến bằng con đường cứng rắn nhất.", en: "Justice and The Tower: truth will out, even if it takes a sudden collapse to reveal it — this is balance arriving by the hardest possible path." },
  "11_17": { vi: "Công Lý và Ngôi Sao: sự thật công bằng được hòa mình vào ánh sáng chữa lành của hy vọng được đổi mới — hãy hành động đúng và tin tưởng rằng điều tốt sẽ theo sau.", en: "Justice and The Star: fair truth aligned with the healing light of renewed hope — act rightly and trust that good will follow." },
  "11_18": { vi: "Công Lý và Mặt Trăng: sự thật bị che khuất bởi ảo giác, nỗi sợ và thủy triều thay đổi của vô thức — hãy tìm kiếm sự rõ ràng trước khi đưa ra bất kỳ phán xét nào.", en: "Justice and The Moon: truth obscured by illusion, fear, and the shifting tides of the unconscious — seek clarity before making any judgement." },
  "11_19": { vi: "Công Lý và Mặt Trời: biểu hiện rõ ràng, vui tươi và không mơ hồ nhất của sự thật và cân bằng — đây là khi mọi thứ đều được nhìn thấy và công nhận.", en: "Justice and The Sun: the clearest, most joyful, and unambiguous expression of truth — this is when everything is seen and acknowledged." },
  "11_20": { vi: "Công Lý và Phán Xét: mỗi hành động được cân bằng; lời gọi thức tỉnh cũng là lời gọi đến sự trách nhiệm — hãy nghe cả hai với lòng can đảm và tính chính trực.", en: "Justice and Judgement: every action balanced; the call to awakening is also a call to account — hear both with courage and integrity." },
  "11_21": { vi: "Công Lý và Thế Giới: sự thật và cân bằng được tích hợp đầy đủ vào trạng thái hoàn chỉnh và toàn vẹn — sự công bằng đã được thực hiện và trật tự được khôi phục.", en: "Justice and The World: truth and balance fully integrated into a complete and whole state — justice has been done and order is restored." },

  // Hanged Man (12) pairs
  "12_13": { vi: "Người Treo Ngược và Thần Chết: sự buông bỏ sâu sắc nhất dẫn đến sự chuyển hóa sâu sắc nhất — hãy để đi hoàn toàn và tin tưởng vào điều đang được tái sinh.", en: "The Hanged Man and Death: the deepest surrender leads to the most profound transformation — let go completely and trust what is being reborn." },
  "12_14": { vi: "Người Treo Ngược và Điều Độ: hai lá bài của sự kiên nhẫn sâu sắc — điều gì đó đặc biệt đang được tinh lọc trong sự im lặng và chờ đợi này.", en: "The Hanged Man and Temperance: two cards of deep patience — something extraordinary is being refined within this silence and waiting." },
  "12_15": { vi: "Người Treo Ngược và Ác Quỷ: sự buông bỏ sẵn lòng tiết lộ những gì đang giữ bạn bị ràng buộc mà không hề hay biết — hãy nhìn thẳng vào những gì hiện ra.", en: "The Hanged Man and The Devil: willing surrender reveals what has been keeping you bound without your awareness — look directly at what appears." },
  "12_16": { vi: "Người Treo Ngược và Tháp: sự sẵn lòng buông bỏ đi trước hoặc theo sau sự tháo dỡ đột ngột — cả hai đều dọn sạch những gì không còn phục vụ bạn.", en: "The Hanged Man and The Tower: the willingness to let go precedes or follows sudden dismantling — both clear away what no longer serves you." },
  "12_17": { vi: "Người Treo Ngược và Ngôi Sao: một giai đoạn tạm dừng và buông bỏ mở ra hy vọng thực sự và sự đổi mới — sự chờ đợi không phải là vô ích; nó đang chuẩn bị bạn.", en: "The Hanged Man and The Star: a period of suspension opens into genuine hope and renewal — the waiting is not wasted; it is preparing you." },
  "12_18": { vi: "Người Treo Ngược và Mặt Trăng: sự tạm dừng trong những lớp sâu nhất, bí ẩn nhất của vô thức — hãy ở lại với sự không biết và xem điều gì nổi lên.", en: "The Hanged Man and The Moon: suspension in the deepest and most mysterious layers of the unconscious — stay with the not-knowing and see what surfaces." },
  "12_19": { vi: "Người Treo Ngược và Mặt Trời: sau sự tạm dừng và buông bỏ, sự rõ ràng và niềm vui xuất hiện — việc chờ đợi đã được đền đáp.", en: "The Hanged Man and The Sun: after the pause and surrender, clarity and joy emerge — the waiting has been worthwhile." },
  "12_20": { vi: "Người Treo Ngược và Phán Xét: sự hy sinh sẵn lòng được đáp lại bởi lời gọi thức tỉnh sâu sắc — những gì bạn đã buông bỏ tạo ra khoảng trống cho điều thực sự cần đến.", en: "The Hanged Man and Judgement: a willing sacrifice answered by a profound call to awaken — what you released made space for what truly needed to arrive." },
  "12_21": { vi: "Người Treo Ngược và Thế Giới: sự buông bỏ và giải phóng dẫn đến sự trọn vẹn và hoàn chỉnh tối thượng — chính vì bạn đã thả ra mà bạn mới có thể giữ lấy tất cả.", en: "The Hanged Man and The World: surrender and release arrive at ultimate wholeness and completion — it is because you let go that you can now hold everything." },

  // Death (13) pairs
  "13_14": { vi: "Thần Chết và Điều Độ: sự chuyển hóa được hướng dẫn bởi sự kiên nhẫn và dòng chảy chữa lành của thời gian — hãy để quá trình diễn ra theo nhịp độ của chính nó.", en: "Death and Temperance: transformation guided by patience and the healing flow of time — let the process unfold at its own pace." },
  "13_15": { vi: "Thần Chết và Ác Quỷ: sự chuyển hóa đến khi bạn cuối cùng đối mặt và giải phóng những gì đang ràng buộc bạn — cái kết thúc và sự giải phóng là cùng một chuyển động.", en: "Death and The Devil: transformation comes when you finally face and release what is binding you — the ending and the liberation are the same movement." },
  "13_16": { vi: "Thần Chết và Tháp: hai lá bài của sự gián đoạn sâu sắc — sự thay đổi kịch tính nhất có thể đang đến; hãy buông bỏ sớm thay vì chờ bị buộc phải làm vậy.", en: "Death and The Tower: two cards of profound disruption — the most dramatic change possible is coming; release early rather than waiting to be forced." },
  "13_17": { vi: "Thần Chết và Ngôi Sao: sau kết thúc cần thiết, sự đổi mới và hy vọng thực sự xuất hiện — đêm tối nhất luôn đến ngay trước bình minh.", en: "Death and The Star: after the necessary ending, genuine renewal and hope emerge — the darkest night always comes just before dawn." },
  "13_18": { vi: "Thần Chết và Mặt Trăng: sự chuyển hóa xảy ra trong những vùng biển bí ẩn và không chắc chắn nhất — hãy tin tưởng vào quá trình ngay cả khi bạn không thể thấy bờ bên kia.", en: "Death and The Moon: transformation occurring in the most mysterious and uncertain waters — trust the process even when you cannot see the other shore." },
  "13_19": { vi: "Thần Chết và Mặt Trời: sau kết thúc, khởi đầu mới rực rỡ nhất xuất hiện — mọi mặt trời mọc đều đòi hỏi một đêm đứng trước nó.", en: "Death and The Sun: after the ending, the most radiant new beginning emerges — every sunrise requires a night to precede it." },
  "13_20": { vi: "Thần Chết và Phán Xét: kết thúc sâu sắc gọi ra sự thức tỉnh ngang bằng sâu sắc — sự mất mát bạn trải qua đã mở cánh cửa cho điều thực sự cần đến.", en: "Death and Judgement: a profound ending calls forth an equally profound awakening — the loss you experienced opened the door for what truly needed to arrive." },
  "13_21": { vi: "Thần Chết và Thế Giới: kết thúc và hoàn thành là cùng một điều — chu kỳ trọn vẹn và một chu kỳ mới có thể bắt đầu.", en: "Death and The World: ending and completion are the same — the cycle is whole and a new one can begin." },

  // Temperance (14) pairs
  "14_15": { vi: "Điều Độ và Ác Quỷ: sự chữa lành kiên nhẫn và sự điều độ đối mặt với sức hút của bóng tối và sự thái quá — hãy nhận ra ranh giới và chọn con đường giữa.", en: "Temperance and The Devil: patient healing and moderation confronting the pull of shadow and excess — recognise the boundary and choose the middle path." },
  "14_16": { vi: "Điều Độ và Tháp: sự bình tĩnh được đo lường bị gián đoạn bởi sự sụp đổ đột ngột và không thể tránh — hãy quay lại dòng chảy càng sớm càng tốt sau cơn bão.", en: "Temperance and The Tower: measured calm disrupted by sudden and unavoidable collapse — return to flow as quickly as possible after the storm." },
  "14_17": { vi: "Điều Độ và Ngôi Sao: sự chữa lành kiên nhẫn và sự điều độ hòa mình hoàn hảo với hy vọng được đổi mới — đây là con đường chữa lành rõ ràng nhất.", en: "Temperance and The Star: patient healing and temperance aligned perfectly with renewed hope — this is the clearest path to genuine healing." },
  "14_18": { vi: "Điều Độ và Mặt Trăng: sự kiên nhẫn được đo lường điều hướng chiều sâu không chắc chắn của vô thức — hãy tiến chậm và thận trọng qua những vùng biển này.", en: "Temperance and The Moon: measured patience navigating the uncertain depths of the unconscious — move slowly and carefully through these waters." },
  "14_19": { vi: "Điều Độ và Mặt Trời: sự chữa lành kiên nhẫn đến được biểu hiện vui tươi và rực rỡ nhất của nó — mọi nỗ lực bền bỉ cuối cùng dẫn đến điều này.", en: "Temperance and The Sun: patient healing arriving at its most joyful and luminous expression — every sustained effort ultimately leads to this." },
  "14_20": { vi: "Điều Độ và Phán Xét: sự tinh lọc kiên nhẫn dẫn đến khoảnh khắc được gọi và thức tỉnh — những gì được chuẩn bị từ từ cuối cùng được sẵn sàng hoàn toàn.", en: "Temperance and Judgement: patient refinement leading to the moment of calling and awakening — what is prepared slowly is ultimately fully ready." },
  "14_21": { vi: "Điều Độ và Thế Giới: dòng chảy của sự kiên nhẫn và cân bằng đến được sự tích hợp hoàn toàn — con đường giữa luôn dẫn đến trung tâm.", en: "Temperance and The World: the flow of patience and balance arriving at full integration — the middle path always leads to the centre." },

  // Devil (15) pairs
  "15_16": { vi: "Ác Quỷ và Tháp: những xiềng xích của bóng tối và ảo giác bị phá vỡ bởi sự khải thị đột ngột, kịch tính — sự sụp đổ là sự giải phóng.", en: "The Devil and The Tower: the chains of shadow and illusion broken by sudden, dramatic revelation — the collapse is the liberation." },
  "15_17": { vi: "Ác Quỷ và Ngôi Sao: bóng tối được đối mặt sẽ mở ra con đường đến sự chữa lành và hy vọng thực sự — bạn không thể đi vòng; bạn phải đi qua.", en: "The Devil and The Star: shadow confronted opens the way to genuine healing and hope — you cannot go around; you must go through." },
  "15_18": { vi: "Ác Quỷ và Mặt Trăng: bóng tối và lãnh thổ vô thức — những gì ẩn náu trong bóng tối đang ảnh hưởng đến bạn nhiều hơn bạn nhận ra.", en: "The Devil and The Moon: shadow and the unconscious realm — what lurks in the dark is influencing you more than you realise." },
  "15_19": { vi: "Ác Quỷ và Mặt Trời: bóng tối tan biến trong ánh sáng đầy đủ của sự rõ ràng và sự thật hân hoan — hãy mang những gì ẩn giấu ra ánh sáng.", en: "The Devil and The Sun: shadow dissolves in the full light of clarity and joyful truth — bring what is hidden into the light." },
  "15_20": { vi: "Ác Quỷ và Phán Xét: lời gọi thức tỉnh cũng là lời gọi cuối cùng để giải phóng những gì đang ràng buộc bạn — đã đến lúc thoát ra.", en: "The Devil and Judgement: the call to awaken is also the final call to release what is binding you — it is time to break free." },
  "15_21": { vi: "Ác Quỷ và Thế Giới: bóng tối được thừa nhận và tích hợp vào sự trọn vẹn đầy đủ của bản thể — bạn không phải xóa bỏ bóng tối; bạn phải hiểu và chấp nhận nó.", en: "The Devil and The World: shadow acknowledged and integrated into the full wholeness of being — you do not erase the shadow; you understand and accept it." },

  // Tower (16) pairs
  "16_17": { vi: "Tháp và Ngôi Sao: sau sự sụp đổ kịch tính nhất, sự đổi mới và hy vọng thực sự xuất hiện — hãy tin tưởng rằng điều đang được xây dựng lại sẽ vững chắc hơn.", en: "The Tower and The Star: after the most dramatic collapse, genuine renewal and hope emerge — trust that what is being rebuilt will be more solid." },
  "16_18": { vi: "Tháp và Mặt Trăng: sự đổ vỡ đột ngột nhấn chìm vào sự không chắc chắn sâu sắc và nỗi sợ hãi chưa được giải quyết — hãy ở lại trong hiện tại và đặt từng bước một.", en: "The Tower and The Moon: sudden upheaval plunging into deep uncertainty and unresolved fear — stay in the present and take one step at a time." },
  "16_19": { vi: "Tháp và Mặt Trời: sự phá hủy tiếp theo bởi sự rõ ràng và niềm vui rực rỡ nhất — đây là minh chứng rằng những kết thúc lớn nhất tạo ra những khởi đầu lớn nhất.", en: "The Tower and The Sun: destruction followed by the most radiant clarity and joy — this is proof that the biggest endings make the biggest beginnings." },
  "16_20": { vi: "Tháp và Phán Xét: sự sụp đổ đột ngột là lời gọi thức tỉnh thay đổi tất cả — đây không phải là thảm họa; đây là sự giải phóng.", en: "The Tower and Judgement: a sudden collapse serves as the awakening call that changes everything — this is not catastrophe; this is liberation." },
  "16_21": { vi: "Tháp và Thế Giới: sự sụp đổ tạo chỗ cho sự khởi đầu mới hoàn chỉnh và toàn vẹn — những gì ngã xuống đã dọn sạch con đường cho điều thực sự.", en: "The Tower and The World: the fall makes room for the complete and whole new beginning — what came down cleared the path for what is real." },

  // Star (17) pairs
  "17_18": { vi: "Ngôi Sao và Mặt Trăng: hy vọng và sự chữa lành kề cận sự không chắc chắn của những chiều sâu vô thức — hãy mang ánh sáng vào bóng tối nhưng đừng giả vờ bóng tối không có ở đó.", en: "The Star and The Moon: hope and healing alongside the uncertainty of unconscious depths — bring light into the dark but don't pretend the dark isn't there." },
  "17_19": { vi: "Ngôi Sao và Mặt Trời: hai nguồn sáng — hy vọng và niềm vui cùng nhau, tương lai rực rỡ nhất có thể — hãy tiến về phía trước với sự tin tưởng và sự hân hoan.", en: "The Star and The Sun: two sources of light — hope and joy together, the most radiant possible future — move forward with trust and joy." },
  "17_20": { vi: "Ngôi Sao và Phán Xét: hy vọng được đổi mới trả lời lời gọi thức tỉnh đến mục đích cao hơn — hãy tin tưởng rằng những gì đang đến xứng đáng với cuộc hành trình.", en: "The Star and Judgement: renewed hope answering the call to awaken to a higher purpose — trust that what is coming is worth the journey." },
  "17_21": { vi: "Ngôi Sao và Thế Giới: hy vọng được đổi mới của Ngôi Sao đến được sự trọn vẹn của sự hoàn chỉnh — điều bạn hy vọng không còn là hy vọng nữa; nó trở thành hiện thực.", en: "The Star and The World: the renewed hope of the Star arriving at the fullness of completion — what you hoped for is no longer hope; it has become real." },

  // Moon (18) pairs
  "18_19": { vi: "Mặt Trăng và Mặt Trời: hành trình đầy đủ từ những chiều sâu vô thức đến sự rõ ràng rực rỡ — bạn đã đi qua bóng tối và ánh sáng đang chờ ở phía bên kia.", en: "The Moon and The Sun: the full journey from unconscious depths to radiant clarity — you have traveled through the dark and the light is waiting on the other side." },
  "18_20": { vi: "Mặt Trăng và Phán Xét: những gì ẩn giấu trong vô thức cuối cùng nổi lên để được nghe và biết — đã đến lúc những giấc mơ và nỗi sợ hãi được nhìn nhận đầy đủ.", en: "The Moon and Judgement: what was hidden in the unconscious finally rises to be heard and known — it is time for the dreams and fears to be fully seen." },
  "18_21": { vi: "Mặt Trăng và Thế Giới: những chiều sâu bí ẩn được tích hợp vào sự trọn vẹn — không có phần nào của bạn, dù tối tăm hay khó hiểu, bị loại trừ khỏi toàn thể.", en: "The Moon and The World: mysterious depths integrated into wholeness — no part of you, however dark or confusing, is excluded from the whole." },

  // Sun (19) pairs
  "19_20": { vi: "Mặt Trời và Phán Xét: sự rõ ràng rực rỡ gặp lời gọi thức tỉnh sâu sắc — đây là sự nhận thức vui mừng rằng cuộc hành trình đã dẫn đến đây vì một lý do.", en: "The Sun and Judgement: radiant clarity meets the profound call to awaken — this is the joyful recognition that the journey led here for a reason." },
  "19_21": { vi: "Mặt Trời và Thế Giới: ánh sáng đầy đủ của sự rõ ràng và niềm vui trong vòng tròn hoàn chỉnh — không có kết hợp nào tích cực hơn trong bộ bài; hãy đón nhận điều này.", en: "The Sun and The World: the full light of clarity and joy within the complete circle — there is no more positive combination in the deck; receive this fully." },

  // Judgement (20) pairs
  "20_21": { vi: "Phán Xét và Thế Giới: lời gọi thức tỉnh dẫn đến trạng thái tích hợp và hoàn chỉnh tối thượng — bạn đã nghe lời gọi và bước đi; bây giờ bạn được hoàn chỉnh.", en: "Judgement and The World: the call to awaken leads to the ultimate state of integration and completion — you heard the call and walked toward it; now you are whole." },

  // ─── TIER 2: Major × Court (352 pairs) ─────────────────────────────────────
  // Fool (0) × Courts
  "0_32": { vi: "Kẻ Khờ và Trang Bị Gậy: cả hai tràn đầy nhiệt huyết bồng bột — ý tưởng bùng cháy nhưng dễ tắt nhanh; hãy tập trung ngọn lửa này trước khi nó phân tán.", en: "The Fool and Wands Page: both brim with restless enthusiasm — exciting sparks ignite but may fizzle fast; channel this energy before it scatters in all directions." },
  "0_33": { vi: "Kẻ Khờ và Kỵ Sĩ Gậy: phiêu lưu liều lĩnh nhân đôi — lao vào chưa biết với đam mê không kiềm chế; những bước nhảy vọt hào hứng nhưng hãy cẩn thận quyết định bốc đồng.", en: "The Fool and Wands Knight: reckless adventure doubled — charging into the unknown with unbridled passion; exhilarating leaps of faith, but watch for impulsive decisions with no safety net." },
  "0_34": { vi: "Kẻ Khờ và Nữ Hoàng Gậy: tinh thần ngây thơ gặp sự tự tin lôi cuốn — kẻ mơ mộng hồn nhiên tìm được người đỡ đầu sáng tạo, thổi bùng tiềm năng thành ngọn lửa thực sự.", en: "The Fool and Wands Queen: naive spirit meets charismatic confidence — the uninhibited dreamer finds a bold creative patron who fans innocent potential into real flame." },
  "0_35": { vi: "Kẻ Khờ và Vua Gậy: kẻ lang thang gặp nhà lãnh đạo có tầm nhìn — sự khởi đầu thô ráp tìm thấy định hướng; những cuộc phiêu lưu lớn có thể bắt đầu nếu Kẻ Khờ lắng nghe kinh nghiệm của Vua.", en: "The Fool and Wands King: the wanderer meets the visionary leader — raw beginnings find focus; great ventures can start from this encounter if the Fool heeds the King's hard-won experience." },
  "0_46": { vi: "Kẻ Khờ và Trang Bị Cốc: sự kỳ diệu và cởi mở cảm xúc tràn đầy — cả hai nhìn thế giới qua đôi mắt tươi trẻ; sự nhạy cảm đẹp đẽ nhưng cần được neo đậu nhẹ nhàng.", en: "The Fool and Cups Page: wonder and emotional openness overflow — both see the world through fresh, feeling eyes; beautiful sensitivity that easily overwhelms and needs gentle grounding." },
  "0_47": { vi: "Kẻ Khờ và Kỵ Sĩ Cốc: đi theo con tim mù quáng vào những cuộc phiêu lưu cảm xúc — chủ nghĩa lãng mạn lý tưởng đang bùng nổ; những khả năng mê hoặc nhưng hãy cẩn thận đừng đuổi theo ảo tưởng.", en: "The Fool and Cups Knight: following the heart blindly into emotional adventures — romantic idealism in full swing; enchanting possibilities, but beware of chasing illusions over substance." },
  "0_48": { vi: "Kẻ Khờ và Nữ Hoàng Cốc: sự trực giác từ bi ôm ấp tinh thần hồn nhiên — trái tim chăm sóc mang lại bến bình yên cho cuộc hành trình ngây thơ của Kẻ Khờ vào thế giới cảm xúc.", en: "The Fool and Cups Queen: compassionate intuition cradles the innocent spirit — the nurturing heart offers a safe harbor for the Fool's naive journey into the realm of feeling." },
  "0_49": { vi: "Kẻ Khờ và Vua Cốc: sự thành thục cảm xúc gặp trái tim người mới thuần khiết — lòng từ bi của Vua khôn ngoan dạy Kẻ Khờ rằng chiều sâu và sự cởi mở có thể cùng tồn tại.", en: "The Fool and Cups King: emotional mastery meets pure beginner's heart — the wise King's compassion teaches the Fool that depth and wisdom can coexist with openness and wonder." },
  "0_60": { vi: "Kẻ Khờ và Trang Bị Kiếm: những bộ óc tò mò tràn đầy dũng cảm ngây thơ — câu hỏi sắc bén nảy sinh từ quan sát hồn nhiên; tia lửa trí tuệ thú vị nhưng phán đoán chưa chín.", en: "The Fool and Swords Page: curious minds charged with naive courage — sharp questions emerge from innocent observations; exciting intellectual sparks, but judgment is undeveloped and mistakes likely." },
  "0_61": { vi: "Kẻ Khờ và Kỵ Sĩ Kiếm: xông thẳng vào xung đột mà không suy nghĩ — hành động liều lĩnh và lời nói sắc bén va chạm; hào hứng nhưng có thể gây hại; hãy chậm lại trước khi nói hoặc ra tay.", en: "The Fool and Swords Knight: headlong charge into conflict without thinking — reckless action and sharp words collide; exhilarating but potentially destructive; slow down before speaking or striking." },
  "0_62": { vi: "Kẻ Khờ và Nữ Hoàng Kiếm: sự thật rõ ràng cắt qua ảo tưởng ngây thơ — nhận thức thẳng thắn của Nữ Hoàng có thể làm Kẻ Khờ đau, nhưng sự rõ ràng này là món quà cho hành trình phía trước.", en: "The Fool and Swords Queen: clear-eyed truth cuts through innocent illusions — the Queen's honest perception may sting, yet this clarity is a necessary gift for the journey ahead." },
  "0_63": { vi: "Kẻ Khờ và Vua Kiếm: quyền uy và trí tuệ sắc bén đối mặt với tinh thần tự do — cấu trúc gặp hỗn độn; Vua có thể hướng dẫn Kẻ Khờ khôn ngoan hoặc bóp nghẹt niềm vui của khởi đầu mới.", en: "The Fool and Swords King: authority and sharp intellect confront the carefree spirit — structure meets chaos; the King can guide the Fool wisely or crush the joy out of new beginnings." },
  "0_74": { vi: "Kẻ Khờ và Trang Bị Tiền: học trò hăng hái gặp bình minh của một cuộc phiêu lưu mới — cả hai đều ở đầu hành trình vật chất; những hạt giống phong phú nhỏ được gieo với sự nhiệt tình.", en: "The Fool and Pentacles Page: eager student meets the dawn of a new venture — both stand at the beginning of a material journey; small seeds of abundance planted with wide-eyed enthusiasm." },
  "0_75": { vi: "Kẻ Khờ và Kỵ Sĩ Tiền: bước nhảy vọt nhẹ nhàng gặp sự kiên trì có phương pháp — tính tự phát của Kẻ Khờ đạt được sức bền khi kết hợp với tham vọng vật chất ổn định của Kỵ Sĩ.", en: "The Fool and Pentacles Knight: carefree leaps of faith meet methodical perseverance — the Fool's spontaneity gains staying power when paired with the Knight's steady, earthly ambition." },
  "0_76": { vi: "Kẻ Khờ và Nữ Hoàng Tiền: sự nuôi dưỡng phong phú chào đón tinh thần lang thang — người mẹ đất hào phóng nhận ra tiềm năng thô của Kẻ Khờ và mang đến sự khôn ngoan thực tế để neo đậu hành trình.", en: "The Fool and Pentacles Queen: abundant nurturing welcomes the wandering spirit — the generous earth-mother recognizes raw potential and offers practical wisdom to ground the journey forward." },
  "0_77": { vi: "Kẻ Khờ và Vua Tiền: sự thành thục vật chất làm ổn định những bước đầu tiên ngây thơ — kho tàng kinh nghiệm của Vua hướng dẫn Kẻ Khờ tránh xa rủi ro tài chính liều lĩnh, hướng tới khởi đầu bền vững.", en: "The Fool and Pentacles King: material mastery steadies naive first steps — the King's wealth of experience guides the Fool away from foolish risks toward sustainable, well-grounded new beginnings." },

  // Magician (1) × Courts
  "1_32": { vi: "Pháp Sư và Trang Bị Gậy: ý chí lành nghề thổi bùng lửa của học trò — sự thành thạo của Pháp Sư truyền cảm hứng cho Trang Bị biến đam mê thô thành hành động có mục đích.", en: "The Magician and Wands Page: skilled will ignites the student's fire — the Magician's mastery inspires the Page to channel raw passion into purposeful, manifested action." },
  "1_33": { vi: "Pháp Sư và Kỵ Sĩ Gậy: ý chí quyết đoán thúc đẩy bước tiến táo bạo — sự chỉ huy tài nguyên của Pháp Sư gặp cuộc xung phong dũng cảm của Kỵ Sĩ; ý định mạnh mẽ trở thành động lực không thể cản.", en: "The Magician and Wands Knight: decisive willpower fuels bold forward motion — the Magician's command of resources meets the Knight's fearless charge; powerful intentions become unstoppable momentum." },
  "1_34": { vi: "Pháp Sư và Nữ Hoàng Gậy: hai sự hiện diện mạnh mẽ hợp nhất — ý chí tập trung của Pháp Sư và sức hút sáng tạo của Nữ Hoàng kết hợp để tạo ra sức mạnh hiện thực hóa phi thường.", en: "The Magician and Wands Queen: two commanding presences unite — the Magician's focused will and the Queen's creative magnetism combine for extraordinary manifestation power in creative and career goals." },
  "1_35": { vi: "Pháp Sư và Vua Gậy: hai nhà lãnh đạo từ các lĩnh vực khác nhau liên kết — tham vọng có tầm nhìn gặp kỹ thuật thành thạo; cùng nhau họ có thể xây dựng đế chế, nhưng phải tránh tranh giành quyền lực.", en: "The Magician and Wands King: two leaders of different domains align — visionary ambition meets masterful technique; together they can build empires, but must avoid power struggles over direction." },
  "1_46": { vi: "Pháp Sư và Trang Bị Cốc: ý chí lành nghề áp dụng vào sự khởi đầu cảm xúc — Pháp Sư dạy kẻ mơ mộng trẻ cách tạo hình và ý định cho những cảm xúc xoáy cuộn và ấn tượng trực giác.", en: "The Magician and Cups Page: skilled will applied to emotional beginnings — the Magician teaches the young dreamer how to give form and intention to swirling feelings and intuitive impressions." },
  "1_47": { vi: "Pháp Sư và Kỵ Sĩ Cốc: ý định kỳ diệu gặp sự theo đuổi lãng mạn — kỹ năng của Pháp Sư dẫn đường đam mê lý tưởng của Kỵ Sĩ thành hành động hiệu quả; kết quả quyến rũ khi ý chí và cảm xúc hòa hợp.", en: "The Magician and Cups Knight: magical intention meets romantic pursuit — the Magician's skill channels the Knight's idealistic passion into effective action; enchanting results when will and feeling align." },
  "1_48": { vi: "Pháp Sư và Nữ Hoàng Cốc: sự hiện thực hóa thành thạo kết hợp với sự khôn ngoan cảm xúc sâu sắc — Pháp Sư cung cấp công cụ trong khi Nữ Hoàng cung cấp trái tim; cùng nhau họ chữa lành và tạo dựng hiệu quả phi thường.", en: "The Magician and Cups Queen: masterful manifestation joins deep emotional wisdom — the Magician provides tools while the Queen provides heart; together they can heal, create, and nurture with extraordinary effect." },
  "1_49": { vi: "Pháp Sư và Vua Cốc: sự thành thạo trí tuệ gặp quyền uy cảm xúc — hai chuyên gia hợp tác; sự tháo vát của Pháp Sư và chiều sâu của Vua tạo ra liên minh mạnh mẽ giữa tâm trí và trái tim.", en: "The Magician and Cups King: intellectual mastery meets emotional authority — two experts in their domains collaborate; the Magician's resourcefulness and the King's depth create a powerful alliance of mind and heart." },
  "1_60": { vi: "Pháp Sư và Trang Bị Kiếm: ý chí lành nghề gặp trí tuệ trẻ sắc bén — Pháp Sư hướng sự tò mò của Trang Bị vào học tập tập trung và tư duy có kỷ luật; việc học nhanh chóng tăng tốc.", en: "The Magician and Swords Page: skilled will meets sharp young intellect — the Magician channels the Page's mental curiosity into focused study and disciplined thinking; learning accelerates rapidly." },
  "1_61": { vi: "Pháp Sư và Kỵ Sĩ Kiếm: hai lực lượng của hành động quyết đoán, sắc bén — ý chí chính xác của Pháp Sư khuếch đại cuộc xung phong của Kỵ Sĩ; sự rõ ràng và thực thi phi thường, nhưng có nguy cơ tàn nhẫn.", en: "The Magician and Swords Knight: two forces of decisive cutting action — the Magician's precise will amplifies the Knight's swift charge; extraordinary clarity and execution, but risk of ruthlessness." },
  "1_62": { vi: "Pháp Sư và Nữ Hoàng Kiếm: hai bậc thầy về giao tiếp rõ ràng có chủ đích — kỹ năng của Pháp Sư và sự thành thật nhạy bén của Nữ Hoàng tạo ra đối thoại mạnh mẽ; lời nói trở thành công cụ biến đổi.", en: "The Magician and Swords Queen: two masters of clear, intentional communication — the Magician's skill and the Queen's perceptive honesty create powerful dialogue; words become instruments of transformation." },
  "1_63": { vi: "Pháp Sư và Vua Kiếm: hai trí tuệ chỉ huy liên kết — sự tháo vát của Pháp Sư kết hợp với quyền uy phân tích của Vua có thể giải quyết bất kỳ vấn đề nào, nhưng hãy cẩn thận với thao túng lạnh lùng.", en: "The Magician and Swords King: two commanding intellects align — the Magician's resourcefulness combined with the King's analytical authority can solve any problem, but beware of cold manipulation." },
  "1_74": { vi: "Pháp Sư và Trang Bị Tiền: sự tháo vát lành nghề gặp học trò háo hức về thành thạo vật chất — Pháp Sư làm mẫu cách biến ý tưởng thành kết quả hữu hình; sự hiện thực hóa thực tế bắt đầu.", en: "The Magician and Pentacles Page: skilled resourcefulness meets the eager student of material mastery — the Magician models how to turn ideas into tangible results; practical manifestation begins here." },
  "1_75": { vi: "Pháp Sư và Kỵ Sĩ Tiền: ý chí và phương pháp hợp nhất để đạt thành tựu thực tế — kỹ năng hiện thực hóa của Pháp Sư định hướng công sức bền bỉ của Kỵ Sĩ để xây dựng kết quả thực sự, lâu bền.", en: "The Magician and Pentacles Knight: will and method unite for practical achievement — the Magician's manifestation skills direct the Knight's steady labor toward building real, lasting results." },
  "1_76": { vi: "Pháp Sư và Nữ Hoàng Tiền: ý chí tập trung của Pháp Sư gặp sự hào phóng dồi dào của Nữ Hoàng — cùng nhau họ có thể hiện thực hóa sự thịnh vượng đáng kể; sự kết hợp mạnh mẽ cho kinh doanh và tài chính.", en: "The Magician and Pentacles Queen: the Magician's focused will meets the Queen's abundant generosity — together they can manifest remarkable prosperity; a potent combination for business and financial growth." },
  "1_77": { vi: "Pháp Sư và Vua Tiền: hai bậc thầy về hiện thực hóa vật chất hợp nhất — kỹ năng của Pháp Sư và sự thịnh vượng đã xây dựng của Vua tạo ra sức mạnh không thể cản cho việc xây dựng sự giàu có lâu dài.", en: "The Magician and Pentacles King: two masters of material manifestation unite — the Magician's skill and the King's established prosperity create an unstoppable force for building lasting wealth and success." },

  // High Priestess (2) × Courts
  "2_32": { vi: "Nữ Tư Tế và Trang Bị Gậy: sự hiểu biết nội tâm sâu sắc gặp sự tò mò nhiệt tình — Nữ Tư Tế hướng dẫn người tìm kiếm trẻ nhìn vào bên trong; trực giác, không phải bốc đồng, soi sáng con đường phía trước.", en: "The High Priestess and Wands Page: deep inner knowing meets enthusiastic curiosity — the Priestess guides the young seeker to look within; intuition, not impulse, lights the way forward." },
  "2_33": { vi: "Nữ Tư Tế và Kỵ Sĩ Gậy: dòng nước tĩnh lặng ẩn giấu bên dưới cuộc xung phong lửa — trước khi hành động táo bạo, hãy dừng lại và lắng nghe; giọng nói nội tâm nắm giữ sự khôn ngoan mà Kỵ Sĩ hối hả không thể thấy.", en: "The High Priestess and Wands Knight: still hidden waters beneath the fiery charge — before taking bold action, pause and listen; the inner voice holds wisdom the rushing Knight cannot see." },
  "2_34": { vi: "Nữ Tư Tế và Nữ Hoàng Gậy: trực giác bí ẩn bên cạnh sự tự tin rạng rỡ — Nữ Tư Tế đọc những điều vô hình trong khi Nữ Hoàng hành động trong thế giới hữu hình; liên minh nữ tính mạnh mẽ giữa biết và làm.", en: "The High Priestess and Wands Queen: mysterious intuition beside radiant confidence — the Priestess reads the unseen while the Queen acts in the visible; a powerful feminine alliance of knowing and doing." },
  "2_35": { vi: "Nữ Tư Tế và Vua Gậy: sự khôn ngoan nội tâm thách thức quyền uy bên ngoài — thành công hữu hình của Vua có thể đang bỏ lỡ dòng chảy tinh thần sâu sắc hơn; Nữ Tư Tế gợi ý ông nhìn xa hơn vật chất.", en: "The High Priestess and Wands King: inner wisdom challenges outer authority — the King's visible success may be missing a deeper spiritual current; the Priestess suggests he look beyond the material." },
  "2_46": { vi: "Nữ Tư Tế và Trang Bị Cốc: chiều sâu trực giác sâu sắc gặp sự nhạy cảm cảm xúc dịu dàng — hai lực lượng hướng nước tạo ra sự tiếp nhận gần như thần giao cách cảm; hãy tin tưởng hoàn toàn vào cảm xúc và giấc mơ.", en: "The High Priestess and Cups Page: profound intuitive depths meet tender emotional sensitivity — two water-aligned forces create an almost psychic receptivity; trust feelings, dreams, and subtle signs completely." },
  "2_47": { vi: "Nữ Tư Tế và Kỵ Sĩ Cốc: tiếng gọi của chiều sâu ẩn giấu đối mặt với thôi thúc lao về phía tình yêu — Nữ Tư Tế khuyên sự tĩnh lặng trước sự theo đuổi cảm xúc của Kỵ Sĩ; hãy chờ sự mặc khải trước khi hành động.", en: "The High Priestess and Cups Knight: the call of hidden depths versus the urge to ride toward love — the Priestess counsels stillness before emotional pursuit; wait for revelation before action." },
  "2_48": { vi: "Nữ Tư Tế và Nữ Hoàng Cốc: hai dòng nước nữ tính vĩ đại — sự hiểu biết nội tâm huyền bí và thành thạo cảm xúc từ bi; sự chữa lành sâu sắc, đồng cảm và hiểu biết tâm linh chảy tự nhiên ở đây.", en: "The High Priestess and Cups Queen: the two great feminine waters — mystical inner knowing and compassionate emotional mastery; profound healing, empathy, and psychic understanding flow here without effort." },
  "2_49": { vi: "Nữ Tư Tế và Vua Cốc: sự khôn ngoan trực giác gặp quyền uy cảm xúc chín chắn — nữ tính nội tâm và trái tim nam tính khôn ngoan nhận ra nhau; sự hiểu biết sâu sắc, đồng cảm và chiều sâu tinh thần hợp nhất.", en: "The High Priestess and Cups King: intuitive wisdom meets mature emotional authority — the inner feminine and the wise masculine heart recognize each other; deep understanding, empathy, and spiritual depth unite." },
  "2_60": { vi: "Nữ Tư Tế và Trang Bị Kiếm: giọng nói nội tâm im lặng đối mặt với tâm trí phân tích bồn chồn — Nữ Tư Tế thách thức Trang Bị đặt câu hỏi liệu sự khéo léo tinh thần một mình có thể tiếp cận sự thật sâu sắc hơn không.", en: "The High Priestess and Swords Page: the silent inner voice versus the restless analytical mind — the Priestess challenges the Page to question whether mental cleverness alone can access deeper truths." },
  "2_61": { vi: "Nữ Tư Tế và Kỵ Sĩ Kiếm: bí ẩn nội tâm đối mặt với cuộc xung phong sắc bén — trước khi lưỡi kiếm rơi xuống, Nữ Tư Tế hỏi: điều gì thực sự chưa biết ở đây? Hãy dừng lại trước xung đột để nghe sự thật ẩn giấu.", en: "The High Priestess and Swords Knight: inner mystery confronts the cutting charge — before the sword falls, the Priestess asks: what is truly unknown here? Pause before conflict to hear hidden truths." },
  "2_62": { vi: "Nữ Tư Tế và Nữ Hoàng Kiếm: hai lực lượng nữ tính sắc bén, nhạy cảm — Nữ Tư Tế nhìn xuyên màn bí ẩn trong khi Nữ Hoàng nhìn xuyên sự giả vờ; cùng nhau họ nhận thức những gì người khác không thể.", en: "The High Priestess and Swords Queen: two sharp, perceptive feminine forces — the Priestess sees through the veil of mystery while the Queen sees through pretense; together they perceive what others cannot." },
  "2_63": { vi: "Nữ Tư Tế và Vua Kiếm: sự hiểu biết nội tâm bí ẩn đối mặt với sự phán xét lý trí có thẩm quyền — Nữ Tư Tế nắm giữ sự thật mà logic của Vua không thể định lượng; sự khôn ngoan nằm ở việc tôn trọng cả tâm trí lẫn bí ẩn.", en: "The High Priestess and Swords King: mysterious inner knowing confronts authoritative rational judgment — the Priestess holds truths the King's logic cannot quantify; wisdom honors both mind and mystery." },
  "2_74": { vi: "Nữ Tư Tế và Trang Bị Tiền: kiến thức tinh thần ẩn giấu bên dưới những khởi đầu vật chất — Nữ Tư Tế nhắc nhở học trò háo hức rằng sự giàu có lớn nhất là trí tuệ; hãy nhìn sâu hơn học tập bề mặt.", en: "The High Priestess and Pentacles Page: hidden spiritual knowledge beneath material beginnings — the Priestess reminds the eager student that the greatest wealth is wisdom; look deeper than surface-level learning." },
  "2_75": { vi: "Nữ Tư Tế và Kỵ Sĩ Tiền: sự khôn ngoan nội tâm kiên nhẫn bên cạnh nỗ lực bên ngoài bền bỉ — Nữ Tư Tế khuyên Kỵ Sĩ hãy để trực giác hướng dẫn con đường có phương pháp; hãy tin tưởng những gì không thể đo đếm.", en: "The High Priestess and Pentacles Knight: patient inner wisdom alongside steady outer effort — the Priestess counsels the Knight to let intuition guide the methodical path; trust what cannot be measured." },
  "2_76": { vi: "Nữ Tư Tế và Nữ Hoàng Tiền: hai lực lượng nữ tính hiểu biết sâu sắc — bí ẩn nội tâm của Nữ Tư Tế và sự khôn ngoan đất đai của Nữ Hoàng kết hợp; nuôi dưỡng từ nơi của sự hiểu biết tinh thần sâu sắc.", en: "The High Priestess and Pentacles Queen: two deeply knowing feminine forces — the Priestess's inner mystery and the Queen's earthly wisdom combine; nurturing from a place of profound spiritual understanding." },
  "2_77": { vi: "Nữ Tư Tế và Vua Tiền: bí ẩn tinh thần bên cạnh thành thạo vật chất — Nữ Tư Tế thấy những gì Vua đã xây dựng nhưng hỏi điều gì còn chưa xây dựng bên trong; thành công bên ngoài được làm phong phú bởi tìm kiếm bên trong.", en: "The High Priestess and Pentacles King: spiritual mystery alongside material mastery — the Priestess sees what the King has built but asks what remains unbuilt within; outer success enriched by inner seeking." },

  // Empress (3) × Courts
  "3_32": { vi: "Nữ Hoàng Đất và Trang Bị Gậy: sự sáng tạo dồi dào nuôi dưỡng ngọn lửa trẻ — năng lượng màu mỡ của Nữ Hoàng Đất khuyến khích đam mê của Trang Bị lớn lên và nở rộ thành điều gì đó thực sự đẹp đẽ.", en: "The Empress and Wands Page: abundant creativity nurtures the young fire — the Empress's fertile energy encourages the Page's passion to grow and bloom into something real and beautiful." },
  "3_33": { vi: "Nữ Hoàng Đất và Kỵ Sĩ Gậy: sự phong phú của thiên nhiên tiếp sức cho cuộc xung phong đam mê — năng lượng tạo sinh của Nữ Hoàng Đất cung cấp cho Kỵ Sĩ nhiên liệu vô tận; những dự án sáng tạo từ sự kết hợp này phát triển mạnh.", en: "The Empress and Wands Knight: nature's abundance fuels the passionate charge — the Empress's generative energy provides the Knight with inexhaustible fuel; creative ventures born from this combination flourish." },
  "3_34": { vi: "Nữ Hoàng Đất và Nữ Hoàng Gậy: hai nữ hoàng của sự sáng tạo — sự phong phú màu mỡ của Nữ Hoàng Đất và sự tự tin sáng tạo mãnh liệt của Nữ Hoàng Gậy; sự kết hợp mạnh mẽ cho nghệ thuật, kinh doanh và tự thể hiện.", en: "The Empress and Wands Queen: two queens of creation — the Empress's fertile abundance and the Wands Queen's fierce creative confidence; a powerhouse combination for art, business, and passionate self-expression." },
  "3_35": { vi: "Nữ Hoàng Đất và Vua Gậy: người mẹ nuôi dưỡng gặp người cha có tầm nhìn — năng lượng sáng tạo dồi dào kết hợp với lãnh đạo mạnh mẽ tạo điều kiện cho doanh nghiệp phát triển và gia đình nở rộ.", en: "The Empress and Wands King: the nurturing mother meets the visionary patriarch — abundant creative energy combined with strong leadership creates conditions for thriving enterprises and flourishing families." },
  "3_46": { vi: "Nữ Hoàng Đất và Trang Bị Cốc: sự phong phú tràn đầy gặp sự kỳ diệu cảm xúc dịu dàng — môi trường nuôi dưỡng sâu sắc, giàu cảm xúc cho sự tăng trưởng; sự sáng tạo và cảm xúc chảy tự do và đẹp đẽ cùng nhau.", en: "The Empress and Cups Page: overflowing abundance meets tender emotional wonder — a deeply nurturing, emotionally rich environment for growth; creativity and feeling flow freely and beautifully together." },
  "3_47": { vi: "Nữ Hoàng Đất và Kỵ Sĩ Cốc: sự phong phú màu mỡ đẩy mạnh cuộc tìm kiếm lãng mạn — trái tim hào phóng của Nữ Hoàng Đất khuếch đại sự theo đuổi lý tưởng tình yêu của Kỵ Sĩ; vẻ đẹp và lãng mạn nở rộ dưới cặp đôi này.", en: "The Empress and Cups Knight: fertile abundance propels the romantic quest — the Empress's generous heart amplifies the Knight's idealistic pursuit of love; beauty and romance flourish under this pairing." },
  "3_48": { vi: "Nữ Hoàng Đất và Nữ Hoàng Cốc: hai người mẹ vĩ đại của sự phong phú và tình yêu — năng lượng kết hợp của họ tạo ra không gian nuôi dưỡng và chữa lành sâu sắc; lòng từ bi, sự nở rộ sáng tạo và toàn vẹn cảm xúc.", en: "The Empress and Cups Queen: two great mothers of abundance and love — their combined energies create a profoundly nurturing and healing space; deep compassion, creative flourishing, and emotional wholeness." },
  "3_49": { vi: "Nữ Hoàng Đất và Vua Cốc: đất đai phong phú nuôi dưỡng trái tim cảm xúc khôn ngoan — Nữ Hoàng Đất cung cấp nền tảng màu mỡ cho chiều sâu của Vua tự thể hiện; gia đình, chữa lành và sự khôn ngoan sáng tạo hợp nhất.", en: "The Empress and Cups King: abundant earth nurtures the wise emotional heart — the Empress provides fertile ground for the King's depth to express itself; family, healing, and creative wisdom unite." },
  "3_60": { vi: "Nữ Hoàng Đất và Trang Bị Kiếm: sự phong phú sáng tạo đối mặt với sự đặt câu hỏi phân tích — Nữ Hoàng Đất mời Trang Bị tò mò nghiên cứu thiên nhiên thay vì chỉ mổ xẻ nó; kiến thức được làm phong phú bởi sự kỳ diệu.", en: "The Empress and Swords Page: creative abundance confronts analytical questioning — the Empress invites the curious Page to study nature rather than merely dissect it; knowledge enriched by wonder." },
  "3_61": { vi: "Nữ Hoàng Đất và Kỵ Sĩ Kiếm: sự phong phú nuôi dưỡng đối mặt với sự tiến triển hung hăng — Nữ Hoàng Đất khuyên Kỵ Sĩ phát triển bền vững thay vì chinh phục liều lĩnh; sự kiên nhẫn và chiến lược hiệu quả hơn ở đây.", en: "The Empress and Swords Knight: nurturing abundance versus aggressive advancement — the Empress counsels sustainable growth rather than reckless conquest; patience and strategy work better here." },
  "3_62": { vi: "Nữ Hoàng Đất và Nữ Hoàng Kiếm: sự phong phú nuôi dưỡng gặp nhận thức rõ ràng thành thật — Nữ Hoàng Đất làm dịu sự sắc bén của Nữ Hoàng; cùng nhau họ mang đến sự thật yêu thương vừa chữa lành vừa soi sáng.", en: "The Empress and Swords Queen: nurturing abundance meets clear honest perception — the Empress softens the Queen's sharpness; together they offer loving truth that both heals and illuminates." },
  "3_63": { vi: "Nữ Hoàng Đất và Vua Kiếm: người mẹ phong phú thách thức người cha trí tuệ — dòng chảy sáng tạo gặp cấu trúc phân tích; tốt nhất là quản trị có cảm hứng; tệ nhất là kiểm soát cứng nhắc bóp nghẹt tăng trưởng tự nhiên.", en: "The Empress and Swords King: the mother of abundance challenges the intellectual patriarch — creative flow meets analytical structure; at best, inspired governance; at worst, rigid control stifling natural growth." },
  "3_74": { vi: "Nữ Hoàng Đất và Trang Bị Tiền: năng lượng đất màu mỡ nuôi dưỡng học trò về sự phong phú thực tế — Nữ Hoàng Đất làm mẫu cách các chu kỳ của thiên nhiên tạo ra sự giàu có vật chất; học cách phát triển qua sự kiên nhẫn.", en: "The Empress and Pentacles Page: fertile earth energy nurtures the student of practical abundance — the Empress models how nature's cycles create material wealth; learning to grow through patience and care." },
  "3_75": { vi: "Nữ Hoàng Đất và Kỵ Sĩ Tiền: sự phong phú của thiên nhiên hỗ trợ người xây dựng bền bỉ — năng lượng màu mỡ của Nữ Hoàng Đất thúc đẩy nỗ lực có phương pháp của Kỵ Sĩ; sự giàu có bền vững phát triển từ công việc hài hòa với đất.", en: "The Empress and Pentacles Knight: nature's abundance supports the steady builder — the Empress's fertile energy fuels the Knight's methodical efforts; sustainable wealth grows from patient, earth-aligned work." },
  "3_76": { vi: "Nữ Hoàng Đất và Nữ Hoàng Tiền: hai nữ hoàng tuyệt vời của sự phong phú trên đất — cùng nhau họ thể hiện đỉnh cao của sự hào phóng vật chất và sáng tạo; sự thịnh vượng phi thường, nuôi dưỡng và sự phong phú giác quan.", en: "The Empress and Pentacles Queen: two magnificent queens of earth's abundance — together they embody the peak of material and creative generosity; extraordinary prosperity, nurturing, and sensual richness." },
  "3_77": { vi: "Nữ Hoàng Đất và Vua Tiền: sự phong phú sáng tạo gặp lãnh địa vật chất — sự hào phóng màu mỡ của Nữ Hoàng Đất và sự giàu có đã xây dựng của Vua tạo ra di sản lâu dài; sự thịnh vượng gia đình có gốc rễ trong cả tình yêu lẫn thực tế.", en: "The Empress and Pentacles King: creative abundance meets material dominion — the Empress's fertile generosity and the King's established wealth create lasting legacy; family prosperity rooted in both love and practicality." },

  // Emperor (4) × Courts
  "4_32": { vi: "Hoàng Đế và Trang Bị Gậy: quyền uy vững chắc hướng dẫn ngọn lửa trẻ nhiệt tình — Hoàng Đế cung cấp cho Trang Bị cấu trúc và định hướng; đam mê thô được kênh hóa dưới sự hướng dẫn khôn ngoan mang lại kết quả ấn tượng.", en: "The Emperor and Wands Page: firm authority guides the eager young fire — the Emperor offers the Page structure and direction; raw passion channeled under wise guidance yields impressive early results." },
  "4_33": { vi: "Hoàng Đế và Kỵ Sĩ Gậy: quyền uy chiến lược định hướng cuộc xung phong dũng cảm — cấu trúc của Hoàng Đế kênh hóa ngọn lửa của Kỵ Sĩ thành chinh phục có kỷ luật; tham vọng có tổ chức đạt được nhiều hơn động lực liều lĩnh.", en: "The Emperor and Wands Knight: strategic authority directs the fearless charge — the Emperor's structure channels the Knight's fire into disciplined conquest; organized ambition achieves far more than reckless momentum." },
  "4_34": { vi: "Hoàng Đế và Nữ Hoàng Gậy: quyền uy gia trưởng gặp lửa nữ quyền — va chạm tiềm tàng của ý chí mạnh mẽ; khi cân bằng, cặp đôi này thúc đẩy những dự án đầy tham vọng với sức mạnh kết hợp ấn tượng.", en: "The Emperor and Wands Queen: paternal authority meets matriarchal fire — a potential clash of strong wills; when balanced, this pairing drives ambitious ventures with impressive combined force." },
  "4_35": { vi: "Hoàng Đế và Vua Gậy: hai vị vua quyền năng từ các lĩnh vực khác nhau — quyền uy và tầm nhìn phải đàm phán; tiềm năng cho thành tựu lớn khi liên kết, nhưng tranh quyền và xung đột nếu không.", en: "The Emperor and Wands King: two powerful kings from different domains — authority and vision must negotiate; potential for great achievement when they align, but rivalry and power struggles if they don't." },
  "4_46": { vi: "Hoàng Đế và Trang Bị Cốc: quyền uy có cấu trúc đối mặt với sự nhạy cảm cảm xúc dịu dàng — Hoàng Đế có thể cung cấp ranh giới cần thiết cho sự tràn đầy cảm xúc của Trang Bị; kỷ luật bảo vệ thay vì nghiền nát.", en: "The Emperor and Cups Page: structured authority confronts tender emotional sensitivity — the Emperor can provide needed boundaries for the Page's overflow of feeling; discipline that protects rather than crushes." },
  "4_47": { vi: "Hoàng Đế và Kỵ Sĩ Cốc: trật tự cố gắng kênh hóa dòng chảy lãng mạn — Hoàng Đế thúc giục Kỵ Sĩ suy nghĩ trước khi cảm nhận; những hành trình cảm xúc thành công hơn với kế hoạch đằng sau đam mê.", en: "The Emperor and Cups Knight: order attempts to channel the romantic tide — the Emperor urges the Knight to think before feeling; emotional quests succeed better with a plan behind the passion." },
  "4_48": { vi: "Hoàng Đế và Nữ Hoàng Cốc: quyền uy có cấu trúc gặp sự khôn ngoan cảm xúc — cặp đôi quyền lực cân bằng hoặc sự hài hòa nội tâm giữa cấu trúc và cảm xúc; điểm mạnh bổ sung tạo ra khả năng lãnh đạo toàn diện.", en: "The Emperor and Cups Queen: structured authority meets emotional wisdom — a balanced power couple or inner harmony between structure and feeling; complementary strengths create well-rounded leadership." },
  "4_49": { vi: "Hoàng Đế và Vua Cốc: hai vị vua chín chắn từ các nguyên tố đối lập — lửa-và-cấu-trúc gặp nước-và-chiều-sâu; khi hợp tác, họ bao phủ tất cả nền tảng của lãnh đạo, tạo ra quyền uy khôn ngoan và từ bi.", en: "The Emperor and Cups King: two mature kings from opposing elements — fire-and-structure meets water-and-depth; when they cooperate, they cover all bases of leadership, creating wise and compassionate authority." },
  "4_60": { vi: "Hoàng Đế và Trang Bị Kiếm: quyền uy có cấu trúc gặp trí tuệ trẻ sắc bén — Hoàng Đế có thể định hướng tâm trí bồn chồn của Trang Bị đến sự tìm tòi có kỷ luật; phát triển trí tuệ được hưởng lợi từ sự cố vấn có cấu trúc.", en: "The Emperor and Swords Page: structured authority meets sharp young intelligence — the Emperor can direct the Page's restless mind toward disciplined inquiry; intellectual development benefits from structured mentorship." },
  "4_61": { vi: "Hoàng Đế và Kỵ Sĩ Kiếm: hai lực lượng của hành động quyết đoán hướng tới mục tiêu — quyền uy chiến lược của Hoàng Đế và cuộc xung phong nhanh của Kỵ Sĩ; sự kết hợp mạnh mẽ để thực thi kế hoạch, nhưng có nguy cơ quá mức.", en: "The Emperor and Swords Knight: two forces of decisive goal-driven action — the Emperor's strategic authority and the Knight's swift charge; powerful for executing plans, but risk of aggression or overkill." },
  "4_62": { vi: "Hoàng Đế và Nữ Hoàng Kiếm: hai trong số những quyền uy sắc bén nhất của bộ bài — sức mạnh cấu trúc của Hoàng Đế và sự rõ ràng nhạy cảm của Nữ Hoàng; đáng gờm khi liên kết, nhưng có thể xung đột về ai nắm phán quyết cuối cùng.", en: "The Emperor and Swords Queen: two of the deck's sharpest authorities — the Emperor's structural power and the Queen's perceptive clarity; formidable when aligned, but may clash over who holds final judgment." },
  "4_63": { vi: "Hoàng Đế và Vua Kiếm: hai vị vua của quyền uy và trí tuệ sắc bén — khi hợp tác, không gì là không thể; sức mạnh chiến lược và phân tích tối cao, mặc dù có nguy cơ quản trị lạnh lùng, vô cảm.", en: "The Emperor and Swords King: two kings of authority and sharp intellect — when they work together, nothing is beyond reach; supreme strategic and analytical power, though risk of cold, impersonal governance." },
  "4_74": { vi: "Hoàng Đế và Trang Bị Tiền: quyền uy có cấu trúc hướng dẫn học trò chăm chỉ — Hoàng Đế cung cấp khung và kỷ luật mà Trang Bị cần để chuyển đổi nỗ lực thành thành tựu vật chất lâu dài.", en: "The Emperor and Pentacles Page: structured authority guides the diligent student — the Emperor provides the framework and discipline the Page needs to convert effort into lasting material achievement." },
  "4_75": { vi: "Hoàng Đế và Kỵ Sĩ Tiền: quyền uy có kỷ luật và lao động bền bỉ — sự kết hợp xuất sắc để xây dựng cấu trúc và sự giàu có lâu dài; cả hai đều kiên nhẫn, có phương pháp và tập trung vào kết quả dài hạn.", en: "The Emperor and Pentacles Knight: disciplined authority and steady labor — an excellent combination for building lasting structures and wealth; both are patient, methodical, and focused on concrete long-term results." },
  "4_76": { vi: "Hoàng Đế và Nữ Hoàng Tiền: quyền uy cấu trúc gặp sự nuôi dưỡng dồi dào — Hoàng Đế cung cấp khung trong khi Nữ Hoàng lấp đầy nó bằng sự ấm áp và màu mỡ; một cặp đôi năng suất và thịnh vượng.", en: "The Emperor and Pentacles Queen: structural authority meets abundant nurturing — the Emperor provides the framework while the Queen fills it with warmth and fertility; a productive and prosperous pairing." },
  "4_77": { vi: "Hoàng Đế và Vua Tiền: hai vị vua của lãnh địa vật chất — quyền uy kết hợp trên các cấu trúc, tài nguyên và sức mạnh thực tế; khả năng phi thường để xây dựng và duy trì sự giàu có và di sản lâu dài.", en: "The Emperor and Pentacles King: two kings of material dominion — combined authority over structures, resources, and practical power; exceptional ability to build and maintain lasting wealth and legacy." },

  // Hierophant (5) × Courts
  "5_32": { vi: "Giáo Hoàng và Trang Bị Gậy: sự khôn ngoan truyền thống gặp người mới bắt đầu háo hức — Giáo Hoàng nhập môn Trang Bị vào những giáo huấn đã được thiết lập; thời kỳ học tập chính thức, cố vấn và học hỏi truyền thống thiêng liêng.", en: "The Hierophant and Wands Page: traditional wisdom meets the eager beginner — the Hierophant initiates the Page into established teachings; a period of formal study, mentorship, and learning sacred traditions." },
  "5_33": { vi: "Giáo Hoàng và Kỵ Sĩ Gậy: quy ước bị thách thức bởi người tìm kiếm bồn chồn — quyền uy của Giáo Hoàng thử thách Kỵ Sĩ muốn vượt ra ngoài truyền thống; sự tăng trưởng thông qua việc đặt câu hỏi về các quy tắc đã được thiết lập.", en: "The Hierophant and Wands Knight: convention challenged by the restless seeker — the Hierophant's authority tests the Knight who would ride beyond tradition; growth through questioning established rules." },
  "5_34": { vi: "Giáo Hoàng và Nữ Hoàng Gậy: truyền thống thể chế gặp tinh thần sáng tạo độc lập — Giáo Hoàng và Nữ Hoàng có thể mâu thuẫn; lời mời là tạo ra con đường tinh thần cá nhân tôn trọng cả lửa lẫn truyền thống.", en: "The Hierophant and Wands Queen: institutional tradition meets the independent creative spirit — potentially at odds; the invitation is to forge a personal spiritual path that honors both fire and tradition." },
  "5_35": { vi: "Giáo Hoàng và Vua Gậy: thể chế tinh thần gặp lãnh đạo có tầm nhìn — trật tự đã được thiết lập và doanh nhân; cả hai đều lãnh đạo qua các kênh khác nhau; tôn trọng truyền thống bên cạnh đổi mới táo bạo.", en: "The Hierophant and Wands King: spiritual institution meets visionary leadership — the established order and the entrepreneur; both lead through different channels; respect for tradition alongside bold innovation." },
  "5_46": { vi: "Giáo Hoàng và Trang Bị Cốc: giáo huấn thiêng liêng gặp sự cởi mở tinh thần dịu dàng — Giáo Hoàng chào đón học trò tiếp nhận chân thành; mối quan hệ học nghề đẹp đẽ trong sự sùng kính, lòng từ bi và đời sống tôn giáo nội tâm.", en: "The Hierophant and Cups Page: sacred teachings meet tender spiritual openness — the Hierophant welcomes the sincerely receptive student; a beautiful apprenticeship in devotion, compassion, and inner religious life." },
  "5_47": { vi: "Giáo Hoàng và Kỵ Sĩ Cốc: truyền thống tinh thần bị kiểm tra bởi chủ nghĩa lãng mạn lý tưởng — Giáo Hoàng thúc giục Kỵ Sĩ tìm kiếm tình yêu thiêng liêng thay vì lãng mạn trần thế; lời kêu gọi đến sự sùng kính cao hơn.", en: "The Hierophant and Cups Knight: spiritual tradition tested by romantic idealism — the Hierophant urges the Knight to seek divine love rather than earthly romance; the call to a higher devotion." },
  "5_48": { vi: "Giáo Hoàng và Nữ Hoàng Cốc: quyền uy tinh thần gặp sự khôn ngoan cảm xúc từ bi — cùng nhau họ đại diện cho đỉnh cao của sự chăm sóc sùng kính và mục vụ; chữa lành qua đức tin, cộng đồng và sự hiện diện yêu thương.", en: "The Hierophant and Cups Queen: spiritual authority meets compassionate emotional wisdom — together they represent the height of devotional and pastoral care; healing through faith, community, and loving presence." },
  "5_49": { vi: "Giáo Hoàng và Vua Cốc: truyền thống tinh thần bên cạnh quyền uy cảm xúc chín chắn — có thể đại diện cho sự tư vấn tinh thần hoặc hướng dẫn trong các vấn đề cảm xúc có gốc rễ trong sự khôn ngoan đã được thiết lập.", en: "The Hierophant and Cups King: spiritual tradition alongside mature emotional authority — may represent spiritual counseling or guidance in emotional matters rooted in established wisdom and compassion." },
  "5_60": { vi: "Giáo Hoàng và Trang Bị Kiếm: học thuyết gặp sự đặt câu hỏi sắc bén — tâm trí tò mò của Trang Bị thách thức những giáo huấn đã thiết lập của Giáo Hoàng; căng thẳng hiệu quả giữa sự khôn ngoan được truyền thụ và tư duy phê phán tươi mới.", en: "The Hierophant and Swords Page: doctrine meets sharp questioning — the Page's inquiring mind challenges established teachings; productive tension between received wisdom and fresh critical thinking." },
  "5_61": { vi: "Giáo Hoàng và Kỵ Sĩ Kiếm: truyền thống đối mặt với lực lượng nổi loạn — quyền uy của Giáo Hoàng bị thách thức bởi cuộc xung phong hung hăng của Kỵ Sĩ; phá vỡ sự chính thống, hoặc chiến đấu để bảo vệ các thể chế thiêng liêng.", en: "The Hierophant and Swords Knight: tradition confronted by rebellious force — the Hierophant's authority is challenged by the Knight's aggressive charge; breaking from orthodoxy, or fighting to defend sacred institutions." },
  "5_62": { vi: "Giáo Hoàng và Nữ Hoàng Kiếm: học thuyết đã thiết lập gặp sự thật sắc bén không khoan nhượng — nhận thức của Nữ Hoàng có thể phơi bày sai sót trong truyền thống; lời kêu gọi phân biệt sự khôn ngoan tinh thần chân thực với nghi lễ rỗng tuếch.", en: "The Hierophant and Swords Queen: established doctrine meets sharp, unsparing truth — the Queen's perception may expose flaws in tradition; a call to distinguish authentic spiritual wisdom from hollow ritual." },
  "5_63": { vi: "Giáo Hoàng và Vua Kiếm: hai quyền uy gia trưởng từ các lĩnh vực khác nhau — thể chế tinh thần và quản trị phân tích; khi liên kết, luật pháp và đạo đức hỗ trợ lẫn nhau; khi xung đột, các mâu thuẫn đạo đức nảy sinh.", en: "The Hierophant and Swords King: two patriarchal authorities from different domains — spiritual institution and analytical governance; when aligned, laws and morality reinforce each other; when they clash, ethical conflicts arise." },
  "5_74": { vi: "Giáo Hoàng và Trang Bị Tiền: giáo huấn thiêng liêng áp dụng cho việc học vật chất — Giáo Hoàng hướng dẫn học trò tôn trọng công việc và sự phong phú như thực hành tinh thần; kỷ luật, đóng góp và quản lý.", en: "The Hierophant and Pentacles Page: sacred teachings applied to material learning — the Hierophant guides the student to honor work and abundance as spiritual practice; discipline, stewardship, and tithing." },
  "5_75": { vi: "Giáo Hoàng và Kỵ Sĩ Tiền: giá trị truyền thống hướng dẫn người xây dựng bền bỉ — khuôn khổ đạo đức của Giáo Hoàng hài hòa với nỗ lực có phương pháp của Kỵ Sĩ; xây dựng sự giàu có với tính chính trực và các nguyên tắc đạo đức.", en: "The Hierophant and Pentacles Knight: traditional values guide the steady builder — the Hierophant's moral framework aligns with the Knight's methodical effort; building wealth with integrity and ethical principles." },
  "5_76": { vi: "Giáo Hoàng và Nữ Hoàng Tiền: truyền thống tinh thần gặp sự phong phú trần thế — Giáo Hoàng nhận ra sự quản lý của Nữ Hoàng như một hình thức sùng kính; chăm sóc thế giới vật chất như một trách nhiệm thiêng liêng.", en: "The Hierophant and Pentacles Queen: spiritual tradition meets earthly abundance — the Hierophant recognizes the Queen's stewardship as a form of devotion; tending the material world as a sacred responsibility." },
  "5_77": { vi: "Giáo Hoàng và Vua Tiền: quyền uy tinh thần gặp thành thạo vật chất — cùng nhau họ đại diện cho sự tích hợp của sự giàu có, quyền lực và đạo đức; lãnh đạo được hướng dẫn bởi cả nguyên tắc lẫn sự thịnh vượng.", en: "The Hierophant and Pentacles King: spiritual authority meets material mastery — together they represent the integration of wealth, power, and ethics; leadership guided by both principle and prosperity." },

  // Lovers (6) × Courts
  "6_32": { vi: "Người Yêu và Trang Bị Gậy: một lựa chọn thổi bùng đam mê mới — Người Yêu mời Trang Bị sắp xếp các giá trị với hành động trước khi tiến lên; mối quan hệ bắt đầu từ mong muốn chân thực sẽ nở rộ.", en: "The Lovers and Wands Page: a choice that sparks new passion — the Lovers invite the Page to align values with action before charging ahead; partnerships begun from authentic desire flourish." },
  "6_33": { vi: "Người Yêu và Kỵ Sĩ Gậy: theo đuổi điều yêu thương với trọn vẹn đam mê — lao về phía sự hợp nhất với sự cống hiến hoàn toàn; mối quan hệ sáng tạo hoặc lãng mạn thúc đẩy hành động táo bạo tiến lên.", en: "The Lovers and Wands Knight: the pursuit of the beloved with full passion — riding toward union with complete dedication; a romantic or creative partnership drives bold action forward." },
  "6_34": { vi: "Người Yêu và Nữ Hoàng Gậy: mối quan hệ đam mê tiếp thêm sức mạnh cho người sáng tạo tự tin — khi tình yêu hài hòa với mục đích sáng tạo, cả mối quan hệ lẫn công việc đều trở nên phi thường.", en: "The Lovers and Wands Queen: passionate partnership empowers the confident creator — when love aligns with creative purpose, both the relationship and the work become extraordinary." },
  "6_35": { vi: "Người Yêu và Vua Gậy: sự hợp nhất với tầm nhìn chung — sự hài hòa về giá trị của Người Yêu gặp sự lãnh đạo của Vua; cặp đôi quyền năng hoặc mối quan hệ liên kết có thể cùng nhau xây dựng điều gì đó vĩ đại.", en: "The Lovers and Wands King: union with shared vision — the Lovers' harmony of values meets the King's leadership; a power couple or aligned partnership that can build something great together." },
  "6_46": { vi: "Người Yêu và Trang Bị Cốc: mối tình đầu ngọt ngào — sự ngây thơ cảm xúc gặp lựa chọn sâu sắc của trái tim; một sự mở lòng dễ bị tổn thương và đẹp đẽ với tình cảm sâu sắc và kết nối chân thực.", en: "The Lovers and Cups Page: tender first love — emotional innocence meets the profound choice of the heart; a sweet, vulnerable opening to deep feeling and authentic connection." },
  "6_47": { vi: "Người Yêu và Kỵ Sĩ Cốc: cuộc tìm kiếm lãng mạn đạt đến đỉnh điểm — cả Người Yêu lẫn Kỵ Sĩ đều đi theo trái tim hoàn toàn; tình yêu lý tưởng sâu sắc đang chuyển động, đẹp đẽ nhưng hãy chú ý đến sự phi thực tế.", en: "The Lovers and Cups Knight: the romantic quest reaches its peak — both the Lovers and the Knight follow the heart completely; deep idealistic love in motion, beautiful but watch for impracticality." },
  "6_48": { vi: "Người Yêu và Nữ Hoàng Cốc: tình yêu được làm sâu sắc hơn bởi sự khôn ngoan từ bi — sự hợp nhất của Người Yêu được nuôi dưỡng và duy trì bởi trí tuệ cảm xúc của Nữ Hoàng; mối quan hệ chín chắn, trọn vẹn.", en: "The Lovers and Cups Queen: love deepened by compassionate wisdom — the Lovers' union is nurtured and sustained by the Queen's emotional intelligence; mature, fulfilling partnership." },
  "6_49": { vi: "Người Yêu và Vua Cốc: tình yêu bền lâu được neo đậu trong sự thành thục cảm xúc — lựa chọn của Người Yêu được tôn trọng qua sự hiện diện ổn định, từ bi của Vua; mối quan hệ sâu sắc được xây dựng để tồn tại.", en: "The Lovers and Cups King: enduring love grounded in emotional mastery — the Lovers' choice is honored through the King's steady, compassionate presence; deep partnership built to last." },
  "6_60": { vi: "Người Yêu và Trang Bị Kiếm: một lựa chọn đòi hỏi sự rõ ràng trí tuệ thành thật — sự tò mò sắc bén của Trang Bị giúp gỡ rối những giọng nói mâu thuẫn xung quanh một quyết định lớn; hãy suy nghĩ trước khi trái tim cam kết.", en: "The Lovers and Swords Page: a choice requiring honest mental clarity — the Page's sharp curiosity helps untangle conflicting voices around a major decision; think carefully before the heart commits." },
  "6_61": { vi: "Người Yêu và Kỵ Sĩ Kiếm: một nhát cắt quyết đoán qua sự do dự — Kỵ Sĩ buộc một lựa chọn không thể trì hoãn; hành động táo bạo theo sau khi các giá trị được làm rõ.", en: "The Lovers and Swords Knight: a decisive cut through indecision — the Knight forces a choice that cannot be postponed; bold action follows once values are clarified and the path is clear." },
  "6_62": { vi: "Người Yêu và Nữ Hoàng Kiếm: tình yêu được xem xét bởi nhận thức rõ ràng thành thật — sự thật sắc bén của Nữ Hoàng giúp Người Yêu nhìn mối quan hệ không có ảo tưởng; đôi khi tình yêu đòi hỏi sự thành thật khó khăn.", en: "The Lovers and Swords Queen: love examined by clear honest perception — the Queen's incisive truth helps see the relationship without illusion; sometimes love requires difficult honesty." },
  "6_63": { vi: "Người Yêu và Vua Kiếm: một lựa chọn lớn được phán xét bởi trí tuệ sắc bén — quyền uy lý trí của Vua có thể giúp điều hướng tình thế khó xử của Người Yêu, nhưng có nguy cơ bỏ qua sự khôn ngoan của trái tim.", en: "The Lovers and Swords King: a major choice judged by sharp intellect — the King's rational authority can help navigate the Lovers' dilemma, but risks overlooking the heart's deeper wisdom." },
  "6_74": { vi: "Người Yêu và Trang Bị Tiền: tình yêu bắt đầu bén rễ trong thực tế — sự hợp nhất của Người Yêu bắt đầu thể hiện theo những cách hữu hình, hàng ngày; các giá trị được sắp xếp với thực tế vật chất.", en: "The Lovers and Pentacles Page: love beginning to take practical root — the Lovers' union starts to express itself in tangible, everyday ways; values aligned with material reality." },
  "6_75": { vi: "Người Yêu và Kỵ Sĩ Tiền: mối quan hệ được xây dựng qua nỗ lực kiên nhẫn bền bỉ — mối liên kết của Người Yêu sâu sắc hơn qua công việc chung và cam kết thực tế thay vì chỉ lãng mạn.", en: "The Lovers and Pentacles Knight: a relationship built through patient, steady effort — the Lovers' bond deepens through shared work and practical commitment rather than romance alone." },
  "6_76": { vi: "Người Yêu và Nữ Hoàng Tiền: tình yêu được hiện thực hóa trong sự phong phú — sự hợp nhất của Người Yêu được nuôi dưỡng bởi sự quan tâm hào phóng, thực tế; một mối quan hệ tạo ra sự nở rộ thực sự trong thế giới vật chất.", en: "The Lovers and Pentacles Queen: love made manifest in abundance — the Lovers' union is nourished by generous, practical care; a relationship that produces real flourishing in the material world." },
  "6_77": { vi: "Người Yêu và Vua Tiền: mối quan hệ được neo đậu trong sự an toàn vật chất — các giá trị của Người Yêu hài hòa xung quanh việc cùng nhau xây dựng sự giàu có và di sản lâu dài; sự hợp nhất ổn định, thịnh vượng.", en: "The Lovers and Pentacles King: partnership grounded in material security — the Lovers' values align around building lasting wealth and legacy together; stable, prosperous union." },

  // Chariot (7) × Courts
  "7_32": { vi: "Cỗ Xe và Trang Bị Gậy: tham vọng có định hướng thổi bùng học trò trẻ — ý chí tập trung của Cỗ Xe kênh hóa sự nhiệt tình của Trang Bị thành hành động có mục đích hướng về phía trước.", en: "The Chariot and Wands Page: driven ambition fires up the young student — the Chariot's focused will channels the Page's enthusiasm into purposeful forward movement." },
  "7_33": { vi: "Cỗ Xe và Kỵ Sĩ Gậy: hai lực lượng của động lực tiến lên không ngừng — ý chí và đam mê liên kết; sức mạnh gần như không thể cản trở, nhưng hãy chú ý đến tầm nhìn hạn hẹp.", en: "The Chariot and Wands Knight: two forces of relentless forward momentum — willpower and passion fully aligned; an almost unstoppable drive, but watch for tunnel vision." },
  "7_34": { vi: "Cỗ Xe và Nữ Hoàng Gậy: ý chí có định hướng gặp sức mạnh sáng tạo tự tin — kỷ luật của Cỗ Xe khai thác ngọn lửa của Nữ Hoàng; các mục tiêu được theo đuổi với cả đam mê lẫn sự kiểm soát.", en: "The Chariot and Wands Queen: directed willpower meets confident creative power — the Chariot's discipline harnesses the Queen's fire; goals pursued with both passion and control." },
  "7_35": { vi: "Cỗ Xe và Vua Gậy: sự quyết tâm có kỷ luật gặp lãnh đạo có tầm nhìn — động lực chiến thắng của Cỗ Xe và tầm nhìn chiến lược của Vua tạo ra sự kết hợp gần như không thể ngăn cản.", en: "The Chariot and Wands King: disciplined determination meets visionary leadership — the Chariot's victory drive and the King's strategic vision create an almost unstoppable combination." },
  "7_46": { vi: "Cỗ Xe và Trang Bị Cốc: những động lực cảm xúc được kiểm soát và định hướng — Cỗ Xe dạy Trang Bị nhạy cảm cách lái cảm xúc hướng tới các mục tiêu rõ ràng thay vì bị cuốn trôi.", en: "The Chariot and Cups Page: emotional drives controlled and directed — the Chariot teaches the sensitive Page to steer feelings toward clear goals rather than being swept away." },
  "7_47": { vi: "Cỗ Xe và Kỵ Sĩ Cốc: sự theo đuổi lãng mạn được kỷ luật hóa bởi mục đích rõ ràng — Cỗ Xe giúp Kỵ Sĩ chọn một hướng rõ ràng thay vì đuổi theo mọi làn sóng cảm xúc.", en: "The Chariot and Cups Knight: romantic pursuit disciplined by clear purpose — the Chariot helps the Knight choose a clear direction rather than chasing every emotional wave." },
  "7_48": { vi: "Cỗ Xe và Nữ Hoàng Cốc: sự thành thạo cảm xúc cầm lái — sự quyết tâm kiểm soát của Cỗ Xe được hướng dẫn bởi trực giác sâu sắc của Nữ Hoàng tạo ra sự chuyển động mạnh mẽ, có chủ đích.", en: "The Chariot and Cups Queen: emotional mastery takes the wheel — the Chariot's controlled determination guided by the Queen's deep intuition creates powerful, intentional movement." },
  "7_49": { vi: "Cỗ Xe và Vua Cốc: sự thành thạo trên hai mặt trận — ý chí kiểm soát của Cỗ Xe và quyền uy cảm xúc của Vua kết hợp cho sự lãnh đạo quyết đoán, từ bi.", en: "The Chariot and Cups King: mastery on two fronts — the Chariot's controlled willpower and the King's emotional authority combine for decisive, compassionate leadership." },
  "7_60": { vi: "Cỗ Xe và Trang Bị Kiếm: sự rõ ràng trí tuệ thúc đẩy tiến trình tiến lên — Cỗ Xe khai thác trí tuệ sắc bén của Trang Bị; tư duy có kỷ luật trở thành phương tiện để đạt được các mục tiêu.", en: "The Chariot and Swords Page: mental clarity drives forward progress — the Chariot harnesses the Page's sharp intellect; disciplined thinking becomes the vehicle for achieving goals." },
  "7_61": { vi: "Cỗ Xe và Kỵ Sĩ Kiếm: hai lực lượng của hành động quyết đoán nhanh như chớp — động lực tối đa; khả năng phi thường để phá vỡ chướng ngại vật, nhưng có nguy cơ liều lĩnh ở tốc độ cao.", en: "The Chariot and Swords Knight: two forces of lightning-fast decisive action — maximum momentum; extraordinary ability to break through obstacles, but risk of recklessness at high speed." },
  "7_62": { vi: "Cỗ Xe và Nữ Hoàng Kiếm: chiến thắng được hướng dẫn bởi nhận thức sắc bén, rõ ràng — Cỗ Xe tiến lên với sự đánh giá thành thật của Nữ Hoàng là la bàn; sự chính xác và quyết tâm.", en: "The Chariot and Swords Queen: victory guided by sharp, clear-eyed perception — the Chariot moves forward with the Queen's honest assessment as its compass; precision and determination." },
  "7_63": { vi: "Cỗ Xe và Vua Kiếm: ý chí có kỷ luật được hỗ trợ bởi trí tuệ có thẩm quyền — sự kết hợp đáng gờm cho thành tựu chiến lược; lực lượng kiểm soát được định hướng bởi sự thành thạo phân tích.", en: "The Chariot and Swords King: disciplined willpower supported by authoritative intellect — a formidable pairing for strategic achievement; controlled force directed by analytical mastery." },
  "7_74": { vi: "Cỗ Xe và Trang Bị Tiền: nỗ lực có định hướng hướng tới các mục tiêu vật chất — sự tập trung của Cỗ Xe giúp Trang Bị duy trì đúng hướng trong việc học thực tế và các dự án ban đầu.", en: "The Chariot and Pentacles Page: determined effort toward material goals — the Chariot's focus helps the Page stay on course in practical studies and early ventures." },
  "7_75": { vi: "Cỗ Xe và Kỵ Sĩ Tiền: sự kiên trì bền bỉ được khuếch đại bởi ý chí có định hướng — Cỗ Xe và Kỵ Sĩ cùng nhau thể hiện tiến trình có phương pháp không thể cản về phía thành công vật chất.", en: "The Chariot and Pentacles Knight: steady persistence amplified by directed willpower — the Chariot and Knight together embody unstoppable methodical progress toward material success." },
  "7_76": { vi: "Cỗ Xe và Nữ Hoàng Tiền: tiến trình quyết tâm được nuôi dưỡng bởi sự phong phú thực tế — động lực của Cỗ Xe được duy trì bởi sự hỗ trợ ổn định, hào phóng của Nữ Hoàng; động lực được neo đậu trong tài nguyên.", en: "The Chariot and Pentacles Queen: determined progress nurtured by practical abundance — the Chariot's drive sustained by the Queen's steady, generous support; momentum grounded in resources." },
  "7_77": { vi: "Cỗ Xe và Vua Tiền: chiến thắng được mang lại qua sự thành thạo vật chất — sự quyết tâm của Cỗ Xe được xây dựng trên sự giàu có đã thiết lập của Vua; các mục tiêu đạt được thông qua kiểm soát và chỉ huy tài nguyên.", en: "The Chariot and Pentacles King: victory delivered through material mastery — the Chariot's determination builds on the King's established wealth; goals achieved through control and resource command." },

  // Strength (8) × Courts
  "8_32": { vi: "Sức Mạnh và Trang Bị Gậy: sự can đảm nhẹ nhàng làm ổn định ngọn lửa trẻ — Sức Mạnh dạy Trang Bị rằng sức mạnh thực sự là kiên nhẫn và từ bi, không chỉ là bùng nổ; sự thành thạo nội tâm vượt qua bốc đồng.", en: "Strength and Wands Page: gentle courage steadies the young fire — Strength teaches the Page that true power is patient and compassionate, not just explosive; inner mastery over impulse." },
  "8_33": { vi: "Sức Mạnh và Kỵ Sĩ Gậy: đam mê mãnh liệt được thuần hóa bởi sức mạnh nội tâm yên lặng — Sức Mạnh mời Kỵ Sĩ khai thác ngọn lửa thô với sự duyên dáng; hành động dũng cảm thấm nhuần sự khôn ngoan từ bi.", en: "Strength and Wands Knight: fierce passion tamed by quiet inner power — Strength invites the Knight to harness raw fire with grace; courageous action infused with compassionate wisdom." },
  "8_34": { vi: "Sức Mạnh và Nữ Hoàng Gậy: sự can đảm nội tâm gặp sự tự tin bên ngoài — cả hai đều thể hiện sự tự chủ rạng rỡ; cùng nhau họ tỏa ra sức mạnh có từ tính, được neo đậu sâu sắc, truyền cảm hứng cho người khác.", en: "Strength and Wands Queen: inner courage meets outward confidence — both embody radiant self-possession; together they project a magnetic, deeply grounded power that inspires others." },
  "8_35": { vi: "Sức Mạnh và Vua Gậy: sự thành thạo nội tâm yên lặng bên cạnh quyền uy bên ngoài — Sức Mạnh nhắc nhở Vua rằng sự lãnh đạo thực sự chảy từ sự tự chủ, không phải từ sức mạnh.", en: "Strength and Wands King: quiet inner mastery alongside outer authority — the Strength card reminds the King that true leadership flows from self-command, not from force." },
  "8_46": { vi: "Sức Mạnh và Trang Bị Cốc: sự can đảm từ bi trong những khởi đầu cảm xúc — Sức Mạnh dạy Trang Bị nhạy cảm rằng sự nhẹ nhàng là hình thức sức mạnh riêng của nó; hãy giữ cảm xúc bằng đôi tay ổn định, yêu thương.", en: "Strength and Cups Page: compassionate courage in emotional beginnings — Strength teaches the sensitive Page that gentleness is its own form of power; hold feelings with steady, loving hands." },
  "8_47": { vi: "Sức Mạnh và Kỵ Sĩ Cốc: trái tim dũng cảm của cuộc tìm kiếm lãng mạn — Sức Mạnh neo đậu chủ nghĩa lý tưởng của Kỵ Sĩ; lòng dũng cảm để duy trì cởi mở và yêu thương ngay cả khi trái tim đã bị tổn thương.", en: "Strength and Cups Knight: the brave heart of the romantic quest — Strength grounds the Knight's idealism; the courage to remain open and loving even when the heart has been hurt." },
  "8_48": { vi: "Sức Mạnh và Nữ Hoàng Cốc: sức mạnh nội tâm sâu sắc được thể hiện qua tình yêu từ bi — hai trong số những năng lượng nuôi dưỡng nhất của bộ bài; sâu sắc, kiên nhẫn và hào phóng bền vững.", en: "Strength and Cups Queen: deep inner strength expressed through compassionate love — two of the deck's most nurturing energies; profound, patient, and sustainably generous." },
  "8_49": { vi: "Sức Mạnh và Vua Cốc: sức mạnh bền vững nội tâm gặp sự khôn ngoan cảm xúc — sức mạnh yên lặng của sự tự chủ bên cạnh lòng từ bi chín chắn; sự hiện diện được neo đậu sâu sắc, không thể lay chuyển nhưng nhẹ nhàng.", en: "Strength and Cups King: inner fortitude meeting emotional wisdom — the quiet power of self-mastery alongside mature compassion; deeply centered, unshakeable yet gentle authority." },
  "8_60": { vi: "Sức Mạnh và Trang Bị Kiếm: sự kiên nhẫn với tâm trí đặt câu hỏi bồn chồn — Sức Mạnh khuyên Trang Bị giữ năng lượng trí tuệ với sự bình tĩnh kiểm soát; tư duy sắc bén được hướng dẫn bởi sự ổn định nội tâm.", en: "Strength and Swords Page: patience with the restless questioning mind — Strength counsels the Page to hold mental energy with calm control; sharp thinking guided by inner steadiness." },
  "8_61": { vi: "Sức Mạnh và Kỵ Sĩ Kiếm: sức mạnh yên lặng trước cuộc xung phong nhanh chóng — Sức Mạnh mời Kỵ Sĩ dừng lại; hành động từ sự tự tin sâu sắc thay vì tốc độ phản ứng.", en: "Strength and Swords Knight: quiet power before the swift charge — Strength invites the Knight to pause; act from deep self-assurance rather than reactive speed." },
  "8_62": { vi: "Sức Mạnh và Nữ Hoàng Kiếm: hai hình thức thành thạo nữ tính — sức mạnh từ bi nội tâm bên cạnh sự thật rõ ràng sắc bén; mạnh mẽ, được neo đậu và thành thật không khoan nhượng.", en: "Strength and Swords Queen: two forms of feminine mastery — inner compassionate strength alongside sharp clear truth; powerful, grounded, and unflinchingly honest." },
  "8_63": { vi: "Sức Mạnh và Vua Kiếm: sự tự chủ nội tâm bên cạnh quyền uy trí tuệ bên ngoài — Sức Mạnh gợi ý rằng quyền uy sắc bén của Vua hiệu quả nhất khi có gốc rễ trong sự kiên nhẫn và khôn ngoan.", en: "Strength and Swords King: inner self-mastery alongside outer intellectual command — Strength suggests even the King's sharp authority is most effective when rooted in patient wisdom." },
  "8_74": { vi: "Sức Mạnh và Trang Bị Tiền: sự can đảm nội tâm kiên nhẫn áp dụng cho việc học thực tế — Sức Mạnh khuyến khích Trang Bị kiên trì qua những thách thức vật chất với lòng từ bi cho quá trình học tập.", en: "Strength and Pentacles Page: patient inner courage applied to practical learning — Strength encourages the Page to persist through material challenges with compassion for the learning process." },
  "8_75": { vi: "Sức Mạnh và Kỵ Sĩ Tiền: lòng dũng cảm bền bỉ và nỗ lực có phương pháp — Sức Mạnh khuếch đại sự kiên trì của Kỵ Sĩ; sức mạnh nội tâm kiên nhẫn duy trì hành trình trần thế dài đến các mục tiêu vật chất.", en: "Strength and Pentacles Knight: steady courage and methodical effort — Strength amplifies the Knight's perseverance; patient inner power sustains the long, earthly journey toward material goals." },
  "8_76": { vi: "Sức Mạnh và Nữ Hoàng Tiền: sức mạnh nội tâm nuôi dưỡng sự phong phú bên ngoài — Sức Mạnh và Nữ Hoàng đều thể hiện sức mạnh hào phóng, kiên nhẫn; sự thịnh vượng được xây dựng từ sự tự chủ sâu sắc.", en: "Strength and Pentacles Queen: inner strength nurturing outer abundance — Strength and the Queen both embody patient, generous power; prosperity built from a foundation of deep self-possession." },
  "8_77": { vi: "Sức Mạnh và Vua Tiền: sự thành thạo nội tâm yên lặng bên cạnh quyền năng bên ngoài đã được thiết lập — Sức Mạnh nhắc nhở Vua rằng sự thành công vật chất bền lâu dựa trên nền tảng của tính cách, không chỉ là chỉ huy.", en: "Strength and Pentacles King: quiet inner mastery beside established outer power — Strength reminds the King that enduring material success rests on the foundation of character, not just command." },

  // Hermit (9) × Courts
  "9_32": { vi: "Ẩn Sĩ và Trang Bị Gậy: sự khôn ngoan của hành trình nội tâm được dâng tặng cho tuổi trẻ — Ẩn Sĩ hướng dẫn Trang Bị háo hức hãy chậm lại và tìm kiếm sự hiểu biết trước khi hành động theo sự nhiệt tình.", en: "The Hermit and Wands Page: the wisdom of the inner journey offered to youth — the Hermit guides the eager Page to slow down and seek understanding before acting on enthusiasm." },
  "9_33": { vi: "Ẩn Sĩ và Kỵ Sĩ Gậy: sự dừng lại trước cuộc xung phong — Ẩn Sĩ khuyên Kỵ Sĩ hãy rút lui ngắn ngủi, tìm kiếm định hướng nội tâm, rồi tiến lên với sự rõ ràng lớn hơn.", en: "The Hermit and Wands Knight: the pause before the charge — the Hermit counsels the Knight to withdraw briefly, seek inner direction, then ride forward with greater clarity and purpose." },
  "9_34": { vi: "Ẩn Sĩ và Nữ Hoàng Gậy: sự khôn ngoan nội tâm được dâng tặng cho người sáng tạo tự tin — Ẩn Sĩ mời Nữ Hoàng làm sâu sắc hơn ngọn lửa của cô qua sự chiêm nghiệm; sự sáng tạo mạnh mẽ từ một nơi có trung tâm.", en: "The Hermit and Wands Queen: introspective wisdom offered to the confident creator — the Hermit invites the Queen to deepen her fire through reflection; powerful creativity from a centered place." },
  "9_35": { vi: "Ẩn Sĩ và Vua Gậy: vị hiền nhân cô độc cố vấn cho nhà lãnh đạo có tầm nhìn — Ẩn Sĩ nhắc nhở Vua rằng sự khôn ngoan đòi hỏi những khoảnh khắc im lặng xa tiếng ồn của triều đình.", en: "The Hermit and Wands King: the solitary sage advises the visionary leader — the Hermit reminds the King that wisdom requires moments of silence away from the court's noise." },
  "9_46": { vi: "Ẩn Sĩ và Trang Bị Cốc: sự cô đơn dịu dàng cho khám phá cảm xúc — Ẩn Sĩ và Trang Bị cùng nhau khám phá những chiều sâu cảm xúc yên tĩnh; sự chiêm nghiệm nội tâm tiết lộ những sự thật cảm xúc.", en: "The Hermit and Cups Page: tender solitude for emotional discovery — the Hermit and Page together explore the quiet depths of feeling; inner reflection reveals emotional truths." },
  "9_47": { vi: "Ẩn Sĩ và Kỵ Sĩ Cốc: hành trình nội tâm đối mặt với cuộc tìm kiếm lãng mạn bên ngoài — Ẩn Sĩ yêu cầu Kỵ Sĩ tìm kiếm điều yêu thương từ bên trong trước khi theo đuổi nó từ bên ngoài.", en: "The Hermit and Cups Knight: the inner journey versus the outward romantic quest — the Hermit asks the Knight to seek the beloved within before pursuing it without." },
  "9_48": { vi: "Ẩn Sĩ và Nữ Hoàng Cốc: sự khôn ngoan sâu sắc được chia sẻ với lòng từ bi sâu sắc — Ẩn Sĩ và Nữ Hoàng đều mang sự khôn ngoan được kiếm qua hành trình nội tâm; một cuộc gặp gỡ sâu sắc của hai ánh sáng dịu dàng.", en: "The Hermit and Cups Queen: deep wisdom shared with deep compassion — both carry wisdom earned through inner journeys; a profound meeting of two gentle lights." },
  "9_49": { vi: "Ẩn Sĩ và Vua Cốc: hai hình thức sự khôn ngoan nội tâm sâu sắc — sự chiêm nghiệm cô độc bên cạnh sự chín chắn được neo đậu trong cảm xúc; cả hai đã đi xa bên trong; sự hiểu biết chảy tự nhiên ở đây.", en: "The Hermit and Cups King: two forms of deep inner wisdom — solitary contemplation beside emotionally rooted maturity; both have traveled far within; understanding flows easily here." },
  "9_60": { vi: "Ẩn Sĩ và Trang Bị Kiếm: người tìm kiếm nội tâm và tâm trí đặt câu hỏi — Ẩn Sĩ khuyến khích sự tò mò của Trang Bị đi sâu hơn, vượt ra ngoài phân tích bề mặt vào sự khôn ngoan thực sự.", en: "The Hermit and Swords Page: the inner seeker and the questioning mind — the Hermit encourages the Page's curiosity to go deeper, beyond surface analysis into genuine wisdom." },
  "9_61": { vi: "Ẩn Sĩ và Kỵ Sĩ Kiếm: vị hiền nhân và chiến binh — Ẩn Sĩ yêu cầu Kỵ Sĩ thực hiện rút lui chiến thuật và tìm kiếm sự khôn ngoan trước bước di chuyển quyết đoán tiếp theo.", en: "The Hermit and Swords Knight: the sage and the warrior — the Hermit asks the Knight to take a tactical retreat and seek wisdom before the next decisive move." },
  "9_62": { vi: "Ẩn Sĩ và Nữ Hoàng Kiếm: sự khôn ngoan cô độc gặp nhận thức rõ ràng thành thật — cả hai đều nhìn vào sự thật không do dự; Ẩn Sĩ và Nữ Hoàng cùng nhau có thể soi sáng ngay cả những góc tối nhất.", en: "The Hermit and Swords Queen: solitary wisdom meets clear honest perception — both look at truth unflinchingly; the Hermit and Queen together can illuminate even the darkest corners." },
  "9_63": { vi: "Ẩn Sĩ và Vua Kiếm: sự khôn ngoan nội tâm bên cạnh quyền uy trí tuệ bên ngoài — Ẩn Sĩ mời Vua xem xét rằng những phán xét sâu sắc nhất nảy sinh từ sự yên tĩnh thay vì từ chỉ huy.", en: "The Hermit and Swords King: inner wisdom alongside outer intellectual authority — the Hermit invites the King to consider that the deepest judgments emerge from quiet rather than command." },
  "9_74": { vi: "Ẩn Sĩ và Trang Bị Tiền: hướng dẫn nội tâm cho những khởi đầu vật chất — Ẩn Sĩ dạy học trò rằng việc học có giá trị nhất đến từ bên trong; sự khôn ngoan thực tế từ quan sát cẩn thận.", en: "The Hermit and Pentacles Page: inner guidance for material beginnings — the Hermit teaches the student that the most valuable learning comes from within; practical wisdom from careful observation." },
  "9_75": { vi: "Ẩn Sĩ và Kỵ Sĩ Tiền: sự khôn ngoan nội tâm chậm rãi bên cạnh nỗ lực bên ngoài có phương pháp — Ẩn Sĩ xác nhận cách tiếp cận kiên nhẫn của Kỵ Sĩ; soi sáng con đường từng bước cẩn thận một.", en: "The Hermit and Pentacles Knight: slow steady inner wisdom alongside methodical outer effort — the Hermit confirms the Knight's patient approach; illuminating the path one careful step at a time." },
  "9_76": { vi: "Ẩn Sĩ và Nữ Hoàng Tiền: sự khôn ngoan yên tĩnh nuôi dưỡng sự phong phú thực tế — ánh sáng nội tâm của Ẩn Sĩ giúp Nữ Hoàng biết nơi định hướng những món quà hào phóng của cô để đạt hiệu quả bền vững tối đa.", en: "The Hermit and Pentacles Queen: quiet wisdom nurturing practical abundance — the Hermit's inner light helps the Queen know where to direct her generous gifts for maximum sustainable effect." },
  "9_77": { vi: "Ẩn Sĩ và Vua Tiền: vị hiền nhân và người gia trưởng đã được thiết lập — Ẩn Sĩ nhắc nhở Vua rằng sự giàu có thực sự bao gồm sự khôn ngoan để biết điều gì thực sự quan trọng.", en: "The Hermit and Pentacles King: the sage and the established patriarch — the Hermit reminds the King that true wealth includes the wisdom to know what truly matters." },

  // Wheel of Fortune (10) × Courts
  "10_32": { vi: "Bánh Xe Số Mệnh và Trang Bị Gậy: một bước ngoặt trong hành trình của ngọn lửa trẻ — Bánh Xe mang đến cơ hội hoặc sự thay đổi bất ngờ; Trang Bị phải sẵn sàng nắm bắt thời điểm khi vận may quay.", en: "The Wheel of Fortune and Wands Page: a turning point in a young fire's journey — the Wheel brings unexpected opportunity or change; the Page must be ready to seize the moment when fortune spins." },
  "10_33": { vi: "Bánh Xe Số Mệnh và Kỵ Sĩ Gậy: số phận tăng tốc cuộc xung phong táo bạo — Bánh Xe quay theo hướng có lợi cho Kỵ Sĩ, khuếch đại động lực; hãy lướt theo làn sóng vận may với nhận thức về sự vô thường của nó.", en: "The Wheel of Fortune and Wands Knight: fate accelerates the bold charge — the Wheel turns in the Knight's favor, amplifying momentum; ride the wave of fortune with awareness of its impermanence." },
  "10_34": { vi: "Bánh Xe Số Mệnh và Nữ Hoàng Gậy: vận may ủng hộ người táo bạo và sáng tạo — Bánh Xe mang lại sự thay đổi lớn cho người sáng tạo tự tin; các chu kỳ quay về phía quyền năng và cơ hội lớn hơn.", en: "The Wheel of Fortune and Wands Queen: fortune favors the bold and creative — the Wheel brings a major shift; cycles turn toward greater power and opportunity for the confident creator." },
  "10_35": { vi: "Bánh Xe Số Mệnh và Vua Gậy: vận may đang quay đối với nhà lãnh đạo đã được thiết lập — một thời điểm then chốt thử thách tầm nhìn của Vua; các chu kỳ quyền lực dịch chuyển, đòi hỏi khả năng thích nghi bên cạnh quyền uy.", en: "The Wheel of Fortune and Wands King: the turning of fortune for the established leader — a pivotal moment that tests the King's vision; cycles of power shift, requiring adaptability alongside authority." },
  "10_46": { vi: "Bánh Xe Số Mệnh và Trang Bị Cốc: những dòng chảy cảm xúc đang quay — Bánh Xe mang lại một chương cảm xúc mới cho người mới bắt đầu nhạy cảm; điều từng áp đảo tìm thấy nhịp điệu tự nhiên của nó.", en: "The Wheel of Fortune and Cups Page: emotional tides turning — the Wheel brings a new emotional chapter for the sensitive beginner; what was overwhelming finds its natural rhythm." },
  "10_47": { vi: "Bánh Xe Số Mệnh và Kỵ Sĩ Cốc: bánh xe của vận may lãng mạn — số phận can thiệp vào cuộc tìm kiếm của Kỵ Sĩ; một cuộc gặp gỡ được định trước hoặc một bước ngoặt cảm xúc bất ngờ thay đổi hướng đi của hành trình.", en: "The Wheel of Fortune and Cups Knight: the wheel of romantic fortune — fate intervenes in the Knight's quest; a destined meeting or an unexpected emotional turning point shifts the journey's direction." },
  "10_48": { vi: "Bánh Xe Số Mệnh và Nữ Hoàng Cốc: các chu kỳ nuôi dưỡng và phong phú đang dịch chuyển — Bánh Xe mang lại những thay đổi cho cảnh quan cảm xúc; sự khôn ngoan của Nữ Hoàng điều hướng những dòng chảy thay đổi với sự duyên dáng.", en: "The Wheel of Fortune and Cups Queen: cycles of nurturing and abundance shifting — the Wheel brings changes to the emotional landscape; the Queen's wisdom navigates the turning tides with grace." },
  "10_49": { vi: "Bánh Xe Số Mệnh và Vua Cốc: số phận gặp sự khôn ngoan cảm xúc chín chắn — sự quay của Bánh Xe được đáp lại bởi chiều sâu ổn định của Vua; sự thay đổi được điều hướng với sự bình tĩnh từ bi.", en: "The Wheel of Fortune and Cups King: fate meets mature emotional wisdom — the Wheel's turn is met by the King's steady depth; change is navigated with compassionate equanimity." },
  "10_60": { vi: "Bánh Xe Số Mệnh và Trang Bị Kiếm: một bước ngoặt trí tuệ — số phận mang lại thông tin hoặc quan điểm mới định hình lại sự hiểu biết của người tư duy trẻ; hãy sẵn sàng xem xét lại ý kiến khi Bánh Xe quay.", en: "The Wheel of Fortune and Swords Page: a mental turning point — fate brings new information or perspective that reshapes the young thinker's understanding; be ready to revise opinions as the Wheel turns." },
  "10_61": { vi: "Bánh Xe Số Mệnh và Kỵ Sĩ Kiếm: vận may can thiệp vào cuộc xung phong quyết đoán — Bánh Xe có thể chuyển hướng con đường của Kỵ Sĩ bất ngờ; hãy thích nghi nhanh chóng với hướng thay đổi của số phận.", en: "The Wheel of Fortune and Swords Knight: fortune intervenes in the decisive charge — the Wheel may redirect the Knight's path unexpectedly; adapt swiftly to the changing direction of fate." },
  "10_62": { vi: "Bánh Xe Số Mệnh và Nữ Hoàng Kiếm: sự rõ ràng về sự quay của các chu kỳ — trí tuệ nhạy cảm của Nữ Hoàng đọc được các mô hình của Bánh Xe; hiểu khi nào cần hành động và khi nào cần chờ đợi bước đi tiếp theo của vận may.", en: "The Wheel of Fortune and Swords Queen: clarity about the turning of cycles — the Queen's perceptive intelligence reads the Wheel's patterns; understanding when to act and when to wait for fortune's next move." },
  "10_63": { vi: "Bánh Xe Số Mệnh và Vua Kiếm: sự khôn ngoan chiến lược gặp sự quay của số phận — quyền uy phân tích của Vua giúp điều hướng các chu kỳ thay đổi lớn; hiểu các mô hình của vận may thay vì chống lại chúng.", en: "The Wheel of Fortune and Swords King: strategic wisdom meets the turning of fate — the King's analytical authority helps navigate major cycles of change; understanding fortune's patterns rather than resisting them." },
  "10_74": { vi: "Bánh Xe Số Mệnh và Trang Bị Tiền: một cơ hội may mắn trong những khởi đầu vật chất — Bánh Xe quay về phía cơ hội cho học trò háo hức; hãy sẵn sàng nhận ra và hành động theo vận may thực tế tốt.", en: "The Wheel of Fortune and Pentacles Page: a lucky break in material beginnings — the Wheel turns toward opportunity for the eager student; be ready to recognize and act on practical good fortune." },
  "10_75": { vi: "Bánh Xe Số Mệnh và Kỵ Sĩ Tiền: nỗ lực kiên nhẫn được sắp xếp với sự quay của vận may — Bánh Xe thưởng cho công sức bền bỉ của Kỵ Sĩ bằng cơ hội được phối hợp tốt; sự kiên trì gặp được thời điểm của nó.", en: "The Wheel of Fortune and Pentacles Knight: patient effort aligned with fortune's turning — the Wheel rewards the Knight's steady work with well-timed opportunity; persistence meets its moment." },
  "10_76": { vi: "Bánh Xe Số Mệnh và Nữ Hoàng Tiền: các chu kỳ phong phú và hào phóng — Bánh Xe quay qua các mùa thịnh vượng vật chất; sự khôn ngoan ổn định của Nữ Hoàng duy trì sự thịnh vượng qua các chu kỳ.", en: "The Wheel of Fortune and Pentacles Queen: cycles of abundance and generosity — the Wheel turns through seasons of material flourishing; the Queen's steady wisdom sustains prosperity through the cycles." },
  "10_77": { vi: "Bánh Xe Số Mệnh và Vua Tiền: sự quay của vận may trong sự giàu có đã được thiết lập — Bánh Xe có thể mang lại những thay đổi cho lãnh địa vật chất của Vua; sự quản lý khôn ngoan điều hướng các chu kỳ thay đổi.", en: "The Wheel of Fortune and Pentacles King: fortune's turning within established wealth — the Wheel may bring shifts to the King's material dominion; wise stewardship navigates cycles of change." },

  // Justice (11) × Courts
  "11_32": { vi: "Công Lý và Trang Bị Gậy: ngọn lửa trẻ phải chịu trách nhiệm — Công Lý yêu cầu Trang Bị xem xét hậu quả trước khi hành động; tính chính trực và sự thành thật phải hướng dẫn những khởi đầu mới.", en: "Justice and Wands Page: the young fire held to account — Justice asks the Page to consider consequences before acting; integrity and honesty must guide new beginnings." },
  "11_33": { vi: "Công Lý và Kỵ Sĩ Gậy: hành động gặp trách nhiệm — cuộc xung phong của Kỵ Sĩ được xem xét bởi cân bằng của Công Lý; hành động táo bạo chỉ được biện minh khi được neo đậu trong sự công bằng và sự thật.", en: "Justice and Wands Knight: action meets accountability — the Knight's charge is examined by Justice's scales; bold action is justified only when grounded in fairness and truth." },
  "11_34": { vi: "Công Lý và Nữ Hoàng Gậy: quyền năng sáng tạo được sắp xếp với sự công bằng — Công Lý mời Nữ Hoàng xem xét tác động công bằng của những hành động tự tin của cô; quyền lực được sử dụng với tính chính trực.", en: "Justice and Wands Queen: creative power aligned with fairness — Justice invites the Queen to consider the equitable impact of her confident actions; power used with integrity." },
  "11_35": { vi: "Công Lý và Vua Gậy: sự lãnh đạo được xem xét bởi cân bằng của Công Lý — tầm nhìn của Vua phải vượt qua bài kiểm tra sự công bằng; quyền uy vĩ đại mang theo sức nặng của trách nhiệm.", en: "Justice and Wands King: leadership examined by Justice's scales — the King's vision must pass the test of fairness; great authority carries the weight of accountability." },
  "11_46": { vi: "Công Lý và Trang Bị Cốc: sự thật cảm xúc được giữ theo tiêu chuẩn công bằng — Công Lý yêu cầu người mới bắt đầu nhạy cảm hãy thành thật về cảm xúc; hãy tránh tự lừa dối trong các vấn đề cảm xúc.", en: "Justice and Cups Page: emotional truth held to a fair standard — Justice asks the sensitive beginner to be honest about feelings; avoid self-deception in emotional matters." },
  "11_47": { vi: "Công Lý và Kỵ Sĩ Cốc: chủ nghĩa lý tưởng lãng mạn được phán xét bởi sự công bằng — Công Lý mời Kỵ Sĩ xem xét liệu sự theo đuổi của anh có tôn trọng sự thật của tình huống không; tình yêu này có công bằng không?", en: "Justice and Cups Knight: romantic idealism judged by fairness — Justice invites the Knight to examine whether his pursuit honors the truth of the situation; is this love equitable?" },
  "11_48": { vi: "Công Lý và Nữ Hoàng Cốc: sự khôn ngoan từ bi và sự phán xét công bằng — Công Lý và Nữ Hoàng cùng nhau mang đến sự tích hợp đẹp đẽ của lòng tốt và trách nhiệm; lời khuyên khôn ngoan, cân bằng.", en: "Justice and Cups Queen: compassionate wisdom and fair judgment — Justice and the Queen together offer a beautiful integration of kindness and accountability; wise, balanced counsel." },
  "11_49": { vi: "Công Lý và Vua Cốc: quyền uy cảm xúc được thực thi với sự công bằng hoàn hảo — sự khôn ngoan từ bi của Vua hài hòa với cân bằng của Công Lý; sự lãnh đạo sâu sắc nhân văn và công bằng.", en: "Justice and Cups King: emotional authority exercised with perfect fairness — the King's compassionate wisdom aligns with Justice's scales; deeply humane and equitable leadership." },
  "11_60": { vi: "Công Lý và Trang Bị Kiếm: trí tuệ trẻ sắc bén phục vụ sự thật — Công Lý hài hòa hoàn hảo với tình yêu tìm kiếm thành thật của Trang Bị; tính chính trực trí tuệ và lòng dũng cảm đi theo sự thật bất kể nó dẫn đến đâu.", en: "Justice and Swords Page: sharp young intellect serving truth — Justice aligns perfectly with the Page's love of honest inquiry; intellectual integrity and the courage to follow truth wherever it leads." },
  "11_61": { vi: "Công Lý và Kỵ Sĩ Kiếm: hành động quyết đoán trong phục vụ công lý — thanh kiếm của Kỵ Sĩ vung lên bảo vệ điều đúng; sự biểu hiện rõ ràng nhất của sức mạnh cao quý, chính trực.", en: "Justice and Swords Knight: decisive action in service of justice — the Knight's sword swings in defense of what is right; the clearest expression of noble, righteous force." },
  "11_62": { vi: "Công Lý và Nữ Hoàng Kiếm: hai trong số những lá bài hướng về sự thật nhất của bộ bài — Công Lý và Nữ Hoàng cùng nhau cắt đến tận cùng của những gì thực sự và công bằng; không khoan nhượng, thành thật và chính đáng.", en: "Justice and Swords Queen: two of the deck's most truth-oriented cards — Justice and the Queen together cut to the heart of what is real and fair; uncompromising, honest, and just." },
  "11_63": { vi: "Công Lý và Vua Kiếm: luật pháp và quyền uy trí tuệ hợp nhất — biểu hiện cao nhất của quản trị công bằng; quyền lực phân tích của Vua được định hướng hoàn toàn về phía sự công bằng và trách nhiệm.", en: "Justice and Swords King: law and intellectual authority united — the highest expression of fair governance; the King's analytical power directed entirely toward equity and accountability." },
  "11_74": { vi: "Công Lý và Trang Bị Tiền: tính chính trực trong những khởi đầu vật chất — Công Lý hướng dẫn học trò xây dựng kỹ năng thực tế và sự giàu có qua nỗ lực thành thật; nền tảng của nghiệp quả là những gì bạn thực sự kiếm được.", en: "Justice and Pentacles Page: integrity in material beginnings — Justice guides the student to build practical skills and wealth through honest effort; the foundation of karma is what you truly earn." },
  "11_75": { vi: "Công Lý và Kỵ Sĩ Tiền: phần thưởng công bằng cho lao động kiên nhẫn thành thật — Công Lý xác nhận công sức bền bỉ của Kỵ Sĩ; những gì được xây dựng qua tính chính trực sẽ đứng vững và được công nhận.", en: "Justice and Pentacles Knight: fair reward for patient, honest labor — Justice confirms the Knight's steady work; what is built through integrity will stand and be recognized." },
  "11_76": { vi: "Công Lý và Nữ Hoàng Tiền: sự phong phú hào phóng được hướng dẫn bởi các nguyên tắc công bằng — Công Lý hài hòa với sự khôn ngoan thực tế của Nữ Hoàng; sự thịnh vượng được phân phối với sự công bằng và đạo đức.", en: "Justice and Pentacles Queen: generous abundance guided by fair principles — Justice aligns with the Queen's practical wisdom; prosperity distributed with equity and ethical care." },
  "11_77": { vi: "Công Lý và Vua Tiền: sự thành thạo vật chất được giữ theo tiêu chuẩn tính chính trực cao nhất — sự giàu có và quyền lực của Vua là bằng chứng rằng công lý và thịnh vượng có thể cùng tồn tại; di sản được xây dựng trên sự công bằng.", en: "Justice and Pentacles King: material mastery held to the highest standards of integrity — the King's wealth and power stand as proof that justice and prosperity can coexist; legacy built on fairness." },

  // Hanged Man (12) × Courts
  "12_32": { vi: "Người Bị Treo và Trang Bị Gậy: sự dừng lại biến đổi tất cả — Người Bị Treo yêu cầu Trang Bị háo hức hãy đình chỉ hành động và nhìn từ một góc độ mới; sự khôn ngoan kiếm được trong sự tĩnh lặng thay đổi mọi thứ.", en: "The Hanged Man and Wands Page: the pause that transforms everything — the Hanged Man asks the eager Page to suspend action and see from a new angle; wisdom earned in stillness changes everything." },
  "12_33": { vi: "Người Bị Treo và Kỵ Sĩ Gậy: điều khó nhất đối với Kỵ Sĩ đang xung phong là dừng lại — Người Bị Treo đòi hỏi sự buông bỏ trước khi tiến lên tiếp; những sự khải thị chỉ đến qua sự đình chỉ tự nguyện.", en: "The Hanged Man and Wands Knight: the hardest thing for the charging Knight — stopping. The Hanged Man demands surrender before the next advance; revelations come only through willing suspension." },
  "12_34": { vi: "Người Bị Treo và Nữ Hoàng Gậy: quyền năng sáng tạo được giữ trong sự đình chỉ tạm thời — Người Bị Treo mời Nữ Hoàng để ngọn lửa của cô được nghỉ ngơi; những tầm nhìn sáng tạo mới nảy sinh từ góc nhìn khác.", en: "The Hanged Man and Wands Queen: creative power held in temporary suspension — the Hanged Man invites the Queen to let her fire rest; new creative visions emerge from a different vantage point." },
  "12_35": { vi: "Người Bị Treo và Vua Gậy: nhà lãnh đạo phải chờ đợi — Người Bị Treo yêu cầu Vua tạm thời từ bỏ sự kiểm soát; một góc nhìn khác có thể tiết lộ một con đường tốt hơn phía trước.", en: "The Hanged Man and Wands King: the leader who must wait — the Hanged Man asks the King to surrender control temporarily; a different perspective may reveal a better path forward." },
  "12_46": { vi: "Người Bị Treo và Trang Bị Cốc: sự buông bỏ cảm xúc và sự kỳ diệu — Người Bị Treo và Trang Bị cùng nhau trôi nổi trong không gian cởi mở tiếp nhận; cảm xúc được nhận lấy thay vì được theo đuổi.", en: "The Hanged Man and Cups Page: emotional surrender and wonder — the Hanged Man and the Page together float in a space of receptive openness; feelings are received rather than pursued." },
  "12_47": { vi: "Người Bị Treo và Kỵ Sĩ Cốc: cuộc theo đuổi lãng mạn bị đình chỉ — Người Bị Treo yêu cầu Kỵ Sĩ ngừng đuổi theo và để tình yêu đến; sự buông bỏ tiết lộ những gì nỗ lực không thể tìm thấy.", en: "The Hanged Man and Cups Knight: romantic pursuit suspended — the Hanged Man asks the Knight to stop chasing and allow love to arrive; surrender reveals what striving cannot." },
  "12_48": { vi: "Người Bị Treo và Nữ Hoàng Cốc: buông mình vào lòng từ bi sâu sắc — Người Bị Treo và Nữ Hoàng cùng nhau tạo ra không gian tiếp nhận sâu sắc và sự khôn ngoan cảm xúc; hãy buông bỏ và nhận lấy.", en: "The Hanged Man and Cups Queen: surrendering into deep compassion — the Hanged Man and Queen together create a space of profound receptivity and emotional wisdom; let go and receive." },
  "12_49": { vi: "Người Bị Treo và Vua Cốc: sự hi sinh tự nguyện của người khôn ngoan về mặt cảm xúc — Người Bị Treo gặp chiều sâu của Vua; cả hai đều biết giá trị của sự buông bỏ tự nguyện để có sự hiểu biết lớn hơn.", en: "The Hanged Man and Cups King: the willing sacrifice of the emotionally wise — the Hanged Man meets the King's depth; both know the value of voluntary surrender for greater understanding." },
  "12_60": { vi: "Người Bị Treo và Trang Bị Kiếm: tâm trí đặt câu hỏi được đặt trong sự đình chỉ — Người Bị Treo yêu cầu Trang Bị ngừng phân tích và chỉ đơn giản là quan sát; sự thật đến trong khoảng dừng giữa các suy nghĩ.", en: "The Hanged Man and Swords Page: the questioning mind placed in suspension — the Hanged Man asks the Page to stop analyzing and simply observe; truth arrives in the pause between thoughts." },
  "12_61": { vi: "Người Bị Treo và Kỵ Sĩ Kiếm: thanh kiếm vẫn trong vỏ bao — Người Bị Treo dừng Kỵ Sĩ giữa chừng; chỉ bằng cách từ bỏ nhu cầu hành động ngay bây giờ mới có thể nhìn thấy một con đường rõ ràng.", en: "The Hanged Man and Swords Knight: the sword stays sheathed — the Hanged Man stops the Knight mid-charge; only by surrendering the need to act now can a clear path be seen." },
  "12_62": { vi: "Người Bị Treo và Nữ Hoàng Kiếm: sự rõ ràng tìm thấy qua góc nhìn khác — tâm trí nhạy bén của Nữ Hoàng đạt được cái nhìn sâu sắc mới khi Người Bị Treo đảo ngược quan điểm của cô.", en: "The Hanged Man and Swords Queen: clarity found through a different vantage point — the Queen's perceptive mind gains new insight when the Hanged Man inverts her perspective." },
  "12_63": { vi: "Người Bị Treo và Vua Kiếm: quyền uy bị đình chỉ — Người Bị Treo thách thức sự chắc chắn của Vua; đôi khi phán xét khôn ngoan nhất là giữ phán quyết cho đến khi một góc nhìn mới đến.", en: "The Hanged Man and Swords King: the suspended authority — the Hanged Man challenges the King's certainty; sometimes the wisest judgment is to hold the verdict until a new perspective arrives." },
  "12_74": { vi: "Người Bị Treo và Trang Bị Tiền: những nỗ lực vật chất được đặt sang một bên — Người Bị Treo yêu cầu học trò dừng lại và xem xét lại những gì thực sự đáng xây dựng; sự thay đổi ưu tiên đang đến.", en: "The Hanged Man and Pentacles Page: material pursuits placed on hold — the Hanged Man asks the student to pause and reassess what is truly worth building; a shift in priorities is coming." },
  "12_75": { vi: "Người Bị Treo và Kỵ Sĩ Tiền: con đường chậm rãi còn trở nên chậm hơn — Người Bị Treo thúc giục một sự dừng lại sâu hơn nữa trong hành trình có phương pháp của Kỵ Sĩ; cái nhìn sâu sắc đạt được bây giờ sẽ tiết kiệm công sức sau này.", en: "The Hanged Man and Pentacles Knight: the slow path made slower — the Hanged Man urges an even deeper pause in the Knight's methodical journey; insight gained now saves considerable effort later." },
  "12_76": { vi: "Người Bị Treo và Nữ Hoàng Tiền: để sự phong phú đến thay vì cố nắm lấy nó — Người Bị Treo dạy Nữ Hoàng rằng đôi khi hành động tạo ra nhất là chờ đợi và tiếp nhận.", en: "The Hanged Man and Pentacles Queen: letting abundance come rather than grasping for it — the Hanged Man teaches the Queen that sometimes the most generative act is to wait and receive." },
  "12_77": { vi: "Người Bị Treo và Vua Tiền: người gia trưởng phải buông bỏ — Người Bị Treo yêu cầu ngay cả Vua đã được thiết lập nhất hãy buông bỏ sự kiểm soát của mình; một tầm nhìn mới về sự thịnh vượng đang chờ đợi sự buông bỏ tự nguyện.", en: "The Hanged Man and Pentacles King: the patriarch who must surrender — the Hanged Man asks even the most established King to release his grip; a new vision of prosperity awaits the willing surrender." },

  // Death (13) × Courts
  "13_32": { vi: "Thần Chết và Trang Bị Gậy: sự kết thúc của một chương sáng tạo trước khi chương mới bắt đầu — Thần Chết xóa bỏ sự nhiệt tình cũ để nhường chỗ cho ngọn lửa tươi mới, chân thực hơn.", en: "Death and Wands Page: the end of one creative chapter before a new one begins — Death clears the old enthusiasm to make room for a fresher, more authentic fire." },
  "13_33": { vi: "Thần Chết và Kỵ Sĩ Gậy: cuộc xung phong dẫn đến sự biến đổi — Thần Chết đánh dấu sự kết thúc của một hướng và sự bắt đầu của hướng khác; cuộc tìm kiếm phải thay đổi hướng đi một cách cơ bản.", en: "Death and Wands Knight: the charge that leads to transformation — Death marks the end of one direction and the beginning of another; the quest must fundamentally change course." },
  "13_34": { vi: "Thần Chết và Nữ Hoàng Gậy: sự biến đổi sáng tạo — Thần Chết và Nữ Hoàng cùng nhau báo hiệu sự lột xác lớn của các bản sắc cũ; những gì trỗi dậy từ tro tàn sẽ chân thực và mạnh mẽ hơn.", en: "Death and Wands Queen: creative transformation — Death and the Queen signal a major shedding of old identities; what rises from the ashes will be more authentic and powerful." },
  "13_35": { vi: "Thần Chết và Vua Gậy: sự lãnh đạo phải được tái sinh — Thần Chết kêu gọi sự kết thúc của tầm nhìn hoặc quyền uy cũ; những gì được biến đổi sẽ nổi lên mạnh mẽ hơn và phù hợp hơn với mục đích thực sự.", en: "Death and Wands King: leadership must be reborn — Death calls for the end of an old vision or authority; what transforms will emerge stronger and more aligned with true purpose." },
  "13_46": { vi: "Thần Chết và Trang Bị Cốc: sự kết thúc của sự ngây thơ cảm xúc — Thần Chết mang lại sự khai tâm cần thiết vào cảm xúc sâu sắc hơn; trái tim dịu dàng học rằng sự mất mát là một phần của toàn bộ phổ tình yêu.", en: "Death and Cups Page: the end of emotional innocence — Death brings a necessary initiation into deeper feeling; the tender heart learns that loss is part of the full spectrum of love." },
  "13_47": { vi: "Thần Chết và Kỵ Sĩ Cốc: một chương lãng mạn khép lại — Thần Chết kết thúc một cuộc tìm kiếm cảm xúc để một cuộc tìm kiếm sâu sắc hơn, chân thực hơn có thể bắt đầu; sự biến đổi của ý nghĩa tình yêu.", en: "Death and Cups Knight: a romantic chapter closes — Death ends one emotional quest so a deeper, more authentic pursuit can begin; transformation of what love truly means." },
  "13_48": { vi: "Thần Chết và Nữ Hoàng Cốc: sự biến đổi sâu sắc của bản thân nuôi dưỡng — Thần Chết và Nữ Hoàng báo hiệu sự kết thúc của một cách quan tâm cũ; những gì được tái sinh sẽ khôn ngoan hơn và bền vững hơn trong sự cho đi.", en: "Death and Cups Queen: profound transformation of the nurturing self — Death and the Queen signal the end of an old way of caring; what is reborn will be wiser and more sustainably giving." },
  "13_49": { vi: "Thần Chết và Vua Cốc: vị vua cảm xúc được biến đổi — Thần Chết mang lại sự thay đổi lớn cho quyền uy cảm xúc; những gì được lột bỏ không còn cần thiết; những gì còn lại là sự khôn ngoan sâu sắc, chân thực nhất.", en: "Death and Cups King: the emotional king transformed — Death brings a major shift to emotional authority; what is shed is no longer needed; what remains is the truest, deepest wisdom." },
  "13_60": { vi: "Thần Chết và Trang Bị Kiếm: các mô hình tư duy cũ phải chết đi — Thần Chết yêu cầu tâm trí trẻ sắc bén hãy buông bỏ các khung tinh thần lỗi thời; sự tái sinh trí tuệ theo sau sự buông bỏ.", en: "Death and Swords Page: old thinking patterns must die — Death asks the sharp young mind to release outdated mental frameworks; intellectual rebirth follows the letting go." },
  "13_61": { vi: "Thần Chết và Kỵ Sĩ Kiếm: chiến binh được biến đổi — Thần Chết kết thúc một trận chiến để một cuộc chiến có ý nghĩa hơn có thể bắt đầu; bản chất của những gì đáng chiến đấu được biến đổi hoàn toàn.", en: "Death and Swords Knight: the warrior transformed — Death ends one battle so a more meaningful fight can begin; the nature of what is worth fighting for is radically transformed." },
  "13_62": { vi: "Thần Chết và Nữ Hoàng Kiếm: sự thật sắc nét nhất — không có gì là vĩnh viễn. Thần Chết và Nữ Hoàng cùng nhau đại diện cho lòng dũng cảm đối mặt với sự kết thúc với cái nhìn trong sáng; nỗi đau thành thật là con đường đến tự do.", en: "Death and Swords Queen: the sharpest truth — nothing is permanent. Death and the Queen together represent the courage to face endings with clear eyes; honest grief as a path to freedom." },
  "13_63": { vi: "Thần Chết và Vua Kiếm: quyền uy phải được biến đổi — Thần Chết thách thức sự cai trị đã thiết lập của Vua; các hệ thống logic và quản trị cũ phải kết thúc để các cấu trúc khôn ngoan hơn nổi lên.", en: "Death and Swords King: authority must be transformed — Death challenges the King's established rule; old systems of logic and governance must end for wiser structures to emerge." },
  "13_74": { vi: "Thần Chết và Trang Bị Tiền: một chương vật chất kết thúc — Thần Chết xóa bỏ con đường thực tế cũ để nhường chỗ cho cách tiếp cận mới trong việc học và xây dựng; hãy buông bỏ những gì không còn phục vụ bạn.", en: "Death and Pentacles Page: a material chapter ends — Death clears the old practical path to make room for a new approach to learning and building; release what no longer serves." },
  "13_75": { vi: "Thần Chết và Kỵ Sĩ Tiền: con đường có phương pháp bị thay đổi cơ bản — Thần Chết yêu cầu Kỵ Sĩ buông bỏ tuyến đường cũ; một hướng được biến đổi hướng tới các mục tiêu vật chất.", en: "Death and Pentacles Knight: the methodical path fundamentally altered — Death asks the Knight to let go of the old route; a transformed direction toward material goals." },
  "13_76": { vi: "Thần Chết và Nữ Hoàng Tiền: chu kỳ phong phú đang quay — Thần Chết và Nữ Hoàng báo hiệu sự kết thúc của một mùa nuôi dưỡng và sự bắt đầu của mùa khác; sự buông bỏ tạo điều kiện cho sự tăng trưởng mới.", en: "Death and Pentacles Queen: the abundance cycle turning — Death and the Queen signal the end of one season of nurturing and the beginning of another; release enables new growth." },
  "13_77": { vi: "Thần Chết và Vua Tiền: một triều đại được biến đổi — Thần Chết báo hiệu sự kết thúc của một kỷ nguyên trong sự thành thạo vật chất; những gì được buông bỏ tạo không gian cho một trật tự mới của sự giàu có và di sản.", en: "Death and Pentacles King: a dynasty transforms — Death signals the end of an era in material mastery; what is released creates space for a new order of wealth and legacy." },

  // Temperance (14) × Courts
  "14_32": { vi: "Điều Độ và Trang Bị Gậy: đam mê được kiềm chế bởi sự kiên nhẫn — Điều Độ dạy Trang Bị bốc đồng hãy pha trộn sự nhiệt tình với thời điểm; thuật giả kim sáng tạo đến từ thực hành có chủ đích, có cân nhắc.", en: "Temperance and Wands Page: passion moderated by patience — Temperance teaches the impulsive Page to blend enthusiasm with timing; creative alchemy comes from measured, intentional practice." },
  "14_33": { vi: "Điều Độ và Kỵ Sĩ Gậy: cuộc xung phong táo bạo được cân bằng bởi dòng chảy — Điều Độ yêu cầu Kỵ Sĩ pha trộn tốc độ với sự kiên nhẫn; hành động hiệu quả nhất tìm thấy thời điểm hoàn hảo của nó.", en: "Temperance and Wands Knight: the bold charge balanced by flow — Temperance asks the Knight to blend speed with patience; the most effective action finds its perfect timing." },
  "14_34": { vi: "Điều Độ và Nữ Hoàng Gậy: thuật giả kim sáng tạo ở đỉnh cao — Điều Độ và Nữ Hoàng pha trộn lửa và mục đích với kỹ năng duyên dáng; hành động lấy cảm hứng, được tính toán kỹ lưỡng biến đổi mọi thứ nó chạm vào.", en: "Temperance and Wands Queen: creative alchemy at its finest — Temperance and the Queen blend fire and purpose with graceful skill; inspired, well-timed action that transforms everything it touches." },
  "14_35": { vi: "Điều Độ và Vua Gậy: tầm nhìn được cân bằng và tinh chỉnh — Điều Độ mời Vua pha trộn sự lãnh đạo táo bạo với sự khôn ngoan kiên nhẫn; những thành tựu lâu dài nhất được xây dựng qua sự thành thạo có cân nhắc.", en: "Temperance and Wands King: vision balanced and refined — Temperance invites the King to blend bold leadership with patient wisdom; the most lasting achievements are built through measured mastery." },
  "14_46": { vi: "Điều Độ và Trang Bị Cốc: sự cân bằng cảm xúc cho người mới bắt đầu nhạy cảm — Điều Độ dạy trái tim trẻ cách chảy giữa cảm xúc và sự tĩnh lặng; thuật giả kim cảm xúc qua sự tự hiểu biết kiên nhẫn.", en: "Temperance and Cups Page: emotional balance for the sensitive beginner — Temperance teaches the young heart to flow between feeling and stillness; emotional alchemy through patient self-understanding." },
  "14_47": { vi: "Điều Độ và Kỵ Sĩ Cốc: cuộc tìm kiếm lãng mạn được điều hòa — Điều Độ mời Kỵ Sĩ pha trộn đam mê với sự kiên nhẫn; tình yêu được theo đuổi đúng mức độ, đúng thời điểm sẽ bền lâu.", en: "Temperance and Cups Knight: the romantic quest tempered — Temperance invites the Knight to blend passion with patience; love pursued in the right measure at the right time endures." },
  "14_48": { vi: "Điều Độ và Nữ Hoàng Cốc: bậc thầy của thuật giả kim cảm xúc — Điều Độ và Nữ Hoàng cùng nhau đại diện cho sự tích hợp cao nhất của cảm xúc, sự chữa lành và sự khôn ngoan từ bi.", en: "Temperance and Cups Queen: the master of emotional alchemy — Temperance and the Queen together represent the highest integration of feeling, healing, and compassionate wisdom." },
  "14_49": { vi: "Điều Độ và Vua Cốc: sự cân bằng cảm xúc chín chắn — Điều Độ và Vua cùng nhau thể hiện sự tích hợp tinh chỉnh của chiều sâu, lòng từ bi và quyền uy có cân nhắc; sự thành thạo cảm xúc thực sự.", en: "Temperance and Cups King: mature emotional balance — Temperance and the King together embody the refined integration of depth, compassion, and measured authority; true emotional mastery." },
  "14_60": { vi: "Điều Độ và Trang Bị Kiếm: tư duy sắc bén được cân bằng bởi sự tìm tòi kiên nhẫn — Điều Độ hướng dẫn tâm trí trẻ háo hức pha trộn sự tò mò với phân tích cẩn thận, có cân nhắc; sự khôn ngoan qua suy nghĩ được hiệu chỉnh.", en: "Temperance and Swords Page: sharp thinking balanced with patient inquiry — Temperance guides the eager young mind to blend curiosity with measured, careful analysis; wisdom through calibrated thought." },
  "14_61": { vi: "Điều Độ và Kỵ Sĩ Kiếm: hành động được cân bằng bởi sự chính xác và thời điểm — Điều Độ điều hòa cuộc xung phong nhanh của Kỵ Sĩ; hành động quyết đoán hiệu quả nhất tìm thấy thời điểm hoàn hảo của nó.", en: "Temperance and Swords Knight: action balanced by precision and timing — Temperance tempering the Knight's swift charge; the most effective decisive action finds its perfect moment." },
  "14_62": { vi: "Điều Độ và Nữ Hoàng Kiếm: nhận thức rõ ràng được pha trộn với sự khôn ngoan kiên nhẫn — Điều Độ và Nữ Hoàng cùng nhau đại diện cho sự tích hợp của sự thật sắc bén với thời điểm duyên dáng, có cân nhắc.", en: "Temperance and Swords Queen: clear perception blended with patient wisdom — Temperance and the Queen together represent the integration of sharp truth with measured, graceful timing." },
  "14_63": { vi: "Điều Độ và Vua Kiếm: quyền uy phân tích được tinh chỉnh qua sự cân bằng — Điều Độ mời Vua pha trộn sự phán xét sắc bén với sự cân nhắc kiên nhẫn; công lý ở trạng thái tinh chỉnh nhất.", en: "Temperance and Swords King: analytical authority refined through balance — Temperance invites the King to blend sharp judgment with patient deliberation; justice at its most refined." },
  "14_74": { vi: "Điều Độ và Trang Bị Tiền: việc học vật chất qua thực hành kiên nhẫn — Điều Độ dạy học trò rằng sự thành thạo đến từ nỗ lực ổn định, có cân nhắc; thuật giả kim thực tế từng bước cẩn thận một.", en: "Temperance and Pentacles Page: material learning through patient practice — Temperance teaches the student that mastery comes from steady, measured effort; practical alchemy one careful step at a time." },
  "14_75": { vi: "Điều Độ và Kỵ Sĩ Tiền: nỗ lực kiên nhẫn được tinh chỉnh thành nghệ thuật — Điều Độ và Kỵ Sĩ cùng nhau đại diện cho sự diễn đạt cao nhất của tiến trình ổn định, có cân nhắc; sự xuất sắc có phương pháp.", en: "Temperance and Pentacles Knight: patient effort refined to an art — Temperance and the Knight together represent the highest expression of steady, measured progress; methodical excellence." },
  "14_76": { vi: "Điều Độ và Nữ Hoàng Tiền: sự phong phú hào phóng qua quản lý cân bằng — Điều Độ và Nữ Hoàng cùng nhau tạo ra sự thịnh vượng bền vững; cho và nhận trong sự cân bằng hoàn hảo, chảy tự nhiên.", en: "Temperance and Pentacles Queen: generous abundance through balanced stewardship — Temperance and the Queen together create sustainable prosperity; giving and receiving in perfect, flowing measure." },
  "14_77": { vi: "Điều Độ và Vua Tiền: sự thành thạo vật chất qua quản lý kiên nhẫn, cân bằng — Điều Độ tinh chỉnh việc xây dựng sự giàu có của Vua; sự thịnh vượng lâu dài được xây dựng qua quản lý tài nguyên khôn ngoan, có cân nhắc.", en: "Temperance and Pentacles King: material mastery through patient, balanced stewardship — Temperance refines the King's wealth-building; lasting prosperity built through measured, wise resource management." },

  // Devil (15) × Courts
  "15_32": { vi: "Ác Quỷ và Trang Bị Gậy: sự nhiệt tình bị ám bởi nỗi ám ảnh không lành mạnh — Ác Quỷ cảnh báo Trang Bị rằng đam mê không được kiểm soát có thể trở thành cưỡng bức; ngọn lửa sáng tạo không được biến thành nô lệ.", en: "The Devil and Wands Page: enthusiasm captured by unhealthy obsession — the Devil warns the Page that unchecked passion can become compulsion; creative fire must not be enslaved." },
  "15_33": { vi: "Ác Quỷ và Kỵ Sĩ Gậy: cuộc xung phong dẫn đến giam cầm — Ác Quỷ cảnh báo Kỵ Sĩ rằng sự theo đuổi không ngừng nghỉ mà không có sự phản tư tạo ra xiềng xích; hành động táo bạo được thúc đẩy bởi nỗi ám ảnh không dẫn đến đâu.", en: "The Devil and Wands Knight: the charge that leads to captivity — the Devil warns the Knight that relentless pursuit without reflection creates chains; bold action driven by obsession leads nowhere." },
  "15_34": { vi: "Ác Quỷ và Nữ Hoàng Gậy: quyền năng sáng tạo bị làm tối bởi sự kiểm soát — Ác Quỷ và Nữ Hoàng báo hiệu rằng sự tự tin có thể che giấu hành vi kiểm soát; hãy xem xét liệu ngọn lửa phục vụ hay nô dịch.", en: "The Devil and Wands Queen: creative power shadowed by control — the Devil and Queen signal that confidence may mask controlling behavior; examine whether the fire serves or enslaves." },
  "15_35": { vi: "Ác Quỷ và Vua Gậy: sự lãnh đạo bị trói buộc bởi nghiện ngập quyền lực — Ác Quỷ cảnh báo Vua rằng quyền uy có thể trở thành bạo ngược; hãy xem xét những xiềng xích của bản ngã và sự kiểm soát cần được buông bỏ.", en: "The Devil and Wands King: leadership bound by power addiction — the Devil warns the King that authority can become tyranny; examine what chains of ego and control must be released." },
  "15_46": { vi: "Ác Quỷ và Trang Bị Cốc: sự nhạy cảm cảm xúc bị vướng vào các mô hình không lành mạnh — Ác Quỷ cảnh báo trái tim dịu dàng về các mối liên hệ cảm xúc gây nghiện; không phải mọi cảm xúc đều lành mạnh để theo đuổi.", en: "The Devil and Cups Page: emotional sensitivity entangled in unhealthy patterns — the Devil warns the tender heart against addictive emotional dynamics; not every feeling is healthy to pursue." },
  "15_47": { vi: "Ác Quỷ và Kỵ Sĩ Cốc: nỗi ám ảnh lãng mạn — Ác Quỷ và Kỵ Sĩ báo hiệu sự gắn bó không lành mạnh; cuộc tìm kiếm lãng mạn đã trở nên cưỡng bức; hãy xem xét liệu tình yêu này giải phóng hay ràng buộc.", en: "The Devil and Cups Knight: romantic obsession — the Devil and Knight signal unhealthy attachment; the romantic quest has become compulsive; examine whether this love is liberating or binding." },
  "15_48": { vi: "Ác Quỷ và Nữ Hoàng Cốc: sự chăm sóc nuôi dưỡng tạo điều kiện thay vì chữa lành — Ác Quỷ và Nữ Hoàng báo hiệu lòng từ bi đã nghiêng sang sự tạo điều kiện không lành mạnh; hãy xem xét những xiềng xích đằng sau sự quan tâm.", en: "The Devil and Cups Queen: nurturing that enables rather than heals — the Devil and Queen signal compassion that has tipped into unhealthy enabling; examine the chains behind the care." },
  "15_49": { vi: "Ác Quỷ và Vua Cốc: quyền uy cảm xúc bị làm tối bởi sự thao túng — Ác Quỷ và Vua báo hiệu rằng quyền lực cảm xúc có thể được sử dụng để ràng buộc thay vì giải phóng; hãy xem xét sự kiểm soát ẩn giấu.", en: "The Devil and Cups King: emotional authority shadowed by manipulation — the Devil and King signal that emotional power may be used to bind rather than liberate; examine hidden control." },
  "15_60": { vi: "Ác Quỷ và Trang Bị Kiếm: các mô hình tinh thần giam cầm — Ác Quỷ cảnh báo tâm trí trẻ sắc bén rằng suy nghĩ quá mức và các vòng lặp suy nghĩ tiêu cực trở thành xiềng xích; hãy xem xét những thói quen tinh thần nào ràng buộc bạn.", en: "The Devil and Swords Page: mental patterns that imprison — the Devil warns the sharp young mind that overthinking and negative thought loops become chains; examine what mental habits bind you." },
  "15_61": { vi: "Ác Quỷ và Kỵ Sĩ Kiếm: thanh kiếm phục vụ bóng tối — Ác Quỷ và Kỵ Sĩ báo hiệu sự xâm lược hoặc lực lượng được sử dụng để duy trì quyền lực không lành mạnh; hãy xem xét những gì cuộc xung phong thực sự phục vụ.", en: "The Devil and Swords Knight: the sword that serves the shadow — the Devil and Knight signal aggression or force used to maintain unhealthy power; examine what the charge truly serves." },
  "15_62": { vi: "Ác Quỷ và Nữ Hoàng Kiếm: nhìn rõ bóng tối — Nữ Hoàng có thể nhận thấy chính xác những xiềng xích của Ác Quỷ; cặp đôi này có thể báo hiệu việc nhìn thấy các mô hình không lành mạnh đủ rõ ràng để cuối cùng thoát ra.", en: "The Devil and Swords Queen: clear sight of the shadow — the Queen can perceive the Devil's chains precisely; this pairing may signal seeing unhealthy patterns clearly enough to finally cut free." },
  "15_63": { vi: "Ác Quỷ và Vua Kiếm: quyền uy bị trói buộc bởi các hệ thống cứng nhắc của chính nó — Ác Quỷ cảnh báo Vua rằng quyền lực trí tuệ có thể trở thành giáo điều giam cầm; hãy xem xét những xiềng xích tinh thần nào ngụy trang thành lý trí.", en: "The Devil and Swords King: authority bound by its own rigid systems — the Devil warns the King that intellectual power can become imprisoning dogma; examine what mental chains masquerade as reason." },
  "15_74": { vi: "Ác Quỷ và Trang Bị Tiền: nỗi ám ảnh vật chất đang hình thành — Ác Quỷ cảnh báo học trò háo hức rằng sự tập trung vật chất ban đầu có thể trở thành lòng tham hoặc chứng nghiện làm việc; hãy xem xét động lực đằng sau nỗ lực.", en: "The Devil and Pentacles Page: material obsession in the making — the Devil warns the eager student that early material focus can become greed or workaholism; examine the motivation behind the effort." },
  "15_75": { vi: "Ác Quỷ và Kỵ Sĩ Tiền: tham vọng biến thành nỗi ám ảnh — Ác Quỷ và Kỵ Sĩ báo hiệu rằng sự kiên trì ổn định đã nghiêng sang làm việc cưỡng bức; hãy xem xét liệu nỗ lực phục vụ cuộc sống hay tiêu thụ nó.", en: "The Devil and Pentacles Knight: ambition turned to obsession — the Devil and Knight signal that steady persistence has tipped into compulsive work; examine whether effort serves life or consumes it." },
  "15_76": { vi: "Ác Quỷ và Nữ Hoàng Tiền: sự phong phú vật chất bị làm tối bởi tính chiếm hữu — Ác Quỷ và Nữ Hoàng báo hiệu việc nắm giữ quá chặt; sự hào phóng che giấu sự kiểm soát; hãy xem xét những xiềng xích xung quanh sự phong phú.", en: "The Devil and Pentacles Queen: material abundance shadowed by possessiveness — the Devil and Queen signal holding on too tightly; generosity that hides control; examine the chains around the abundance." },
  "15_77": { vi: "Ác Quỷ và Vua Tiền: sự giàu có đã trở thành một nhà tù — Ác Quỷ và Vua báo hiệu sự thành thạo vật chất phục vụ sự kiểm soát thay vì tự do; hãy xem xét những gì đế chế thực sự đánh đổi.", en: "The Devil and Pentacles King: wealth that has become a prison — the Devil and King signal material mastery in service of control rather than freedom; examine what the empire truly costs." },

  // Tower (16) × Courts
  "16_32": { vi: "Tháp Sụp và Trang Bị Gậy: sự gián đoạn đột ngột của sự nhiệt tình ban đầu — Tháp Sụp xóa tan các giả định sai lầm về con đường phía trước; những gì còn sót lại sau cú sốc chân thực hơn những gì đã đến trước.", en: "The Tower and Wands Page: sudden disruption of early enthusiasm — the Tower shatters false assumptions about the path ahead; what survives the shock is more authentic than what came before." },
  "16_33": { vi: "Tháp Sụp và Kỵ Sĩ Gậy: cuộc xung phong gặp sự đảo lộn đột ngột — Tháp Sụp chuyển hướng động lực của Kỵ Sĩ qua một tia sáng mặc khải; các mục tiêu cũ bị xóa bỏ để tiết lộ một hướng đúng hơn.", en: "The Tower and Wands Knight: the charge meets sudden upheaval — the Tower redirects the Knight's momentum through a bolt of revelation; old goals shattered to reveal a truer direction." },
  "16_34": { vi: "Tháp Sụp và Nữ Hoàng Gậy: các cấu trúc sáng tạo sụp đổ để tiết lộ điều gì đó vĩ đại hơn — Tháp Sụp tấn công bản sắc đã thiết lập của Nữ Hoàng; những gì nổi lên từ đống đổ nát mạnh mẽ và chân thực hơn.", en: "The Tower and Wands Queen: creative structures crumble to reveal something greater — the Tower strikes the Queen's established identity; what emerges from the ruins is more authentically powerful." },
  "16_35": { vi: "Tháp Sụp và Vua Gậy: tầm nhìn đã thiết lập bị tấn công bởi mặc khải đột ngột — Tháp Sụp phá bỏ những sự chắc chắn của Vua; những gì còn sót lại là những gì thực sự được xây dựng trên nền tảng vững chắc.", en: "The Tower and Wands King: the established vision struck by sudden revelation — the Tower dismantles the King's certainties; what survives is what is truly built on solid ground." },
  "16_46": { vi: "Tháp Sụp và Trang Bị Cốc: những sự chắc chắn cảm xúc bị vỡ tan — Tháp Sụp phá vỡ những giả định của trái tim dịu dàng về cảm xúc và kết nối; cảm xúc thô, thành thật còn lại sau cú sốc.", en: "The Tower and Cups Page: emotional certainties shattered — the Tower breaks open the tender heart's assumptions about feeling and connection; raw, honest emotion remains after the shock." },
  "16_47": { vi: "Tháp Sụp và Kỵ Sĩ Cốc: cuộc tìm kiếm lãng mạn bị gián đoạn bởi mặc khải đột ngột — Tháp Sụp can thiệp vào sự theo đuổi của Kỵ Sĩ; những gì có vẻ là tình yêu có thể được tiết lộ là ảo tưởng hoặc phóng chiếu.", en: "The Tower and Cups Knight: the romantic quest interrupted by sudden revelation — the Tower intervenes in the Knight's pursuit; what seemed like love may be revealed as illusion or projection." },
  "16_48": { vi: "Tháp Sụp và Nữ Hoàng Cốc: sự đảo lộn trong lĩnh vực chăm sóc và nuôi dưỡng — Tháp Sụp tấn công thế giới cảm xúc của Nữ Hoàng; sự tổ chức lại sâu sắc về cách tình yêu và lòng từ bi được thể hiện.", en: "The Tower and Cups Queen: upheaval in the realm of care and nurturing — the Tower strikes the Queen's emotional world; profound reorganization of how love and compassion are expressed." },
  "16_49": { vi: "Tháp Sụp và Vua Cốc: sự gián đoạn đột ngột đối với quyền uy cảm xúc — Tháp Sụp thách thức sự ổn định cảm xúc của Vua; sau làn sóng chấn động, sự khôn ngoan sâu sắc, chân thực hơn có thể nổi lên.", en: "The Tower and Cups King: sudden disruption to emotional authority — the Tower challenges the King's emotional stability; after the shockwave, deeper, more authentic wisdom can emerge." },
  "16_60": { vi: "Tháp Sụp và Trang Bị Kiếm: các khuôn khổ tinh thần bị xóa tan — Tháp Sụp tấn công những giả định của người tư duy trẻ; mọi thứ được tin là sự thật đột nhiên bị đặt câu hỏi; sự hiểu biết được xây dựng lại mạnh mẽ hơn.", en: "The Tower and Swords Page: mental frameworks shattered — the Tower strikes the young thinker's assumptions; everything believed to be true is suddenly questioned; rebuilt understanding is stronger." },
  "16_61": { vi: "Tháp Sụp và Kỵ Sĩ Kiếm: cuộc xung phong bị gián đoạn bởi tia sét — Tháp Sụp dừng Kỵ Sĩ giữa chừng tiến lên; mặc khải đột ngột thay đổi mọi thứ về những gì đáng chiến đấu.", en: "The Tower and Swords Knight: charge interrupted by lightning — the Tower stops the Knight mid-advance; the sudden revelation changes everything about what is worth fighting for." },
  "16_62": { vi: "Tháp Sụp và Nữ Hoàng Kiếm: Tháp Sụp được soi sáng bởi nhận thức rõ ràng — tầm nhìn sắc bén của Nữ Hoàng có thể nhìn thấy mặc khải của Tháp Sụp một cách rõ ràng; sử dụng sự đảo lộn để cắt bỏ mọi thứ giả dối.", en: "The Tower and Swords Queen: the Tower illuminated by clear perception — the Queen's sharp vision can see the Tower's revelation clearly; using the upheaval to cut away everything false." },
  "16_63": { vi: "Tháp Sụp và Vua Kiếm: quyền uy trí tuệ đã thiết lập bị tấn công — Tháp Sụp phá bỏ những sự chắc chắn của Vua; các hệ thống tư duy cũ sụp đổ; những gì còn lại là chỉ những gì thực sự vững chắc.", en: "The Tower and Swords King: established intellectual authority struck — the Tower dismantles the King's certainties; old systems of thought collapse; what remains is only what is truly sound." },
  "16_74": { vi: "Tháp Sụp và Trang Bị Tiền: các kế hoạch vật chất bị gián đoạn — Tháp Sụp cắt ngang những khởi đầu thực tế; sự thay đổi hoàn cảnh đột ngột buộc phải xem xét lại những gì thực sự đang được xây dựng.", en: "The Tower and Pentacles Page: material plans disrupted — the Tower interrupts practical beginnings; a sudden change of circumstances forces a reassessment of what is truly being built." },
  "16_75": { vi: "Tháp Sụp và Kỵ Sĩ Tiền: con đường ổn định bị gián đoạn — Tháp Sụp làm trệch hướng tiến trình có phương pháp của Kỵ Sĩ; sau cú sốc, một hướng vật chất chân thực hơn nổi lên.", en: "The Tower and Pentacles Knight: the steady path disrupted — the Tower throws the Knight's methodical progress off course; after the shock, a more authentic material direction emerges." },
  "16_76": { vi: "Tháp Sụp và Nữ Hoàng Tiền: các cấu trúc phong phú đột nhiên bị dịch chuyển — Tháp Sụp gián đoạn thế giới vật chất ổn định của Nữ Hoàng; những gì được xây dựng lại sau sự đảo lộn thịnh vượng hơn một cách chân thực.", en: "The Tower and Pentacles Queen: abundance structures suddenly shifted — the Tower disrupts the Queen's stable material world; what is rebuilt after the upheaval is more genuinely prosperous." },
  "16_77": { vi: "Tháp Sụp và Vua Tiền: đế chế bị tấn công — Tháp Sụp thách thức lãnh địa vật chất của Vua; những gì còn sót lại sau sự gián đoạn đột ngột vốn đã thực sự vững chắc; những gì sụp đổ luôn rỗng tuếch.", en: "The Tower and Pentacles King: the empire struck — the Tower challenges the King's material dominion; what survives the sudden disruption was truly solid; what crumbles was always hollow." },

  // Star (17) × Courts
  "17_32": { vi: "Ngôi Sao và Trang Bị Gậy: hi vọng làm mới ngọn lửa trẻ — ánh sáng chữa lành của Ngôi Sao truyền cảm hứng cho Trang Bị với sự nhiệt tình được làm mới và định hướng chân thực; năng lượng sáng tạo được hướng dẫn bởi hi vọng thực sự.", en: "The Star and Wands Page: hope renewing young fire — the Star's healing light inspires the Page with renewed enthusiasm and authentic direction; creative energy guided by genuine hope." },
  "17_33": { vi: "Ngôi Sao và Kỵ Sĩ Gậy: cuộc tìm kiếm được làm mới được hướng dẫn bởi ánh sáng sao — hi vọng của Ngôi Sao mang lại cho cuộc xung phong của Kỵ Sĩ một mục đích cao hơn; sự theo đuổi lấy cảm hứng được sắp xếp với một tầm nhìn thực sự.", en: "The Star and Wands Knight: the renewed quest guided by starlight — the Star's hope gives the Knight's charge a higher purpose; inspired pursuit aligned with a genuine vision." },
  "17_34": { vi: "Ngôi Sao và Nữ Hoàng Gậy: cảm hứng sáng tạo được làm mới và nâng cao — Ngôi Sao và Nữ Hoàng cùng nhau đại diện cho tầm nhìn sáng tạo chân thực tỏa sáng ra ngoài; sự tự tin lấy cảm hứng chữa lành và nâng đỡ.", en: "The Star and Wands Queen: creative inspiration renewed and elevated — the Star and Queen together represent authentic creative vision radiating outward; inspired confidence that heals and uplifts." },
  "17_35": { vi: "Ngôi Sao và Vua Gậy: sự lãnh đạo được hướng dẫn bởi hi vọng thực sự — ánh sáng của Ngôi Sao làm mới tầm nhìn của Vua với mục đích cao hơn; quyền uy phục vụ điều gì đó thực sự truyền cảm hứng.", en: "The Star and Wands King: leadership guided by genuine hope — the Star's light renews the King's vision with higher purpose; authority in service of something truly inspiring." },
  "17_46": { vi: "Ngôi Sao và Trang Bị Cốc: hi vọng được rót vào những khởi đầu cảm xúc dịu dàng — Ngôi Sao và Trang Bị cùng nhau tràn đầy cảm xúc chữa lành, dịu dàng; những kết nối cảm xúc mới được hướng dẫn bởi hi vọng chân thực.", en: "The Star and Cups Page: hope poured into tender emotional beginnings — the Star and Page together overflow with gentle, healing feeling; new emotional connections guided by authentic hope." },
  "17_47": { vi: "Ngôi Sao và Kỵ Sĩ Cốc: cuộc tìm kiếm lãng mạn được hướng dẫn bởi cảm hứng thực sự — Ngôi Sao mang lại cho sự theo đuổi của Kỵ Sĩ một lý tưởng cao hơn; tình yêu được tìm kiếm không phải từ nhu cầu mà từ khát vọng và hi vọng chân thực.", en: "The Star and Cups Knight: the romantic quest guided by genuine inspiration — the Star gives the Knight's pursuit a higher ideal; love sought not from need but from authentic longing and hope." },
  "17_48": { vi: "Ngôi Sao và Nữ Hoàng Cốc: người chữa lành được soi sáng bởi ánh sáng sao — Ngôi Sao và Nữ Hoàng cùng nhau đại diện cho sự chữa lành từ bi ở trạng thái cao nhất; hi vọng, tình yêu và sự làm mới chảy tự do.", en: "The Star and Cups Queen: the healer illuminated by starlight — the Star and Queen together represent the highest expression of compassionate healing; hope, love, and renewal flowing freely." },
  "17_49": { vi: "Ngôi Sao và Vua Cốc: sự khôn ngoan cảm xúc được làm mới bởi hi vọng — ánh sáng của Ngôi Sao soi sáng chiều sâu của Vua; quyền uy cảm xúc chín chắn được hướng dẫn bởi đức tin thực sự vào sự chữa lành và làm mới.", en: "The Star and Cups King: emotional wisdom renewed by hope — the Star's light illuminates the King's depth; mature emotional authority guided by genuine faith in healing and renewal." },
  "17_60": { vi: "Ngôi Sao và Trang Bị Kiếm: hi vọng được làm mới cho tâm trí đặt câu hỏi — Ngôi Sao hướng dẫn sự tò mò trí tuệ của Trang Bị đến cái nhìn sâu sắc thực sự; tư duy phục vụ sự chữa lành và sự hiểu biết chân thực.", en: "The Star and Swords Page: renewed hope for the questioning mind — the Star guides the Page's intellectual curiosity toward genuine insight; thinking in service of healing and authentic understanding." },
  "17_61": { vi: "Ngôi Sao và Kỵ Sĩ Kiếm: cuộc xung phong lấy cảm hứng — Ngôi Sao mang lại cho hành động quyết đoán của Kỵ Sĩ một mục đích được làm mới, đầy hi vọng; chiến đấu cho những gì thực sự đáng tin tưởng.", en: "The Star and Swords Knight: the inspired charge — the Star gives the Knight's decisive action a renewed, hopeful purpose; fighting for what is genuinely worth believing in." },
  "17_62": { vi: "Ngôi Sao và Nữ Hoàng Kiếm: nhận thức rõ ràng được hướng dẫn bởi hi vọng thực sự — sự nhìn thấy sự thật của Nữ Hoàng được hướng dẫn bởi ánh sáng chữa lành của Ngôi Sao; cái nhìn sâu sắc thành thật soi sáng thay vì chỉ đơn giản là làm tổn thương.", en: "The Star and Swords Queen: clear perception guided by genuine hope — the Queen's truth-seeing guided by the Star's healing light; honest insight that illuminates rather than merely wounds." },
  "17_63": { vi: "Ngôi Sao và Vua Kiếm: quyền uy trí tuệ được làm mới bởi cảm hứng thực sự — Ngôi Sao mời Vua lãnh đạo với hi vọng; quyền lực phân tích phục vụ một tầm nhìn thực sự truyền cảm hứng.", en: "The Star and Swords King: intellectual authority renewed by genuine inspiration — the Star invites the King to lead with hope; analytical power in service of a genuinely inspiring vision." },
  "17_74": { vi: "Ngôi Sao và Trang Bị Tiền: hi vọng làm mới những khởi đầu vật chất — ánh sáng của Ngôi Sao hướng dẫn những nỗ lực ban đầu của học trò háo hức với cảm hứng thực sự; xây dựng hướng tới điều gì đó thực sự có ý nghĩa.", en: "The Star and Pentacles Page: hope renewing material beginnings — the Star's light guides the eager student's early efforts with genuine inspiration; building toward something authentically meaningful." },
  "17_75": { vi: "Ngôi Sao và Kỵ Sĩ Tiền: nỗ lực kiên nhẫn được hướng dẫn bởi hi vọng thực sự — Ngôi Sao soi sáng con đường ổn định của Kỵ Sĩ; công việc có phương pháp phục vụ một tầm nhìn thực sự truyền cảm hứng.", en: "The Star and Pentacles Knight: patient effort guided by genuine hope — the Star illuminates the Knight's steady path; methodical work in service of a vision that genuinely inspires." },
  "17_76": { vi: "Ngôi Sao và Nữ Hoàng Tiền: sự hào phóng chữa lành dồi dào — Ngôi Sao và Nữ Hoàng cùng nhau đại diện cho sự nuôi dưỡng vật chất phục vụ sự chữa lành thực sự; sự thịnh vượng được chia sẻ với hi vọng và sự duyên dáng.", en: "The Star and Pentacles Queen: abundant healing generosity — the Star and Queen together represent material nurturing in service of genuine healing; prosperity shared with hope and grace." },
  "17_77": { vi: "Ngôi Sao và Vua Tiền: sự thành thạo vật chất được làm mới bởi hi vọng thực sự — ánh sáng của Ngôi Sao mang lại cho sự giàu có của Vua một mục đích cao hơn; sự thịnh vượng đã thiết lập được định hướng đến di sản thực sự truyền cảm hứng.", en: "The Star and Pentacles King: material mastery renewed by genuine hope — the Star's light gives the King's wealth a higher purpose; established prosperity directed toward a truly inspiring legacy." },

  // Moon (18) × Courts
  "18_32": { vi: "Mặt Trăng và Trang Bị Gậy: sự nhiệt tình bị che mờ bởi ảo tưởng — Mặt Trăng cảnh báo Trang Bị háo hức rằng không phải mọi thứ đều như vẻ bề ngoài; hãy tin vào bản năng thay vì tư duy nguyện vọng trong sương mù hiện tại.", en: "The Moon and Wands Page: enthusiasm clouded by illusion — the Moon warns the eager Page that not everything is as it appears; trust gut instinct over wishful thinking in the current fog." },
  "18_33": { vi: "Mặt Trăng và Kỵ Sĩ Gậy: cuộc xung phong vào vùng lãnh thổ không chắc chắn — Mặt Trăng cảnh báo Kỵ Sĩ rằng con đường phía trước không rõ ràng; những ảo tưởng có thể chuyển hướng cuộc tìm kiếm; hãy tiến lên cẩn thận thay vì với tốc độ.", en: "The Moon and Wands Knight: the charge into uncertain territory — the Moon warns the Knight that the path ahead is unclear; illusions may redirect the quest; proceed with caution rather than speed." },
  "18_34": { vi: "Mặt Trăng và Nữ Hoàng Gậy: tầm nhìn sáng tạo bị che mờ bởi những nỗi sợ tiềm thức — Mặt Trăng và Nữ Hoàng báo hiệu rằng những bất an sâu xa có thể bóp méo vẻ ngoài tự tin; hãy nhìn bên dưới bề mặt.", en: "The Moon and Wands Queen: creative vision clouded by subconscious fears — the Moon and Queen signal that deep insecurities may be distorting the confident exterior; look beneath the surface." },
  "18_35": { vi: "Mặt Trăng và Vua Gậy: sự lãnh đạo trong vùng nước không chắc chắn — Mặt Trăng thách thức sự chắc chắn của Vua; những gì có vẻ vững chắc có thể là ảo tưởng; hãy tin vào những bản năng sâu xa hơn thay vì vẻ bề ngoài.", en: "The Moon and Wands King: leadership in uncertain waters — the Moon challenges the King's certainty; what appears solid may be illusory; trust deeper instincts over surface appearances." },
  "18_46": { vi: "Mặt Trăng và Trang Bị Cốc: sự nhạy cảm cảm xúc sâu sắc được khuếch đại bởi tiềm thức — Mặt Trăng và Trang Bị cùng nhau bơi trong chiều sâu của cảm xúc và giấc mơ; trực giác cao nhưng cũng có nguy cơ nhầm lẫn cảm xúc.", en: "The Moon and Cups Page: deep emotional sensitivity amplified by the subconscious — the Moon and Page together swim in the depths of feeling and dream; heightened intuition but also risk of emotional confusion." },
  "18_47": { vi: "Mặt Trăng và Kỵ Sĩ Cốc: cuộc tìm kiếm lãng mạn bước vào vùng nước huyền bí — Mặt Trăng cảnh báo Kỵ Sĩ rằng điều anh đang theo đuổi có thể là ảo tưởng; người được yêu có thể không phải như họ xuất hiện.", en: "The Moon and Cups Knight: the romantic quest enters mysterious waters — the Moon warns the Knight that what he pursues may be an illusion; the beloved may not be who they appear." },
  "18_48": { vi: "Mặt Trăng và Nữ Hoàng Cốc: hai năng lượng nước sâu — bí ẩn của Mặt Trăng và chiều sâu cảm xúc của Nữ Hoàng kết hợp; sự nhạy cảm tâm linh sâu sắc, nhưng cũng có nguy cơ đánh mất bản thân trong chiều sâu.", en: "The Moon and Cups Queen: two deep water energies — the Moon's mystery and the Queen's emotional depth combine; profound psychic sensitivity, but also the risk of losing oneself in the depths." },
  "18_49": { vi: "Mặt Trăng và Vua Cốc: sự khôn ngoan cảm xúc bị thử thách bởi ảo tưởng — Mặt Trăng che mờ ngay cả chiều sâu của Vua; hãy tin vào dòng chảy trực giác bên dưới thay vì những biểu hiện cảm xúc bề mặt.", en: "The Moon and Cups King: emotional wisdom tested by illusion — the Moon clouds even the King's depth; trust the intuitive undercurrent rather than surface emotional presentations." },
  "18_60": { vi: "Mặt Trăng và Trang Bị Kiếm: sự nhầm lẫn tinh thần và tư duy không rõ ràng — Mặt Trăng và Trang Bị báo hiệu sự suy nghĩ quá mức lo lắng; tâm trí xoáy cuộn trong bóng tối; hãy tìm sợi chỉ chắc chắn của sự thật trước khi hành động.", en: "The Moon and Swords Page: mental confusion and unclear thinking — the Moon and Page signal anxious overthinking; the mind spirals in the dark; find the solid thread of truth before acting." },
  "18_61": { vi: "Mặt Trăng và Kỵ Sĩ Kiếm: xung phong qua sương mù — Mặt Trăng cảnh báo Kỵ Sĩ rằng hành động quyết đoán được thực hiện mà không có sự rõ ràng có thể đi sai hướng; hãy dừng lại cho đến khi ánh sáng trở lại.", en: "The Moon and Swords Knight: charging through fog — the Moon warns the Knight that decisive action taken without clarity may be misdirected; pause until the light returns." },
  "18_62": { vi: "Mặt Trăng và Nữ Hoàng Kiếm: nhận thức sắc bén cắt qua ảo tưởng — sự rõ ràng của Nữ Hoàng là một món quà ở đây; sự nhầm lẫn của Mặt Trăng được điều hướng tốt nhất bởi tâm trí tìm kiếm sự thật, sắc bén của Nữ Hoàng.", en: "The Moon and Swords Queen: sharp perception cutting through illusion — the Queen's clarity is a gift here; the Moon's confusion is best navigated by the Queen's incisive, truth-seeking mind." },
  "18_63": { vi: "Mặt Trăng và Vua Kiếm: quyền uy đối mặt với sự không chắc chắn sâu xa — Mặt Trăng làm suy yếu những phán xét tự tin của Vua; những lực lượng sâu xa hơn đang hoạt động bên dưới bề mặt của phân tích lý trí.", en: "The Moon and Swords King: authority facing deep uncertainty — the Moon undermines the King's confident judgments; deeper forces are at work beneath the surface of rational analysis." },
  "18_74": { vi: "Mặt Trăng và Trang Bị Tiền: những khởi đầu vật chất bị che khuất bởi sự nhầm lẫn — Mặt Trăng cảnh báo học trò rằng con đường thực tế phía trước chưa rõ ràng; hãy thực hiện những bước nhỏ, cẩn thận thay vì những bước nhảy táo bạo.", en: "The Moon and Pentacles Page: material beginnings obscured by confusion — the Moon warns the student that the practical path ahead is unclear; take small, careful steps rather than bold leaps." },
  "18_75": { vi: "Mặt Trăng và Kỵ Sĩ Tiền: tiến trình có phương pháp bị cản trở bởi sự không chắc chắn — Mặt Trăng và Kỵ Sĩ báo hiệu thời điểm làm chậm nhịp độ ổn định; những gì có vẻ là con đường vật chất đúng đắn có thể chưa rõ ràng.", en: "The Moon and Pentacles Knight: methodical progress hampered by uncertainty — the Moon and Knight signal a time to slow the steady pace; what seems like the right material path may not yet be clear." },
  "18_76": { vi: "Mặt Trăng và Nữ Hoàng Tiền: sự phong phú thực tế bị che mờ bởi những nỗi sợ tiềm thức — Mặt Trăng cảnh báo Nữ Hoàng rằng những lo lắng ẩn giấu có thể bóp méo các quyết định vật chất; hãy tin vào bản năng thay vì vẻ bề ngoài.", en: "The Moon and Pentacles Queen: practical abundance clouded by subconscious fears — the Moon warns the Queen that hidden anxieties may be distorting material decisions; trust instinct over appearances." },
  "18_77": { vi: "Mặt Trăng và Vua Tiền: sự chắc chắn vật chất bị đặt câu hỏi bởi những lực lượng sâu xa hơn — Mặt Trăng gợi ý rằng sự giàu có đã thiết lập của Vua che giấu những nỗi sợ chưa được kiểm tra; hãy nhìn bên dưới bề mặt của sự thịnh vượng.", en: "The Moon and Pentacles King: material certainty questioned by deeper forces — the Moon suggests the King's established wealth hides unexamined fears; look beneath the surface of prosperity." },

  // Sun (19) × Courts
  "19_32": { vi: "Mặt Trời và Trang Bị Gậy: sự nhiệt tình trẻ trung rạng rỡ — Mặt Trời khuếch đại ngọn lửa của Trang Bị với sự tự tin rõ ràng, vui vẻ; những khởi đầu sáng tạo được ban phước bởi sự ấm áp, sức sống và năng lượng lạc quan.", en: "The Sun and Wands Page: radiant young enthusiasm — the Sun amplifies the Page's fire with clear, joyful confidence; creative beginnings blessed by warmth, vitality, and optimistic energy." },
  "19_33": { vi: "Mặt Trời và Kỵ Sĩ Gậy: cuộc xung phong vui mừng — Mặt Trời và Kỵ Sĩ cùng nhau tỏa ra động lực không thể ngăn cản, đầy phấn khích; sự theo đuổi táo bạo được soi sáng bởi niềm vui thực sự và sự rõ ràng về mục đích.", en: "The Sun and Wands Knight: the joyful charge — the Sun and Knight together radiate unstoppable, celebratory momentum; bold pursuit illuminated by genuine joy and clarity of purpose." },
  "19_34": { vi: "Mặt Trời và Nữ Hoàng Gậy: quyền năng sáng tạo rạng rỡ ở đỉnh cao — Mặt Trời và Nữ Hoàng cùng nhau đại diện cho biểu hiện đầy đủ nhất của năng lượng sáng tạo tự tin, vui tươi; sự hiện diện truyền cảm hứng.", en: "The Sun and Wands Queen: radiant creative power at its peak — the Sun and Queen together represent the fullest expression of confident, joyful creative energy; an inspiring, magnetic presence." },
  "19_35": { vi: "Mặt Trời và Vua Gậy: sự lãnh đạo có tầm nhìn trong ánh sáng đầy đủ — Mặt Trời và Vua cùng nhau tỏa ra quyền uy, sự rõ ràng và thành công đầy cảm hứng; sự lãnh đạo thu hút người khác đến một tương lai thực sự tươi sáng.", en: "The Sun and Wands King: visionary leadership in full light — the Sun and King together radiate authority, clarity, and inspiring success; leadership that draws others toward a genuinely bright future." },
  "19_46": { vi: "Mặt Trời và Trang Bị Cốc: niềm vui và sự kỳ diệu cảm xúc được soi sáng — Mặt Trời và Trang Bị cùng nhau vui đùa trong sự ấm áp của cảm xúc cởi mở từ trái tim; những khởi đầu cảm xúc được ban phước bởi sự rõ ràng, ấm áp và niềm vui thuần túy.", en: "The Sun and Cups Page: joy and emotional wonder illuminated — the Sun and Page together play in the warmth of open-hearted feeling; emotional beginnings blessed by clarity, warmth, and pure joy." },
  "19_47": { vi: "Mặt Trời và Kỵ Sĩ Cốc: cuộc tìm kiếm lãng mạn được ban phước bởi niềm vui — Mặt Trời và Kỵ Sĩ cùng nhau tỏa ra sự theo đuổi hạnh phúc, lạc quan; tình yêu được tìm kiếm từ nơi của sự ấm áp thực sự thay vì từ sự khao khát.", en: "The Sun and Cups Knight: the romantic quest blessed by joy — the Sun and Knight together radiate happy, optimistic pursuit; love sought from a place of genuine warmth rather than longing." },
  "19_48": { vi: "Mặt Trời và Nữ Hoàng Cốc: sự ấm áp cảm xúc và lòng từ bi rạng rỡ — Mặt Trời và Nữ Hoàng cùng nhau đại diện cho tình yêu, niềm vui và sự nuôi dưỡng ở trạng thái hào phóng và soi sáng nhất; sự chữa lành qua niềm vui.", en: "The Sun and Cups Queen: radiant emotional warmth and compassion — the Sun and Queen together represent love, joy, and nurturing at their most generous and illuminated; healing through joy." },
  "19_49": { vi: "Mặt Trời và Vua Cốc: sự thành thạo cảm xúc vui vẻ — Mặt Trời và Vua cùng nhau đại diện cho sự khôn ngoan và lòng từ bi được thể hiện với niềm hạnh phúc thực sự; sự hiểu biết sâu sắc được làm sáng tươi bởi sự ấm áp.", en: "The Sun and Cups King: joyful emotional mastery — the Sun and King together represent wisdom and compassion expressed with genuine happiness; deep understanding brightened by warmth." },
  "19_60": { vi: "Mặt Trời và Trang Bị Kiếm: sự rõ ràng tinh thần và sự tò mò vui tươi — Mặt Trời soi sáng tâm trí sắc bén của Trang Bị; sự tìm tòi trí tuệ được hướng dẫn bởi chủ nghĩa lạc quan và niềm vui thực sự của khám phá.", en: "The Sun and Swords Page: mental clarity and joyful curiosity — the Sun illuminates the Page's sharp mind; intellectual inquiry guided by optimism and the genuine delight of discovery." },
  "19_61": { vi: "Mặt Trời và Kỵ Sĩ Kiếm: hành động quyết đoán với đầy đủ sự tự tin — Mặt Trời và Kỵ Sĩ cùng nhau xung phong với sự rõ ràng và niềm vui; sức mạnh chính nghĩa, định hướng tốt phục vụ một mục đích thực sự tươi sáng.", en: "The Sun and Swords Knight: decisive action in full confidence — the Sun and Knight together charge forward with clarity and joy; righteous, well-directed force in service of a genuinely bright purpose." },
  "19_62": { vi: "Mặt Trời và Nữ Hoàng Kiếm: sự thật được soi sáng bởi niềm vui — Mặt Trời làm dịu sự sắc bén của Nữ Hoàng bằng sự ấm áp; nhận thức rõ ràng, thành thật được truyền đạt với sự rạng rỡ thực sự thay vì khắc nghiệt.", en: "The Sun and Swords Queen: truth illuminated by joy — the Sun softens the Queen's sharpness with warmth; clear, honest perception delivered with genuine radiance rather than severity." },
  "19_63": { vi: "Mặt Trời và Vua Kiếm: quyền uy phân tích trong ánh sáng đầy đủ — Mặt Trời và Vua cùng nhau đại diện cho quản trị sắc bén, tự tin; sự lãnh đạo được hướng dẫn bởi sự rõ ràng, chủ nghĩa lạc quan và sự khôn ngoan thực sự.", en: "The Sun and Swords King: analytical authority in full light — the Sun and King together represent sharp, confident governance; leadership guided by clarity, optimism, and genuine wisdom." },
  "19_74": { vi: "Mặt Trời và Trang Bị Tiền: những khởi đầu vật chất được ban phước bởi niềm vui và sự rõ ràng — Mặt Trời và Trang Bị cùng nhau bắt đầu những dự án thực tế với sự ấm áp và lạc quan; những nỗ lực ban đầu được hướng dẫn bởi sự nhiệt tình thực sự.", en: "The Sun and Pentacles Page: material beginnings blessed by joy and clarity — the Sun and Page together start practical ventures with warmth and optimism; early efforts guided by genuine enthusiasm." },
  "19_75": { vi: "Mặt Trời và Kỵ Sĩ Tiền: tiến trình ổn định được soi sáng bởi niềm vui — Mặt Trời và Kỵ Sĩ cùng nhau mang lại sự ấm áp và tự tin cho nỗ lực có phương pháp; các mục tiêu vật chất được theo đuổi với niềm hạnh phúc thực sự.", en: "The Sun and Pentacles Knight: steady progress illuminated by joy — the Sun and Knight together bring warmth and confidence to methodical effort; material goals pursued with genuine happiness." },
  "19_76": { vi: "Mặt Trời và Nữ Hoàng Tiền: sự thịnh vượng dồi dào trong sự rạng rỡ đầy đủ — Mặt Trời và Nữ Hoàng cùng nhau đại diện cho đỉnh cao của sự nuôi dưỡng vật chất hào phóng, ấm áp, vui tươi; nở rộ theo mọi nghĩa.", en: "The Sun and Pentacles Queen: abundant prosperity in full radiance — the Sun and Queen together represent the height of generous, warm, joyful material nurturing; flourishing in every sense." },
  "19_77": { vi: "Mặt Trời và Vua Tiền: sự thành thạo vật chất được soi sáng bởi niềm vui — Mặt Trời và Vua cùng nhau đại diện cho sự thịnh vượng đã thiết lập được thể hiện với sự ấm áp và hào phóng thực sự; sự giàu có thực sự tỏa sáng.", en: "The Sun and Pentacles King: material mastery illuminated by joy — the Sun and King together represent established prosperity expressed with genuine warmth and generosity; wealth that truly radiates." },

  // Judgement (20) × Courts
  "20_32": { vi: "Phán Xét và Trang Bị Gậy: lời kêu gọi đến một mục đích sáng tạo cao hơn — Phán Xét thức tỉnh Trang Bị đến tiềm năng sâu sắc hơn; ngọn lửa trước đây chỉ nhiệt tình giờ trở nên thực sự có mục đích.", en: "Judgement and Wands Page: the call to a higher creative purpose — Judgement awakens the Page to a deeper potential; the fire that was merely enthusiastic now becomes genuinely purposeful." },
  "20_33": { vi: "Phán Xét và Kỵ Sĩ Gậy: cuộc xung phong được biến đổi bởi sự thức tỉnh — Phán Xét chuyển hướng động lực của Kỵ Sĩ đến thiên chức thực sự của nó; những gì được theo đuổi trở thành những gì luôn được định sẵn.", en: "Judgement and Wands Knight: the charge transformed by awakening — Judgement redirects the Knight's momentum toward its true calling; what was pursued becomes what was always meant to be." },
  "20_34": { vi: "Phán Xét và Nữ Hoàng Gậy: sự tái sinh sáng tạo — Phán Xét gọi Nữ Hoàng đến mục đích sáng tạo cao nhất của cô; một sự thức tỉnh lớn về mục đích thực sự của ngọn lửa; sự sáng tạo lấy cảm hứng, được giải phóng.", en: "Judgement and Wands Queen: creative rebirth — Judgement calls the Queen to her highest creative purpose; a major awakening to what the fire is truly for; inspired, liberated creation." },
  "20_35": { vi: "Phán Xét và Vua Gậy: nhà lãnh đạo trả lời lời kêu gọi cao hơn — Phán Xét thức tỉnh Vua đến một tầm nhìn sâu sắc hơn; quyền uy được tái sinh xung quanh mục đích thực sự thay vì quyền lực.", en: "Judgement and Wands King: the leader answers a higher calling — Judgement awakens the King to a deeper vision; authority reborn around genuine purpose rather than power." },
  "20_46": { vi: "Phán Xét và Trang Bị Cốc: lời kêu gọi đến sự thật cảm xúc sâu sắc hơn — Phán Xét thức tỉnh trái tim dịu dàng đến tiềm năng cảm xúc thực sự của nó; những mô hình cũ được buông bỏ để có cảm xúc chân thực.", en: "Judgement and Cups Page: the call to deeper emotional truth — Judgement awakens the tender heart to its genuine emotional potential; old patterns released for authentic feeling." },
  "20_47": { vi: "Phán Xét và Kỵ Sĩ Cốc: cuộc tìm kiếm lãng mạn được thức tỉnh — Phán Xét gọi Kỵ Sĩ đến một tình yêu sâu sắc hơn, chân thực hơn; những gì được tìm kiếm trên bề mặt nhường chỗ cho điều gì đó thực sự biến đổi.", en: "Judgement and Cups Knight: the romantic quest awakened — Judgement calls the Knight to a deeper, more authentic love; what was sought on the surface yields to something genuinely transformative." },
  "20_48": { vi: "Phán Xét và Nữ Hoàng Cốc: thức tỉnh đến lòng từ bi sâu sắc nhất — Phán Xét và Nữ Hoàng cùng nhau báo hiệu sự làm mới sâu sắc của mục đích nuôi dưỡng; được chữa lành và được gọi để chữa lành người khác.", en: "Judgement and Cups Queen: awakening to the deepest compassion — Judgement and the Queen together signal a profound renewal of nurturing purpose; healed and called to heal others." },
  "20_49": { vi: "Phán Xét và Vua Cốc: sự khôn ngoan cảm xúc được gọi đến biểu hiện cao nhất — Phán Xét thức tỉnh Vua đến một mức độ sâu hơn của lòng từ bi và quyền uy; sự khôn ngoan chín chắn được tái sinh như một lời kêu gọi thực sự.", en: "Judgement and Cups King: emotional wisdom called to its highest expression — Judgement awakens the King to a deeper level of compassion and authority; mature wisdom reborn as genuine calling." },
  "20_60": { vi: "Phán Xét và Trang Bị Kiếm: sự thức tỉnh tinh thần — Phán Xét gọi người tư duy trẻ đến một mức độ thành thật trí tuệ cao hơn; những mô hình tinh thần lỗi thời được buông bỏ để có sự hiểu biết rõ ràng hơn, chân thực hơn.", en: "Judgement and Swords Page: mental awakening — Judgement calls the young thinker to a higher level of intellectual honesty; outdated mental patterns released for clearer, more authentic understanding." },
  "20_61": { vi: "Phán Xét và Kỵ Sĩ Kiếm: sự thức tỉnh quyết đoán — Phán Xét chuyển hướng sức mạnh của Kỵ Sĩ đến mục đích thực sự của nó; những gì đã chiến đấu được biến đổi bởi cái nhìn sâu sắc thực sự về những gì đáng chiến đấu.", en: "Judgement and Swords Knight: decisive awakening — Judgement redirects the Knight's force toward its true purpose; what was fought for is transformed by genuine insight into what is worth fighting for." },
  "20_62": { vi: "Phán Xét và Nữ Hoàng Kiếm: sự thật như sự giải phóng — Phán Xét và Nữ Hoàng cùng nhau đại diện cho sự xóa bỏ ảo tưởng tột cùng; sự reckoning thành thật giải phóng cả người nói lẫn người nghe.", en: "Judgement and Swords Queen: truth as liberation — Judgement and the Queen together represent the ultimate clearing of illusion; honest reckoning that frees both speaker and listener." },
  "20_63": { vi: "Phán Xét và Vua Kiếm: quyền uy trí tuệ được thức tỉnh đến mục đích cao hơn — Phán Xét gọi quyền lực phân tích của Vua đến biểu hiện thực sự, được giải phóng nhất của nó; sự khôn ngoan được tái sinh.", en: "Judgement and Swords King: intellectual authority awakened to higher purpose — Judgement calls the King's analytical power toward its truest, most liberated expression; wisdom reborn." },
  "20_74": { vi: "Phán Xét và Trang Bị Tiền: lời kêu gọi vật chất được thức tỉnh — Phán Xét biến đổi những nỗ lực thực tế của học trò thành thiên chức thực sự; những gì chỉ được học trở nên thực sự có ý nghĩa.", en: "Judgement and Pentacles Page: material calling awakened — Judgement transforms the student's practical efforts into genuine vocation; what was merely studied becomes authentically meaningful." },
  "20_75": { vi: "Phán Xét và Kỵ Sĩ Tiền: con đường có phương pháp trở thành lời kêu gọi — Phán Xét thức tỉnh Kỵ Sĩ đến mục đích sâu xa hơn của công việc bền bỉ; lao động được biến đổi thành đóng góp có ý nghĩa.", en: "Judgement and Pentacles Knight: the methodical path becomes a calling — Judgement awakens the Knight to the deeper purpose of steady work; labor transformed into meaningful contribution." },
  "20_76": { vi: "Phán Xét và Nữ Hoàng Tiền: sự hào phóng dồi dào được tái sinh như lời kêu gọi — Phán Xét và Nữ Hoàng báo hiệu sự thức tỉnh lớn về mục đích thực sự của sự quản lý vật chất; sự nuôi dưỡng như thiên chức thiêng liêng.", en: "Judgement and Pentacles Queen: abundant generosity reborn as calling — Judgement and the Queen signal a major awakening to the true purpose of material stewardship; nurturing as sacred vocation." },
  "20_77": { vi: "Phán Xét và Vua Tiền: sự thành thạo vật chất được thức tỉnh đến di sản — Phán Xét gọi Vua nhìn nhận sự giàu có của mình như phương tiện để đóng góp thực sự; sự thịnh vượng phục vụ điều gì đó lớn hơn.", en: "Judgement and Pentacles King: material mastery awakened to legacy — Judgement calls the King to see his wealth as a vehicle for genuine contribution; prosperity in service of something larger." },

  // World (21) × Courts
  "21_32": { vi: "Thế Giới và Trang Bị Gậy: một chương hoàn chỉnh truyền cảm hứng cho những khởi đầu mới — sự toàn vẹn của Thế Giới khuyến khích Trang Bị rằng những chu kỳ sáng tạo đầy đủ là có thể; sự hoàn thành như nhiên liệu cho ngọn lửa mới.", en: "The World and Wands Page: a completed chapter inspiring new beginnings — the World's wholeness encourages the Page that full creative cycles are possible; completion as the fuel for new fire." },
  "21_33": { vi: "Thế Giới và Kỵ Sĩ Gậy: cuộc tìm kiếm hoàn thành — Thế Giới và Kỵ Sĩ cùng nhau báo hiệu sự đến đích thắng lợi; một mục tiêu sáng tạo hoặc cuộc sống lớn được hoàn thành đầy đủ.", en: "The World and Wands Knight: the quest completed — the World and Knight together signal the triumphant arrival at the destination; a major creative or life goal fully achieved." },
  "21_34": { vi: "Thế Giới và Nữ Hoàng Gậy: sự thành thạo sáng tạo được hiện thực hóa hoàn toàn — Thế Giới và Nữ Hoàng cùng nhau đại diện cho đỉnh cao của quyền năng sáng tạo được đạt đến; biểu hiện đầy đủ của bản thân chân thực, tích hợp.", en: "The World and Wands Queen: creative mastery fully realized — the World and Queen together represent the peak of creative power achieved; complete expression of authentic, integrated self." },
  "21_35": { vi: "Thế Giới và Vua Gậy: sự lãnh đạo có tầm nhìn được hoàn thành — Thế Giới và Vua cùng nhau đại diện cho sự hiện thực hóa đầy đủ của một tầm nhìn lớn; quyền uy, thành tựu và sự toàn vẹn được tích hợp.", en: "The World and Wands King: visionary leadership fulfilled — the World and King together represent the full realization of a grand vision; authority, achievement, and wholeness integrated." },
  "21_46": { vi: "Thế Giới và Trang Bị Cốc: sự hoàn thành cảm xúc truyền cảm hứng cho sự kỳ diệu mới — sự trọn vẹn của Thế Giới khuyến khích trái tim nhạy cảm rằng sự toàn vẹn cảm xúc là có thể; sự hoàn thành mở ra cảm xúc tươi mới.", en: "The World and Cups Page: emotional completion inspiring new wonder — the World's fulfillment encourages the sensitive heart that emotional wholeness is possible; completion opens into fresh feeling." },
  "21_47": { vi: "Thế Giới và Kỵ Sĩ Cốc: cuộc tìm kiếm lãng mạn đạt đến sự hoàn thành chân thực nhất — Thế Giới và Kỵ Sĩ cùng nhau báo hiệu rằng tình yêu đã được tìm thấy, tích hợp và được sống trọn vẹn; cuộc tìm kiếm được hoàn thành.", en: "The World and Cups Knight: the romantic quest reaches its truest completion — the World and Knight together signal that love has been found, integrated, and fully lived; the quest fulfilled." },
  "21_48": { vi: "Thế Giới và Nữ Hoàng Cốc: sự thành thạo cảm xúc và sự toàn vẹn được hợp nhất — Thế Giới và Nữ Hoàng cùng nhau đại diện cho biểu hiện đầy đủ nhất của sự khôn ngoan từ bi; tình yêu và sự nuôi dưỡng được đưa đến hoàn thành.", en: "The World and Cups Queen: emotional mastery and wholeness united — the World and Queen together represent the fullest expression of compassionate wisdom; love and nurturing brought to completion." },
  "21_49": { vi: "Thế Giới và Vua Cốc: quyền uy cảm xúc được tích hợp hoàn toàn — Thế Giới và Vua cùng nhau đại diện cho sự tích hợp đầy đủ của chiều sâu, lòng từ bi và sự khôn ngoan; sự hoàn thành chín chắn của mục đích cảm xúc.", en: "The World and Cups King: emotional authority fully integrated — the World and King together represent the complete integration of depth, compassion, and wisdom; mature fulfillment of emotional purpose." },
  "21_60": { vi: "Thế Giới và Trang Bị Kiếm: sự hoàn thành trí tuệ truyền cảm hứng cho những câu hỏi mới — sự toàn vẹn của Thế Giới khuyến khích người tư duy trẻ rằng sự hiểu biết đầy đủ là có thể; sự hoàn thành mở ra sự tìm tòi mới.", en: "The World and Swords Page: intellectual completion inspiring new questions — the World's wholeness encourages the young thinker that full understanding is possible; completion opens into new inquiry." },
  "21_61": { vi: "Thế Giới và Kỵ Sĩ Kiếm: cuộc tìm kiếm quyết đoán hoàn thành — Thế Giới và Kỵ Sĩ cùng nhau báo hiệu sự đạt được mục tiêu lớn qua hành động quyết đoán, có mục đích; nhiệm vụ hoàn thành.", en: "The World and Swords Knight: the decisive quest completed — the World and Knight together signal the achievement of a major goal through decisive, purposeful action; mission accomplished." },
  "21_62": { vi: "Thế Giới và Nữ Hoàng Kiếm: sự thật được nhận thức đầy đủ và tích hợp — Thế Giới và Nữ Hoàng cùng nhau đại diện cho sự hiểu biết rõ ràng, hoàn chỉnh; sự reckoning thành thật được đưa đến sự toàn vẹn và hoàn thành.", en: "The World and Swords Queen: truth fully perceived and integrated — the World and Queen together represent complete, clear-eyed understanding; honest reckoning brought to wholeness and fulfillment." },
  "21_63": { vi: "Thế Giới và Vua Kiếm: quyền uy trí tuệ được đưa đến hoàn thành — Thế Giới và Vua cùng nhau đại diện cho sự hiện thực hóa đầy đủ của sự thành thạo phân tích; sự khôn ngoan và quyền uy được tích hợp hoàn toàn.", en: "The World and Swords King: intellectual authority brought to completion — the World and King together represent the full realization of analytical mastery; wisdom and authority fully integrated." },
  "21_74": { vi: "Thế Giới và Trang Bị Tiền: nền tảng vật chất được đặt hoàn toàn — Thế Giới khuyến khích học trò rằng sự thành thạo thực tế đầy đủ là kết quả tự nhiên của việc học tập tận tâm; sự hoàn thành truyền cảm hứng cho sự học hỏi mới.", en: "The World and Pentacles Page: material foundations fully laid — the World encourages the student that complete practical mastery is the natural end of dedicated learning; completion inspires new study." },
  "21_75": { vi: "Thế Giới và Kỵ Sĩ Tiền: hành trình vật chất hoàn thành — Thế Giới và Kỵ Sĩ cùng nhau báo hiệu sự đạt được các mục tiêu vật chất lớn qua nỗ lực ổn định, kiên trì; điểm đến được đạt tới.", en: "The World and Pentacles Knight: the material journey completed — the World and Knight together signal the achievement of major material goals through steady, persistent effort; the destination reached." },
  "21_76": { vi: "Thế Giới và Nữ Hoàng Tiền: sự thịnh vượng dồi dào được hiện thực hóa hoàn toàn — Thế Giới và Nữ Hoàng cùng nhau đại diện cho đỉnh cao của sự hào phóng vật chất và sự nuôi dưỡng; sự phong phú hoàn chỉnh, tích hợp.", en: "The World and Pentacles Queen: abundant prosperity fully realized — the World and Queen together represent the peak of material generosity and nurturing; complete, integrated abundance." },
  "21_77": { vi: "Thế Giới và Vua Tiền: sự thành thạo vật chất được đưa đến hoàn thành — Thế Giới và Vua cùng nhau đại diện cho đỉnh cao của sự giàu có đã thiết lập và di sản; thành tựu đầy đủ của mục đích vật chất.", en: "The World and Pentacles King: material mastery brought to fulfillment — the World and King together represent the pinnacle of established wealth and legacy; complete achievement of material purpose." },

  // ─── TIER 3a: Major × Wands Numbered (220 pairs) ────────────────────────────
  // Task 6a: Majors 0–7 × Wands 22–31

  // Fool (0) × Wands
  "0_22": { vi: "Kẻ Ngốc và Át Gậy: tiềm năng thuần túy gặp tia lửa sáng tạo — đây là khoảnh khắc hoàn hảo để bắt đầu điều bạn hằng ấp ủ mà chưa dám thử.", en: "The Fool and Ace of Wands: pure potential meets the spark of creative fire — this is the perfect moment to begin what you have been too cautious to attempt." },
  "0_23": { vi: "Kẻ Ngốc và Hai Gậy: bước nhảy ngây thơ gặp tầm nhìn mở rộng — hãy cầm bản đồ thế giới và dũng cảm lên kế hoạch cho những chân trời chưa ai khai phá.", en: "The Fool and Two of Wands: an innocent leap meets expanding vision — hold the map of the world and boldly plan for horizons no one has yet explored." },
  "0_24": { vi: "Kẻ Ngốc và Ba Gậy: hành trình ngây thơ đứng trên bờ cao nhìn ra cơ hội xa xôi — niềm tin vào tương lai là tài sản duy nhất bạn cần mang theo.", en: "The Fool and Three of Wands: the innocent journey stands at the high shore looking out at distant opportunity — faith in the future is the only asset you need to carry." },
  "0_25": { vi: "Kẻ Ngốc và Bốn Gậy: bước khởi đầu dẫn thẳng đến sự chào đón và ăn mừng — hãy tin rằng cộng đồng đang chờ đón bạn ở phía bên kia của bước nhảy.", en: "The Fool and Four of Wands: your first steps lead directly to welcome and celebration — trust that a community is waiting for you on the other side of the leap." },
  "0_26": { vi: "Kẻ Ngốc và Năm Gậy: năng lượng mới bước vào một khung cảnh náo nhiệt đầy cạnh tranh — hãy giữ tinh thần vui vẻ vì đây là sự cọ xát cần thiết để lớn lên.", en: "The Fool and Five of Wands: fresh energy steps into a noisy scene of rivalry — keep your spirit light, because this friction is the necessary edge for growth." },
  "0_27": { vi: "Kẻ Ngốc và Sáu Gậy: sự táo bạo ngây thơ dẫn đến sự công nhận bất ngờ — đừng đánh giá thấp những gì xảy ra khi bạn hành động mà không sợ hãi.", en: "The Fool and Six of Wands: innocent boldness leads to unexpected recognition — never underestimate what happens when you act without fear of failure." },
  "0_28": { vi: "Kẻ Ngốc và Bảy Gậy: sự tự tin ngây thơ đứng vững trước những kẻ thách thức — hãy tin vào lợi thế duy nhất của bạn: bạn không biết mình được cho là phải sợ.", en: "The Fool and Seven of Wands: innocent confidence holds ground against challengers — trust your unique advantage: you do not know you are supposed to be afraid." },
  "0_29": { vi: "Kẻ Ngốc và Tám Gậy: bước nhảy bốc đồng khớp với tốc độ của những cơ hội đang ùa đến — hành động ngay bây giờ, vì cửa sổ này đóng lại rất nhanh.", en: "The Fool and Eight of Wands: the impulsive leap matches the speed of incoming opportunities — act now, because this window closes quickly." },
  "0_30": { vi: "Kẻ Ngốc và Chín Gậy: khởi đầu mới gặp sự kiên cường được rèn giũa từ những thử thách cũ — bạn đang bước vào với những vết thương đã lành thành sức mạnh.", en: "The Fool and Nine of Wands: a fresh start meets the resilience forged by past trials — you are stepping in with wounds that have healed into strength." },
  "0_31": { vi: "Kẻ Ngốc và Mười Gậy: hành trình mới có nguy cơ bị đè nặng trước khi nó thực sự bắt đầu — hãy đặt xuống những gánh nặng cũ trước khi bước lên con đường mới.", en: "The Fool and Ten of Wands: the new journey risks being crushed under old burdens before it truly begins — set down what you no longer need before stepping onto the new path." },

  // Magician (1) × Wands
  "1_22": { vi: "Pháp Sư và Át Gậy: ý chí tập trung gặp tia lửa sáng tạo thuần túy — đây là sức mạnh biểu hiện mạnh nhất có thể; hãy hành động trước khi khoảnh khắc này qua đi.", en: "The Magician and Ace of Wands: focused will meets pure creative spark — this is manifestation power at its peak; act before this moment passes." },
  "1_23": { vi: "Pháp Sư và Hai Gậy: ý định có chủ đích gặp kế hoạch chiến lược mở rộng — hãy dùng kỹ năng của bạn để lên bản đồ con đường, không chỉ ước mơ về nó.", en: "The Magician and Two of Wands: purposeful intention meets strategic expansion — use your skills to map the route, not merely dream about it." },
  "1_24": { vi: "Pháp Sư và Ba Gậy: năng lực có chủ đích nhìn ra những cơ hội vượt ra ngoài chân trời hiện tại — bạn đã chuẩn bị đủ để chinh phục vùng đất mới.", en: "The Magician and Three of Wands: purposeful capability looks beyond the current horizon — you are prepared enough to claim new territory." },
  "1_25": { vi: "Pháp Sư và Bốn Gậy: nỗ lực có kỹ năng đạt đến thời điểm ăn mừng và nền tảng vững chắc — hãy thừa nhận những gì bạn đã xây dựng trước khi tiếp tục.", en: "The Magician and Four of Wands: skillful effort reaches a moment of celebration and solid foundation — acknowledge what you have built before moving on." },
  "1_26": { vi: "Pháp Sư và Năm Gậy: người thành thạo bị thử thách bởi những lực lượng cạnh tranh và ma sát — hãy dùng kỹ năng để điều hướng sự hỗn loạn, không phải để kiểm soát nó.", en: "The Magician and Five of Wands: the master is tested by competing forces and friction — use skill to navigate the chaos, not to control it." },
  "1_27": { vi: "Pháp Sư và Sáu Gậy: sự thành thạo được ghi nhận bởi sự công nhận công khai xứng đáng — đây là khoảnh khắc xác nhận rằng những gì bạn đã rèn giũa là có giá trị.", en: "The Magician and Six of Wands: mastery earns well-deserved public recognition — this is the confirming moment that what you have honed holds real value." },
  "1_28": { vi: "Pháp Sư và Bảy Gậy: ý chí tập trung đứng vững trước sự phản đối ngày càng tăng — hãy giữ vị thế của bạn bằng sự rõ ràng, không phải bằng sự cứng nhắc.", en: "The Magician and Seven of Wands: focused will holds firm against mounting opposition — keep your position through clarity, not rigidity." },
  "1_29": { vi: "Pháp Sư và Tám Gậy: hành động có chủ đích tăng tốc thành đà thúc đẩy nhanh và quyết định — hãy chỉ đạo năng lượng này chứ đừng để nó cuốn bạn trôi.", en: "The Magician and Eight of Wands: intentional action accelerates into swift decisive momentum — direct this energy or it will carry you with it." },
  "1_30": { vi: "Pháp Sư và Chín Gậy: sự kiên cường được thử thách củng cố sức mạnh của nỗ lực bền vững — mỗi vết thương bạn đã vượt qua đang biến thành công cụ trong tay bạn.", en: "The Magician and Nine of Wands: tested resilience reinforces the power of sustained effort — every wound you have overcome is becoming a tool in your hands." },
  "1_31": { vi: "Pháp Sư và Mười Gậy: tham vọng và kỹ năng có nguy cơ bị chôn vùi dưới quá nhiều nghĩa vụ — hãy dùng khả năng của bạn để ủy thác, không phải để tích lũy thêm.", en: "The Magician and Ten of Wands: ambition and skill risk being buried under too many obligations — use your capability to delegate, not to accumulate more." },

  // High Priestess (2) × Wands
  "2_22": { vi: "Thầy Tư Tế Nữ và Át Gậy: trí tuệ nội tâm châm ngòi một xung lực sáng tạo táo bạo — hãy tin vào tia lửa mà bạn cảm nhận được sâu bên trong trước khi lý trí giải thích nó.", en: "The High Priestess and Ace of Wands: inner knowing sparks a bold creative impulse — trust the fire you feel deep within before your mind explains it away." },
  "2_23": { vi: "Thầy Tư Tế Nữ và Hai Gậy: trí tuệ thầm lặng định hình những kế hoạch tầm xa — hãy để trực giác vẽ bản đồ trước khi tham vọng lao vào chiếm đất.", en: "The High Priestess and Two of Wands: silent wisdom shapes far-reaching plans — let intuition draw the map before ambition rushes to claim the territory." },
  "2_24": { vi: "Thầy Tư Tế Nữ và Ba Gậy: trực giác hướng dẫn bạn nhìn vượt ra ngoài những gì mắt thường có thể thấy — những cơ hội tốt nhất chưa hiện ra trên bề mặt.", en: "The High Priestess and Three of Wands: intuition guides you to see beyond what the naked eye can observe — the best opportunities have not yet surfaced." },
  "2_25": { vi: "Thầy Tư Tế Nữ và Bốn Gậy: sự hài hòa nội tâm tìm thấy biểu hiện trong sự ăn mừng bên ngoài — khi bên trong và bên ngoài khớp nhau, cuộc sống trở thành lễ hội.", en: "The High Priestess and Four of Wands: inner harmony finds expression in outward celebration — when the inside and outside align, life becomes a homecoming." },
  "2_26": { vi: "Thầy Tư Tế Nữ và Năm Gậy: sự tĩnh lặng bên dưới những tiếng ồn của tham vọng cạnh tranh — hãy không tham chiến vào cuộc tranh giành; quan sát và chờ thời.", en: "The High Priestess and Five of Wands: stillness beneath the noise of competing ambitions — do not enter the scramble; observe and wait for the right moment." },
  "2_27": { vi: "Thầy Tư Tế Nữ và Sáu Gậy: kiến thức thầm lặng đứng sau một thành công được công nhận — không phải tất cả những người đã tạo nên chiến thắng đều đứng trên bục vinh quang.", en: "The High Priestess and Six of Wands: quiet knowledge stands behind a publicly recognized success — not everyone who made the victory possible stands on the podium." },
  "2_28": { vi: "Thầy Tư Tế Nữ và Bảy Gậy: sự xác tín bên trong là nền móng để đứng vững trước mọi thách thức — bạn không cần thuyết phục người khác; bạn chỉ cần biết mình đúng.", en: "The High Priestess and Seven of Wands: inner conviction is the foundation to stand firm against every challenge — you do not need to convince others; you only need to know you are right." },
  "2_29": { vi: "Thầy Tư Tế Nữ và Tám Gậy: trực giác hành động nhanh chóng khi khoảnh khắc đúng đắn xuất hiện — đây không phải sự bốc đồng; đây là sự im lặng đã chờ đúng thời điểm.", en: "The High Priestess and Eight of Wands: intuition acts swiftly when the right moment arrives — this is not impulsiveness; it is stillness that has waited for its precise opening." },
  "2_30": { vi: "Thầy Tư Tế Nữ và Chín Gậy: sự hiểu biết sâu sắc duy trì bạn qua những thử thách kéo dài — hãy uống từ giếng nội tâm khi nguồn lực bên ngoài đã cạn kiệt.", en: "The High Priestess and Nine of Wands: deep knowing sustains you through prolonged trials — drink from the inner well when outer resources run dry." },
  "2_31": { vi: "Thầy Tư Tế Nữ và Mười Gậy: trí tuệ thầm lặng tiết lộ những gánh nặng nào thực sự là của bạn để mang — một số thứ bạn đang vác là của người khác; đã đến lúc đặt chúng xuống.", en: "The High Priestess and Ten of Wands: silent wisdom reveals which burdens are truly yours to carry — some of what you bear belongs to others; it is time to set it down." },

  // Empress (3) × Wands
  "3_22": { vi: "Nữ Hoàng và Át Gậy: sự sáng tạo phong phú sinh ra một tia lửa sống động mới — đây là thời điểm của sự sinh sôi; hãy gieo những hạt giống mà bạn muốn thu hoạch.", en: "The Empress and Ace of Wands: abundant creativity births a vibrant new spark of life — this is the season of fertility; plant the seeds you intend to harvest." },
  "3_23": { vi: "Nữ Hoàng và Hai Gậy: năng lượng nuôi dưỡng mở rộng táo bạo ra lãnh thổ mới — hãy mang tình yêu và sự kiên nhẫn vào những kế hoạch lớn lao bạn đang lập ra.", en: "The Empress and Two of Wands: nurturing energy expands boldly into new territory — bring love and patience into the grand plans you are laying out." },
  "3_24": { vi: "Nữ Hoàng và Ba Gậy: tầm nhìn màu mỡ vươn tới những chân trời tăng trưởng xa xôi — hãy tin vào sức mạnh của những gì bạn đang nuôi dưỡng; nó lớn hơn bạn có thể thấy.", en: "The Empress and Three of Wands: fertile vision reaches toward distant horizons of growth — trust the power of what you are nurturing; it is larger than you can yet see." },
  "3_25": { vi: "Nữ Hoàng và Bốn Gậy: sự phong phú và sáng tạo thể hiện trong lễ hội ổn định và vui mừng — hãy cho phép bản thân nghỉ ngơi và ăn mừng những gì đã được tạo ra.", en: "The Empress and Four of Wands: abundance and creativity manifest in stable, joyful celebration — allow yourself to rest and celebrate what has already been created." },
  "3_26": { vi: "Nữ Hoàng và Năm Gậy: sự sáng tạo phong phú bị thử thách bởi những năng lượng cạnh tranh và phân tán — hãy bảo vệ không gian sáng tạo của bạn khỏi những cuộc chiến không cần thiết.", en: "The Empress and Five of Wands: creative abundance is challenged by scattered competing energies — protect your creative space from battles that are not yours to fight." },
  "3_27": { vi: "Nữ Hoàng và Sáu Gậy: nỗ lực sáng tạo hào phóng được ghi nhận và tưởng thưởng công khai — vẻ đẹp bạn đã tạo ra đang chạm đến cuộc sống của người khác theo những cách bạn chưa biết.", en: "The Empress and Six of Wands: generous creative effort is recognized and rewarded publicly — the beauty you have created is touching others' lives in ways you have not yet seen." },
  "3_28": { vi: "Nữ Hoàng và Bảy Gậy: người tạo ra đứng vững để bảo vệ những gì đã được xây dựng với tình yêu — đây không phải về quyền lực; đây là về việc giữ gìn điều thiêng liêng.", en: "The Empress and Seven of Wands: the creator stands firm to protect what has been built with love — this is not about power; it is about preserving what is sacred." },
  "3_29": { vi: "Nữ Hoàng và Tám Gậy: đà sáng tạo chảy nhanh chóng về phía sự hoàn thành — hãy để dòng chảy dẫn dắt; đừng kiểm soát những gì đang muốn được biểu hiện.", en: "The Empress and Eight of Wands: creative momentum flows rapidly toward fruition — allow the current to lead; do not control what is trying to express itself." },
  "3_30": { vi: "Nữ Hoàng và Chín Gậy: sự kiên nhẫn bền bỉ bảo vệ những gì đã được nuôi dưỡng qua thời gian — bạn đã đứng gác quá lâu; hãy tin tưởng rằng điều bạn trồng đã có rễ vững.", en: "The Empress and Nine of Wands: patient endurance protects what has been nurtured over time — you have stood guard long enough; trust that what you planted has taken root." },
  "3_31": { vi: "Nữ Hoàng và Mười Gậy: trách nhiệm quá mức đe dọa làm cạn kiệt nguồn sáng tạo — hãy trao đi một số gánh nặng trước khi lòng hào phóng của bạn cạn kiệt.", en: "The Empress and Ten of Wands: over-responsibility threatens to deplete the creative source — give away some of the load before your generosity runs dry." },

  // Emperor (4) × Wands
  "4_22": { vi: "Hoàng Đế và Át Gậy: quyền lực định hướng một luồng lửa sáng tạo thô vào cấu trúc lâu dài — hãy xây dựng một khuôn khổ đủ mạnh để chứa đựng tầm nhìn lớn lao này.", en: "The Emperor and Ace of Wands: authority channels a burst of raw creative fire into lasting structure — build a framework strong enough to contain this grand vision." },
  "4_23": { vi: "Hoàng Đế và Hai Gậy: sự kiểm soát chiến lược mở rộng về phía những lĩnh vực ảnh hưởng mới — hãy lập kế hoạch với sự kỷ luật của một nhà lãnh đạo, không phải sự bốc đồng của một nhà phiêu lưu.", en: "The Emperor and Two of Wands: strategic control expands toward new domains of influence — plan with the discipline of a leader, not the impulse of an adventurer." },
  "4_24": { vi: "Hoàng Đế và Ba Gậy: quyền lực đã được thiết lập nhìn vượt qua biên giới hiện tại để chiếm đất mới — sức mạnh bạn đã xây dựng là nền tảng để vươn xa hơn.", en: "The Emperor and Three of Wands: established power looks beyond current borders to claim new ground — the strength you have built is the foundation for reaching further." },
  "4_25": { vi: "Hoàng Đế và Bốn Gậy: sự lãnh đạo vững mạnh tạo ra nền tảng cho niềm vui cộng đồng — những cấu trúc bạn xây dựng cho phép người khác phát triển và ăn mừng.", en: "The Emperor and Four of Wands: strong leadership creates the foundation for communal joy — the structures you build allow others to thrive and celebrate." },
  "4_26": { vi: "Hoàng Đế và Năm Gậy: thẩm quyền cứng nhắc vật lộn khi đối mặt với những lực lượng cạnh tranh — hãy biết khi nào nên kiểm soát và khi nào nên cho phép sự hỗn loạn tự giải quyết.", en: "The Emperor and Five of Wands: rigid authority struggles when confronted by competing forces — know when to control and when to allow the chaos to resolve itself." },
  "4_27": { vi: "Hoàng Đế và Sáu Gậy: quyền lực được xác nhận qua chiến thắng xứng đáng và sự công nhận công khai — đây là bằng chứng rằng con đường bạn đã xây dựng là đúng đắn.", en: "The Emperor and Six of Wands: power is confirmed through earned victory and public recognition — this is evidence that the path you have built is the right one." },
  "4_28": { vi: "Hoàng Đế và Bảy Gậy: quyền lực phải giữ vị thế khi bị thách thức từ nhiều hướng — hãy đứng vững từ nguyên tắc, không phải từ cái tôi, và vị thế của bạn sẽ không thể bị lay chuyển.", en: "The Emperor and Seven of Wands: authority must hold its ground when challenged from many directions — stand from principle, not ego, and your position will be unshakeable." },
  "4_29": { vi: "Hoàng Đế và Tám Gậy: sự lãnh đạo quyết đoán tăng tốc đà thúc đẩy hướng tới mục tiêu rõ ràng — hãy đưa ra quyết định ngay bây giờ; sự do dự sẽ làm lãng phí cơ hội này.", en: "The Emperor and Eight of Wands: decisive leadership accelerates momentum toward a clear goal — make the decision now; hesitation will waste this opportunity." },
  "4_30": { vi: "Hoàng Đế và Chín Gậy: sự kiên trì có kỷ luật đứng sau một vị trí được bảo vệ tốt — bạn đã chiến đấu quá lâu để từ bỏ bây giờ; hãy giữ phòng tuyến này.", en: "The Emperor and Nine of Wands: disciplined persistence stands behind a well-defended position — you have fought too long to surrender now; hold this line." },
  "4_31": { vi: "Hoàng Đế và Mười Gậy: sự kiểm soát thái quá dẫn đến gánh nặng trách nhiệm không thể duy trì — hãy học nghệ thuật ủy thác trước khi kiến trúc của bạn sụp đổ vì trọng lượng của chính nó.", en: "The Emperor and Ten of Wands: over-control leads to an unsustainable burden of responsibility — learn the art of delegation before your structure collapses under its own weight." },

  // Hierophant (5) × Wands
  "5_22": { vi: "Giáo Hoàng và Át Gậy: truyền thống gặp tia lửa của sự khởi đầu được truyền cảm hứng — hãy để ngọn lửa mới này soi sáng những gì là thiêng liêng trong con đường cổ xưa.", en: "The Hierophant and Ace of Wands: tradition meets the spark of an inspired new beginning — let this new fire illuminate what is sacred in the ancient path." },
  "5_23": { vi: "Giáo Hoàng và Hai Gậy: trí tuệ đã được thiết lập lên kế hoạch mở rộng vào lãnh thổ mới — hãy mang sự khôn ngoan của quá khứ như la bàn, không phải như xiềng xích.", en: "The Hierophant and Two of Wands: established wisdom plans an expansion into new territory — carry the wisdom of the past as a compass, not as a chain." },
  "5_24": { vi: "Giáo Hoàng và Ba Gậy: sự hướng dẫn đã được kiểm chứng theo thời gian hỗ trợ những chuyến phiêu lưu táo bạo hướng tới chân trời xa — hãy biết rằng những người đi trước cũng đã đứng ở đây.", en: "The Hierophant and Three of Wands: time-tested guidance supports bold ventures toward distant horizons — know that those who came before also stood here, looking outward." },
  "5_25": { vi: "Giáo Hoàng và Bốn Gậy: nghi lễ và truyền thống tạo nên nghi thức của sự trở về vui mừng — những lễ hội có ý nghĩa sâu sắc nhất là những lễ hội được neo đậu bằng hành động thiêng liêng.", en: "The Hierophant and Four of Wands: ceremony and tradition create the ritual of joyful homecoming — the most meaningful celebrations are those anchored in sacred practice." },
  "5_26": { vi: "Giáo Hoàng và Năm Gậy: giáo lý bị thách thức bởi những giọng nói cạnh tranh đang tìm kiếm được lắng nghe — không phải mọi thách thức đều là mối đe dọa; một số mang theo sự thật cần được nghe.", en: "The Hierophant and Five of Wands: doctrine is challenged by competing voices seeking to be heard — not every challenge is a threat; some carry truths worth listening to." },
  "5_27": { vi: "Giáo Hoàng và Sáu Gậy: quyền uy được tôn trọng được vinh danh và biện minh công khai — những giá trị bạn đã đứng ra bảo vệ bây giờ được thế giới ghi nhận.", en: "The Hierophant and Six of Wands: respected authority is publicly honoured and vindicated — the values you have stood for are now being acknowledged by the world." },
  "5_28": { vi: "Giáo Hoàng và Bảy Gậy: niềm tin được thiết lập đứng vững trước những quan điểm đối lập — hãy bảo vệ điều bạn biết là đúng, nhưng vẫn giữ sự khiêm tốn để lắng nghe.", en: "The Hierophant and Seven of Wands: established belief holds firm under attack from opposing views — defend what you know to be true, but keep the humility to listen." },
  "5_29": { vi: "Giáo Hoàng và Tám Gậy: sự hướng dẫn lâu đời tăng tốc hướng tới khoảnh khắc quyết định khẩn cấp — những bài học của truyền thống đang được kiểm tra bằng tốc độ của thời đại hiện tại.", en: "The Hierophant and Eight of Wands: long-held guidance speeds toward an urgent decisive moment — the lessons of tradition are being tested at the pace of the present age." },
  "5_30": { vi: "Giáo Hoàng và Chín Gậy: đức tin và truyền thống cung cấp sức chịu đựng để tiếp tục — hãy quay lại những nền tảng bạn đã xây dựng khi sức mạnh của bạn dường như cạn kiệt.", en: "The Hierophant and Nine of Wands: faith and tradition provide the endurance to continue — return to the foundations you have built when your own strength seems depleted." },
  "5_31": { vi: "Giáo Hoàng và Mười Gậy: trọng lượng của nghĩa vụ được thừa hưởng bắt đầu làm căng thẳng tinh thần — hãy phân biệt những gì bạn chọn mang và những gì bạn chỉ được cho là phải mang.", en: "The Hierophant and Ten of Wands: the weight of inherited obligation begins to strain the spirit — distinguish between what you choose to carry and what you have merely been told to bear." },

  // Lovers (6) × Wands
  "6_22": { vi: "Người Yêu Nhau và Át Gậy: một lựa chọn từ trái tim châm ngòi ngọn lửa đam mê và sáng tạo mới — hãy chọn điều làm bạn bùng cháy, không phải điều an toàn nhất.", en: "The Lovers and Ace of Wands: a choice from the heart ignites passionate new creative fire — choose what sets you alight, not what feels safest." },
  "6_23": { vi: "Người Yêu Nhau và Hai Gậy: quyết định của trái tim đòi hỏi nhìn táo bạo về phía chân trời rộng lớn hơn — tình yêu đích thực không co lại vào không gian nhỏ; nó mời bạn lớn hơn.", en: "The Lovers and Two of Wands: the heart's decision requires looking boldly toward a wider horizon — real love does not shrink into small spaces; it invites you to grow larger." },
  "6_24": { vi: "Người Yêu Nhau và Ba Gậy: sự kết hợp được chọn mở rộng về phía những cơ hội xa xôi được chia sẻ — hãy nhìn vào những gì bạn và đối tác của bạn có thể cùng nhau xây dựng ở phía chân trời.", en: "The Lovers and Three of Wands: the chosen partnership expands toward shared distant opportunities — look at what you and your partner can build together on that horizon." },
  "6_25": { vi: "Người Yêu Nhau và Bốn Gậy: tình yêu và sự liên kết giá trị đạt đến đỉnh điểm trong lễ hội vui mừng và sự thống nhất — đây là điều bạn đã làm việc hướng tới; hãy ở trong khoảnh khắc này.", en: "The Lovers and Four of Wands: love and value alignment culminate in joyful celebration and unity — this is what you have been working toward; be fully present in this moment." },
  "6_26": { vi: "Người Yêu Nhau và Năm Gậy: những ham muốn mâu thuẫn tạo ra ma sát trong lựa chọn của trái tim — hãy nhìn thẳng vào xung đột; nó chỉ ra điều bạn thực sự coi trọng nhất.", en: "The Lovers and Five of Wands: conflicting desires create friction within the heart's choice — look directly at the conflict; it reveals what you actually value most." },
  "6_27": { vi: "Người Yêu Nhau và Sáu Gậy: sự kết hợp giá trị được ăn mừng và ghi nhận công khai — hãy để thế giới chứng kiến điều bạn đã chọn và tại sao bạn chọn nó.", en: "The Lovers and Six of Wands: a union of values is publicly celebrated and recognised — let the world witness what you have chosen and why you chose it." },
  "6_28": { vi: "Người Yêu Nhau và Bảy Gậy: mối quan hệ hoặc niềm tin quý giá phải được bảo vệ trước sự phản đối — hãy đứng ra vì điều bạn yêu; không phải mọi thách thức đều có thể chiến thắng bằng sự im lặng.", en: "The Lovers and Seven of Wands: a valued relationship or belief must be defended against opposition — stand up for what you love; not every challenge can be won by staying silent." },
  "6_29": { vi: "Người Yêu Nhau và Tám Gậy: tình yêu hoặc hướng đi đã được chọn đang di chuyển với đà nhanh và đam mê — hãy theo kịp tốc độ này; đừng để nỗi sợ hãi làm bạn chậm lại.", en: "The Lovers and Eight of Wands: love or chosen direction moves with swift, passionate momentum — keep pace; do not let fear slow you down at this critical moment." },
  "6_30": { vi: "Người Yêu Nhau và Chín Gậy: mối quan hệ đã được thử thách lâu dài đòi hỏi sự kiên cường và cam kết được đổi mới — hãy quyết định có chủ đích xem bạn đang bảo vệ điều gì và tại sao.", en: "The Lovers and Nine of Wands: a long-tested bond requires resilience and renewed commitment — deliberately decide what you are protecting and why it still matters." },
  "6_31": { vi: "Người Yêu Nhau và Mười Gậy: quá nhiều nghĩa vụ đe dọa dập tắt tia lửa ban đầu của tình yêu — hãy đặt xuống những gánh nặng không thuộc về mối quan hệ trước khi chúng đè bẹp nó.", en: "The Lovers and Ten of Wands: too many obligations threaten to extinguish the original spark of love — set down the burdens that do not belong to the relationship before they crush it." },

  // Chariot (7) × Wands
  "7_22": { vi: "Chiến Xa và Át Gậy: ý chí kiên định hóa thành ngọn lửa sáng tạo thô — hãy khai thác năng lượng này với cả hai tay; hiếm khi bạn có được nhiều sức mạnh như vậy cùng một lúc.", en: "The Chariot and Ace of Wands: iron will harnesses a burst of raw creative fire — seize this energy with both hands; rarely do you hold this much power at once." },
  "7_23": { vi: "Chiến Xa và Hai Gậy: đà chiến thắng đẩy về phía trước vào lãnh thổ táo bạo mới — hãy lên kế hoạch cho cuộc chinh phục tiếp theo trong khi năng lượng đang ở đỉnh cao.", en: "The Chariot and Two of Wands: victorious momentum pushes forward into bold new territory — plan your next conquest while the energy is at its peak." },
  "7_24": { vi: "Chiến Xa và Ba Gậy: sự tiến bộ quyết tâm mở rộng tầm nhìn tới chân trời xa nhất — bạn đã đủ xa để thấy những gì người khác không thể; hãy lên kế hoạch cho bước tiếp theo.", en: "The Chariot and Three of Wands: determined progress expands its vision to the furthest horizon — you have gone far enough to see what others cannot; plan your next move from here." },
  "7_25": { vi: "Chiến Xa và Bốn Gậy: nỗ lực có chủ đích đến tại khoảnh khắc của sự ăn mừng xứng đáng — hãy thực sự dừng lại để tôn vinh điều đã đạt được trước khi lao vào trận chiến tiếp theo.", en: "The Chariot and Four of Wands: driven effort arrives at a moment of earned celebration — truly stop to honour what has been achieved before charging into the next battle." },
  "7_26": { vi: "Chiến Xa và Năm Gậy: ý chí mạnh mẽ cắt xuyên qua ma sát và những sao nhãng cạnh tranh — hãy giữ mục tiêu trong tầm nhìn và đừng để tiếng ồn của cuộc chiến nhỏ làm bạn chệch hướng.", en: "The Chariot and Five of Wands: strong will cuts through friction and competing distractions — keep the goal in view and do not let the noise of small battles knock you off course." },
  "7_27": { vi: "Chiến Xa và Sáu Gậy: đà thúc đẩy không thể ngăn cản được gặp với sự công nhận nó xứng đáng — hãy tiếp nhận vinh quang này; nó là bằng chứng về kỷ luật bạn đã áp đặt lên bản thân.", en: "The Chariot and Six of Wands: unstoppable drive is met with the recognition it deserves — receive this glory; it is evidence of the discipline you have imposed on yourself." },
  "7_28": { vi: "Chiến Xa và Bảy Gậy: ý chí không mệt mỏi giữ vị trí cao trước mọi kẻ thách thức — bạn đã đến đây bằng sức mạnh và bạn sẽ đứng ở đây bằng ý chí.", en: "The Chariot and Seven of Wands: relentless will holds the high ground against every challenger — you arrived here by force and you will remain here by will." },
  "7_29": { vi: "Chiến Xa và Tám Gậy: đà thúc đẩy không thể dừng được tăng tốc đến vận tốc tối đa — hãy tin tưởng rằng hướng đi này là đúng và để tốc độ làm việc của nó.", en: "The Chariot and Eight of Wands: unstoppable momentum accelerates to maximum velocity — trust that the direction is right and let the speed do its work." },
  "7_30": { vi: "Chiến Xa và Chín Gậy: người chiến binh kiệt sức tìm thấy sức mạnh để tiếp tục tiến về phía trước — vinh quang không đến với người dừng lại một bước trước vạch đích.", en: "The Chariot and Nine of Wands: the exhausted warrior finds the strength to keep moving forward — glory does not come to those who stop one step before the finish line." },
  "7_31": { vi: "Chiến Xa và Mười Gậy: tham vọng thúc đẩy có nguy cơ nghiền nát chính nó dưới gánh nặng không chịu đựng được — hãy học cách chiến thắng bằng cách ủy quyền, không phải bằng cách tự gánh mọi thứ.", en: "The Chariot and Ten of Wands: driving ambition risks crushing itself under unbearable weight — learn to win through delegation, not by shouldering everything alone." },

  // Task 6b: Majors 8–15 × Wands 22–31

  // Strength (8) × Wands
  "8_22": { vi: "Sức Mạnh và Át Gậy: lòng can đảm nhẹ nhàng châm ngòi tia lửa sáng tạo mạnh mẽ — hãy đến với khởi đầu này không phải bằng sức lực thô mà bằng trái tim dũng cảm và kiên nhẫn.", en: "Strength and Ace of Wands: gentle courage ignites a powerful creative spark — come to this beginning not with brute force but with a brave and patient heart." },
  "8_23": { vi: "Sức Mạnh và Hai Gậy: lòng can đảm kiên nhẫn lên kế hoạch mở rộng táo bạo — hãy để sự điềm tĩnh bên trong là la bàn dẫn bạn vào những lãnh thổ chưa được khám phá.", en: "Strength and Two of Wands: patient courage plans bold expansion — let inner stillness be the compass guiding you into unexplored territory." },
  "8_24": { vi: "Sức Mạnh và Ba Gậy: sức mạnh nội tâm nhìn về phía chân trời xa với sự tự tin lặng lẽ — bạn không cần gào thét về tầm nhìn của mình; hãy để sự hiện diện của bạn nói lên điều đó.", en: "Strength and Three of Wands: inner strength looks toward distant horizons with quiet confidence — you do not need to shout about your vision; let your presence speak it." },
  "8_25": { vi: "Sức Mạnh và Bốn Gậy: sự thành thạo nhẹ nhàng tạo ra điều kiện cho sự ăn mừng ổn định và vui mừng — những nền tảng được xây dựng bằng lòng kiên nhẫn tạo ra không gian cho người khác phát triển.", en: "Strength and Four of Wands: gentle mastery creates the conditions for stable, joyful celebration — foundations built with patience make space for others to flourish." },
  "8_26": { vi: "Sức Mạnh và Năm Gậy: sức mạnh từ bi điều hướng sự cạnh tranh mà không cần hung hăng — hãy tham gia vào cuộc tranh đấu bằng sự nhẹ nhàng; bạn sẽ đứng vững hơn bất kỳ ai trong phòng.", en: "Strength and Five of Wands: compassionate strength navigates competition without aggression — enter the fray with gentleness; you will outlast everyone else in the room." },
  "8_27": { vi: "Sức Mạnh và Sáu Gậy: lòng can đảm lặng lẽ được ghi nhận và tôn vinh công khai — sự điềm tĩnh bạn đã thực hành cuối cùng được thế giới thấy và hiểu.", en: "Strength and Six of Wands: quiet courage is publicly recognised and honoured — the composure you have practised is finally seen and understood by the world." },
  "8_28": { vi: "Sức Mạnh và Bảy Gậy: quyết tâm nhẹ nhàng nhưng kiên định giữ vị thế mà không cần thù địch — hãy đứng vững không phải bằng cách chống lại họ mà bằng cách không lay chuyển từ trung tâm của bạn.", en: "Strength and Seven of Wands: gentle but firm resolve holds ground without hostility — stand firm not by pushing against them but by remaining unmoved at your own centre." },
  "8_29": { vi: "Sức Mạnh và Tám Gậy: sức mạnh bên trong kiên nhẫn di chuyển với hành động nhanh và quyết đoán khi khoảnh khắc đến — sự dịu dàng và tốc độ không mâu thuẫn; đây là bằng chứng.", en: "Strength and Eight of Wands: patient inner power moves with swift decisive action when the moment arrives — gentleness and speed are not opposites; here is the proof." },
  "8_30": { vi: "Sức Mạnh và Chín Gậy: lòng can đảm bền bỉ duy trì người bảo vệ mệt mỏi đến tận cùng — hãy nhớ rằng kiên cường không có nghĩa là không cảm thấy đau; nó có nghĩa là tiếp tục dù vậy.", en: "Strength and Nine of Wands: enduring courage sustains the weary defender to the very end — remember that resilience does not mean feeling no pain; it means continuing anyway." },
  "8_31": { vi: "Sức Mạnh và Mười Gậy: sức mạnh thực sự biết gánh nặng nào để buông bỏ — lòng dũng cảm để đặt xuống đôi khi đòi hỏi nhiều hơn là lòng dũng cảm để tiếp tục mang.", en: "Strength and Ten of Wands: true strength knows which burdens to release — the courage to put something down sometimes demands more than the courage to keep carrying it." },

  // Hermit (9) × Wands
  "9_22": { vi: "Ẩn Sĩ và Át Gậy: tuệ giác từ sự cô độc châm ngòi một khởi đầu sáng tạo mới — những gì bạn đã tìm thấy trong sự im lặng bây giờ sẵn sàng được đưa ra ánh sáng.", en: "The Hermit and Ace of Wands: insight born from solitude sparks a new creative beginning — what you discovered in silence is now ready to be brought into the light." },
  "9_23": { vi: "Ẩn Sĩ và Hai Gậy: trí tuệ nội tâm một mình hoạch định hướng đi của hành trình mới — hãy tin vào sự hướng dẫn của riêng bạn trước khi hỏi bất kỳ ai khác.", en: "The Hermit and Two of Wands: inner wisdom alone maps the direction of the new journey — trust your own guidance before asking anyone else for theirs." },
  "9_24": { vi: "Ẩn Sĩ và Ba Gậy: lữ khách cô đơn đứng ở bờ cao nhìn ra những chân trời mà người khác chưa đạt đến — sự cô lập đã đưa bạn xa hơn bạn biết.", en: "The Hermit and Three of Wands: the lone traveller stands at heights looking out at horizons others have not yet reached — your solitude has carried you further than you know." },
  "9_25": { vi: "Ẩn Sĩ và Bốn Gậy: hành trình cô đơn trở về cộng đồng để ăn mừng — ánh sáng bạn đã tìm thấy trong sự im lặng bây giờ chiếu sáng con đường cho những người khác.", en: "The Hermit and Four of Wands: the solitary journey returns to community for celebration — the light you found in silence now illuminates the way for others." },
  "9_26": { vi: "Ẩn Sĩ và Năm Gậy: trí tuệ lặng lẽ từ chối tham gia vào sự xung đột vô nghĩa — hãy bước ra khỏi cuộc tranh giành; sự im lặng của bạn sẽ nói to hơn bất kỳ lời tranh luận nào.", en: "The Hermit and Five of Wands: quiet wisdom refuses to participate in pointless conflict — step out of the scramble; your silence will speak louder than any argument." },
  "9_27": { vi: "Ẩn Sĩ và Sáu Gậy: nỗ lực lâu dài được che giấu cuối cùng nhận được sự công nhận xứng đáng — bạn không cần phải tìm kiếm sự chú ý; công việc của bạn đã tự tìm thấy nó.", en: "The Hermit and Six of Wands: long-hidden effort finally receives its deserved recognition — you did not need to seek the spotlight; your work found it on its own." },
  "9_28": { vi: "Ẩn Sĩ và Bảy Gậy: một mình trên đỉnh cao, ẩn sĩ giữ vững niềm tin trước những kẻ phê bình — sự cô đơn đã làm cho niềm tin của bạn không thể bị lung lay.", en: "The Hermit and Seven of Wands: alone on the heights, the hermit holds conviction firm against critics — solitude has made your belief unshakeable." },
  "9_29": { vi: "Ẩn Sĩ và Tám Gậy: sự tĩnh lặng bị phá vỡ bởi sự tăng tốc đột ngột của các sự kiện — hãy tin tưởng những gì bạn đã học được trong sự im lặng khi nhịp độ của thế giới tăng vọt.", en: "The Hermit and Eight of Wands: stillness is broken by a sudden acceleration of events — trust what you learned in silence when the pace of the world suddenly surges." },
  "9_30": { vi: "Ẩn Sĩ và Chín Gậy: người gác cổng đơn độc đã đứng canh quá lâu — hãy nhận ra rằng sự cô lập đôi khi là một vết thương cần được chữa lành, không phải một sức mạnh cần được duy trì.", en: "The Hermit and Nine of Wands: the solitary guardian has stood watch for too long — recognise that isolation is sometimes a wound to heal, not a strength to maintain." },
  "9_31": { vi: "Ẩn Sĩ và Mười Gậy: sự cô lập khuếch đại trọng lượng của những gánh nặng được mang một mình — ánh sáng bạn mang không cần phải được mang trong bóng tối; hãy chia sẻ nó.", en: "The Hermit and Ten of Wands: isolation amplifies the weight of burdens carried alone — the light you bear does not need to be carried in darkness; share it." },

  // Wheel of Fortune (10) × Wands
  "10_22": { vi: "Bánh Xe Số Phận và Át Gậy: một điểm xoay của số phận châm ngòi một làn sóng khả năng sáng tạo mới — khoảnh khắc này không phải ngẫu nhiên; hãy nắm lấy tia lửa trước khi bánh xe quay tiếp.", en: "The Wheel of Fortune and Ace of Wands: a turning point of fate ignites a wave of new creative possibility — this moment is not random; seize the spark before the wheel turns again." },
  "10_23": { vi: "Bánh Xe Số Phận và Hai Gậy: số phận dịch chuyển những kế hoạch chiến lược bạn đang thực hiện — hãy giữ tầm nhìn nhưng nới lỏng nắm tay của bạn về cách bạn sẽ đến đó.", en: "The Wheel of Fortune and Two of Wands: fate shifts the strategic plans you were making — keep the vision but loosen your grip on exactly how you will get there." },
  "10_24": { vi: "Bánh Xe Số Phận và Ba Gậy: bánh xe quay và đưa những con tàu từ xa về cảng — những gì bạn đã gửi đi từ lâu bây giờ đang trở về.", en: "The Wheel of Fortune and Three of Wands: the wheel turns, bringing distant ships back to port — what you set out long ago is now on its way back to you." },
  "10_25": { vi: "Bánh Xe Số Phận và Bốn Gậy: vận may quay về phía sự ăn mừng và sự đến nơi — hãy chuẩn bị ngưỡng cửa; sự xuất hiện mà bạn đang chờ đang đến gần.", en: "The Wheel of Fortune and Four of Wands: fortune turns toward celebration and arrival — prepare the threshold; the homecoming you have been waiting for is approaching." },
  "10_26": { vi: "Bánh Xe Số Phận và Năm Gậy: một bước ngoặt của số phận làm tăng sự cạnh tranh và ma sát — đừng xem đây là xui xẻo; hãy xem đây là bài kiểm tra để tinh lọc điều gì có giá trị thực sự.", en: "The Wheel of Fortune and Five of Wands: a twist of fate increases the competition and friction — do not read this as bad luck; read it as the test that refines what is genuinely valuable." },
  "10_27": { vi: "Bánh Xe Số Phận và Sáu Gậy: số phận trao sự công nhận xứng đáng đúng lúc — điều này không phải may mắn; đây là vũ trụ xác nhận những gì bạn đã xây dựng.", en: "The Wheel of Fortune and Six of Wands: fortune delivers well-deserved recognition at the right moment — this is not luck; it is the universe confirming what you have built." },
  "10_28": { vi: "Bánh Xe Số Phận và Bảy Gậy: một bước ngoặt bất ngờ nâng cao cổ phần của những gì bạn đang bảo vệ — hãy giữ vị trí của bạn; những làn sóng xung quanh bạn không định nghĩa lập trường của bạn.", en: "The Wheel of Fortune and Seven of Wands: an unexpected turn raises the stakes of what you are defending — hold your position; the waves around you do not define your stance." },
  "10_29": { vi: "Bánh Xe Số Phận và Tám Gậy: số phận tăng tốc mọi thứ — thời điểm là bây giờ và nó sẽ không chờ đợi — hãy tin vào hướng đi và di chuyển.", en: "The Wheel of Fortune and Eight of Wands: fate accelerates everything — the timing is now and it will not wait — trust the direction and move." },
  "10_30": { vi: "Bánh Xe Số Phận và Chín Gậy: chu kỳ gần hoàn thành; đừng bỏ vị trí của bạn bây giờ — bạn đã ở đây quá lâu để rời đi trước khi bánh xe hoàn thành vòng quay của nó.", en: "The Wheel of Fortune and Nine of Wands: the cycle is nearly complete; do not abandon your post now — you have been here too long to leave before the wheel finishes its turn." },
  "10_31": { vi: "Bánh Xe Số Phận và Mười Gậy: một sự thay đổi của vận may có thể nâng bổng gánh nặng hoặc thêm vào nó — hãy chuẩn bị cho cả hai và tin rằng chu kỳ sẽ mang theo những gì thuộc về nó.", en: "The Wheel of Fortune and Ten of Wands: a change in fortune either lifts the burden or adds to it — prepare for both and trust that the cycle will carry away what belongs to it." },

  // Justice (11) × Wands
  "11_22": { vi: "Công Lý và Át Gậy: một khởi đầu công bằng được kiếm được, không được cho không — hãy bước vào tia lửa này với sự rõ ràng về những gì bạn đã thực sự làm để xứng đáng với nó.", en: "Justice and Ace of Wands: a fair new beginning is earned, not given — step into this spark with clarity about what you have genuinely done to deserve it." },
  "11_23": { vi: "Công Lý và Hai Gậy: sự cân bằng cẩn thận các lựa chọn trước khi có hành động chiến lược táo bạo — hãy nhìn rõ cả hai bên trước khi đặt cược lên bàn cân.", en: "Justice and Two of Wands: careful weighing of options before bold strategic action — see both sides clearly before placing your bet on the scales." },
  "11_24": { vi: "Công Lý và Ba Gậy: đánh giá vô tư những gì thực sự nằm ở phía chân trời — hãy nhìn không phải bằng mắt của hy vọng hay nỗi sợ hãi mà bằng mắt của sự thật.", en: "Justice and Three of Wands: impartial assessment of what truly lies on the horizon — look not with the eyes of hope or fear but with the eyes of honest truth." },
  "11_25": { vi: "Công Lý và Bốn Gậy: một kết quả công bằng tạo ra lý do chính đáng cho sự ăn mừng thực sự — hãy ăn mừng điều này không phải vì may mắn mà vì nó đã được đạt đến một cách công bằng.", en: "Justice and Four of Wands: a fair outcome creates reason for genuine celebration — celebrate this not as luck but because it was arrived at honestly." },
  "11_26": { vi: "Công Lý và Năm Gậy: sự rõ ràng cắt xuyên qua tiếng ồn của những tuyên bố cạnh tranh — hãy đặt câu hỏi đơn giản: điều nào trong những điều này thực sự đúng? Sau đó đứng về phía đó.", en: "Justice and Five of Wands: clarity cuts through the noise of competing claims — ask the simple question: which of these things is actually true? Then stand on that side." },
  "11_27": { vi: "Công Lý và Sáu Gậy: sự công nhận đến với những người đã thực sự kiếm được nó — không có sự vinh quang nào sâu sắc hơn loại này; nó dựa trên nền tảng không thể bị tước đoạt.", en: "Justice and Six of Wands: recognition comes to those who have genuinely earned it — no glory runs deeper than this kind; it rests on a foundation that cannot be taken away." },
  "11_28": { vi: "Công Lý và Bảy Gậy: đứng vững đòi hỏi một lý do chính đáng, không chỉ là sự bướng bỉnh — hãy kiểm tra nguyên nhân trước khi bạn bảo vệ nó; chỉ giữ những gì đáng giữ.", en: "Justice and Seven of Wands: standing firm requires a just cause, not merely stubbornness — examine the cause before you defend it; hold only what is worth holding." },
  "11_29": { vi: "Công Lý và Tám Gậy: hành động nhanh chóng phải được hướng dẫn bởi sự công bằng và hậu quả — tốc độ mà không có sự rõ ràng là sự bốc đồng; hãy biết lý do tại sao bạn di chuyển.", en: "Justice and Eight of Wands: swift action must be guided by fairness and its consequences — speed without clarity is impulsiveness; know exactly why you are moving." },
  "11_30": { vi: "Công Lý và Chín Gậy: người bảo vệ mệt mỏi có lý do chính đáng; hãy tiếp tục giữ phòng tuyến — bạn không đứng vì cái tôi; bạn đứng vì điều đúng đắn, và điều đó có giá trị.", en: "Justice and Nine of Wands: the weary defender's cause is just; keep holding the line — you are not standing from ego; you are standing from what is right, and that matters." },
  "11_31": { vi: "Công Lý và Mười Gậy: sự tính toán thành thật về những trách nhiệm nào thực sự là của bạn — hãy đặt xuống những gì đã được giao cho bạn một cách bất công; bạn không có nghĩa vụ mang tất cả.", en: "Justice and Ten of Wands: honest accounting of which responsibilities are truly yours — put down what was unfairly assigned to you; you are not obligated to carry everything." },

  // Hanged Man (12) × Wands
  "12_22": { vi: "Người Treo Ngược và Át Gậy: một khoảng dừng trước tia lửa mới cho phép sự rõ ràng sâu sắc hơn — đừng vội vàng với sự khởi đầu này; sự chậm lại sẽ làm cho nó mạnh mẽ hơn nhiều.", en: "The Hanged Man and Ace of Wands: a pause before the new spark allows deeper clarity to form — do not rush this beginning; the delay will make it far stronger." },
  "12_23": { vi: "Người Treo Ngược và Hai Gậy: việc buông bỏ kế hoạch cũ mở ra một góc nhìn chiến lược khôn ngoan hơn — sự quy phục này không phải thất bại; đây là sự chuẩn bị cho con đường tốt hơn.", en: "The Hanged Man and Two of Wands: surrendering the old plan opens a wiser strategic perspective — this surrender is not failure; it is preparation for a better path." },
  "12_24": { vi: "Người Treo Ngược và Ba Gậy: hãy buông bỏ nhu cầu nhìn thấy đích đến trước; chân trời sẽ tự tiết lộ — những cơ hội tốt nhất đến khi bạn ngừng cố gắng kiểm soát hướng đi.", en: "The Hanged Man and Three of Wands: release the need to see the destination first; the horizon will reveal itself — the best opportunities arrive when you stop trying to control the direction." },
  "12_25": { vi: "Người Treo Ngược và Bốn Gậy: lễ ăn mừng phải chờ; sự dừng lại là một phần của sự chuẩn bị — điều bạn đang chờ đợi sẽ có ý nghĩa hơn khi bạn đến đó sau khi trải qua sự chuyển đổi này.", en: "The Hanged Man and Four of Wands: the celebration must wait; the pause is part of the preparation — what you are waiting for will mean more when you arrive having been transformed." },
  "12_26": { vi: "Người Treo Ngược và Năm Gậy: bước ra khỏi cuộc xung đột thay đổi toàn bộ động lực — đôi khi sự di chuyển quyền lực nhất là từ chối chơi trò chơi mọi người đang mong đợi.", en: "The Hanged Man and Five of Wands: stepping out of the conflict changes the entire dynamic — sometimes the most powerful move is refusing to play the game everyone expects." },
  "12_27": { vi: "Người Treo Ngược và Sáu Gậy: sự công nhận bị trì hoãn không phải là sự công nhận bị từ chối — hãy kiên nhẫn; điều gì xứng đáng được nhìn thấy sẽ được nhìn thấy vào đúng thời điểm.", en: "The Hanged Man and Six of Wands: recognition delayed is not recognition denied — be patient; what deserves to be seen will be seen at the right moment." },
  "12_28": { vi: "Người Treo Ngược và Bảy Gậy: buông bỏ sự phòng thủ đôi khi mạnh hơn là tiếp tục giữ — hãy hỏi liệu bạn đang bảo vệ điều gì đó có giá trị hay chỉ đang chống lại sự thay đổi.", en: "The Hanged Man and Seven of Wands: letting go of the defence can be more powerful than holding on — ask whether you are protecting something valuable or merely resisting change." },
  "12_29": { vi: "Người Treo Ngược và Tám Gậy: sự quy phục cho phép dòng chảy nhanh mang bạn đi thay vì chống lại bạn — hãy buông bỏ sự kiểm soát và bạn sẽ thấy dòng sông đang chảy về phía bạn muốn đến.", en: "The Hanged Man and Eight of Wands: surrender allows the swift current to carry you rather than fight you — release control and discover the river is already flowing toward where you want to go." },
  "12_30": { vi: "Người Treo Ngược và Chín Gậy: nghỉ ngơi không phải là rút lui; người chiến binh mệt mỏi phải dừng lại để phục hồi — đây không phải là sự từ bỏ; đây là trí tuệ của việc biết giới hạn của mình.", en: "The Hanged Man and Nine of Wands: rest is not retreat; the weary warrior must pause to recover — this is not abandonment; it is the wisdom of knowing your own limits." },
  "12_31": { vi: "Người Treo Ngược và Mười Gậy: treo lơ lửng trong sự yên lặng cho thấy gánh nặng nào được chọn và gánh nặng nào được áp đặt — góc nhìn mới tiết lộ sự tự do mà bạn chưa biết mình có.", en: "The Hanged Man and Ten of Wands: hanging suspended reveals which burdens were chosen and which were imposed — the new perspective reveals a freedom you did not know you had." },

  // Death (13) × Wands
  "13_22": { vi: "Thần Chết và Át Gậy: sự chuyển đổi dọn sạch mảnh đất cho một ngọn lửa sáng tạo hoàn toàn mới — điều kết thúc ở đây không phải là bạn; đó là những gì đã ngăn bạn bắt đầu.", en: "Death and Ace of Wands: transformation clears the ground for an entirely new creative fire — what is ending here is not you; it is what has been preventing you from starting." },
  "13_23": { vi: "Thần Chết và Hai Gậy: kế hoạch cũ phải kết thúc trước khi tầm nhìn mới có thể thực sự hình thành — hãy buông bỏ bản đồ bạn đang giữ; cái mới đòi hỏi bàn tay trống rỗng.", en: "Death and Two of Wands: the old plan must end before the new vision can truly take form — release the map you are holding; the new one requires empty hands." },
  "13_24": { vi: "Thần Chết và Ba Gậy: hãy buông bỏ những gì đã bị vượt qua để tiếp cận bờ xa — bạn không thể tiến về phía trước trong khi đang ôm chặt những gì đã thuộc về quá khứ.", en: "Death and Three of Wands: release what has been outgrown to reach the distant shore — you cannot move forward while holding tightly to what belongs to the past." },
  "13_25": { vi: "Thần Chết và Bốn Gậy: điều gì đó phải kết thúc trước khi sự ăn mừng của điều mới có thể bắt đầu — hãy đặt nó xuống một cách trân trọng và bước qua ngưỡng cửa.", en: "Death and Four of Wands: something must end before the celebration of the new can truly begin — lay it down with reverence and step across the threshold." },
  "13_26": { vi: "Thần Chết và Năm Gậy: cuộc xung đột cũ đang lụi tàn; hãy bước ra trước khi bạn bị chôn vùi cùng với nó — năng lượng của bạn không thuộc về những gì đã sắp qua đi.", en: "Death and Five of Wands: the old conflict is dying; step away before you are buried with it — your energy does not belong to what is already fading." },
  "13_27": { vi: "Thần Chết và Sáu Gậy: chiến thắng bản thân cũ là sự công nhận đáng được ăn mừng nhất — hãy ăn mừng không phải những gì bạn đã đạt được mà là người bạn đã trở thành trong quá trình đó.", en: "Death and Six of Wands: victory over the old self is the recognition most worth celebrating — celebrate not what you have achieved but who you have become in the process." },
  "13_28": { vi: "Thần Chết và Bảy Gậy: hãy ngừng bảo vệ những gì đã đang chết; hãy để nó ra đi với sự uyển chuyển — giữ vị trí là khôn ngoan khi giá trị còn tồn tại; khi không còn, nó chỉ là sự bướng bỉnh.", en: "Death and Seven of Wands: stop defending what is already dying; let it go with grace — holding position is wisdom when value remains; when it does not, it is merely stubbornness." },
  "13_29": { vi: "Thần Chết và Tám Gậy: sự chuyển đổi di chuyển với sự nhanh chóng đột ngột; sự thay đổi đã bắt đầu — đừng cố gắng làm chậm lại những gì đang tăng tốc; hãy để sự kết thúc hoàn thành công việc của nó.", en: "Death and Eight of Wands: transformation moves with sudden swiftness; the shift has already begun — do not try to slow what is accelerating; let the ending complete its work." },
  "13_30": { vi: "Thần Chết và Chín Gậy: đây là bài kiểm tra cuối cùng trước khi sự chuyển đổi hoàn thành — bạn đã đứng vững qua tất cả những điều này; chỉ còn một bước nữa là qua được ngưỡng cửa.", en: "Death and Nine of Wands: this is the final test before the transformation completes — you have stood through all of this; only one more step to cross the threshold." },
  "13_31": { vi: "Thần Chết và Mười Gậy: gánh nặng bạn đang mang sẽ kết thúc; sự giải phóng là sự chuyển đổi — hãy để những gì đang kết thúc kết thúc; sự nhẹ nhàng phía bên kia là có thật.", en: "Death and Ten of Wands: the weight you carry will end; release is the transformation — let what is ending end; the lightness on the other side is real." },

  // Temperance (14) × Wands
  "14_22": { vi: "Điều Độ và Át Gậy: thuật giả kim kiên nhẫn chuyển hóa lửa sáng tạo thành hình thức bền vững — hãy để nhiệt huyết này chảy qua bạn từ từ; điều tốt nhất không được đốt cháy hết cùng một lúc.", en: "Temperance and Ace of Wands: patient alchemy channels creative fire into sustainable form — let this enthusiasm flow through you slowly; the best things are not burned all at once." },
  "14_23": { vi: "Điều Độ và Hai Gậy: sự kiên nhẫn được cân nhắc định hình những kế hoạch táo bạo với tỷ lệ khôn ngoan — hãy lên kế hoạch lớn, nhưng hãy để từng bước có không gian để thở.", en: "Temperance and Two of Wands: measured patience shapes bold plans with wise proportions — plan large, but let each step have room to breathe." },
  "14_24": { vi: "Điều Độ và Ba Gậy: sự tích hợp ổn định cho phép những chân trời xa được tiếp cận mà không bị kiệt sức — hãy đi đến đó theo từng đợt nhịp nhàng, không phải trong một chuyến lao nhanh tuyệt vọng.", en: "Temperance and Three of Wands: steady integration allows far horizons to be reached without burning out — get there in steady rhythms, not in one desperate sprint." },
  "14_25": { vi: "Điều Độ và Bốn Gậy: sự cân bằng và kiên nhẫn tạo ra điều kiện cho sự ăn mừng lâu dài — những lễ hội tốt nhất được xây dựng trên những nền tảng không vội vàng xây dựng.", en: "Temperance and Four of Wands: balance and patience create the conditions for lasting celebration — the best homecomings are built on foundations that were not rushed." },
  "14_26": { vi: "Điều Độ và Năm Gậy: sự điềm tĩnh hòa tan ma sát mà không ép buộc giải pháp — hãy để những quan điểm đối lập tự tìm thấy nhau qua sự đối thoại kiên nhẫn, không phải qua chiến thắng.", en: "Temperance and Five of Wands: calm integration dissolves the friction without forcing resolution — let opposing views find each other through patient dialogue, not through conquest." },
  "14_27": { vi: "Điều Độ và Sáu Gậy: sự công nhận đến với những ai đã hành động với sự uyển chuyển có cân nhắc — chiến thắng của bạn không có vết nứt vì nó được xây dựng dưới nhiệt độ đúng đắn.", en: "Temperance and Six of Wands: recognition comes to those who acted with measured grace — your victory has no cracks in it because it was built at the right temperature." },
  "14_28": { vi: "Điều Độ và Bảy Gậy: hãy giữ vững vị trí với sự điềm tĩnh ổn định, không phải sức mạnh phản ứng — những ai leo lên để thách thức bạn sẽ mệt mỏi trước; hãy tiết kiệm năng lượng của bạn.", en: "Temperance and Seven of Wands: hold the ground with steady composure, not reactive force — those who climb to challenge you will tire first; conserve your energy." },
  "14_29": { vi: "Điều Độ và Tám Gậy: hãy kết hợp tốc độ với thời điểm đúng đắn; không phải mọi thứ nhanh đều đang đi đúng hướng — hãy để sự nhanh nhẹn của bạn được hướng dẫn bởi sự khôn ngoan, không chỉ bởi sự thúc đẩy.", en: "Temperance and Eight of Wands: blend speed with timing; not every fast thing moves in the right direction — let your swiftness be guided by wisdom, not merely by urgency." },
  "14_30": { vi: "Điều Độ và Chín Gậy: người bảo vệ kiên nhẫn biết cách nghỉ ngơi mà không rời bỏ vị trí — hãy tìm nhịp điệu giữa sự cảnh giác và sự phục hồi; cả hai đều thiết yếu.", en: "Temperance and Nine of Wands: the patient guardian knows how to rest without abandoning the post — find the rhythm between vigilance and recovery; both are essential." },
  "14_31": { vi: "Điều Độ và Mười Gậy: dòng chảy và sự điều độ tiết lộ những gánh nặng nào cần mang và những gánh nặng nào cần buông — hãy phân phối những gì bạn mang với sự khôn ngoan; không phải mọi thứ đều có cùng trọng lượng.", en: "Temperance and Ten of Wands: flow and moderation reveal which loads to carry and which to release — distribute what you carry with wisdom; not everything weighs the same." },

  // Devil (15) × Wands
  "15_22": { vi: "Ác Quỷ và Át Gậy: một tia lửa sáng tạo nuôi dưỡng bằng nỗi ám ảnh hơn là cảm hứng — hãy kiểm tra điều đang thúc đẩy sự khởi đầu này: đây là tình yêu hay là sự phụ thuộc?", en: "The Devil and Ace of Wands: a creative spark fed by obsession rather than inspiration — examine what is driving this beginning: is this love, or is this compulsion?" },
  "15_23": { vi: "Ác Quỷ và Hai Gậy: tham vọng táo bạo bị bóng tối của mong muốn kiểm soát bằng mọi giá — hãy nhìn xem bạn đang lên kế hoạch mở rộng hay lên kế hoạch chiếm đoạt.", en: "The Devil and Two of Wands: bold ambition shadowed by the desire to control at any cost — look carefully at whether you are planning expansion or planning domination." },
  "15_24": { vi: "Ác Quỷ và Ba Gậy: nhìn về phía chân trời từ những xiềng xích mà bạn đã tự đặt lên mình — tầm nhìn của bạn về những gì có thể bị làm biến dạng bởi những giới hạn mà bạn đã chấp nhận như sự thật.", en: "The Devil and Three of Wands: looking toward the horizon from chains you have put on yourself — your vision of what is possible is distorted by limits you have accepted as fact." },
  "15_25": { vi: "Ác Quỷ và Bốn Gậy: một cuộc ăn mừng được xây dựng trên sự phụ thuộc hơn là niềm vui thực sự — hãy nhìn xem có ai ở đây đang tự do hay mọi người đều đang bị ràng buộc bởi một cái gì đó.", en: "The Devil and Four of Wands: a celebration built on dependency rather than genuine joy — look carefully at whether anyone here is truly free or whether everyone is bound by something." },
  "15_26": { vi: "Ác Quỷ và Năm Gậy: xung đột nuôi dưỡng bóng tối thay vì giải quyết bất cứ điều gì — hãy nhận ra khi bạn đang chiến đấu để duy trì một vòng lặp chứ không phải để giải quyết một vấn đề.", en: "The Devil and Five of Wands: conflict that feeds the shadow rather than resolving anything — recognise when you are fighting to maintain a loop rather than to solve a problem." },
  "15_27": { vi: "Ác Quỷ và Sáu Gậy: sự công nhận đến kèm theo những sợi dây ẩn — hãy đọc kỹ những gì được yêu cầu đổi lại trước khi bạn chấp nhận vinh quang này.", en: "The Devil and Six of Wands: recognition that comes with hidden strings attached — read carefully what is being asked in return before you accept this glory." },
  "15_28": { vi: "Ác Quỷ và Bảy Gậy: bảo vệ một vị trí được thúc đẩy bởi nỗi sợ hãi hơn là niềm tin thực sự — hãy hỏi: bạn đang đứng vì điều này có giá trị hay vì bạn sợ mất nó?", en: "The Devil and Seven of Wands: defending a position driven by fear rather than genuine conviction — ask honestly: are you standing because this has value, or because you are afraid to lose it?" },
  "15_29": { vi: "Ác Quỷ và Tám Gậy: sự ép buộc tăng tốc thành đà nhanh ám ảnh — hãy nhận ra rằng không phải mọi tốc độ đều là sức sống; một số chỉ là sự hoảng loạn với nhiều chuyển động hơn.", en: "The Devil and Eight of Wands: compulsion accelerates into obsessive momentum — recognise that not every speed is vitality; some is just panic with more movement." },
  "15_30": { vi: "Ác Quỷ và Chín Gậy: đứng canh từ nỗi sợ hãi, không phải từ sức mạnh — hãy nhìn xem ai hoặc điều gì đã làm cho bạn tin rằng tường này là cần thiết và bắt đầu đặt câu hỏi về điều đó.", en: "The Devil and Nine of Wands: standing guard from fear, not from strength — look at who or what made you believe this wall was necessary and begin questioning that." },
  "15_31": { vi: "Ác Quỷ và Mười Gậy: những xiềng xích của nghĩa vụ tự áp đặt cảm thấy như không thể phá vỡ — nhưng bạn đã đóng những chiếc khóa đó; điều đó có nghĩa là bạn cũng có chìa khóa.", en: "The Devil and Ten of Wands: chains of self-imposed obligation that feel impossible to break — but you locked those locks; that means you also hold the key." },

  // Task 6c: Majors 16–21 × Wands 22–31

  // Tower (16) × Wands
  "16_22": { vi: "Tháp và Át Gậy: sự sụp đổ đột ngột dọn sạch mảnh đất cho một tia lửa sáng tạo hoàn toàn mới — những gì vừa bị phá hủy không phải là bạn; đó là những gì đang ngăn cản bạn bắt đầu.", en: "The Tower and Ace of Wands: sudden collapse clears the ground for an entirely new creative spark — what just fell was not you; it was what was preventing you from beginning." },
  "16_23": { vi: "Tháp và Hai Gậy: kế hoạch cũ vừa bị phá vỡ; bây giờ hãy nhìn về phía trước với đôi mắt mới — sự phá hủy này không phải là sự kết thúc của tầm nhìn, mà là sự giải phóng khỏi tầm nhìn sai.", en: "The Tower and Two of Wands: the old plan just collapsed; now look forward with new eyes — this destruction is not the end of vision, it is liberation from the wrong vision." },
  "16_24": { vi: "Tháp và Ba Gậy: sau sự đổ vỡ, bạn có thể nhìn thấy chân trời thực sự lần đầu tiên — những gì vừa sụp đổ đã che khuất những gì luôn đang chờ bạn ở phía xa.", en: "The Tower and Three of Wands: after the collapse, you can see the true horizon for the first time — what just fell had been blocking what was always waiting for you in the distance." },
  "16_25": { vi: "Tháp và Bốn Gậy: sự đổ vỡ đột ngột tiết lộ nền tảng nào thực sự vững chắc và nền tảng nào chỉ là ảo ảnh — hãy xây dựng lại lễ hội trên đất thực, không phải trên những lời hứa rỗng.", en: "The Tower and Four of Wands: sudden collapse reveals which foundations were truly solid and which were illusions — rebuild the celebration on real ground, not on hollow promises." },
  "16_26": { vi: "Tháp và Năm Gậy: vụ nổ vừa đẩy tất cả mọi người vào trận chiến — đừng gia nhập cuộc hỗn loạn; hãy đứng xa ra và chờ cho đến khi bụi lắng xuống trước khi hành động.", en: "The Tower and Five of Wands: the explosion just threw everyone into conflict — do not join the chaos; step back and wait until the dust settles before making any move." },
  "16_27": { vi: "Tháp và Sáu Gậy: sự công nhận thực sự đến sau khi sự giả tạo bị phá hủy — bạn không thể đứng trên bục của sự thật cho đến khi sân khấu của những lời nói dối sụp đổ.", en: "The Tower and Six of Wands: true recognition comes after the false structure is destroyed — you cannot stand on the podium of truth until the stage of lies has collapsed." },
  "16_28": { vi: "Tháp và Bảy Gậy: sau sự sụp đổ, bạn đang bảo vệ điều gì trên đống đổ nát này? — hãy chắc chắn rằng những gì bạn đang giữ lại là điều thực sự xứng đáng được giữ.", en: "The Tower and Seven of Wands: after the collapse, what exactly are you defending on these ruins? — make certain what you are holding onto is something genuinely worth keeping." },
  "16_29": { vi: "Tháp và Tám Gậy: sự sụp đổ đột ngột tăng tốc một chuỗi sự kiện không thể dừng lại — đừng chống cự lại tốc độ này; hãy để sự thay đổi mang bạn đến nơi nó cần đến.", en: "The Tower and Eight of Wands: sudden collapse accelerates an unstoppable chain of events — do not resist the speed; let the change carry you where it needs to go." },
  "16_30": { vi: "Tháp và Chín Gậy: người lính đứng gác trong đống đổ nát phải quyết định điều gì còn đáng bảo vệ — không phải mọi thứ tồn tại sau một cơn bão đều cần được giữ lại.", en: "The Tower and Nine of Wands: the soldier standing guard in the rubble must decide what is still worth protecting — not everything that survives a storm deserves to be kept." },
  "16_31": { vi: "Tháp và Mười Gậy: vụ sụp đổ đã buộc bạn đặt xuống những gánh nặng mà bạn chưa bao giờ tự mình đặt xuống — đây không phải là thảm họa; đây là sự giải phóng mà bạn đã trì hoãn quá lâu.", en: "The Tower and Ten of Wands: the collapse has forced you to put down the burdens you would never have set down yourself — this is not catastrophe; it is the liberation you kept postponing." },

  // Star (17) × Wands
  "17_22": { vi: "Ngôi Sao và Át Gậy: hy vọng và sự đổi mới châm ngòi một tia lửa sáng tạo tinh khiết — hãy bắt đầu điều này không phải từ áp lực mà từ sự tin tưởng rằng vũ trụ đang ủng hộ bạn.", en: "The Star and Ace of Wands: hope and renewal ignite a pure creative spark — begin this not from pressure but from the trust that the universe is behind you." },
  "17_23": { vi: "Ngôi Sao và Hai Gậy: ánh sáng của sự hy vọng soi sáng con đường về phía những kế hoạch mở rộng — hãy lên kế hoạch từ nơi của sự phong phú, không phải từ nơi của sự khan hiếm.", en: "The Star and Two of Wands: the light of hope illuminates the path toward expansive plans — plan from a place of abundance, not from a place of scarcity." },
  "17_24": { vi: "Ngôi Sao và Ba Gậy: ánh sáng ngôi sao hướng dẫn tầm nhìn hướng về phía những chân trời đầy hy vọng — hãy tin rằng những con tàu bạn đã gửi đi đang trên đường trở về.", en: "The Star and Three of Wands: starlight guides the vision toward hopeful horizons — trust that the ships you sent out are already on their way back." },
  "17_25": { vi: "Ngôi Sao và Bốn Gậy: sự hy vọng và sự đổi mới tạo ra nền tảng cho một cuộc ăn mừng thực sự chữa lành — hãy để niềm vui này thấm sâu; bạn xứng đáng được ở đây.", en: "The Star and Four of Wands: hope and renewal create the foundation for a celebration that truly heals — let this joy sink deep; you have earned the right to be here." },
  "17_26": { vi: "Ngôi Sao và Năm Gậy: hãy mang ánh sáng hy vọng vào giữa sự hỗn loạn của cạnh tranh — không phải mọi cuộc tranh đấu đều cần thêm lửa; đôi khi điều nó cần là một ngôi sao để định hướng theo.", en: "The Star and Five of Wands: bring the light of hope into the middle of competitive chaos — not every struggle needs more fire; sometimes what it needs is a star to orient by." },
  "17_27": { vi: "Ngôi Sao và Sáu Gậy: hy vọng được xác nhận trong sự công nhận công khai — điều bạn tin tưởng trong những đêm tối nhất bây giờ được thế giới nhìn thấy và tôn vinh.", en: "The Star and Six of Wands: hope is validated in public recognition — what you trusted on the darkest nights is now seen and honoured by the world." },
  "17_28": { vi: "Ngôi Sao và Bảy Gậy: hãy đứng vững từ hy vọng, không phải từ nỗi sợ hãi — những người leo lên để thách thức bạn không có ngôi sao dẫn đường; bạn thì có.", en: "The Star and Seven of Wands: hold your ground from hope, not from fear — those climbing to challenge you have no star to guide them; you do." },
  "17_29": { vi: "Ngôi Sao và Tám Gậy: hy vọng di chuyển nhanh chóng khi thời điểm đúng đắn đến — hãy hành động với sự tin tưởng rằng tốc độ này đang mang bạn về phía ánh sáng, không phải xa khỏi nó.", en: "The Star and Eight of Wands: hope moves swiftly when the right moment arrives — act with the trust that this speed is carrying you toward the light, not away from it." },
  "17_30": { vi: "Ngôi Sao và Chín Gậy: hy vọng duy trì người bảo vệ mệt mỏi khi mọi thứ khác đã cạn kiệt — hãy nhìn lên; ngôi sao vẫn ở đó ngay cả trong đêm tối nhất.", en: "The Star and Nine of Wands: hope sustains the weary guardian when everything else has run dry — look up; the star is still there even on the darkest night." },
  "17_31": { vi: "Ngôi Sao và Mười Gậy: hy vọng tiết lộ rằng gánh nặng bạn đang mang không phải là số phận của bạn — hãy đặt xuống điều không thuộc về tương lai bạn đang hướng tới.", en: "The Star and Ten of Wands: hope reveals that the burden you are carrying is not your destiny — put down what does not belong to the future you are walking toward." },

  // Moon (18) × Wands
  "18_22": { vi: "Mặt Trăng và Át Gậy: một tia lửa sáng tạo xuất hiện từ vùng đất mơ hồ và không chắc chắn — hãy tin vào điều bạn cảm thấy trước khi bạn có thể hiểu được nó.", en: "The Moon and Ace of Wands: a creative spark emerges from uncertain, shadowy territory — trust what you feel before you can understand it." },
  "18_23": { vi: "Mặt Trăng và Hai Gậy: những kế hoạch được lập ra trong ánh sáng mặt trăng có thể không trông giống như vậy khi mặt trời mọc — hãy chờ đến khi có ánh sáng ban ngày trước khi cam kết bất cứ điều gì.", en: "The Moon and Two of Wands: plans made by moonlight may not look the same when the sun rises — wait for daylight before committing to anything." },
  "18_24": { vi: "Mặt Trăng và Ba Gậy: những gì bạn nhìn thấy ở chân trời có thể là ảo ảnh hoặc sự thật; bóng tối khiến khó phân biệt — hãy tiếp tục nhưng bước đi cẩn thận cho đến khi bình minh xác nhận những gì bạn thấy.", en: "The Moon and Three of Wands: what you see on the horizon may be illusion or truth; the darkness makes it hard to tell — continue but step carefully until dawn confirms what you see." },
  "18_25": { vi: "Mặt Trăng và Bốn Gậy: hãy đảm bảo rằng niềm vui bạn đang ăn mừng là thực sự và không phải là một phiên bản mơ hồ của điều bạn thực sự muốn — đừng ăn mừng bóng của bữa tiệc.", en: "The Moon and Four of Wands: make sure the joy you are celebrating is real and not a hazy version of what you truly want — do not celebrate the shadow of the feast." },
  "18_26": { vi: "Mặt Trăng và Năm Gậy: trong bóng tối, sự cạnh tranh trở nên mơ hồ và méo mó — hãy cẩn thận với những gì bạn đang chiến đấu; nó có thể không phải là kẻ thù mà nó có vẻ.", en: "The Moon and Five of Wands: in the darkness, competition becomes murky and distorted — be careful what you are fighting; it may not be the enemy it appears to be." },
  "18_27": { vi: "Mặt Trăng và Sáu Gậy: sự công nhận đến nhưng trong ánh sáng mờ nhạt khiến khó biết đây là thực sự hay chỉ là bề ngoài — hãy chờ đến khi bạn có thể nhìn rõ trước khi tin vào nó.", en: "The Moon and Six of Wands: recognition arrives but in a dim light that makes it hard to tell if it is real or merely surface — wait until you can see clearly before trusting it." },
  "18_28": { vi: "Mặt Trăng và Bảy Gậy: bạn đang đứng vững trước những cái bóng hay trước những mối đe dọa thực sự? — hãy nhìn kỹ hơn trước khi bạn chiến đấu; nỗi sợ hãi trong bóng tối thường phóng đại kẻ thù.", en: "The Moon and Seven of Wands: are you holding ground against shadows or against real threats? — look more carefully before you fight; fear in the dark tends to enlarge the enemy." },
  "18_29": { vi: "Mặt Trăng và Tám Gậy: tốc độ trong bóng tối là nguy hiểm — hãy làm chậm lại đủ để xác nhận hướng đi trước khi năng lượng tám gậy mang bạn nơi bạn không định đến.", en: "The Moon and Eight of Wands: speed in the dark is dangerous — slow down enough to confirm the direction before Eight of Wands energy carries you somewhere you did not intend to go." },
  "18_30": { vi: "Mặt Trăng và Chín Gậy: người lính canh trong đêm tối không thể tin chắc vào những gì họ thấy — hãy kiên trì nhưng đừng tin mọi cái bóng là kẻ thù.", en: "The Moon and Nine of Wands: the night-watch soldier cannot be certain of what they see — remain vigilant but do not treat every shadow as an enemy." },
  "18_31": { vi: "Mặt Trăng và Mười Gậy: trong ánh sáng mờ nhạt, những gánh nặng có vẻ nặng hơn thực tế — hãy chờ đến buổi sáng trước khi quyết định điều gì cần mang và điều gì cần để lại.", en: "The Moon and Ten of Wands: in the dim light, burdens appear heavier than they actually are — wait until morning before deciding what to carry and what to leave behind." },

  // Sun (19) × Wands
  "19_22": { vi: "Mặt Trời và Át Gậy: ánh sáng rực rỡ nhất gặp tia lửa thuần túy nhất — đây là một trong những sự kết hợp năng lượng mạnh mẽ nhất; hãy bắt đầu với niềm vui và sự tự tin hoàn toàn.", en: "The Sun and Ace of Wands: the most radiant light meets the purest spark — this is one of the most powerful energy combinations; begin with complete joy and confidence." },
  "19_23": { vi: "Mặt Trời và Hai Gậy: tầm nhìn rõ ràng và lạc quan lên kế hoạch mở rộng táo bạo — hãy lên kế hoạch dưới ánh sáng đầy đủ này; bạn đang nhìn thấy những khả năng thực sự, không phải ảo ảnh.", en: "The Sun and Two of Wands: clear and optimistic vision plans bold expansion — plan in this full light; you are seeing real possibilities, not illusions." },
  "19_24": { vi: "Mặt Trời và Ba Gậy: dưới ánh sáng mặt trời, chân trời không có giới hạn — hãy để sự rõ ràng này làm dẫn đường; những gì bạn đang hướng tới là xứng đáng và có thể đạt được.", en: "The Sun and Three of Wands: in full sunlight, the horizon has no limits — let this clarity lead you; what you are moving toward is worthy and reachable." },
  "19_25": { vi: "Mặt Trời và Bốn Gậy: ánh sáng rực rỡ và niềm vui chạm đến đỉnh điểm trong lễ ăn mừng hoàn hảo — hãy ở trọn vẹn trong khoảnh khắc này; không phải ngày nào cũng tỏa sáng như hôm nay.", en: "The Sun and Four of Wands: radiant light and joy reach their peak in the perfect celebration — be fully present in this moment; not every day shines like this one." },
  "19_26": { vi: "Mặt Trời và Năm Gậy: ánh sáng mặt trời soi sáng cuộc tranh đấu và biến nó thành trò chơi vui vẻ hơn là cuộc chiến thực sự — hãy nhớ rằng sự cạnh tranh lành mạnh khiến mọi người tốt hơn.", en: "The Sun and Five of Wands: sunlight illuminates the struggle and transforms it into playful sport rather than real war — remember that healthy competition makes everyone better." },
  "19_27": { vi: "Mặt Trời và Sáu Gậy: chiến thắng trong ánh sáng đầy đủ — không có bóng tối, không có nghi ngờ, không có sự mơ hồ; điều này thực sự là như nó có vẻ.", en: "The Sun and Six of Wands: victory in full light — no shadow, no doubt, no ambiguity; this is genuinely as good as it appears." },
  "19_28": { vi: "Mặt Trời và Bảy Gậy: đứng vững trong ánh sáng đầy đủ với niềm tin trong sáng và vui vẻ — những ai leo lên để thách thức bạn sẽ thấy rõ sự khác biệt giữa ánh sáng và bóng tối.", en: "The Sun and Seven of Wands: hold your ground in full light with clear, joyful confidence — those who climb to challenge you will see plainly the difference between light and shadow." },
  "19_29": { vi: "Mặt Trời và Tám Gậy: năng lượng rực rỡ di chuyển với sự nhanh chóng vui vẻ — hãy theo kịp tốc độ này; nó đang mang bạn về phía điều tốt nhất.", en: "The Sun and Eight of Wands: radiant energy moves with joyful swiftness — keep pace; it is carrying you toward the best of what is possible." },
  "19_30": { vi: "Mặt Trời và Chín Gậy: ánh sáng mặt trời tiếp thêm sức mạnh cho người lính gác mệt mỏi — bình minh đã đến; hãy để ánh sáng này nhắc nhở bạn tại sao bạn bắt đầu đứng vững.", en: "The Sun and Nine of Wands: sunlight replenishes the weary guardian — dawn has arrived; let this light remind you why you started standing firm." },
  "19_31": { vi: "Mặt Trời và Mười Gậy: ánh sáng rõ ràng cho thấy chính xác gánh nặng nào cần đặt xuống — không có bóng tối để che giấu sự thật: một số thứ này không thuộc về bạn để mang.", en: "The Sun and Ten of Wands: clear light shows exactly which burdens need to be set down — there is no shadow to hide the truth: some of this does not belong to you to carry." },

  // Judgement (20) × Wands
  "20_22": { vi: "Phán Xét và Át Gậy: lời gọi thức tỉnh châm ngòi một tia lửa sáng tạo hoàn toàn mới — bạn không trở lại những gì đã qua; bạn đang bắt đầu từ phiên bản được đánh thức của chính mình.", en: "Judgement and Ace of Wands: the call to awaken ignites an entirely new creative spark — you are not going back to what was; you are beginning from the awakened version of yourself." },
  "20_23": { vi: "Phán Xét và Hai Gậy: sự thức tỉnh định hình lại những kế hoạch chiến lược với tầm nhìn mới được soi sáng — hãy lên kế hoạch không phải từ người bạn đã từng là mà từ người bạn đang trở thành.", en: "Judgement and Two of Wands: awakening reshapes strategic plans with newly illuminated vision — plan not from who you were but from who you are becoming." },
  "20_24": { vi: "Phán Xét và Ba Gậy: sự thức tỉnh mở ra những chân trời mà bạn trước đây không thể thấy — khi bạn thay đổi những gì bạn tin là có thể, những gì có thể thay đổi theo.", en: "Judgement and Three of Wands: awakening opens horizons you could not previously see — when you change what you believe is possible, what is possible changes too." },
  "20_25": { vi: "Phán Xét và Bốn Gậy: câu trả lời cho lời gọi dẫn đến một cuộc ăn mừng cộng đồng sâu sắc và thực sự — hãy chia sẻ sự biến đổi này với những người đã đứng bên bạn; chiến thắng của bạn là của họ cũng vậy.", en: "Judgement and Four of Wands: answering the call leads to a deep and genuine communal celebration — share this transformation with those who stood beside you; your victory is theirs too." },
  "20_26": { vi: "Phán Xét và Năm Gậy: sự thức tỉnh tiết lộ những cuộc xung đột nào đáng tiếp tục và những cuộc nào cần buông bỏ — không phải mọi trận chiến thuộc về phiên bản mới của bạn.", en: "Judgement and Five of Wands: awakening reveals which conflicts are worth continuing and which need to be released — not every battle belongs to the new version of you." },
  "20_27": { vi: "Phán Xét và Sáu Gậy: sự thức tỉnh và biến đổi được tôn vinh công khai — thế giới đang công nhận không chỉ những gì bạn đã đạt được mà cả người bạn đã trở thành trong quá trình đó.", en: "Judgement and Six of Wands: awakening and transformation are publicly honoured — the world is recognising not only what you have achieved but who you have become in the process." },
  "20_28": { vi: "Phán Xét và Bảy Gậy: hãy đứng vững từ sự thức tỉnh chứ không phải từ thói quen cũ — đảm bảo rằng những gì bạn đang bảo vệ thuộc về phiên bản được thức tỉnh của bạn, không phải phiên bản cũ.", en: "Judgement and Seven of Wands: hold your ground from awakening rather than old habit — make certain what you are defending belongs to your awakened self, not the old one." },
  "20_29": { vi: "Phán Xét và Tám Gậy: lời gọi thức tỉnh tạo ra đà nhanh chóng không thể đảo ngược — hãy nhận ra rằng bạn đang di chuyển về phía trước và không có cách nào quay lại.", en: "Judgement and Eight of Wands: the call to awaken creates irreversible swift momentum — recognise that you are moving forward and there is no returning." },
  "20_30": { vi: "Phán Xét và Chín Gậy: người lính gác mệt mỏi nghe tiếng kèn gọi và nhận ra điều anh ấy đã bảo vệ đã hoàn thành sứ mệnh của nó — đây là sự kết thúc của một chu kỳ dài, không phải sự thất bại.", en: "Judgement and Nine of Wands: the weary guardian hears the trumpet call and realises what they have been protecting has completed its mission — this is the end of a long cycle, not a defeat." },
  "20_31": { vi: "Phán Xét và Mười Gậy: lời gọi thức tỉnh đòi hỏi bạn đặt xuống những gánh nặng không thuộc về phiên bản mới của bạn — bạn không thể đáp lại lời gọi trong khi đang ôm chặt mọi thứ cũ.", en: "Judgement and Ten of Wands: the call to awaken demands you set down the burdens that do not belong to your new self — you cannot answer the call while holding tightly to everything old." },

  // World (21) × Wands
  "21_22": { vi: "Thế Giới và Át Gậy: sự hoàn thành của một hành trình lớn cùng tồn tại với một tia lửa mới hoàn toàn — bạn đang đứng ở đích đến và ở điểm khởi đầu cùng một lúc.", en: "The World and Ace of Wands: completion of one great journey coexists with an entirely new spark — you are standing at the destination and at the beginning at the same time." },
  "21_23": { vi: "Thế Giới và Hai Gậy: sự hoàn thành của một chu kỳ mở ra tầm nhìn cho chu kỳ tiếp theo — hãy lên kế hoạch cho vòng tiếp theo từ sự khôn ngoan đầy đủ của những gì vừa hoàn thành.", en: "The World and Two of Wands: completion of one cycle opens the vision for the next — plan the next round from the full wisdom of what has just been completed." },
  "21_24": { vi: "Thế Giới và Ba Gậy: người đã hoàn thành hành trình nhìn về phía chân trời tiếp theo với sự tự tin đầy đủ — bạn đã biết mình có thể đến đó; bây giờ bạn biết bạn có thể đến đây.", en: "The World and Three of Wands: the one who has completed the journey looks at the next horizon with full confidence — you have already proven you can get there; now you know you can get here too." },
  "21_25": { vi: "Thế Giới và Bốn Gậy: sự hoàn thành của hành trình vĩ đại là lý do cho sự ăn mừng cộng đồng sâu sắc nhất — hãy để thế giới chia sẻ niềm vui này với bạn; bạn đã kiếm được điều này.", en: "The World and Four of Wands: completion of the great journey is cause for the deepest communal celebration — let the world share in this joy; you have genuinely earned this." },
  "21_26": { vi: "Thế Giới và Năm Gậy: người đã đi hết vòng sẽ thấy những cuộc tranh đấu nhỏ khác đi — hãy mang sự khôn ngoan của sự hoàn thành vào cuộc chơi; đừng để bụi bặm của những cuộc xung đột nhỏ che mờ tầm nhìn đó.", en: "The World and Five of Wands: one who has come full circle sees small struggles differently — bring the wisdom of completion into the contest; do not let the dust of minor conflicts obscure that larger view." },
  "21_27": { vi: "Thế Giới và Sáu Gậy: sự công nhận đến với người đã đi hết hành trình — đây không chỉ là chiến thắng trước người khác mà là chiến thắng hoàn chỉnh trước toàn bộ hành trình.", en: "The World and Six of Wands: recognition comes to the one who has completed the full journey — this is not just victory over others but complete victory over the entire path." },
  "21_28": { vi: "Thế Giới và Bảy Gậy: người đã hoàn thành hành trình không cần chứng minh bất cứ điều gì — hãy đứng vững từ sự hoàn thành, không phải từ nỗi lo lắng; vị trí của bạn là không thể tranh cãi.", en: "The World and Seven of Wands: the one who has completed the journey has nothing left to prove — stand firm from completion, not from anxiety; your position is beyond dispute." },
  "21_29": { vi: "Thế Giới và Tám Gậy: sự hoàn thành của một hành trình tạo ra đà để bắt đầu hành trình tiếp theo — hãy để sự thành công của vòng này mang năng lượng vào vòng tiếp theo.", en: "The World and Eight of Wands: completion of one journey generates the momentum to begin the next — let the success of this round carry energy into the one that follows." },
  "21_30": { vi: "Thế Giới và Chín Gậy: người đã đi hết vòng nhìn lại người lính gác mệt mỏi và nhận ra: bạn đã làm được rồi — đây không phải là sự kiên trì cuối cùng; đây là sự hoàn thành của nó.", en: "The World and Nine of Wands: the one who has come full circle looks back at the weary guardian and realises: you made it — this is not the final endurance; it is the completion of it." },
  "21_31": { vi: "Thế Giới và Mười Gậy: sự hoàn thành tiết lộ rằng những gánh nặng bạn đã mang đã làm xong công việc của chúng — đã đến lúc đặt chúng xuống và bước vào điều tiếp theo nhẹ nhàng hơn nhiều.", en: "The World and Ten of Wands: completion reveals that the burdens you have been carrying have done their work — it is time to set them down and step into what comes next far lighter." },

  // ─── TIER 3b: Major × Cups Numbered (220 pairs) ─────────────────────────────
  // Task 7a: Majors 0–7 × Cups 36–45

  // Fool (0) × Cups
  "0_36": { vi: "Kẻ Ngốc và Át Cốc: trái tim trống rỗng sẵn sàng được lấp đầy bởi tình yêu thuần túy — hãy bước vào cuộc hành trình này với sự cởi mở hoàn toàn; điều tốt nhất đến với những ai không chuẩn bị quá kỹ.", en: "The Fool and Ace of Cups: an open heart ready to be filled with pure love — step into this journey with complete openness; the best things come to those who do not over-prepare." },
  "0_37": { vi: "Kẻ Ngốc và Hai Cốc: bước nhảy ngây thơ vào một kết nối mới đầy hứa hẹn — hãy để trái tim dẫn trước lý trí; mối quan hệ tốt nhất bắt đầu từ sự chân thành không toan tính.", en: "The Fool and Two of Cups: an innocent leap into a promising new connection — let the heart lead before the mind; the best bonds begin with sincerity, not strategy." },
  "0_38": { vi: "Kẻ Ngốc và Ba Cốc: khởi đầu mới được chào đón bởi niềm vui và tình bạn — hãy để bản thân được nuôi dưỡng bởi sự ấm áp của những người đang chờ đón bạn.", en: "The Fool and Three of Cups: a new beginning welcomed by joy and friendship — allow yourself to be nourished by the warmth of those who are waiting to welcome you." },
  "0_39": { vi: "Kẻ Ngốc và Bốn Cốc: bước nhảy hứng khởi gặp phải sự thờ ơ hoặc chán nản — hãy kiểm tra xem liệu sự thụ động này là trí tuệ hay chỉ là thói quen từ chối những điều tốt.", en: "The Fool and Four of Cups: an enthusiastic leap meets apathy or discontent — examine whether this withdrawal is wisdom or merely a habit of refusing what is good." },
  "0_40": { vi: "Kẻ Ngốc và Năm Cốc: khởi đầu mới xuất hiện ngay cả khi bạn đang nhìn chằm chằm vào những gì đã mất — hãy quay đầu; có điều gì đó mới đang đứng sau lưng bạn.", en: "The Fool and Five of Cups: a new beginning exists even while you stare at what was lost — turn around; something new is standing right behind you." },
  "0_41": { vi: "Kẻ Ngốc và Sáu Cốc: bước nhảy dẫn trở lại những ký ức ngọt ngào và kết nối trong sáng — hãy mang sự hồn nhiên của bạn như một món quà cho những người từ quá khứ.", en: "The Fool and Six of Cups: the leap leads back to sweet memories and innocent connection — bring your openness as a gift to those from the past." },
  "0_42": { vi: "Kẻ Ngốc và Bảy Cốc: tinh thần ngây thơ bước vào vùng đất của ảo tưởng và lựa chọn choáng ngợp — hãy cẩn thận; không phải mọi giấc mơ rực rỡ đều xứng đáng được theo đuổi.", en: "The Fool and Seven of Cups: innocent spirit steps into the realm of illusion and overwhelming choices — be careful; not every glittering dream is worth chasing." },
  "0_43": { vi: "Kẻ Ngốc và Tám Cốc: hành trình mới đòi hỏi rời bỏ những gì đã trở nên rỗng tuếch — hãy can đảm bước đi; sự giã từ này không phải là sự thất bại mà là sự trưởng thành.", en: "The Fool and Eight of Cups: the new journey requires leaving behind what has become hollow — have the courage to walk away; this departure is not failure, it is maturity." },
  "0_44": { vi: "Kẻ Ngốc và Chín Cốc: bước nhảy hướng thẳng đến sự thỏa mãn và mãn nguyện — hãy tin rằng con đường bạn đang chọn dẫn đến điều bạn thực sự muốn trong trái tim.", en: "The Fool and Nine of Cups: the leap heads straight toward satisfaction and contentment — trust that the path you are choosing leads to what you genuinely want in your heart." },
  "0_45": { vi: "Kẻ Ngốc và Mười Cốc: hành trình ngây thơ hướng đến hạnh phúc gia đình và sự viên mãn cảm xúc — hãy tin rằng điều tốt đẹp nhất vẫn đang chờ đón bạn ở phía trước.", en: "The Fool and Ten of Cups: the innocent journey moves toward family happiness and emotional fulfilment — trust that the most beautiful things are still ahead waiting for you." },

  // Magician (1) × Cups
  "1_36": { vi: "Pháp Sư và Át Cốc: ý chí có chủ đích mở ra dòng chảy cảm xúc thuần túy — hãy dùng kỹ năng của bạn không chỉ để đạt được điều bạn muốn mà còn để kết nối với những gì bạn thực sự cảm thấy.", en: "The Magician and Ace of Cups: focused will opens a flow of pure emotion — use your skills not only to achieve what you want but to connect with what you genuinely feel." },
  "1_37": { vi: "Pháp Sư và Hai Cốc: kỹ năng và ý chí tạo ra mối quan hệ có chủ đích và cân bằng — hãy đầu tư năng lực vào việc xây dựng kết nối này một cách có ý thức.", en: "The Magician and Two of Cups: skill and will create an intentional, balanced connection — invest your capability into building this bond with full awareness." },
  "1_38": { vi: "Pháp Sư và Ba Cốc: năng lực có chủ đích tạo điều kiện cho niềm vui và sự ăn mừng cộng đồng — hãy dùng kỹ năng của bạn để nuôi dưỡng những mối quan hệ xung quanh, không chỉ mục tiêu cá nhân.", en: "The Magician and Three of Cups: purposeful capability creates the conditions for communal joy and celebration — use your skills to nourish the connections around you, not only personal goals." },
  "1_39": { vi: "Pháp Sư và Bốn Cốc: kỹ năng gặp sự thờ ơ — hãy kiểm tra xem liệu bạn có đang dùng năng lực để tránh né cảm xúc thay vì thực sự cảm nhận chúng hay không.", en: "The Magician and Four of Cups: skill meets apathy — examine whether you are using capability to avoid emotions rather than genuinely feeling them." },
  "1_40": { vi: "Pháp Sư và Năm Cốc: hãy dùng kỹ năng để nhìn thấy những gì còn lại thay vì chỉ tập trung vào những gì đã đổ — năng lực của bạn không mất đi cùng với những mất mát này.", en: "The Magician and Five of Cups: use skill to see what remains rather than focusing only on what has spilled — your capability is not lost with these losses." },
  "1_41": { vi: "Pháp Sư và Sáu Cốc: kỹ năng kết hợp với sự hồi tưởng chân thành về quá khứ — hãy mang trí tuệ từ những ký ức ngọt ngào vào những gì bạn đang xây dựng hôm nay.", en: "The Magician and Six of Cups: skill combined with genuine nostalgia for the past — bring the wisdom from sweet memories into what you are building today." },
  "1_42": { vi: "Pháp Sư và Bảy Cốc: ý chí tập trung cần thiết để điều hướng qua rừng ảo tưởng — hãy dùng sự rõ ràng của bạn để phân biệt giấc mơ thực sự khỏi những ảo giác lộng lẫy.", en: "The Magician and Seven of Cups: focused will is needed to navigate through the forest of illusions — use your clarity to distinguish genuine dreams from spectacular fantasies." },
  "1_43": { vi: "Pháp Sư và Tám Cốc: hãy dùng ý chí có chủ đích để rời bỏ những gì không còn phục vụ bạn — đây không phải là sự bỏ cuộc; đây là sự lựa chọn có ý thức về nơi năng lực của bạn thuộc về.", en: "The Magician and Eight of Cups: use purposeful will to walk away from what no longer serves you — this is not giving up; it is a conscious choice about where your capability belongs." },
  "1_44": { vi: "Pháp Sư và Chín Cốc: kỹ năng và ý chí đạt đến sự thỏa mãn thực sự — hãy công nhận rằng điều bạn đã biểu hiện là có thật; bạn đã tạo ra điều này.", en: "The Magician and Nine of Cups: skill and will arrive at genuine satisfaction — acknowledge that what you have manifested is real; you created this." },
  "1_45": { vi: "Pháp Sư và Mười Cốc: năng lực có chủ đích xây dựng nền tảng cho hạnh phúc lâu dài — những gì bạn đã xây dựng bằng kỹ năng và tình yêu bây giờ đang nuôi dưỡng những người bạn yêu thương.", en: "The Magician and Ten of Cups: purposeful capability builds the foundation for lasting happiness — what you have built with skill and love is now nourishing those you love." },

  // High Priestess (2) × Cups
  "2_36": { vi: "Thầy Tư Tế Nữ và Át Cốc: trí tuệ nội tâm sâu thẳm gặp dòng chảy cảm xúc thuần túy — hãy để tình yêu này đến từ chiều sâu của bạn, không phải từ bề mặt của sự mong đợi.", en: "The High Priestess and Ace of Cups: deep inner wisdom meets pure emotional flow — let this love arise from your depths, not from the surface of expectation." },
  "2_37": { vi: "Thầy Tư Tế Nữ và Hai Cốc: sự thầm lặng nội tâm nuôi dưỡng một kết nối thực sự — hãy mang sự im lặng của bạn vào mối quan hệ này như một món quà; không phải mọi khoảnh khắc cần được lấp đầy bằng lời nói.", en: "The High Priestess and Two of Cups: inner stillness nurtures a genuine connection — bring your silence into this relationship as a gift; not every moment needs to be filled with words." },
  "2_38": { vi: "Thầy Tư Tế Nữ và Ba Cốc: trực giác sâu sắc tìm thấy sự biểu hiện trong niềm vui và sự kết nối cộng đồng — hãy tin tưởng những gì bạn cảm nhận được trong vòng tay của những người thân yêu.", en: "The High Priestess and Three of Cups: deep intuition finds expression in joy and communal connection — trust what you feel in the embrace of those you love." },
  "2_39": { vi: "Thầy Tư Tế Nữ và Bốn Cốc: sự rút lui vào bên trong có thể là trí tuệ hoặc là tránh né — hãy ngồi trong sự im lặng và hỏi trung thực liệu đây là sự phục hồi cần thiết hay sự từ chối những gì cuộc sống đang cung cấp.", en: "The High Priestess and Four of Cups: withdrawal inward may be wisdom or avoidance — sit in the silence and ask honestly whether this is necessary restoration or a refusal of what life is offering." },
  "2_40": { vi: "Thầy Tư Tế Nữ và Năm Cốc: trí tuệ nội tâm ngồi với nỗi đau mà không bị cuốn trôi bởi nó — hãy cảm nhận sự mất mát một cách đầy đủ; sự im lặng của bạn là không gian mà nỗi đau cần để chữa lành.", en: "The High Priestess and Five of Cups: inner wisdom sits with grief without being swept away by it — feel the loss fully; your stillness is the space that grief needs to heal." },
  "2_41": { vi: "Thầy Tư Tế Nữ và Sáu Cốc: trí tuệ sâu thẳm nhận ra điều gì trong quá khứ vẫn còn sống và điều gì cần được để yên — không phải mọi ký ức đều cần được hồi sinh.", en: "The High Priestess and Six of Cups: deep wisdom recognises what from the past is still alive and what needs to be left in peace — not every memory needs to be revived." },
  "2_42": { vi: "Thầy Tư Tế Nữ và Bảy Cốc: trực giác là la bàn duy nhất đáng tin cậy trong vùng đất của ảo tưởng — hãy dùng sự im lặng của bạn để nghe thấy điều gì thực sự đúng, không phải điều gì chỉ trông đẹp.", en: "The High Priestess and Seven of Cups: intuition is the only trustworthy compass in the land of illusion — use your stillness to hear what is genuinely true, not merely what looks beautiful." },
  "2_43": { vi: "Thầy Tư Tế Nữ và Tám Cốc: trí tuệ nội tâm biết khi nào đã đến lúc rời đi — hãy tin vào điều bạn cảm thấy trong chiều sâu, ngay cả khi bề mặt vẫn còn trông ổn.", en: "The High Priestess and Eight of Cups: inner wisdom knows when it is time to leave — trust what you feel in the depths, even when the surface still looks fine." },
  "2_44": { vi: "Thầy Tư Tế Nữ và Chín Cốc: sự mãn nguyện sâu sắc đến từ việc sống trung thực với trực giác của mình — đây không phải là may mắn; đây là kết quả của việc tin vào những gì bạn biết.", en: "The High Priestess and Nine of Cups: deep contentment comes from living honestly with your own intuition — this is not luck; it is the result of trusting what you know." },
  "2_45": { vi: "Thầy Tư Tế Nữ và Mười Cốc: sự hài hòa cảm xúc sâu thẳm được đặt nền trên trí tuệ nội tâm — hạnh phúc thực sự nhất là loại được nhìn thấy rõ ràng, không được thực hiện cho người khác.", en: "The High Priestess and Ten of Cups: deep emotional harmony grounded in inner wisdom — the most real happiness is the kind that is seen clearly, not performed for others." },

  // Empress (3) × Cups
  "3_36": { vi: "Nữ Hoàng và Át Cốc: sự phong phú nuôi dưỡng dòng chảy tình yêu thuần túy — hãy mở lòng để nhận cũng như cho; sự phong phú cảm xúc chảy theo cả hai chiều.", en: "The Empress and Ace of Cups: nurturing abundance feeds a flow of pure love — open to receive as well as give; emotional abundance flows in both directions." },
  "3_37": { vi: "Nữ Hoàng và Hai Cốc: năng lượng nuôi dưỡng tạo ra nền tảng an toàn cho sự kết nối lẫn nhau — hãy xây dựng mối quan hệ này trong không gian của sự chăm sóc và không phán xét.", en: "The Empress and Two of Cups: nurturing energy creates a safe foundation for mutual connection — build this relationship in the space of care and non-judgment." },
  "3_38": { vi: "Nữ Hoàng và Ba Cốc: tình yêu phong phú tìm thấy biểu hiện trong sự ăn mừng và gắn kết cộng đồng — hãy để sự hào phóng của bạn lan tỏa; niềm vui chia sẻ nhân lên chứ không chia hết.", en: "The Empress and Three of Cups: abundant love finds expression in celebration and communal bonding — let your generosity ripple outward; shared joy multiplies rather than divides." },
  "3_39": { vi: "Nữ Hoàng và Bốn Cốc: sự nuôi dưỡng gặp phải sự thờ ơ — hãy nhẹ nhàng tự hỏi liệu bạn có đang chăm sóc cho người khác trong khi bỏ bê chính mình hay không.", en: "The Empress and Four of Cups: nurturing meets apathy — gently ask yourself whether you are caring for others while neglecting your own emotional needs." },
  "3_40": { vi: "Nữ Hoàng và Năm Cốc: lòng trắc ẩn ngồi bên cạnh sự đau buồn mà không vội vã chữa lành nó — hãy để tình yêu của bạn là sự hiện diện, không phải là sự giải pháp.", en: "The Empress and Five of Cups: compassion sits beside grief without rushing to fix it — let your love be a presence, not a solution." },
  "3_41": { vi: "Nữ Hoàng và Sáu Cốc: lòng trắc ẩn nuôi dưỡng những kỷ niệm ngọt ngào và kết nối tinh tế với quá khứ — hãy để sự ấm áp đó chảy về phía trước như là nguồn cội, không phải neo đậu.", en: "The Empress and Six of Cups: nurturing compassion honours sweet memories and tender connection with the past — let that warmth flow forward as a source, not an anchor." },
  "3_42": { vi: "Nữ Hoàng và Bảy Cốc: sự phong phú sáng tạo có nguy cơ bị phân tán vào quá nhiều ước mơ — hãy nuôi dưỡng một hoặc hai cái cây thực sự hơn là tưới nước cho cả một rừng ảo tưởng.", en: "The Empress and Seven of Cups: creative abundance risks being scattered across too many dreams — nurture one or two real trees rather than watering an entire forest of fantasies." },
  "3_43": { vi: "Nữ Hoàng và Tám Cốc: lòng từ bi đối với bản thân cho phép sự ra đi khi điều nuôi dưỡng đã cạn kiệt — hãy yêu thương chính mình đủ để bước đi.", en: "The Empress and Eight of Cups: self-compassion allows the departure when what once nourished has run dry — love yourself enough to walk away." },
  "3_44": { vi: "Nữ Hoàng và Chín Cốc: sự phong phú và lòng biết ơn tạo ra sự mãn nguyện thực sự — hãy đếm những gì đang nở hoa trong cuộc sống của bạn trước khi tìm kiếm thêm.", en: "The Empress and Nine of Cups: abundance and gratitude create genuine contentment — count what is already blooming in your life before searching for more." },
  "3_45": { vi: "Nữ Hoàng và Mười Cốc: lòng yêu thương phong phú đạt đến sự viên mãn trong hạnh phúc gia đình và sự hài hòa sâu sắc — đây là điều trái tim bạn đã nuôi dưỡng trong rất nhiều năm.", en: "The Empress and Ten of Cups: abundant love reaches fulfilment in family happiness and deep harmony — this is what your heart has been nurturing for so many years." },

  // Emperor (4) × Cups
  "4_36": { vi: "Hoàng Đế và Át Cốc: cấu trúc và quyền lực gặp dòng chảy cảm xúc thuần túy — hãy cho phép trái tim này làm mềm những góc cạnh của bạn mà không mất đi nền tảng.", en: "The Emperor and Ace of Cups: structure and authority meet pure emotional flow — allow this heart to soften your edges without losing your foundation." },
  "4_37": { vi: "Hoàng Đế và Hai Cốc: quyền lực gặp sự kết nối bình đẳng — hãy bước vào mối quan hệ này không phải với tư cách người cai trị mà với tư cách đối tác.", en: "The Emperor and Two of Cups: authority meets equal connection — enter this relationship not as a ruler but as an equal partner." },
  "4_38": { vi: "Hoàng Đế và Ba Cốc: quyền lực ổn định tạo không gian an toàn cho niềm vui cộng đồng — sức mạnh tốt nhất là sức mạnh tạo ra điều kiện để người khác phát triển.", en: "The Emperor and Three of Cups: stable authority creates the safe space for communal joy — the best strength is the kind that creates conditions for others to flourish." },
  "4_39": { vi: "Hoàng Đế và Bốn Cốc: kỷ luật và sự kiểm soát đang che chắn khỏi một điều gì đó đang được cung cấp — hãy hạ thấp lá chắn đủ để thấy cái gì đang ở trong chiếc cốc thứ tư đó.", en: "The Emperor and Four of Cups: discipline and control are shielding from something being offered — lower the guard enough to see what is in that fourth cup." },
  "4_40": { vi: "Hoàng Đế và Năm Cốc: sức mạnh đứng trước nỗi đau và không biết phải làm gì với nó — hãy cho phép bản thân đau buồn; đây không phải là sự yếu đuối mà là sự can đảm của loại khác.", en: "The Emperor and Five of Cups: strength stands before grief and does not know what to do with it — allow yourself to grieve; this is not weakness but courage of a different kind." },
  "4_41": { vi: "Hoàng Đế và Sáu Cốc: quyền lực nhìn lại quá khứ với sự nhớ nhung chân thật — hãy để những kỷ niệm này nhắc nhở bạn về những gì quan trọng hơn là quyền lực.", en: "The Emperor and Six of Cups: authority looks back at the past with genuine tenderness — let these memories remind you of what matters more than power." },
  "4_42": { vi: "Hoàng Đế và Bảy Cốc: ý chí kỷ luật cần thiết để cắt qua màn sương của những ảo tưởng — hãy dùng sự rõ ràng của bạn để nhìn thấy thực tế, không phải những gì bạn muốn thực tế là.", en: "The Emperor and Seven of Cups: disciplined will is needed to cut through the mist of illusions — use your clarity to see reality, not what you wish reality to be." },
  "4_43": { vi: "Hoàng Đế và Tám Cốc: sức mạnh thực sự đôi khi là sức mạnh để rời bỏ những gì không còn phục vụ bạn — hãy đưa ra quyết định có cấu trúc, không phải phản ứng cảm xúc.", en: "The Emperor and Eight of Cups: true strength is sometimes the strength to leave what no longer serves — make a structured decision, not an emotional reaction." },
  "4_44": { vi: "Hoàng Đế và Chín Cốc: kỷ luật và ý chí dẫn đến sự thỏa mãn xứng đáng — hãy ngồi trong sự hài lòng này; bạn đã xây dựng nó một cách có chủ đích.", en: "The Emperor and Nine of Cups: discipline and will lead to well-deserved satisfaction — sit in this contentment; you built it deliberately." },
  "4_45": { vi: "Hoàng Đế và Mười Cốc: cấu trúc vững chắc là nền tảng cho hạnh phúc gia đình lâu dài — điều bạn đã xây dựng không phải là nhà tù mà là ngôi nhà.", en: "The Emperor and Ten of Cups: solid structure is the foundation for lasting family happiness — what you have built is not a prison but a home." },

  // Hierophant (5) × Cups
  "5_36": { vi: "Giáo Hoàng và Át Cốc: truyền thống thiêng liêng gặp dòng chảy tình yêu thuần túy — hãy để tình yêu này được biểu hiện qua những nghi lễ có ý nghĩa, không chỉ là cảm xúc thoáng qua.", en: "The Hierophant and Ace of Cups: sacred tradition meets pure love's flow — let this love be expressed through meaningful ritual, not merely fleeting feeling." },
  "5_37": { vi: "Giáo Hoàng và Hai Cốc: kết nối được chứng kiến và được chúc phúc bởi một truyền thống lớn hơn — hãy để nghi lễ và cam kết làm sâu sắc thêm điều bắt đầu như là cảm xúc đơn thuần.", en: "The Hierophant and Two of Cups: connection witnessed and blessed by something larger than the two of you — let ritual and commitment deepen what began as mere feeling." },
  "5_38": { vi: "Giáo Hoàng và Ba Cốc: lễ hội được tổ chức trong khuôn khổ của truyền thống và tập tục — những lễ kỷ niệm sâu sắc nhất là những lễ kỷ niệm được neo đậu trong điều thiêng liêng.", en: "The Hierophant and Three of Cups: celebration held within the framework of tradition and ritual — the deepest festivities are those anchored in the sacred." },
  "5_39": { vi: "Giáo Hoàng và Bốn Cốc: cấu trúc tôn giáo không thể lấp đầy khoảng trống cảm xúc nếu trái tim thực sự không có ở đó — hãy kiểm tra xem bạn có đang đi theo hình thức mà không có bản chất hay không.", en: "The Hierophant and Four of Cups: religious structure cannot fill emotional emptiness if the heart is genuinely absent — examine whether you are following the form without the essence." },
  "5_40": { vi: "Giáo Hoàng và Năm Cốc: truyền thống có thể cung cấp nghi lễ để tang và sự an ủi qua sự mất mát — hãy để những tập tục cổ xưa giữ bạn khi sức mạnh cá nhân đang lung lay.", en: "The Hierophant and Five of Cups: tradition can provide the ritual of mourning and comfort through loss — let ancient practices hold you when personal strength is faltering." },
  "5_41": { vi: "Giáo Hoàng và Sáu Cốc: sự tôn kính với truyền thống gặp sự nhớ nhung về nguồn cội trong sáng — hãy tôn vinh những người đã dạy bạn cách yêu thương và thuộc về.", en: "The Hierophant and Six of Cups: reverence for tradition meets nostalgia for innocent origins — honour those who taught you how to love and to belong." },
  "5_42": { vi: "Giáo Hoàng và Bảy Cốc: giáo lý được thiết lập cung cấp khuôn khổ để điều hướng qua sự bất định — không phải mọi truyền thống là xiềng xích; một số là la bàn.", en: "The Hierophant and Seven of Cups: established teaching provides a framework for navigating through confusion — not every tradition is a chain; some are a compass." },
  "5_43": { vi: "Giáo Hoàng và Tám Cốc: khi một con đường tâm linh đã bị vượt qua, hãy để đi với sự kính trọng — không phải sự từ bỏ truyền thống mà là sự lớn lên trong nó.", en: "The Hierophant and Eight of Cups: when a spiritual path has been outgrown, leave with respect — this is not abandoning tradition but growing within it." },
  "5_44": { vi: "Giáo Hoàng và Chín Cốc: sự thực hành tâm linh nhất quán dẫn đến sự thỏa mãn sâu sắc — điều bạn đã cống hiến cho con đường này đang quay trở lại với bạn như là sự bình yên.", en: "The Hierophant and Nine of Cups: consistent spiritual practice leads to deep satisfaction — what you have given to this path is returning to you as peace." },
  "5_45": { vi: "Giáo Hoàng và Mười Cốc: niềm tin và tập tục thiêng liêng tạo ra nền tảng cho hạnh phúc và sự hài hòa gia đình — hãy truyền lại những gì có giá trị cho những người sẽ đến sau.", en: "The Hierophant and Ten of Cups: faith and sacred practice create the foundation for family happiness and harmony — pass on what has genuine value to those who will come after." },

  // Lovers (6) × Cups
  "6_36": { vi: "Người Yêu Nhau và Át Cốc: một lựa chọn từ trái tim mở ra dòng chảy tình yêu thuần túy — hãy chọn không phải từ sự sợ hãi hay sự tiện lợi mà từ điều làm cho trái tim bạn mở ra.", en: "The Lovers and Ace of Cups: a choice from the heart opens a flow of pure love — choose not from fear or convenience but from what makes your heart open." },
  "6_37": { vi: "Người Yêu Nhau và Hai Cốc: sự lựa chọn của tâm hồn gặp sự kết nối lẫn nhau sâu sắc — đây là sự kết hợp của những tâm hồn đã chọn nhau một cách có ý thức.", en: "The Lovers and Two of Cups: the soul's choice meets deep mutual connection — this is the union of souls who have chosen each other consciously." },
  "6_38": { vi: "Người Yêu Nhau và Ba Cốc: tình yêu đã chọn tìm thấy sự biểu hiện trong niềm vui cộng đồng — hãy để mối quan hệ của bạn là nguồn sức mạnh lan tỏa, không phải là điều đóng cửa thế giới ra ngoài.", en: "The Lovers and Three of Cups: chosen love finds expression in communal joy — let your relationship be a source of radiating strength, not something that closes the world out." },
  "6_39": { vi: "Người Yêu Nhau và Bốn Cốc: lựa chọn của trái tim gặp sự không hài lòng hoặc sự thờ ơ cảm xúc — hãy kiểm tra liệu sự thờ ờ này là về mối quan hệ hay về một điều gì đó bên trong bạn cần chú ý.", en: "The Lovers and Four of Cups: the heart's choice meets emotional dissatisfaction or apathy — examine whether this numbness is about the relationship or about something inside you that needs attention." },
  "6_40": { vi: "Người Yêu Nhau và Năm Cốc: tình yêu đứng trước sự mất mát và đau khổ — hãy đau buồn những gì đã vỡ trước khi quyết định những gì cần làm tiếp theo.", en: "The Lovers and Five of Cups: love stands before loss and grief — mourn what has broken before deciding what to do next." },
  "6_41": { vi: "Người Yêu Nhau và Sáu Cốc: tình yêu đã chọn được tô màu bởi sự nhớ nhung và kết nối thuần túy từ quá khứ — hãy nhận ra phần nào của điều này là ký ức và phần nào là hiện thực.", en: "The Lovers and Six of Cups: chosen love is coloured by nostalgia and innocent connection from the past — recognise which part of this is memory and which part is present reality." },
  "6_42": { vi: "Người Yêu Nhau và Bảy Cốc: lựa chọn của trái tim bị làm phức tạp bởi quá nhiều ảo tưởng về điều tình yêu nên là — hãy hỏi không phải tình yêu bạn muốn mà là tình yêu bạn thực sự có.", en: "The Lovers and Seven of Cups: the heart's choice is complicated by too many illusions about what love should be — ask not what love you want but what love you actually have." },
  "6_43": { vi: "Người Yêu Nhau và Tám Cốc: đôi khi lựa chọn có ý thức nhất là rời bỏ những gì bạn đã yêu — hãy tôn trọng cả mối quan hệ và bản thân bạn đủ để thành thật.", en: "The Lovers and Eight of Cups: sometimes the most conscious choice is to leave what you once loved — honour both the relationship and yourself enough to be honest." },
  "6_44": { vi: "Người Yêu Nhau và Chín Cốc: lựa chọn đúng dẫn đến sự thỏa mãn và hạnh phúc thực sự — hãy nhận ra rằng điều bạn cảm thấy bây giờ là bằng chứng cho sự lựa chọn bạn đã thực hiện.", en: "The Lovers and Nine of Cups: the right choice leads to genuine satisfaction and happiness — recognise that what you feel now is evidence of the choice you made." },
  "6_45": { vi: "Người Yêu Nhau và Mười Cốc: tình yêu được chọn một cách có ý thức đạt đến sự viên mãn trong hạnh phúc chung — đây là những gì các lựa chọn nhỏ làm từ trái tim xây dựng theo thời gian.", en: "The Lovers and Ten of Cups: love chosen consciously reaches fulfilment in shared happiness — this is what small choices made from the heart build over time." },

  // Chariot (7) × Cups
  "7_36": { vi: "Chiến Xa và Át Cốc: ý chí sắt đá gặp dòng chảy tình yêu thuần túy — hãy để trái tim này làm mềm sự cứng rắn của bạn mà không phá vỡ sự tập trung của bạn.", en: "The Chariot and Ace of Cups: iron will meets pure love's flow — let this heart soften your hardness without breaking your focus." },
  "7_37": { vi: "Chiến Xa và Hai Cốc: ý chí chinh phục gặp sự kết nối lẫn nhau — hãy nhớ rằng những mối quan hệ tốt nhất không phải là những gì bạn chinh phục mà là những gì bạn đồng hành.", en: "The Chariot and Two of Cups: conquering will meets mutual connection — remember that the best relationships are not those you win but those you walk alongside." },
  "7_38": { vi: "Chiến Xa và Ba Cốc: động lực chiến thắng đến bữa tiệc của tình bạn và niềm vui — hãy học cách chiến thắng cùng với người khác, không chỉ vì người khác.", en: "The Chariot and Three of Cups: victorious momentum arrives at the feast of friendship and joy — learn how to win alongside others, not merely on behalf of them." },
  "7_39": { vi: "Chiến Xa và Bốn Cốc: ý chí thúc đẩy tiến lên phía trước bị kiềm lại bởi sự không hài lòng cảm xúc — hãy dừng lại đủ lâu để nhận ra những gì đang được cung cấp trước khi tiếp tục chạy.", en: "The Chariot and Four of Cups: the will pushing forward is checked by emotional dissatisfaction — pause long enough to recognise what is being offered before continuing to run." },
  "7_40": { vi: "Chiến Xa và Năm Cốc: ý chí tiến về phía trước bị thử thách bởi nỗi đau và sự mất mát — đừng lái xe qua đau buồn; hãy dừng lại và cảm nhận nó hoặc nó sẽ bắt kịp bạn sau này.", en: "The Chariot and Five of Cups: the will to move forward is challenged by pain and loss — do not drive through grief; stop to feel it or it will catch up with you later." },
  "7_41": { vi: "Chiến Xa và Sáu Cốc: ý chí hướng về phía trước được nhắc nhở bởi sự ngọt ngào của nguồn cội — đừng chạy quá nhanh đến mức quên mất những gì đã làm bạn muốn đến đích.", en: "The Chariot and Six of Cups: the forward will is reminded of the sweetness of origins — do not run so fast that you forget what made you want to reach the destination." },
  "7_42": { vi: "Chiến Xa và Bảy Cốc: ý chí kỷ luật là điều duy nhất giữ bạn đi thẳng qua vùng đất của ảo tưởng — hãy không cho phép bản thân bị phân tâm bởi những tầm nhìn lộng lẫy.", en: "The Chariot and Seven of Cups: disciplined will is the only thing that keeps you driving straight through the land of illusion — do not allow yourself to be distracted by spectacular visions." },
  "7_43": { vi: "Chiến Xa và Tám Cốc: đôi khi ý chí mạnh nhất là ý chí để rời đi — hãy lái chiến xa của bạn về phía trước, ra khỏi những gì đã trở nên trống rỗng.", en: "The Chariot and Eight of Cups: sometimes the strongest will is the will to leave — drive your chariot forward, away from what has become hollow." },
  "7_44": { vi: "Chiến Xa và Chín Cốc: ý chí kỷ luật dẫn đến sự thỏa mãn xứng đáng — hãy ngồi với sự mãn nguyện này; bạn đã chiến đấu cho nó.", en: "The Chariot and Nine of Cups: disciplined will leads to well-deserved satisfaction — sit with this contentment; you fought for it." },
  "7_45": { vi: "Chiến Xa và Mười Cốc: hành trình đầy ý chí kết thúc trong vòng tay của hạnh phúc và sự hài hòa — tất cả những cuộc chiến đấu đã dẫn bạn đến đây.", en: "The Chariot and Ten of Cups: the journey of will ends in the embrace of happiness and harmony — all of the battles brought you here." },

  // Task 7b: Majors 8–15 × Cups 36–45

  // Strength (8) × Cups
  "8_36": { vi: "Sức Mạnh và Át Cốc: lòng can đảm nhẹ nhàng mở ra dòng chảy tình yêu thuần túy — hãy để trái tim này đến không phải từ sự kiểm soát mà từ sự dịu dàng đã được rèn giũa.", en: "Strength and Ace of Cups: gentle courage opens a flow of pure love — let this heart arrive not from control but from tenderness that has been earned." },
  "8_37": { vi: "Sức Mạnh và Hai Cốc: lòng can đảm dịu dàng tạo ra không gian an toàn cho kết nối lẫn nhau — mối quan hệ tốt nhất được xây dựng không phải bằng sự chi phối mà bằng sức mạnh nhẹ nhàng.", en: "Strength and Two of Cups: gentle courage creates the safe space for mutual connection — the best bonds are built not through dominance but through gentle strength." },
  "8_38": { vi: "Sức Mạnh và Ba Cốc: lòng can đảm kiên nhẫn tìm thấy sự nghỉ ngơi và phục hồi trong niềm vui cộng đồng — hãy để sức mạnh của bạn được nuôi dưỡng bởi những người yêu thương bạn.", en: "Strength and Three of Cups: patient courage finds rest and restoration in communal joy — let your strength be nourished by those who love you." },
  "8_39": { vi: "Sức Mạnh và Bốn Cốc: can đảm nhẹ nhàng ngồi với sự không hài lòng mà không vội xua đuổi nó — hãy để sự điềm tĩnh của bạn tạo ra không gian để cảm xúc thực sự nổi lên.", en: "Strength and Four of Cups: gentle courage sits with dissatisfaction without rushing to chase it away — let your stillness create space for genuine feelings to surface." },
  "8_40": { vi: "Sức Mạnh và Năm Cốc: lòng can đảm nhất là ngồi đầy đủ với nỗi đau mà không bị nghiền nát — hãy để mình khóc; đây là sức mạnh, không phải sự yếu đuối.", en: "Strength and Five of Cups: the greatest courage is sitting fully with grief without being crushed — allow yourself to weep; this is strength, not weakness." },
  "8_41": { vi: "Sức Mạnh và Sáu Cốc: lòng can đảm dịu dàng giữ gìn những ký ức ngọt ngào với lòng biết ơn — hãy tôn vinh quá khứ mà không bị kéo ngược về nó.", en: "Strength and Six of Cups: gentle courage holds sweet memories with gratitude — honour the past without being pulled backward into it." },
  "8_42": { vi: "Sức Mạnh và Bảy Cốc: can đảm kiên nhẫn cần thiết để không bị lạc trong rừng ảo tưởng — hãy dùng sức mạnh nhẹ nhàng của bạn để chọn thực tế hơn là điều lộng lẫy.", en: "Strength and Seven of Cups: patient courage is needed to avoid getting lost in the forest of illusions — use your gentle strength to choose reality over what merely appears magnificent." },
  "8_43": { vi: "Sức Mạnh và Tám Cốc: đôi khi hành động can đảm nhất là bước đi khỏi những gì không còn nuôi dưỡng bạn — hãy ra đi không phải với sự giận dữ mà với lòng biết ơn về những gì đã từng là.", en: "Strength and Eight of Cups: sometimes the most courageous act is walking away from what no longer nourishes — leave not with anger but with gratitude for what once was." },
  "8_44": { vi: "Sức Mạnh và Chín Cốc: lòng can đảm được nuôi dưỡng qua nhiều năm dẫn đến sự thỏa mãn thực sự — hãy nhận sự mãn nguyện này; bạn đã kiếm được nó bằng sự kiên nhẫn.", en: "Strength and Nine of Cups: courage nurtured over many years leads to genuine satisfaction — receive this contentment; you earned it through patience." },
  "8_45": { vi: "Sức Mạnh và Mười Cốc: lòng can đảm nhẹ nhàng xây dựng nền tảng cho hạnh phúc lâu dài và hài hòa sâu sắc — điều bền vững nhất được xây dựng bằng tình yêu, không phải sức mạnh.", en: "Strength and Ten of Cups: gentle courage builds the foundation for lasting happiness and deep harmony — the most enduring things are built with love, not force." },

  // Hermit (9) × Cups
  "9_36": { vi: "Ẩn Sĩ và Át Cốc: sự tĩnh lặng cô độc mở ra dòng chảy tình yêu thuần túy — điều bạn đã tìm kiếm trong im lặng đang tìm đường đến với bạn.", en: "The Hermit and Ace of Cups: solitary stillness opens a flow of pure love — what you have been seeking in silence is finding its way to you." },
  "9_37": { vi: "Ẩn Sĩ và Hai Cốc: người đã học cách ở một mình gặp sự kết nối thực sự — hãy mang sự trọn vẹn của bản thân bạn vào mối quan hệ này, không phải nhu cầu cần được lấp đầy.", en: "The Hermit and Two of Cups: one who has learned to be alone meets genuine connection — bring your wholeness into this bond, not a need to be filled." },
  "9_38": { vi: "Ẩn Sĩ và Ba Cốc: hành trình cô độc trở về vòng tay của tình bạn và niềm vui — ánh sáng bạn đã giữ gìn trong im lặng bây giờ chiếu sáng căn phòng.", en: "The Hermit and Three of Cups: the solitary journey returns to the embrace of friendship and joy — the light you have kept in silence now illuminates the room." },
  "9_39": { vi: "Ẩn Sĩ và Bốn Cốc: sự cô đơn và sự thờ ơ trở nên khó phân biệt — hãy hỏi trung thực liệu sự rút lui này là sự phục hồi cần thiết hay là cái bẫy của sự cô lập.", en: "The Hermit and Four of Cups: solitude and apathy become hard to distinguish — ask honestly whether this withdrawal is necessary restoration or the trap of isolation." },
  "9_40": { vi: "Ẩn Sĩ và Năm Cốc: sự cô đơn với nỗi đau có thể là nơi trú ẩn hoặc nhà tù — hãy để ánh đèn lồng của bạn chiếu vào cả những gì vẫn còn đứng vững lẫn những gì đã bị mất.", en: "The Hermit and Five of Cups: solitude with grief can be sanctuary or prison — let your lantern shine on both what still stands and what has been lost." },
  "9_41": { vi: "Ẩn Sĩ và Sáu Cốc: nhà ẩn dật nhìn lại quá khứ trong sáng với sự nhận ra — những ký ức đó đã định hình bạn thành người đang cầm đèn lồng này.", en: "The Hermit and Six of Cups: the hermit looks back at innocent origins with recognition — those memories shaped you into the one holding this lantern." },
  "9_42": { vi: "Ẩn Sĩ và Bảy Cốc: ánh sáng nội tâm là la bàn duy nhất đáng tin cậy qua những ảo tưởng — hãy rọi đèn lồng vào từng chiếc cốc; bạn sẽ thấy cái nào chứa thực tế.", en: "The Hermit and Seven of Cups: inner light is the only trustworthy compass through illusions — shine the lantern into each cup; you will see which one holds reality." },
  "9_43": { vi: "Ẩn Sĩ và Tám Cốc: người ẩn dật hiểu rõ hơn ai hết ý nghĩa của việc đi về phía ánh sáng của mình — hãy tiếp tục bước đi; bóng tối đằng sau bạn không phải là tương lai của bạn.", en: "The Hermit and Eight of Cups: the hermit understands better than anyone what it means to walk toward one's own light — keep moving; the darkness behind you is not your future." },
  "9_44": { vi: "Ẩn Sĩ và Chín Cốc: sự tìm kiếm nội tâm lâu dài dẫn đến sự thỏa mãn yên tĩnh và sâu sắc — hạnh phúc bạn tìm thấy trong im lặng là loại thực nhất.", en: "The Hermit and Nine of Cups: the long inner search leads to quiet, deep satisfaction — the happiness you find in silence is the most real kind." },
  "9_45": { vi: "Ẩn Sĩ và Mười Cốc: người đã đi một mình tìm thấy sự hài hòa và thuộc về — hành trình đơn độc không kết thúc trong sự cô đơn; nó kết thúc ở đây.", en: "The Hermit and Ten of Cups: one who journeyed alone finds harmony and belonging — the solitary path does not end in loneliness; it ends here." },

  // Wheel of Fortune (10) × Cups
  "10_36": { vi: "Bánh Xe Số Phận và Át Cốc: một điểm xoay của số phận mở ra dòng tình yêu và cảm xúc mới — hãy nắm lấy khoảnh khắc này; trái tim đang được mời mở ra.", en: "The Wheel of Fortune and Ace of Cups: a turning point of fate opens a new flow of love and emotion — seize this moment; the heart is being invited to open." },
  "10_37": { vi: "Bánh Xe Số Phận và Hai Cốc: số phận mang hai người lại gặp nhau đúng thời điểm — đây không phải ngẫu nhiên; hãy trân trọng sự gặp gỡ này.", en: "The Wheel of Fortune and Two of Cups: fate brings two people together at the right moment — this is not accident; honour this meeting." },
  "10_38": { vi: "Bánh Xe Số Phận và Ba Cốc: vận may quay về phía niềm vui và sự kết nối — hãy để bản thân được ôm đón bởi những người đang ăn mừng cùng bạn.", en: "The Wheel of Fortune and Three of Cups: fortune turns toward joy and connection — allow yourself to be embraced by those celebrating alongside you." },
  "10_39": { vi: "Bánh Xe Số Phận và Bốn Cốc: một bước ngoặt đang diễn ra ngay cả khi bạn đang ngồi trong sự thờ ơ — hãy nhìn lên; cái gì đó mới đang được cung cấp ngay lúc này.", en: "The Wheel of Fortune and Four of Cups: a turning point is happening even while you sit in apathy — look up; something new is being offered right now." },
  "10_40": { vi: "Bánh Xe Số Phận và Năm Cốc: bánh xe quay và mang sự mất mát đến — hãy nhớ rằng nó cũng sẽ quay lại; sự đau buồn này không phải là trạng thái vĩnh viễn.", en: "The Wheel of Fortune and Five of Cups: the wheel turns and brings loss — remember that it will turn again; this grief is not a permanent state." },
  "10_41": { vi: "Bánh Xe Số Phận và Sáu Cốc: số phận mang những kết nối từ quá khứ trở lại theo những cách bất ngờ — hãy tiếp nhận sự trở lại này với sự cởi mở và nhận thức rõ ràng.", en: "The Wheel of Fortune and Six of Cups: fate brings connections from the past back in unexpected ways — receive this return with openness and clear awareness." },
  "10_42": { vi: "Bánh Xe Số Phận và Bảy Cốc: khi bánh xe quay bạn qua những ảo tưởng, hãy giữ lấy điều thực sự — không phải mọi giấc mơ rực rỡ xuất hiện ở đỉnh của bánh xe đều xứng đáng được theo đuổi.", en: "The Wheel of Fortune and Seven of Cups: as the wheel spins you through illusions, hold on to what is real — not every glittering dream appearing at the top of the wheel is worth pursuing." },
  "10_43": { vi: "Bánh Xe Số Phận và Tám Cốc: bánh xe quay và đã đến lúc rời đi — đừng chống lại sự dịch chuyển này; hãy để nó mang bạn về phía điều tiếp theo.", en: "The Wheel of Fortune and Eight of Cups: the wheel turns and it is time to move on — do not resist this shift; let it carry you toward what comes next." },
  "10_44": { vi: "Bánh Xe Số Phận và Chín Cốc: vận may quay về phía sự thỏa mãn và niềm vui — hãy nhận ra điều này không chỉ là may mắn; đây là sự hội tụ của thời điểm và nỗ lực.", en: "The Wheel of Fortune and Nine of Cups: fortune turns toward satisfaction and joy — recognise this is not only luck; it is the convergence of timing and effort." },
  "10_45": { vi: "Bánh Xe Số Phận và Mười Cốc: một chu kỳ hoàn thành trong sự hài hòa và hạnh phúc — hãy ăn mừng không chỉ điều bạn có mà cả hành trình mà bánh xe đã đưa bạn qua.", en: "The Wheel of Fortune and Ten of Cups: a cycle completes in harmony and happiness — celebrate not only what you have but the journey the wheel has carried you through." },

  // Justice (11) × Cups
  "11_36": { vi: "Công Lý và Át Cốc: tình yêu thực sự bắt đầu bằng sự trung thực — hãy mở trái tim này từ sự rõ ràng, không phải từ sự lý tưởng hóa.", en: "Justice and Ace of Cups: real love begins with honesty — open this heart from clarity, not from idealisation." },
  "11_37": { vi: "Công Lý và Hai Cốc: kết nối thực sự đòi hỏi sự cân bằng và công bằng lẫn nhau — hãy xây dựng mối quan hệ này trên sự bình đẳng, không phải trên quyền lực.", en: "Justice and Two of Cups: genuine connection requires balance and mutual fairness — build this bond on equality, not on power." },
  "11_38": { vi: "Công Lý và Ba Cốc: hãy đảm bảo rằng niềm vui bạn đang chia sẻ được xây dựng trên sự công bằng và đóng góp thực sự — những kết nối tốt nhất là những kết nối mà mọi người đều thực sự có mặt.", en: "Justice and Three of Cups: make sure the joy you are sharing is built on genuine fairness and contribution — the best connections are those where everyone is truly present." },
  "11_39": { vi: "Công Lý và Bốn Cốc: sự thờ ơ đòi hỏi sự trung thực — hãy nhìn rõ liệu sự không hài lòng này có phần gốc rễ trong sự bất công mà bạn chưa giải quyết hay không.", en: "Justice and Four of Cups: apathy demands honesty — look clearly at whether this dissatisfaction is rooted in an injustice you have not yet addressed." },
  "11_40": { vi: "Công Lý và Năm Cốc: sự mất mát đôi khi là kết quả của những lựa chọn và hành động — hãy ngồi với sự thật của điều này mà không tự trừng phạt, chỉ với sự nhận thức rõ ràng.", en: "Justice and Five of Cups: loss is sometimes the consequence of choices and actions — sit with the truth of this without self-punishment, only with clear awareness." },
  "11_41": { vi: "Công Lý và Sáu Cốc: hãy nhìn quá khứ không phải qua màu hồng mà qua sự rõ ràng — những ký ức ngọt ngào nhất đôi khi che giấu những sự thật cần được thừa nhận.", en: "Justice and Six of Cups: look at the past not through rose tint but through clarity — the sweetest memories sometimes conceal truths that need to be acknowledged." },
  "11_42": { vi: "Công Lý và Bảy Cốc: sự công bằng là đèn soi sáng qua rừng ảo tưởng — hãy hỏi không phải điều gì trông đẹp nhất mà điều gì thực sự đúng đắn nhất.", en: "Justice and Seven of Cups: fairness is the light that cuts through the forest of illusions — ask not what looks most beautiful but what is most genuinely true." },
  "11_43": { vi: "Công Lý và Tám Cốc: rời đi là một hành động công bằng đối với chính mình và người khác khi không có gì thực sự còn lại — hãy đi với sự rõ ràng, không phải sự hối hận.", en: "Justice and Eight of Cups: leaving is an act of fairness to yourself and others when nothing genuine remains — go with clarity, not with guilt." },
  "11_44": { vi: "Công Lý và Chín Cốc: sự thỏa mãn thực sự đến khi bạn biết rằng bạn đã sống trung thực — hạnh phúc được kiếm bằng sự thành thật có vị ngọt khác.", en: "Justice and Nine of Cups: genuine satisfaction comes when you know you have lived honestly — happiness earned through integrity tastes different." },
  "11_45": { vi: "Công Lý và Mười Cốc: hạnh phúc gia đình thực sự được xây dựng trên sự công bằng và sự tôn trọng lẫn nhau — hãy vun đắp nền tảng này mỗi ngày.", en: "Justice and Ten of Cups: real family happiness is built on fairness and mutual respect — tend this foundation every day." },

  // Hanged Man (12) × Cups
  "12_36": { vi: "Người Treo Ngược và Át Cốc: sự quy phục mở ra một dòng tình yêu thuần túy không thể đến khi bạn đang cố gắng kiểm soát — hãy buông tay và để cảm xúc đến.", en: "The Hanged Man and Ace of Cups: surrender opens a flow of pure love that cannot arrive while you are trying to control — let go and allow feeling to come." },
  "12_37": { vi: "Người Treo Ngược và Hai Cốc: nhìn mối quan hệ từ góc độ ngược lại tiết lộ những gì bị che khuất — những gì bạn cần thay đổi không phải là người kia mà là góc nhìn của bạn.", en: "The Hanged Man and Two of Cups: viewing the relationship from the inverted angle reveals what has been hidden — what needs to change is not the other person but your own perspective." },
  "12_38": { vi: "Người Treo Ngược và Ba Cốc: sự dừng lại mời bạn tham dự vào niềm vui theo cách mới — đôi khi chứng kiến hạnh phúc của người khác từ phía sau là một loại hồng ân.", en: "The Hanged Man and Three of Cups: the pause invites you to participate in joy in a new way — sometimes witnessing others' happiness from the edges is its own kind of grace." },
  "12_39": { vi: "Người Treo Ngược và Bốn Cốc: treo lơ lửng trong sự không hành động cho thấy liệu sự thờ ơ đến từ sự mệt mỏi hay sự khôn ngoan — hãy chú ý đến sự khác biệt.", en: "The Hanged Man and Four of Cups: hanging suspended in non-action reveals whether the apathy comes from exhaustion or wisdom — pay attention to the difference." },
  "12_40": { vi: "Người Treo Ngược và Năm Cốc: góc nhìn mới tiết lộ rằng những gì đổ ra không mất đi vĩnh viễn — hãy nhìn từ phía ngược lại và bạn sẽ thấy những chiếc cốc vẫn còn đứng vững.", en: "The Hanged Man and Five of Cups: the new perspective reveals that what spilled is not permanently lost — look from the inverted angle and you will see the cups still standing." },
  "12_41": { vi: "Người Treo Ngược và Sáu Cốc: nhìn quá khứ từ góc độ treo ngược — có thể những gì bạn đang nhớ nhung không đẹp như bạn nghĩ, hoặc đẹp hơn bạn cho phép mình thừa nhận.", en: "The Hanged Man and Six of Cups: viewing the past from the inverted angle — perhaps what you are nostalgic for is not as golden as you think, or more precious than you allow yourself to admit." },
  "12_42": { vi: "Người Treo Ngược và Bảy Cốc: nhìn từ phía ngược lại tiết lộ ảo tưởng nào đang che giấu sự thật — hãy buông bỏ tư thế thông thường và bạn sẽ thấy những chiếc cốc khác đi.", en: "The Hanged Man and Seven of Cups: looking from the inverted angle reveals which illusion is masking truth — release the usual posture and you will see the cups differently." },
  "12_43": { vi: "Người Treo Ngược và Tám Cốc: đôi khi sự dừng lại là bước đầu tiên của việc rời đi — hãy treo lơ lửng ở đây đủ lâu để biết chắc chắn trước khi bước xuống và bước đi.", en: "The Hanged Man and Eight of Cups: sometimes the pause is the first step of the departure — hang here long enough to be certain before stepping down and walking away." },
  "12_44": { vi: "Người Treo Ngược và Chín Cốc: buông bỏ sự kiểm soát là điều kiện tiên quyết cho sự thỏa mãn thực sự — hạnh phúc mà bạn đang tìm kiếm không thể bị nắm bắt, chỉ có thể được nhận.", en: "The Hanged Man and Nine of Cups: releasing control is the prerequisite for genuine satisfaction — the happiness you seek cannot be seized, only received." },
  "12_45": { vi: "Người Treo Ngược và Mười Cốc: góc nhìn mới tiết lộ rằng hài hòa không phải là điều đạt được mà là điều được cho phép xảy ra — hãy buông bỏ sự cần phải kiểm soát kết quả.", en: "The Hanged Man and Ten of Cups: the new perspective reveals that harmony is not something achieved but something allowed to happen — release the need to control the outcome." },

  // Death (13) × Cups
  "13_36": { vi: "Thần Chết và Át Cốc: sự kết thúc dọn sạch không gian cho tình yêu thuần túy hoàn toàn mới — trái tim bạn không thể lấp đầy bởi những gì mới khi nó vẫn đang ôm chặt những gì cũ.", en: "Death and Ace of Cups: an ending clears space for entirely new, pure love — your heart cannot be filled by what is new while it is still clutching what is old." },
  "13_37": { vi: "Thần Chết và Hai Cốc: một mối quan hệ đang chuyển hóa — không phải mọi sự kết thúc đều là sự chia ly; đôi khi điều chết đi là phiên bản cũ của mối quan hệ, không phải chính mối quan hệ.", en: "Death and Two of Cups: a relationship is transforming — not every ending is a separation; sometimes what dies is the old version of the bond, not the bond itself." },
  "13_38": { vi: "Thần Chết và Ba Cốc: một nhóm hoặc một mối dây kết nối đang đến hồi kết — hãy ăn mừng những gì đã là trước khi buông bỏ, và buông bỏ với lòng biết ơn.", en: "Death and Three of Cups: a group or connection is reaching its natural end — celebrate what was before releasing it, and release it with gratitude." },
  "13_39": { vi: "Thần Chết và Bốn Cốc: sự thờ ơ này không phải là một pha; đây là dấu hiệu cho thấy điều gì đó đã thực sự kết thúc — hãy trung thực với bản thân về điều đó.", en: "Death and Four of Cups: this apathy is not a phase; it is a sign that something has genuinely ended — be honest with yourself about that." },
  "13_40": { vi: "Thần Chết và Năm Cốc: đây là sự mất mát thực sự đang kết thúc một chương — hãy để tang đầy đủ; đây là sự tôn trọng đối với những gì đã có ý nghĩa.", en: "Death and Five of Cups: this is real loss closing a chapter — grieve fully; this is the respect owed to what once mattered." },
  "13_41": { vi: "Thần Chết và Sáu Cốc: sự chuyển đổi tiết lộ những ký ức nào từ quá khứ cần được mang theo và những ký ức nào cần được chôn cất — không phải mọi ký ức đẹp đều cần làm hành trang.", en: "Death and Six of Cups: transformation reveals which memories from the past deserve to be carried forward and which deserve to be buried — not every beautiful memory needs to become luggage." },
  "13_42": { vi: "Thần Chết và Bảy Cốc: sự chuyển đổi phá tan những ảo tưởng và chỉ để lại những gì thực sự có thực — hãy nhìn những chiếc cốc còn lại; chúng thực hơn bất kỳ điều gì bạn đã mơ.", en: "Death and Seven of Cups: transformation shatters illusions and leaves only what is genuinely real — look at the cups that remain; they are more real than anything you have been dreaming." },
  "13_43": { vi: "Thần Chết và Tám Cốc: sự chuyển đổi và sự rời đi là hai mặt của cùng một cánh cửa — hãy bước qua với lòng can đảm; điều đang chết đi đang mở đường cho điều đang sống.", en: "Death and Eight of Cups: transformation and departure are two faces of the same door — step through with courage; what is dying is making way for what is living." },
  "13_44": { vi: "Thần Chết và Chín Cốc: sự thỏa mãn thực sự đến sau khi điều cũ qua đi — hạnh phúc bạn cảm thấy bây giờ không thể đến sớm hơn; nó cần sự kết thúc đó mới có thể xuất hiện.", en: "Death and Nine of Cups: genuine satisfaction arrives after the old passes away — the happiness you feel now could not have come sooner; it needed that ending to become possible." },
  "13_45": { vi: "Thần Chết và Mười Cốc: hài hòa và viên mãn mới chỉ có thể xuất hiện sau sự chuyển đổi đầy đủ — điều bạn đang hướng tới đẹp hơn những gì bạn rời bỏ.", en: "Death and Ten of Cups: new harmony and fulfilment can only emerge after full transformation — what you are moving toward is more beautiful than what you left behind." },

  // Temperance (14) × Cups
  "14_36": { vi: "Điều Độ và Át Cốc: thuật giả kim kiên nhẫn pha trộn tình yêu thuần túy thành điều bền vững — hãy để cảm xúc này đến từ từ; điều được cảm nhận đầy đủ sẽ tồn tại lâu hơn điều bùng lên rồi tắt.", en: "Temperance and Ace of Cups: patient alchemy blends pure love into something enduring — let this feeling arrive slowly; what is felt fully lasts longer than what ignites and burns out." },
  "14_37": { vi: "Điều Độ và Hai Cốc: sự cân bằng và kiên nhẫn xây dựng kết nối lâu dài — hãy pha trộn hai dòng chảy này với sự chú tâm; mối quan hệ tốt nhất là những mối quan hệ được vun đắp từ từ.", en: "Temperance and Two of Cups: balance and patience build lasting connection — blend these two streams with care; the best relationships are those tended slowly." },
  "14_38": { vi: "Điều Độ và Ba Cốc: niềm vui được chia sẻ theo đúng nhịp điệu tạo ra sự kết nối sâu sắc nhất — hãy để sự ăn mừng chảy tự nhiên, không cần khuếch đại cũng không cần kìm hãm.", en: "Temperance and Three of Cups: shared joy in the right rhythm creates the deepest connection — let the celebration flow naturally, neither amplified nor suppressed." },
  "14_39": { vi: "Điều Độ và Bốn Cốc: hãy pha trộn sự rút lui cần thiết với sự hiện diện; quá nhiều một trong hai đều không lành mạnh — hãy tìm nhịp điệu giữa nội tâm và thế giới bên ngoài.", en: "Temperance and Four of Cups: blend necessary withdrawal with presence; too much of either is unhealthy — find the rhythm between inner world and outer engagement." },
  "14_40": { vi: "Điều Độ và Năm Cốc: thuật giả kim của sự chữa lành hoạt động chậm và ổn định — đừng vội vàng qua nỗi đau và cũng đừng ở lại trong nó mãi; hãy để nó chảy qua đúng thời điểm.", en: "Temperance and Five of Cups: the alchemy of healing works slowly and steadily — do not rush through grief nor stay in it forever; let it flow through at its own pace." },
  "14_41": { vi: "Điều Độ và Sáu Cốc: hãy pha trộn sự nhớ nhung về quá khứ với sự hiện diện của hiện tại — những ký ức đẹp nhất nuôi dưỡng bạn khi chúng chảy về phía trước, không phải khi chúng kéo bạn ngược lại.", en: "Temperance and Six of Cups: blend nostalgia for the past with presence in the now — the most beautiful memories nourish you when they flow forward, not when they pull you back." },
  "14_42": { vi: "Điều Độ và Bảy Cốc: sự cân bằng và sự rõ ràng là những gì điều hướng bạn qua rừng ảo tưởng — hãy pha trộn trực giác với lý trí; không cái nào là đủ một mình.", en: "Temperance and Seven of Cups: balance and clarity are what navigate you through the forest of illusions — blend intuition with reason; neither is sufficient alone." },
  "14_43": { vi: "Điều Độ và Tám Cốc: sự ra đi được thực hiện với sự điều độ — không phải sự bùng phát hay sự tan biến, mà là sự lựa chọn có ý thức được thực hiện với sự bình tĩnh.", en: "Temperance and Eight of Cups: the departure made with temperance — not a burst nor a fade, but a conscious choice made with composure." },
  "14_44": { vi: "Điều Độ và Chín Cốc: sự thỏa mãn đến với những ai đã học cách pha trộn mong muốn với sự biết ơn — hạnh phúc không phải là sự vắng mặt của ham muốn mà là sự hài hòa với những gì đang là.", en: "Temperance and Nine of Cups: satisfaction comes to those who have learned to blend desire with gratitude — happiness is not the absence of longing but harmony with what is." },
  "14_45": { vi: "Điều Độ và Mười Cốc: hài hòa gia đình được xây dựng qua sự kiên nhẫn hàng ngày và sự cân bằng ổn định — không phải sự hoàn hảo mà là sự điều chỉnh liên tục theo đúng hướng.", en: "Temperance and Ten of Cups: family harmony is built through daily patience and steady balance — not perfection but continuous adjustment in the right direction." },

  // Devil (15) × Cups
  "15_36": { vi: "Ác Quỷ và Át Cốc: hãy kiểm tra liệu tình yêu mới này đến từ sự cởi mở hay từ sự cần thiết — tình yêu được sinh ra từ nỗi sợ hãi sự cô đơn không phải là tình yêu; đó là sự phụ thuộc.", en: "The Devil and Ace of Cups: examine whether this new love arrives from openness or from need — love born from fear of loneliness is not love; it is dependency." },
  "15_37": { vi: "Ác Quỷ và Hai Cốc: hãy nhìn kỹ vào sợi dây kết nối giữa hai người này — liệu đây là sự chọn lựa tự do hay là những xiềng xích được giải thích thành tình yêu?", en: "The Devil and Two of Cups: look carefully at the cord connecting these two people — is this free choice or are these chains being interpreted as love?" },
  "15_38": { vi: "Ác Quỷ và Ba Cốc: hãy kiểm tra liệu vòng tròn này được xây dựng trên niềm vui thực sự hay trên những thói quen không lành mạnh được chia sẻ — không phải mọi sự gắn kết đều là kết nối.", en: "The Devil and Three of Cups: examine whether this circle is built on genuine joy or on shared unhealthy habits — not every bonding is a genuine connection." },
  "15_39": { vi: "Ác Quỷ và Bốn Cốc: sự thờ ơ cảm xúc có thể là kết quả của những xiềng xích mà bạn đã quá quen với chúng đến mức không còn cảm thấy chúng nữa — hãy nhìn lại những gì đang giữ bạn tê liệt.", en: "The Devil and Four of Cups: emotional numbness may be the result of chains you have worn so long you no longer feel them — look again at what is keeping you paralysed." },
  "15_40": { vi: "Ác Quỷ và Năm Cốc: hãy kiểm tra liệu nỗi đau này đang được duy trì bởi chính bạn vì nó cảm thấy quen thuộc — đôi khi chúng ta bám vào đau khổ vì nó ít nhất là điều chúng ta biết.", en: "The Devil and Five of Cups: examine whether this pain is being maintained by you because it feels familiar — sometimes we cling to suffering because it is at least something known." },
  "15_41": { vi: "Ác Quỷ và Sáu Cốc: hãy kiểm tra liệu sự nhớ nhung này là tình yêu thực sự hay là sự nghiện với một cảm giác an toàn từ quá khứ — quá khứ không thể cứu bạn khỏi hiện tại.", en: "The Devil and Six of Cups: examine whether this nostalgia is genuine love or an addiction to a feeling of safety from the past — the past cannot rescue you from the present." },
  "15_42": { vi: "Ác Quỷ và Bảy Cốc: trong rừng ảo tưởng, bóng tối có thể trông giống ánh sáng — hãy cẩn thận với những ước mơ nào đang dẫn bạn về phía những gì làm hại bạn.", en: "The Devil and Seven of Cups: in the forest of illusions, shadow can look like light — be careful which dreams are leading you toward what harms you." },
  "15_43": { vi: "Ác Quỷ và Tám Cốc: xiềng xích mạnh nhất là những xiềng xích giả vờ là tình yêu — hãy kiểm tra liệu điều bạn đang rời bỏ là một lựa chọn tự do hay sự trốn thoát khỏi điều bạn không thể đặt tên.", en: "The Devil and Eight of Cups: the strongest chains are the ones pretending to be love — examine whether what you are walking away from is a free choice or an escape from something you cannot name." },
  "15_44": { vi: "Ác Quỷ và Chín Cốc: hãy kiểm tra liệu sự thỏa mãn này đến từ sự sung mãn thực sự hay từ sự thỏa mãn những ham muốn không bao giờ thực sự thỏa mãn — sự thỏa mãn thực sự không cần nhiều hơn mỗi ngày.", en: "The Devil and Nine of Cups: examine whether this satisfaction comes from genuine fulfilment or from feeding desires that are never truly satisfied — real contentment does not demand more each day." },
  "15_45": { vi: "Ác Quỷ và Mười Cốc: hãy kiểm tra liệu hình ảnh hạnh phúc gia đình này là thực hay là một màn trình diễn để che giấu những xiềng xích ở phía sau — hài hòa thực sự không cần khán giả.", en: "The Devil and Ten of Cups: examine whether this image of family happiness is real or a performance masking chains behind the scene — genuine harmony does not need an audience." },

  // Tower (16) × Cups 36–45
  "16_36": { vi: "Tháp và Át Cốc: giữa đống đổ vỡ, một cảm xúc thuần khiết xuất hiện — đây không phải tai họa mà là khoảnh khắc trái tim được rửa sạch và sẵn sàng cho tình yêu thật sự.", en: "The Tower and Ace of Cups: within the rubble, a pure emotion surfaces — this is not disaster but the moment the heart is cleansed and made ready for genuine love." },
  "16_37": { vi: "Tháp và Hai Cốc: mối kết nối này sẽ không sống sót nếu nó được xây trên những nền tảng sai — sự sụp đổ chỉ là dấu hiệu cho thấy những gì thật sự bền vững cần được xây lại từ đầu.", en: "The Tower and Two of Cups: this connection will not survive if built on false foundations — the collapse is simply the signal that what is truly lasting must be rebuilt from the ground up." },
  "16_38": { vi: "Tháp và Ba Cốc: đám đông ăn mừng tan vỡ khi sự thật xuất hiện — nhưng những người ở lại sau cơn lũ là những người bạn đồng hành thực sự của bạn.", en: "The Tower and Three of Cups: the celebrating crowd scatters when truth arrives — but those who remain after the flood are your genuine companions." },
  "16_39": { vi: "Tháp và Bốn Cốc: sự thờ ơ bị xóa tan bởi một cú sét đánh — cái mà bạn thấy nhàm chán giờ bỗng trở nên quý giá, và bạn nhận ra mình đã có những gì thực sự cần.", en: "The Tower and Four of Cups: apathy is shattered by a lightning strike — what felt tedious suddenly becomes precious, and you realise you already had what truly mattered." },
  "16_40": { vi: "Tháp và Năm Cốc: mất mát chồng chất mất mát — nhưng hãy nhìn vào những gì còn đứng vững bên cạnh những gì đã đổ vỡ, vì đó là nơi cuộc sống mới bắt đầu.", en: "The Tower and Five of Cups: loss heaped upon loss — yet look at what still stands beside what has fallen, for that is precisely where new life begins." },
  "16_41": { vi: "Tháp và Sáu Cốc: ký ức về một thời bình yên trở thành neo đậu khi mọi thứ sụp đổ — hãy để quá khứ lành mạnh đó làm nền tảng, không phải làm nơi để trốn tránh.", en: "The Tower and Six of Cups: memories of a peaceful time become an anchor when everything collapses — let that wholesome past be a foundation, not a place to hide." },
  "16_42": { vi: "Tháp và Bảy Cốc: ảo tưởng bị phá tan bởi thực tại khắc nghiệt — sự sụp đổ này thực ra là ân huệ, vì nó buộc bạn nhìn thấy điều thật thay vì ôm những giấc mơ không bao giờ thành.", en: "The Tower and Seven of Cups: illusions are shattered by harsh reality — this collapse is actually a mercy, forcing you to see what is real instead of clinging to dreams that could never materialise." },
  "16_43": { vi: "Tháp và Tám Cốc: cái mà bạn định dần dần rời bỏ bị cướp đi đột ngột — đôi khi vũ trụ đẩy nhanh một cuộc chia tay mà bạn đã trì hoãn quá lâu.", en: "The Tower and Eight of Cups: what you planned to leave gradually is taken suddenly — sometimes the universe accelerates a departure you have been postponing far too long." },
  "16_44": { vi: "Tháp và Chín Cốc: sự hài lòng bề ngoài vỡ tan cùng với tòa tháp — nhưng điều xuất hiện từ đống đổ nát là một niềm vui sâu sắc hơn, không cần bất kỳ màn trình diễn nào.", en: "The Tower and Nine of Cups: surface contentment shatters with the tower — but what emerges from the rubble is a deeper joy that requires no performance." },
  "16_45": { vi: "Tháp và Mười Cốc: bức tranh gia đình hoàn hảo đột ngột vỡ — và chỉ khi ảo tưởng tan đi, tình yêu thực sự mới có thể đứng trên đôi chân của chính nó.", en: "The Tower and Ten of Cups: the perfect family picture suddenly shatters — and only when the illusion dissolves can genuine love stand on its own feet." },

  // Star (17) × Cups 36–45
  "17_36": { vi: "Ngôi Sao và Át Cốc: sau bão tối, một tình cảm thuần khiết và tươi mới đến như sương mai — hãy đón nhận nó với đôi tay rộng mở, vì hy vọng và tình yêu cùng xuất hiện một lúc.", en: "The Star and Ace of Cups: after the dark storm, a pure and fresh emotion arrives like morning dew — receive it with open hands, for hope and love are arriving together." },
  "17_37": { vi: "Ngôi Sao và Hai Cốc: hai tâm hồn gặp nhau dưới ánh sao chỉ đường — đây là kết nối được nuôi dưỡng bằng sự chữa lành lẫn nhau, không phải nhu cầu hay nỗi sợ.", en: "The Star and Two of Cups: two souls meet beneath the guiding star — this is a bond nourished by mutual healing rather than need or fear." },
  "17_38": { vi: "Ngôi Sao và Ba Cốc: niềm vui chung được chia sẻ dưới bầu trời đầy hy vọng — hãy ăn mừng không chỉ thành tựu mà còn sự phục hồi sau những gì đã thử thách các bạn.", en: "The Star and Three of Cups: shared joy beneath a sky full of hope — celebrate not only achievement but also the recovery from what has tested you." },
  "17_39": { vi: "Ngôi Sao và Bốn Cốc: ánh sao chiếu vào sự chán nản, nhắc nhở rằng những món quà luôn có mặt dù bạn không nhìn thấy — hãy mở mắt ra trước khi ánh sáng tắt.", en: "The Star and Four of Cups: starlight falls on your disillusionment, reminding you that gifts are always present even when unseen — open your eyes before the light fades." },
  "17_40": { vi: "Ngôi Sao và Năm Cốc: ngôi sao hy vọng không xóa đau buồn mà chiếu sáng con đường tiếp tục — hãy để nước mắt rơi xuống và sau đó nhìn lên bầu trời phía trước.", en: "The Star and Five of Cups: the star of hope does not erase grief but illuminates the path forward — let the tears fall and then look up at the sky ahead." },
  "17_41": { vi: "Ngôi Sao và Sáu Cốc: hồi tưởng về những khoảnh khắc thuần khiết trong quá khứ như ánh sao dẫn đường — nhưng hãy mang sự ngây thơ đó vào hiện tại thay vì sống mãi trong hoài niệm.", en: "The Star and Six of Cups: reflecting on pure moments from the past as starlight guiding you — but bring that innocence into the present rather than living forever in nostalgia." },
  "17_42": { vi: "Ngôi Sao và Bảy Cốc: giữa vô vàn khả năng mơ hồ, ngôi sao chỉ một hướng rõ ràng — hãy tin vào ước mơ sâu nhất của bạn và để nó dẫn đường qua những ảo tưởng còn lại.", en: "The Star and Seven of Cups: among countless vague possibilities, the star points one clear direction — trust your deepest dream and let it guide you through the remaining illusions." },
  "17_43": { vi: "Ngôi Sao và Tám Cốc: sự ra đi này không phải từ bỏ — ánh sao phía trước đang gọi bạn về phía điều thật sự xứng đáng, và bước chân đầu tiên bao giờ cũng là khó nhất.", en: "The Star and Eight of Cups: this departure is not abandonment — the star ahead is calling you toward what is truly worthy, and the first step is always the hardest." },
  "17_44": { vi: "Ngôi Sao và Chín Cốc: điều ước trở thành hiện thực khi bạn tin tưởng đủ lâu để chờ đợi — sự thoả mãn này là phần thưởng xứng đáng cho ai đã không từ bỏ hy vọng.", en: "The Star and Nine of Cups: the wish becomes real when you trust long enough to wait — this contentment is the rightful reward for those who did not give up on hope." },
  "17_45": { vi: "Ngôi Sao và Mười Cốc: hy vọng và tình yêu cùng nhau tạo nên hạnh phúc gia đình đích thực — đây không phải may mắn mà là kết quả của việc không ngừng tin vào điều tốt đẹp.", en: "The Star and Ten of Cups: hope and love together create genuine family happiness — this is not luck but the fruit of never ceasing to believe in what is good." },

  // Moon (18) × Cups 36–45
  "18_36": { vi: "Mặt Trăng và Át Cốc: một cảm xúc mới nảy sinh từ vùng vô thức sâu thẳm — hãy đón nhận nó mà không vội phán xét, vì nước dưới ánh trăng luôn ẩn chứa nhiều hơn mặt phẳng của nó.", en: "The Moon and Ace of Cups: a new emotion rises from the deep unconscious — receive it without rushing to judge, for water under moonlight always holds more than its surface." },
  "18_37": { vi: "Mặt Trăng và Hai Cốc: mối quan hệ này có những lớp ẩn dưới bề mặt — hãy kiên nhẫn khám phá thay vì vội kết luận, vì ánh trăng không bao giờ chiếu sáng tất cả cùng một lúc.", en: "The Moon and Two of Cups: this relationship has layers beneath the surface — be patient in exploring rather than rushing to conclusions, for moonlight never illuminates everything at once." },
  "18_38": { vi: "Mặt Trăng và Ba Cốc: niềm vui chia sẻ có những dòng chảy ngầm — hãy chắc chắn rằng lễ kỷ niệm này dựa trên sự thật chứ không phải ảo tưởng tập thể.", en: "The Moon and Three of Cups: shared joy has undercurrents — make certain this celebration is rooted in truth rather than collective illusion." },
  "18_39": { vi: "Mặt Trăng và Bốn Cốc: sự thờ ơ của bạn có thể đến từ những nỗi sợ không được thừa nhận ẩn dưới ánh trăng — hãy khám phá vùng bóng tối bên trong trước khi kết luận rằng bạn thật sự không muốn gì.", en: "The Moon and Four of Cups: your apathy may come from unacknowledged fears lurking beneath the moonlight — explore the shadow within before concluding you truly desire nothing." },
  "18_40": { vi: "Mặt Trăng và Năm Cốc: nỗi đau buồn này có những chiều sâu mà bạn chưa khám phá — ánh trăng chiếu xuống những gì còn lại, nhắc rằng mất mát và còn lại đều cần được nhìn nhận đầy đủ.", en: "The Moon and Five of Cups: this grief has depths you have not yet explored — moonlight falls on what remains, reminding you that both loss and what is left must be fully seen." },
  "18_41": { vi: "Mặt Trăng và Sáu Cốc: ký ức trong ánh trăng trở nên lung linh hơn thực tế — hãy phân biệt giữa những gì thực sự xảy ra và những gì trí nhớ đã tô vẽ lại theo mong muốn.", en: "The Moon and Six of Cups: memories by moonlight become more luminous than reality — distinguish between what truly happened and what memory has repainted according to longing." },
  "18_42": { vi: "Mặt Trăng và Bảy Cốc: ảo tưởng chồng chất ảo tưởng dưới ánh trăng — bạn không thể chọn đúng con đường khi cả bản đồ lẫn la bàn đều bị sương mù che phủ.", en: "The Moon and Seven of Cups: illusion upon illusion under moonlight — you cannot choose the right path when both the map and compass are obscured by fog." },
  "18_43": { vi: "Mặt Trăng và Tám Cốc: cuộc hành trình rời bỏ này diễn ra trong bóng tối — bạn không thể thấy rõ điểm đến, nhưng bước chân vẫn cần tiếp tục vì ở lại còn mờ mịt hơn.", en: "The Moon and Eight of Cups: this departing journey happens in darkness — you cannot clearly see the destination, but the steps must continue because staying is even more obscure." },
  "18_44": { vi: "Mặt Trăng và Chín Cốc: điều ước đã được đáp ứng, nhưng ánh trăng nhắc nhở rằng hạnh phúc có những tầng lớp sâu hơn cần được khám phá — đừng dừng lại ở bề mặt.", en: "The Moon and Nine of Cups: the wish has been granted, but moonlight reminds you that happiness has deeper layers yet to explore — do not stop at the surface." },
  "18_45": { vi: "Mặt Trăng và Mười Cốc: hạnh phúc gia đình này được bao phủ bởi ánh trăng huyền ảo — hãy đảm bảo rằng nền tảng của nó là thực, không phải là một giấc mơ chung mà ai cũng sợ phá vỡ.", en: "The Moon and Ten of Cups: this family happiness is veiled by mysterious moonlight — ensure its foundation is real and not a shared dream everyone is too afraid to question." },

  // Sun (19) × Cups 36–45
  "19_36": { vi: "Mặt Trời và Át Cốc: ánh sáng rực rỡ chiếu vào tình cảm thuần khiết mới nảy sinh — đây là khoảnh khắc của niềm vui và tình yêu không bị che khuất bởi bất kỳ bóng tối nào.", en: "The Sun and Ace of Cups: brilliant light pours into a pure newly rising emotion — this is a moment of joy and love unobscured by any shadow." },
  "19_37": { vi: "Mặt Trời và Hai Cốc: mối quan hệ này nở rộ dưới ánh mặt trời — sự rõ ràng và niềm vui cùng nhau làm cho kết nối này trở thành một trong những điều quý giá nhất trong cuộc sống.", en: "The Sun and Two of Cups: this relationship blossoms under full sunlight — clarity and joy together make this bond one of the most precious things in your life." },
  "19_38": { vi: "Mặt Trời và Ba Cốc: lễ kỷ niệm tràn đầy ánh sáng và sự chân thật — đây là niềm vui được chia sẻ không cần che giấu bất cứ điều gì, và đó là loại hạnh phúc hiếm nhất.", en: "The Sun and Three of Cups: celebration filled with light and authenticity — this is shared joy that needs to hide nothing, and that is the rarest kind of happiness." },
  "19_39": { vi: "Mặt Trời và Bốn Cốc: ánh mặt trời đánh thức bạn khỏi cơn thờ ơ — hãy nhìn vào những gì đang bày ra trước mắt trong ánh sáng ban ngày, vì bạn sẽ ngạc nhiên với những gì mình đang bỏ lỡ.", en: "The Sun and Four of Cups: sunlight awakens you from apathy — look at what is laid out before you in the daylight, for you will be surprised by what you have been missing." },
  "19_40": { vi: "Mặt Trời và Năm Cốc: ánh sáng không xóa nỗi đau mà chiếu sáng con đường phía trước — hãy nhìn nhận mất mát trong sự rõ ràng của ban ngày và sau đó chọn bước tiếp theo.", en: "The Sun and Five of Cups: light does not erase grief but illuminates the path forward — acknowledge loss in the clarity of daylight and then choose your next step." },
  "19_41": { vi: "Mặt Trời và Sáu Cốc: ký ức tuổi thơ được chiếu sáng bởi mặt trời — mang sự ngây thơ và niềm vui thuần khiết đó vào hiện tại thay vì để chúng chỉ là những tấm ảnh cũ.", en: "The Sun and Six of Cups: childhood memories illuminated by sunlight — bring that innocence and pure joy into the present rather than letting them remain only old photographs." },
  "19_42": { vi: "Mặt Trời và Bảy Cốc: ánh sáng mặt trời đốt cháy màn sương ảo tưởng — trong sự rõ ràng này, bạn có thể thấy đâu là mơ ước thực và đâu chỉ là bong bóng xà phòng lấp lánh.", en: "The Sun and Seven of Cups: sunlight burns away the veil of illusion — in this clarity you can see which dreams are real and which are merely glistening soap bubbles." },
  "19_43": { vi: "Mặt Trời và Tám Cốc: bạn rời đi không phải trong bóng tối mà dưới ánh sáng ban ngày — sự ra đi rõ ràng và có chủ đích này là dấu hiệu của sức mạnh chứ không phải thất bại.", en: "The Sun and Eight of Cups: you depart not in darkness but in full daylight — this clear and intentional leaving is a sign of strength rather than defeat." },
  "19_44": { vi: "Mặt Trời và Chín Cốc: điều ước được đáp ứng trong ánh sáng đầy đủ — đây là niềm vui không cần che giấu, không cần biện hộ, không cần ai đó xác nhận rằng bạn xứng đáng.", en: "The Sun and Nine of Cups: the wish granted in full light — this is joy that needs no concealment, no justification, no one else confirming you deserve it." },
  "19_45": { vi: "Mặt Trời và Mười Cốc: cầu vồng và ánh nắng gặp nhau trong bức tranh hạnh phúc hoàn chỉnh nhất — đây là kết quả của tình yêu thật sự, niềm tin kiên định và ngôi nhà được xây bằng ánh sáng.", en: "The Sun and Ten of Cups: rainbow and sunlight meet in the most complete picture of happiness — this is the fruit of genuine love, steadfast faith, and a home built from light." },

  // Judgement (20) × Cups 36–45
  "20_36": { vi: "Phán Quyết và Át Cốc: kèn gọi tâm hồn thức dậy, và tình cảm thuần khiết nhất xuất hiện — đây là thời điểm để mở rộng trái tim đón nhận điều bạn đã đủ dũng cảm để chọn.", en: "Judgement and Ace of Cups: the trumpet calls the soul to awaken, and the purest emotion emerges — this is the moment to open the heart and receive what you have finally been brave enough to choose." },
  "20_37": { vi: "Phán Quyết và Hai Cốc: mối quan hệ này được gọi lên để xem xét lại — không phải để phán xét mà để thừa nhận rõ ràng điều gì thật sự có giá trị và điều gì cần được buông bỏ.", en: "Judgement and Two of Cups: this relationship is called up for review — not to judge but to clearly acknowledge what is truly valuable and what needs to be released." },
  "20_38": { vi: "Phán Quyết và Ba Cốc: cộng đồng này được triệu hồi để thừa nhận một hành trình đã qua — hãy cùng nhau nhìn lại những gì đã xây dựng và cảm ơn nhau trước khi bước sang chương mới.", en: "Judgement and Three of Cups: this community is summoned to acknowledge a journey completed — look back together at what has been built and thank one another before stepping into the new chapter." },
  "20_39": { vi: "Phán Quyết và Bốn Cốc: tiếng kèn đánh thức bạn khỏi sự thờ ơ — đây là lúc để ngừng ngồi chờ và đứng dậy nhận lấy phần của mình trong cuộc sống đang mời gọi bạn.", en: "Judgement and Four of Cups: the trumpet shakes you from apathy — it is time to stop waiting and stand up to claim your share of the life that is calling you." },
  "20_40": { vi: "Phán Quyết và Năm Cốc: tiếng gọi thức tỉnh đến trong khoảnh khắc đau buồn sâu nhất — đây không phải thêm mất mát mà là lời mời để chuyển hóa đau thương thành sự hiểu biết sâu sắc hơn.", en: "Judgement and Five of Cups: the awakening call arrives in your deepest moment of grief — this is not more loss but an invitation to transform sorrow into deeper understanding." },
  "20_41": { vi: "Phán Quyết và Sáu Cốc: quá khứ được gọi lên không để sống lại mà để hòa giải — hãy nhìn nhận những gì đã qua với lòng từ bi, tha thứ những gì cần tha thứ và mang bài học vào tương lai.", en: "Judgement and Six of Cups: the past is called up not to be relived but to be reconciled — look at what has passed with compassion, forgive what needs forgiving, and carry the lesson forward." },
  "20_42": { vi: "Phán Quyết và Bảy Cốc: giữa vô vàn lựa chọn, tiếng gọi thức tỉnh yêu cầu bạn chọn điều thật — không còn thời gian cho ảo tưởng khi cuộc sống đang gọi bạn về phía điều thật sự có ý nghĩa.", en: "Judgement and Seven of Cups: amid countless choices, the awakening call demands you choose what is real — there is no longer time for illusion when life is calling you toward what truly matters." },
  "20_43": { vi: "Phán Quyết và Tám Cốc: cuộc ra đi này không phải bỏ trốn mà là sự hồi sinh — bạn đang rời bỏ phiên bản cũ của chính mình để đáp lời triệu hồi của một cuộc sống thật sự.", en: "Judgement and Eight of Cups: this departure is not escape but resurrection — you are leaving the old version of yourself to answer the summons of a truly lived life." },
  "20_44": { vi: "Phán Quyết và Chín Cốc: điều ước đã thành hiện thực và tiếng kèn vang lên để thừa nhận — đây là kết quả của sự trưởng thành và chọn lựa đúng đắn, xứng đáng được ăn mừng đầy đủ.", en: "Judgement and Nine of Cups: the wish has come true and the trumpet sounds in acknowledgement — this is the fruit of growth and right choice, worthy of full celebration." },
  "20_45": { vi: "Phán Quyết và Mười Cốc: gia đình và cộng đồng được triệu hồi để thừa nhận điều tốt đẹp đã được tạo ra — đây là di sản của tình yêu và sự cam kết, xứng đáng được ghi nhớ mãi mãi.", en: "Judgement and Ten of Cups: family and community are summoned to acknowledge the good that has been created — this is the legacy of love and commitment, worthy of being remembered always." },

  // World (21) × Cups 36–45
  "21_36": { vi: "Thế Giới và Át Cốc: sự hoàn thành một chu kỳ mở ra không gian cho tình cảm mới thuần khiết — đây là phần thưởng của người đã đi trọn vẹn con đường và giờ đây đứng trước ngưỡng cửa của tình yêu.", en: "The World and Ace of Cups: completing one cycle opens space for a pure new emotion — this is the reward of one who has walked the path fully and now stands at the threshold of love." },
  "21_37": { vi: "Thế Giới và Hai Cốc: mối kết nối này đạt đến một sự hoàn chỉnh hiếm có — hai người cùng nhau đã đi qua đủ thử thách để trân trọng điều họ đang có trong tay.", en: "The World and Two of Cups: this bond reaches a rare wholeness — two people who have walked through enough together to truly value what they hold in their hands." },
  "21_38": { vi: "Thế Giới và Ba Cốc: cộng đồng ăn mừng sự hoàn thành một hành trình lớn — đây là lúc để chia sẻ thành tựu với những người đã đồng hành và biết ơn mỗi bước đường đã qua.", en: "The World and Three of Cups: the community celebrates the completion of a great journey — this is the time to share achievement with those who walked alongside and to be grateful for every step taken." },
  "21_39": { vi: "Thế Giới và Bốn Cốc: sự hoàn chỉnh của một chu kỳ nhắc nhở bạn nhìn lại những gì bạn đã từng mơ — hãy đánh giá lại những điều hiện có trước khi kết luận rằng bạn cần điều gì khác.", en: "The World and Four of Cups: the wholeness of a completed cycle invites you to look back at what you once dreamed — re-evaluate what you currently have before concluding you need something different." },
  "21_40": { vi: "Thế Giới và Năm Cốc: ngay cả trong sự hoàn chỉnh, vẫn có những mất mát đã xảy ra — hãy mang chúng vào vị trí xứng đáng trong câu chuyện của bạn, không phải để đau buồn mà để trân trọng đầy đủ.", en: "The World and Five of Cups: even in wholeness, there are losses that have occurred — place them in their rightful position in your story, not to grieve but to appreciate fully." },
  "21_41": { vi: "Thế Giới và Sáu Cốc: chu kỳ hoàn thành kết nối bạn với những kỷ niệm đẹp nhất — đây là khoảnh khắc để nhận ra rằng những giá trị cốt lõi từ thời thơ ấu vẫn hiện diện trong con người bạn hôm nay.", en: "The World and Six of Cups: the completed cycle connects you to your most beautiful memories — this is the moment to recognise that the core values from childhood are still present in who you are today." },
  "21_42": { vi: "Thế Giới và Bảy Cốc: khi chu kỳ hoàn thành, tất cả ảo tưởng cũng tan đi — bạn đứng trên đôi chân vững chắc và có thể thấy rõ ràng hơn bao giờ hết đâu là điều thật.", en: "The World and Seven of Cups: as the cycle completes, all illusions dissolve — you stand on firm ground and can see more clearly than ever before which things are real." },
  "21_43": { vi: "Thế Giới và Tám Cốc: bạn không còn phải rời bỏ một mình trong bóng tối — chu kỳ đã hoàn thành và cuộc hành trình mới bắt đầu trong ánh sáng của sự hiểu biết đầy đủ.", en: "The World and Eight of Cups: you no longer have to depart alone in darkness — the cycle is complete and the new journey begins in the light of full understanding." },
  "21_44": { vi: "Thế Giới và Chín Cốc: sự hoàn chỉnh và điều ước thành hiện thực gặp nhau — đây là đỉnh cao của hành trình tâm hồn, nơi bạn nhận ra rằng bạn đã luôn có những gì mình cần.", en: "The World and Nine of Cups: wholeness and wish-fulfilment meet — this is the summit of the soul's journey, where you realise you have always held within you everything you needed." },
  "21_45": { vi: "Thế Giới và Mười Cốc: hành trình hoàn chỉnh dẫn đến hạnh phúc gia đình đích thực — đây là đích đến mà mọi thử thách, mọi hy vọng và mọi tình yêu đã hướng đến từ đầu.", en: "The World and Ten of Cups: the completed journey leads to genuine family happiness — this is the destination toward which every trial, every hope, and every love has always been pointing." },

  // ─── TIER 3c: Major × Swords Numbered (220 pairs) ───────────────────────────
  // Fool (0) × Swords 50–59
  "0_50": { vi: "Kẻ Ngốc và Át Kiếm: bước đầu tiên được cắt đứt bởi sự sáng suốt tuyệt đối — hãy để trực giác ngây thơ kết hợp với tư duy sắc bén để mở đường cho điều chưa từng thử.", en: "The Fool and Ace of Swords: the first step is cut clear by absolute clarity — let naive intuition combine with sharp thinking to open the way toward what has never been tried." },
  "0_51": { vi: "Kẻ Ngốc và Hai Kiếm: bước vào thế giới mới nhưng từ chối chọn hướng đi — sự ngây thơ không thể thay thế quyết định, và đứng mãi ở ngưỡng cửa cũng là một cách bỏ lỡ.", en: "The Fool and Two of Swords: stepping into a new world but refusing to choose a direction — innocence cannot substitute for decision, and standing forever at the threshold is its own kind of missing out." },
  "0_52": { vi: "Kẻ Ngốc và Ba Kiếm: sự thật đau đớn xuất hiện ngay trên con đường mới — đây không phải dấu hiệu để quay lại mà là bài học đầu tiên mà bất kỳ hành trình thực sự nào cũng phải trải qua.", en: "The Fool and Three of Swords: a painful truth arrives on the new path — this is not a signal to turn back but the first lesson that any genuine journey must pass through." },
  "0_53": { vi: "Kẻ Ngốc và Bốn Kiếm: trước khi bước đi, hãy nghỉ ngơi — năng lượng ngây thơ cần được nạp đầy bằng sự tĩnh lặng để hành trình phía trước không bị vắt cạn ngay từ bước đầu.", en: "The Fool and Four of Swords: before setting out, rest — naive energy needs to be replenished by stillness so the journey ahead is not exhausted from the very first step." },
  "0_54": { vi: "Kẻ Ngốc và Năm Kiếm: cuộc xung đột đầu tiên dạy rằng không phải trận chiến nào cũng đáng thắng — hãy học bài học này sớm trước khi thói quen chiếm đoạt làm hỏng những gì đến sau.", en: "The Fool and Five of Swords: the first conflict teaches that not every battle is worth winning — learn this lesson early before the habit of taking becomes corrosive to what comes next." },
  "0_55": { vi: "Kẻ Ngốc và Sáu Kiếm: hành trình rời khỏi vùng hỗn loạn về phía bình yên bắt đầu bằng một bước liều lĩnh — sự ngây thơ giúp bạn lên thuyền dù chưa biết bến đến.", en: "The Fool and Six of Swords: the journey away from chaos toward calm begins with a bold step — innocence helps you board the boat even without knowing the destination." },
  "0_56": { vi: "Kẻ Ngốc và Bảy Kiếm: sự ngây thơ có thể biến thành mồi ngon cho những ai mưu mô — hãy cẩn thận với những người đang lấy nhiều hơn những gì họ cho thấy trên bước đường đầu đời.", en: "The Fool and Seven of Swords: innocence can become easy prey for those who scheme — be wary of those taking more than they show on this first stretch of the path." },
  "0_57": { vi: "Kẻ Ngốc và Tám Kiếm: những giới hạn trong tâm trí ngăn bạn bước đi dù không có rào cản thực sự — hãy nhớ rằng con người không biết mình không thể bay thường bay được xa nhất.", en: "The Fool and Eight of Swords: mental limits stop you from walking when no real barrier exists — remember that those who do not know they cannot fly often soar the furthest." },
  "0_58": { vi: "Kẻ Ngốc và Chín Kiếm: lo âu trong đêm tối trước một bước nhảy chưa biết kết quả — nhưng hãy nhớ rằng hầu hết những điều ta sợ không bao giờ xảy ra theo cách ta tưởng tượng.", en: "The Fool and Nine of Swords: anxiety in the dark before an unknown leap — but remember that most things we fear never arrive in the form we imagine." },
  "0_59": { vi: "Kẻ Ngốc và Mười Kiếm: kết thúc hoàn toàn dọn đường cho bước đi đầu tiên — không có gì cần mang theo từ những gì đã sụp đổ, và đó chính là điều giải phóng bạn để bắt đầu lại.", en: "The Fool and Ten of Swords: complete ending clears the way for the first step — nothing needs to be carried from what has collapsed, and that is precisely what frees you to begin again." },

  // Magician (1) × Swords 50–59
  "1_50": { vi: "Pháp Sư và Át Kiếm: sức mạnh và sự sáng suốt kết hợp thành ý chí không gì cản được — đây là khoảnh khắc bạn biết chính xác điều mình muốn và có đủ công cụ để đạt được nó.", en: "The Magician and Ace of Swords: power and clarity combine into unstoppable will — this is the moment you know exactly what you want and possess every tool needed to achieve it." },
  "1_51": { vi: "Pháp Sư và Hai Kiếm: tài năng bị đình trệ bởi sự do dự — mọi công cụ đang ở trong tay nhưng lưỡi kiếm vẫn chưa chọn hướng, và năng lực không dùng đến cũng như không có.", en: "The Magician and Two of Swords: talent stalled by hesitation — every tool is in hand but the blade has not chosen direction, and unused ability is the same as having none." },
  "1_52": { vi: "Pháp Sư và Ba Kiếm: sự thành thạo không bảo vệ bạn khỏi đau thương — đây là lúc kỹ năng gặp thử thách của con tim và bạn phải học cách hàn gắn không chỉ sửa chữa.", en: "The Magician and Three of Swords: mastery does not shield you from heartbreak — this is where skill meets the trial of the heart and you must learn to heal, not merely repair." },
  "1_53": { vi: "Pháp Sư và Bốn Kiếm: người thành thạo biết khi nào cần nghỉ ngơi — việc buông xuống công cụ trong chốc lát không phải thất bại mà là cách nạp lại sức mạnh để tiếp tục sắc bén hơn.", en: "The Magician and Four of Swords: the master knows when to rest — setting down the tools for a moment is not defeat but the way to recharge for sharper work ahead." },
  "1_54": { vi: "Pháp Sư và Năm Kiếm: chiến thắng bằng trí tuệ nhưng đánh mất lòng tin — hãy kiểm tra liệu cái giá của chiến thắng này có xứng đáng với những gì bạn đã hy sinh để đạt được nó.", en: "The Magician and Five of Swords: winning through intellect but losing trust — examine whether the price of this victory is worth what you have sacrificed to secure it." },
  "1_55": { vi: "Pháp Sư và Sáu Kiếm: kỹ năng dẫn đường qua giai đoạn chuyển tiếp — hãy dùng những gì bạn biết để điều hướng qua vùng nước yên tĩnh hơn mà không để lại những người cần bạn phía sau.", en: "The Magician and Six of Swords: skill navigates the transition — use what you know to steer through calmer waters without leaving behind those who need you." },
  "1_56": { vi: "Pháp Sư và Bảy Kiếm: trí tuệ dễ trượt sang thủ đoạn — hãy kiểm tra xem chiến thuật thông minh của bạn đang phục vụ mục tiêu đúng đắn hay đang hợp lý hóa cho sự gian lận.", en: "The Magician and Seven of Swords: intelligence easily slides toward cunning — examine whether your clever tactics serve a rightful goal or merely rationalise deception." },
  "1_57": { vi: "Pháp Sư và Tám Kiếm: năng lực bị giam cầm bởi những giới hạn tự áp đặt — bạn có mọi thứ cần thiết để thoát ra, nhưng trước tiên phải nhận ra rằng chính mình đã buộc dây trói đó.", en: "The Magician and Eight of Swords: ability imprisoned by self-imposed limits — you have everything needed to break free, but first must recognise that you yourself tied those bonds." },
  "1_58": { vi: "Pháp Sư và Chín Kiếm: lo âu ăn mòn sức mạnh và khả năng — đây là thời điểm để phân biệt giữa những mối đe dọa thực sự và những bóng ma do tâm trí tự tạo ra trong đêm tối.", en: "The Magician and Nine of Swords: anxiety erodes strength and capability — now is the time to distinguish between real threats and the phantoms the mind creates in the dark." },
  "1_59": { vi: "Pháp Sư và Mười Kiếm: sự sụp đổ hoàn toàn của một cách tiếp cận — nhưng người thành thạo biết rằng mọi công cụ vẫn còn đó, chỉ cần xây dựng lại từ một góc độ hoàn toàn mới.", en: "The Magician and Ten of Swords: the complete collapse of one approach — but the master knows every tool remains, requiring only a rebuild from an entirely new angle." },

  // High Priestess (2) × Swords 50–59
  "2_50": { vi: "Nữ Tư Tế và Át Kiếm: trực giác sâu sắc gặp sự sáng suốt sắc bén — đây là khoảnh khắc bạn biết sự thật không phải qua lý luận mà qua một cái gì đó còn rõ ràng hơn lý luận.", en: "The High Priestess and Ace of Swords: deep intuition meets sharp clarity — this is the moment you know truth not through reasoning but through something even clearer than reason." },
  "2_51": { vi: "Nữ Tư Tế và Hai Kiếm: sự cân bằng giữa hai con đường được cô giữ trong im lặng — bạn không cần phải chọn ngay; đôi khi giữ cả hai phương án trong tâm thức là cách thông thái nhất.", en: "The High Priestess and Two of Swords: the balance between two paths held in silence — you need not choose immediately; sometimes holding both options in awareness is the wisest stance." },
  "2_52": { vi: "Nữ Tư Tế và Ba Kiếm: nỗi đau ẩn sâu được giữ trong bí mật thiêng liêng — không phải mọi vết thương đều cần được nói ra, nhưng những gì không được thừa nhận sẽ âm ỉ mãi phía sau tấm màn.", en: "The High Priestess and Three of Swords: deep grief held in sacred secrecy — not every wound needs voicing, but what is not acknowledged smoulders endlessly behind the veil." },
  "2_53": { vi: "Nữ Tế Tư và Bốn Kiếm: sự tĩnh lặng thiêng liêng là ngôi nhà của trực giác — hãy rút vào trong để nghe những điều chỉ nói chuyện với bạn trong im lặng hoàn toàn.", en: "The High Priestess and Four of Swords: sacred stillness is the home of intuition — withdraw inward to hear what speaks to you only in complete silence." },
  "2_54": { vi: "Nữ Tư Tế và Năm Kiếm: cô biết cuộc chiến này không đáng — trực giác nhận ra rằng chiến thắng bằng thủ đoạn chỉ làm tổn thương chính người thắng nhiều hơn người thua.", en: "The High Priestess and Five of Swords: she knows this battle is not worth it — intuition recognises that winning through cunning damages the victor more deeply than the defeated." },
  "2_55": { vi: "Nữ Tư Tế và Sáu Kiếm: sự dịch chuyển lặng lẽ khỏi nơi không còn nuôi dưỡng bạn — không cần thông báo, không cần giải thích; trực giác biết khi nào đã đến lúc ra đi.", en: "The High Priestess and Six of Swords: a quiet departure from what no longer nourishes — no announcement needed, no explanation required; intuition knows when it is time to go." },
  "2_56": { vi: "Nữ Tư Tế và Bảy Kiếm: cô nhìn thấy qua màn sương của sự lừa dối — trực giác sâu sắc khó bị đánh lừa vì nó nhận ra những mẫu hình dưới bề mặt trước khi lý trí kịp nhận ra.", en: "The High Priestess and Seven of Swords: she sees through the veil of deception — deep intuition is hard to fool because it recognises patterns beneath the surface before reason has caught on." },
  "2_57": { vi: "Nữ Tư Tế và Tám Kiếm: chiếc băng bịt mắt là do chính cô chọn — đôi khi không muốn nhìn thấy là một cách bảo vệ bản thân trước sự thật mà tâm hồn chưa sẵn sàng đón nhận.", en: "The High Priestess and Eight of Swords: the blindfold is her own choice — sometimes not wanting to see is how the self protects against a truth the soul is not yet ready to receive." },
  "2_58": { vi: "Nữ Tư Tế và Chín Kiếm: những bí mật được giữ quá lâu biến thành ác mộng trong đêm — điều không được thừa nhận tìm cách thoát ra qua những nỗi sợ tối tăm nhất của bạn.", en: "The High Priestess and Nine of Swords: secrets held too long become nightmares — what is not acknowledged finds its way out through your darkest fears." },
  "2_59": { vi: "Nữ Tư Tế và Mười Kiếm: sự kết thúc đã được cô nhìn thấy từ lâu — và chính việc biết trước đó không làm nỗi đau bớt đi, nhưng giúp bạn đứng vững khi mọi thứ sụp đổ.", en: "The High Priestess and Ten of Swords: the ending was foreseen long ago — and knowing it in advance does not lessen the pain but helps you stand firm when everything falls." },

  // Empress (3) × Swords 50–59
  "3_50": { vi: "Hoàng Hậu và Át Kiếm: sức sáng tạo gặp sự sáng suốt — đây là khoảnh khắc khi cảm hứng và ý tưởng rõ ràng kết hợp để tạo ra điều gì đó vừa đẹp vừa có sức mạnh.", en: "The Empress and Ace of Swords: creative force meets clarity — this is the moment inspiration and sharp ideas combine to produce something both beautiful and powerful." },
  "3_51": { vi: "Hoàng Hậu và Hai Kiếm: sự phong phú bị đình trệ bởi sự do dự — vườn cây không thể nở hoa khi người chăm sóc cứ mãi đứng giữa hai lựa chọn mà không gieo hạt xuống đất.", en: "The Empress and Two of Swords: abundance stalled by indecision — the garden cannot bloom when the gardener stands between two choices and plants no seeds." },
  "3_52": { vi: "Hoàng Hậu và Ba Kiếm: đau buồn trong khu vườn của sự sống — mất mát và tổn thương có thể xảy ra ngay trong nơi phong phú nhất, và nỗi đau đó cũng xứng đáng được chăm sóc như những điều nở hoa.", en: "The Empress and Three of Swords: grief in the garden of life — loss and heartbreak can arrive even in the most abundant place, and that pain deserves as much tending as what blooms." },
  "3_53": { vi: "Hoàng Hậu và Bốn Kiếm: thiên nhiên biết cách nghỉ ngơi — hãy bắt chước sự im lặng của mùa đông, vì đất cần thời gian để phục hồi trước khi mùa xuân có thể nảy mầm.", en: "The Empress and Four of Swords: nature knows how to rest — imitate the silence of winter, for the earth needs time to recover before spring can germinate." },
  "3_54": { vi: "Hoàng Hậu và Năm Kiếm: xung đột phá vỡ sự hài hòa tự nhiên — hãy hỏi xem chiến thắng này có trồng được gì không, hay nó chỉ để lại đất khô cằn sau những gì đã đốt cháy.", en: "The Empress and Five of Swords: conflict ruptures natural harmony — ask whether this victory will grow anything, or whether it leaves only scorched earth behind." },
  "3_55": { vi: "Hoàng Hậu và Sáu Kiếm: bỏ lại vùng đất cằn cỗi để đến nơi có thể nảy sinh — sự chuyển dịch này là bản năng sinh tồn và phát triển, không phải thất bại hay đầu hàng.", en: "The Empress and Six of Swords: leaving barren ground for where growth is possible — this transition is the survival and flourishing instinct, not defeat or surrender." },
  "3_56": { vi: "Hoàng Hậu và Bảy Kiếm: có điều gì đó đang được lấy đi khỏi khu vườn mà bạn không biết — hãy kiểm tra kỹ những gì đang sinh trưởng và những gì đang biến mất dưới bóng tối.", en: "The Empress and Seven of Swords: something is being taken from the garden without your knowledge — examine closely what is growing and what is disappearing in the shadows." },
  "3_57": { vi: "Hoàng Hậu và Tám Kiếm: sức sáng tạo bị trói buộc bởi những quy tắc và giới hạn không thực sự tồn tại — hãy nhớ rằng thiên nhiên không hỏi phép trước khi nở hoa.", en: "The Empress and Eight of Swords: creative force bound by rules and limits that do not truly exist — remember that nature does not ask permission before it blooms." },
  "3_58": { vi: "Hoàng Hậu và Chín Kiếm: lo âu về sự sinh sôi, nuôi dưỡng và sáng tạo — hãy nhớ rằng mọi mùa đông đều có kết thúc và những gì bạn lo mất đi thường đang âm thầm chuẩn bị tái sinh.", en: "The Empress and Nine of Swords: anxiety about fertility, nurturing, and creation — remember that every winter ends and what you fear has been lost is often quietly preparing to be reborn." },
  "3_59": { vi: "Hoàng Hậu và Mười Kiếm: sự kết thúc đau đớn trong vùng đất từng phong phú — nhưng đất không chết mà chỉ nằm im chờ đợi; mùa tới sẽ đến và sự sống sẽ trở lại mạnh mẽ hơn.", en: "The Empress and Ten of Swords: painful ending in once-abundant ground — but earth does not die, it only lies waiting; next season will come and life will return stronger." },

  // Emperor (4) × Swords 50–59
  "4_50": { vi: "Hoàng Đế và Át Kiếm: quyền lực gặp quyết tâm sắc nét — đây là khoảnh khắc lãnh đạo thực sự khi tầm nhìn và ý chí kết hợp để thiết lập trật tự từ hỗn loạn.", en: "The Emperor and Ace of Swords: authority meets sharp resolve — this is the moment of true leadership when vision and will combine to establish order from chaos." },
  "4_51": { vi: "Hoàng Đế và Hai Kiếm: quyền lực không thể trì hoãn mãi — người cầm quyền phải chọn và chịu trách nhiệm về lựa chọn đó, vì do dự kéo dài là sự yếu đuối mang mặt nạ thận trọng.", en: "The Emperor and Two of Swords: authority cannot delay indefinitely — the one who holds power must choose and own that choice, for prolonged hesitation is weakness wearing the mask of caution." },
  "4_52": { vi: "Hoàng Đế và Ba Kiếm: cấu trúc và quyền lực bị tổn thương bởi sự mất mát — ngay cả người cai trị cũng biết đau, và chấp nhận điều đó không làm suy yếu mà làm sâu sắc hơn sự lãnh đạo.", en: "The Emperor and Three of Swords: structure and authority wounded by loss — even the ruler knows pain, and accepting that does not weaken but deepens the quality of leadership." },
  "4_53": { vi: "Hoàng Đế và Bốn Kiếm: chiến lược gia biết khi nào cần rút lui để tái tổ chức — đây không phải từ bỏ mà là tích lũy sức mạnh trước khi bước vào trận chiến tiếp theo với toàn bộ năng lực.", en: "The Emperor and Four of Swords: the strategist knows when to withdraw and reorganise — this is not retreat but the gathering of full strength before entering the next battle." },
  "4_54": { vi: "Hoàng Đế và Năm Kiếm: chiến thắng bằng sức mạnh thuần túy nhưng để lại oán hận — hãy xem xét liệu đế chế được xây bằng sự thống trị có thể tồn tại lâu hơn sự tuân thủ từ nỗi sợ.", en: "The Emperor and Five of Swords: victory through raw force but leaving resentment — consider whether an empire built through domination can outlast the obedience born of fear." },
  "4_55": { vi: "Hoàng Đế và Sáu Kiếm: lãnh đạo dẫn dắt qua thời kỳ chuyển tiếp — trách nhiệm thực sự không chỉ là ra lệnh mà là đảm bảo rằng những người bạn dẫn đầu đến được bến bờ an toàn.", en: "The Emperor and Six of Swords: the leader guides through a period of transition — true responsibility is not only commanding but ensuring those you lead arrive at a safe shore." },
  "4_56": { vi: "Hoàng Đế và Bảy Kiếm: trí tuệ chiến thuật phục vụ quyền lực — nhưng hãy kiểm tra xem chiến lược này đang phục vụ toàn bộ vương quốc hay chỉ củng cố vị trí của chính mình.", en: "The Emperor and Seven of Swords: tactical intelligence serves authority — but examine whether this strategy serves the entire kingdom or merely consolidates personal position." },
  "4_57": { vi: "Hoàng Đế và Tám Kiếm: kiểm soát trở thành cái bẫy — khi mọi thứ đều bị ràng buộc bởi quy tắc và sự kiểm soát quá chặt, chính người cai trị cũng bị giam cầm trong hệ thống mình tạo ra.", en: "The Emperor and Eight of Swords: control becomes the trap — when everything is bound by rules and excessive oversight, the ruler too becomes imprisoned by the system they created." },
  "4_58": { vi: "Hoàng Đế và Chín Kiếm: người cầm quyền bị ám ảnh bởi những quyết định đã đưa ra — đây là bóng tối của trách nhiệm lãnh đạo, và đối mặt với nó là phần không thể tránh khỏi của sự trưởng thành.", en: "The Emperor and Nine of Swords: the ruler haunted by decisions already made — this is the shadow side of leadership responsibility, and facing it is the unavoidable part of maturity." },
  "4_59": { vi: "Hoàng Đế và Mười Kiếm: sự sụp đổ hoàn toàn của một cấu trúc quyền lực — nhưng trên đống đổ nát luôn có cơ hội xây dựng lại điều gì đó bền vững và công bằng hơn.", en: "The Emperor and Ten of Swords: the complete collapse of a power structure — but within every ruin lies the opportunity to build something more durable and just." },

  // Hierophant (5) × Swords 50–59
  "5_50": { vi: "Giáo Hoàng và Át Kiếm: giáo lý truyền thống gặp sự thật mới sắc bén — đây là khoảnh khắc mà sự khôn ngoan cổ xưa phải đối mặt với ánh sáng của nhận thức chưa từng được thử thách trước đây.", en: "The Hierophant and Ace of Swords: traditional doctrine meets sharp new truth — this is the moment ancient wisdom must face the light of insight never previously challenged." },
  "5_51": { vi: "Giáo Hoàng và Hai Kiếm: truyền thống do dự ở ngưỡng cửa của sự thay đổi — không phải mọi lựa chọn đều phải ngay lập tức; đôi khi tổ chức cần thời gian để hòa giải với những gì đang đến.", en: "The Hierophant and Two of Swords: tradition hesitating at the threshold of change — not every choice must be immediate; sometimes institutions need time to reconcile with what is coming." },
  "5_52": { vi: "Giáo Hoàng và Ba Kiếm: chia ly đau đớn khỏi giáo lý hoặc cộng đồng đức tin — đây là một trong những nỗi đau sâu sắc nhất vì nó không chỉ mất đi một người mà mất đi cả một thế giới quan.", en: "The Hierophant and Three of Swords: painful break from doctrine or faith community — this is among the deepest griefs because it loses not only a person but an entire worldview." },
  "5_53": { vi: "Giáo Hoàng và Bốn Kiếm: thiền định và ẩn tu như là thực hành thiêng liêng — hãy rút vào tĩnh lặng để làm mới ý nghĩa của những gì bạn tin tưởng trước khi tiếp tục truyền đạt nó.", en: "The Hierophant and Four of Swords: meditation and retreat as sacred practice — withdraw into stillness to renew the meaning of what you believe before continuing to transmit it." },
  "5_54": { vi: "Giáo Hoàng và Năm Kiếm: xung đột về giáo lý hoặc lòng tin — chiến thắng trong cuộc tranh luận tín ngưỡng hiếm khi thực sự thuyết phục ai, vì đức tin không bao giờ bị đánh bại bằng lý luận thuần túy.", en: "The Hierophant and Five of Swords: conflict over doctrine or belief — winning a religious argument rarely truly persuades, because faith is never defeated by pure reasoning alone." },
  "5_55": { vi: "Giáo Hoàng và Sáu Kiếm: người hướng dẫn tâm linh dẫn đường qua giai đoạn chuyển tiếp — hãy cho phép truyền thống đóng vai trò là la bàn trong hành trình đến vùng đất mới.", en: "The Hierophant and Six of Swords: the spiritual guide leads through transition — allow tradition to serve as compass on the journey toward new ground." },
  "5_56": { vi: "Giáo Hoàng và Bảy Kiếm: những ý định ẩn trong tổ chức tôn giáo — hãy phân biệt giữa giáo lý thực sự phục vụ con người và những thứ được dùng để duy trì quyền lực cho một số ít người.", en: "The Hierophant and Seven of Swords: hidden agendas within religious institution — distinguish between doctrine that genuinely serves people and what is used to maintain power for a few." },
  "5_57": { vi: "Giáo Hoàng và Tám Kiếm: bị trói buộc bởi hệ thống tín ngưỡng — hãy kiểm tra liệu những giới hạn bạn đang sống theo là sự thật tinh thần hay là quy tắc do con người tạo ra và có thể thay đổi được.", en: "The Hierophant and Eight of Swords: bound by a belief system — examine whether the limits you are living within are spiritual truth or human-made rules that can be changed." },
  "5_58": { vi: "Giáo Hoàng và Chín Kiếm: khủng hoảng tâm linh trong đêm tối — khi đức tin lung lay, hãy cho phép sự nghi ngờ làm sạch những gì không còn thật sự là của bạn và tìm lại cái lõi vẫn còn vững chắc.", en: "The Hierophant and Nine of Swords: spiritual crisis in the night — when faith wavers, allow the doubt to purge what is no longer truly yours and find again the core that still holds." },
  "5_59": { vi: "Giáo Hoàng và Mười Kiếm: sự sụp đổ hoàn toàn của hệ thống tín ngưỡng cũ — đây không phải cái chết của tinh thần mà là sự kết thúc của những hình thức không còn đủ sức chứa đựng sự thật đang lớn hơn.", en: "The Hierophant and Ten of Swords: complete collapse of the old belief system — this is not the death of spirit but the ending of forms no longer large enough to contain the growing truth." },

  // Lovers (6) × Swords 50–59
  "6_50": { vi: "Người Yêu và Át Kiếm: lựa chọn được thực hiện với sự sáng suốt tuyệt đối — khi tim và trí tuệ đồng thuận hoàn toàn, quyết định này mang sức mạnh không thể lung lay.", en: "The Lovers and Ace of Swords: a choice made with absolute clarity — when heart and mind agree completely, this decision carries an unshakeable force." },
  "6_51": { vi: "Người Yêu và Hai Kiếm: bị kẹt giữa hai con đường hoặc hai tình yêu — đây là sự do dự sâu sắc nhất vì cả hai phương án đều có ý nghĩa thực sự và mỗi lựa chọn đều đồng nghĩa với mất mát.", en: "The Lovers and Two of Swords: caught between two paths or two loves — this is the deepest hesitation because both options carry genuine meaning and every choice implies loss." },
  "6_52": { vi: "Người Yêu và Ba Kiếm: nỗi đau của sự chia ly hoặc lựa chọn sai — tim bị xé đôi không phải vì yếu đuối mà vì đã yêu thương đủ sâu để cảm nhận trọn vẹn cái giá của sự mất mát.", en: "The Lovers and Three of Swords: the pain of separation or a wrong choice — a broken heart is not weakness but the mark of having loved deeply enough to feel the full cost of loss." },
  "6_53": { vi: "Người Yêu và Bốn Kiếm: bình yên sau một quyết định khó khăn — hãy cho phép mình nghỉ ngơi trong sự im lặng sau khi đã chọn, vì trái tim cần thời gian để thích nghi với những gì đã thay đổi.", en: "The Lovers and Four of Swords: peace after a difficult decision — allow yourself to rest in the quiet after choosing, for the heart needs time to adjust to what has changed." },
  "6_54": { vi: "Người Yêu và Năm Kiếm: xung đột trong tình yêu hoặc mối quan hệ — hãy hỏi xem chiến thắng trong cuộc tranh cãi này có giá trị hơn sự hòa hợp mà bạn đang đánh đổi để đạt được nó.", en: "The Lovers and Five of Swords: conflict in love or relationship — ask whether winning this argument is worth more than the harmony you are sacrificing to achieve it." },
  "6_55": { vi: "Người Yêu và Sáu Kiếm: chuyển đổi trong mối quan hệ, bước vào giai đoạn mới — hãy để sự chuyển dịch này xảy ra với lòng biết ơn về những gì đã qua và sự cởi mở với những gì đang đến.", en: "The Lovers and Six of Swords: transition in relationship, moving into a new phase — allow this shift to happen with gratitude for what has passed and openness to what is coming." },
  "6_56": { vi: "Người Yêu và Bảy Kiếm: sự không trung thực trong tình yêu — hãy kiểm tra xem sự lừa dối này là từ đối phương hay từ chính bạn, vì đôi khi ta lừa dối bản thân trước khi lừa dối người khác.", en: "The Lovers and Seven of Swords: dishonesty in love — examine whether this deception comes from the other or from yourself, for sometimes we deceive ourselves before deceiving another." },
  "6_57": { vi: "Người Yêu và Tám Kiếm: cảm thấy bị giam cầm trong mối quan hệ hoặc lựa chọn — hãy kiểm tra xem những ràng buộc này có thật không hay chúng là những câu chuyện bạn đang kể cho chính mình.", en: "The Lovers and Eight of Swords: feeling imprisoned in a relationship or choice — examine whether these bonds are real or stories you are telling yourself to avoid the fear of freedom." },
  "6_58": { vi: "Người Yêu và Chín Kiếm: lo âu về mối quan hệ hoặc quyết định quan trọng — hãy nhớ rằng nỗi sợ trong đêm tối thường phóng đại mọi thứ, và ánh sáng ban mai thường làm cho chúng nhỏ lại.", en: "The Lovers and Nine of Swords: anxiety about a relationship or important decision — remember that fears in the dark often magnify everything, and morning light tends to make them smaller." },
  "6_59": { vi: "Người Yêu và Mười Kiếm: sự kết thúc đau đớn của một tình yêu hoặc mối quan hệ — hãy để sự kết thúc này là hoàn toàn thay vì kéo dài, vì chỉ khi chấp nhận đây là điểm cuối bạn mới có thể bắt đầu chữa lành.", en: "The Lovers and Ten of Swords: the painful ending of a love or relationship — let this ending be complete rather than prolonged, for only by accepting it as the final point can you begin to heal." },

  // Chariot (7) × Swords 50–59
  "7_50": { vi: "Cỗ Xe và Át Kiếm: ý chí sắt đá gặp sự sáng suốt tuyệt vời — đây là khoảnh khắc của chiến thắng không thể nghi ngờ khi mục tiêu rõ ràng và quyết tâm không gì lay chuyển được.", en: "The Chariot and Ace of Swords: iron will meets brilliant clarity — this is the moment of undeniable victory when the goal is clear and the resolve is unshakeable." },
  "7_51": { vi: "Cỗ Xe và Hai Kiếm: đà tiến bị chặn lại bởi sự do dự — bạn không thể lao về phía trước với tốc độ tối đa khi đang nhìn sang cả hai hướng cùng một lúc; hãy chọn và sau đó tiến.", en: "The Chariot and Two of Swords: momentum halted by indecision — you cannot charge forward at full speed while looking in both directions at once; choose, and then advance." },
  "7_52": { vi: "Cỗ Xe và Ba Kiếm: chiến thắng được đánh dấu bởi nỗi đau — thành công có giá của nó, và đôi khi cái giá đó là vết thương ở tim mà không có huy chương nào có thể che lấp được.", en: "The Chariot and Three of Swords: victory marked by pain — success has its price, and sometimes that price is a wound in the heart that no medal can cover." },
  "7_53": { vi: "Cỗ Xe và Bốn Kiếm: dừng lại sau trận chiến để phục hồi — không phải người chiến thắng nào cũng tiếp tục lao đi ngay lập tức; sức mạnh thực sự biết khi nào cần dừng lại và nạp lại.", en: "The Chariot and Four of Swords: stopping after battle to recover — not every victor charges on immediately; true strength knows when to pause and replenish." },
  "7_54": { vi: "Cỗ Xe và Năm Kiếm: chinh phục bằng sức mạnh nhưng với cái giá quá cao — hãy đặt câu hỏi liệu đích đến có xứng đáng với những gì đã bị bỏ lại dọc đường khi bạn lao về phía trước.", en: "The Chariot and Five of Swords: conquest by force at too high a cost — question whether the destination was worth what was left behind on the road as you charged forward." },
  "7_55": { vi: "Cỗ Xe và Sáu Kiếm: tiến về phía trước có chủ đích qua giai đoạn chuyển tiếp — bạn không trôi dạt mà đang điều hướng, và sự khác biệt đó tạo nên tất cả.", en: "The Chariot and Six of Swords: moving purposefully forward through transition — you are not drifting but navigating, and that difference makes everything." },
  "7_56": { vi: "Cỗ Xe và Bảy Kiếm: trí tuệ chiến thuật phục vụ cuộc tiến quân — đôi khi con đường thông minh nhất không phải đường thẳng mà là con đường vòng được tính toán kỹ lưỡng.", en: "The Chariot and Seven of Swords: tactical intelligence serves the advance — sometimes the cleverest route is not the straight line but the carefully calculated detour." },
  "7_57": { vi: "Cỗ Xe và Tám Kiếm: tiến về phía trước dù bị những giới hạn tinh thần cản lại — ý chí có thể vượt qua phần lớn những trở ngại do tâm trí tạo ra, nhưng trước tiên phải nhận ra đâu là rào cản thực và đâu là ảo tưởng.", en: "The Chariot and Eight of Swords: pressing forward despite mental limitations — will can overcome most mind-made obstacles, but first requires recognising which barriers are real and which are illusion." },
  "7_58": { vi: "Cỗ Xe và Chín Kiếm: lo âu đe dọa làm chệch hướng hành trình — hãy không để những câu chuyện trong đầu lúc nửa đêm điều khiển cỗ xe của bạn; ý chí phải mạnh hơn nỗi sợ.", en: "The Chariot and Nine of Swords: anxiety threatening to derail the journey — do not let the midnight stories in your head steer the chariot; will must be stronger than fear." },
  "7_59": { vi: "Cỗ Xe và Mười Kiếm: sụp đổ hoàn toàn sau khi đẩy quá mạnh quá lâu — hãy để sự thất bại này là bài học về giới hạn chứ không phải về bản sắc, vì ngã xuống không có nghĩa là kết thúc hành trình.", en: "The Chariot and Ten of Swords: complete collapse after pushing too hard for too long — let this failure be a lesson about limits rather than identity, for falling does not mean the journey is over." },

  // Strength (8) × Swords 50–59
  "8_50": { vi: "Sức Mạnh và Át Kiếm: lòng dũng cảm kết hợp với sự sáng suốt tuyệt vời — khi bạn biết chính xác điều mình đang đứng lên bảo vệ và không có gì có thể làm bạn lay chuyển.", en: "Strength and Ace of Swords: courage combined with brilliant clarity — when you know exactly what you are standing for and nothing can shake you from it." },
  "8_51": { vi: "Sức Mạnh và Hai Kiếm: lòng dũng cảm giúp bạn đứng trước lựa chọn khó khăn mà không hoảng loạn — sức mạnh thực sự không phải là biết câu trả lời ngay lập tức mà là có thể chịu đựng sự không chắc chắn.", en: "Strength and Two of Swords: courage lets you stand before a hard choice without panic — true strength is not knowing the answer immediately but being able to bear the uncertainty." },
  "8_52": { vi: "Sức Mạnh và Ba Kiếm: dũng cảm để đối mặt và chịu đựng nỗi đau thay vì né tránh — trái tim bị tổn thương vẫn tiếp tục đập, và đó là biểu hiện của sức mạnh sâu sắc nhất.", en: "Strength and Three of Swords: the courage to face and endure pain rather than avoid it — a wounded heart that keeps beating is the deepest expression of strength." },
  "8_53": { vi: "Sức Mạnh và Bốn Kiếm: nghỉ ngơi như là một hành động dũng cảm — không phải ai cũng đủ mạnh để đặt xuống gánh nặng và cho phép bản thân hồi phục mà không cảm thấy tội lỗi.", en: "Strength and Four of Swords: rest as an act of courage — not everyone is strong enough to put down the burden and allow themselves to recover without guilt." },
  "8_54": { vi: "Sức Mạnh và Năm Kiếm: sức mạnh thực sự biết khi nào không cần chiến đấu — lùi bước khỏi một cuộc xung đột không đáng đôi khi đòi hỏi nhiều dũng cảm hơn là xông vào.", en: "Strength and Five of Swords: true strength knows when not to fight — stepping back from a worthless conflict sometimes demands more courage than charging in." },
  "8_55": { vi: "Sức Mạnh và Sáu Kiếm: dũng cảm để rời đi và không nhìn lại — bước lên con thuyền dù không biết bờ đến đòi hỏi loại can đảm im lặng mà ít ai nhận ra.", en: "Strength and Six of Swords: the courage to leave and not look back — stepping onto the boat without knowing the destination requires a quiet kind of bravery few recognise." },
  "8_56": { vi: "Sức Mạnh và Bảy Kiếm: sức mạnh nội tâm nhìn thấu màn sương lừa dối — bạn không bị lung lay bởi những gì người khác che giấu vì bạn đã học cách đọc những gì ẩn dưới bề mặt.", en: "Strength and Seven of Swords: inner strength sees through the veil of deception — you are not shaken by what others conceal because you have learned to read what lies beneath the surface." },
  "8_57": { vi: "Sức Mạnh và Tám Kiếm: sức mạnh từ bên trong có thể phá tan những giới hạn tự áp đặt — bạn không cần ai cởi trói cho mình, vì năng lực để thoát ra luôn ở trong bạn.", en: "Strength and Eight of Swords: inner strength can shatter self-imposed limitations — you need no one to untie you, for the power to break free has always been inside you." },
  "8_58": { vi: "Sức Mạnh và Chín Kiếm: đối mặt với nỗi sợ trong đêm tối bằng sự dịu dàng thay vì sức mạnh cứng nhắc — hãy đặt tay lên ngực và nhắc nhở bản thân rằng bạn đã từng sống sót qua những đêm như thế này.", en: "Strength and Nine of Swords: facing night fears with gentleness rather than rigid force — place a hand on your chest and remind yourself you have survived nights like this before." },
  "8_59": { vi: "Sức Mạnh và Mười Kiếm: sức mạnh để đứng dậy sau thất bại hoàn toàn — ngã xuống không phải kết thúc câu chuyện của bạn, và chính ý chí bước tiếp dù kiệt sức mới là định nghĩa thực sự của sức mạnh.", en: "Strength and Ten of Swords: the strength to rise after complete defeat — falling is not the end of your story, and the will to continue even in exhaustion is the truest definition of strength." },

  // Hermit (9) × Swords 50–59
  "9_50": { vi: "Ẩn Sĩ và Át Kiếm: ánh đèn cô đơn soi rọi sự thật mà đám đông không thể nhìn thấy — sự cô tịch là điều kiện để những nhận thức sắc bén nhất xuất hiện.", en: "The Hermit and Ace of Swords: the solitary lantern illuminates truth the crowd cannot see — solitude is the condition for the sharpest insights to emerge." },
  "9_51": { vi: "Ẩn Sĩ và Hai Kiếm: người khôn ngoan biết cách ngồi với sự không chắc chắn mà không vội kết luận — đôi khi câu trả lời tốt nhất là tiếp tục ở lại với câu hỏi thêm một thời gian nữa.", en: "The Hermit and Two of Swords: the wise one knows how to sit with uncertainty without rushing to conclude — sometimes the best answer is to remain with the question a little longer." },
  "9_52": { vi: "Ẩn Sĩ và Ba Kiếm: nỗi đau được mang trong cô đơn — không phải vì không có ai lắng nghe, mà vì có những vết thương chỉ có thể được chữa lành trong sự im lặng hoàn toàn.", en: "The Hermit and Three of Swords: grief carried in solitude — not because there is no one to listen, but because some wounds can only be healed in complete silence." },
  "9_53": { vi: "Ẩn Sĩ và Bốn Kiếm: sự ẩn tu sâu sắc như là con đường chữa lành — không có gì tốt hơn cho tâm trí kiệt sức bằng sự tĩnh lặng hoàn toàn không bị gián đoạn.", en: "The Hermit and Four of Swords: deep retreat as a healing path — nothing restores an exhausted mind better than complete uninterrupted stillness." },
  "9_54": { vi: "Ẩn Sĩ và Năm Kiếm: người khôn ngoan từ chối tham gia vào những trận chiến dưới tầm của mình — không phải mọi cuộc xung đột đều xứng đáng với sự chú ý của người đã thấy quá nhiều.", en: "The Hermit and Five of Swords: the wise one refuses to engage in battles beneath their wisdom — not every conflict deserves the attention of one who has seen too much." },
  "9_55": { vi: "Ẩn Sĩ và Sáu Kiếm: hành trình lặng lẽ rời khỏi những gì đã hết ý nghĩa — không cần thông báo hay giải thích; người ẩn sĩ ra đi khi ánh đèn của mình chỉ hướng khác.", en: "The Hermit and Six of Swords: the quiet journey away from what has lost meaning — no announcement needed; the hermit departs when their lantern points another way." },
  "9_56": { vi: "Ẩn Sĩ và Bảy Kiếm: trí tuệ nhận ra những ý định ẩn trước khi chúng được tiết lộ — người đã dành nhiều thời gian quan sát con người biết cách đọc những gì ở phía sau những gì được nói ra.", en: "The Hermit and Seven of Swords: wisdom recognises hidden intentions before they are revealed — one who has spent much time observing people knows how to read what is behind what is said." },
  "9_57": { vi: "Ẩn Sĩ và Tám Kiếm: sự cô lập trở thành nhà tù — hãy phân biệt giữa sự cô đơn do chọn lựa và sự cô lập do sợ hãi, vì cả hai trông giống nhau từ bên ngoài nhưng khác nhau hoàn toàn từ bên trong.", en: "The Hermit and Eight of Swords: isolation becoming a prison — distinguish between chosen solitude and isolation born of fear, for both look alike from outside but are entirely different from within." },
  "9_58": { vi: "Ẩn Sĩ và Chín Kiếm: đêm tối của tâm hồn trong cô đơn hoàn toàn — đây là khoảng thời gian khó khăn nhất nhưng cũng là cái nôi của sự biến đổi sâu sắc nhất nếu bạn không chạy trốn khỏi nó.", en: "The Hermit and Nine of Swords: the dark night of the soul in complete solitude — this is the hardest time but also the cradle of the deepest transformation if you do not run from it." },
  "9_59": { vi: "Ẩn Sĩ và Mười Kiếm: sự kết thúc mà người khôn ngoan đã nhìn thấy từ xa — biết trước không làm giảm bớt nỗi đau, nhưng nó có nghĩa là bạn đã có thời gian chuẩn bị và tâm hồn đã sẵn sàng.", en: "The Hermit and Ten of Swords: the ending the wise one saw coming from a distance — foreknowledge does not lessen pain, but it means you had time to prepare and the soul is ready." },

  // Wheel of Fortune (10) × Swords 50–59
  "10_50": { vi: "Bánh Xe Vận Mệnh và Át Kiếm: điểm bước ngoặt được chiếu sáng bởi nhận thức sắc bén — khi vòng quay thay đổi hướng, sự rõ ràng về những gì đang xảy ra cho phép bạn tận dụng đà thay đổi.", en: "The Wheel of Fortune and Ace of Swords: the turning point illuminated by sharp insight — when the cycle changes direction, clarity about what is happening lets you harness the momentum of change." },
  "10_51": { vi: "Bánh Xe Vận Mệnh và Hai Kiếm: số phận dừng lại ở ngã tư đường — nhưng ngay cả vòng quay số phận cũng không thể đứng yên mãi, và sự do dự của bạn không ngăn được bánh xe tiếp tục quay.", en: "The Wheel of Fortune and Two of Swords: fate pausing at the crossroads — but even the wheel of destiny cannot stand still forever, and your hesitation does not stop it from turning." },
  "10_52": { vi: "Bánh Xe Vận Mệnh và Ba Kiếm: nỗi đau đến theo chu kỳ của bánh xe — đây không phải trừng phạt mà là một phần không thể tránh khỏi của chu kỳ, và sau đáy luôn có hướng đi lên.", en: "The Wheel of Fortune and Three of Swords: grief arriving on the wheel's cycle — this is not punishment but an unavoidable part of the cycle, and after the bottom there is always an upward direction." },
  "10_53": { vi: "Bánh Xe Vận Mệnh và Bốn Kiếm: khoảng dừng trong chu kỳ — hãy dùng thời gian giữa hai lần bánh xe quay để phục hồi, vì năng lượng của bạn cũng cần được nạp lại như chính vòng quay cần thời gian để tích lũy đà.", en: "The Wheel of Fortune and Four of Swords: the pause in the cycle — use the time between turns to recover, for your energy needs replenishing as much as the wheel needs time to build momentum." },
  "10_54": { vi: "Bánh Xe Vận Mệnh và Năm Kiếm: xung đột trong thời điểm chuyển tiếp — những cuộc tranh giành trong giai đoạn vòng quay thay đổi thường có kết quả khó đoán, vì chính sự thay đổi đang làm mọi thứ không ổn định.", en: "The Wheel of Fortune and Five of Swords: conflict during a moment of transition — struggles during a turning of the wheel often have unpredictable outcomes, for the change itself is making everything unstable." },
  "10_55": { vi: "Bánh Xe Vận Mệnh và Sáu Kiếm: bánh xe quay về phía vùng nước bình lặng hơn — hãy tin tưởng rằng chu kỳ này đang dẫn bạn đến nơi an toàn hơn, ngay cả khi hành trình vẫn còn gập ghềnh.", en: "The Wheel of Fortune and Six of Swords: the wheel turning toward calmer waters — trust that this cycle is carrying you toward safer ground, even when the journey is still rough." },
  "10_56": { vi: "Bánh Xe Vận Mệnh và Bảy Kiếm: những yếu tố ẩn đang định hình vòng quay — không phải mọi thứ đang diễn ra đều nằm trong tầm nhìn của bạn, và đôi khi những gì tưởng chừng ngẫu nhiên lại có bàn tay ẩn đằng sau.", en: "The Wheel of Fortune and Seven of Swords: hidden factors shaping the turn — not everything unfolding is within your field of vision, and sometimes what appears random has an unseen hand behind it." },
  "10_57": { vi: "Bánh Xe Vận Mệnh và Tám Kiếm: cảm thấy bị trói buộc khi vận mệnh đang thay đổi — hãy nhớ rằng những ràng buộc bạn cảm thấy thường ít thực hơn bạn nghĩ, và bánh xe đang quay ngay cả khi bạn không nhìn thấy nó.", en: "The Wheel of Fortune and Eight of Swords: feeling bound as fate shifts — remember that the constraints you feel are often less real than they seem, and the wheel is turning even when you cannot see it." },
  "10_58": { vi: "Bánh Xe Vận Mệnh và Chín Kiếm: lo âu về những gì vòng quay tiếp theo sẽ mang lại — hãy nhớ rằng sự lo lắng không thay đổi được chu kỳ, nhưng cách bạn chuẩn bị tinh thần sẽ định hình cách bạn trải qua nó.", en: "The Wheel of Fortune and Nine of Swords: anxiety about what the next turn will bring — remember that worry cannot change the cycle, but how you prepare mentally shapes how you will experience it." },
  "10_59": { vi: "Bánh Xe Vận Mệnh và Mười Kiếm: chạm đáy của một chu kỳ — điều quan trọng cần nhớ là đây là đáy, không phải điểm cuối; bánh xe tiếp tục quay và từ điểm thấp nhất chỉ có một hướng duy nhất.", en: "The Wheel of Fortune and Ten of Swords: reaching the bottom of a cycle — the crucial thing to remember is this is the nadir, not the end; the wheel keeps turning, and from the lowest point there is only one direction." },

  // Justice (11) × Swords 50–59
  "11_50": { vi: "Công Lý và Át Kiếm: sự thật là nền tảng của mọi phán quyết công bằng — khi cả sự thật và trí tuệ đều hiện diện, công lý không phải đoán mò mà là điều tất yếu.", en: "Justice and Ace of Swords: truth is the foundation of every fair judgment — when both truth and intellect are present, justice is not guesswork but inevitability." },
  "11_51": { vi: "Công Lý và Hai Kiếm: cân nhắc cẩn thận cả hai phía — đây là bản chất của công lý thực sự: không vội kết luận mà giữ cân bằng cho đến khi mọi bằng chứng được xem xét đầy đủ.", en: "Justice and Two of Swords: carefully weighing both sides — this is the essence of true justice: not rushing to conclusion but holding balance until all evidence is fully considered." },
  "11_52": { vi: "Công Lý và Ba Kiếm: phán quyết đúng đắn nhưng gây đau đớn — công lý không hứa hẹn sự thoải mái, chỉ hứa hẹn sự thật; và đôi khi sự thật để lại vết thương mà cần thời gian để lành.", en: "Justice and Three of Swords: a fair judgment that causes pain — justice does not promise comfort, only truth; and sometimes truth leaves wounds that need time to heal." },
  "11_53": { vi: "Công Lý và Bốn Kiếm: thời gian cân nhắc trước khi hành động — quyết định đúng đắn không bao giờ cần phải vội vàng, và sự im lặng của phòng nghị án đôi khi là phần quan trọng nhất của quá trình xét xử.", en: "Justice and Four of Swords: the time of deliberation before action — a just decision never needs to be rushed, and the silence of the deliberation chamber is sometimes the most important part of the process." },
  "11_54": { vi: "Công Lý và Năm Kiếm: chiến thắng bất công đặt câu hỏi về toàn bộ hệ thống — khi kẻ sử dụng thủ đoạn thắng, không chỉ người thua bị tổn thương mà cả nền tảng của sự tin tưởng lẫn nhau.", en: "Justice and Five of Swords: an unjust victory throws the whole system into question — when the one using cunning wins, it is not only the loser who is damaged but the foundation of mutual trust." },
  "11_55": { vi: "Công Lý và Sáu Kiếm: dịch chuyển về phía sự công bằng hơn — hành trình này không phải lúc nào cũng dễ dàng nhưng mỗi bước tiến là bước tiến thực sự, và công lý thực sự luôn đáng để đi về phía đó.", en: "Justice and Six of Swords: moving toward greater fairness — this journey is not always easy but every step forward is a real one, and true justice is always worth moving toward." },
  "11_56": { vi: "Công Lý và Bảy Kiếm: phơi bày những gì bị che giấu là một phần của công lý — sự thật không thể bị giấu mãi mãi, và những gì được che đậy sẽ phải ra ánh sáng khi đến thời điểm thích hợp.", en: "Justice and Seven of Swords: exposing what is hidden is part of justice — truth cannot be concealed forever, and what is covered will have to come to light when the moment arrives." },
  "11_57": { vi: "Công Lý và Tám Kiếm: luật pháp trói buộc cả những người thực thi nó — không ai đứng trên luật, và khi ngay cả người cầm cân cũng bị ràng buộc bởi các quy tắc, đó là dấu hiệu của hệ thống lành mạnh.", en: "Justice and Eight of Swords: the law binds even those who enforce it — no one stands above the rule, and when even the one holding the scales is bound by rules, that is the sign of a healthy system." },
  "11_58": { vi: "Công Lý và Chín Kiếm: tội lỗi và trách nhiệm trong đêm tối — lương tâm là tòa án nghiêm khắc nhất, và những gì bạn đã làm sai sẽ tìm đến bạn dù không ai khác biết.", en: "Justice and Nine of Swords: guilt and accountability in the dark — conscience is the harshest court, and what you have done wrong will find you even when no one else knows." },
  "11_59": { vi: "Công Lý và Mười Kiếm: phán quyết cuối cùng không thể kháng cáo — đây là điểm kết thúc mà tất cả các bằng chứng đều dẫn đến, và việc chấp nhận nó là bước đầu tiên để tiến về phía trước.", en: "Justice and Ten of Swords: the final verdict from which there is no appeal — this is the conclusion all evidence points to, and accepting it is the first step toward moving forward." },

  // Hanged Man (12) × Swords 50–59
  "12_50": { vi: "Người Treo Ngược và Át Kiếm: nhìn từ góc độ đảo ngược mang lại sự rõ ràng chưa từng có — những nhận thức sắc bén nhất đôi khi chỉ đến khi bạn sẵn sàng nhìn mọi thứ theo một cách hoàn toàn khác.", en: "The Hanged Man and Ace of Swords: seeing from an inverted perspective brings unprecedented clarity — the sharpest insights sometimes only arrive when you are willing to see everything in a completely different way." },
  "12_51": { vi: "Người Treo Ngược và Hai Kiếm: bị treo lơ lửng giữa hai lựa chọn mà không thể quyết định — đây có thể là một bài học về việc chấp nhận rằng không phải mọi lựa chọn đều cần phải được giải quyết ngay lập tức.", en: "The Hanged Man and Two of Swords: suspended between two choices unable to decide — this may be a lesson in accepting that not every choice needs to be resolved immediately." },
  "12_52": { vi: "Người Treo Ngược và Ba Kiếm: đau khổ tự nguyện như là con đường đến sự hiểu biết — không phải mọi nỗi đau đều cần phải được chấm dứt ngay lập tức; đôi khi việc ở lại với nó mới là điều mang lại sự chuyển hóa.", en: "The Hanged Man and Three of Swords: voluntary suffering as a path to understanding — not every pain needs to be ended immediately; sometimes staying with it is what brings transformation." },
  "12_53": { vi: "Người Treo Ngược và Bốn Kiếm: sự buông bỏ và nghỉ ngơi hoàn toàn — đây là nghệ thuật của việc không làm gì, không phải vì lười biếng mà vì bạn biết rằng sự tĩnh lặng là điều kiện để điều gì đó mới có thể xuất hiện.", en: "The Hanged Man and Four of Swords: complete surrender and rest — this is the art of doing nothing, not from laziness but from knowing that stillness is the condition for something new to emerge." },
  "12_54": { vi: "Người Treo Ngược và Năm Kiếm: từ chối chiến đấu trong khi đang treo lơ lửng — khi bạn không còn cố gắng kiểm soát mọi thứ, những cuộc xung đột nhỏ nhặt tự nhiên mất đi sức kéo đối với bạn.", en: "The Hanged Man and Five of Swords: refusing to fight while suspended — when you are no longer trying to control everything, petty conflicts naturally lose their pull on you." },
  "12_55": { vi: "Người Treo Ngược và Sáu Kiếm: nhìn thấy sự chuyển tiếp từ phía trên — từ vị trí treo ngược, bạn có thể thấy toàn bộ bức tranh của hành trình và hiểu tại sao giai đoạn này là cần thiết.", en: "The Hanged Man and Six of Swords: seeing the transition from above — from the inverted position you can see the full picture of the journey and understand why this phase is necessary." },
  "12_56": { vi: "Người Treo Ngược và Bảy Kiếm: nhìn thấu sự lừa dối từ một góc độ mới — điều mà mọi người không nhận ra là đôi khi việc đảo ngược quan điểm của bạn tiết lộ những gì bị che giấu rõ ràng hơn bất kỳ điều tra nào.", en: "The Hanged Man and Seven of Swords: seeing through deception from a new angle — what people do not realise is that sometimes inverting your perspective reveals what is hidden more clearly than any investigation." },
  "12_57": { vi: "Người Treo Ngược và Tám Kiếm: tự nguyện bị trói buộc như một bài học — hãy phân biệt giữa việc chọn ở lại trong giới hạn để học hỏi và việc bị mắc kẹt mà không biết mình có thể ra đi.", en: "The Hanged Man and Eight of Swords: voluntarily bound as a lesson — distinguish between choosing to remain within limits in order to learn and being stuck without knowing you could leave." },
  "12_58": { vi: "Người Treo Ngược và Chín Kiếm: đau khổ là cái giá của sự khôn ngoan — trong đêm tối nhất, hãy nhớ rằng bạn đã chọn ở lại với điều này vì bạn biết nó sẽ dẫn đến điều gì đó quan trọng hơn sự thoải mái.", en: "The Hanged Man and Nine of Swords: suffering as the price of wisdom — in the darkest night, remember you chose to stay with this because you knew it would lead to something more important than comfort." },
  "12_59": { vi: "Người Treo Ngược và Mười Kiếm: sự buông bỏ hoàn toàn mở đường cho sự tái sinh — khi bạn không còn bám víu vào bất cứ điều gì, ngay cả sự kết thúc cũng trở thành cánh cổng chứ không phải bức tường.", en: "The Hanged Man and Ten of Swords: complete surrender opens the way for rebirth — when you cling to nothing, even an ending becomes a gate rather than a wall." },

  // Death (13) × Swords 50–59
  "13_50": { vi: "Thần Chết và Át Kiếm: sự kết thúc mang đến sự sáng suốt mới — khi những gì cũ không còn nữa, không gian trống rỗng cho phép những nhận thức sắc bén nhất xuất hiện trong sự trong sáng hoàn toàn.", en: "Death and Ace of Swords: the ending brings new clarity — when what is old is gone, the empty space allows the sharpest insights to appear in complete freshness." },
  "13_51": { vi: "Thần Chết và Hai Kiếm: từ chối nhận ra điều phải kết thúc — việc đứng với đôi mắt nhắm trước những gì không thể tránh khỏi không ngăn cản nó xảy ra mà chỉ khiến sự kết thúc đau đớn hơn.", en: "Death and Two of Swords: refusing to acknowledge what must end — standing with eyes closed before the inevitable does not prevent it but only makes the ending more painful." },
  "13_52": { vi: "Thần Chết và Ba Kiếm: đau buồn là một phần không thể thiếu của sự biến đổi — không có cái chết biểu tượng nào mà không kèm theo nỗi đau thực sự, và việc cho phép mình đau buồn là tôn trọng những gì đã qua.", en: "Death and Three of Swords: grief is an inseparable part of transformation — no symbolic death comes without real pain, and allowing yourself to grieve is honouring what has passed." },
  "13_53": { vi: "Thần Chết và Bốn Kiếm: sự tĩnh lặng hoàn toàn của quá trình biến đổi — trong khoảng giữa cái chết và sự tái sinh, không có gì xảy ra bên ngoài nhưng tất cả đang thay đổi bên trong.", en: "Death and Four of Swords: the complete stillness of the transformation process — in the space between death and rebirth, nothing happens on the outside but everything is changing within." },
  "13_54": { vi: "Thần Chết và Năm Kiếm: xung đột phá hủy làm đẩy nhanh sự kết thúc — đôi khi một cuộc chiến bùng phát tàn phá tất cả là cách duy nhất để cái gì đó mới có thể được xây dựng từ đầu.", en: "Death and Five of Swords: destructive conflict accelerating the ending — sometimes a battle that burns everything down is the only way for something new to be built from the beginning." },
  "13_55": { vi: "Thần Chết và Sáu Kiếm: sự chuyển tiếp là sự biến đổi — hành trình từ bờ này sang bờ kia không chỉ là thay đổi địa điểm mà là sự thay đổi về bản chất của chính bạn.", en: "Death and Six of Swords: transition as transformation — the journey from one shore to another is not only a change of location but a change in your very nature." },
  "13_56": { vi: "Thần Chết và Bảy Kiếm: sự lừa dối làm chậm lại điều không thể tránh khỏi — bạn có thể trì hoãn sự kết thúc bằng cách che giấu sự thật nhưng bạn không thể hủy bỏ nó; và sự trì hoãn chỉ làm mọi thứ phức tạp hơn.", en: "Death and Seven of Swords: deception delaying the inevitable — you may postpone ending by hiding the truth but cannot cancel it; the delay only complicates everything further." },
  "13_57": { vi: "Thần Chết và Tám Kiếm: bị mắc kẹt trong những gì đã đang chết đi — bạn không thể sống đầy đủ trong cái đã hết sống, và việc buông tay khỏi điều đang kết thúc mới chính là hành động dũng cảm nhất.", en: "Death and Eight of Swords: trapped within what is already dying — you cannot live fully within what has ceased to live, and releasing what is ending is the most courageous act available." },
  "13_58": { vi: "Thần Chết và Chín Kiếm: nỗi sợ hãi về sự kết thúc — đây không phải nỗi sợ về cái chết mà là nỗi sợ về sự mất mát bản sắc, và đối mặt với nỗi sợ đó là bước đầu tiên để vượt qua nó.", en: "Death and Nine of Swords: terror about the ending — this is not fear of death but fear of losing identity, and facing that fear is the first step toward moving through it." },
  "13_59": { vi: "Thần Chết và Mười Kiếm: sự kết thúc hoàn toàn cũng là sự chuyển hóa hoàn toàn — không gì còn lại, không gì cần mang theo; và chính sự trống rỗng hoàn toàn này là nền tảng thuần khiết nhất để bắt đầu lại.", en: "Death and Ten of Swords: complete ending is also complete transformation — nothing remains, nothing needs to be carried; and this very completeness of emptiness is the purest foundation for beginning again." },

  // Temperance (14) × Swords 50–59
  "14_50": { vi: "Điều Độ và Át Kiếm: sự cân bằng mang lại sự sáng suốt trong sáng nhất — khi tâm trí không bị kéo về hai phía cực đoan, nó thấy rõ ràng hơn bất kỳ lúc nào và quyết định trở nên tự nhiên như nước chảy.", en: "Temperance and Ace of Swords: balance brings the clearest clarity — when the mind is not pulled to either extreme, it sees more clearly than at any other time and decisions flow as naturally as water." },
  "14_51": { vi: "Điều Độ và Hai Kiếm: kiên nhẫn với lựa chọn khó khăn — không phải sự bối rối mà là sự kiên nhẫn cố ý; hãy pha trộn cả hai viễn cảnh cho đến khi con đường thứ ba tự nhiên xuất hiện.", en: "Temperance and Two of Swords: patience with a difficult choice — not confusion but deliberate patience; blend both perspectives until a third way naturally appears." },
  "14_52": { vi: "Điều Độ và Ba Kiếm: tích hợp nỗi đau mà không bị nó nhấn chìm — nghệ thuật của sự chữa lành là không né tránh vết thương cũng không bị chìm đắm trong đó mà đứng ở điểm cân bằng giữa cả hai.", en: "Temperance and Three of Swords: integrating grief without being consumed — the art of healing is not avoiding the wound nor drowning in it but standing at the balance point between both." },
  "14_53": { vi: "Điều Độ và Bốn Kiếm: sự nghỉ ngơi như là linh đan chữa lành — hãy để sự tĩnh lặng pha trộn với sự chú tâm, tạo ra một trạng thái phục hồi sâu hơn bất kỳ giải pháp nhanh nào có thể mang lại.", en: "Temperance and Four of Swords: rest as the healing elixir — let stillness blend with attention, creating a state of recovery deeper than any quick fix could provide." },
  "14_54": { vi: "Điều Độ và Năm Kiếm: làm dịu xung đột bằng sự điều độ — khi mọi người bị cuốn vào trận chiến, người có khả năng làm chậm lại và pha trộn những quan điểm đối lập trở thành cầu nối hòa giải thực sự.", en: "Temperance and Five of Swords: de-escalating conflict through moderation — when everyone is swept into battle, the one able to slow down and blend opposing perspectives becomes the real bridge to reconciliation." },
  "14_55": { vi: "Điều Độ và Sáu Kiếm: dòng chảy nhẹ nhàng của sự chuyển tiếp — không có gì chuyển động mượt mà hơn khi được dẫn dắt bởi sự kiên nhẫn và sự cân bằng thay vì bởi sự vội vàng hay sợ hãi.", en: "Temperance and Six of Swords: the gentle flow of transition — nothing moves more smoothly than when guided by patience and balance rather than by urgency or fear." },
  "14_56": { vi: "Điều Độ và Bảy Kiếm: tích hợp bóng tối mà không phán xét — sự điều độ thực sự không phủ nhận những phần khuất tối của bản thân mà tìm cách đưa chúng vào cân bằng với toàn bộ con người bạn.", en: "Temperance and Seven of Swords: integrating shadow without judgment — true temperance does not deny the darker parts of the self but finds a way to bring them into balance with the whole person." },
  "14_57": { vi: "Điều Độ và Tám Kiếm: hòa tan những giới hạn tự áp đặt thông qua sự cân bằng — khi bạn không còn đẩy quá mạnh hay giữ lại quá nhiều, những ràng buộc tưởng chừng chắc chắn tự nhiên tan biến.", en: "Temperance and Eight of Swords: dissolving self-imposed limits through balance — when you no longer push too hard or hold back too much, bonds that seemed solid naturally dissolve." },
  "14_58": { vi: "Điều Độ và Chín Kiếm: tìm thấy sự bình an trong nỗi lo âu bằng cách không chống lại nó — hãy pha trộn hơi thở và nỗi sợ, để chúng cùng tồn tại cho đến khi sự cân bằng tự tìm đến.", en: "Temperance and Nine of Swords: finding peace within anxiety by not fighting it — blend your breath and your fear, let them coexist until balance finds its own way." },
  "14_59": { vi: "Điều Độ và Mười Kiếm: biến thất bại hoàn toàn thành trí tuệ — người có thể lấy những gì đã sụp đổ và pha trộn nó với khả năng phục hồi để tạo ra điều gì đó hoàn toàn mới đang thực hành điều độ ở mức cao nhất.", en: "Temperance and Ten of Swords: transmuting complete defeat into wisdom — the one who can take what has collapsed and blend it with resilience to create something entirely new is practising temperance at its highest level." },

  // Devil (15) × Swords 50–59
  "15_50": { vi: "Ác Quỷ và Át Kiếm: sự thật sắc bén là thứ duy nhất cắt đứt được xiềng xích — khi bạn nhìn thẳng vào bản chất của sự giam cầm mà không tự dối, khoảnh khắc giải phóng thực sự bắt đầu.", en: "The Devil and Ace of Swords: sharp truth is the only thing that can cut through chains — when you look directly at the nature of your bondage without self-deception, the moment of genuine liberation begins." },
  "15_51": { vi: "Ác Quỷ và Hai Kiếm: từ chối nhìn nhận sự thật về xiềng xích của mình — khi bạn đứng trước sự thật về những ràng buộc không lành mạnh với đôi mắt nhắm, bạn không phải đang nghĩ hay đang bảo vệ mình mà đang tiếp tục bị giam cầm.", en: "The Devil and Two of Swords: refusing to see the truth about one's own chains — when you stand before the truth of unhealthy bonds with eyes closed, you are not thinking or protecting yourself but continuing to be imprisoned." },
  "15_52": { vi: "Ác Quỷ và Ba Kiếm: nỗi đau là một phần của sự giam cầm — đôi khi chính nỗi đau của mối ràng buộc độc hại là thứ giữ bạn lại trong đó, vì nỗi đau quen thuộc cảm thấy an toàn hơn sự tự do xa lạ.", en: "The Devil and Three of Swords: pain as part of the bondage — sometimes it is the very pain of the toxic bond that keeps you within it, for familiar pain feels safer than unfamiliar freedom." },
  "15_53": { vi: "Ác Quỷ và Bốn Kiếm: sự nghỉ ngơi nuôi dưỡng sự trì trệ — hãy kiểm tra liệu khoảng nghỉ này đang nạp năng lượng cho bạn để thay đổi hay đang cho phép bạn tránh nhìn thẳng vào những gì cần phải đối mặt.", en: "The Devil and Four of Swords: rest feeding stagnation — examine whether this pause is recharging you for change or allowing you to avoid looking squarely at what must be faced." },
  "15_54": { vi: "Ác Quỷ và Năm Kiếm: xung đột giữa ham muốn và tự do — khi bạn muốn cả hai nhưng chúng không thể cùng tồn tại, sự chiến thắng của ham muốn luôn để lại tự do bị thương và sự chiến thắng của tự do luôn để lại ham muốn không được thỏa mãn.", en: "The Devil and Five of Swords: conflict between desire and freedom — when you want both but they cannot coexist, desire winning always leaves freedom wounded and freedom winning always leaves desire unsatisfied." },
  "15_55": { vi: "Ác Quỷ và Sáu Kiếm: thoát khỏi ràng buộc thông qua sự chuyển dịch — đôi khi cách duy nhất để thoát khỏi xiềng xích là đơn giản là đặt chúng xuống và bước lên con thuyền đi về phía trước.", en: "The Devil and Six of Swords: escaping bondage through transition — sometimes the only way to leave chains behind is simply to put them down and step onto the boat heading forward." },
  "15_56": { vi: "Ác Quỷ và Bảy Kiếm: sự lừa dối trong giao kèo với Ác Quỷ — hãy đọc kỹ những gì bạn đã đồng ý, vì những điều khoản nhỏ in chữ mờ thường là những điều đắt giá nhất bạn phải trả.", en: "The Devil and Seven of Swords: the deception within the devil's bargain — read carefully what you have agreed to, for the fine print is usually the most costly clause." },
  "15_57": { vi: "Ác Quỷ và Tám Kiếm: xiềng xích chồng xiềng xích — bị ràng buộc bởi ham muốn và sau đó bị ràng buộc thêm bởi nỗi sợ mất đi ham muốn đó là trạng thái giam cầm kép mà chỉ sự thật mới có thể phá vỡ.", en: "The Devil and Eight of Swords: chains upon chains — bound by desire and then further bound by fear of losing that desire is the double imprisonment that only truth can break." },
  "15_58": { vi: "Ác Quỷ và Chín Kiếm: đêm tối nhất của sự nghiện ngập hay ám ảnh — trong khoảnh khắc khó chịu nhất này, hãy nhớ rằng bạn vẫn đang đứng ở ngưỡng cửa của sự lựa chọn dù bạn không tin điều đó.", en: "The Devil and Nine of Swords: the darkest night of addiction or obsession — in this most unbearable moment, remember you are still standing at the threshold of choice even when you do not believe it." },
  "15_59": { vi: "Ác Quỷ và Mười Kiếm: sự sụp đổ hoàn toàn phá tan xiềng xích — đôi khi cần phải chạm đáy hoàn toàn để nhận ra rằng những gì giữ bạn lại cũng đã rơi xuống cùng bạn và không còn quyền lực gì nữa.", en: "The Devil and Ten of Swords: complete collapse shattering the chains — sometimes it takes reaching absolute bottom to realise that what was holding you has also fallen and no longer holds any power." },

  // Tower (16) × Swords 50–59
  "16_50": { vi: "Tháp và Át Kiếm: sự sụp đổ mang đến sự thật không thể phủ nhận — khi tất cả những lớp vỏ bọc tan vỡ, điều còn lại là sự sáng suốt thuần khiết và không thể che giấu được nữa.", en: "The Tower and Ace of Swords: collapse delivers undeniable truth — when all the layers of pretence shatter, what remains is pure clarity that can no longer be hidden." },
  "16_51": { vi: "Tháp và Hai Kiếm: sự sụp đổ buộc bạn phải chọn khi bạn vẫn còn đang do dự — không còn lựa chọn nào được giữ lại sau cơn lũ, và chính sự bắt buộc đó đôi khi là điều giải phóng bạn.", en: "The Tower and Two of Swords: collapse forces a choice while you were still hesitating — no option can be kept after the flood, and that very compulsion is sometimes what sets you free." },
  "16_52": { vi: "Tháp và Ba Kiếm: đau buồn chồng chất lên sự hủy diệt — nhưng hãy nhớ rằng trái tim chỉ vỡ tan khi nó đã từng chứa đựng điều gì đó thật sự, và điều đó luôn xứng đáng được trân trọng.", en: "The Tower and Three of Swords: grief heaped upon destruction — but remember a heart only shatters when it once held something real, and that will always be worth honouring." },
  "16_53": { vi: "Tháp và Bốn Kiếm: trong đống đổ nát, buộc phải nghỉ ngơi — khi mọi thứ sụp đổ xung quanh, đôi khi điều duy nhất có thể làm là nằm xuống và để thân xác và tâm trí được dừng lại.", en: "The Tower and Four of Swords: amid the rubble, forced rest — when everything collapses around you, sometimes the only thing available is to lie down and let body and mind simply stop." },
  "16_54": { vi: "Tháp và Năm Kiếm: xung đột trong thời điểm khủng hoảng đẩy nhanh sự tan vỡ — những gì đã lung lay từ lâu không cần thêm một cú đánh mạnh để sụp đổ hoàn toàn.", en: "The Tower and Five of Swords: conflict during crisis accelerating the collapse — what has been shaking for long needs no great blow to fall completely." },
  "16_55": { vi: "Tháp và Sáu Kiếm: rời khỏi đống đổ nát và bước lên thuyền — không cần phải hiểu hết mọi thứ đã xảy ra trước khi rời đi; đôi khi chỉ cần bước đi trước và hiểu sau.", en: "The Tower and Six of Swords: leaving the rubble and stepping onto the boat — you do not need to understand everything that happened before departing; sometimes step first and understand later." },
  "16_56": { vi: "Tháp và Bảy Kiếm: những bí mật bị phơi bày bởi sự sụp đổ — không có điều gì được che giấu lâu dài khi tòa nhà bảo vệ nó không còn đứng vững nữa.", en: "The Tower and Seven of Swords: secrets exposed by the collapse — nothing stays hidden for long when the building protecting it no longer stands." },
  "16_57": { vi: "Tháp và Tám Kiếm: sự sụp đổ phá tan những ràng buộc — điều trớ trêu là những xiềng xích tưởng chừng không thể tháo gỡ lại tan biến dễ dàng nhất khi nền tảng giam giữ bạn tự sụp đổ.", en: "The Tower and Eight of Swords: collapse shattering the bonds — the irony is that chains which seemed impossible to remove dissolve most easily when the very foundation imprisoning you falls." },
  "16_58": { vi: "Tháp và Chín Kiếm: kinh hoàng trong đêm tối sau cơn thảm họa — hãy để những nỗi sợ hãi đó chạy qua bạn mà không cố gắng kiểm soát chúng, vì đây là phản ứng tự nhiên và nó sẽ qua đi.", en: "The Tower and Nine of Swords: terror in the night after catastrophe — let those fears move through you without trying to control them, for this is a natural response and it will pass." },
  "16_59": { vi: "Tháp và Mười Kiếm: sự hủy diệt hoàn toàn và tuyệt đối — không còn gì sót lại, không cần giả vờ, không cần cứu vãn; và chính sự trống rỗng hoàn toàn này là điều kiện trong sáng nhất để bắt đầu lại từ đầu.", en: "The Tower and Ten of Swords: complete and total destruction — nothing remains, no pretence needed, nothing to salvage; and this very completeness of emptiness is the cleanest condition for beginning again." },

  // Star (17) × Swords 50–59
  "17_50": { vi: "Ngôi Sao và Át Kiếm: hy vọng được chiếu sáng bởi sự sáng suốt — sau bóng tối, nhận thức mới này không chỉ là ánh sáng mà còn là hướng đi rõ ràng, và bạn biết chính xác bước tiếp theo cần làm gì.", en: "The Star and Ace of Swords: hope illuminated by clarity — after the darkness, this new insight is not only light but clear direction, and you know precisely what the next step requires." },
  "17_51": { vi: "Ngôi Sao và Hai Kiếm: hy vọng giúp bạn đứng vững trước lựa chọn khó khăn — ánh sao không chọn thay bạn nhưng chiếu đủ ánh sáng để bạn thấy cả hai con đường rõ ràng hơn trước khi quyết định.", en: "The Star and Two of Swords: hope steadying you before a hard choice — starlight does not choose for you but sheds enough light to see both paths more clearly before deciding." },
  "17_52": { vi: "Ngôi Sao và Ba Kiếm: hy vọng không xóa vết thương nhưng cho thấy con đường phục hồi — ngôi sao vẫn sáng ngay cả khi tim đang đau, và sự hiện diện của nó là lời hứa hẹn rằng nỗi đau này không phải là điểm cuối.", en: "The Star and Three of Swords: hope does not erase the wound but shows the path of recovery — the star shines even while the heart aches, and its presence is a promise that this pain is not the final word." },
  "17_53": { vi: "Ngôi Sao và Bốn Kiếm: nghỉ ngơi dưới ánh sao chữa lành — đây là loại nghỉ ngơi không đơn thuần là ngủ mà là sự phục hồi sâu sắc khi bạn biết rằng hy vọng vẫn còn đó chờ bạn thức dậy.", en: "The Star and Four of Swords: resting under healing starlight — this is not mere sleep but deep restoration, knowing that hope is still there waiting when you wake." },
  "17_54": { vi: "Ngôi Sao và Năm Kiếm: hy vọng sau một cuộc chiến không đáng — ngay cả khi bạn không chắc tại sao cuộc xung đột đó xảy ra, ánh sao phía trước nhắc rằng nó không định nghĩa bạn.", en: "The Star and Five of Swords: hope after a battle not worth fighting — even when you are unsure why that conflict happened, the star ahead reminds you it does not define you." },
  "17_55": { vi: "Ngôi Sao và Sáu Kiếm: hành trình về phía hy vọng — bạn đang rời xa hỗn loạn và di chuyển về phía ánh sao; không phải đến điểm đến cuối cùng ngay lập tức mà là về phía điều tốt đẹp hơn.", en: "The Star and Six of Swords: the journey toward hope — you are moving away from turmoil and toward the star; not to the final destination immediately but toward what is better." },
  "17_56": { vi: "Ngôi Sao và Bảy Kiếm: hy vọng bảo vệ bạn khỏi sự lừa dối — khi bạn biết điều mình đang hướng đến, những cạm bẫy trên đường đi không còn quyến rũ như trước vì bạn thấy chúng rõ ràng hơn.", en: "The Star and Seven of Swords: hope protecting you from deception — when you know what you are moving toward, the traps along the way lose their appeal because you see them more clearly." },
  "17_57": { vi: "Ngôi Sao và Tám Kiếm: ánh sao có thể thắp sáng ngay cả trong phòng bị giam cầm — bạn có thể cảm thấy bị trói buộc nhưng hy vọng nhắc nhở rằng những ràng buộc này không phải là vĩnh viễn.", en: "The Star and Eight of Swords: starlight can illuminate even a room of captivity — you may feel bound but hope reminds you these bonds are not permanent." },
  "17_58": { vi: "Ngôi Sao và Chín Kiếm: ánh sao trong đêm tối lo âu — hy vọng không xóa nỗi sợ nhưng hiện diện cùng với nó, và chính sự hiện diện đó làm cho đêm tối bớt tuyệt vọng hơn một chút.", en: "The Star and Nine of Swords: starlight within the dark night of anxiety — hope does not erase fear but exists alongside it, and that very presence makes the darkness a little less absolute." },
  "17_59": { vi: "Ngôi Sao và Mười Kiếm: hy vọng xuất hiện ngay trên đống đổ nát — điều kỳ diệu không phải là tòa nhà đứng vững mà là ngôi sao vẫn chiếu sáng ngay cả khi mọi thứ đã sụp đổ hoàn toàn.", en: "The Star and Ten of Swords: hope appearing right above the ruins — the miracle is not that the tower stands but that the star still shines even after everything has completely fallen." },

  // Moon (18) × Swords 50–59
  "18_50": { vi: "Mặt Trăng và Át Kiếm: sự thật xuất hiện từ vùng tối — nhận thức này không đến từ lý trí mà từ tầng sâu của vô thức, và sức mạnh của nó nằm chính ở chỗ nó không thể bị phủ nhận.", en: "The Moon and Ace of Swords: truth surfacing from the darkness — this insight comes not from reason but from the deep unconscious layer, and its power lies in the fact that it cannot be denied." },
  "18_51": { vi: "Mặt Trăng và Hai Kiếm: không thể quyết định trong bóng tối — ánh trăng che phủ cả hai con đường một lớp sương mờ, và đôi khi đúng đắn nhất là chờ đến khi ánh sáng rõ hơn trước khi chọn.", en: "The Moon and Two of Swords: unable to decide in the darkness — moonlight veils both paths in mist, and sometimes the wisest move is to wait for clearer light before choosing." },
  "18_52": { vi: "Mặt Trăng và Ba Kiếm: nỗi đau ẩn sâu dưới ánh trăng — những vết thương không được nhìn nhận ban ngày trở nên to lớn hơn trong bóng tối, và chỉ có sự thừa nhận mới có thể bắt đầu quá trình chữa lành.", en: "The Moon and Three of Swords: pain lurking beneath the moonlight — wounds not acknowledged by day grow larger in the dark, and only recognition can begin the healing process." },
  "18_53": { vi: "Mặt Trăng và Bốn Kiếm: giấc ngủ dưới ánh trăng là nơi vô thức nói chuyện — hãy chú ý đến những gì xuất hiện trong giấc mơ vì nó thường chứa đựng những câu trả lời mà tâm trí tỉnh táo đang né tránh.", en: "The Moon and Four of Swords: sleep beneath moonlight is where the unconscious speaks — pay attention to what appears in dreams, for it often holds the answers the waking mind is avoiding." },
  "18_54": { vi: "Mặt Trăng và Năm Kiếm: xung đột trong bóng tối rất khó phân biệt thật giả — hãy cẩn thận với những cuộc chiến bắt đầu từ những hiểu lầm hoặc từ những nỗi sợ không có tên gọi rõ ràng.", en: "The Moon and Five of Swords: conflict in darkness is very hard to separate from illusion — be careful of battles arising from misunderstandings or from fears that have no clear name." },
  "18_55": { vi: "Mặt Trăng và Sáu Kiếm: vượt qua vùng nước tối trong đêm — hành trình này đòi hỏi sự tin tưởng vào cái gì đó sâu hơn lý trí vì không thể thấy rõ đích đến, chỉ có thể cảm nhận nó.", en: "The Moon and Six of Swords: crossing dark waters in the night — this journey demands trust in something deeper than reason, for the destination cannot be clearly seen, only sensed." },
  "18_56": { vi: "Mặt Trăng và Bảy Kiếm: những gì ẩn náu dưới ánh trăng — đây là lĩnh vực của sự lừa dối tinh tế nhất vì ánh sáng không đủ để phân biệt bóng tối thực sự với bóng tối của trí tưởng tượng.", en: "The Moon and Seven of Swords: what hides beneath the moonlight — this is the realm of the most subtle deception, for the light is not enough to distinguish real darkness from the darkness of imagination." },
  "18_57": { vi: "Mặt Trăng và Tám Kiếm: bị trói buộc bởi những nỗi sợ không có hình dạng rõ ràng — ánh trăng phóng đại bóng tối và những gì bạn không thể nhìn thấy rõ thường to lớn hơn những gì thực sự đang ở đó.", en: "The Moon and Eight of Swords: bound by fears with no clear shape — moonlight amplifies shadows and what you cannot see clearly is usually larger than what is actually there." },
  "18_58": { vi: "Mặt Trăng và Chín Kiếm: đây là lãnh địa của Mặt Trăng — nỗi lo âu trong đêm tối được nuôi dưỡng bởi những gì vô thức không thể xử lý ban ngày, và chỉ có sự dũng cảm để nhìn thẳng vào mới làm nó nhỏ lại.", en: "The Moon and Nine of Swords: this is the Moon's own territory — night anxiety fed by what the unconscious cannot process by day, and only the courage to look directly at it makes it smaller." },
  "18_59": { vi: "Mặt Trăng và Mười Kiếm: sự kết thúc trong bóng tối — không được thấy rõ, không được hiểu đầy đủ, nhưng vẫn hoàn toàn thực; và đôi khi những điều quan trọng nhất trong cuộc sống xảy ra trong màn đêm mà không có khán giả.", en: "The Moon and Ten of Swords: the ending in darkness — not clearly seen, not fully understood, but entirely real; and sometimes the most significant things in life happen in the night without any audience." },

  // Sun (19) × Swords 50–59
  "19_50": { vi: "Mặt Trời và Át Kiếm: ánh sáng rực rỡ và sự sáng suốt hoàn hảo gặp nhau — đây là khoảnh khắc của nhận thức hoàn toàn, khi sự thật hiện ra trong ánh ban mai và không có gì còn mơ hồ nữa.", en: "The Sun and Ace of Swords: brilliant light and perfect clarity meeting — this is the moment of complete understanding, when truth appears in the morning light and nothing remains obscure." },
  "19_51": { vi: "Mặt Trời và Hai Kiếm: ánh sáng ban ngày giúp bạn thấy cả hai lựa chọn rõ ràng hơn — quyết định khó không phải vì thiếu thông tin mà vì cả hai con đường đều có giá trị thực sự, và ánh sáng không thể chọn thay bạn.", en: "The Sun and Two of Swords: daylight helps you see both choices more clearly — a hard decision is not hard from lack of information but because both paths carry real value, and light cannot choose for you." },
  "19_52": { vi: "Mặt Trời và Ba Kiếm: vết thương được nhìn thấy trong ánh sáng đầy đủ — không thể che giấu hay giảm nhẹ nỗi đau khi mặt trời chiếu sáng tất cả, nhưng chính sự rõ ràng đó là điều kiện để chữa lành thật sự.", en: "The Sun and Three of Swords: the wound seen in full light — pain cannot be hidden or minimised when the sun illuminates everything, but that very clarity is the condition for genuine healing." },
  "19_53": { vi: "Mặt Trời và Bốn Kiếm: nghỉ ngơi trong ánh nắng ấm áp — đây là loại phục hồi tốt nhất: không phải trốn trong bóng tối mà là nằm xuống dưới ánh mặt trời và để ánh sáng làm phần việc của nó.", en: "The Sun and Four of Swords: resting in warm sunlight — this is the best kind of recovery: not hiding in darkness but lying down beneath the sun and letting the light do its part of the work." },
  "19_54": { vi: "Mặt Trời và Năm Kiếm: xung đột được chiếu sáng rõ ràng — trong ánh mặt trời, không thể che giấu ai đúng ai sai, và chính sự rõ ràng đó đôi khi kết thúc cuộc chiến nhanh hơn bất kỳ lý luận nào.", en: "The Sun and Five of Swords: conflict illuminated clearly — in full sunlight, there is no hiding who is right and who is wrong, and that clarity sometimes ends the battle faster than any argument." },
  "19_55": { vi: "Mặt Trời và Sáu Kiếm: hành trình về phía ánh sáng — bạn đang rời bỏ vùng tối và hướng đến nơi mặt trời chiếu sáng đầy đủ, và mỗi bước đi đều có thể cảm nhận được sự ấm áp ngày càng tăng.", en: "The Sun and Six of Swords: the journey toward light — you are leaving the dark zone and heading where the sun shines fully, and with each step you can feel the warmth increasing." },
  "19_56": { vi: "Mặt Trời và Bảy Kiếm: ánh sáng phơi bày những gì bị che giấu — không ai có thể ẩn náu lâu dưới ánh mặt trời, và những ý định bí mật trở nên rõ ràng hơn bao giờ hết khi ánh sáng đầy đủ chiếu rọi.", en: "The Sun and Seven of Swords: light exposing what is hidden — no one can stay concealed long beneath the sun, and hidden intentions become clearer than ever when full light shines." },
  "19_57": { vi: "Mặt Trời và Tám Kiếm: ánh sáng mặt trời phá tan những ràng buộc — rất khó để tiếp tục tin rằng mình bị giam cầm khi ánh sáng rực rỡ chiếu vào và cho thấy không có tường nào thực sự ở đây.", en: "The Sun and Eight of Swords: sunlight dissolving the bonds — it is very hard to keep believing you are imprisoned when brilliant light pours in and reveals there are no real walls here." },
  "19_58": { vi: "Mặt Trời và Chín Kiếm: ánh sáng ban mai xua tan bóng ma đêm — những nỗi sợ trong đêm tối luôn trông khác đi khi bình minh đến, và mặt trời là lời nhắc nhở rằng đêm không kéo dài mãi mãi.", en: "The Sun and Nine of Swords: morning light scattering the night's phantoms — night fears always look different when dawn arrives, and the sun is the reminder that darkness does not last forever." },
  "19_59": { vi: "Mặt Trời và Mười Kiếm: ánh sáng chiếu xuống đống đổ nát — ngay cả sau khi tất cả sụp đổ hoàn toàn, mặt trời vẫn mọc vào buổi sáng tiếp theo, và chính sự không thể ngăn cản đó là hy vọng thực sự nhất.", en: "The Sun and Ten of Swords: light falling on the ruins — even after everything has completely collapsed, the sun rises the following morning, and that very unstoppability is the most genuine hope." },

  // Judgement (20) × Swords 50–59
  "20_50": { vi: "Phán Quyết và Át Kiếm: tiếng kèn thức tỉnh mang theo sự sáng suốt tuyệt đối — đây là khoảnh khắc nhận ra sự thật về bản thân một cách rõ ràng đến mức không còn chỗ cho sự tự dối nào nữa.", en: "Judgement and Ace of Swords: the awakening trumpet carries absolute clarity — this is the moment of recognising truth about yourself so clearly that no room remains for self-deception." },
  "20_51": { vi: "Phán Quyết và Hai Kiếm: tiếng gọi thức tỉnh đến trong khi bạn vẫn còn đang do dự — sự thức tỉnh không đợi bạn sẵn sàng quyết định; đôi khi nó xuất hiện và buộc bạn phải chọn một bên.", en: "Judgement and Two of Swords: the awakening call arrives while you are still hesitating — awakening does not wait for you to be ready to decide; sometimes it simply appears and forces you to a side." },
  "20_52": { vi: "Phán Quyết và Ba Kiếm: được kêu gọi thức tỉnh giữa nỗi đau — tiếng kèn không chờ đến khi bạn đã lành lại; đôi khi sự thức tỉnh sâu sắc nhất xảy ra ngay trong khoảnh khắc vết thương còn mở.", en: "Judgement and Three of Swords: called to awaken in the midst of pain — the trumpet does not wait until you have healed; sometimes the deepest awakening happens in the very moment the wound is still open." },
  "20_53": { vi: "Phán Quyết và Bốn Kiếm: tiếng kèn thức tỉnh phá tan sự im lặng của phòng nghỉ — hành trình tiếp theo đang gọi, và dù bạn chưa hoàn toàn phục hồi, đây là lúc phải đứng dậy và đáp lời.", en: "Judgement and Four of Swords: the awakening trumpet shattering the silence of the rest chamber — the next journey is calling, and even if you have not fully recovered, this is the moment to rise and answer." },
  "20_54": { vi: "Phán Quyết và Năm Kiếm: được triệu hồi để nhìn nhận lại một cuộc chiến không đáng — sự thức tỉnh bao gồm việc nhìn thẳng vào những lựa chọn không tốt đẹp của mình và hỏi chúng đã dạy bạn điều gì.", en: "Judgement and Five of Swords: summoned to reckon with a battle not worth fighting — awakening includes looking directly at your less noble choices and asking what they have taught you." },
  "20_55": { vi: "Phán Quyết và Sáu Kiếm: tiếng gọi thức tỉnh trong khi đang chuyển tiếp — bạn đang trên đường rồi, và tiếng kèn xác nhận rằng hướng đi này là đúng và cuộc hành trình này là cần thiết.", en: "Judgement and Six of Swords: awakening call arriving during transition — you are already on the way, and the trumpet confirms this direction is right and this journey is necessary." },
  "20_56": { vi: "Phán Quyết và Bảy Kiếm: tiếng kèn phơi bày tất cả — trong khoảnh khắc thức tỉnh, không còn chỗ cho sự che giấu; mọi ý định ẩn giấu đều được nhìn nhận và điều đó buộc bạn phải chọn con người bạn thực sự muốn trở thành.", en: "Judgement and Seven of Swords: the trumpet exposing everything — in the moment of awakening, no room remains for concealment; every hidden intention is seen and that forces you to choose who you truly want to be." },
  "20_57": { vi: "Phán Quyết và Tám Kiếm: tiếng kèn thức tỉnh phá tan những ràng buộc — bạn đã bị giam cầm bởi những câu chuyện về bản thân, và khoảnh khắc thức tỉnh là khi bạn nhận ra rằng những câu chuyện đó không bao giờ là thật.", en: "Judgement and Eight of Swords: the awakening trumpet shattering the bonds — you have been imprisoned by stories about yourself, and the moment of awakening is when you recognise those stories were never true." },
  "20_58": { vi: "Phán Quyết và Chín Kiếm: tiếng gọi thức tỉnh đến ngay lúc lo âu đang đỉnh điểm — đây là lúc bạn có thể chọn: tiếp tục ở lại trong những câu chuyện đêm tối hay đứng dậy và đáp lời của cuộc sống đang triệu hồi bạn.", en: "Judgement and Nine of Swords: the awakening call arriving at the peak of anxiety — this is the moment you can choose: remain in the dark stories or rise and answer what life is summoning you toward." },
  "20_59": { vi: "Phán Quyết và Mười Kiếm: được triệu hồi từ sự sụp đổ hoàn toàn — tiếng kèn vang lên ngay trên đống đổ nát, và điều đáng kinh ngạc nhất là bạn vẫn có thể nghe thấy và đáp lời nó.", en: "Judgement and Ten of Swords: summoned from complete collapse — the trumpet sounds right above the ruins, and the most astonishing thing is that you can still hear it and still answer." },

  // World (21) × Swords 50–59
  "21_50": { vi: "Thế Giới và Át Kiếm: chu kỳ hoàn chỉnh mang đến sự sáng suốt trọn vẹn nhất — khi bạn đã đi hết con đường, nhận thức xuất hiện không phải từ sách vở mà từ mỗi vết thương và mỗi chiến thắng đã qua.", en: "The World and Ace of Swords: the completed cycle brings the most complete clarity — when you have walked the full path, insight arrives not from books but from every wound and every victory already passed." },
  "21_51": { vi: "Thế Giới và Hai Kiếm: khi chu kỳ hoàn thành, những lựa chọn không giải quyết được tự nhiên tan biến — thời gian và hành trình làm sáng tỏ những gì không thể giải quyết bằng lý trí đơn thuần.", en: "The World and Two of Swords: as the cycle completes, unresolved choices naturally dissolve — time and journey clarify what pure reason could never resolve." },
  "21_52": { vi: "Thế Giới và Ba Kiếm: sự hoàn chỉnh bao gồm cả những mất mát đã qua — không có hành trình đầy đủ nào mà không có vết thương, và việc tích hợp chúng vào câu chuyện của mình là phần không thể thiếu của sự trưởng thành.", en: "The World and Three of Swords: wholeness includes the losses already endured — no complete journey is without wounds, and integrating them into your story is the inseparable part of maturity." },
  "21_53": { vi: "Thế Giới và Bốn Kiếm: sau khi hoàn thành chu kỳ, sự nghỉ ngơi xứng đáng — đây không phải trốn tránh mà là việc nạp năng lượng của người đã đi hết một chặng đường dài và xứng đáng được dừng lại trước khi bước tiếp.", en: "The World and Four of Swords: after completing the cycle, well-earned rest — this is not avoidance but the restoration of one who has walked the full distance and deserves to pause before the next step." },
  "21_54": { vi: "Thế Giới và Năm Kiếm: khi chu kỳ hoàn chỉnh, những cuộc xung đột cũ mất đi sức kéo — bạn đã đủ trưởng thành để biết rằng không phải trận chiến nào cũng xứng đáng với năng lượng của một người đã thấy quá nhiều.", en: "The World and Five of Swords: as the cycle completes, old conflicts lose their pull — you are mature enough to know that not every battle is worth the energy of one who has already seen too much." },
  "21_55": { vi: "Thế Giới và Sáu Kiếm: sự hoàn chỉnh của một chu kỳ là cũng là bước đầu tiên của hành trình mới — bạn không ở lại trên bờ cũ mà bước lên thuyền với tất cả những gì bạn đã học được từ con đường đã qua.", en: "The World and Six of Swords: the completion of one cycle is also the first step of the next journey — you do not stay on the old shore but board the boat carrying everything you have learned from the path already walked." },
  "21_56": { vi: "Thế Giới và Bảy Kiếm: khi chu kỳ hoàn thành, không còn chỗ cho sự che giấu — bạn đã đi qua quá nhiều để tiếp tục giả vờ, và sự trưởng thành thực sự bao gồm việc nhìn nhận đầy đủ cả bóng tối của chính mình.", en: "The World and Seven of Swords: as the cycle completes, no room remains for hiding — you have been through too much to keep pretending, and true maturity includes fully acknowledging your own shadow." },
  "21_57": { vi: "Thế Giới và Tám Kiếm: sự hoàn chỉnh của hành trình phá tan những ràng buộc cuối cùng — sau khi đã đi hết con đường, bạn nhận ra rằng những gì giữ bạn lại chỉ là ký ức về các ràng buộc chứ không phải ràng buộc thực sự.", en: "The World and Eight of Swords: the completion of the journey shattering the last bonds — after walking the full path, you realise what was holding you back was only the memory of bonds, not actual bonds." },
  "21_58": { vi: "Thế Giới và Chín Kiếm: khi chu kỳ hoàn chỉnh, những lo âu cũ không còn quyền lực — bạn đã sống sót qua những đêm tối nhất và chứng minh với chính mình rằng những nỗi sợ đó không bao giờ thực sự có thể hủy diệt bạn.", en: "The World and Nine of Swords: as the cycle completes, old anxieties lose their power — you have survived the darkest nights and proven to yourself that those fears could never truly destroy you." },
  "21_59": { vi: "Thế Giới và Mười Kiếm: sự kết thúc hoàn toàn là phần không thể thiếu của sự hoàn chỉnh — không có chu kỳ nào thực sự kết thúc mà không có một điểm cuối rõ ràng, và điểm cuối đó không phải là sự thất bại mà là dấu chấm hết cho phép câu chuyện tiếp theo bắt đầu.", en: "The World and Ten of Swords: complete ending as an inseparable part of wholeness — no cycle truly closes without a clear final point, and that point is not failure but the full stop that allows the next story to begin." },

  // ─── TIER 3d: Major × Pentacles Numbered (220 pairs) ────────────────────────
  // Task 9a: Majors 0–7 × Pentacles 64–73

  // Fool (0) × Pentacles
  "0_64": { vi: "Kẻ Ngốc và Át Tiền: tiềm năng thuần túy gặp hạt giống của sự thịnh vượng — đây là khoảnh khắc lý tưởng để bắt đầu điều bạn hằng ước muốn; hãy gieo hạt trước khi lý trí tìm cớ để chờ thêm.", en: "The Fool and Ace of Pentacles: pure potential meets the seed of prosperity — this is the ideal moment to begin what you have long desired; plant the seed before your mind finds another reason to wait." },
  "0_65": { vi: "Kẻ Ngốc và Hai Tiền: nhiệt huyết ngây thơ gặp thực tế tung hứng — hành trình mới của bạn sẽ cần sự linh hoạt và ưu tiên rõ ràng, không chỉ tình thần phiêu lưu.", en: "The Fool and Two of Pentacles: naive enthusiasm meets the reality of juggling demands — your new journey will require flexibility and clear priorities, not just an adventurous spirit." },
  "0_66": { vi: "Kẻ Ngốc và Ba Tiền: năng lượng tươi mới gia nhập một nhóm thợ lành nghề — góc nhìn ngây thơ của bạn là tài sản quý giá cho cả đội, đừng để sự tự ti che giấu đóng góp đó.", en: "The Fool and Three of Pentacles: fresh energy joining a team of skilled craftspeople — your beginner's perspective is a genuine asset to the group; don't let self-doubt hide the contribution you carry." },
  "0_67": { vi: "Kẻ Ngốc và Bốn Tiền: tinh thần tự do gặp cám dỗ tích lũy — đừng để nhu cầu an toàn quá sớm bóp nghẹt bước nhảy vào điều chưa biết trước khi nó kịp nảy mầm.", en: "The Fool and Four of Pentacles: free spirit meets the temptation of early hoarding — don't let the need for premature security strangle the leap into the unknown before it has a chance to take root." },
  "0_68": { vi: "Kẻ Ngốc và Năm Tiền: sự ngây thơ gặp phải khó khăn vật chất thực sự — thử thách này có thật nhưng đừng đi bộ qua cơn lạnh mà không nhìn vào những cánh cửa đang mở sẵn quanh bạn.", en: "The Fool and Five of Pentacles: innocence encountering real material hardship — the difficulty is genuine, but don't walk through the cold without noticing the doors that are already open around you." },
  "0_69": { vi: "Kẻ Ngốc và Sáu Tiền: hành trình mới được nâng đỡ bởi sự hào phóng — hãy nhận lấy sự giúp đỡ được trao không có điều kiện; lòng biết ơn là câu trả lời duy nhất cần thiết.", en: "The Fool and Six of Pentacles: a new journey sustained by generosity — accept the help being offered without condition; gratitude is the only response that is needed right now." },
  "0_70": { vi: "Kẻ Ngốc và Bảy Tiền: sự bồn chồn của người mới bắt đầu gặp bài học về chờ đợi — không phải mọi hạt giống đều mọc trong một đêm; hãy đánh giá trước khi từ bỏ.", en: "The Fool and Seven of Pentacles: the restlessness of a beginner meets the lesson of patient assessment — not every seed grows in a single night; evaluate honestly before you abandon the work." },
  "0_71": { vi: "Kẻ Ngốc và Tám Tiền: người mới bắt đầu gặp người thợ kiên trì — hãy lao vào và cam kết học hỏi đúng cách; sự nhiệt tình ban đầu chỉ trở thành kỹ năng khi có kỷ luật.", en: "The Fool and Eight of Pentacles: the beginner meets the diligent craftsperson — dive in and commit to learning properly; initial enthusiasm only becomes skill when discipline follows." },
  "0_72": { vi: "Kẻ Ngốc và Chín Tiền: người khởi hành nhìn thấy khu vườn đã nở rộ ở phía trước — bạn đang bước vào con đường dẫn đến sự độc lập tự chủ; đó là thành quả của những gì bạn bắt đầu hôm nay.", en: "The Fool and Nine of Pentacles: the one setting out sees a flourishing garden ahead — you are stepping onto the path that leads to hard-won independence; that reward is the fruit of what you begin today." },
  "0_73": { vi: "Kẻ Ngốc và Mười Tiền: bước đầu tiên trên con đường dẫn đến di sản lâu dài — điều bạn bắt đầu với trái tim cởi mở hôm nay mang trong nó tiềm năng trở thành nền tảng cho những người đến sau.", en: "The Fool and Ten of Pentacles: the first step on a path that leads to lasting legacy — what you begin today with an open heart carries within it the potential to become a foundation for those who follow." },

  // Magician (1) × Pentacles
  "1_64": { vi: "Pháp Sư và Át Tiền: ý chí và kỹ năng gặp cơ hội vật chất thực sự — đây là thời điểm tốt nhất để biến ý định thành hành động cụ thể; bạn có đủ công cụ, chỉ cần dùng chúng.", en: "The Magician and Ace of Pentacles: will and skill meet a real material opportunity — this is the moment to turn intention into concrete action; you possess every tool needed, now use them." },
  "1_65": { vi: "Pháp Sư và Hai Tiền: tư duy chiến lược áp vào bài toán tung hứng — dừng cố gắng làm tất cả cùng lúc; hãy chọn mặt trận quan trọng nhất và tập trung nguồn lực vào đó.", en: "The Magician and Two of Pentacles: strategic thinking applied to the juggling act — stop trying to manage every front simultaneously; choose the most important one and concentrate your resources there." },
  "1_66": { vi: "Pháp Sư và Ba Tiền: bậc thầy gia nhập nhóm cộng tác — kỹ năng của bạn toả sáng mạnh hơn trong nhóm so với khi đơn độc; hãy chia sẻ kiến thức thay vì giữ nó như lợi thế.", en: "The Magician and Three of Pentacles: the master joining skilled collaborators — your abilities shine far brighter within a team than in isolation; share your knowledge rather than hoarding it as an advantage." },
  "1_67": { vi: "Pháp Sư và Bốn Tiền: ý chí bị chuyển hướng vào việc giữ chặt — bạn có đủ tài năng để xây dựng điều mới, nhưng tay bạn đang bận nắm giữ những gì đã cũ.", en: "The Magician and Four of Pentacles: will misdirected into holding on — you have more than enough skill to build something new, but your hands are busy gripping what is already past." },
  "1_68": { vi: "Pháp Sư và Năm Tiền: khả năng gặp sự thiếu thốn — chính kỹ năng của bạn là nguồn lực sẽ kéo bạn ra khỏi đây; hãy bắt đầu áp dụng những gì bạn biết thay vì chờ hoàn cảnh thay đổi.", en: "The Magician and Five of Pentacles: capability encountering scarcity — your skills are the very resource that can lift you from this; begin applying what you know rather than waiting for circumstances to change first." },
  "1_69": { vi: "Pháp Sư và Sáu Tiền: sự hào phóng có chủ đích — hãy cho và nhận một cách có ý thức; nguồn lực được phân phối với sự khéo léo tạo ra sự thịnh vượng chảy cả hai chiều.", en: "The Magician and Six of Pentacles: intentional generosity — give and receive with full awareness; resources distributed with skill and intention create an abundance that flows in both directions." },
  "1_70": { vi: "Pháp Sư và Bảy Tiền: người thợ lành nghề đánh giá lại công trình dài hạn — khả năng của bạn không bị nghi ngờ, nhưng sự kiên nhẫn của bạn đang bị thử thách; đừng rời đi trước khi thu hoạch.", en: "The Magician and Seven of Pentacles: the skilled worker reassessing long-term work — your ability is not in question here, but your patience is; don't walk away from a harvest that is nearly ready." },
  "1_71": { vi: "Pháp Sư và Tám Tiền: tài năng chọn kỷ luật — khi năng lực bẩm sinh kết hôn với sự luyện tập có chủ đích, sự tinh thông trở thành điều không thể tránh khỏi.", en: "The Magician and Eight of Pentacles: talent choosing discipline — when natural ability marries deliberate practice, mastery becomes not a distant goal but an inevitable destination." },
  "1_72": { vi: "Pháp Sư và Chín Tiền: sự thành thạo tạo ra sự độc lập — những nỗ lực bạn đang đầu tư ngay bây giờ đang xây dựng cuộc sống tự chủ mà bạn hướng tới.", en: "The Magician and Nine of Pentacles: mastery building self-sufficiency — the work you are putting in right now is constructing the independent, self-determined life you have been aiming toward." },
  "1_73": { vi: "Pháp Sư và Mười Tiền: kỹ năng hướng tới di sản — những gì bạn xây dựng bằng tay và trí tuệ của mình có tiềm năng vượt ra ngoài cuộc đời của chính bạn.", en: "The Magician and Ten of Pentacles: skill directed toward legacy — what you build with your hands and mind has the potential to outlast you and become a foundation others inherit." },

  // High Priestess (2) × Pentacles
  "2_64": { vi: "Thầy Tư Tế Nữ và Át Tiền: trực giác sâu thẳm nhận ra một cơ hội vật chất thực sự — hãy tin vào sự hiểu biết thầm lặng đó trước khi tâm trí phân tích tìm cách bác bỏ nó.", en: "The High Priestess and Ace of Pentacles: deep intuition recognising a genuine material opportunity — trust that quiet knowing before the analytical mind finds reasons to dismiss what your depths already understand." },
  "2_65": { vi: "Thầy Tế Nữ và Hai Tiền: trí tuệ nội tâm quan sát màn tung hứng — bản năng của bạn biết quả bóng nào quan trọng nhất; hãy để nó hướng dẫn bạn thay vì để đầu óc phân tích quyết định.", en: "The High Priestess and Two of Pentacles: inner wisdom watching the juggling act — your instinct already knows which ball matters most; let it guide the choice rather than letting the anxious mind decide." },
  "2_66": { vi: "Thầy Tư Tế Nữ và Ba Tiền: sự im lặng biết điều nhóm cần trước khi ai nói ra — đóng góp bằng cách lắng nghe sâu sắc; đôi khi hiểu biết tốt nhất một nhóm đến từ người quan sát nhất.", en: "The High Priestess and Three of Pentacles: silence knowing what the group needs before anyone voices it — contribute by listening deeply; sometimes the greatest understanding of a team comes from its most watchful member." },
  "2_67": { vi: "Thầy Tư Tế Nữ và Bốn Tiền: trực giác nhận ra sự sợ hãi ẩn đằng sau cái nắm chặt — bạn đang bảo vệ hay tích trữ? Câu trả lời thật nằm trong chiều sâu mà bạn chưa dám nhìn thẳng vào.", en: "The High Priestess and Four of Pentacles: intuition recognising the fear hidden behind the grip — are you protecting or hoarding? The true answer lives in the depth you have not yet been willing to look into directly." },
  "2_68": { vi: "Thầy Tư Tế Nữ và Năm Tiền: trí tuệ nội tâm thấy qua vẻ ngoài thiếu thốn — có nhiều hơn những gì bạn đang thấy ngay bây giờ; hãy để sự im lặng bên trong dẫn bạn đến nguồn lực vẫn còn đó.", en: "The High Priestess and Five of Pentacles: inner wisdom seeing through the appearance of lack — there is more available than your current perception shows; let inner stillness guide you toward the resources still present." },
  "2_69": { vi: "Thầy Tư Tế Nữ và Sáu Tiền: trí tuệ hướng dẫn sự hào phóng — sự cho đi thực sự đến từ việc biết cái gì, bao nhiêu và cho ai; đừng cho vì lo sợ, hãy cho vì hiểu biết.", en: "The High Priestess and Six of Pentacles: wisdom guiding generosity — genuine giving comes from knowing what, how much, and to whom; do not give from fear of judgment but from a place of knowing." },
  "2_70": { vi: "Thầy Tư Tế Nữ và Bảy Tiền: sự tĩnh lặng và kiên nhẫn ở trong trạng thái hoàn hảo — thu hoạch đến với những ai biết chờ đợi và quan sát; đừng hành động cho đến khi bạn thực sự thấy rõ.", en: "The High Priestess and Seven of Pentacles: stillness and patience in perfect alignment — the harvest comes to those who wait and truly observe; do not act until the moment reveals itself with unmistakable clarity." },
  "2_71": { vi: "Thầy Tư Tế Nữ và Tám Tiền: trực giác dẫn dắt sự thành thạo — người thợ lắng nghe trực giác nội tâm tạo ra tác phẩm chạm đến điều gì đó sâu hơn kỹ thuật đơn thuần.", en: "The High Priestess and Eight of Pentacles: intuition informing craft — the artisan who listens to inner knowing creates work that touches something deeper than technique alone can ever produce." },
  "2_72": { vi: "Thầy Tư Tế Nữ và Chín Tiền: sự hiểu biết sâu sắc gặp sự sung túc tự tạo — sự thịnh vượng bạn đã tích lũy được là biểu hiện bên ngoài của trí tuệ bên trong bạn đã kiên nhẫn vun đắp.", en: "The High Priestess and Nine of Pentacles: deep knowing meeting cultivated abundance — the prosperity you have built is the outward expression of the inner wisdom you have been patiently tending." },
  "2_73": { vi: "Thầy Tư Tế Nữ và Mười Tiền: trí tuệ tổ tiên được mã hóa vào di sản lâu bền — những mẫu hình từ quá khứ đang ghi vào nền tảng của những gì bạn đang xây dựng; hãy đọc chúng trước khi bạn xây tiếp.", en: "The High Priestess and Ten of Pentacles: ancestral wisdom encoded into lasting legacy — the patterns of the past are written into the foundation of what you are building; read them before you build another layer." },

  // Empress (3) × Pentacles
  "3_64": { vi: "Nữ Hoàng và Át Tiền: đất màu mỡ đón nhận hạt giống mới — đây là một trong những kết hợp tốt nhất để bắt đầu điều gì đó sẽ phát triển; hãy gieo và chăm sóc với sự kiên nhẫn.", en: "The Empress and Ace of Pentacles: fertile earth welcoming a new seed — this is one of the finest combinations for starting something that will genuinely grow; plant it and tend it with patience." },
  "3_65": { vi: "Nữ Hoàng và Hai Tiền: sức sáng tạo được nuôi dưỡng trong khi cân bằng các đòi hỏi — đừng để màn tung hứng hút cạn năng lượng mà sự sáng tạo cần để nảy mầm; hãy bảo vệ thời gian cho điều quan trọng nhất.", en: "The Empress and Two of Pentacles: creative abundance nurtured while balancing demands — don't let the juggling drain the energy that creativity needs to bloom; protect your time for the most important work." },
  "3_66": { vi: "Nữ Hoàng và Ba Tiền: người tạo ra hợp lực với những người thợ lành nghề — năng lượng tạo sinh của bạn nâng cao toàn bộ công việc nhóm; sự hợp tác này sẽ tạo ra nhiều hơn tổng các phần.", en: "The Empress and Three of Pentacles: the creator joining skilled collaborators — your generative energy elevates the entire team's output; this collaboration will produce more than the sum of its individual parts." },
  "3_67": { vi: "Nữ Hoàng và Bốn Tiền: sự phong phú tự nhiên bị chặn bởi cái nắm chặt — hãy nới lỏng; sự thịnh vượng của bạn chảy được khi bạn buông ra, không phải khi bạn giữ chặt.", en: "The Empress and Four of Pentacles: natural abundance blocked by hoarding — release the grip; your prosperity flows when you let it move rather than when you lock it in place out of fear." },
  "3_68": { vi: "Nữ Hoàng và Năm Tiền: đất phong phú gặp mùa đông khó khăn — hãy nuôi dưỡng bản thân và những người xung quanh qua sự thiếu thốn; mùa xuân đến sau mùa đông là điều đất mẹ biết rõ hơn ai hết.", en: "The Empress and Five of Pentacles: abundant earth meeting winter hardship — nurture yourself and those around you through the scarcity; spring follows winter, and the earth knows this truth more deeply than any fear." },
  "3_69": { vi: "Nữ Hoàng và Sáu Tiền: sự hào phóng tràn đầy — hãy cho tự do và để chu kỳ của sự dồi dào trở lại với bạn; người phụ nữ đất mẹ biết rằng cho đi không bao giờ tạo ra sự nghèo nàn.", en: "The Empress and Six of Pentacles: overflowing generosity — give freely and allow the cycle of abundance to return; the earth mother knows that genuine giving has never created real poverty." },
  "3_70": { vi: "Nữ Hoàng và Bảy Tiền: nhịp điệu kiên nhẫn của thiên nhiên gặp người nông dân đang chờ đợi — hãy tin vào thời điểm; khu vườn không vội vàng và không bao giờ trễ.", en: "The Empress and Seven of Pentacles: nature's patient rhythm aligning with the farmer's waiting — trust the timing; the garden never hurries and it is never late." },
  "3_71": { vi: "Nữ Hoàng và Tám Tiền: sức sáng tạo dồi dào gặp tay nghề tận tụy — hãy đổ năng lượng tạo sinh của bạn vào việc thành thạo điều bạn yêu; khi đam mê và kỷ luật kết hợp, tác phẩm nảy sinh.", en: "The Empress and Eight of Pentacles: creative abundance meeting dedicated craft — pour your generative energy into mastering what you love; when passion and discipline combine, work of real beauty emerges." },
  "3_72": { vi: "Nữ Hoàng và Chín Tiền: khu vườn đang nở rộ đầy đủ — những gì bạn đã chăm sóc và nuôi dưỡng đã trưởng thành thành điều gì đó thực sự đẹp và hoàn toàn là của bạn.", en: "The Empress and Nine of Pentacles: the garden in full bloom — what you have tended and nurtured with care has ripened into something genuinely beautiful and entirely your own to enjoy." },
  "3_73": { vi: "Nữ Hoàng và Mười Tiền: người mẹ vĩ đại xây dựng di sản lâu dài — những gì bạn tạo ra bằng tình yêu và sự chăm sóc có sức mạnh nuôi dưỡng các thế hệ đến sau bạn.", en: "The Empress and Ten of Pentacles: the great mother building a lasting legacy — what you create with love and genuine care holds the power to nourish those who come long after you are gone." },

  // Emperor (4) × Pentacles
  "4_64": { vi: "Hoàng Đế và Át Tiền: quyền lực định hướng một cơ hội vật chất mới — hãy tạo cấu trúc ngay từ đầu để cơ hội này có nền tảng vững chắc thay vì chỉ là tốt đẹp trên giấy.", en: "The Emperor and Ace of Pentacles: authority directing a new material opportunity — structure it from the beginning so this venture has a solid foundation rather than remaining merely promising on paper." },
  "4_65": { vi: "Hoàng Đế và Hai Tiền: sự kiểm soát đối mặt với những đòi hỏi cạnh tranh — hãy thiết lập ưu tiên rõ ràng thay vì để màn tung hứng bào mòn quyền lực của bạn.", en: "The Emperor and Two of Pentacles: control meeting competing demands — establish clear priorities rather than letting the juggling slowly erode the authority you have built." },
  "4_66": { vi: "Hoàng Đế và Ba Tiền: lãnh đạo định hình công việc cộng tác — hãy đặt tiêu chuẩn và để nhóm của bạn vươn lên đáp ứng; sự lãnh đạo tốt nhất tạo ra điều kiện cho sự tinh thông của người khác.", en: "The Emperor and Three of Pentacles: leadership shaping collaborative work — set the standards and let your team rise to meet them; the finest leadership creates the conditions for others to achieve their own mastery." },
  "4_67": { vi: "Hoàng Đế và Bốn Tiền: hai lực lượng kiểm soát và giữ chặt — hãy kiểm tra liệu cái an ninh bạn đang bảo vệ đã trở thành nhà tù do chính tay bạn xây.", en: "The Emperor and Four of Pentacles: two forces of control and holding — examine honestly whether the security you are protecting has already become a prison you built with your own hands." },
  "4_68": { vi: "Hoàng Đế và Năm Tiền: sự lãnh đạo đối mặt với khó khăn — cái cấu trúc vững chắc bạn đã xây dựng là điều sẽ chịu đựng được qua giai đoạn này; hãy tin vào nền tảng của chính mình.", en: "The Emperor and Five of Pentacles: leadership encountering hardship — the solid structure you have built is precisely what will endure through this difficulty; trust the foundation you laid." },
  "4_69": { vi: "Hoàng Đế và Sáu Tiền: quyền lực và sự hào phóng — sự cho đi từ vị trí sức mạnh là mạnh mẽ khi nó tôn trọng phẩm giá của người nhận, không tạo ra sự lệ thuộc.", en: "The Emperor and Six of Pentacles: authority and generosity — giving from a position of strength is genuinely powerful when it honours the recipient's dignity rather than creating dependence." },
  "4_70": { vi: "Hoàng Đế và Bảy Tiền: kỷ luật và sự chờ đợi — bạn đã xây nền tảng; thử thách khó nhất bây giờ là ở lại con đường mà không kiểm soát quá mức quá trình thu hoạch.", en: "The Emperor and Seven of Pentacles: disciplined waiting — you have built the foundation; the hardest task now is staying the course without micromanaging the harvest that is quietly ripening." },
  "4_71": { vi: "Hoàng Đế và Tám Tiền: kỷ luật có cấu trúc áp vào việc phát triển kỹ năng — khi tính quyết đoán và sự luyện tập tận tụy kết hợp, kết quả xuất sắc không còn là ngẫu nhiên nữa.", en: "The Emperor and Eight of Pentacles: structured discipline applied to skill development — when decisive authority and dedicated practice combine, exceptional results cease to be a matter of luck." },
  "4_72": { vi: "Hoàng Đế và Chín Tiền: quyền lực gặp sự độc lập tự đạt — sự tự chủ bạn đã xây dựng là biểu hiện cao nhất của năng lực lãnh đạo thực sự.", en: "The Emperor and Nine of Pentacles: command meeting earned self-sufficiency — the independence you have built through structure and discipline is the finest expression of genuine leadership capacity." },
  "4_73": { vi: "Hoàng Đế và Mười Tiền: người xây dựng hoàn thành một vương triều — những gì bạn đã cấu trúc, duy trì và bảo vệ đã sẵn sàng trở thành một thể chế lâu dài vượt qua chính bạn.", en: "The Emperor and Ten of Pentacles: the builder completing a dynasty — what you have structured, sustained, and protected is now ready to become a lasting institution that outlives its founder." },

  // Hierophant (5) × Pentacles
  "5_64": { vi: "Giáo Hoàng và Át Tiền: truyền thống mở ra cho một con đường vật chất mới — phương pháp đã được chứng minh tạo ra vật chứa an toàn để hạt giống mới lớn lên đúng cách.", en: "The Hierophant and Ace of Pentacles: tradition opening to a new material path — proven methods provide the safe container in which the new seed can grow with proper grounding." },
  "5_65": { vi: "Giáo Hoàng và Hai Tiền: trí tuệ được kiểm nghiệm quản lý các đòi hỏi cạnh tranh — hãy dựa vào những phương pháp đã được thời gian chứng minh để mang lại sự cân bằng cho màn tung hứng.", en: "The Hierophant and Two of Pentacles: tested wisdom managing competing demands — draw on the methods that time has already proven in order to bring genuine balance to the juggling act." },
  "5_66": { vi: "Giáo Hoàng và Ba Tiền: kiến thức thể chế gặp sự cộng tác lành nghề — mối quan hệ cố vấn và đào tạo ở đây quan trọng không kém gì công việc kỹ thuật; hãy dạy những gì bạn biết.", en: "The Hierophant and Three of Pentacles: institutional knowledge meeting skilled collaboration — the mentoring and teaching relationship here matters as much as the technical work; share what you know." },
  "5_67": { vi: "Giáo Hoàng và Bốn Tiền: truyền thống và sự giữ chặt — hãy kiểm tra liệu bạn đang bảo vệ những gì thực sự quan trọng hay chỉ đơn giản là bảo tồn những gì quen thuộc.", en: "The Hierophant and Four of Pentacles: tradition and holding — examine whether you are protecting what genuinely matters or simply preserving what is familiar because change feels threatening." },
  "5_68": { vi: "Giáo Hoàng và Năm Tiền: thể chế và người ngoài lề — cộng đồng và truyền thống có thể là nguồn hỗ trợ thực sự nếu bạn sẵn sàng bước trở vào thay vì ở ngoài lạnh.", en: "The Hierophant and Five of Pentacles: the institution and the outsider — community and tradition can be genuine sources of support if you are willing to step back inside rather than endure the cold alone." },
  "5_69": { vi: "Giáo Hoàng và Sáu Tiền: sự hào phóng có cấu trúc phù hợp với các giá trị — sự cho đi phù hợp với chuẩn mực cộng đồng và giá trị tạo ra lòng tin xã hội lâu dài.", en: "The Hierophant and Six of Pentacles: giving structured around values and community norms — generosity that aligns with shared principles and communal standards creates enduring social trust." },
  "5_70": { vi: "Giáo Hoàng và Bảy Tiền: sự kiên nhẫn được xác nhận bởi trí tuệ truyền thống — những người đã chờ đợi trước bạn biết rằng cái dài hạn là cách duy nhất; hãy để di sản của họ nâng đỡ sự bền bỉ của bạn.", en: "The Hierophant and Seven of Pentacles: patience confirmed by traditional wisdom — those who waited before you knew that the long view is the only way; let their legacy sustain your perseverance." },
  "5_71": { vi: "Giáo Hoàng và Tám Tiền: thời gian học nghề trong một truyền thống đã được thiết lập — sự kết hợp này nói trực tiếp về việc học hỏi từ bậc thầy trong khuôn khổ một ngành nghề đã được lập ra.", en: "The Hierophant and Eight of Pentacles: apprenticeship within an established tradition — this combination speaks directly to learning from a master within the framework of a craft that has been built over generations." },
  "5_72": { vi: "Giáo Hoàng và Chín Tiền: các giá trị truyền thống được biến đổi thành sự sung túc độc lập — kỷ luật bạn thừa hưởng đã được chắt lọc thành điều gì đó hoàn toàn là của riêng bạn.", en: "The Hierophant and Nine of Pentacles: traditional values transformed into independent abundance — the discipline you inherited has been distilled into something that is now entirely and authentically your own." },
  "5_73": { vi: "Giáo Hoàng và Mười Tiền: thể chế như nền tảng gia đình và di sản — những gì đã được truyền lại qua truyền thống là nền tảng của sự thịnh vượng bạn đang được hưởng.", en: "The Hierophant and Ten of Pentacles: the institution as family foundation and legacy — what has been handed down through tradition is the very bedrock of the prosperity you now inhabit and enjoy." },

  // Lovers (6) × Pentacles
  "6_64": { vi: "Người Yêu và Át Tiền: lựa chọn phản ánh các giá trị vật chất sâu nhất của bạn — những gì bạn quyết định về cơ hội này sẽ tiết lộ điều bạn thực sự ưu tiên khi không có áp lực.", en: "The Lovers and Ace of Pentacles: a choice reflecting your deepest material values — what you decide about this opportunity will reveal what you truly prioritise when the pressure is removed." },
  "6_65": { vi: "Người Yêu và Hai Tiền: lựa chọn trong khi đang tung hứng — bạn không thể tập trung hoàn toàn vào mọi thứ; hãy chọn điều thực sự quan trọng và cam kết với nó.", en: "The Lovers and Two of Pentacles: choosing while juggling — you cannot give full attention to every demand at once; choose what truly matters and commit to it rather than fragmenting indefinitely." },
  "6_66": { vi: "Người Yêu và Ba Tiền: lựa chọn những người cộng tác của bạn một cách khôn ngoan — những người bạn làm việc cùng trên dự án này sẽ định hình những gì được tạo ra; hãy chọn dựa trên giá trị, không chỉ kỹ năng.", en: "The Lovers and Three of Pentacles: choosing your collaborators with care — the people you work alongside on this project will define what gets built; choose based on shared values, not skills alone." },
  "6_67": { vi: "Người Yêu và Bốn Tiền: tình yêu và sự giữ chặt — hãy kiểm tra liệu nỗi sợ mất mát đang khiến bạn bóp chặt hơn những gì mối quan hệ hay tình huống có thể chịu đựng.", en: "The Lovers and Four of Pentacles: love and holding — examine whether fear of loss is causing you to grip tighter than the relationship or situation can sustainably bear." },
  "6_68": { vi: "Người Yêu và Năm Tiền: lựa chọn trong thời điểm khó khăn — khó khăn này có thật, nhưng lựa chọn giữa co rút một mình hay dựa vào nhau sẽ định hình những gì đến tiếp theo.", en: "The Lovers and Five of Pentacles: choosing in the moment of hardship — the difficulty is real, but the choice between withdrawing alone or leaning toward each other will shape everything that follows." },
  "6_69": { vi: "Người Yêu và Sáu Tiền: trao cho những người bạn yêu thương — hành động hào phóng nhất đôi khi là biết chính xác khi nào, cái gì và cách cho để người nhận cảm thấy được nhìn nhận.", en: "The Lovers and Six of Pentacles: giving to those you love — the most generous act is often knowing exactly when, what, and how to give so that the recipient feels genuinely seen rather than managed." },
  "6_70": { vi: "Người Yêu và Bảy Tiền: sự kiên nhẫn như một hành động tình yêu — đầu tư thời gian vào những gì bạn coi trọng nhất mà không đòi hỏi sự hoàn trả ngay lập tức là tình yêu biểu hiện dưới dạng hành động.", en: "The Lovers and Seven of Pentacles: patience as an act of love — investing time in what you value most without demanding immediate return is love expressed through the language of consistent action." },
  "6_71": { vi: "Người Yêu và Tám Tiền: chọn con đường của tay nghề tận tụy — khi tình yêu và sự chăm chỉ thẳng hàng, kỷ luật không còn cảm thấy như sự hy sinh nữa.", en: "The Lovers and Eight of Pentacles: choosing the path of dedicated craft — when love and diligence align with each other, the discipline required no longer feels like sacrifice." },
  "6_72": { vi: "Người Yêu và Chín Tiền: lựa chọn cuộc sống độc lập tự chủ — sự độc lập và mối quan hệ không nhất thiết phải mâu thuẫn; sự lựa chọn nằm ở cách bạn cấu trúc cả hai.", en: "The Lovers and Nine of Pentacles: choosing the self-sufficient life — independence and relationship do not have to conflict with each other; the choice lies in how you intentionally structure both." },
  "6_73": { vi: "Người Yêu và Mười Tiền: lựa chọn mang trọng lượng của di sản — những gì bạn quyết định bây giờ có tiềm năng định hình gia đình hay cộng đồng bạn thuộc về trong nhiều thế hệ.", en: "The Lovers and Ten of Pentacles: a choice carrying the weight of legacy — what you decide now has the potential to shape the family or community you are part of across generations." },

  // Chariot (7) × Pentacles
  "7_64": { vi: "Cỗ Xe và Át Tiền: sự quyết tâm tập trung vào một cơ hội vật chất mới — hãy tiến về phía cơ hội này với sự kiên định; khả năng thành công của bạn cao khi năng lực gặp hành động.", en: "The Chariot and Ace of Pentacles: focused determination channelled into a new material opportunity — move toward this opening with resolve; your chances of success are high when capability meets decisive action." },
  "7_65": { vi: "Cỗ Xe và Hai Tiền: sự quyết đoán gặp những đòi hỏi cạnh tranh — bạn không thể tiến lên mạnh mẽ trên tất cả các mặt trận cùng lúc; hãy chọn hướng đi của mình và tập trung toàn lực.", en: "The Chariot and Two of Pentacles: determination meeting competing demands — you cannot advance strongly on every front simultaneously; choose your primary direction and concentrate your full force there." },
  "7_66": { vi: "Cỗ Xe và Ba Tiền: chiến thắng thông qua làm việc nhóm — sức mạnh tiến lên của Cỗ Xe được khuếch đại khi những người cộng tác lành nghề kéo cùng một hướng.", en: "The Chariot and Three of Pentacles: victory through teamwork — the Chariot's forward drive is genuinely amplified when skilled collaborators are pulling with full commitment in the same direction." },
  "7_67": { vi: "Cỗ Xe và Bốn Tiền: ý chí gặp sự kháng cự từ bên trong — cái nắm chặt đang làm chậm đà tiến của bạn; hãy xem xét những gì cần phải buông để tiếp tục di chuyển về phía trước.", en: "The Chariot and Four of Pentacles: will meeting inner resistance — the grip you are maintaining is slowing your forward momentum; consider what needs to be released in order to keep moving." },
  "7_68": { vi: "Cỗ Xe và Năm Tiền: sự quyết tâm đối mặt với khó khăn vật chất — nghị lực của bạn là thực sự, nhưng giai đoạn này đòi hỏi một loại tiến bộ khác nhau: từng bước chắc chắn.", en: "The Chariot and Five of Pentacles: determination facing material hardship — your resolve is genuine, but this period requires a different kind of forward movement: one steady step at a time." },
  "7_69": { vi: "Cỗ Xe và Sáu Tiền: sự hào phóng sau chiến thắng — khi bạn đã vượt qua các trở ngại, chia sẻ nguồn lực của mình với những người còn đang chịu đựng là hành động tự nhiên tiếp theo.", en: "The Chariot and Six of Pentacles: generous victory — when you have overcome the obstacles placed before you, sharing your resources with those still enduring hardship is the natural next act." },
  "7_70": { vi: "Cỗ Xe và Bảy Tiền: sự quyết tâm gặp nhu cầu phải chờ đợi — thử thách lớn nhất của Cỗ Xe là học được rằng một số chiến thắng được tính bằng mùa vụ, không phải trận đánh.", en: "The Chariot and Seven of Pentacles: determination meeting the necessity of waiting — the greatest challenge for the Chariot is learning that some victories are measured in seasons, not battles." },
  "7_71": { vi: "Cỗ Xe và Tám Tiền: luyện tập với sự thúc đẩy — khi ý chí tập trung gặp tay nghề tận tụy, chất lượng của công việc cải thiện ở một tốc độ mà cả hai lực lượng đơn lẻ không thể đạt được.", en: "The Chariot and Eight of Pentacles: driven practice — when focused will meets disciplined craft, the quality of the work improves at a pace neither force alone could ever achieve." },
  "7_72": { vi: "Cỗ Xe và Chín Tiền: người chiến thắng quyết đoán gặp phần thưởng do chính tay mình giành được — sự độc lập bạn đã hướng tới giờ là của bạn; hãy tận hưởng mà không vội vã đến cuộc chinh phạt tiếp theo.", en: "The Chariot and Nine of Pentacles: the determined achiever meeting their hard-won reward — the independence you drove toward is now yours; allow yourself to enjoy it before rushing toward the next conquest." },
  "7_73": { vi: "Cỗ Xe và Mười Tiền: sức mạnh ý chí hướng về di sản — khi sự quyết tâm của bạn được định hướng vào việc xây dựng điều gì đó lâu dài, nó có sức mạnh tạo ra nền tảng bền vững qua nhiều thế hệ.", en: "The Chariot and Ten of Pentacles: will directed toward legacy — when your determination is aimed at building something lasting rather than merely winning, it carries the power to create a foundation that endures." },

  // ─── TIER 3d — Majors 8–15 × Pentacles Numbered (80 pairs) ─────────────────

  // Strength (8) × Pentacles 64–73
  "8_64": { vi: "Sức Mạnh và Át Tiền: lòng dũng cảm từ bên trong gặp hạt giống cơ hội vật chất — không cần ép buộc hay vội vàng; hãy tiếp cận khởi đầu mới này với sự kiên nhẫn và tự tin bền bỉ.", en: "Strength and Ace of Pentacles: inner courage meeting the seed of material opportunity — no force or urgency required; approach this new beginning with patient, grounded confidence and it will take root." },
  "8_65": { vi: "Sức Mạnh và Hai Tiền: can đảm để giữ thăng bằng giữa những đòi hỏi cạnh tranh — lòng kiên nhẫn chính là sức mạnh thực sự ở đây; đừng ép mọi thứ phải giải quyết nhanh hơn nhịp điệu tự nhiên.", en: "Strength and Two of Pentacles: the courage to hold balance amid competing demands — patience is the true strength here; do not force every tension to resolve faster than its natural rhythm allows." },
  "8_66": { vi: "Sức Mạnh và Ba Tiền: sự thành thạo kiên nhẫn trong công việc cộng tác — khi bạn mang lòng kiên trì vào một nhóm có năng lực, chất lượng công việc chung vượt xa những gì ai có thể tự làm.", en: "Strength and Three of Pentacles: patient mastery within collaborative work — when you bring steady perseverance into a skilled group, the quality of what you build together exceeds what anyone achieves alone." },
  "8_67": { vi: "Sức Mạnh và Bốn Tiền: lòng dũng cảm đối mặt với nỗi sợ thiếu thốn — sức mạnh thực sự không nằm ở việc nắm chặt hơn mà ở chỗ biết mình đủ vững để buông bỏ cái đang kìm hãm mình.", en: "Strength and Four of Pentacles: courage to face the fear beneath the hoarding — true strength is not gripping tighter but knowing you are secure enough to release what is holding you back." },
  "8_68": { vi: "Sức Mạnh và Năm Tiền: sức bền vững chắc trong giai đoạn khó khăn vật chất — bạn không cần lực lượng cơ bắp mà cần ngọn lửa bên trong không bao giờ tắt, dù hoàn cảnh bên ngoài khắc nghiệt đến đâu.", en: "Strength and Five of Pentacles: resilient endurance through material hardship — what you need is not physical force but the inner flame that refuses to be extinguished, however harsh the outer conditions become." },
  "8_69": { vi: "Sức Mạnh và Sáu Tiền: lòng hào phóng xuất phát từ sự sung mãn bên trong — khi sức mạnh của bạn đến từ bên trong chứ không phải từ tài sản, bạn có thể cho đi với bàn tay mở mà không sợ hãi.", en: "Strength and Six of Pentacles: generosity that flows from inner abundance — when your strength comes from within rather than from possessions, you can give with an open hand without fear of losing ground." },
  "8_70": { vi: "Sức Mạnh và Bảy Tiền: kiên nhẫn đánh giá lại công việc dài hơi — sức mạnh ở đây không phải là thúc đẩy cho nhanh mà là đứng yên đủ lâu để nhìn thẳng vào những gì thực sự đang phát triển.", en: "Strength and Seven of Pentacles: patient reassessment of long-term work — the strength here is not to push for speed but to stand still long enough to honestly see what is truly growing and what is not." },
  "8_71": { vi: "Sức Mạnh và Tám Tiền: sức bền kỷ luật trong tay nghề — mỗi ngày trở lại bàn làm việc, mỗi chi tiết được trau chuốt lại, chính là biểu hiện của lòng dũng cảm lặng thầm nhất và bền nhất.", en: "Strength and Eight of Pentacles: disciplined endurance within the craft — returning to the work each day, refining each detail once more, is itself an act of the quietest and most lasting form of courage." },
  "8_72": { vi: "Sức Mạnh và Chín Tiền: tự chủ dẫn đến độc lập thực sự — phần thưởng vật chất bạn đang hưởng không phải là kết quả của may mắn mà là bằng chứng của sức mạnh nội tâm được vun đắp qua năm tháng.", en: "Strength and Nine of Pentacles: self-mastery earning genuine independence — the material comfort you now enjoy is not the result of luck but the evidence of inner strength cultivated steadily over years." },
  "8_73": { vi: "Sức Mạnh và Mười Tiền: sức mạnh bền bỉ xây nền di sản — điều trường tồn qua các thế hệ không phải là của cải vật chất mà là tấm gương về sức chịu đựng và lòng kiên trì bạn để lại.", en: "Strength and Ten of Pentacles: enduring strength building a lasting legacy — what passes across generations is not material wealth alone but the example of resilience and steady perseverance you leave behind." },

  // The Hermit (9) × Pentacles 64–73
  "9_64": { vi: "Ẩn Sĩ và Át Tiền: hạt giống được gieo trong sự tĩnh lặng — khởi đầu vật chất tốt nhất đôi khi được nuôi dưỡng trong cô đơn và chiêm nghiệm trước khi mang ra ánh sáng của thế giới.", en: "The Hermit and Ace of Pentacles: a seed planted in stillness — the most durable material beginnings are sometimes nurtured in solitude and reflection before being brought into the light of the world." },
  "9_65": { vi: "Ẩn Sĩ và Hai Tiền: trí tuệ nội tâm để điều phối nhiều trách nhiệm — thay vì đánh giá từ bên ngoài, hãy rút lui vào bên trong và để sự im lặng chỉ cho bạn biết đâu là ưu tiên thực sự.", en: "The Hermit and Two of Pentacles: inner wisdom for navigating competing responsibilities — instead of seeking external validation, withdraw and let stillness show you which priority is the one that genuinely matters." },
  "9_66": { vi: "Ẩn Sĩ và Ba Tiền: bậc thầy cô độc và sự xuất sắc thầm lặng — không phải mọi công việc tuyệt vời đều cần được chứng kiến; sự thành thạo sâu sắc nhất thường được mài giũa trong những giờ làm việc một mình.", en: "The Hermit and Three of Pentacles: the solitary master and quiet excellence — not all great work requires an audience; the deepest mastery is often honed in hours of working alone, unseen and unhurried." },
  "9_67": { vi: "Ẩn Sĩ và Bốn Tiền: sự cô độc được củng cố bởi sự an toàn vật chất — hãy kiểm tra xem việc thu mình lại có phải là trí tuệ hay là sự co rúm vì sợ hãi, vì hai điều này trông giống nhau từ bên ngoài.", en: "The Hermit and Four of Pentacles: solitude reinforced by material security — examine whether your withdrawal is wisdom or fear-driven contraction, because from the outside these two can look almost identical." },
  "9_68": { vi: "Ẩn Sĩ và Năm Tiền: sự rút lui trong thời kỳ thiếu thốn — đèn lồng của Ẩn Sĩ không tắt trong bóng tối; ngay cả trong hoàn cảnh vật chất khốn khó, ánh sáng nội tâm vẫn có thể tìm đường ra.", en: "The Hermit and Five of Pentacles: withdrawal during material hardship — the Hermit's lantern does not go out in darkness; even within difficult material circumstances, the inner light can still find a path forward." },
  "9_69": { vi: "Ẩn Sĩ và Sáu Tiền: sự hào phóng thầm lặng từ người đã từng trải — người biết cả sự thiếu hụt lẫn sự đủ đầy có thể cho đi với sự hiểu biết thực sự; đây không phải là bổn phận mà là sự thấu hiểu.", en: "The Hermit and Six of Pentacles: the quiet generosity of one who has known both lack and sufficiency — giving from experience rather than obligation carries a depth of understanding that changes what is offered." },
  "9_70": { vi: "Ẩn Sĩ và Bảy Tiền: chiêm nghiệm về công việc lâu dài — Ẩn Sĩ không vội vàng thu hoạch; ông đứng lặng lẽ trên đỉnh đồi và quan sát với sự khôn ngoan rằng đôi khi chờ đợi chính là công việc.", en: "The Hermit and Seven of Pentacles: contemplation over long-term work — the Hermit does not rush the harvest; he stands quietly on the hillside and watches with the wisdom that waiting is sometimes the work." },
  "9_71": { vi: "Ẩn Sĩ và Tám Tiền: sự thành thạo đơn độc và tay nghề thâm sâu — trong những giờ làm việc một mình không ai nhìn, kỹ năng được mài giũa sâu nhất; người thợ giỏi nhất thường là người im lặng nhất.", en: "The Hermit and Eight of Pentacles: solitary mastery and deep craft — in the hours of working alone with no one watching, skill is honed deepest; the finest craftspeople are often the quietest ones." },
  "9_72": { vi: "Ẩn Sĩ và Chín Tiền: người tự túc đã tìm thấy khu vườn của mình — sự độc lập bạn đang tận hưởng là thành quả của những năm dài tự chỉ dẫn và nỗ lực một mình; đây chính là đỉnh cao của cuộc hành trình nội tâm.", en: "The Hermit and Nine of Pentacles: the self-sufficient one who has found their garden — the independence you now enjoy is the fruit of years of self-guidance and solitary effort; this is the inner journey's reward." },
  "9_73": { vi: "Ẩn Sĩ và Mười Tiền: trí tuệ là di sản thực sự — điều bạn truyền lại không phải là tài sản mà là tấm gương về cách sống có chiều sâu, cách học hỏi kiên nhẫn, và cách biết đủ.", en: "The Hermit and Ten of Pentacles: wisdom as the true inheritance — what you pass on is not possessions but the example of how to live with depth, how to learn patiently, and how to know when enough is enough." },

  // Wheel of Fortune (10) × Pentacles 64–73
  "10_64": { vi: "Bánh Xe Số Phận và Át Tiền: thời điểm và vận may hội tụ cho khởi đầu vật chất — khi bánh xe xoay về phía bạn, hãy nắm lấy hạt giống này ngay; những cơ hội như vậy không chờ người do dự.", en: "The Wheel of Fortune and Ace of Pentacles: timing and fortune converging for a material beginning — when the wheel turns in your direction, seize this seed now; opportunities of this kind do not wait for the hesitant." },
  "10_65": { vi: "Bánh Xe Số Phận và Hai Tiền: những chu kỳ lên xuống trong cách bạn quản lý nguồn lực — đừng coi sự mất cân bằng hiện tại là thất bại vĩnh viễn; bánh xe vẫn đang quay và thăng bằng sẽ trở lại.", en: "The Wheel of Fortune and Two of Pentacles: the rising and falling cycles in how you manage your resources — do not read the current imbalance as permanent failure; the wheel is still turning and equilibrium will return." },
  "10_66": { vi: "Bánh Xe Số Phận và Ba Tiền: thành công của dự án phụ thuộc vào thời điểm cũng như kỹ năng — ngay cả công việc xuất sắc cũng cần vận may hỗ trợ; nhận ra khi nào chu kỳ đang nghiêng về phía bạn và hành động lúc đó.", en: "The Wheel of Fortune and Three of Pentacles: a project whose outcome depends as much on timing as skill — even excellent work needs the cycle's support; recognize when the wheel is tilting your way and act then." },
  "10_67": { vi: "Bánh Xe Số Phận và Bốn Tiền: bánh xe quay ngược lại sự siết chặt — sự bám víu không ngăn được sự thay đổi mà chỉ làm cho quá trình chuyển tiếp trở nên đau đớn hơn; hãy buông tay trước khi bánh xe ép bạn phải làm.", en: "The Wheel of Fortune and Four of Pentacles: the wheel turning against the grip — clinging does not prevent change, it only makes the transition more painful; release before the wheel forces your hand." },
  "10_68": { vi: "Bánh Xe Số Phận và Năm Tiền: những chu kỳ khó khăn vật chất rồi sẽ đảo chiều — khó khăn hiện tại không phải là điểm kết thúc; bánh xe không bao giờ đứng yên mãi ở điểm thấp nhất của nó.", en: "The Wheel of Fortune and Five of Pentacles: material hardship cycles that will eventually reverse — the current difficulty is not the final destination; the wheel does not remain permanently fixed at its lowest point." },
  "10_69": { vi: "Bánh Xe Số Phận và Sáu Tiền: vận may luân chuyển giữa người cho và người nhận — ai đang ở trên hôm nay có thể cần đến sự giúp đỡ ngày mai; sự hào phóng bây giờ đầu tư vào vòng quay tiếp theo của bánh xe.", en: "The Wheel of Fortune and Six of Pentacles: fortune cycling between those who give and those who receive — whoever stands above today may need assistance tomorrow; generosity now is an investment in the wheel's next turn." },
  "10_70": { vi: "Bánh Xe Số Phận và Bảy Tiền: biết thời điểm thu hoạch khi bánh xe đã xoay đủ — có sự khôn ngoan trong việc nhận ra khi nào chu kỳ đã chín muồi cho sự thu hoạch và không chờ thêm một vòng quay nữa.", en: "The Wheel of Fortune and Seven of Pentacles: knowing when the wheel has turned enough to harvest — there is wisdom in recognizing when the cycle has ripened for harvest and not waiting for one more rotation." },
  "10_71": { vi: "Bánh Xe Số Phận và Tám Tiền: tay nghề được mài sắc đúng lúc vận may xoay chiều — khi chu kỳ thuận lợi gặp kỹ năng được rèn giũa sẵn sàng, kết quả vượt xa những gì một trong hai yếu tố có thể tạo ra một mình.", en: "The Wheel of Fortune and Eight of Pentacles: craft sharpened at the moment fortune turns — when a favorable cycle meets a skill that has been diligently prepared, the result exceeds what either element produces alone." },
  "10_72": { vi: "Bánh Xe Số Phận và Chín Tiền: khi bánh xe nghiêng về phía thuận lợi, độc lập là quả ngọt — không phải mọi thành quả đều là may mắn thuần túy, nhưng biết nhận ra và nắm bắt khoảnh khắc thuận lợi là một phần của trí tuệ.", en: "The Wheel of Fortune and Nine of Pentacles: when the wheel tilts favorably, independence is the sweet fruit — not all achievement is pure luck, but recognizing and seizing the opportune moment is itself a form of wisdom." },
  "10_73": { vi: "Bánh Xe Số Phận và Mười Tiền: những chu kỳ của sự thịnh vượng qua nhiều thế hệ — di sản gia đình mang dấu vết của những lần bánh xe xoay thuận; truyền sự khôn ngoan về cách nhận ra và đón nhận những thời điểm đó cho thế hệ sau.", en: "The Wheel of Fortune and Ten of Pentacles: cycles of prosperity across generations — family legacy carries the marks of times when the wheel turned favorably; pass on the wisdom of recognizing and receiving those moments." },

  // Justice (11) × Pentacles 64–73
  "11_64": { vi: "Công Lý và Át Tiền: khởi đầu vật chất xứng đáng, được tạo ra chứ không phải được tặng — hạt giống này có giá trị đặc biệt vì nó đến từ sự trung thực và công sức thực sự; hãy trân trọng và vun đắp nó.", en: "Justice and Ace of Pentacles: a material beginning that is earned rather than given — this seed carries particular weight because it comes from honesty and genuine effort; tend it with the care it deserves." },
  "11_65": { vi: "Công Lý và Hai Tiền: cân bằng các nghĩa vụ vật chất với sự công bằng — khi bạn phân bổ thời gian, tiền bạc và năng lượng, hãy để nguyên tắc công bằng hướng dẫn chứ không phải chỉ là tiện lợi nhất thời.", en: "Justice and Two of Pentacles: allocating competing material obligations with fairness — when distributing your time, money, and energy, let the principle of fair balance guide you rather than momentary convenience." },
  "11_66": { vi: "Công Lý và Ba Tiền: sự ghi nhận xứng đáng dựa trên năng lực thực sự — khi công việc chuyên nghiệp được đánh giá đúng mức và đãi ngộ công bằng, nó nuôi dưỡng sự cống hiến; hãy đảm bảo bạn đang cho và nhận một cách công bằng.", en: "Justice and Three of Pentacles: recognition and compensation proportional to genuine skill — when professional work is evaluated fairly and rewarded accordingly, it sustains commitment; ensure you are both giving and receiving equitably." },
  "11_67": { vi: "Công Lý và Bốn Tiền: sự thẩm tra trung thực về điều thực sự là của bạn để giữ — không phải mọi thứ bạn đang bảo vệ đều thực sự thuộc về bạn; Công Lý đòi hỏi sự rõ ràng về ranh giới giữa bảo vệ hợp lý và chiếm hữu sai trái.", en: "Justice and Four of Pentacles: an honest examination of what is truly yours to hold — not everything you are protecting genuinely belongs to you; Justice demands clarity about the line between rightful protection and unjust possession." },
  "11_68": { vi: "Công Lý và Năm Tiền: nguyên nhân gốc rễ của khó khăn vật chất phải được nhìn thẳng — không phải tất cả mọi thiếu thốn đều là hệ quả của sự không công bằng, nhưng một số thì có; hãy phân biệt để biết hành động nào là phù hợp.", en: "Justice and Five of Pentacles: the root cause of material hardship must be honestly examined — not all deprivation is the result of injustice, but some is; distinguish between them so you know which action is appropriate." },
  "11_69": { vi: "Công Lý và Sáu Tiền: cho và nhận trong sự cân bằng thực sự — hào phóng thật sự không có nghĩa là cho đi nhiều hơn bạn có; nó có nghĩa là hiểu rõ mình có gì và phân bổ một cách chính xác và không thiên vị.", en: "Justice and Six of Pentacles: giving and receiving in genuine balance — true generosity does not mean giving more than you have; it means understanding clearly what you have and distributing it accurately and without favoritism." },
  "11_70": { vi: "Công Lý và Bảy Tiền: sự đánh giá trung thực về những gì công việc thực sự tạo ra — Công Lý không cho phép tự lừa dối; hãy nhìn thẳng vào những con số, vào những kết quả thực tế, và đưa ra quyết định dựa trên thực tế đó.", en: "Justice and Seven of Pentacles: an honest reckoning with what the work has actually produced — Justice permits no self-deception; look squarely at the numbers, the real results, and make decisions based on that truth." },
  "11_71": { vi: "Công Lý và Tám Tiền: sự ghi nhận xứng đáng cho tay nghề cần cù — người thợ thủ công làm việc chăm chỉ có quyền được nhận thù lao công bằng; nếu điều đó chưa xảy ra, Công Lý đang kêu gọi bạn giải quyết vấn đề này.", en: "Justice and Eight of Pentacles: fair recognition for diligent craft — the craftsperson who works with care and persistence deserves fair compensation; if that is not happening, Justice is calling you to address it." },
  "11_72": { vi: "Công Lý và Chín Tiền: sự độc lập được kiếm xứng đáng — không ai có thể lấy đi điều bạn xây dựng qua sự chính trực và nỗ lực thực sự; đây là thành quả của mình, và bạn có quyền tận hưởng nó không chút nghi ngờ.", en: "Justice and Nine of Pentacles: independence genuinely earned — no one can take from you what you have built through integrity and real effort; this achievement is yours, and you have every right to enjoy it without doubt." },
  "11_73": { vi: "Công Lý và Mười Tiền: di sản phản ánh sự trung thực qua nhiều thế hệ — tài sản và danh tiếng được truyền lại theo thời gian phải được xây dựng trên nền tảng giao dịch công bằng và đối xử trung thực để thực sự trường tồn.", en: "Justice and Ten of Pentacles: legacy reflecting honest dealing across generations — wealth and reputation that endure across time must be built on a foundation of fair dealing and honest treatment to truly last." },

  // The Hanged Man (12) × Pentacles 64–73
  "12_64": { vi: "Người Treo Ngược và Át Tiền: hạt giống phải chờ dưới đất trước khi nảy mầm — cơ hội vật chất mới này đòi hỏi giai đoạn thai nghén trong bóng tối; đừng đào lên sớm vì lo lắng về những gì chưa thể nhìn thấy.", en: "The Hanged Man and Ace of Pentacles: the seed must wait beneath the earth before it can sprout — this new material opportunity requires a period of dark gestation; do not dig it up early out of anxiety about what cannot yet be seen." },
  "12_65": { vi: "Người Treo Ngược và Hai Tiền: treo lơ lửng giữa hai lựa chọn vật chất — chưa có lựa chọn nào được thực hiện, và đây không nhất thiết là sự do dự; đôi khi thời điểm đúng đắn nhất là khi bạn dừng lại để thấy rõ hơn.", en: "The Hanged Man and Two of Pentacles: suspended between two material options, neither yet chosen — no choice has been made, and this is not necessarily indecision; sometimes the right moment requires pausing to see more clearly." },
  "12_66": { vi: "Người Treo Ngược và Ba Tiền: lùi lại khỏi dự án để nhìn bằng con mắt mới — đôi khi công việc cộng tác cần một người sẵn sàng tạm dừng và đặt câu hỏi liệu hướng đi hiện tại có thực sự đúng không, dù điều đó khó chịu với nhóm.", en: "The Hanged Man and Three of Pentacles: stepping back from the project to see with fresh eyes — sometimes collaborative work needs someone willing to pause and question whether the current direction is truly right, even if that is uncomfortable." },
  "12_67": { vi: "Người Treo Ngược và Bốn Tiền: nghi vấn về điều bạn đang giữ và lý do tại sao — từ góc nhìn đảo ngược, những thứ bạn cho là tài sản có thể hiện ra như gánh nặng; hãy để quan điểm mới này thách thức những gì bạn coi là an toàn.", en: "The Hanged Man and Four of Pentacles: questioning what you hold and why you hold it — from an inverted perspective, what you consider assets may appear as burdens; let this new angle challenge what you have been calling security." },
  "12_68": { vi: "Người Treo Ngược và Năm Tiền: tìm ý nghĩa bên trong khó khăn vật chất — giai đoạn thiếu hụt không phải là tai nạn mà là môi trường để một loại hiểu biết mới phát triển, nếu bạn đủ kiên nhẫn để không vội thoát ra.", en: "The Hanged Man and Five of Pentacles: discovering meaning within material hardship — this period of lack is not random misfortune but an environment in which a new kind of understanding grows, if you are patient enough to not rush out." },
  "12_69": { vi: "Người Treo Ngược và Sáu Tiền: sự hào phóng từ người đã học được giá trị của việc nhận — người từng ở vị trí của người nhận cho đi với sự hiểu biết khác; họ không cho vì bổn phận mà vì biết rõ sự cho đi có ý nghĩa gì.", en: "The Hanged Man and Six of Pentacles: generosity from one who has learned what it means to receive — one who has stood in the receiver's place gives with different understanding; they give not from obligation but from knowing what it means." },
  "12_70": { vi: "Người Treo Ngược và Bảy Tiền: chờ đợi và quan sát, mùa thu hoạch chưa đến — đây không phải là sự lười biếng mà là sự phân biệt; người khôn ngoan biết rằng ép buộc thu hoạch trước thời điểm là cách chắc chắn nhất để phá hỏng nó.", en: "The Hanged Man and Seven of Pentacles: waiting and watching, the harvest not yet ready — this is not laziness but discernment; the wise one knows that forcing the harvest before its time is the surest way to ruin it." },
  "12_71": { vi: "Người Treo Ngược và Tám Tiền: tạm dừng để xem xét liệu tay nghề của bạn có thực sự phục vụ bạn — đôi khi cần dừng lại giữa chừng để hỏi: công việc này đang dạy tôi điều gì, và tôi có thực sự muốn đi đến nơi nó đang dẫn tôi không?", en: "The Hanged Man and Eight of Pentacles: pausing to examine whether your craft is truly serving you — sometimes you must stop mid-process to ask: what is this work teaching me, and do I genuinely want to go where it is leading?" },
  "12_72": { vi: "Người Treo Ngược và Chín Tiền: sự cô độc được lựa chọn, độc lập như một hình thức buông bỏ — Chín Tiền đạt được không phải luôn thông qua nỗ lực mà đôi khi thông qua sự buông bỏ chiến lược những con đường không còn phù hợp.", en: "The Hanged Man and Nine of Pentacles: chosen solitude, independence as a form of deliberate surrender — Nine of Pentacles is sometimes reached not through striving but through strategically releasing the paths that no longer fit." },
  "12_73": { vi: "Người Treo Ngược và Mười Tiền: đặt câu hỏi liệu di sản có thực sự là điều bạn trân trọng — trước khi dành cả đời để xây dựng một di sản, hãy treo ngược quan điểm của mình và hỏi xem điều đó có thực sự là điều bạn muốn truyền lại không.", en: "The Hanged Man and Ten of Pentacles: questioning whether legacy is truly what you value — before spending a lifetime building a legacy, invert your perspective and honestly ask whether that is genuinely what you want to leave behind." },

  // Death (13) × Pentacles 64–73
  "13_64": { vi: "Thần Chết và Át Tiền: sự chuyển hóa mở ra cánh cửa cho khởi đầu vật chất mới — điều kết thúc không phải là cơ hội mà là cách cũ bạn tiếp cận sự thịnh vượng; hạt giống mới này đòi hỏi một phương pháp hoàn toàn khác.", en: "Death and Ace of Pentacles: transformation opening the door to a new material beginning — what is ending is not the opportunity itself but the old way you approached abundance; this new seed requires an entirely different method." },
  "13_65": { vi: "Thần Chết và Hai Tiền: cách cũ cân bằng nguồn lực phải được để cho qua — một phương pháp quản lý mới đang được kêu gọi; cố gắng duy trì hệ thống cũ chỉ làm chậm sự chuyển tiếp không thể tránh khỏi.", en: "Death and Two of Pentacles: the old way of balancing resources must be allowed to end — a new management approach is being called for; trying to maintain the old system only delays a transition that is already inevitable." },
  "13_66": { vi: "Thần Chết và Ba Tiền: một dự án đang đến điểm kết thúc tự nhiên của nó — không phải mọi kết thúc đều là thất bại; đôi khi sự chuyển hóa của công việc là bước tất yếu để điều gì đó tốt hơn có thể được sinh ra.", en: "Death and Three of Pentacles: a project reaching its natural point of completion — not every ending is failure; sometimes the transformation of the work itself is the necessary step before something better can be born from it." },
  "13_67": { vi: "Thần Chết và Bốn Tiền: sự nắm chặt phải được buông ra; bám víu chỉ trì hoãn sự chuyển tiếp cần thiết — Thần Chết không thương lượng, và sự kháng cự chỉ kéo dài nỗi đau của điều đã được quyết định.", en: "Death and Four of Pentacles: the grip must be released; clinging only prolongs a transition that has already been decided — Death does not negotiate, and resistance only extends the pain of what has already been determined." },
  "13_68": { vi: "Thần Chết và Năm Tiền: chấm dứt những chu kỳ thiếu hụt vật chất thông qua sự thay đổi căn bản — nếu cùng một mô thức thiếu thốn cứ lặp lại, không phải hoàn cảnh cần thay đổi mà là nhận thức và hành vi ở gốc rễ.", en: "Death and Five of Pentacles: ending cycles of material hardship through fundamental change — if the same pattern of deprivation keeps recurring, it is not the circumstances that need to change but the perception and behavior at the root." },
  "13_69": { vi: "Thần Chết và Sáu Tiền: sự chuyển hóa mối quan hệ của bạn với việc cho và nhận — hãy để vai trò cũ chết đi: người luôn cho mà không nhận, hoặc người luôn phụ thuộc; sự cân bằng mới đòi hỏi cả hai phía phải sẵn sàng thay đổi.", en: "Death and Six of Pentacles: transforming your relationship with giving and receiving — let the old role die: the one who always gives without receiving, or the one who always depends; a new balance requires both sides to change." },
  "13_70": { vi: "Thần Chết và Bảy Tiền: để vụ thu hoạch kết thúc để đất có thể tái sinh — không phải mọi thứ được trồng đều cần phải giữ lại; đôi khi điều khôn ngoan nhất là để đất nghỉ ngơi trước khi bắt đầu vụ mùa tiếp theo.", en: "Death and Seven of Pentacles: letting the harvest end so the soil can regenerate — not everything planted needs to be preserved; sometimes the wisest act is allowing the land to rest before beginning the next season's work." },
  "13_71": { vi: "Thần Chết và Tám Tiền: tay nghề trải qua sự chuyển hóa; kỹ năng cũ được thay bằng kỹ năng mới — người thợ thực sự không sợ học lại từ đầu; sự sẵn sàng để những gì đã biết chết đi là điều phân biệt bậc thầy với người thợ bình thường.", en: "Death and Eight of Pentacles: the craft undergoing transformation, old skills giving way to new ones — the true craftsperson is not afraid to begin learning again; willingness to let the known die is what separates mastery from competence." },
  "13_72": { vi: "Thần Chết và Chín Tiền: sự độc lập đạt được qua việc buông bỏ những gì không còn nuôi dưỡng bạn — đôi khi Chín Tiền không phải là điểm đến của nỗ lực mà là phần thưởng của sự buông bỏ dũng cảm những con đường không còn phù hợp.", en: "Death and Nine of Pentacles: independence gained by releasing what no longer sustains you — sometimes Nine of Pentacles is not the destination of effort but the reward of courageously releasing the paths that no longer fit." },
  "13_73": { vi: "Thần Chết và Mười Tiền: di sản cũ kết thúc để di sản mới có thể được xây dựng — không phải sự thừa kế nào cũng cần được giữ nguyên; đôi khi việc kính trọng tổ tiên nhất là phá bỏ những gì họ tạo ra để xây dựng điều phù hợp với thời đại mới.", en: "Death and Ten of Pentacles: the old legacy ending so a new one can be built — not every inheritance needs to be preserved intact; sometimes the greatest respect for ancestors is dismantling what they built to construct what fits the new era." },

  // Temperance (14) × Pentacles 64–73
  "14_64": { vi: "Điều Độ và Át Tiền: tiếp cận hạt giống vật chất mới với sự kiên nhẫn của người thợ luyện kim — không có gì được vội vàng; hãy để quá trình pha trộn và biến đổi diễn ra theo nhịp độ tự nhiên của nó.", en: "Temperance and Ace of Pentacles: approaching the new material seed with the patience of an alchemist — nothing is rushed; allow the mixing and transformation to proceed at its own natural pace rather than forcing an outcome." },
  "14_65": { vi: "Điều Độ và Hai Tiền: nghệ thuật điều phối nhiều nguồn lực với sự duyên dáng — không phải tung hứng căng thẳng mà là dòng chảy nhịp nhàng; Điều Độ biến sự phức tạp thành vũ điệu khi bạn ngừng chống cự với nó.", en: "Temperance and Two of Pentacles: the art of managing multiple resources with grace — not tense juggling but rhythmic flow; Temperance turns complexity into dance when you stop resisting it and begin moving with its rhythm." },
  "14_66": { vi: "Điều Độ và Ba Tiền: pha chế của cộng tác, công việc được tinh chỉnh qua sự cân bằng — nhóm tốt nhất không phải là nhóm mạnh nhất mà là nhóm biết cân bằng những đóng góp đa dạng thành một tổng thể hài hòa.", en: "Temperance and Three of Pentacles: collaborative alchemy, work refined through balance — the best team is not the strongest one but the one that balances diverse contributions into a harmonious whole that serves a larger purpose." },
  "14_67": { vi: "Điều Độ và Bốn Tiền: điều tiết bản năng nắm chặt bằng trí tuệ của sự buông thả — Điều Độ không bảo bạn từ bỏ sự an toàn; nó mời bạn giữ và buông trong nhịp điệu, như hơi thở vào và ra.", en: "Temperance and Four of Pentacles: tempering the instinct to hold with the wisdom of release — Temperance does not ask you to abandon security; it invites you to hold and release in rhythm, like breathing in and breathing out." },
  "14_68": { vi: "Điều Độ và Năm Tiền: tìm sự cân bằng bên trong khó khăn, từng ngày một — không cần phải giải quyết tất cả cùng một lúc; Điều Độ dạy rằng vượt qua giai đoạn thiếu thốn bắt đầu bằng việc cân bằng những gì bạn có, không phải những gì bạn thiếu.", en: "Temperance and Five of Pentacles: finding equilibrium within hardship, one day at a time — not everything needs solving at once; Temperance teaches that surviving a period of lack begins with balancing what you have, not what is missing." },
  "14_69": { vi: "Điều Độ và Sáu Tiền: sự cân bằng hoàn hảo của việc cho và nhận — khi dòng chảy vật chất di chuyển tự do theo cả hai hướng, không có tích lũy và không có thiếu hụt, đây là trạng thái ân sủng mà Điều Độ hướng đến.", en: "Temperance and Six of Pentacles: the perfect balance of giving and receiving — when material flow moves freely in both directions, with no accumulation and no deprivation, this is the state of grace that Temperance is pointing toward." },
  "14_70": { vi: "Điều Độ và Bảy Tiền: sự chăm sóc kiên nhẫn, bản chất thực sự của nghệ thuật luyện kim — người thợ luyện kim không cưỡng bức kim loại biến đổi; họ tạo điều kiện đúng và đợi; đây là sức mạnh kỷ luật của người làm vườn thực thụ.", en: "Temperance and Seven of Pentacles: patient tending as the true nature of the alchemist's art — the alchemist does not force the metal to transform; they create the right conditions and wait; this is the disciplined strength of the true gardener." },
  "14_71": { vi: "Điều Độ và Tám Tiền: sự tinh chỉnh cần cù qua sự kiên nhẫn — tay nghề bậc thầy không đến từ việc làm nhanh hơn mà từ việc làm mỗi lần một ít tốt hơn; đây là thuật giả kim của tay nghề: kiên nhẫn, lặp đi lặp lại, và sự tinh tế ngày càng tăng.", en: "Temperance and Eight of Pentacles: diligent refinement through patience — master craft does not come from working faster but from working each time slightly better; this is the alchemy of the craftsperson: patience, repetition, and increasing subtlety." },
  "14_72": { vi: "Điều Độ và Chín Tiền: sự đủ đầy thanh thản đạt được qua nỗ lực có chừng mực và nhất quán — không phải qua sự bùng phát hay sự ép buộc mà qua dòng chảy đều đặn của công việc được cân bằng tốt qua nhiều năm.", en: "Temperance and Nine of Pentacles: quiet sufficiency achieved through measured and consistent effort — not through bursts or forcing but through the steady flow of well-balanced work sustained across many seasons." },
  "14_73": { vi: "Điều Độ và Mười Tiền: di sản được xây dựng qua sự cân bằng chứ không phải qua những cực đoan — điều trường tồn nhất không phải là được tạo ra trong những khoảnh khắc cuồng nhiệt mà trong sự kiên nhẫn bền bỉ của người biết đủ.", en: "Temperance and Ten of Pentacles: legacy built through balance rather than extremes — what lasts longest is not forged in moments of frenzy but in the patient persistence of those who understand moderation as a form of power." },

  // The Devil (15) × Pentacles 64–73
  "15_64": { vi: "Ác Quỷ và Át Tiền: cơ hội vật chất có thể trói buộc nếu không được tiếp cận với sự tỉnh thức — không phải mọi khởi đầu hứa hẹn đều dẫn đến tự do; hãy hỏi xem điều này sẽ nuôi dưỡng bạn hay giam cầm bạn trong dài hạn.", en: "The Devil and Ace of Pentacles: material opportunity that may bind if approached without awareness — not every promising beginning leads to freedom; ask whether this will nourish you or imprison you over the long term before accepting." },
  "15_65": { vi: "Ác Quỷ và Hai Tiền: bị mắc kẹt trong vòng tung hứng không hồi kết, không thể thoát ra — khi quản lý nguồn lực trở thành sự kiểm soát ám ảnh, đây không còn là sự linh hoạt mà là sự phụ thuộc; hãy nhìn xem điều gì thực sự đang giữ bạn lại.", en: "The Devil and Two of Pentacles: trapped in the endless juggle, unable to break free — when resource management becomes obsessive control, this is no longer flexibility but dependency; look honestly at what is truly keeping you in this loop." },
  "15_66": { vi: "Ác Quỷ và Ba Tiền: có kỹ năng nhưng bị nô dịch bởi công việc không còn phục vụ bạn — tay nghề của bạn là thật, nhưng khi bạn cảm thấy bị nhốt trong nó hơn là được trao quyền bởi nó, đây là tín hiệu cần chú ý.", en: "The Devil and Three of Pentacles: skilled but enslaved to work that no longer serves you — your craft is real, but when you feel imprisoned by it rather than empowered by it, this is a signal that deserves your honest attention." },
  "15_67": { vi: "Ác Quỷ và Bốn Tiền: cái bóng của sự tích trữ — nỗi sợ thiếu thốn đang điều khiển bạn nắm chặt hơn mức cần thiết; đây không phải là sự an toàn mà là sự giam cầm trong vỏ của chính mình; hãy hỏi điều gì đang thực sự kiểm soát bạn.", en: "The Devil and Four of Pentacles: the shadow of hoarding — fear of lack is driving you to grip tighter than necessary; this is not security but self-imposed imprisonment; ask honestly what is truly controlling you in this dynamic." },
  "15_68": { vi: "Ác Quỷ và Năm Tiền: khó khăn vật chất đang giữ bạn bị xích vào những mô thức sinh tồn — khi thiếu thốn trở thành bản sắc, khi 'tôi không có gì' trở thành câu chuyện bạn kể về mình, đây là xích của Ác Quỷ cần được nhìn nhận.", en: "The Devil and Five of Pentacles: material hardship keeping you chained to survival patterns — when deprivation becomes identity, when 'I have nothing' becomes the story you tell about yourself, these are the Devil's chains worth recognizing." },
  "15_69": { vi: "Ác Quỷ và Sáu Tiền: sự mất cân bằng quyền lực trong mối quan hệ cho và nhận — khi một người luôn kiểm soát nguồn lực và người kia luôn phụ thuộc, cả hai đều bị xích vào một động lực không lành mạnh cần phá vỡ.", en: "The Devil and Six of Pentacles: power imbalance in the giving and receiving dynamic — when one person always controls resources and another always depends, both are chained to an unhealthy dynamic that needs to be broken." },
  "15_70": { vi: "Ác Quỷ và Bảy Tiền: bị mắc kẹt trong sự chờ đợi một vụ thu hoạch không bao giờ thỏa mãn — khi 'chỉ cần thêm một chút nữa' trở thành câu thần chú bất tận, đây là sự trói buộc vật chất của Ác Quỷ đang hoạt động.", en: "The Devil and Seven of Pentacles: trapped waiting for a harvest that will never be enough — when 'just a little more' becomes the endless mantra, this is the Devil's material binding in operation; the finish line keeps moving forward." },
  "15_71": { vi: "Ác Quỷ và Tám Tiền: công việc ám ảnh, tay nghề như một chứng nghiện hoặc sự né tránh — khi bạn không thể dừng làm việc dù muốn, khi công việc lấp đầy khoảng trống cảm xúc mà bạn không dám nhìn, đây là xích cần được nhìn thẳng.", en: "The Devil and Eight of Pentacles: compulsive work, craft functioning as addiction or avoidance — when you cannot stop working even when you want to, when work fills an emotional void you are afraid to face, these are chains worth examining." },
  "15_72": { vi: "Ác Quỷ và Chín Tiền: sự thoải mái vật chất che giấu sự giam cầm tinh thần — mọi thứ từ bên ngoài trông như thành công và độc lập, nhưng bên trong bạn cảm thấy rỗng hoặc bị mắc kẹt; đây là nghịch lý đau đớn nhất của Ác Quỷ.", en: "The Devil and Nine of Pentacles: material comfort masking spiritual imprisonment — everything from the outside looks like success and independence, but inside you feel empty or trapped; this is the Devil's most painful paradox." },
  "15_73": { vi: "Ác Quỷ và Mười Tiền: di sản được xây dựng trên những xích xiềng, những mô thức trói buộc được thừa kế qua các thế hệ — đôi khi điều gia đình truyền lại không phải là sự thịnh vượng mà là những tín ngưỡng về tiền bạc và giá trị bản thân vô hình nhưng ràng buộc sâu sắc.", en: "The Devil and Ten of Pentacles: legacy built on chains, inherited patterns of bondage passed across generations — sometimes what families transmit is not prosperity but invisible beliefs about money and self-worth that bind just as deeply." },

  // ─── TIER 3d — Majors 16–21 × Pentacles Numbered (60 pairs) ────────────────

  // The Tower (16) × Pentacles 64–73
  "16_64": { vi: "Tháp và Át Tiền: sự sụp đổ dọn sạch không gian cho nền móng vật chất hoàn toàn mới — điều đang bị phá hủy không phải là cơ hội mà là những cấu trúc giả tạo đã ngăn cản hạt giống thực sự nảy mầm.", en: "The Tower and Ace of Pentacles: collapse clearing space for an entirely new material foundation — what is being destroyed is not the opportunity but the false structures that were preventing the real seed from taking root." },
  "16_65": { vi: "Tháp và Hai Tiền: sự đột phá đánh sập màn biểu diễn cân bằng cũ — cách bạn tung hứng các nguồn lực đã không còn hiệu quả từ lâu; sự gián đoạn này là cơ hội để xây dựng hệ thống quản lý thực sự bền vững.", en: "The Tower and Two of Pentacles: sudden disruption bringing down the old balancing act — the way you have been juggling resources has not been working for a long time; this interruption is the chance to build what is truly sustainable." },
  "16_66": { vi: "Tháp và Ba Tiền: sự tiết lộ đột ngột làm rung chuyển nền tảng của dự án — không phải mọi sự sụp đổ đều là thảm họa; đôi khi công việc cộng tác cần bị phá vỡ để được xây dựng lại với sự trung thực và mục đích rõ ràng hơn.", en: "The Tower and Three of Pentacles: a sudden revelation shaking the project's foundations — not every collapse is disaster; sometimes collaborative work needs to be broken apart to be rebuilt with greater honesty and clearer purpose." },
  "16_67": { vi: "Tháp và Bốn Tiền: Tháp giáng xuống pháo đài của sự tích trữ, đập vỡ ảo tưởng về sự an toàn — không có bức tường nào đủ dày để chống lại sự thay đổi mà cuộc sống đang đòi hỏi; hãy buông tay trước khi Tháp quyết định cho bạn.", en: "The Tower and Four of Pentacles: the Tower striking the fortress of hoarding, shattering the illusion of security — no wall is thick enough to hold back the change life is demanding; release before the Tower decides for you." },
  "16_68": { vi: "Tháp và Năm Tiền: mất mát vật chất đột ngột, nhưng sự xóa sạch hé lộ những gì chưa bao giờ thực sự hoạt động — đây không phải là thảm họa thuần túy mà là sự kết thúc bắt buộc của điều đã suy yếu từ lâu.", en: "The Tower and Five of Pentacles: sudden material loss, but the clearing reveals what was never truly working — this is not pure disaster but the forced ending of something that had long been failing beneath the surface." },
  "16_69": { vi: "Tháp và Sáu Tiền: sự xáo trộn trong các cấu trúc quyền lực xung quanh việc cho và nhận — khi hệ thống phân phối không công bằng bị phá vỡ, đây là cơ hội để thiết lập lại một mối quan hệ lành mạnh hơn với nguồn lực.", en: "The Tower and Six of Pentacles: upheaval in the power structures around giving and receiving — when an unjust distribution system is broken apart, this is the chance to establish a healthier relationship with resources from the ground up." },
  "16_70": { vi: "Tháp và Bảy Tiền: mùa thu hoạch bị mất đột ngột, mọi thứ phải được đánh giá lại từ đầu — điều khó khăn nhất là nhận ra rằng công việc bạn đã đầu tư không sai; chỉ là mảnh đất cần được thay đổi trước khi tiếp tục.", en: "The Tower and Seven of Pentacles: the harvest suddenly lost, everything requiring reassessment from the beginning — the hardest recognition is that the work you invested was not wrong; only the ground needs to change before continuing." },
  "16_71": { vi: "Tháp và Tám Tiền: tay nghề bị gián đoạn hoặc phá hủy, phải được xây dựng lại theo cách khác — nghệ nhân thực sự không mất đi kỹ năng khi mọi thứ sụp đổ; họ mang theo nó và xây dựng lại trên nền móng vững chắc hơn.", en: "The Tower and Eight of Pentacles: craft disrupted or destroyed, requiring rebuilding in a different form — the true craftsperson does not lose their skill when things collapse; they carry it forward and build again on firmer ground." },
  "16_72": { vi: "Tháp và Chín Tiền: sự độc lập được xây dựng khó nhọc bị chấn động, nhưng không có gì giả tạo có thể sống sót qua Tháp — điều sụp đổ chưa bao giờ là nền tảng thực sự của tự do; những gì còn lại sau đó mới chính là điều bạn cần giữ.", en: "The Tower and Nine of Pentacles: hard-won independence shaken, but nothing false survives the Tower — what collapses was never the true foundation of freedom; what remains afterward is precisely what is worth keeping." },
  "16_73": { vi: "Tháp và Mười Tiền: những cấu trúc di sản sụp đổ, những mô thức thế hệ bị phá vỡ — đây không chỉ là mất mát mà còn là sự giải phóng; đôi khi điều tốt nhất một thế hệ có thể làm là phá bỏ những gì không còn phục vụ thế hệ tiếp theo.", en: "The Tower and Ten of Pentacles: legacy structures collapsing, generational patterns broken open — this is not only loss but also liberation; sometimes the finest gift one generation can offer the next is dismantling what no longer serves them." },

  // The Star (17) × Pentacles 64–73
  "17_64": { vi: "Ngôi Sao và Át Tiền: sự đổi mới và hy vọng cho khởi đầu vật chất mới sau cơn bão — Ngôi Sao không hứa hẹn sự giàu có tức thì; nó cung cấp ánh sáng dẫn đường để bạn biết hạt giống này đáng được chăm sóc.", en: "The Star and Ace of Pentacles: renewal and hope for a new material beginning after the storm — the Star does not promise immediate wealth; it offers guiding light so you know this seed is worth tending through what comes next." },
  "17_65": { vi: "Ngôi Sao và Hai Tiền: sự duyên dáng và nhẹ nhàng trong việc điều phối các nguồn lực cạnh tranh — khi bạn tiếp cận sự cân bằng với sự tin tưởng hơn là lo lắng, những đòi hỏi phức tạp nhất cũng trở nên dễ thở hơn.", en: "The Star and Two of Pentacles: ease and grace in managing competing resources — when you approach balance with trust rather than anxiety, even the most complex competing demands begin to feel less like burden and more like rhythm." },
  "17_66": { vi: "Ngôi Sao và Ba Tiền: công việc cộng tác được soi sáng bởi mục đích cao hơn — khi mỗi thành viên nhóm được truyền cảm hứng bởi điều gì đó lớn hơn phần thưởng cá nhân, chất lượng của những gì họ cùng tạo ra thay đổi đáng kể.", en: "The Star and Three of Pentacles: collaborative work illuminated by higher purpose — when each team member is inspired by something larger than personal reward, the quality of what they create together changes in ways that are genuinely remarkable." },
  "17_67": { vi: "Ngôi Sao và Bốn Tiền: mở bàn tay ra nhẹ nhàng, được dẫn dắt bởi hy vọng thay vì nỗi sợ — Ngôi Sao dạy rằng sự an toàn thực sự không nằm trong những gì bạn nắm giữ mà trong lòng tin rằng bạn sẽ có đủ những gì cần.", en: "The Star and Four of Pentacles: opening the hand gently, guided by hope rather than fear — the Star teaches that true security does not lie in what you hold but in the trust that you will have enough of what genuinely matters." },
  "17_68": { vi: "Ngôi Sao và Năm Tiền: sau giai đoạn thiếu thốn, quá trình chữa lành bắt đầu — Ngôi Sao không xóa bỏ khó khăn ngay lập tức; nó thắp lên điều bạn cần nhất để tiếp tục: niềm tin rằng tình trạng này sẽ thay đổi.", en: "The Star and Five of Pentacles: after the period of hardship, healing begins — the Star does not erase difficulty immediately; it lights what you need most to continue: the belief that this condition is genuinely going to change." },
  "17_69": { vi: "Ngôi Sao và Sáu Tiền: dòng chảy hào phóng từ trái tim đã phục hồi lòng tin — khi bạn cho đi từ sự phong phú nội tâm hơn là từ nghĩa vụ, năng lượng của món quà thay đổi và người nhận cảm nhận được sự khác biệt đó.", en: "The Star and Six of Pentacles: generous flow from a heart restored to trust — when you give from inner abundance rather than obligation, the energy of the gift changes and the receiver genuinely feels the difference." },
  "17_70": { vi: "Ngôi Sao và Bảy Tiền: sự chờ đợi kiên nhẫn được dẫn dắt bởi hy vọng, tin tưởng rằng mùa thu hoạch sẽ đến — khó khăn nhất không phải là chờ đợi mà là chờ đợi với trái tim mở, không phải trong lo lắng mà trong sự tin tưởng bình thản.", en: "The Star and Seven of Pentacles: patient waiting guided by hope, trusting the harvest will arrive — the hardest part is not waiting but waiting with an open heart, not in anxiety but in quiet, grounded trust." },
  "17_71": { vi: "Ngôi Sao và Tám Tiền: tay nghề được truyền cảm hứng, công việc được làm với mục đích và tầm nhìn đổi mới — khi nghệ nhân tìm lại lý do tại sao họ yêu công việc, ngay cả những chi tiết tẻ nhất cũng mang ý nghĩa mới.", en: "The Star and Eight of Pentacles: inspired craft, work infused with renewed purpose and vision — when the craftsperson rediscovers why they love the work, even the most tedious details carry new meaning and the quality reflects it." },
  "17_72": { vi: "Ngôi Sao và Chín Tiền: vẻ đẹp thanh thản và sự sung túc vật chất sau những thử thách — đây không phải là may mắn mà là sự hoàn thành của một hành trình dài; hãy để mình tận hưởng khoảnh khắc này đầy đủ và không chút nghi ngờ.", en: "The Star and Nine of Pentacles: serene beauty and material self-sufficiency after trials — this is not luck but the completion of a long journey; allow yourself to enjoy this moment fully and without the guilt of wondering if you deserve it." },
  "17_73": { vi: "Ngôi Sao và Mười Tiền: di sản của sự chữa lành và hy vọng tiếp tục vượt ra ngoài cá nhân — những gì bạn xây dựng với lòng tin và sự chính trực không chỉ nuôi dưỡng bạn; nó trở thành ngọn đèn cho những người đến sau.", en: "The Star and Ten of Pentacles: a legacy of healing and hope that continues beyond the individual — what you build with trust and integrity does not only nourish you; it becomes a guiding light for those who come after." },

  // The Moon (18) × Pentacles 64–73
  "18_64": { vi: "Mặt Trăng và Át Tiền: sự không chắc chắn bao phủ khởi đầu vật chất mới — nền tảng của cơ hội này không rõ ràng như vẻ ngoài; hãy tiến từng bước nhỏ trong ánh sáng mờ này thay vì cam kết toàn bộ khi chưa thấy rõ.", en: "The Moon and Ace of Pentacles: uncertainty surrounding a new material beginning — the foundations of this opportunity are not as clear as they appear; proceed in small steps within this dim light rather than committing fully before you can see." },
  "18_65": { vi: "Mặt Trăng và Hai Tiền: ảo tưởng về sự cân bằng — những gì bạn nghĩ là mình đang quản lý tốt có thể là bức tranh méo mó dưới ánh trăng; hãy tìm kiếm ánh sáng rõ ràng hơn trước khi kết luận rằng mọi thứ đang ổn.", en: "The Moon and Two of Pentacles: illusions about balance — what you believe you are managing well may be a distorted picture under moonlight; seek clearer illumination before concluding that everything is under control." },
  "18_66": { vi: "Mặt Trăng và Ba Tiền: những căng thẳng ẩn giấu bên dưới bề mặt của công việc cộng tác — không phải mọi thứ đã được nói ra; hãy lắng nghe những gì không được nói và kiểm tra xem có điều gì đang bị che giấu trong nhóm không.", en: "The Moon and Three of Pentacles: hidden tensions beneath the surface of collaborative work — not everything has been spoken; listen for what is left unsaid and examine whether something is being concealed or avoided within the group." },
  "18_67": { vi: "Mặt Trăng và Bốn Tiền: giữ chặt những thứ từ nỗi sợ không rõ ràng — bạn không chắc mình đang bảo vệ điều gì; hãy mang ánh đèn vào bóng tối của sự bám víu này và xem thứ thực sự đang được giữ là gì.", en: "The Moon and Four of Pentacles: holding tightly to things from a fear that is not clearly defined — you are not certain what you are protecting; bring light into the shadow of this clinging and see what is truly being guarded." },
  "18_68": { vi: "Mặt Trăng và Năm Tiền: nỗi sợ và sự mơ hồ làm sâu thêm hoàn cảnh khó khăn vật chất — tình trạng thực tế có thể không tệ như nó trông dưới ánh trăng lo lắng; hãy tìm kiếm bức tranh rõ ràng hơn trước khi hành động từ nỗi hoảng loạn.", en: "The Moon and Five of Pentacles: fear and confusion deepening the experience of material hardship — the actual situation may not be as dire as it appears under anxious moonlight; seek a clearer picture before acting from panic." },
  "18_69": { vi: "Mặt Trăng và Sáu Tiền: những động cơ không rõ ràng trong mối quan hệ cho và nhận — hãy hỏi điều gì thực sự đang xảy ra bên dưới bề mặt; không phải mọi sự hào phóng đều vô điều kiện và không phải mọi sự cần giúp đỡ đều được nói lên.", en: "The Moon and Six of Pentacles: unclear motives beneath the surface of giving and receiving — ask what is genuinely happening below the appearance; not all generosity is unconditional and not all need for help is being spoken aloud." },
  "18_70": { vi: "Mặt Trăng và Bảy Tiền: khó khăn trong việc đánh giá thực sự những gì công việc đã tạo ra — dưới ánh sáng mờ ảo của sự tự lừa dối, cả thành công lẫn thất bại đều có thể bị hiểu sai; hãy tìm kiếm quan điểm trung thực từ bên ngoài.", en: "The Moon and Seven of Pentacles: difficulty accurately assessing what the work has truly produced — under the dim light of self-deception, both success and failure can be misread; seek honest perspective from outside yourself." },
  "18_71": { vi: "Mặt Trăng và Tám Tiền: làm việc trong bóng tối, không rõ tay nghề đang thực sự phát triển theo hướng nào — đây không nhất thiết là dấu hiệu xấu; đôi khi kỹ năng phát triển trong bóng tối trước khi nó sẵn sàng được nhìn thấy.", en: "The Moon and Eight of Pentacles: working in darkness, uncertain whether the craft is genuinely developing — this is not necessarily a bad sign; sometimes skill develops in the dark before it is ready to be seen by anyone." },
  "18_72": { vi: "Mặt Trăng và Chín Tiền: sự độc lập có thể là ảo tưởng; hãy kiểm tra những gì thực sự nằm bên dưới — vẻ ngoài của sự tự túc đôi khi che giấu sự phụ thuộc ẩn giấu hoặc sự cô lập mà bạn chưa sẵn sàng nhìn nhận.", en: "The Moon and Nine of Pentacles: the independence may be illusory; examine what is genuinely underneath — the appearance of self-sufficiency sometimes conceals hidden dependency or isolation you have not yet been willing to acknowledge." },
  "18_73": { vi: "Mặt Trăng và Mười Tiền: những dòng chảy ngầm ẩn giấu trong di sản gia đình, những điều chưa được nói — những gì được truyền lại giữa các thế hệ không chỉ là tài sản hữu hình mà còn là những bí mật, những tổn thương, và những mô thức chưa bao giờ được đặt tên.", en: "The Moon and Ten of Pentacles: hidden undercurrents within family legacy, the things that have never been spoken — what is transmitted across generations is not only tangible wealth but also secrets, wounds, and patterns that have never been named." },

  // The Sun (19) × Pentacles 64–73
  "19_64": { vi: "Mặt Trời và Át Tiền: khởi đầu vật chất rực rỡ và tràn đầy sức sống — đây là thời điểm lý tưởng để gieo hạt giống; ánh sáng đang ủng hộ bạn và năng lượng của khoảnh khắc này xứng đáng được đón nhận với niềm vui.", en: "The Sun and Ace of Pentacles: a radiant and vital material beginning — this is the ideal moment to plant the seed; the light is supporting you and the energy of this moment deserves to be received with genuine joy and confidence." },
  "19_65": { vi: "Mặt Trời và Hai Tiền: sự thoải mái và sức sống trong việc điều phối nhiều trách nhiệm — khi bạn tiếp cận những đòi hỏi cạnh tranh với năng lượng dồi dào hơn là kiệt sức, chúng biến đổi từ gánh nặng thành nhịp điệu của cuộc sống.", en: "The Sun and Two of Pentacles: ease and vitality in managing multiple responsibilities — when you approach competing demands from a place of abundance rather than exhaustion, they transform from burdens into the living rhythm of a full life." },
  "19_66": { vi: "Mặt Trời và Ba Tiền: một dự án cộng tác phát triển rực rỡ dưới ánh sáng — khi mỗi thành viên mang theo nhiệt huyết và sự tự tin, những gì họ cùng tạo ra không chỉ là tốt mà là điều gì đó thực sự đáng để kỷ niệm.", en: "The Sun and Three of Pentacles: a collaborative project thriving in the light — when each member brings genuine enthusiasm and confidence to the work, what they create together is not merely good but something truly worth celebrating." },
  "19_67": { vi: "Mặt Trời và Bốn Tiền: buông lỏng sự nắm chặt với sự tự tin, sự an toàn tỏa sáng từ bên trong — khi bạn biết mình đủ, khi ánh sáng của Mặt Trời chiếu vào trái tim, bàn tay tự nhiên mở ra mà không cần nỗ lực.", en: "The Sun and Four of Pentacles: loosening the grip with confidence, security radiating from within — when you know yourself to be enough, when the Sun's light enters the heart, the hand opens naturally without requiring effort or convincing." },
  "19_68": { vi: "Mặt Trời và Năm Tiền: Mặt Trời mọc lên sau giai đoạn thiếu thốn, hơi ấm và sự phục hồi bắt đầu — bóng tối đã thực sự, nhưng ánh sáng đang trở lại; hãy hướng về phía nó và để sự ấm áp của nó bắt đầu làm tan chảy những gì đã đóng băng.", en: "The Sun and Five of Pentacles: the Sun rising on a period of hardship, warmth and recovery beginning — the darkness was real, but the light is returning; turn toward it and allow its warmth to begin thawing what has been frozen." },
  "19_69": { vi: "Mặt Trời và Sáu Tiền: sự hào phóng dồi dào tỏa ra ngoài mà không tính toán — khi bạn cho đi từ nơi thực sự có thừa, không có gì để sợ mất; đây là niềm vui thuần túy của việc chia sẻ ánh sáng.", en: "The Sun and Six of Pentacles: generous abundance radiating outward without calculation — when you give from a place of genuine surplus, there is nothing to fear losing; this is the pure joy of sharing light with those who need it." },
  "19_70": { vi: "Mặt Trời và Bảy Tiền: mùa thu hoạch sẵn sàng đón ánh sáng, những kết quả được xác nhận và ăn mừng — những gì bạn đã kiên nhẫn vun đắp giờ đang đứng dưới ánh mặt trời; đây là thời điểm nhìn nhận thành quả và cho phép bản thân cảm thấy tự hào.", en: "The Sun and Seven of Pentacles: the harvest ready to receive the light, results confirmed and celebrated — what you have patiently tended is now standing in the sunlight; this is the moment to acknowledge the fruits and allow yourself to feel pride." },
  "19_71": { vi: "Mặt Trời và Tám Tiền: niềm vui trong tay nghề, công việc phù hợp với sức sống sâu nhất của người thợ — khi bạn yêu những gì mình làm và làm tốt, mỗi ngày làm việc là biểu hiện của điều gì đó quý giá và đáng trân trọng.", en: "The Sun and Eight of Pentacles: joyful mastery, craft aligned with the craftsperson's deepest vitality — when you love what you do and do it well, each day of work is an expression of something precious and worth being genuinely grateful for." },
  "19_72": { vi: "Mặt Trời và Chín Tiền: sự tự túc rạng rỡ, sự độc lập được tận hưởng trọn vẹn và không chút tội lỗi — đây là thành quả của công sức thực sự; hãy để Mặt Trời soi sáng điều bạn đã xây dựng và nhận ra rằng bạn xứng đáng với điều này.", en: "The Sun and Nine of Pentacles: radiant self-sufficiency, independence enjoyed fully and without guilt — this is the fruit of genuine effort; let the Sun illuminate what you have built and recognize clearly that you are deserving of this." },
  "19_73": { vi: "Mặt Trời và Mười Tiền: di sản của sự ấm áp và thịnh vượng được kỷ niệm qua nhiều thế hệ — những gia đình được xây dựng trên niềm vui thực sự và sự hào phóng thực sự để lại dấu ấn khác với những gia đình được xây dựng trên sự tích lũy thuần túy.", en: "The Sun and Ten of Pentacles: a legacy of warmth and abundance celebrated across generations — families built on genuine joy and real generosity leave a different mark than those built on accumulation alone; this is that rarer and richer inheritance." },

  // Judgement (20) × Pentacles 64–73
  "20_64": { vi: "Phán Xét và Át Tiền: tiếng gọi đến một con đường vật chất mới không thể bị phớt lờ — đây không phải là cơ hội thông thường; đây là sự triệu hồi từ điều gì đó sâu hơn, và câu trả lời của bạn sẽ định hình hướng đi của một chương hoàn toàn mới.", en: "Judgement and Ace of Pentacles: a calling to a new material path that cannot be ignored — this is not an ordinary opportunity; it is a summons from something deeper, and your answer will shape the direction of an entirely new chapter." },
  "20_65": { vi: "Phán Xét và Hai Tiền: sự thức tỉnh về cách bạn đã quản lý các nguồn lực — khoảnh khắc reckoning đã đến; không phải để phán xét mà để nhìn thẳng vào những mô thức thực sự và quyết định xem bạn muốn tiếp tục theo chúng hay không.", en: "Judgement and Two of Pentacles: an awakening about how you have truly been managing your resources — the moment of reckoning has arrived; not for judgment but to see the actual patterns clearly and decide whether you choose to continue them." },
  "20_66": { vi: "Phán Xét và Ba Tiền: sự đánh giá về mục đích thực sự của công việc và liệu nó có trả lời tiếng gọi sâu hơn không — khi bạn đặt câu hỏi liệu tay nghề của mình đang phục vụ điều gì thực sự quan trọng, đây là câu hỏi của Phán Xét.", en: "Judgement and Three of Pentacles: an evaluation of the work's true purpose and whether it answers a deeper calling — when you ask whether your craft is serving what genuinely matters, you are asking the question that Judgement demands." },
  "20_67": { vi: "Phán Xét và Bốn Tiền: sự thức tỉnh về những gì bạn đã tích trữ và chi phí thực sự của mô thức đó — Phán Xét không kết tội; nó chiếu sáng với độ rõ nét mà bạn không thể phủ nhận những gì sự nắm chặt đã thực sự lấy đi của bạn.", en: "Judgement and Four of Pentacles: awakening to what you have been hoarding and the true cost of that pattern — Judgement does not condemn; it illuminates with a clarity you cannot deny what the clinging has actually been taking from you." },
  "20_68": { vi: "Phán Xét và Năm Tiền: khoảnh khắc reckoning về những mô thức đã dẫn đến sự thiếu thốn — không phải để tự trách mà để nhìn thấy rõ ràng; sự hiểu biết này là điều kiện cần thiết để phá vỡ chu kỳ và bước sang trang mới.", en: "Judgement and Five of Pentacles: a moment of reckoning about the patterns that led to hardship — not for self-blame but for clear sight; this understanding is the necessary condition for breaking the cycle and genuinely stepping into something new." },
  "20_69": { vi: "Phán Xét và Sáu Tiền: tiếng gọi đến mức độ hào phóng cao hơn, sự thức tỉnh về sức mạnh của sự đóng góp — khi bạn nhận ra rằng những gì bạn có thể đóng góp là quan trọng, bạn không thể giả vờ rằng việc giữ lại nó là trung lập.", en: "Judgement and Six of Pentacles: called to a higher level of generosity, awakening to the power of genuine contribution — when you recognize that what you have to offer truly matters, you can no longer pretend that withholding it is a neutral act." },
  "20_70": { vi: "Phán Xét và Bảy Tiền: sự đánh giá cuối cùng về những gì công việc dài hơi thực sự đang hướng đến — đây là khoảnh khắc dừng lại và hỏi không chỉ 'nó đang phát triển không?' mà còn 'nó đang phát triển thành điều gì, và điều đó có phải là điều tôi thực sự muốn không?'", en: "Judgement and Seven of Pentacles: the final evaluation of what the long work has truly been building toward — this is the moment to ask not only 'is it growing?' but 'growing into what, and is that genuinely what I want to create?'" },
  "20_71": { vi: "Phán Xét và Tám Tiền: tiếng gọi đánh giá xem tay nghề của bạn có đang trả lời thiên chức thực sự của bạn không — sự thành thạo kỹ thuật không phải lúc nào cũng tương đương với việc đang sống theo mục đích; Phán Xét hỏi liệu hai điều này có phù hợp với nhau không.", en: "Judgement and Eight of Pentacles: called to evaluate whether your craft is answering your true vocation — technical mastery is not always the same as living in alignment with purpose; Judgement asks whether these two things genuinely match." },
  "20_72": { vi: "Phán Xét và Chín Tiền: sự thức tỉnh về những gì sự độc lập của bạn thực sự đang chuẩn bị bạn cho điều gì — sự tự túc bạn đã xây dựng là bước đệm cho điều gì đó lớn hơn; Phán Xét hỏi bạn có sẵn sàng nghe tiếng gọi đó không.", en: "Judgement and Nine of Pentacles: awakening to what your independence has truly been preparing you for — the self-sufficiency you have built is a platform for something larger; Judgement asks whether you are ready to hear and answer that call." },
  "20_73": { vi: "Phán Xét và Mười Tiền: sự reckoning của một di sản — những gì đã được xây dựng, liệu nó có thực sự phục vụ không, và điều gì cần được giữ lại hay buông bỏ để những gì tiếp theo có thể xứng đáng hơn với những gì đến trước.", en: "Judgement and Ten of Pentacles: the reckoning of a legacy — what has been built, whether it truly serves, and what must be kept or released so that what comes next is genuinely worthy of what came before." },

  // The World (21) × Pentacles 64–73
  "21_64": { vi: "Thế Giới và Át Tiền: một chu kỳ hoàn thành tạo ra không gian cho hạt giống vật chất mới được gieo — mỗi sự kết thúc thực sự là một sự khởi đầu; hạt giống bạn đang gieo hôm nay được trồng trên nền đất màu mỡ từ những gì đã hoàn thành.", en: "The World and Ace of Pentacles: a completed cycle creating the perfect space for a new material seed — every genuine ending is a beginning; the seed you plant today is sown in the fertile soil of everything that has been completed." },
  "21_65": { vi: "Thế Giới và Hai Tiền: sự thành thạo về cân bằng, màn tung hứng được giải quyết thành dòng chảy tự nhiên — khi bạn đạt đến sự hoàn thành trong nghệ thuật điều phối, nó không còn là nỗ lực nữa; nó trở thành một loại vũ điệu.", en: "The World and Two of Pentacles: mastery of balance, the juggling act resolving into natural flow — when you reach completion in the art of managing competing demands, it ceases to be effort; it becomes a kind of effortless dance." },
  "21_66": { vi: "Thế Giới và Ba Tiền: một kiệt tác đã hoàn thành, đỉnh cao của nỗ lực cộng tác — khi tất cả các kỹ năng hội tụ và thời điểm chín muồi, những gì nhóm tạo ra cùng nhau đạt đến điều hiếm hoi: sự hoàn thiện thực sự.", en: "The World and Three of Pentacles: a completed masterwork, the culmination of collaborative effort — when all skills converge and the timing is right, what the group creates together achieves something rare: genuine completion and wholeness." },
  "21_67": { vi: "Thế Giới và Bốn Tiền: sự trọn vẹn cho phép buông bỏ; bạn không còn cần nắm chặt vì bạn đã toàn vẹn — khi bạn thực sự hoàn thành, khi bạn không thiếu gì, bàn tay tự nhiên mở ra vì không có gì cần bảo vệ nữa.", en: "The World and Four of Pentacles: wholeness enabling release; you no longer need to grip because you are genuinely complete — when you are truly whole, when nothing is missing, the hand opens naturally because there is nothing left that needs protecting." },
  "21_68": { vi: "Thế Giới và Năm Tiền: giai đoạn khó khăn đang đến điểm hoàn thành của nó, chu kỳ xoay về phía thịnh vượng — không phải mọi sự kết thúc đều diễn ra đột ngột; đôi khi điều vĩ đại nhất là nhận ra rằng thời kỳ thiếu thốn đã đến ngày cuối cùng của nó.", en: "The World and Five of Pentacles: the period of hardship reaching its completion, the cycle turning toward abundance — not every ending comes suddenly; sometimes the greatest moment is recognizing that the season of lack has finally reached its last day." },
  "21_69": { vi: "Thế Giới và Sáu Tiền: sự hoàn thành của một chu kỳ cho và nhận, vòng tròn khép lại — khi bạn đã từng là cả người cho và người nhận, khi bạn đã đi trọn vòng, bạn hiểu dòng chảy này theo cách không thể được dạy bằng lý thuyết.", en: "The World and Six of Pentacles: the completion of a giving and receiving cycle, the circle closing — when you have been both giver and receiver, when you have traveled the full circle, you understand this flow in a way that cannot be taught in theory." },
  "21_70": { vi: "Thế Giới và Bảy Tiền: mùa thu hoạch của một chu kỳ đã hoàn thành, sự biểu hiện đầy đủ nhất của công việc kiên nhẫn — đây không chỉ là thời điểm thu hoạch; đây là khoảnh khắc nhận ra rằng toàn bộ hành trình đã dẫn đến đúng nơi này.", en: "The World and Seven of Pentacles: the harvest of a completed cycle, the fullest expression of patient work — this is not merely the time of harvest; it is the moment of recognizing that the entire journey was leading precisely here." },
  "21_71": { vi: "Thế Giới và Tám Tiền: tay nghề đạt đến đỉnh cao của sự thành thạo, công việc hoàn thành tiềm năng trọn vẹn của nó — bậc thầy không phải là người không còn gì để học; họ là người đã hoàn thành đủ để biết chính xác những gì còn lại.", en: "The World and Eight of Pentacles: craft reaching its highest mastery, the work fulfilling its complete potential — the master is not one who has nothing left to learn; they are one who has completed enough to know precisely what remains." },
  "21_72": { vi: "Thế Giới và Chín Tiền: sự toàn vẹn và sự tự túc vật chất như điểm hoàn thành của một hành trình sống — đây là khoảnh khắc hiếm có khi bên trong và bên ngoài đều phù hợp nhau; hãy đứng trong sự viên mãn này và nhận ra rằng điều này là thật.", en: "The World and Nine of Pentacles: wholeness and material self-sufficiency as the completion of a life journey — this is the rare moment when inner and outer are in alignment; stand in this fullness and allow yourself to recognize that this is genuinely real." },
  "21_73": { vi: "Thế Giới và Mười Tiền: sự hoàn thành trọn vẹn nhất của hành trình vật chất, di sản đạt đến sự viên mãn của nó — đây không phải là điểm kết thúc mà là điểm tích hợp; tất cả những gì đã được xây dựng, cho đi, và truyền lại giờ tạo thành một tổng thể có ý nghĩa.", en: "The World and Ten of Pentacles: the fullest completion of the material journey, legacy reaching its wholeness — this is not an ending but an integration; everything that has been built, given, and passed forward now forms a meaningful and coherent whole." },

  // ─── TIER 4: Minor × Minor, Same Suit (364 pairs) ──────────────────────────
  // ─── TIER 4a: Wands × Wands Same-Suit (91 pairs) ───────────────────────────

  // Ace of Wands (22) × Wands
  "22_23": { vi: "Át Gậy và Hai Gậy: tia lửa ban đầu gặp tầm nhìn táo bạo — trước khi hành động, hãy hướng ngọn lửa này vào điều gì đó xứng đáng; bước đầu tiên là chọn hướng đi chứ không phải chỉ đốt cháy.", en: "Ace of Wands and Two of Wands: the initial spark meeting bold vision — before you act, point this fire at something worthy; the first step is choosing a direction, not simply igniting everything around you." },
  "22_24": { vi: "Át Gậy và Ba Gậy: ngọn lửa mới đã hướng mắt ra những chân trời xa — khởi đầu này không nhỏ bé; nó mang theo tham vọng của người đã hình dung rõ ràng những gì chương tiếp theo có thể trở thành.", en: "Ace of Wands and Three of Wands: the new flame already looking outward toward distant horizons — this beginning is not small; it carries the ambition of someone who has already clearly imagined what the next chapter holds." },
  "22_25": { vi: "Át Gậy và Bốn Gậy: năng lượng sáng tạo mới được đón nhận vào nơi thuộc về — những khởi đầu sáng tạo bền vững nhất không phải là những cái được khởi động trong cô đơn mà là những cái bén rễ trong cộng đồng và sự ăn mừng.", en: "Ace of Wands and Four of Wands: new creative energy welcomed into a place of belonging — the most durable creative beginnings are not launched in isolation but are rooted in community, celebration, and a foundation already built." },
  "22_26": { vi: "Át Gậy và Năm Gậy: cảm hứng bùng lên giữa hỗn loạn và cạnh tranh — tia lửa có thật, nhưng môi trường đang sôi sục; hãy bảo vệ ngọn lửa mới đủ lâu để nó bắt được trước khi mọi cơn gió kịp thổi tắt.", en: "Ace of Wands and Five of Wands: inspiration igniting in the middle of chaos and competition — the spark is real, but the environment is turbulent; protect the new flame long enough for it to catch before every wind reaches it." },
  "22_27": { vi: "Át Gậy và Sáu Gậy: năng lượng mới đã hướng thẳng về phía sự công nhận và chiến thắng — khởi đầu này mang theo sự tự tin của người đã biết mình có khả năng hoàn thành điều họ đang bắt đầu.", en: "Ace of Wands and Six of Wands: new energy already pointing toward recognition and victory — this beginning carries the confidence of someone who already knows they are capable of completing what they are now starting." },
  "22_28": { vi: "Át Gậy và Bảy Gậy: tia lửa mới phải bảo vệ chính nó ngay từ đầu — không phải mọi khởi đầu sáng tạo đều được chào đón; một số phải được che chở bằng sự kiên định trước khi đủ mạnh để đứng vững một mình.", en: "Ace of Wands and Seven of Wands: the new spark needing to defend itself from the start — not every creative beginning is welcomed; some must be protected with conviction before they are strong enough to stand without sheltering." },
  "22_29": { vi: "Át Gậy và Tám Gậy: tia lửa bùng lên và ngọn lửa lan rộng nhanh chóng — ý tưởng mới này không chờ đợi; nó phóng thẳng vào hành động với tốc độ khiến ngay cả người khởi xướng nó cũng phải ngạc nhiên.", en: "Ace of Wands and Eight of Wands: the spark ignites and the fire spreads with startling speed — this new idea does not wait; it launches directly into motion at a pace that surprises even the person who originally started it." },
  "22_30": { vi: "Át Gậy và Chín Gậy: khởi đầu sáng tạo mang theo vết tích của những trận chiến đã qua — điều mới đang bắt đầu, nhưng người khởi xướng nó đã chiến đấu nhiều rồi; sức bền là một phần không thể tách rời của khởi đầu này.", en: "Ace of Wands and Nine of Wands: a new creative beginning carrying the marks of past battles — something new is starting, but the one initiating it has already fought long; resilience is inseparable from the nature of this beginning." },
  "22_31": { vi: "Át Gậy và Mười Gậy: cảm hứng mới đến khi đôi tay đã đầy ắp — tia lửa có thật, nhưng thêm nó vào gánh nặng hiện có mà không buông bỏ điều gì chắc chắn tạo ra lửa và khói mà không có ánh sáng.", en: "Ace of Wands and Ten of Wands: new inspiration arriving when the hands are already full — the spark is genuine, but adding it to an existing burden without releasing something first will produce fire and smoke without any useful light." },
  "22_32": { vi: "Át Gậy và Trang Bị Gậy: năng lượng sáng tạo thuần túy nhân đôi — khi tia lửa mới gặp sự hào hứng không lọc của Trang Bị, ngọn lửa sáng tạo cháy với độ sáng gần như liều lĩnh và hoàn toàn sống động.", en: "Ace of Wands and Page of Wands: pure creative energy doubled — when the new spark meets the unfiltered enthusiasm of the Page, the creative fire burns with a brightness that is nearly reckless and completely, vibrantly alive." },
  "22_33": { vi: "Át Gậy và Kỵ Sĩ Gậy: tia lửa lập tức phóng về phía trước — không có kế hoạch, không chờ đợi; Kỵ Sĩ và Át tạo ra sự kết hợp nổ tung nhất trong bộ Gậy, toàn là hành động và không một chút do dự.", en: "Ace of Wands and Knight of Wands: the spark immediately charging forward — no planning, no waiting; the Knight and the Ace create the most explosive combination in the suit, all action and not a moment of hesitation." },
  "22_34": { vi: "Át Gậy và Nữ Hoàng Gậy: cảm hứng gặp thẩm quyền sáng tạo ấm áp — Nữ Hoàng không dập tắt tia lửa; bà cho nó hướng đi, sự ấm áp, và một sân khấu để nó có thể lớn thành điều gì đó thực sự đáng kể.", en: "Ace of Wands and Queen of Wands: inspiration meeting warm creative authority — the Queen does not extinguish the spark; she gives it direction, warmth, and a stage from which it can grow into something genuinely remarkable." },
  "22_35": { vi: "Át Gậy và Vua Gậy: lửa thô sơ gặp bậc thầy của lửa — Vua đã thấy nhiều tia lửa đến rồi đi; vai trò của ông ở đây không phải là kiểm soát mà là nhận ra tiềm năng thực sự và tạo ra điều kiện để nó phát triển.", en: "Ace of Wands and King of Wands: raw new fire meeting the master of fire — the King has seen many sparks come and go; his role here is not to contain but to recognize genuine potential and provide conditions for it to grow." },

  // Two of Wands (23) × Wands
  "23_24": { vi: "Hai Gậy và Ba Gậy: kế hoạch đang gặp sự mở rộng — bạn đã đứng trên tháp cao nhìn ra phía trước; giờ là lúc những con tàu đang ra khơi và tầm nhìn của bạn đang trở thành hành trình thực sự.", en: "Two of Wands and Three of Wands: the plan meeting the expansion — you have been standing on the high tower looking ahead; now the ships are sailing and your vision is becoming a genuine journey with real stakes." },
  "23_25": { vi: "Hai Gậy và Bốn Gậy: tầm nhìn táo bạo được ăn mừng bằng một cột mốc — trước khi phóng về phía trước, có điều gì đó đáng được công nhận; những nền móng vững chắc không cản trở sự mở rộng mà làm cho nó có thể bền vững.", en: "Two of Wands and Four of Wands: bold vision marked by a milestone worth celebrating — before launching forward, something deserves recognition; strong foundations do not hinder expansion but make it genuinely sustainable over time." },
  "23_26": { vi: "Hai Gậy và Năm Gậy: kế hoạch bị gián đoạn bởi xung đột — sự hỗn loạn xung quanh bạn không phải là lý do để từ bỏ tầm nhìn; nhưng nó là lý do để xem xét lại chiến lược và chọn thời điểm hành động khôn ngoan hơn.", en: "Two of Wands and Five of Wands: the plan disrupted by conflict — the chaos around you is not a reason to abandon the vision; but it is a reason to reconsider the strategy and choose a wiser moment to act decisively." },
  "23_27": { vi: "Hai Gậy và Sáu Gậy: quyết định táo bạo dẫn đến sự công nhận — khi bạn dám vạch ra hành trình mà người khác không dám, chiến thắng mà bạn nhận được không chỉ là may mắn mà là kết quả của sự can đảm rõ ràng.", en: "Two of Wands and Six of Wands: a bold decision leading to deserved recognition — when you dare to chart the journey others hesitate to attempt, the victory you receive is not luck but the direct result of evident courage." },
  "23_28": { vi: "Hai Gậy và Bảy Gậy: kế hoạch đang lên trong khi phải bảo vệ vị trí — thử thách không phải là từ bỏ tầm nhìn mà là thực thi nó trong khi chịu đựng áp lực liên tục đến từ những người thách thức vị trí của bạn.", en: "Two of Wands and Seven of Wands: the plan forming while the position must be defended — the challenge is not abandoning the vision but executing it while enduring the constant pressure from those who challenge your right to hold this ground." },
  "23_29": { vi: "Hai Gậy và Tám Gậy: kế hoạch đang được triển khai với tốc độ ngoài mong đợi — bạn đã tưởng tượng hành trình; bây giờ mọi thứ đang di chuyển nhanh hơn bạn tính; hãy tin tưởng vào phương hướng đã đặt ra và giữ vững trước tốc độ.", en: "Two of Wands and Eight of Wands: the plan accelerating beyond expectation — you imagined the journey; now everything is moving faster than calculated; trust the direction you set and hold steady as the pace surpasses your original plan." },
  "23_30": { vi: "Hai Gậy và Chín Gậy: tầm nhìn được thử thách bởi sự kiệt sức và trận chiến liên tục — bạn vẫn đứng đó, vẫn giữ bản đồ trong tay; không phải vì bạn chưa bị thương mà vì bạn chưa sẵn sàng buông bỏ hành trình.", en: "Two of Wands and Nine of Wands: the vision tested by exhaustion and ongoing battle — you are still standing there, still holding the map; not because you are unhurt but because you are not yet ready to let go of the journey." },
  "23_31": { vi: "Hai Gậy và Mười Gậy: những kế hoạch lớn tạo ra gánh nặng nặng nề — tầm nhìn của bạn là thật, nhưng cách bạn đang thực thi nó đang nghiền nát bạn; hãy xem xét ủy thác hoặc phân phạm vi trước khi chính tham vọng trở thành cái cản bước bạn.", en: "Two of Wands and Ten of Wands: grand plans creating crushing burden — your vision is real, but the way you are executing it is grinding you down; consider delegation or scope reduction before the ambition itself becomes the obstacle." },
  "23_32": { vi: "Hai Gậy và Trang Bị Gậy: tầm nhìn chiến lược được chia sẻ với sự hiếu kỳ hào hứng — Trang Bị không hiểu hết kế hoạch, nhưng sự nhiệt tình của cậu ấy có thể đem lại góc nhìn tươi mới giúp bạn thấy những gì kinh nghiệm đã làm mờ đi.", en: "Two of Wands and Page of Wands: strategic vision shared with eager curiosity — the Page does not fully grasp the plan, but his enthusiasm may bring a fresh angle that lets you see what experience has gradually been obscuring." },
  "23_33": { vi: "Hai Gậy và Kỵ Sĩ Gậy: kế hoạch được đưa vào hành động bởi năng lượng bốc đồng — khi chiến lược dài hạn của bạn gặp sự xung lực của Kỵ Sĩ, kết quả là hành động nhanh chóng; hãy đảm bảo nó đang phóng về đúng hướng.", en: "Two of Wands and Knight of Wands: the plan set in motion by impulsive energy — when your long-range strategy meets the Knight's drive, the result is rapid action; ensure it is launching in the direction you actually intended." },
  "23_34": { vi: "Hai Gậy và Nữ Hoàng Gậy: tầm nhìn chiến lược được dẫn dắt bởi sự tự tin lôi cuốn — Nữ Hoàng không làm theo kế hoạch của người khác; bà làm cho nó trở thành của bà và thực thi với thẩm quyền khiến người khác tin tưởng đi theo.", en: "Two of Wands and Queen of Wands: strategic vision guided by charismatic confidence — the Queen does not follow someone else's plan; she makes it hers and executes with an authority that makes others genuinely want to follow along." },
  "23_35": { vi: "Hai Gậy và Vua Gậy: kế hoạch phù hợp với tầm nhìn lãnh đạo — khi tư duy chiến lược của bạn gặp sự lãnh đạo dày dạn kinh nghiệm của Vua, những gì bạn cùng nhau nhìn thấy vượt xa những gì một trong hai có thể hình dung một mình.", en: "Two of Wands and King of Wands: the plan aligning with visionary leadership — when your strategic thinking meets the King's seasoned direction, what you see together extends far beyond what either could have imagined working alone." },

  // Three of Wands (24) × Wands
  "24_25": { vi: "Ba Gậy và Bốn Gậy: sự mở rộng được ăn mừng bằng một cột mốc thực sự — bạn đang nhìn ra phía trước và đồng thời tổ chức ăn mừng những gì đã được xây dựng; cả hai đều cần thiết cho hành trình dài.", en: "Three of Wands and Four of Wands: expansion celebrated with a genuine milestone — you are looking ahead while simultaneously celebrating what has been built; both are necessary for any journey that intends to go the distance." },
  "24_26": { vi: "Ba Gậy và Năm Gậy: tầm nhìn xa gặp sự gián đoạn gần — những cuộc xung đột xung quanh bạn không xóa bỏ hành trình phía trước; nhưng chúng đòi hỏi sự chú ý ngay bây giờ, trước khi bạn tiếp tục nhìn ra đường chân trời.", en: "Three of Wands and Five of Wands: far vision meeting nearby disruption — the conflicts around you do not erase the journey ahead; but they require attention now, before you can return to watching the horizon with useful focus." },
  "24_27": { vi: "Ba Gậy và Sáu Gậy: sự mở rộng được khen thưởng bằng sự công nhận — khi bạn dám nhìn xa hơn những gì người khác dám thấy, chiến thắng bạn nhận về không chỉ là vật chất mà còn là xác nhận rằng con đường của bạn là đúng.", en: "Three of Wands and Six of Wands: expansion rewarded with recognition — when you dare to see further than others venture to look, the victory you receive is not only material but a confirmation that your chosen direction was genuinely right." },
  "24_28": { vi: "Ba Gậy và Bảy Gậy: nhìn xa trong khi bảo vệ vị trí hiện tại — thử thách không phải là chọn giữa tầm nhìn và phòng thủ mà là duy trì cả hai đồng thời; người có thể làm điều đó hiếm và đáng giá.", en: "Three of Wands and Seven of Wands: looking far ahead while defending current ground — the challenge is not choosing between vision and defense but sustaining both simultaneously; the person who can do this is rare and genuinely valuable." },
  "24_29": { vi: "Ba Gậy và Tám Gậy: sự mở rộng đang tăng tốc — những con tàu bạn đã phái đi đang trở về với tốc độ mà bạn không lường trước; hãy sẵn sàng nhận kết quả sớm hơn kế hoạch và xử lý chúng với sự chuẩn bị tốt.", en: "Three of Wands and Eight of Wands: the expansion accelerating — the ships you dispatched are returning with a speed you did not anticipate; be ready to receive results earlier than planned and handle them with preparation." },
  "24_30": { vi: "Ba Gậy và Chín Gậy: nhìn xa với sức bền dày dạn trận mạc — bạn đang nhìn về phía trước không phải với sự ngây thơ mà với đôi mắt của người đã biết hành trình dài trông như thế nào từ bên trong.", en: "Three of Wands and Nine of Wands: looking forward with battle-hardened resilience — you are looking ahead not with naivety but with the eyes of someone who already knows from the inside what the long journey actually looks like." },
  "24_31": { vi: "Ba Gậy và Mười Gậy: nhìn xa nhưng đôi tay đang bị nghiền nát bởi gánh nặng — tầm nhìn của bạn không sai, nhưng cơ thể và tinh thần mang quá nhiều để thực sự bước đến nơi đôi mắt đang nhìn; một cái gì đó phải được buông xuống.", en: "Three of Wands and Ten of Wands: far vision while the hands are crushed by burden — your vision is not wrong, but the body and spirit are carrying too much to actually walk where the eyes are looking; something must be set down." },
  "24_32": { vi: "Ba Gậy và Trang Bị Gậy: sự mở rộng với sự tò mò trẻ trung — đôi khi người trẻ nhất trong nhóm là người duy nhất đặt câu hỏi tại sao không đi xa hơn nữa; đừng bỏ qua tiếng nói đó.", en: "Three of Wands and Page of Wands: expansion met with youthful curiosity — sometimes the youngest person in the group is the only one who asks why you are not going even further; do not dismiss that voice too quickly." },
  "24_33": { vi: "Ba Gậy và Kỵ Sĩ Gậy: doanh nghiệp phóng thẳng về phía trước với sự táo bạo — khi tầm nhìn mở rộng của bạn gặp sự xung lực không ngừng của Kỵ Sĩ, kết quả là hành trình bắt đầu ngay bây giờ, không phải sau này.", en: "Three of Wands and Knight of Wands: the enterprise charging boldly forward — when your expansive vision meets the Knight's unstoppable drive, the result is a journey that begins right now rather than at some more convenient later date." },
  "24_34": { vi: "Ba Gậy và Nữ Hoàng Gậy: sự mở rộng được dẫn dắt bởi thẩm quyền ấm áp — Nữ Hoàng biết những con tàu sẽ đi đâu bởi vì bà đã biến tầm nhìn thành của mình; dưới sự lãnh đạo của bà, những chuyến đi xa không gây sợ hãi mà gây hứng khởi.", en: "Three of Wands and Queen of Wands: expansion guided by warm authority — the Queen knows where the ships are sailing because she has made the vision her own; under her leadership, distant journeys inspire rather than frighten." },
  "24_35": { vi: "Ba Gậy và Vua Gậy: doanh nghiệp gặp tầm nhìn lãnh đạo — khi triển vọng dài hạn của bạn phù hợp với sự lãnh đạo dày dạn của Vua, hành trình phía trước không chỉ đầy tham vọng mà còn thực sự có thể thực hiện được.", en: "Three of Wands and King of Wands: enterprise meeting visionary leadership — when your long-range outlook aligns with the King's seasoned command, the journey ahead is not merely ambitious but genuinely achievable within your lifetime." },

  // Four of Wands (25) × Wands
  "25_26": { vi: "Bốn Gậy và Năm Gậy: lễ ăn mừng bị gián đoạn bởi xung đột — không phải mọi lễ hội đều được phép kéo dài; đôi khi sự tranh chấp xảy đến ngay khi bạn vừa đặt xuống gánh nặng để thở.", en: "Four of Wands and Five of Wands: the celebration disrupted by conflict — not every festival is allowed to last; sometimes the dispute arrives precisely when you have just set down the burden to breathe for a moment." },
  "25_27": { vi: "Bốn Gậy và Sáu Gậy: cột mốc được công nhận thành chiến thắng — điều bạn đã xây dựng và ăn mừng giờ đang được thế giới nhìn nhận; đây không phải là may mắn mà là sự xác nhận cho công sức đặt vào nền móng.", en: "Four of Wands and Six of Wands: the milestone recognized as victory — what you built and celebrated is now being acknowledged by the wider world; this is not luck but confirmation for the effort that went into building the foundation." },
  "25_28": { vi: "Bốn Gậy và Bảy Gậy: sự hài hòa phải được bảo vệ — không phải mọi thứ đã được xây dựng đều an toàn mãi mãi; những gì bạn đang bảo vệ là thực sự đáng bảo vệ, và đó là lý do sự kiên định này không phải là sự cứng nhắc.", en: "Four of Wands and Seven of Wands: the harmony requiring active defense — not everything built remains safe forever; what you are defending is genuinely worth defending, which is why this particular stubbornness is not rigidity but wisdom." },
  "25_29": { vi: "Bốn Gậy và Tám Gậy: nền tảng ổn định phóng ra chuyển động nhanh — vì bạn đã xây dựng từ một nơi thực sự vững chắc, khi bạn di chuyển, bạn di chuyển với tốc độ và sự tự tin mà không có sự bất ổn trong lõi.", en: "Four of Wands and Eight of Wands: stable foundation launching rapid movement — because you built from a genuinely solid place, when you move you move with a speed and confidence that has no instability at its core." },
  "25_30": { vi: "Bốn Gậy và Chín Gậy: cột mốc gặp sức bền kiệt sức — bạn đã xây dựng được điều gì đó đáng ăn mừng; nhưng người đứng tại buổi lễ đó mang những vết thương và mệt mỏi mà không ai nhìn thấy trong ảnh.", en: "Four of Wands and Nine of Wands: a milestone met by exhausted resilience — you have built something genuinely worth celebrating; but the person standing at that celebration is carrying wounds and fatigue that do not appear in any photograph." },
  "25_31": { vi: "Bốn Gậy và Mười Gậy: ăn mừng bị đè nặng bởi quá nhiều trách nhiệm — buổi lễ không hoàn chỉnh vì đôi vai đang mang quá nhiều để thực sự vui; hãy đặt một phần xuống trước khi bữa tiệc bắt đầu.", en: "Four of Wands and Ten of Wands: celebration weighed down by too much responsibility — the ceremony is incomplete because the shoulders are carrying too much to genuinely celebrate; set something down before the feast begins." },
  "25_32": { vi: "Bốn Gậy và Trang Bị Gậy: nền móng vui mừng được khám phá với sự tò mò — Trang Bị không hiểu tất cả những gì đã được xây dựng, nhưng sự nhiệt tình của cậu ấy nhắc nhở những người già hơn tại sao tất cả điều này đáng được xây dựng ngay từ đầu.", en: "Four of Wands and Page of Wands: the joyful foundation explored with curiosity — the Page does not understand everything that was built, but his enthusiasm reminds the older ones why all of this was worth building in the first place." },
  "25_33": { vi: "Bốn Gậy và Kỵ Sĩ Gậy: nền tảng ổn định phóng ra hành động phiêu lưu — vì có một ngôi nhà thực sự để trở về, Kỵ Sĩ có thể phóng đi xa với sự tự tin rằng có điều gì đó đáng giá đang chờ khi anh ta quay lại.", en: "Four of Wands and Knight of Wands: stable base launching adventurous action — because there is a genuine home to return to, the Knight can ride out far with the confidence that something worthwhile is waiting when he comes back." },
  "25_34": { vi: "Bốn Gậy và Nữ Hoàng Gậy: sự hài hòa cộng đồng được dẫn dắt bởi thẩm quyền tự tin — Nữ Hoàng không cần ép buộc sự đoàn kết; bà tạo ra điều kiện để mọi người tự nhiên tập hợp xung quanh điều bà đang xây dựng.", en: "Four of Wands and Queen of Wands: community harmony centered by confident authority — the Queen does not force unity; she creates the conditions within which people naturally gather around what she is building and tending." },
  "25_35": { vi: "Bốn Gậy và Vua Gậy: cộng đồng được lãnh đạo bởi tầm nhìn mạnh mẽ — dưới sự lãnh đạo của Vua, lễ ăn mừng không phải là điểm kết thúc mà là điểm tập hợp lực lượng trước khi tiếp tục xây dựng điều gì đó lớn hơn.", en: "Four of Wands and King of Wands: community led by strong vision — under the King's leadership, the celebration is not an endpoint but a gathering of forces before continuing to build something larger and more enduring." },

  // Five of Wands (26) × Wands
  "26_27": { vi: "Năm Gậy và Sáu Gậy: cạnh tranh được giải quyết thành chiến thắng — sự hỗn loạn không phải là vô ích; nó sàng lọc, và người đứng vững trong đó với sự tập trung và khéo léo thực sự thường là người nhận được sự công nhận.", en: "Five of Wands and Six of Wands: competition resolving into victory — the chaos is not pointless; it filters, and the one who stands within it with genuine focus and skill is usually the person who earns the recognition that follows." },
  "26_28": { vi: "Năm Gậy và Bảy Gậy: xung đột gặp sự bảo vệ kiên định — không phải mọi trận chiến đều có thể giải quyết bằng cách né tránh; đôi khi điều cần thiết là chọn đồi mình muốn bảo vệ và giữ vững bất kể những gì đến.", en: "Five of Wands and Seven of Wands: conflict meeting determined defense — not every battle can be resolved by stepping aside; sometimes what is needed is to choose the hill you will hold and stand firm regardless of what comes." },
  "26_29": { vi: "Năm Gậy và Tám Gậy: sự hỗn loạn được tăng tốc bởi hành động nhanh — khi năng lượng hỗn loạn gặp tốc độ, kết quả có thể vừa hủy diệt vừa tạo ra; hãy đảm bảo rằng hành động nhanh của bạn đang giải quyết chứ không phải khuếch đại sự hỗn loạn.", en: "Five of Wands and Eight of Wands: chaos accelerated by rapid action — when turbulent energy meets speed, the result can be both destructive and creative; ensure your rapid action is resolving the chaos and not amplifying it further." },
  "26_30": { vi: "Năm Gậy và Chín Gậy: xung đột liên tục gặp sức bền kiệt sức — bạn đã chiến đấu lâu rồi; không phải mọi trận chiến xung quanh bạn đều cần sự tham gia của bạn; học cách lựa chọn những trận chiến đáng đứng vào.", en: "Five of Wands and Nine of Wands: ongoing conflict meeting exhausted resilience — you have been fighting for a long time; not every battle around you requires your engagement; learn to distinguish the ones worth entering from those that are not." },
  "26_31": { vi: "Năm Gậy và Mười Gậy: những xung đột đang chồng chất thêm lên gánh nặng đã quá nặng — mỗi tranh chấp mới là một thanh củi khác trên đôi vai đang gập xuống; điều khẩn cấp nhất lúc này là ngừng thêm vào trước khi cột sống gãy.", en: "Five of Wands and Ten of Wands: conflicts adding to an already overwhelming burden — each new dispute is another stick on the shoulders already bending; the most urgent thing is to stop adding before the spine finally gives way." },
  "26_32": { vi: "Năm Gậy và Trang Bị Gậy: năng lượng cạnh tranh gặp sự khám phá hiếu kỳ — Trang Bị không tham gia tranh đấu vì quyền lực; cậu ấy tham gia vì mọi thứ đều thú vị; sự hồn nhiên này đôi khi đủ để làm tan chảy sự căng thẳng.", en: "Five of Wands and Page of Wands: competitive energy met with curious exploration — the Page does not enter the fray for power; he enters because everything is interesting; this innocence is sometimes enough to dissolve the tension." },
  "26_33": { vi: "Năm Gậy và Kỵ Sĩ Gậy: trận chiến gặp chiến binh đang lao thẳng vào — Kỵ Sĩ không ngại hỗn loạn; anh ta lao vào không phải vì không có lựa chọn nào khác mà vì đây chính xác là nơi anh ta muốn ở.", en: "Five of Wands and Knight of Wands: the battle meeting the warrior charging straight in — the Knight does not fear the chaos; he charges not because he has no other option but because this is precisely where he wants to be." },
  "26_34": { vi: "Năm Gậy và Nữ Hoàng Gậy: xung đột được làm dịu bởi thẩm quyền tự tin — Nữ Hoàng không tham gia cuộc tranh cãi theo các điều khoản của nó; bà thay đổi năng lượng trong phòng đủ để mọi người nhớ lại tại sao họ ở đây.", en: "Five of Wands and Queen of Wands: conflict calmed by confident authority — the Queen does not join the argument on its own terms; she changes the energy in the room enough that everyone remembers why they are here in the first place." },
  "26_35": { vi: "Năm Gậy và Vua Gậy: căng thẳng sáng tạo được định hướng bởi sự lãnh đạo mạnh mẽ — Vua không dập tắt cuộc cạnh tranh; ông hướng nó về phía những gì đáng thi đua và loại bỏ những gì chỉ tạo ra tiếng ồn.", en: "Five of Wands and King of Wands: creative tension channeled by strong leadership — the King does not extinguish the competition; he directs it toward what is worth contesting and eliminates what is generating nothing but noise." },

  // Six of Wands (27) × Wands
  "27_28": { vi: "Sáu Gậy và Bảy Gậy: chiến thắng vẫn phải được bảo vệ — không phải mọi người đều vui mừng với thành công của bạn; ngay cả sau khi nhận được sự công nhận, vẫn có những người muốn thách thức vị trí bạn đã đạt được.", en: "Six of Wands and Seven of Wands: victory still requiring defense — not everyone celebrates your success; even after receiving recognition, there are those who want to challenge the position you have earned and now must actively hold." },
  "27_29": { vi: "Sáu Gậy và Tám Gậy: chiến thắng đang tăng tốc về phía mục tiêu tiếp theo — không có thời gian để nghỉ ngơi trên vòng nguyệt quế; ngọn lửa chiến thắng đang thúc đẩy về phía trước và động lực này quá quý giá để để mất.", en: "Six of Wands and Eight of Wands: triumph accelerating toward the next goal — there is no time to rest on laurels; the fire of victory is propelling forward and this momentum is too valuable to allow to dissipate through complacency." },
  "27_30": { vi: "Sáu Gậy và Chín Gậy: sự công nhận được kiếm qua sự kiên trì lâu dài — chiến thắng này không đến dễ dàng; người nhận nó mang trong người những vết sẹo và sự mệt mỏi của một hành trình dài hơn nhiều so với người ngoài thấy.", en: "Six of Wands and Nine of Wands: recognition earned through long perseverance — this victory did not come easily; the person receiving it carries the scars and fatigue of a journey far longer than most observers from the outside can see." },
  "27_31": { vi: "Sáu Gậy và Mười Gậy: chiến thắng mang theo gánh nặng nặng nề của thành công — sự công nhận là thật, nhưng cái giá bạn đang trả để giữ ngọn cờ cao là đôi vai đang gập xuống; đây không phải là sự thất bại mà là tín hiệu cần ủy thác.", en: "Six of Wands and Ten of Wands: victory carrying the heavy burden of success — the recognition is real, but the cost of holding the banner high is shoulders that are bending; this is not failure but a signal that delegation is overdue." },
  "27_32": { vi: "Sáu Gậy và Trang Bị Gậy: chiến thắng được ăn mừng với sự hào hứng trẻ trung — sự phấn khích của Trang Bị không giảm bớt sự thành tích; nó nhắc nhở người chiến thắng rằng chiến thắng này truyền cảm hứng không chỉ cho chính họ.", en: "Six of Wands and Page of Wands: triumph celebrated with youthful enthusiasm — the Page's excitement does not diminish the achievement; it reminds the victor that this victory inspires beyond just themselves and those immediately watching." },
  "27_33": { vi: "Sáu Gậy và Kỵ Sĩ Gậy: chiến thắng phóng ra cuộc phiêu lưu tiếp theo — đối với Kỵ Sĩ, chiến thắng không phải là điểm đến mà là nhiên liệu; không có gì kích thích anh ta hơn là chiến thắng vừa xong đang thúc đẩy về phía điều tiếp theo.", en: "Six of Wands and Knight of Wands: triumph launching the next adventure — for the Knight, victory is not a destination but fuel; nothing motivates him more than a recent win propelling him toward the next thing on the horizon." },
  "27_34": { vi: "Sáu Gậy và Nữ Hoàng Gậy: sự công nhận và thẩm quyền lôi cuốn — khi chiến thắng gặp sự ấm áp và sự tự tin của Nữ Hoàng, nó trở thành thứ gì đó hơn là thành tích cá nhân; nó trở thành nguồn cảm hứng cho cộng đồng.", en: "Six of Wands and Queen of Wands: recognition meeting charismatic authority — when victory meets the Queen's warmth and confidence, it becomes something more than personal achievement; it becomes a source of genuine inspiration for the community." },
  "27_35": { vi: "Sáu Gậy và Vua Gậy: chiến thắng được phù hợp với sự lãnh đạo tầm nhìn — Vua không chỉ nhận lấy chiến thắng; ông hướng nó về phía điều gì đó có ý nghĩa lâu dài hơn là khoảnh khắc công nhận thoáng qua.", en: "Six of Wands and King of Wands: triumph aligned with visionary leadership — the King does not merely accept the victory; he directs it toward something of longer-lasting significance than the passing moment of recognition." },

  // Seven of Wands (28) × Wands
  "28_29": { vi: "Bảy Gậy và Tám Gậy: phòng thủ phóng ra phản công nhanh chóng — sau khi giữ vững vị trí, khoảnh khắc để phản công đến nhanh và dứt khoát; đừng để nó trôi qua vì mải lo ngại về những mối đe dọa đã qua.", en: "Seven of Wands and Eight of Wands: defense launching into rapid countermovement — after holding the position, the moment to counteract arrives fast and decisively; do not let it pass by worrying about the threats that have already been weathered." },
  "28_30": { vi: "Bảy Gậy và Chín Gậy: giữ vững vị trí với sức bền đã trải qua trận mạc — bạn không đứng vững ở đây vì chưa bị thương; bạn đứng vững vì bạn đã học được rằng buông tay ở điểm này có nghĩa là từ bỏ những gì bạn đã trả giá bằng mồ hôi và máu.", en: "Seven of Wands and Nine of Wands: holding ground with battle-tested resilience — you are not standing firm here because you are unhurt; you are standing firm because you have learned that releasing now means surrendering what you have paid for dearly." },
  "28_31": { vi: "Bảy Gậy và Mười Gậy: phòng thủ dưới gánh nặng đang nghiền nát — bạn đang bảo vệ vị trí trong khi đang mang quá nhiều; điều này không thể tiếp tục mãi mãi; ưu tiên giải phóng gánh nặng sẽ làm cho sự phòng thủ của bạn mạnh hơn, không phải yếu hơn.", en: "Seven of Wands and Ten of Wands: defense while carrying a crushing load — you are holding ground while bearing too much; this cannot continue indefinitely; prioritizing the release of burden will make your defense stronger, not weaker." },
  "28_32": { vi: "Bảy Gậy và Trang Bị Gậy: năng lượng phòng thủ được khám phá với sự tò mò — Trang Bị không lo lắng về những thách thức đến; cậu ấy tò mò về chúng; quan điểm này có thể làm mới cách bạn nhìn về những gì đang đến.", en: "Seven of Wands and Page of Wands: defensive energy explored with curiosity — the Page is not anxious about the challenges approaching; he is curious about them; this perspective might refresh how you look at what is coming toward you." },
  "28_33": { vi: "Bảy Gậy và Kỵ Sĩ Gậy: giữ vững trước sự tấn công đang lao đến — khi Kỵ Sĩ đang lao thẳng đến và bạn đang bảo vệ điều bạn trân trọng, câu hỏi không phải là có nên giữ vững không mà là làm thế nào để giữ vững một cách khôn ngoan nhất.", en: "Seven of Wands and Knight of Wands: holding ground against the charging opposition — when the Knight is bearing down and you are defending what you value, the question is not whether to hold but how to hold it with the greatest intelligence." },
  "28_34": { vi: "Bảy Gậy và Nữ Hoàng Gậy: phòng thủ được hỗ trợ bởi thẩm quyền tự tin — Nữ Hoàng không chỉ đứng phía sau bạn; bà đứng bên cạnh bạn và sự hiện diện của bà thay đổi cán cân theo những cách mà những kẻ đang thách thức không lường trước.", en: "Seven of Wands and Queen of Wands: defense supported by confident authority — the Queen does not merely stand behind you; she stands beside you and her presence shifts the balance in ways that those challenging you did not anticipate." },
  "28_35": { vi: "Bảy Gậy và Vua Gậy: lãnh thổ được bảo vệ bởi sự lãnh đạo mạnh mẽ — Vua không chỉ chiến đấu; ông kiểm soát sân chơi, đặt ra các điều khoản, và đảm bảo rằng mọi cuộc tấn công đều phải đối mặt với mức độ chuẩn bị mà họ không mong đợi.", en: "Seven of Wands and King of Wands: ground held by strong leadership — the King does not merely fight; he controls the field, sets the terms, and ensures that every challenge must face a level of preparation and command it did not anticipate." },

  // Eight of Wands (29) × Wands
  "29_30": { vi: "Tám Gậy và Chín Gậy: tốc độ nhanh gặp sức bền kiệt sức — khi mọi thứ di chuyển nhanh, người mang theo sự mệt mỏi chiến đấu phải tìm cách duy trì tốc độ mà không bị nghiền nát bởi nhịp điệu mà ngay cả người khỏe cũng khó theo.", en: "Eight of Wands and Nine of Wands: rapid pace meeting exhausted resilience — when everything is moving fast, the one carrying battle fatigue must find a way to maintain the pace without being crushed by a rhythm that even the fresh would find demanding." },
  "29_31": { vi: "Tám Gậy và Mười Gậy: tốc độ bị đè nặng bởi quá nhiều cam kết — bạn đang di chuyển nhanh nhưng đang mang theo tất cả mọi thứ; điều này không bền vững; tốc độ thực sự đòi hỏi phải thả bớt, không phải tích lũy thêm.", en: "Eight of Wands and Ten of Wands: speed burdened by too many commitments — you are moving fast but carrying everything; this is not sustainable; true velocity requires releasing, not accumulating more on top of what is already there." },
  "29_32": { vi: "Tám Gậy và Trang Bị Gậy: hành động nhanh được thực hiện với năng lượng trẻ trung — khi Trang Bị và Tám Gậy cùng nhau, không có gì là quá tham vọng và không có gì là quá xa để thử; điều này có thể là một điểm mạnh hoặc một cái bẫy.", en: "Eight of Wands and Page of Wands: swift action taken with youthful energy — when the Page and Eight of Wands combine, nothing is too ambitious and nothing is too far to attempt; this can be a strength or a trap depending on what guides it." },
  "29_33": { vi: "Tám Gậy và Kỵ Sĩ Gậy: lửa nhân đôi — sự nổ tung của Kỵ Sĩ và tốc độ của Tám Gậy kết hợp tạo ra một lực lượng gần như không thể dừng lại; câu hỏi duy nhất là liệu nó có đang đi đúng hướng không.", en: "Eight of Wands and Knight of Wands: fire doubled — the Knight's explosive charge combined with the Eight's velocity creates a force that is nearly unstoppable; the only question is whether it is heading in the right direction." },
  "29_34": { vi: "Tám Gậy và Nữ Hoàng Gậy: tốc độ nhanh được dẫn dắt bởi thẩm quyền lôi cuốn — Nữ Hoàng không làm chậm tốc độ; bà đảm bảo rằng nó đang đi đúng hướng và mang đúng ưu tiên, biến tốc độ thành sức mạnh có mục đích.", en: "Eight of Wands and Queen of Wands: swift energy guided by charismatic authority — the Queen does not slow the pace; she ensures it is heading in the right direction with the right priorities, transforming speed into purposeful power." },
  "29_35": { vi: "Tám Gậy và Vua Gậy: tốc độ phù hợp với chiến lược tầm nhìn — Vua biết rằng tốc độ mà không có hướng chỉ là sự hỗn loạn; dưới sự hướng dẫn của ông, sự nhanh nhẹn của Tám Gậy trở thành vũ khí chiến lược thực sự.", en: "Eight of Wands and King of Wands: speed aligned with visionary strategy — the King knows that pace without direction is only chaos; under his guidance, the swiftness of Eight of Wands becomes a genuine strategic weapon rather than scattered energy." },

  // Nine of Wands (30) × Wands
  "30_31": { vi: "Chín Gậy và Mười Gậy: sức bền gần hoàn thành bị đè nặng bởi gánh nặng thậm chí còn nhiều hơn — người này đã chiến đấu gần đến đích rồi và bây giờ đang mang nhiều hơn cả những gì họ bắt đầu; đây là khoảnh khắc quan trọng nhất để buông bỏ.", en: "Nine of Wands and Ten of Wands: near-completion resilience crushed by even more burden — this person has fought nearly to the finish and is now carrying more than they started with; this is the most critical moment to set something down." },
  "30_32": { vi: "Chín Gậy và Trang Bị Gậy: sức bền dày dạn gặp sự hào hứng mới tươi — sự mệt mỏi của Chín Gậy và sự hào hứng của Trang Bị không mâu thuẫn nhau; năng lượng trẻ trung có thể nhắc nhở người chiến đấu tại sao hành trình này đáng tiếp tục.", en: "Nine of Wands and Page of Wands: battle-worn resilience met with fresh enthusiasm — the Nine's weariness and the Page's excitement are not opposites; young energy can remind the seasoned fighter why this particular journey is still worth continuing." },
  "30_33": { vi: "Chín Gậy và Kỵ Sĩ Gậy: can đảm đầy thương tích và sự xung lực bất khuất — Chín Gậy đã học được rằng cần phải chọn lựa trận chiến; Kỵ Sĩ chưa học điều đó; sự kết hợp này thú vị và nguy hiểm theo những cách khác nhau.", en: "Nine of Wands and Knight of Wands: scarred courage meeting undimmed drive — the Nine has learned to choose battles; the Knight has not yet learned this; this combination is fascinating and dangerous in different and complementary ways." },
  "30_34": { vi: "Chín Gậy và Nữ Hoàng Gậy: sức bền kiệt sức được nâng đỡ bởi thẩm quyền ấm áp — Nữ Hoàng nhìn thấy điều mà người chiến đấu không thể nhìn thấy từ vị trí của họ: họ gần đến mức nào và điều gì đang thực sự chờ đợi ở phía bên kia.", en: "Nine of Wands and Queen of Wands: exhausted resilience supported by warm authority — the Queen sees what the fighter cannot see from their position: how close they are and what is genuinely waiting on the other side of this final effort." },
  "30_35": { vi: "Chín Gậy và Vua Gậy: trận chiến cuối cùng được dẫn dắt bởi sự lãnh đạo mạnh mẽ — Vua biết rằng người chiến đấu cuối cùng này cần ít lời khuyên hơn và nhiều sự lãnh đạo thực tế hơn; ông đứng đó không phải để chỉ đạo từ xa mà để dẫn đầu.", en: "Nine of Wands and King of Wands: the last stand guided by strong leadership — the King knows this final fighter needs less advice and more actual leadership; he stands there not to direct from a distance but to lead from the front." },

  // Ten of Wands (31) × Wands
  "31_32": { vi: "Mười Gậy và Trang Bị Gậy: gánh nặng nặng nề và sự tò mò trẻ trung — Trang Bị có thể không đủ mạnh để mang hết gánh nặng, nhưng câu hỏi ngây thơ của cậu ấy đôi khi đủ để chỉ ra con đường ngắn nhất đến nơi bạn đang đi.", en: "Ten of Wands and Page of Wands: the crushing load and youthful curiosity — the Page may not be strong enough to carry the full burden, but his innocent question sometimes reveals the shorter path to where you are trying to go." },
  "31_33": { vi: "Mười Gậy và Kỵ Sĩ Gậy: gánh nặng đang bị đè nghẹt và sự xung lực bốc đồng — Kỵ Sĩ muốn thêm nhiệm vụ; người đang mang Mười Gậy không thể thêm bất cứ điều gì khác; đây là thời điểm để ủy thác chứ không phải để chứa chấp thêm.", en: "Ten of Wands and Knight of Wands: the suffocating burden and impulsive drive — the Knight wants to add tasks; the person carrying Ten of Wands cannot add anything else; this is the moment to delegate rather than to absorb more." },
  "31_34": { vi: "Mười Gậy và Nữ Hoàng Gậy: gánh nặng được chia sẻ với thẩm quyền có năng lực — Nữ Hoàng không lấy gánh nặng vì tội nghiệp bạn; bà nhận một phần vì bà có thể xử lý nó và vì việc chia sẻ làm cho nhiệm vụ chung có thể hoàn thành được.", en: "Ten of Wands and Queen of Wands: the burden shared with capable authority — the Queen does not take the load out of pity; she takes a portion because she can handle it and because sharing makes the collective mission actually completable." },
  "31_35": { vi: "Mười Gậy và Vua Gậy: trách nhiệm nặng nề gặp tầm nhìn lãnh đạo — Vua nhìn thấy không chỉ gánh nặng mà còn cái đang tạo ra nó; sự lãnh đạo thực sự ở đây là thiết kế lại hệ thống để một người không phải mang tất cả.", en: "Ten of Wands and King of Wands: the weight of responsibility meeting visionary leadership — the King sees not only the burden but what is creating it; genuine leadership here means redesigning the system so that one person is not carrying everything alone." },

  // Court × Court (Wands)
  "32_33": { vi: "Trang Bị Gậy và Kỵ Sĩ Gậy: sự nhiệt tình tươi mới và hành động phiêu lưu — khi người học việc và chiến binh trẻ hợp sức, không có dự án nào là quá táo bạo để thử; vấn đề là đảm bảo có đủ khôn ngoan để chỉ đường.", en: "Page of Wands and Knight of Wands: fresh enthusiasm meeting adventurous action — when the apprentice and the young warrior combine, no project is too bold to attempt; the challenge is ensuring there is enough wisdom present to point the direction." },
  "32_34": { vi: "Trang Bị Gậy và Nữ Hoàng Gậy: học trò và người hướng dẫn — Nữ Hoàng nhìn thấy trong Trang Bị không phải là sự ngây thơ cần được sửa chữa mà là tiềm năng cần được nuôi dưỡng; mối quan hệ hướng dẫn tốt nhất không dập tắt ngọn lửa mà định hướng nó.", en: "Page of Wands and Queen of Wands: the student meeting the mentor — the Queen sees in the Page not naivety to be corrected but potential to be nurtured; the best mentorship does not extinguish the flame but gives it direction and a worthy stage." },
  "32_35": { vi: "Trang Bị Gậy và Vua Gậy: sự khám phá háo hức được dẫn dắt bởi thẩm quyền tầm nhìn — Vua không cho Trang Bị câu trả lời; ông cho cậu ấy những câu hỏi đúng đắn và chỉ ra hướng để tự tìm ra; đây là cách tạo ra thế hệ lãnh đạo tiếp theo.", en: "Page of Wands and King of Wands: eager exploration guided by visionary authority — the King does not give the Page the answers; he gives the right questions and points the direction to find them; this is how the next generation of leaders is created." },
  "33_34": { vi: "Kỵ Sĩ Gậy và Nữ Hoàng Gậy: hành động táo bạo và thẩm quyền ấm áp — Nữ Hoàng không làm chậm Kỵ Sĩ; bà đảm bảo rằng năng lượng của anh ta đang được hướng vào điều gì đó xứng đáng với sự dũng cảm anh ta mang vào.", en: "Knight of Wands and Queen of Wands: bold action meeting warm authority — the Queen does not slow the Knight; she ensures his energy is directed toward something worthy of the courage and fire he brings to everything he does." },
  "33_35": { vi: "Kỵ Sĩ Gậy và Vua Gậy: hành động táo bạo dưới sự lãnh đạo mạnh mẽ — Kỵ Sĩ cần sứ mệnh xứng đáng; Vua cần người thực thi chiến lược với sự can đảm và tốc độ; khi hai điều này gặp nhau, họ tạo ra một lực lượng khó cản.", en: "Knight of Wands and King of Wands: bold action under strong leadership — the Knight needs a mission worthy of his fire; the King needs someone to execute strategy with courage and speed; when these meet, they create a force that is genuinely hard to stop." },
  "34_35": { vi: "Nữ Hoàng Gậy và Vua Gậy: thẩm quyền sáng tạo nữ tính và nam tính hợp nhất — khi hai trụ cột của lửa kết hợp, không phải là sự cạnh tranh mà là sự bổ sung; cái mà một người không thể thấy, người kia thấy và ngược lại.", en: "Queen of Wands and King of Wands: feminine and masculine creative authority united — when the two pillars of fire combine, it is not competition but complementarity; what one cannot see the other sees, and what one cannot do the other does." },

  // ── Tier 4b: Cups same-suit (91 pairs) ──
  "36_37": { vi: "Át Cốc và Hai Cốc: hạt giống tình yêu thuần khiết gặp sự cộng hưởng lẫn nhau — khi cả hai trái tim mở ra cùng lúc, không cần thêm lời giải thích; đây là ngôn ngữ của linh hồn nhận ra linh hồn.", en: "Ace of Cups and Two of Cups: the seed of pure love meeting mutual resonance — when both hearts open at once, no explanation is needed; this is the language of soul recognizing soul." },
  "36_38": { vi: "Át Cốc và Ba Cốc: khởi đầu cảm xúc mới lan tỏa thành niềm vui cộng đồng — món quà tình cảm được chia sẻ sẽ nhân lên; hãy để trái tim mới mở này dẫn bạn vào vòng tay của những người thực sự yêu thương bạn.", en: "Ace of Cups and Three of Cups: a new emotional beginning flowing into communal joy — a shared emotional gift multiplies; let this freshly opened heart lead you into the arms of those who truly celebrate you." },
  "36_39": { vi: "Át Cốc và Bốn Cốc: một món quà tình cảm đang được trao nhưng sự thờ ơ hay mệt mỏi đang che khuất nó — đừng để nội tâm bị cuốn vào bản thân đến mức bạn bỏ lỡ điều đang được dâng lên ngay trước mắt.", en: "Ace of Cups and Four of Cups: an emotional gift being offered while withdrawal or boredom obscures it — do not let inward preoccupation cause you to miss what is being placed directly before you." },
  "36_40": { vi: "Át Cốc và Năm Cốc: mở lòng đón nhận tình yêu mới trong khi nỗi đau vẫn còn đó — cần can đảm để tiếp nhận điều mới bên cạnh nỗi mất mát; cả hai đều có thật và cả hai đều xứng đáng được thừa nhận.", en: "Ace of Cups and Five of Cups: opening to new love while grief still lingers — it takes courage to receive something new alongside loss; both are real and both deserve acknowledgment." },
  "36_41": { vi: "Át Cốc và Sáu Cốc: khởi đầu cảm xúc mới được nhuộm màu bởi sự ấm áp của quá khứ — có thể đây là tình cũ tái ngộ hoặc một điều gì đó mới mẻ mang theo hương vị quen thuộc từ thời thơ ấu mà trái tim bạn vẫn nhớ.", en: "Ace of Cups and Six of Cups: a new emotional beginning colored by the warmth of the past — this may be an old love revisited or something new carrying a familiar childhood feeling your heart still recognizes." },
  "36_42": { vi: "Át Cốc và Bảy Cốc: món quà tình yêu thuần khiết bị mờ đi bởi quá nhiều lựa chọn và ảo tưởng — khi mọi thứ đều có vẻ hấp dẫn, hãy trở về với hạt giống thực sự đang được trao; sự rõ ràng là hành động yêu thương với chính mình.", en: "Ace of Cups and Seven of Cups: the pure gift of love obscured by too many choices and illusions — when everything seems appealing, return to the real seed being offered; clarity is an act of love toward yourself." },
  "36_43": { vi: "Át Cốc và Tám Cốc: khởi đầu mới đang kêu gọi nhưng hành trình cũ chưa kết thúc — thời điểm quan trọng; đừng mang theo những gì bạn đang bước đi khỏi vào điều mới mẻ này; hãy hoàn thành việc buông bỏ trước.", en: "Ace of Cups and Eight of Cups: a new beginning calling while an old journey is not yet finished — timing matters; do not carry what you are walking away from into this new thing; complete the release first." },
  "36_44": { vi: "Át Cốc và Chín Cốc: hạt giống tình yêu mới gặp chiếc cốc tràn đầy sự thỏa mãn — khi bạn đã đủ đầy với chính mình, mọi tình yêu mới đến đều là món quà chứ không phải lối thoát; đây là nền tảng lý tưởng nhất.", en: "Ace of Cups and Nine of Cups: the seed of new love meeting the full cup of contentment — when you are already full within yourself, new love arriving is a gift not an escape; this is the ideal foundation." },
  "36_45": { vi: "Át Cốc và Mười Cốc: một khởi đầu mang trong mình hạt giống của hạnh phúc gia đình hoàn chỉnh — không phải mọi mối quan hệ đều đến đây, nhưng cái này có tiềm năng trở thành thứ gì đó vĩnh cửu và đẹp đẽ thực sự.", en: "Ace of Cups and Ten of Cups: a single new beginning carrying the seed of complete family joy — not every relationship arrives here, but this one has the potential to become something genuinely lasting and beautiful." },
  "36_46": { vi: "Át Cốc và Trang Bị Cốc: món quà tình cảm thuần khiết được đón nhận bởi một trái tim tò mò và rộng mở — đây là sự kết hợp tươi mới nhất của nước; hãy để sự ngây thơ và sự tò mò dẫn đường thay vì phân tích quá mức.", en: "Ace of Cups and Page of Cups: a pure emotional gift received by an open curious heart — this is the freshest combination of water energy; let innocence and curiosity lead rather than over-analysis." },
  "36_47": { vi: "Át Cốc và Kỵ Sĩ Cốc: tình yêu mới bị cuốn ngay vào sự theo đuổi lãng mạn — đẹp và hứng khởi, nhưng hãy kiểm tra chiều sâu; không phải mọi sự nhiệt tình đều là cam kết và không phải mọi lãng mạn đều là tình yêu thực sự.", en: "Ace of Cups and Knight of Cups: new love swept immediately into romantic pursuit — beautiful and exciting, but check for depth; not every enthusiasm is commitment and not every romance is real love." },
  "36_48": { vi: "Át Cốc và Nữ Hoàng Cốc: sự mở đầu cảm xúc tươi mới được nâng đỡ bởi sự khôn ngoan và lòng trắc ẩn sâu sắc — đây là tình yêu được đón nhận bởi người hiểu rõ chiều sâu của tâm hồn; an toàn và sâu sắc cùng lúc.", en: "Ace of Cups and Queen of Cups: a fresh emotional opening held by deep compassionate wisdom — this is love received by someone who understands the depths of the heart; safe and profound at the same time." },
  "36_49": { vi: "Át Cốc và Vua Cốc: khởi đầu mới được dẫn dắt bởi sự làm chủ cảm xúc và thẩm quyền điềm tĩnh — khi tình yêu được định hướng bởi sự trưởng thành, nó không cần phải ồn ào để chứng minh mình; nó đơn giản là lớn lên.", en: "Ace of Cups and King of Cups: a new beginning guided by emotional mastery and calm authority — when love is directed by maturity, it does not need to be loud to prove itself; it simply grows." },

  "37_38": { vi: "Hai Cốc và Ba Cốc: mối liên kết thân mật được tôn vinh trong cộng đồng — tình yêu không sống trong bong bóng cô lập; khi mối quan hệ của bạn được bạn bè và gia đình chào đón, đó là dấu hiệu của điều gì đó thực sự lành mạnh.", en: "Two of Cups and Three of Cups: an intimate bond celebrated within community — love does not live in isolated bubbles; when your relationship is welcomed by friends and family, that is a sign of something genuinely healthy." },
  "37_39": { vi: "Hai Cốc và Bốn Cốc: mối quan hệ đình trệ khi một người rút lui vào bên trong — đây không phải là sự kết thúc mà là lời kêu gọi giao tiếp; hãy hỏi người kia họ cần gì thay vì giả định về sự thờ ơ.", en: "Two of Cups and Four of Cups: a partnership stagnating as one person withdraws — this is not an ending but a call for communication; ask what the other needs rather than assuming indifference." },
  "37_40": { vi: "Hai Cốc và Năm Cốc: mối quan hệ chạm phải đau khổ hay hối tiếc — cùng nhau đau buồn có thể làm sâu sắc thêm sợi dây liên kết; đừng bảo vệ nhau khỏi nỗi đau, hãy đứng bên cạnh nhau trong nỗi đau đó.", en: "Two of Cups and Five of Cups: a relationship touched by grief or regret — mourning together can deepen the bond; do not protect each other from pain, stand beside each other within it." },
  "37_41": { vi: "Hai Cốc và Sáu Cốc: quan hệ đối tác mang màu sắc hoài niệm — có thể là bạn bè cũ trở thành người yêu, hoặc hai người tìm lại nhau sau nhiều năm; ký ức chung tạo ra nền tảng đặc biệt mà các mối quan hệ mới không có.", en: "Two of Cups and Six of Cups: a partnership colored by nostalgia — perhaps old friends becoming lovers, or two people finding each other again after years; shared memory creates a foundation that new relationships lack." },
  "37_42": { vi: "Hai Cốc và Bảy Cốc: sự kết nối bị che khuất bởi ảo tưởng — hãy chắc chắn rằng bạn đang thực sự nhìn thấy nhau chứ không phải những gì bạn muốn thấy; tình yêu thực sự cần người thật chứ không phải hình ảnh lý tưởng hóa.", en: "Two of Cups and Seven of Cups: connection clouded by fantasy — make sure you are seeing each other as you actually are, not as you wish the other to be; real love needs real people not idealized projections." },
  "37_43": { vi: "Hai Cốc và Tám Cốc: mối liên kết sâu sắc nhưng có thể một người đang chuẩn bị ra đi — trước khi quyết định, hãy nói chuyện thật lòng; đôi khi những gì trông giống như sự kết thúc chỉ là một cuộc trò chuyện chưa diễn ra.", en: "Two of Cups and Eight of Cups: a deep bond but one partner may be preparing to walk away — before deciding, speak honestly; sometimes what looks like an ending is simply a conversation that has not yet happened." },
  "37_44": { vi: "Hai Cốc và Chín Cốc: mối quan hệ hài hòa dẫn đến sự thỏa mãn cá nhân sâu sắc — khi mối quan hệ đối tác nuôi dưỡng chứ không làm cạn kiệt, cả hai người đều trở nên đầy đủ hơn; đây là loại tình yêu xứng đáng để trân trọng.", en: "Two of Cups and Nine of Cups: a harmonious partnership flowing into deep personal fulfillment — when a relationship nourishes rather than depletes, both people become more whole; this is the kind of love worth keeping." },
  "37_45": { vi: "Hai Cốc và Mười Cốc: cặp đôi yêu thương trở thành nền tảng của hạnh phúc gia đình lâu dài — không phải tình yêu nào cũng phát triển đến đây, nhưng cái này có; hãy trân trọng những gì các bạn đã xây dựng cùng nhau.", en: "Two of Cups and Ten of Cups: the loving couple who become the foundation of lasting family happiness — not every love grows here, but this one does; honor what you have built together." },
  "37_46": { vi: "Hai Cốc và Trang Bị Cốc: mối quan hệ còn trẻ hay mới đầy tò mò và khám phá cảm xúc — đây là thời điểm học hỏi về nhau, không phải thời điểm đòi hỏi sự chắc chắn; hãy để sự tò mò dẫn đường.", en: "Two of Cups and Page of Cups: a young or new relationship full of wonder and emotional discovery — this is the time for learning about each other, not demanding certainty; let curiosity lead." },
  "37_47": { vi: "Hai Cốc và Kỵ Sĩ Cốc: mối quan hệ đối tác được thổi vào lý tưởng lãng mạn và sự theo đuổi nhiệt tình — tận hưởng vẻ đẹp của nó nhưng hãy giữ mình có chân trên mặt đất; tình yêu lãng mạn cần sự thực hành không chỉ cảm xúc.", en: "Two of Cups and Knight of Cups: a partnership infused with romantic idealism and enthusiastic pursuit — enjoy its beauty but stay grounded; romantic love needs practice not just feeling." },
  "37_48": { vi: "Hai Cốc và Nữ Hoàng Cốc: mối quan hệ được nuôi dưỡng sâu sắc bởi sự đồng cảm và khôn ngoan cảm xúc — dù đây là phong cách tự nhiên của bạn hay của đối tác, loại chăm sóc này là thứ giữ cho tình yêu tồn tại qua thời gian.", en: "Two of Cups and Queen of Cups: a partnership deeply nourished by empathy and emotional wisdom — whether this is your natural style or your partner's, this kind of care is what keeps love alive through time." },
  "37_49": { vi: "Hai Cốc và Vua Cốc: mối liên kết yêu thương được dẫn dắt bởi sự lãnh đạo trưởng thành và ổn định về mặt cảm xúc — khi có người trong mối quan hệ làm chủ được cảm xúc của mình, nó tạo ra sự an toàn cho cả hai phát triển.", en: "Two of Cups and King of Cups: a loving bond guided by steady emotionally mature leadership — when one person in a relationship has mastered their emotions, it creates safety for both to grow." },

  "38_39": { vi: "Ba Cốc và Bốn Cốc: niềm vui cộng đồng gặp sự rút lui cá nhân — mệt mỏi xã hội hay tiếng gọi bên trong; đôi khi sau một lễ kỷ niệm, chúng ta cần lặng lẽ để tích hợp; hãy lắng nghe nhu cầu thật sự của bạn.", en: "Three of Cups and Four of Cups: communal joy meeting personal withdrawal — social fatigue or an inner calling; sometimes after celebration we need quiet to integrate; listen to what you actually need." },
  "38_40": { vi: "Ba Cốc và Năm Cốc: lễ kỷ niệm bị phủ bóng bởi mất mát — niềm vui và đau buồn cùng tồn tại; không phải lúc nào cũng phải là thứ này hay thứ kia; tôn vinh cả hai cùng một lúc là điều trưởng thành nhất bạn có thể làm.", en: "Three of Cups and Five of Cups: celebration shadowed by loss — joy and grief can coexist; it does not always have to be one or the other; honoring both at once is the most mature thing you can do." },
  "38_41": { vi: "Ba Cốc và Sáu Cốc: tái hội ngộ và hoài niệm được tôn vinh cùng nhau — khi những kết nối cũ hồi sinh, hãy mang theo những gì tốt nhất của quá khứ vào hiện tại mà không cố gắng tái tạo chính xác những gì đã qua.", en: "Three of Cups and Six of Cups: reunion and nostalgia celebrated joyfully — when old connections revive, carry the best of the past into the present without trying to exactly recreate what was." },
  "38_42": { vi: "Ba Cốc và Bảy Cốc: năng lượng lễ hội tan biến vào ảo tưởng — hãy giữ cho những buổi tụ họp có nền tảng trong thực tế; sự hứng khởi xã hội là tốt nhưng đừng để nó che khuất những gì thực sự cần chú ý.", en: "Three of Cups and Seven of Cups: festive energy dissolving into fantasy — keep celebrations grounded in reality; social excitement is fine but do not let it obscure what genuinely needs attention." },
  "38_43": { vi: "Ba Cốc và Tám Cốc: cộng đồng vui vẻ trong khi có ai đó đang lặng lẽ chuẩn bị ra đi — đôi khi người buồn nhất trong phòng là người mỉm cười nhất; hãy kiểm tra những người mà bạn nghĩ là ổn.", en: "Three of Cups and Eight of Cups: a joyful community while one member quietly prepares to leave — sometimes the saddest person in the room is the one smiling most; check on those you assume are fine." },
  "38_44": { vi: "Ba Cốc và Chín Cốc: niềm vui được chia sẻ gặp sự sung túc cá nhân — khi tập thể và cá nhân đều tràn đầy, không ai phải thu hẹp mình; đây là thời điểm hiếm hoi và đẹp đẽ khi mọi thứ đều vừa phải.", en: "Three of Cups and Nine of Cups: shared celebration meeting personal abundance — when the collective and the individual are both full, no one has to shrink; this is a rare and beautiful moment when everything is enough." },
  "38_45": { vi: "Ba Cốc và Mười Cốc: niềm vui xã hội như nền tảng của hạnh phúc gia đình lâu dài — những ký ức tập thể được tạo ra cùng nhau, những lễ kỷ niệm được chia sẻ, chính là mô hồ kết dính các thế hệ lại với nhau.", en: "Three of Cups and Ten of Cups: social celebration as the foundation of lasting family happiness — the shared memories made together, the celebrations held together, are the mortar that binds generations." },
  "38_46": { vi: "Ba Cốc và Trang Bị Cốc: năng lượng sáng tạo vui tươi được nhân lên khi trái tim mở — trí tưởng tượng nảy nở trong sự cởi mở vui vẻ; đây là sự kết hợp hoàn hảo cho nghệ thuật, sự vui chơi và khám phá cùng nhau.", en: "Three of Cups and Page of Cups: playful creative energy amplified when hearts are open — imagination flourishes in joyful openness; this is the perfect combination for art, play, and discovery together." },
  "38_47": { vi: "Ba Cốc và Kỵ Sĩ Cốc: sự tụ họp vui vẻ được thổi sức sống bởi sự theo đuổi lãng mạn hay lý tưởng — có ai đó mang đến năng lượng nhiệt tình cho không gian này; hãy để nó truyền cảm hứng nhưng đừng để nó làm lu mờ những kết nối thực.", en: "Three of Cups and Knight of Cups: joyful gathering energized by romantic or idealistic pursuit — someone is bringing enthusiastic energy into this space; let it inspire without letting it overshadow real connections." },
  "38_48": { vi: "Ba Cốc và Nữ Hoàng Cốc: cộng đồng được nuôi dưỡng bởi sự khôn ngoan đồng cảm sâu sắc — người biết cách giữ không gian cho người khác chính là người giữ cho mọi mối quan hệ không bị tan vỡ; sự chăm sóc thầm lặng này vô giá.", en: "Three of Cups and Queen of Cups: a community held together by deep empathic wisdom — the person who knows how to hold space for others is the one who keeps every relationship intact; this quiet care is invaluable." },
  "38_49": { vi: "Ba Cốc và Vua Cốc: lễ kỷ niệm được dẫn dắt bởi sự lãnh đạo khôn ngoan về mặt cảm xúc — khi người lãnh đạo biết điều tiết cảm xúc tập thể, không gian trở nên an toàn để mọi người thực sự hiện diện và tận hưởng.", en: "Three of Cups and King of Cups: celebration guided by emotionally wise leadership — when the leader knows how to regulate collective emotion, the space becomes safe for everyone to be genuinely present and enjoy." },

  "39_40": { vi: "Bốn Cốc và Năm Cốc: rút lui đôi — cả sự chiêm nghiệm lẫn đau buồn đang kéo vào bên trong; đây không phải là trạng thái mãi mãi mà là thời điểm cần được thừa nhận; hãy nhẹ nhàng với bản thân và di chuyển dần dần về phía trước.", en: "Four of Cups and Five of Cups: double withdrawal — both contemplation and grief pulling inward; this is not a permanent state but a moment that needs acknowledging; be gentle with yourself and move gradually forward." },
  "39_41": { vi: "Bốn Cốc và Sáu Cốc: sự buồn chán được chữa lành bởi sự ấm áp hoài niệm — khi hiện tại cảm thấy trống rỗng, quá khứ đôi khi cung cấp sự an ủi; hãy để ký ức tốt đẹp nhắc nhở bạn về khả năng kết nối mà không cố gắng sống lại trong đó.", en: "Four of Cups and Six of Cups: boredom healed by nostalgic warmth — when the present feels hollow, the past sometimes offers comfort; let good memories remind you of your capacity for connection without trying to live inside them." },
  "39_42": { vi: "Bốn Cốc và Bảy Cốc: sự thờ ơ gặp ảo tưởng — cả hai đều là cách tránh né thực tế; khi bạn không thể tìm thấy hứng thú trong cái có thật và chỉ bị thu hút bởi những mơ mộng, đó là lúc cần phải xem xét lại nền tảng của bản thân.", en: "Four of Cups and Seven of Cups: apathy meeting fantasy — both are ways of avoiding reality; when you cannot find interest in what is real and are only drawn to daydreams, it is time to examine your actual foundations." },
  "39_43": { vi: "Bốn Cốc và Tám Cốc: chiêm nghiệm chín muồi thành quyết định ra đi — sự quay vào bên trong dẫn đến nhận thức rõ ràng rằng đã đến lúc bước đi; đây không phải là sự bỏ chạy mà là sự lựa chọn có ý thức sau khi đã thực sự ngồi với sự thật.", en: "Four of Cups and Eight of Cups: contemplation ripening into the decision to walk away — the inward turn leading to clear recognition that it is time to move; this is not running away but a conscious choice after truly sitting with the truth." },
  "39_44": { vi: "Bốn Cốc và Chín Cốc: chuyển dịch từ sự không thỏa mãn kín đáo sang sự sung túc đầy đủ — sự thay đổi là bên trong; những gì bạn cần không ở xa mà ở sự điều chỉnh cách bạn đang tiếp nhận những gì đã ở đây.", en: "Four of Cups and Nine of Cups: moving from withdrawn dissatisfaction to full contentment — the shift is internal; what you need is not far away but in adjusting how you are receiving what is already here." },
  "39_45": { vi: "Bốn Cốc và Mười Cốc: sự chiêm nghiệm cá nhân như một điểm dừng cần thiết trước khi bước vào sự hài hòa gia đình — đôi khi bạn cần không gian một mình để hiểu được những gì thực sự quan trọng; sự rút lui này có mục đích.", en: "Four of Cups and Ten of Cups: personal contemplation as a necessary pause before stepping into family harmony — sometimes you need space alone to understand what truly matters; this withdrawal has purpose." },
  "39_46": { vi: "Bốn Cốc và Trang Bị Cốc: tâm trí yên lặng bỗng nhận được thông điệp sáng tạo bất ngờ — hãy ở lại cởi mở dù đang rút lui; đôi khi sự thụ động chính xác nhất lại là cách chúng ta nhận được những thứ mà sự bận rộn không bao giờ có thể mang lại.", en: "Four of Cups and Page of Cups: a quiet mind receiving an unexpected creative message — stay open despite withdrawal; sometimes the most precise passivity is how we receive what busyness could never deliver." },
  "39_47": { vi: "Bốn Cốc và Kỵ Sĩ Cốc: sự đình trệ bị gián đoạn bởi lời mời hay sự theo đuổi đầy nhiệt huyết — đây có thể chính xác là điều bạn cần hoặc là sự phân tâm từ công việc bên trong thực sự; hãy phân biệt trước khi bị cuốn đi.", en: "Four of Cups and Knight of Cups: stagnation interrupted by an enthusiastic invitation or pursuit — this may be exactly what you need or a distraction from the real inner work; discern before being swept along." },
  "39_48": { vi: "Bốn Cốc và Nữ Hoàng Cốc: sự rút lui được gặp gỡ bởi lòng trắc ẩn kiên nhẫn — có ai đó đang nhìn thấy bạn ngay cả trong sự im lặng; bạn không cần phải nói chuyện hay thể hiện; chỉ cần biết rằng sự hiện diện quan tâm đó vẫn ở đó.", en: "Four of Cups and Queen of Cups: withdrawal met with patient compassion — someone sees you even in your silence; you do not need to talk or perform; simply knowing that caring presence is there is enough." },
  "39_49": { vi: "Bốn Cốc và Vua Cốc: chiêm nghiệm nội tâm được dẫn dắt bởi sự làm chủ cảm xúc — hãy dành thời gian nhưng đừng đánh mất mình; sự khôn ngoan biết khi nào cần ở trong bóng tối và khi nào cần trở lại ánh sáng.", en: "Four of Cups and King of Cups: introspection guided by emotional mastery — take the time but do not lose yourself; wisdom knows when to remain in darkness and when to return to the light." },

  "40_41": { vi: "Năm Cốc và Sáu Cốc: đang đau buồn về điều đã mất trong khi ký ức ấm áp cung cấp sự an ủi — quá khứ không thể được lấy lại nhưng những món quà nó để lại vẫn có thật; hãy để hoài niệm chữa lành mà không trở thành xiềng xích.", en: "Five of Cups and Six of Cups: grieving what was lost while warm memories offer comfort — the past cannot be reclaimed but the gifts it left behind are still real; let nostalgia heal without becoming a chain." },
  "40_42": { vi: "Năm Cốc và Bảy Cốc: đau buồn chạy trốn vào ảo tưởng — hãy cẩn thận đừng thay thế những gì bạn đã mất bằng những hình ảnh lý tưởng hóa; sự chữa lành thực sự đòi hỏi phải đối mặt với sự mất mát chứ không phải trang trí nó.", en: "Five of Cups and Seven of Cups: grief escaping into fantasy — be careful not to replace what you have lost with idealized images; real healing requires facing the loss not decorating it." },
  "40_43": { vi: "Năm Cốc và Tám Cốc: sự giải phóng kép — đau buồn và ra đi, xóa sạch hoàn toàn để bắt đầu lại; đây là bộ đôi của sự kết thúc triệt để nhất, nhưng cũng là bộ đôi tạo ra không gian sạch nhất cho điều tiếp theo.", en: "Five of Cups and Eight of Cups: double release — mourning and walking away, clearing completely to begin again; this is the most thorough ending combination, but also the one that creates the cleanest space for what comes next." },
  "40_44": { vi: "Năm Cốc và Chín Cốc: những gì bạn đau buồn bây giờ đang tạo ra khoảng trống cho sự thỏa mãn sâu sắc — mất mát không phải là điểm dừng cuối cùng; nó là điều đến trước sự đầy đủ; hãy cho phép bản thân đi qua nỗi đau.", en: "Five of Cups and Nine of Cups: what you grieve now is making space for deep contentment — loss is not the final destination; it is what comes before fullness; allow yourself to move through the sorrow." },
  "40_45": { vi: "Năm Cốc và Mười Cốc: nỗi buồn cá nhân bên cạnh niềm vui tập thể — cả hai thực tế đều có thể cùng tồn tại; bạn không phải giả vờ ổn vì người khác đang vui, và bạn không phải làm tối đám đông vì bạn đang đau.", en: "Five of Cups and Ten of Cups: individual sorrow alongside collective joy — both realities can coexist; you do not have to pretend to be fine because others are happy, and you do not have to darken the crowd because you are hurting." },
  "40_46": { vi: "Năm Cốc và Trang Bị Cốc: nỗi đau được làm dịu bởi thông điệp kỳ diệu — sự chữa lành cảm xúc đến thông qua sự cởi mở sáng tạo; đôi khi một bài thơ, một bức tranh hay một giấc mơ nói với trái tim bị tổn thương theo cách mà lời lẽ bình thường không thể.", en: "Five of Cups and Page of Cups: grief softened by a message of wonder — emotional healing arriving through creative openness; sometimes a poem, a painting, or a dream speaks to the wounded heart in ways ordinary words cannot." },
  "40_47": { vi: "Năm Cốc và Kỵ Sĩ Cốc: đau lòng nhưng có cơ hội lãng mạn mới đang đến — đừng vội vàng chữa lành; cảm xúc cũ cần không gian để được xử lý trước khi bạn sẵn sàng thực sự cho điều mới.", en: "Five of Cups and Knight of Cups: heartbreak with a new romantic possibility approaching — do not rush the healing; old feelings need space to be processed before you are truly ready for what is new." },
  "40_48": { vi: "Năm Cốc và Nữ Hoàng Cốc: nỗi mất mát được ôm ấp bởi sự đồng cảm sâu sắc — bạn không đơn độc trong nỗi đau; có ai đó bên cạnh bạn đủ kiên nhẫn để ở lại trong không gian khó khăn này mà không cố gắng vội vàng sửa chữa nó.", en: "Five of Cups and Queen of Cups: loss held in deep compassion — you are not alone in your grief; someone beside you is patient enough to remain in this difficult space without rushing to fix it." },
  "40_49": { vi: "Năm Cốc và Vua Cốc: nỗi buồn được ổn định bởi sự khôn ngoan cảm xúc — bạn có thể cảm nhận đầy đủ mà không chìm đắm; sự làm chủ cảm xúc không có nghĩa là không cảm thấy, nó có nghĩa là cảm thấy mà không bị mất đi.", en: "Five of Cups and King of Cups: sorrow steadied by emotional wisdom — you can feel it fully without drowning; emotional mastery does not mean not feeling, it means feeling without losing yourself." },

  "41_42": { vi: "Sáu Cốc và Bảy Cốc: ký ức hoài niệm trôi dạt vào ảo tưởng — hãy phân biệt giữa quá khứ thực và hình ảnh lý tưởng hóa; không phải mọi thứ khi xưa đều tốt hơn, và không phải mọi ký ức đều chính xác như bạn nhớ.", en: "Six of Cups and Seven of Cups: nostalgic memory drifting into fantasy — distinguish between genuine past and idealized illusion; not everything was better then, and not every memory is as accurate as you recall." },
  "41_43": { vi: "Sáu Cốc và Tám Cốc: rời bỏ không chỉ hiện tại mà còn cả quá khứ — đây là sự buông bỏ sâu sắc và đầy đủ hơn; không chỉ bước đi từ những gì không còn phục vụ bạn mà còn từ những câu chuyện về chính mình mà bạn đã mang theo.", en: "Six of Cups and Eight of Cups: leaving behind not just the present but the past — this is a deeper and more complete letting go; not just walking away from what no longer serves but from the stories about yourself you have been carrying." },
  "41_44": { vi: "Sáu Cốc và Chín Cốc: sự ấm áp của niềm vui được nhớ đến gặp sự thỏa mãn hiện tại — cuộc sống cảm thấy hoàn chỉnh khi quá khứ và hiện tại đều tốt; đây không phải là trạng thái phổ biến; hãy dừng lại để thực sự nhận ra nó.", en: "Six of Cups and Nine of Cups: the warmth of remembered joy meeting present contentment — life feels complete when both past and present are good; this is not a common state; pause to genuinely recognize it." },
  "41_45": { vi: "Sáu Cốc và Mười Cốc: hạnh phúc thời thơ ấu lớn lên thành sự hài hòa gia đình lâu dài — những hạt giống tình yêu được gieo ngày xưa đang nở hoa trong thực tế hiện tại; điều bạn đã học được về tình yêu trong tuổi thơ đang định hình điều bạn đang tạo ra bây giờ.", en: "Six of Cups and Ten of Cups: childhood happiness grown into lasting family harmony — the seeds of love planted long ago are flowering in present reality; what you learned about love in childhood is shaping what you are creating now." },
  "41_46": { vi: "Sáu Cốc và Trang Bị Cốc: sự hồn nhiên của hoài niệm gặp sự tò mò tươi mới — trái tim ngây thơ được hồi sinh thông qua trí tưởng tượng sáng tạo; hãy mang theo sự kỳ diệu của thời thơ ấu vào hiện tại thay vì chỉ nhớ về nó.", en: "Six of Cups and Page of Cups: playful nostalgia meeting fresh wonder — childhood innocence rekindled through creative imagination; bring the wonder of childhood into the present rather than simply remembering it." },
  "41_47": { vi: "Sáu Cốc và Kỵ Sĩ Cốc: sự theo đuổi lãng mạn được nhuộm màu bởi hoài niệm — đang tìm kiếm cảm giác của một tình yêu cũ trong hình thức mới; hãy hỏi xem bạn đang bị thu hút bởi người thực trước mặt hay bởi ký ức bạn đang chiếu lên họ.", en: "Six of Cups and Knight of Cups: romantic pursuit colored by nostalgia — seeking the feeling of an old love in new form; ask whether you are drawn to the real person before you or to the memory you are projecting onto them." },
  "41_48": { vi: "Sáu Cốc và Nữ Hoàng Cốc: ký ức ấm áp được gìn giữ bởi sự khôn ngoan nuôi dưỡng sâu sắc — di sản cảm xúc được tôn trọng; người biết ôm giữ quá khứ với lòng trắc ẩn trong khi vẫn sống đầy đủ trong hiện tại là người thực sự trưởng thành.", en: "Six of Cups and Queen of Cups: warm memories tended by deep nurturing wisdom — emotional heritage honored; the person who can hold the past with compassion while still living fully in the present is genuinely mature." },
  "41_49": { vi: "Sáu Cốc và Vua Cốc: sự ấm áp của quá khứ được tích hợp bởi góc nhìn trưởng thành về mặt cảm xúc — hoài niệm mà không có sự ủy mị; Vua này có thể trân trọng những gì đã qua mà không bị mắc kẹt trong đó, và điều đó cho thấy sự khôn ngoan thực sự.", en: "Six of Cups and King of Cups: past warmth integrated by emotionally mature perspective — nostalgia without sentimentality; this King can cherish what was without being trapped by it, and that shows real wisdom." },

  "42_43": { vi: "Bảy Cốc và Tám Cốc: bước đi khỏi những ảo tưởng — sự rõ ràng cuối cùng cắt qua màn sương của những mơ mộng; khi bạn nhận ra rằng những gì bạn đã theo đuổi không phải là thực, rời bỏ không còn đau đớn mà là giải phóng.", en: "Seven of Cups and Eight of Cups: walking away from illusions — the clarity that finally cuts through the fog of fantasies; when you realize what you have been pursuing is not real, leaving is no longer painful but liberating." },
  "42_44": { vi: "Bảy Cốc và Chín Cốc: hãy cẩn thận — một cốc chứa ước mơ hão huyền và cái kia chứa sự thỏa mãn thực sự; học cách phân biệt cái nào là cái nào là bài học quan trọng nhất mà nước có thể dạy bạn.", en: "Seven of Cups and Nine of Cups: be careful — one cup holds wishful thinking and the other holds true fulfillment; learning to tell which is which is the most important lesson water can teach you." },
  "42_45": { vi: "Bảy Cốc và Mười Cốc: ảo tưởng về hạnh phúc gia đình so với công việc thực sự, không hoàn hảo và đẹp đẽ của nó — một cái là hình ảnh, cái kia là cuộc sống; hãy chọn cuộc sống thực ngay cả khi nó không hoàn hảo như những gì bạn đã tưởng tượng.", en: "Seven of Cups and Ten of Cups: fantasies of family happiness versus the real, imperfect, beautiful work of it — one is an image, the other is life; choose real life even when it does not match what you imagined." },
  "42_46": { vi: "Bảy Cốc và Trang Bị Cốc: trí tưởng tượng sáng tạo cần được định hướng — những tầm nhìn đẹp đẽ phải gặp sự tò mò thực tiễn; đừng chỉ mơ về những điều có thể, hãy bắt đầu khám phá một cái gì đó cụ thể và thực tế.", en: "Seven of Cups and Page of Cups: creative imagination that needs direction — beautiful visions must meet practical curiosity; do not only dream of possibilities, begin exploring one concrete real thing." },
  "42_47": { vi: "Bảy Cốc và Kỵ Sĩ Cốc: lý tưởng mộng mơ đang trong cuộc truy đuổi toàn phần — lãng mạn và đẹp đẽ, nhưng hãy kiểm tra nó với thực tế; những gì thực sự chịu đựng được không phải là dự án hoàn hảo nhất mà là cái chúng ta thực sự gắn kết với.", en: "Seven of Cups and Knight of Cups: dreamy idealism in full pursuit — romantic and beautiful, but test it against reality; what truly endures is not the most perfect project but the one we are genuinely committed to." },
  "42_48": { vi: "Bảy Cốc và Nữ Hoàng Cốc: tầm nhìn cảm xúc được giữ trong sự phân biệt khôn ngoan — trực giác biết điều gì là thực và điều gì là ảo giác; sự đồng cảm sâu sắc là khả năng cảm nhận sự khác biệt trước khi tâm trí có thể giải thích nó.", en: "Seven of Cups and Queen of Cups: emotional visions held in wise discernment — intuition knowing what is real and what is illusion; deep empathy is the ability to feel the difference before the mind can articulate it." },
  "42_49": { vi: "Bảy Cốc và Vua Cốc: sự rõ ràng của Vua cắt qua màn sương ảo tưởng — sự trưởng thành cảm xúc đặt tên cho những ảo tưởng; những ai đã làm chủ được cảm xúc của mình nhận ra ảo giác nhanh hơn không phải vì họ ít cảm nhận mà vì họ hiểu rõ hơn về những gì họ cảm nhận.", en: "Seven of Cups and King of Cups: the King's clarity cutting through the fog of fantasy — emotional maturity names illusions; those who have mastered their emotions recognize delusion faster not because they feel less but because they understand better what they feel." },

  "43_44": { vi: "Tám Cốc và Chín Cốc: sau khi rời bỏ những gì không phục vụ, đến với sự thỏa mãn thực sự — hành trình đáng giá; điều bạn từ bỏ không phải là điều bạn muốn giữ mà là điều đang giữ bạn lại khỏi những gì bạn thực sự cần.", en: "Eight of Cups and Nine of Cups: having walked away from what did not serve, arriving at genuine contentment — the journey was worth it; what you gave up was not what you wanted to keep but what was keeping you from what you truly needed." },
  "43_45": { vi: "Tám Cốc và Mười Cốc: sự hy sinh cuối cùng dẫn đến sự thuộc về hoàn chỉnh — những gì bạn đã rời bỏ đã chuẩn bị bạn cho điều này; những người đã rời đi và tìm lại mình thường là những người xây dựng nên những ngôi nhà lâu bền nhất.", en: "Eight of Cups and Ten of Cups: sacrifice that ultimately leads to complete belonging — what you left prepared you for this; those who have left and found themselves again often build the most lasting homes." },
  "43_46": { vi: "Tám Cốc và Trang Bị Cốc: rời bỏ một chương với sự tò mò hồn nhiên về những gì nằm phía trước — dũng cảm và cởi mở; người bước đi không vì sợ hãi mà vì tò mò chính là người tìm thấy những điều kỳ diệu nhất trong chuyến hành trình.", en: "Eight of Cups and Page of Cups: leaving one chapter with innocent curiosity about what lies ahead — brave and open; the person who walks away not from fear but from curiosity is the one who finds the most wondrous things on the journey." },
  "43_47": { vi: "Tám Cốc và Kỵ Sĩ Cốc: ra đi trong cuộc tìm kiếm điều gì đó có ý nghĩa hơn — hãy chắc chắn rằng bạn đang hướng tới điều thực sự chứ không chỉ chạy trốn khỏi nỗi không thoải mái theo một hướng trông có vẻ lãng mạn hơn.", en: "Eight of Cups and Knight of Cups: walking away in idealistic pursuit of something more meaningful — make sure you are moving toward something real and not simply running from discomfort in a more romantic-looking direction." },
  "43_48": { vi: "Tám Cốc và Nữ Hoàng Cốc: sự buông bỏ đầy lòng trắc ẩn — rời bỏ không phải trong tức giận hay sợ hãi mà trong sự khôn ngoan và yêu thương bản thân; đây là loại kết thúc chữa lành cả hai phía vì nó được thực hiện với sự trung thực và chăm sóc.", en: "Eight of Cups and Queen of Cups: compassionate release — walking away not in anger or fear but in wisdom and self-care; this is the kind of ending that heals both sides because it is done with honesty and care." },
  "43_49": { vi: "Tám Cốc và Vua Cốc: sự ra đi được dẫn dắt bởi thẩm quyền cảm xúc — biết khi nào cần rời đi là sự khôn ngoan; Vua này không rời bỏ vì hoảng sợ hay bốc đồng mà vì hiểu biết thực sự rằng đây là điều đúng đắn cần làm vào thời điểm này.", en: "Eight of Cups and King of Cups: departure guided by emotional authority — knowing when to leave is wisdom; this King does not walk away in panic or impulse but in genuine understanding that this is the right thing to do at this time." },

  "44_45": { vi: "Chín Cốc và Mười Cốc: sự thỏa mãn cá nhân mở rộng thành niềm vui tập thể — điều ước được thực hiện và được chia sẻ; khi bạn đã thực sự đầy đủ bên trong, tình yêu bạn chia sẻ không phải là những gì bạn cần từ người khác mà là những gì bạn có thể tặng cho họ.", en: "Nine of Cups and Ten of Cups: personal fulfillment expanding into collective joy — the wish fulfilled and shared; when you are truly full within, the love you share is not what you need from others but what you can give to them." },
  "44_46": { vi: "Chín Cốc và Trang Bị Cốc: sự thỏa mãn mở cửa cho những thông điệp cảm xúc mới — đầy đủ nhưng vẫn còn tò mò; người hài lòng với hiện tại trong khi vẫn cởi mở với những điều kỳ diệu không mong đợi là người có được nhiều nhất từ cả hai thế giới.", en: "Nine of Cups and Page of Cups: contentment opening to new emotional messages — satisfied but still curious; the person content with what is while remaining open to unexpected wonder is the one who gets the most from both worlds." },
  "44_47": { vi: "Chín Cốc và Kỵ Sĩ Cốc: sự thỏa mãn được theo đuổi bởi lý tưởng lãng mạn tiếp tục — tận hưởng sự sung túc trong khi giữ cho trái tim vẫn còn hoạt động; cuộc sống tốt nhất là khi bạn vừa biết ơn về những gì bạn có vừa hứng thú với những gì có thể đến.", en: "Nine of Cups and Knight of Cups: fulfillment pursued alongside continued romantic idealism — enjoy abundance while keeping the heart active; the best life is when you are both grateful for what you have and excited about what may come." },
  "44_48": { vi: "Chín Cốc và Nữ Hoàng Cốc: sự thỏa mãn sâu sắc được gìn giữ bởi sự chăm sóc đầy lòng trắc ẩn — hạnh phúc được nuôi dưỡng chứ không chỉ được tìm thấy; người biết cách chăm sóc niềm vui của mình như chăm sóc một khu vườn sẽ giữ được nó lâu hơn.", en: "Nine of Cups and Queen of Cups: deep personal contentment tended by compassionate care — happiness nurtured not just found; the person who knows how to tend their joy like a garden will keep it far longer." },
  "44_49": { vi: "Chín Cốc và Vua Cốc: điều ước được thực hiện được hướng dẫn bởi sự làm chủ cảm xúc — sự thỏa mãn được giữ với thẩm quyền điềm tĩnh; người đã làm việc để hiểu chính mình sẽ giữ được sự thỏa mãn của mình một cách khác biệt hơn so với người chỉ đơn giản là may mắn.", en: "Nine of Cups and King of Cups: wish fulfillment guided by emotional mastery — contentment held with calm authority; the person who has worked to know themselves will hold their contentment differently than the person who simply got lucky." },

  "45_46": { vi: "Mười Cốc và Trang Bị Cốc: sự hài hòa gia đình truyền cảm hứng cho những khởi đầu cảm xúc mới — từ sự hoàn chỉnh, một chương sáng tạo mới mẻ mở ra; hạnh phúc không phải là điểm dừng mà là nền tảng từ đó tất cả những điều tiếp theo phát triển.", en: "Ten of Cups and Page of Cups: family harmony inspiring new emotional beginnings — from completion, a fresh creative chapter opens; happiness is not a destination but a foundation from which everything subsequent grows." },
  "45_47": { vi: "Mười Cốc và Kỵ Sĩ Cốc: niềm vui tập thể được mang về phía trước bởi sự theo đuổi lãng mạn — hạnh phúc tại nhà thổi sức mạnh cho những cuộc phiêu lưu lý tưởng; khi bạn biết rằng nền tảng ở đó, bạn có thể mạo hiểm nhiều hơn.", en: "Ten of Cups and Knight of Cups: collective joy carried forward by romantic pursuit — the happiness of home fueling idealistic ventures; when you know the foundation is there, you can risk more." },
  "45_48": { vi: "Mười Cốc và Nữ Hoàng Cốc: sự hài hòa gia đình được giữ gìn bởi sự chăm sóc đầy đồng cảm sâu sắc — sự khôn ngoan nuôi dưỡng là nền tảng của niềm hạnh phúc lâu dài; không có gì lâu bền không được chăm sóc và không có sự chăm sóc nào lớn hơn được trao cho gia đình.", en: "Ten of Cups and Queen of Cups: family harmony held in deep empathic care — nurturing wisdom as the foundation of lasting joy; nothing endures that is not tended, and no tending is greater than that given to family." },
  "45_49": { vi: "Mười Cốc và Vua Cốc: hạnh phúc lâu dài được dẫn dắt bởi sự lãnh đạo khôn ngoan về mặt cảm xúc — Vua bảo vệ sự ấm áp của những chiếc mười; khi người lãnh đạo ổn định về mặt cảm xúc và thực sự thông minh, cả gia đình đều phát triển.", en: "Ten of Cups and King of Cups: lasting happiness guided by emotionally wise leadership — the King who protects the warmth of ten; when the leader is emotionally steady and genuinely intelligent, the whole family thrives." },

  "46_47": { vi: "Trang Bị Cốc và Kỵ Sĩ Cốc: sự trẻ trung cảm xúc gặp sự theo đuổi lãng mạn — hai trái tim đang tìm kiếm, một thì tò mò hơn, một thì nhiệt huyết hơn; cả hai đều chân thật và cả hai đều học hỏi; hãy tôn trọng giai đoạn này mà không vội vã thoát ra khỏi nó.", en: "Page of Cups and Knight of Cups: emotional youth meeting romantic pursuit — two hearts searching, one more curious, one more ardent; both are genuine and both are learning; honor this stage without rushing out of it." },
  "46_48": { vi: "Trang Bị Cốc và Nữ Hoàng Cốc: sự nhạy cảm cảm xúc trẻ trung đang học hỏi từ sự khôn ngoan đồng cảm sâu sắc — học sinh và bậc thầy của trái tim; những gì Trang Bị mang theo trong sự hồn nhiên, Nữ Hoàng đã học được qua nhiều năm sống và yêu thương.", en: "Page of Cups and Queen of Cups: young emotional sensitivity learning from deep empathic wisdom — the student and the master of the heart; what the Page carries in innocence, the Queen has earned through years of living and loving." },
  "46_49": { vi: "Trang Bị Cốc và Vua Cốc: thông điệp hồn nhiên được đón nhận bởi thẩm quyền trưởng thành về mặt cảm xúc — trực giác trẻ trung được tôn trọng bởi kinh nghiệm khôn ngoan; Vua đủ an toàn trong sự làm chủ của mình để lắng nghe thứ gì đó mà người khác có thể bác bỏ.", en: "Page of Cups and King of Cups: innocent emotional messages received by emotionally mature authority — youthful intuition honored by wise experience; the King is secure enough in his mastery to listen to something others might dismiss." },

  "47_48": { vi: "Kỵ Sĩ Cốc và Nữ Hoàng Cốc: sự theo đuổi lãng mạn gặp lòng trắc ẩn sâu sắc — người lý tưởng chủ nghĩa và người đồng cảm; đẹp đẽ khi kết hợp nếu cả hai ở lại đúng thực tại; Kỵ Sĩ học được chiều sâu và Nữ Hoàng được nhắc nhở về sự phấn khích của cuộc theo đuổi.", en: "Knight of Cups and Queen of Cups: romantic pursuit meeting deep compassion — the idealist and the empath; beautiful together if both stay grounded; the Knight learns depth and the Queen is reminded of the excitement of the chase." },
  "47_49": { vi: "Kỵ Sĩ Cốc và Vua Cốc: trái tim lý tưởng được hướng dẫn bởi sự khôn ngoan đã làm chủ về mặt cảm xúc — đam mê của Kỵ Sĩ được điều tiết bởi sự điềm tĩnh của Vua; học cách mang đến nhiệt huyết mà không mất đi sự rõ ràng là bài học quan trọng nhất của nước.", en: "Knight of Cups and King of Cups: idealistic heart guided by emotionally mastered wisdom — the Knight's passion tempered by the King's equanimity; learning to bring enthusiasm without losing clarity is the most important lesson of water." },

  "48_49": { vi: "Nữ Hoàng Cốc và Vua Cốc: hai thẩm quyền cảm xúc của nước hợp nhất — sự đồng cảm sâu sắc và sự làm chủ điềm tĩnh cùng nhau; khi cả hai hợp nhất, không phải là sự cạnh tranh mà là sự biểu hiện đầy đủ nhất của nước mà có thể tồn tại.", en: "Queen of Cups and King of Cups: the two emotional authorities of water united — deep empathy and calm mastery together; when these two combine, it is not competition but the most complete expression of water that is possible." },
  // ── Tier 4c: Swords same-suit (91 pairs) ──
  "50_51": { vi: "Át Kiếm và Hai Kiếm: chân lý thuần khiết gặp sự do dự — lưỡi kiếm sắc bén nhất bị giữ lại bởi một tâm trí không dám nhìn thẳng; sự rõ ràng tuyệt đối chờ đợi chỉ một quyết định dũng cảm để được giải phóng.", en: "Ace of Swords and Two of Swords: pure truth meeting hesitation — the sharpest blade held back by a mind unwilling to look directly; absolute clarity waits for only one courageous decision to be released." },
  "50_52": { vi: "Át Kiếm và Ba Kiếm: sự thật cắt qua đau lòng — khoảnh khắc đột phá khi chân lý không thể tránh né thêm được nữa; đôi khi cái hiểu biết đau đớn nhất lại là điều giải phóng linh hồn.", en: "Ace of Swords and Three of Swords: truth cutting through heartbreak — the breakthrough moment when reality can no longer be avoided; sometimes the most painful understanding is the very thing that frees the soul." },
  "50_53": { vi: "Át Kiếm và Bốn Kiếm: sự rõ ràng đòi hỏi sự nghỉ ngơi — tâm trí cần dừng lại để tiêu hóa chân lý; hiểu biết sắc bén không có giá trị nếu tâm thần quá kiệt sức để hành động theo đó.", en: "Ace of Swords and Four of Swords: clarity requiring rest — the mind must pause to absorb truth; sharp understanding has no value if the spirit is too exhausted to act upon it." },
  "50_54": { vi: "Át Kiếm và Năm Kiếm: chân lý giữa xung đột — sức mạnh trí tuệ thuần khiết bước vào chiến trường; chiến thắng bằng sự thật là có thể, nhưng cái giá phải trả có thể cao hơn tưởng tượng.", en: "Ace of Swords and Five of Swords: pure truth entering the battlefield — intellectual power at its most raw confronting conflict; winning by truth is possible, but the cost may be higher than imagined." },
  "50_55": { vi: "Át Kiếm và Sáu Kiếm: chân lý như một hành trình — sự rõ ràng cho phép bước chân khỏi sóng gió; khi tâm trí nhìn thấy thực tại không bị bóp méo, con đường thoát ra luôn trở nên rõ hơn.", en: "Ace of Swords and Six of Swords: truth as passage — clarity enabling movement away from turbulence; when the mind sees reality undistorted, the way forward always becomes clearer." },
  "50_56": { vi: "Át Kiếm và Bảy Kiếm: chân lý đối mặt với mưu kế — sức mạnh trí tuệ gặp sự khéo léo và xảo quyệt; khi cả hai đều sắc bén, cuộc đấu trí là câu hỏi liệu minh bạch hay chiến lược mới thực sự thắng.", en: "Ace of Swords and Seven of Swords: truth confronting cunning — intellectual power meeting cleverness and strategy; when both are sharp, the contest of minds asks whether transparency or strategy truly wins." },
  "50_57": { vi: "Át Kiếm và Tám Kiếm: chân lý đủ sức giải phóng — tâm trí bị trói buộc chỉ cần một cái nhìn rõ ràng để cắt đứt những sợi dây tự áp đặt; sự thật là thanh kiếm duy nhất thực sự cần thiết.", en: "Ace of Swords and Eight of Swords: truth powerful enough to free — the bound mind needs only one clear perception to cut through self-imposed bonds; truth is the only sword that is truly needed." },
  "50_58": { vi: "Át Kiếm và Chín Kiếm: sự rõ ràng xuyên qua lo âu — ánh sáng của chân lý tiếp xúc với bóng tối của nỗi sợ hãi trong đêm khuya; nhận ra sự khác biệt giữa thực tế và tưởng tượng là liều thuốc chữa trị.", en: "Ace of Swords and Nine of Swords: clarity piercing anxiety — the light of truth touching the darkness of night-time fears; recognizing the difference between reality and imagination is the medicine." },
  "50_59": { vi: "Át Kiếm và Mười Kiếm: chân lý tại thời điểm kết thúc — sự hiểu biết sắc bén nhất đến ngay khoảnh khắc điều gì đó hoàn toàn chấm dứt; đây là sự thức tỉnh đau đớn nhưng hoàn toàn cần thiết.", en: "Ace of Swords and Ten of Swords: truth at the moment of ending — the sharpest understanding arriving exactly when something completely concludes; this is the most painful but absolutely necessary awakening." },
  "50_60": { vi: "Át Kiếm và Trang Bị Kiếm: tiềm năng trí tuệ thuần khiết gặp trí óc tò mò — bản năng đặt câu hỏi của Trang Bị được mài giũa thành lưỡi kiếm thực sự khi chân lý gốc rễ của khí được nhận ra.", en: "Ace of Swords and Page of Swords: pure intellectual potential meeting the curious mind — the Page's questioning instinct sharpened into a real blade when the root truth of air is recognized." },
  "50_61": { vi: "Át Kiếm và Kỵ Sĩ Kiếm: chân lý thô sơ gặp hành động táo bạo — khi hai lưỡi kiếm của khí kết hợp, không có gì có thể cản trở được sức xung kích; nguy hiểm ở chỗ không có sự khôn ngoan nào kiểm soát.", en: "Ace of Swords and Knight of Swords: raw truth meeting bold action — when two air swords combine, nothing can halt the charge; the danger is that no wisdom governs the blade." },
  "50_62": { vi: "Át Kiếm và Nữ Hoàng Kiếm: chân lý sơ khai được tinh luyện bởi sự khôn ngoan — Nữ Hoàng biết cách dùng lưỡi kiếm của sự thật không chỉ để cắt mà còn để chữa lành; đây là không khí ở hình thức trưởng thành nhất.", en: "Ace of Swords and Queen of Swords: primal truth refined by wisdom — the Queen knows how to use truth's blade not only to cut but also to heal; this is air at its most mature form." },
  "50_63": { vi: "Át Kiếm và Vua Kiếm: chân lý tuyệt đối gặp thẩm quyền tuyệt đối — lưỡi kiếm nguyên thủy trong tay người làm chủ cao nhất; khi cả hai hợp nhất, lẽ phải và quyền lực nói bằng một giọng duy nhất.", en: "Ace of Swords and King of Swords: ultimate truth meeting ultimate authority — the primal blade in the hands of the highest master; when these two unite, reason and power speak with a single voice." },

  "51_52": { vi: "Hai Kiếm và Ba Kiếm: sự lưỡng lự trước sự đau lòng — che mắt tránh né không làm mất đi sự thật đau đớn; câu hỏi chỉ là liệu trái tim sẽ chọn nhìn thấy nó bây giờ hay sau này.", en: "Two of Swords and Three of Swords: hesitation before heartbreak — blindfolded avoidance does not erase a painful truth; the only question is whether the heart will choose to see it now or later." },
  "51_53": { vi: "Hai Kiếm và Bốn Kiếm: tê liệt kép của khí — một tâm trí bị tê liệt bởi lựa chọn, một tâm trí đang phục hồi trong im lặng; cả hai đều dừng lại, nhưng một cái là đóng băng, cái kia là chữa lành.", en: "Two of Swords and Four of Swords: double stillness of air — one mind paralyzed by choice, another healing in silence; both pause, but one is frozen while the other is recovering." },
  "51_54": { vi: "Hai Kiếm và Năm Kiếm: do dự và xung đột — lưỡi kiếm không thể chọn gặp lưỡi kiếm chiến đấu quá nhiều; không hành động và hành động sai đều có thể gây tổn hại như nhau.", en: "Two of Swords and Five of Swords: indecision and conflict — the sword that cannot choose meeting the sword that fights too much; both inaction and wrong action can cause equal harm." },
  "51_55": { vi: "Hai Kiếm và Sáu Kiếm: chọn con đường rời đi — quyết định khó khăn cuối cùng được đưa ra, cho phép rời bỏ sóng gió; biết khi nào nên buông tay là hình thức sáng suốt nhất của khí.", en: "Two of Swords and Six of Swords: choosing to move on — the difficult decision finally made, allowing departure from turbulence; knowing when to let go is the highest form of air's wisdom." },
  "51_56": { vi: "Hai Kiếm và Bảy Kiếm: suy xét và mưu mô — tâm trí cẩn thận cân nhắc ranh giới giữa lập luận thận trọng và toan tính không trung thực; sự khéo léo không cần che giấu nếu ý định trong sạch.", en: "Two of Swords and Seven of Swords: deliberation and cunning — the careful mind weighing the line between prudent reasoning and dishonest scheming; cleverness needs no concealment when intention is clean." },
  "51_57": { vi: "Hai Kiếm và Tám Kiếm: mù quáng kép — hai hình thức hạn chế tinh thần tăng cường lẫn nhau; né tránh quyết định và tự trói buộc bản thân đều là những con đường dẫn đến cùng một bế tắc.", en: "Two of Swords and Eight of Swords: double blindness — two forms of mental restriction compounding each other; avoiding decisions and binding yourself are different paths leading to the same impasse." },
  "51_58": { vi: "Hai Kiếm và Chín Kiếm: lo lắng đến từ sự do dự — cái giá của việc trì hoãn một sự thật khó khăn; tâm trí tự trừng phạt vào ban đêm vì những điều nó từ chối nhìn thẳng vào ban ngày.", en: "Two of Swords and Nine of Swords: anxiety born from hesitation — the cost of postponing a difficult truth; the mind punishes itself at night for what it refuses to face clearly in the day." },
  "51_59": { vi: "Hai Kiếm và Mười Kiếm: bế tắc trước kết thúc — sự lựa chọn bị trì hoãn gặp sự kết thúc không thể tránh khỏi; đôi khi quyết định không được đưa ra cũng là một quyết định, và hậu quả là như vậy.", en: "Two of Swords and Ten of Swords: stalemate before the ending — the postponed choice meeting the inevitable conclusion; sometimes the decision not made is still a decision, and the consequences are the same." },
  "51_60": { vi: "Hai Kiếm và Trang Bị Kiếm: tâm trí tò mò đối mặt với lựa chọn — Trang Bị học rằng không phải mọi câu hỏi đều cần câu trả lời ngay lập tức; sự thận trọng và sự do dự trông giống nhau nhưng xuất phát từ những nguồn gốc rất khác.", en: "Two of Swords and Page of Swords: curious mind facing choices — the Page learns that not every question requires an immediate answer; caution and indecision look alike but spring from very different sources." },
  "51_61": { vi: "Hai Kiếm và Kỵ Sĩ Kiếm: sự do dự đối lập với sự xông pha — sự bế tắc của tâm trí cẩn thận gặp năng lượng của người không bao giờ chờ đợi; cả hai cần điều mà người kia có nhưng chưa sẵn sàng thừa nhận.", en: "Two of Swords and Knight of Swords: hesitation opposing the charge — the careful mind's standstill meeting the energy of one who never waits; each needs what the other has but is not yet ready to admit." },
  "51_62": { vi: "Hai Kiếm và Nữ Hoàng Kiếm: lựa chọn khó khăn được dẫn dắt bởi sự khôn ngoan — Nữ Hoàng cắt qua sự do dự bằng sự rõ ràng đã được trả bằng kinh nghiệm sống; bà biết rằng không lựa chọn cũng là một lựa chọn.", en: "Two of Swords and Queen of Swords: difficult choice guided by wisdom — the Queen cuts through hesitation with clarity paid for by lived experience; she knows that no choice is also a choice." },
  "51_63": { vi: "Hai Kiếm và Vua Kiếm: sự cân nhắc kỹ lưỡng gặp thẩm quyền quyết đoán — Vua không tê liệt bởi sự phức tạp mà điều hướng nó bằng sự phán xét đã được rèn luyện; suy nghĩ kỹ rồi hành động, đó là tinh hoa của khí.", en: "Two of Swords and King of Swords: careful deliberation meeting decisive authority — the King is not paralyzed by complexity but navigates it with hardened judgment; think deeply then act, that is the essence of air." },

  "52_53": { vi: "Ba Kiếm và Bốn Kiếm: đau lòng dẫn đến phục hồi — vết thương mới nhất sau khi chịu đựng sự đau đớn là sự tĩnh lặng để chữa lành; tâm trí cần bóng tối và sự im lặng trước khi ánh sáng có thể trở lại.", en: "Three of Swords and Four of Swords: heartbreak leading to recovery — the only right response after bearing such pain is stillness to heal; the mind needs darkness and silence before light can return." },
  "52_54": { vi: "Ba Kiếm và Năm Kiếm: nỗi đau và xung đột — nhiều vết thương chồng chất lên nhau; khi sự tàn nhẫn của khí chưa lắng xuống, sự khắc nghiệt mới lại đến từ phía khác của chiến trường.", en: "Three of Swords and Five of Swords: sorrow and conflict — multiple wounds compounding each other; when one form of air's harshness has not yet settled, a new cruelty arrives from another side of the battlefield." },
  "52_55": { vi: "Ba Kiếm và Sáu Kiếm: nỗi đau chuyển hóa thành hành trình — nỗi đau buồn dần trở thành lý do để rời bỏ; khi trái tim đã chấp nhận mất mát, con thuyền có thể bắt đầu hành trình sang bờ kia.", en: "Three of Swords and Six of Swords: sorrow transforming into passage — grief becoming the very reason to depart; when the heart has accepted its loss, the boat can begin its journey to the other shore." },
  "52_56": { vi: "Ba Kiếm và Bảy Kiếm: nỗi đau lòng và sự phản bội — khi nguyên nhân của vết thương là sự không trung thực, nỗi đau mang thêm trọng lượng của sự không tin tưởng; lành lại tức là học cách tin tưởng lại một ngày nào đó.", en: "Three of Swords and Seven of Swords: heartbreak and betrayal — when the source of the wound is dishonesty, the pain carries the added weight of broken trust; healing means learning to trust again someday." },
  "52_57": { vi: "Ba Kiếm và Tám Kiếm: nỗi đau và cảm giác bị giam cầm — sự kết hợp tối tăm nhất của khí; khi cả đau lòng lẫn sự trói buộc cùng xuất hiện, tâm trí cần sự giúp đỡ từ bên ngoài để tìm thấy lối ra.", en: "Three of Swords and Eight of Swords: sorrow and entrapment — among the darkest combinations of air; when both heartbreak and bondage appear together, the mind needs outside help to find any way out." },
  "52_58": { vi: "Ba Kiếm và Chín Kiếm: nỗi đau được lo âu giữ sống — trái tim tan vỡ trở thành vật liệu cho những đêm không ngủ; nỗi buồn được kéo dài không chỉ bởi vết thương mà bởi tâm trí không ngừng hành hạ bản thân.", en: "Three of Swords and Nine of Swords: sorrow kept alive by anxiety — the broken heart becoming raw material for sleepless nights; grief extended not only by the wound but by the mind's relentless self-torment." },
  "52_59": { vi: "Ba Kiếm và Mười Kiếm: kết thúc kép — nỗi đau sâu sắc nhất và cú đánh cuối cùng cùng xuất hiện; đây là điểm chạm đáy của khí, nhưng cũng chính là nền tảng để từ đó mọi sự hồi sinh đều có thể bắt đầu.", en: "Three of Swords and Ten of Swords: double endings — the deepest cut and the final blow appearing together; this is air at its lowest point, but also the foundation from which all renewal can begin." },
  "52_60": { vi: "Ba Kiếm và Trang Bị Kiếm: bài học đau đớn cho tâm trí trẻ — Trang Bị đối mặt với sự mất mát sớm hơn mong đợi; những vết thương đầu tiên dạy sâu sắc nhất nếu người học có dũng khí không bỏ cuộc.", en: "Three of Swords and Page of Swords: painful lesson for the young mind — the Page confronting loss earlier than expected; the first wounds teach most deeply if the learner has the courage not to give up." },
  "52_61": { vi: "Ba Kiếm và Kỵ Sĩ Kiếm: sự liều lĩnh gây ra hoặc bỏ qua nỗi đau — Kỵ Sĩ xông vào quá nhanh đến nỗi không nhận ra rằng mình đang gây thương tổn hoặc đang trốn chạy vết thương của riêng mình.", en: "Three of Swords and Knight of Swords: recklessness causing or ignoring pain — the Knight charging so fast he does not realize he is wounding others or fleeing wounds of his own." },
  "52_62": { vi: "Ba Kiếm và Nữ Hoàng Kiếm: sự chấp nhận khôn ngoan trước nỗi đau — Nữ Hoàng không phủ nhận vết thương mà đứng thẳng với trái tim tan vỡ và tiếp tục nhìn thấy rõ ràng; đây là sức mạnh thực sự của khí.", en: "Three of Swords and Queen of Swords: wise acceptance of sorrow — the Queen does not deny the wound but stands upright with a broken heart and continues to see clearly; this is air's true strength." },
  "52_63": { vi: "Ba Kiếm và Vua Kiếm: thẩm quyền vượt qua nỗi đau — Vua học cách cai quản tâm trí ngay cả khi trái tim đau; sự làm chủ thực sự không có nghĩa là không cảm nhận mà là không bị ý nghĩa đó điều khiển.", en: "Three of Swords and King of Swords: authority over pain — the King learning to govern the mind even when the heart is breaking; true mastery does not mean not feeling but not being controlled by feeling." },

  "53_54": { vi: "Bốn Kiếm và Năm Kiếm: nghỉ ngơi trước hoặc sau xung đột — hoặc là sự phục hồi được cần thiết trước khi chiến đấu, hoặc là sự yên tĩnh cuối cùng tìm thấy sau khi trận chiến kết thúc; cả hai đều liên quan đến cái giá của sự đối đầu.", en: "Four of Swords and Five of Swords: rest before or after conflict — either recovery needed before the fight or quiet finally found after the battle ends; both concern the cost of confrontation." },
  "53_55": { vi: "Bốn Kiếm và Sáu Kiếm: sự chữa lành cho phép hành trình — thời gian phục hồi trang bị cho tâm trí sức mạnh để vượt qua; chỉ khi ngủ đủ giấc mới có thể lái con thuyền đến bờ bình yên.", en: "Four of Swords and Six of Swords: healing enabling passage — the recovery period equipping the mind with the strength to cross over; only when rested enough can one steer the boat toward the peaceful shore." },
  "53_56": { vi: "Bốn Kiếm và Bảy Kiếm: rút lui chiến lược — nghỉ ngơi trong khi chuẩn bị kế hoạch tiếp theo; sự tĩnh lặng của Bốn không phải là sự bại trận mà là sự bảo toàn lực lượng cho thời điểm quan trọng hơn.", en: "Four of Swords and Seven of Swords: strategic retreat — resting while planning the next move; the Four's stillness is not defeat but conservation of strength for a more important moment ahead." },
  "53_57": { vi: "Bốn Kiếm và Tám Kiếm: hai dạng rút lui — một là sự chữa lành có chủ ý, một là sự tê liệt vô tình; bề ngoài trông giống nhau nhưng một cái dẫn đến sự phục hồi, cái kia cần sự phá vỡ để thoát ra.", en: "Four of Swords and Eight of Swords: two forms of withdrawal — one a deliberate healing, the other an accidental paralysis; both look similar from outside but one leads to recovery while the other requires breaking through." },
  "53_58": { vi: "Bốn Kiếm và Chín Kiếm: sự nghỉ ngơi không thể xoa dịu lo âu — tâm trí nằm xuống nhưng không ngủ được; ngay cả khi thể xác dừng lại, những lo lắng vẫn tiếp tục chạy như những bóng ma trong đầu.", en: "Four of Swords and Nine of Swords: rest unable to quiet anxiety — the mind lies down but cannot sleep; even when the body stops, the worries keep running like ghosts through the mind." },
  "53_59": { vi: "Bốn Kiếm và Mười Kiếm: sự nghỉ ngơi dài trước kết thúc cuối cùng — cả hai đều báo hiệu sự dừng lại trong hành trình, nhưng cái kết của Mười mang tính chất hoàn toàn khác; phần hồi kết đang đến, cần sẵn sàng để buông bỏ.", en: "Four of Swords and Ten of Swords: the long rest before the final ending — both signal a pause in the journey, but the Ten's conclusion is of a different nature entirely; the last chapter is approaching, readiness to release is needed." },
  "53_60": { vi: "Bốn Kiếm và Trang Bị Kiếm: việc học trong sự tĩnh lặng — Trang Bị khám phá ra rằng sự quan sát kiên nhẫn dạy nhiều như hành động; những bài học sâu sắc nhất đến khi tâm trí im lặng đủ để lắng nghe.", en: "Four of Swords and Page of Swords: learning in stillness — the Page discovering that patient observation teaches as much as action; the deepest lessons come when the mind is quiet enough to listen." },
  "53_61": { vi: "Bốn Kiếm và Kỵ Sĩ Kiếm: sự nghỉ ngơi đối lập với hành động — tâm trí tĩnh lặng gặp tâm trí không bao giờ ngừng xông pha; cả hai cần nhau để cân bằng, vì tốc độ mà không có sự phục hồi dẫn đến sự sụp đổ.", en: "Four of Swords and Knight of Swords: rest opposing action — the still mind meeting the one that never stops charging; each needs the other to balance, for speed without recovery leads to collapse." },
  "53_62": { vi: "Bốn Kiếm và Nữ Hoàng Kiếm: sự tĩnh lặng có chủ đích — Nữ Hoàng hiểu rằng sự im lặng chiến lược là một trong những công cụ sắc bén nhất của khí; nghỉ ngơi trước khi nói chính xác hơn xông vào quá sớm.", en: "Four of Swords and Queen of Swords: intentional stillness — the Queen understands that strategic silence is among air's sharpest tools; resting before speaking precisely is sharper than charging in too soon." },
  "53_63": { vi: "Bốn Kiếm và Vua Kiếm: sự tĩnh lặng tính toán — Vua biết khi nào cần chờ đợi trước khi đưa ra phán quyết; sức mạnh thực sự của trí tuệ không phải là nói ngay mà là nói đúng thời điểm.", en: "Four of Swords and King of Swords: calculated stillness — the King knowing when to wait before passing judgment; the true strength of intellect is not speaking immediately but speaking at the right moment." },

  "54_55": { vi: "Năm Kiếm và Sáu Kiếm: xung đột nhường chỗ cho sự di chuyển — chọn rời khỏi chiến trường; biết khi nào nên tiếp tục chiến đấu và khi nào nên rời đi là ranh giới giữa sự dũng cảm và sự khôn ngoan.", en: "Five of Swords and Six of Swords: conflict giving way to movement — choosing to leave the battlefield; knowing when to keep fighting and when to depart is the line between courage and wisdom." },
  "54_56": { vi: "Năm Kiếm và Bảy Kiếm: nhiều dạng xung đột — chiến đấu trực tiếp gặp chiến đấu xảo quyệt; khi không khí tràn ngập sự đối đầu, câu hỏi là liệu sức mạnh hay sự khéo léo mới là vũ khí thực sự hiệu quả.", en: "Five of Swords and Seven of Swords: multiple forms of conflict — open fighting meeting cunning combat; when the air is full of confrontation, the question is whether brute force or cleverness is the truly effective weapon." },
  "54_57": { vi: "Năm Kiếm và Tám Kiếm: chiến thắng dẫn đến sự cô lập — người thắng trong xung đột nhưng cuối cùng tự cô lập; chiến thắng bằng mọi giá để lại người chiến thắng bị trói buộc bởi những hậu quả của chính mình.", en: "Five of Swords and Eight of Swords: victory leading to isolation — winning the conflict but ending up alone and bound; winning at all costs leaves the victor trapped by the consequences of their own actions." },
  "54_58": { vi: "Năm Kiếm và Chín Kiếm: lo lắng về xung đột — tâm trí sống lại những trận chiến đã qua vào ban đêm; dù đã chiến thắng hay thất bại, ký ức về sự đối đầu tiếp tục quay trở lại như những bóng ma.", en: "Five of Swords and Nine of Swords: anxiety about conflict — the mind reliving past battles in the night; whether victorious or defeated, memories of confrontation keep returning as ghosts." },
  "54_59": { vi: "Năm Kiếm và Mười Kiếm: xung đột đạt đến hồi kết tuyệt đối — sau khi lưỡi kiếm đã chiến đấu đến cùng, chỉ còn lại hậu quả; không có cuộc chiến nào kéo dài mãi, và đây là minh chứng cho điều đó.", en: "Five of Swords and Ten of Swords: conflict reaching its absolute end — after swords have fought to the limit, only consequences remain; no battle lasts forever, and this is proof of that." },
  "54_60": { vi: "Năm Kiếm và Trang Bị Kiếm: tâm trí trẻ gặp xung đột — Trang Bị học rằng không phải mọi cuộc chiến đều xứng đáng để tham gia; bài học quan trọng nhất của khí đôi khi là biết từ chối chiến đấu.", en: "Five of Swords and Page of Swords: young mind encountering conflict — the Page learning that not every battle is worth entering; one of air's most important lessons is sometimes knowing how to refuse the fight." },
  "54_61": { vi: "Năm Kiếm và Kỵ Sĩ Kiếm: gây hấn kép — cả hai lá bài đều mang năng lượng chiến đấu; khi hai lưỡi kiếm tấn công cùng một lúc, thiệt hại cho tất cả những ai xung quanh là không thể tránh khỏi.", en: "Five of Swords and Knight of Swords: double aggression — both cards carry fighting energy; when two swords attack at once, damage to all those around is unavoidable." },
  "54_62": { vi: "Năm Kiếm và Nữ Hoàng Kiếm: xung đột được kiểm soát bởi sự khôn ngoan — Nữ Hoàng biết rằng không phải mọi trận chiến đều cần phải được đánh; bà chọn những trận chiến của mình và chiến đấu chúng với sự chính xác lạnh lùng.", en: "Five of Swords and Queen of Swords: conflict moderated by wisdom — the Queen knows not every battle needs to be fought; she chooses her battles and fights them with cold precision." },
  "54_63": { vi: "Năm Kiếm và Vua Kiếm: xung đột gặp thẩm quyền quyết đoán — Vua không bị cuốn vào trận chiến bốc đồng mà đứng trên cao hơn, nhìn thấy toàn cảnh và đưa ra phán quyết khi thời điểm thích hợp.", en: "Five of Swords and King of Swords: conflict meeting decisive authority — the King is not drawn into impulsive battle but stands above it, seeing the full picture and delivering judgment at the right moment." },

  "55_56": { vi: "Sáu Kiếm và Bảy Kiếm: thoát đi trong im lặng — rời khỏi rắc rối một cách khéo léo và kín đáo; đôi khi cách thông minh nhất để vượt qua một tình huống khó khăn là di chuyển trước khi ai đó nhận ra.", en: "Six of Swords and Seven of Swords: escape in silence — departing from trouble cleverly and quietly; sometimes the most intelligent way to navigate a difficult situation is to move before anyone notices." },
  "55_57": { vi: "Sáu Kiếm và Tám Kiếm: hành trình qua sự hạn chế — chuyển đổi mặc dù bị trói buộc hoặc hạn chế; con đường về phía trước tồn tại ngay cả khi tâm trí không hoàn toàn tự do, chỉ cần đặt một bước chân nhỏ.", en: "Six of Swords and Eight of Swords: passage through restriction — transition despite being bound or limited; the path forward exists even when the mind is not fully free, requiring only one small step to be taken." },
  "55_58": { vi: "Sáu Kiếm và Chín Kiếm: rời xa lo âu — nhẹ nhõm khi rời bỏ sự hỗn loạn tinh thần; hành trình sang bờ kia không chỉ là di chuyển về mặt địa lý mà còn là bước khỏi vòng xoáy lo lắng không hồi kết.", en: "Six of Swords and Nine of Swords: moving away from anxiety — the relief of departing from mental chaos; the journey to the other shore is not just physical movement but stepping out of the endless spiral of worry." },
  "55_59": { vi: "Sáu Kiếm và Mười Kiếm: hành trình sau kết thúc — tiến về phía trước sau mất mát hoàn toàn; khi tất cả đã tan vỡ, con thuyền vẫn có thể chèo, và bờ bên kia vẫn đang chờ đợi.", en: "Six of Swords and Ten of Swords: journey after the ending — moving forward after total loss; when everything has shattered, the boat can still be rowed, and the other shore is still waiting." },
  "55_60": { vi: "Sáu Kiếm và Trang Bị Kiếm: người học trẻ trên hành trình — Trang Bị khám phá ra rằng di chuyển đến vùng lãnh thổ mới là cách học hỏi hiệu quả nhất; những vùng nước mới dạy những bài học mà sách giáo khoa không bao giờ có thể.", en: "Six of Swords and Page of Swords: the young learner on a journey — the Page discovering that moving into new territory is the most effective way to learn; new waters teach what textbooks never can." },
  "55_61": { vi: "Sáu Kiếm và Kỵ Sĩ Kiếm: hành trình nhanh — di chuyển có mục đích và tốc độ; khi cả sự định hướng lẫn tốc độ cùng hiện diện, khoảng cách giữa điểm xuất phát và đích đến trở nên ngắn hơn đáng kể.", en: "Six of Swords and Knight of Swords: the swift journey — movement with purpose and speed; when both direction and velocity are present, the distance between departure and destination becomes significantly shorter." },
  "55_62": { vi: "Sáu Kiếm và Nữ Hoàng Kiếm: sự chuyển tiếp khôn ngoan — Nữ Hoàng dẫn dắt hành trình qua sóng gió bằng sự thấu hiểu đã được tích lũy; bà biết con đường vì đã từng đi qua những vùng nước này trước đây.", en: "Six of Swords and Queen of Swords: wise transition — the Queen guiding passage through difficulty with accumulated understanding; she knows the way because she has traveled these waters before." },
  "55_63": { vi: "Sáu Kiếm và Vua Kiếm: sự vượt qua có trật tự — thẩm quyền chỉ đạo phong trào và sự thay đổi; Vua ra lệnh cho sự chuyển tiếp không phải bằng sức mạnh mà bằng uy tín và sự rõ ràng của tầm nhìn.", en: "Six of Swords and King of Swords: the ordered crossing — authority directing movement and change; the King commands transition not through force but through the credibility and clarity of his vision." },

  "56_57": { vi: "Bảy Kiếm và Tám Kiếm: kẻ mưu mô bị bẫy — người dùng sự xảo quyệt cuối cùng bị bao vây bởi những hậu quả của chính mình; chiến lược không trung thực gieo mầm cho chính sự trói buộc mà nó muốn tránh.", en: "Seven of Swords and Eight of Swords: the schemer ensnared — the one who uses cunning eventually surrounded by the consequences of their own plans; dishonest strategy sows the very bondage it sought to avoid." },
  "56_58": { vi: "Bảy Kiếm và Chín Kiếm: lo lắng về sự gian dối — tâm trí bị ám ảnh bởi những kế hoạch của mình hoặc bởi nỗi sợ bị lừa dối vào ban đêm; sự xảo quyệt mà không có sự trung thực là nguồn gốc của lo âu sâu sắc nhất.", en: "Seven of Swords and Nine of Swords: anxiety about deception — the mind haunted by its own plans or by fear of being betrayed in the night; cunning without integrity is the source of the deepest anxiety." },
  "56_59": { vi: "Bảy Kiếm và Mười Kiếm: chiến lược thất bại — sự xảo quyệt bị vạch trần dẫn đến kết cục hoàn toàn; kế hoạch tinh vi nhất cũng có thể sụp đổ khi thực tế không chịu bị thao túng thêm nữa.", en: "Seven of Swords and Ten of Swords: the strategy that failed — cunning exposed leading to total defeat; even the most sophisticated plan can collapse when reality refuses to be manipulated any further." },
  "56_60": { vi: "Bảy Kiếm và Trang Bị Kiếm: tâm trí trẻ học về chiến lược — Trang Bị bị thu hút bởi sự xảo quyệt nhưng còn chưa hiểu sự khác biệt giữa sự lanh lợi thông minh và sự gian dối có hại.", en: "Seven of Swords and Page of Swords: the young mind learning about strategy — the Page attracted to cleverness but not yet understanding the difference between smart resourcefulness and harmful deception." },
  "56_61": { vi: "Bảy Kiếm và Kỵ Sĩ Kiếm: nhanh nhẹn và xảo quyệt — sức mạnh kết hợp giữa tốc độ và sự khéo léo; khi cả hai cùng hiện diện, rất ít kẻ thù có thể phản ứng kịp, nhưng tính liêm chính vẫn là ranh giới không thể vượt qua.", en: "Seven of Swords and Knight of Swords: agility and cunning — the combined power of speed and cleverness; when both are present, few opponents can react in time, but integrity remains the boundary that must not be crossed." },
  "56_62": { vi: "Bảy Kiếm và Nữ Hoàng Kiếm: sự khôn ngoan nhìn xuyên qua mọi mưu kế — Nữ Hoàng nhận ra sự xảo quyệt ngay lập tức và không bị lừa; bà có thể sử dụng chiến lược nhưng luôn từ chỗ đứng của sự trung thực và minh bạch.", en: "Seven of Swords and Queen of Swords: wisdom seeing through all schemes — the Queen recognizes cunning immediately and is never deceived; she can employ strategy but always from a position of honesty and transparency." },
  "56_63": { vi: "Bảy Kiếm và Vua Kiếm: thẩm quyền chiến lược — Vua sử dụng chiến lược tính toán từ chỗ đứng của sự minh bạch; ông không cần sự gian dối vì sức mạnh trí tuệ thực sự không bao giờ cần che giấu ý định.", en: "Seven of Swords and King of Swords: strategic authority — the King employing calculated strategy from a position of transparency; he does not need deception because true intellectual power never needs to hide its intentions." },

  "57_58": { vi: "Tám Kiếm và Chín Kiếm: đau khổ tinh thần kép — sự trói buộc và lo âu nuôi dưỡng lẫn nhau; khi tâm trí bị giam cầm và đồng thời bị tra tấn bởi lo lắng, chỉ có sự can thiệp từ bên ngoài hoặc sự chấp nhận toàn diện mới có thể giải thoát.", en: "Eight of Swords and Nine of Swords: double mental anguish — restriction and anxiety feeding each other; when the mind is both imprisoned and tormented by worry, only outside intervention or complete surrender can liberate." },
  "57_59": { vi: "Tám Kiếm và Mười Kiếm: từ bị giam cầm đến kết thúc — sự tích lũy của sự hạn chế tinh thần cuối cùng đạt đến điểm vỡ; điểm cuối này, dù đau đớn, là cánh cửa duy nhất dẫn ra khỏi bóng tối.", en: "Eight of Swords and Ten of Swords: from imprisonment to ending — the accumulation of mental restriction finally reaching the breaking point; this ending, though painful, is the only door out of the darkness." },
  "57_60": { vi: "Tám Kiếm và Trang Bị Kiếm: người học bị hạn chế — Trang Bị tìm kiếm kiến thức ngay cả khi bị giới hạn; sự tò mò không thể bị trói buộc hoàn toàn, và chỉ cần một tia sáng nhỏ của hiểu biết là đủ để bắt đầu tháo gỡ.", en: "Eight of Swords and Page of Swords: the restricted learner — the Page seeking knowledge even under limitation; curiosity cannot be wholly bound, and only a small ray of understanding is enough to begin unraveling the bonds." },
  "57_61": { vi: "Tám Kiếm và Kỵ Sĩ Kiếm: sự tự do thông qua hành động — Kỵ Sĩ có thể cắt đứt những sợi dây trói buộc; đôi khi sự tê liệt chỉ cần một hành động táo bạo để tan vỡ, ngay cả khi hành động đó có vẻ liều lĩnh.", en: "Eight of Swords and Knight of Swords: freedom through action — the Knight capable of cutting through the binding ropes; sometimes paralysis needs only one bold act to shatter, even if that act seems reckless." },
  "57_62": { vi: "Tám Kiếm và Nữ Hoàng Kiếm: sự khôn ngoan giải phóng sự hạn chế — cái nhìn rõ ràng của Nữ Hoàng nhận ra rằng sự trói buộc phần lớn là tự tạo ra; sự thấu hiểu của bà tan chảy những sợi dây tinh thần mà không cần một lưỡi kiếm vật lý nào.", en: "Eight of Swords and Queen of Swords: wisdom releasing restriction — the Queen's clear sight recognizing that bondage is largely self-created; her understanding dissolves mental bonds without needing any physical blade." },
  "57_63": { vi: "Tám Kiếm và Vua Kiếm: thẩm quyền ra lệnh tự do — Vua không chấp nhận sự tê liệt khi có thể hành động; bằng mệnh lệnh của ý chí và lý trí, ông phá vỡ sự hạn chế không cần thiết bằng một lời nói.", en: "Eight of Swords and King of Swords: authority commanding freedom — the King does not accept paralysis when action is possible; by the command of will and reason, he dissolves unnecessary restriction with a single word." },

  "58_59": { vi: "Chín Kiếm và Mười Kiếm: sự kết hợp tối tăm nhất của kiếm — nỗi đau tột cùng của ban đêm và cú đánh cuối cùng của ban ngày; đây là đáy sâu nhất mà khí có thể chạm tới, nhưng cũng chính là nền tảng từ đó sự hồi sinh là bắt buộc.", en: "Nine of Swords and Ten of Swords: the darkest combination of swords — the deepest nighttime anguish and the final daytime blow together; this is the lowest point air can reach, but also the foundation from which renewal becomes necessary." },
  "58_60": { vi: "Chín Kiếm và Trang Bị Kiếm: tâm trí trẻ bị lo âu ám ảnh — Trang Bị đang học cách sống với những suy nghĩ tối tăm; điều quan trọng là phân biệt giữa những mối nguy hiểm thực sự và những bóng ma mà tâm trí tự tạo ra.", en: "Nine of Swords and Page of Swords: young mind haunted by anxiety — the Page learning to live with dark thoughts; what matters is distinguishing between real dangers and the ghosts the mind manufactures for itself." },
  "58_61": { vi: "Chín Kiếm và Kỵ Sĩ Kiếm: lo âu thúc đẩy hành động — lao vào hành động từ nỗi sợ hãi chứ không phải từ lòng dũng cảm; Kỵ Sĩ chạy trốn những bóng ma của mình bằng cách không bao giờ dừng lại, nhưng chúng luôn luôn theo kịp.", en: "Nine of Swords and Knight of Swords: anxiety fueling the charge — rushing into action from fear rather than courage; the Knight fleeing his ghosts by never stopping, but they always catch up." },
  "58_62": { vi: "Chín Kiếm và Nữ Hoàng Kiếm: sự khôn ngoan xoa dịu lo âu — Nữ Hoàng, người đã từng ở trong bóng tối đó, biết cách đưa tâm trí trở về với thực tại; sự rõ ràng đã được mài giũa bởi đau khổ là liều thuốc duy nhất thực sự hiệu quả.", en: "Nine of Swords and Queen of Swords: wisdom soothing anxiety — the Queen, who has been in that darkness herself, knows how to bring the mind back to reality; clarity hardened by suffering is the only medicine that truly works." },
  "58_63": { vi: "Chín Kiếm và Vua Kiếm: thẩm quyền ra lệnh cho trật tự trong hỗn loạn của tâm trí — Vua áp đặt cấu trúc lên sự hỗn loạn cảm xúc không phải bằng sự phủ nhận mà bằng sự kỷ luật; lý trí không thể ngăn nỗi đau nhưng có thể ngăn nó chiếm toàn bộ lãnh thổ.", en: "Nine of Swords and King of Swords: authority commanding order in the mind's chaos — the King imposes structure on emotional chaos not through denial but through discipline; reason cannot prevent pain but can prevent it from occupying all territory." },

  "59_60": { vi: "Mười Kiếm và Trang Bị Kiếm: người học trẻ đứng trước kết thúc — Trang Bị chứng kiến hoặc trải qua một sự kết thúc hoàn toàn và học rằng ngay cả điều tồi tệ nhất cũng có thể là điểm bắt đầu của một điều gì đó mới.", en: "Ten of Swords and Page of Swords: the student at the ending — the Page witnessing or experiencing a total conclusion and learning that even the worst can be the starting point for something new." },
  "59_61": { vi: "Mười Kiếm và Kỵ Sĩ Kiếm: sự lao vào dẫn đến kết thúc — Kỵ Sĩ đến quá muộn hoặc quá nhanh; đôi khi tốc độ mà không có sự phán xét là nguyên nhân trực tiếp của cú sụp đổ cuối cùng.", en: "Ten of Swords and Knight of Swords: the charge leading to the ending — the Knight arriving too late or charging too fast; sometimes speed without judgment is the direct cause of the final downfall." },
  "59_62": { vi: "Mười Kiếm và Nữ Hoàng Kiếm: Nữ Hoàng vượt qua điều tồi tệ nhất — sự kiên cường và sự rõ ràng sau mất mát hoàn toàn; Nữ Hoàng đứng dậy sau thất bại tuyệt đối không phải vì không đau mà vì bà từ chối để nó xác định bà.", en: "Ten of Swords and Queen of Swords: the Queen surviving the worst — resilience and clarity after total loss; the Queen rising after absolute defeat not because she is not hurt but because she refuses to let it define her." },
  "59_63": { vi: "Mười Kiếm và Vua Kiếm: Vua chủ trì những kết thúc — thẩm quyền tại thời điểm kết luận hoàn toàn; Vua biết rằng một số kết thúc là cần thiết và phải được tuyên bố rõ ràng để một chương mới có thể bắt đầu.", en: "Ten of Swords and King of Swords: the King presiding over endings — authority at the moment of absolute conclusion; the King knows that some endings are necessary and must be clearly declared so a new chapter can begin." },

  "60_61": { vi: "Trang Bị Kiếm và Kỵ Sĩ Kiếm: tâm trí tò mò được đẩy nhanh bởi tham vọng — sự khám phá kiên nhẫn của Trang Bị được đẩy vào hành động bởi năng lượng của Kỵ Sĩ; cả hai cùng sắc bén nhưng cần học cách kiểm soát tốc độ của mình.", en: "Page of Swords and Knight of Swords: curious mind accelerated by ambition — the Page's patient exploration pushed into action by the Knight's energy; both are sharp but need to learn to govern their own speed." },
  "60_62": { vi: "Trang Bị Kiếm và Nữ Hoàng Kiếm: học trò và bậc thầy của không khí — Nữ Hoàng dạy Trang Bị rằng sự thật không chỉ cần được tìm thấy mà còn cần được nói đúng cách và đúng thời điểm; đây là bài học quan trọng nhất của kiếm.", en: "Page of Swords and Queen of Swords: student and master of air — the Queen teaching the Page that truth must not only be found but also spoken correctly and at the right moment; this is the most important lesson of swords." },
  "60_63": { vi: "Trang Bị Kiếm và Vua Kiếm: trí tuệ trẻ trước thẩm quyền cao nhất — Trang Bị học trọng lượng đầy đủ của sự thật từ Vua; sự tò mò cần được trả lời, nhưng chân lý mà không có sự khôn ngoan về hậu quả của nó là một thanh kiếm chưa được rèn xong.", en: "Page of Swords and King of Swords: young intellect before the highest authority — the Page learning the full weight of truth from the King; curiosity must be answered, but truth without wisdom about its consequences is an unfinished blade." },

  "61_62": { vi: "Kỵ Sĩ Kiếm và Nữ Hoàng Kiếm: tốc độ được điều tiết bởi sự khôn ngoan — sự lao vào của Kỵ Sĩ được kiểm soát bởi sự thấu hiểu của Nữ Hoàng; khi cả hai hoạt động cùng nhau, không khí đạt đến hình thức cân bằng nhất của nó.", en: "Knight of Swords and Queen of Swords: speed tempered by wisdom — the Knight's charge governed by the Queen's understanding; when both work together, air reaches its most balanced form." },
  "61_63": { vi: "Kỵ Sĩ Kiếm và Vua Kiếm: hai lưỡi kiếm trong chuyển động — sự xông pha của Kỵ Sĩ được hướng dẫn bởi chiến lược của Vua; khi nhiệt huyết và sự phán xét được kết hợp, sức mạnh của khí trở nên không thể cưỡng lại được.", en: "Knight of Swords and King of Swords: two swords in motion — the Knight's charge directed by the King's strategy; when enthusiasm and judgment are combined, the power of air becomes irresistible." },

  "62_63": { vi: "Nữ Hoàng Kiếm và Vua Kiếm: hai bộ óc vĩ đại của không khí — sự đồng cảm sắc bén và thẩm quyền lý trí kết hợp; khi cả hai nói, sự thật có tiếng nói đầy đủ nhất của nó: không có sự tàn nhẫn, không có sự mềm yếu, chỉ là chân lý hoàn hảo.", en: "Queen of Swords and King of Swords: the two great minds of air united — sharp empathy and rational authority combined; when both speak, truth has its fullest voice: no cruelty, no softness, only perfect clarity." },
  // ── Tier 4d: Pentacles same-suit (91 pairs) ──
  "64_65": { vi: "Át Tiền và Hai Tiền: hạt giống của sự thịnh vượng gặp sự cân bằng thực tế — tiềm năng vật chất thuần khiết học cách điều phối nhiều nguồn lực và ưu tiên; bắt đầu tốt đòi hỏi cả sự cam kết lẫn sự linh hoạt.", en: "Ace of Pentacles and Two of Pentacles: the seed of prosperity meeting practical balance — pure material potential learning to juggle multiple resources and priorities; starting well requires both commitment and flexibility." },
  "64_66": { vi: "Át Tiền và Ba Tiền: tiềm năng được xây dựng thành kỹ năng — hạt giống của đất trở thành bàn tay tạo ra thứ gì đó có giá trị; sự hợp tác và tay nghề là những con đường biến nguồn lực thô thành sự thịnh vượng lâu dài.", en: "Ace of Pentacles and Three of Pentacles: potential built into skill — the earth's seed becoming the hands that craft something of value; collaboration and craftsmanship are the paths that turn raw resource into lasting prosperity." },
  "64_67": { vi: "Át Tiền và Bốn Tiền: sự phong phú gặp sự tích lũy — khi tiềm năng vật chất gặp bản năng giữ chặt, câu hỏi là liệu sự bảo vệ hay sự chia sẻ mới tạo ra sự tăng trưởng thực sự trong đất.", en: "Ace of Pentacles and Four of Pentacles: abundance meeting accumulation — when material potential meets the hoarding instinct, the question is whether protection or sharing truly creates real growth in earth." },
  "64_68": { vi: "Át Tiền và Năm Tiền: tiềm năng trước sự nghèo khó — hạt giống của sự sung túc có thể chưa được biết đến khi đang ở trong khốn khó; đôi khi cơ hội thực sự tồn tại ngay cả trong những hoàn cảnh tối tăm nhất.", en: "Ace of Pentacles and Five of Pentacles: potential before hardship — the seed of abundance may be unknown when one is in dire straits; sometimes the real opportunity exists even within the darkest circumstances." },
  "64_69": { vi: "Át Tiền và Sáu Tiền: hạt giống của sự cho đi — tiềm năng vật chất thuần khiết gặp nguyên tắc của sự cân bằng trao và nhận; sự thịnh vượng thực sự không chỉ được tích lũy mà còn được lưu thông.", en: "Ace of Pentacles and Six of Pentacles: the seed of giving — pure material potential meeting the principle of balanced giving and receiving; real prosperity is not only accumulated but also circulated." },
  "64_70": { vi: "Át Tiền và Bảy Tiền: tiềm năng đòi hỏi sự kiên nhẫn — hạt giống phải chờ đợi mùa thu hoạch; đất dạy rằng những điều tốt nhất đòi hỏi thời gian và sự đánh giá lại trung thực về việc đang tiến triển như thế nào.", en: "Ace of Pentacles and Seven of Pentacles: potential requiring patience — the seed must wait for harvest time; earth teaches that the best things require time and an honest reassessment of how things are actually progressing." },
  "64_71": { vi: "Át Tiền và Tám Tiền: hạt giống của sự thành thạo — tiềm năng vật chất gặp sự cống hiến không ngừng nghỉ cho tay nghề; những gì bắt đầu như một cơ hội trở thành sự xuất sắc thông qua sự tập trung không mệt mỏi.", en: "Ace of Pentacles and Eight of Pentacles: the seed of mastery — material potential meeting tireless dedication to craft; what begins as an opportunity becomes excellence through unwavering focus." },
  "64_72": { vi: "Át Tiền và Chín Tiền: hạt giống của sự độc lập — tiềm năng được nuôi dưỡng đúng cách dẫn đến vườn riêng của mình; kết quả của sự kiên nhẫn và tự lực là sự thịnh vượng tự chủ mà không ai có thể lấy đi.", en: "Ace of Pentacles and Nine of Pentacles: the seed of independence — potential properly cultivated leading to one's own garden; the result of patience and self-reliance is autonomous prosperity that no one can take away." },
  "64_73": { vi: "Át Tiền và Mười Tiền: hạt giống của di sản — tiềm năng được thực hiện đầy đủ qua nhiều thế hệ; mọi gia tài vĩ đại đều bắt đầu từ một hạt nhân duy nhất được gieo với ý định và được chăm sóc qua thời gian.", en: "Ace of Pentacles and Ten of Pentacles: the seed of legacy — potential fully realized across generations; every great fortune begins from a single seed planted with intention and tended through time." },
  "64_74": { vi: "Át Tiền và Trang Bị Tiền: hạt giống trong tay người học — Trang Bị nhận ra cơ hội vật chất và bắt đầu khám phá nó với sự cẩn thận và niềm hứng khởi; đây là khoảnh khắc khi giấc mơ gặp mảnh đất thực tế đầu tiên.", en: "Ace of Pentacles and Page of Pentacles: the seed in the learner's hands — the Page recognizing a material opportunity and beginning to explore it with care and enthusiasm; this is when a dream first touches real earth." },
  "64_75": { vi: "Át Tiền và Kỵ Sĩ Tiền: tiềm năng được thực hiện một cách có phương pháp — Kỵ Sĩ không lãng phí hạt giống mà làm việc đều đặn để biến nó thành hiện thực; sự thịnh vượng được xây dựng từng bước không ấn tượng nhưng không thể nghi ngờ.", en: "Ace of Pentacles and Knight of Pentacles: potential realized methodically — the Knight does not waste the seed but works steadily to make it real; prosperity built step by step is unimpressive but undeniable." },
  "64_76": { vi: "Át Tiền và Nữ Hoàng Tiền: hạt giống được nuôi dưỡng bởi bàn tay khôn ngoan — Nữ Hoàng biết đất cần gì để phát triển; sự kết hợp của tiềm năng và sự chăm sóc ân cần tạo ra sự thịnh vượng sống động và bền vững.", en: "Ace of Pentacles and Queen of Pentacles: the seed nurtured by wise hands — the Queen knows what the earth needs to flourish; the combination of potential and tender care creates living, sustainable prosperity." },
  "64_77": { vi: "Át Tiền và Vua Tiền: hạt giống trong tay người kiến tạo vĩ đại — Vua biết cách biến một cơ hội duy nhất thành một đế chế; tầm nhìn chiến lược và sự kiên định của đất làm cho những gì ban đầu nhỏ bé trở thành điều khổng lồ.", en: "Ace of Pentacles and King of Pentacles: the seed in the great builder's hands — the King knows how to turn a single opportunity into an empire; strategic vision and earth's steadiness make what begins small eventually become immense." },

  "65_66": { vi: "Hai Tiền và Ba Tiền: sự cân bằng hỗ trợ tay nghề — giữ nhiều thứ trong không khí cùng lúc trong khi vẫn đóng góp có ý nghĩa vào công việc nhóm; sự linh hoạt thực tế và sự hợp tác đều quan trọng như nhau.", en: "Two of Pentacles and Three of Pentacles: balance supporting craft — juggling many things at once while still contributing meaningfully to team work; practical flexibility and collaboration are equally important." },
  "65_67": { vi: "Hai Tiền và Bốn Tiền: dao động giữa linh hoạt và kiểm soát — một bên thích ứng với dòng chảy của cuộc sống, một bên bám chặt những gì đã có; sự cân bằng thực sự nằm ở chỗ biết khi nào nên giữ và khi nào nên buông.", en: "Two of Pentacles and Four of Pentacles: oscillating between flexibility and control — one adapting to life's flow, the other clinging to what is already held; true balance lies in knowing when to hold and when to release." },
  "65_68": { vi: "Hai Tiền và Năm Tiền: cân bằng trong gian khó — tiếp tục điều phối các ưu tiên ngay cả khi nguồn lực ít; khó khăn không dừng nhu cầu phải lựa chọn khéo léo mà thực ra làm sắc nét hơn khả năng đó.", en: "Two of Pentacles and Five of Pentacles: balance under hardship — continuing to juggle priorities even when resources are scarce; difficulty does not stop the need for skillful choices but actually sharpens that ability." },
  "65_69": { vi: "Hai Tiền và Sáu Tiền: cân bằng trong sự chia sẻ — quản lý những gì mình có trong khi vẫn biết cách trao và nhận; giữ vững sự ổn định trong khi lưu thông sự giàu có là một trong những kỹ năng thiết thực nhất của đất.", en: "Two of Pentacles and Six of Pentacles: balance in sharing — managing what one has while knowing how to give and receive; maintaining stability while circulating wealth is one of earth's most practical skills." },
  "65_70": { vi: "Hai Tiền và Bảy Tiền: điều phối trong khi chờ đợi — tiếp tục xoay xở hàng ngày trong khi đồng thời đánh giá các dự án dài hạn; sự kiên nhẫn và sự thực tế cùng cần thiết để không bị cuốn đi bởi cả bận rộn lẫn sự chờ đợi.", en: "Two of Pentacles and Seven of Pentacles: juggling while waiting — continuing to manage daily affairs while simultaneously assessing long-term projects; patience and practicality are both needed to avoid being swept away by busyness or waiting." },
  "65_71": { vi: "Hai Tiền và Tám Tiền: tung hứng và chuyên tâm — khả năng làm nhiều việc gặp sự cống hiến cho một việc duy nhất; biết khi nào cần mở rộng và khi nào cần thu hẹp là trí tuệ thực hành của đất.", en: "Two of Pentacles and Eight of Pentacles: juggling and dedication — the ability to do many things meeting dedication to one single thing; knowing when to expand and when to narrow down is earth's practical wisdom." },
  "65_72": { vi: "Hai Tiền và Chín Tiền: sự thích ứng dẫn đến sự tự chủ — linh hoạt hàng ngày được xây dựng theo thời gian thành sự độc lập vật chất; người học cách điều hành nhiều thứ cùng lúc cuối cùng học cách điều hành vườn của riêng mình.", en: "Two of Pentacles and Nine of Pentacles: adaptability leading to autonomy — daily flexibility built over time into material independence; one who learns to manage many things at once eventually learns to manage their own garden." },
  "65_73": { vi: "Hai Tiền và Mười Tiền: cân bằng xây dựng di sản — những điều chỉnh thực tế hàng ngày tích lũy thành nền tảng gia đình và di sản; không có sự thịnh vượng nào của Mười tồn tại mà không có sự khéo léo thường ngày của Hai.", en: "Two of Pentacles and Ten of Pentacles: balance building legacy — daily practical adjustments accumulating into family foundations and lasting heritage; no Ten's prosperity exists without the Two's everyday skillfulness behind it." },
  "65_74": { vi: "Hai Tiền và Trang Bị Tiền: người học điều phối nhiều thứ — Trang Bị khám phá ra rằng cuộc sống đòi hỏi sự cân bằng nhiều nhiệm vụ cùng một lúc; bài học đầu tiên của đất thường là quản lý thời gian và ưu tiên.", en: "Two of Pentacles and Page of Pentacles: the learner juggling many things — the Page discovering that life requires balancing multiple responsibilities simultaneously; earth's first lesson is often time management and prioritization." },
  "65_75": { vi: "Hai Tiền và Kỵ Sĩ Tiền: điều phối với sự kiên định — Kỵ Sĩ không bị phân tâm bởi nhiều thứ mà tiến đều đặn ngay cả khi mang nhiều gánh nặng; sự đáng tin cậy chính là cách xử lý gánh nặng mà không có tiếng ồn hay than vãn.", en: "Two of Pentacles and Knight of Pentacles: juggling with steadiness — the Knight not distracted by many things but moving consistently even when carrying multiple loads; reliability is handling burden without noise or complaint." },
  "65_76": { vi: "Hai Tiền và Nữ Hoàng Tiền: sự duyên dáng trong sự cân bằng — Nữ Hoàng quản lý vô số trách nhiệm mà làm cho nó trông dễ dàng; sự khéo léo thực tế của bà là tài sản vô hình nhất và không thể thiếu nhất.", en: "Two of Pentacles and Queen of Pentacles: grace in balance — the Queen managing countless responsibilities making it all look effortless; her practical dexterity is the most invisible and indispensable asset." },
  "65_77": { vi: "Hai Tiền và Vua Tiền: cân bằng trong đế chế — Vua điều phối những nguồn lực khổng lồ, nhiều luồng thu nhập, và những quyết định cạnh tranh mà không để bất kỳ điều gì mất kiểm soát; đây là đất ở hình thức quản lý hoàn hảo nhất của nó.", en: "Two of Pentacles and King of Pentacles: balance within empire — the King coordinating vast resources, multiple income streams, and competing decisions without losing control of any; this is earth in its most masterful management form." },

  "66_67": { vi: "Ba Tiền và Bốn Tiền: tay nghề gặp sự bảo vệ — người thợ thủ công giỏi có thể muốn bảo vệ phương pháp của mình, nhưng sự kiểm soát quá mức cản trở sự hợp tác; đất phát triển khi kỹ năng được chia sẻ, không phải khi được giữ bí mật.", en: "Three of Pentacles and Four of Pentacles: craft meeting protection — the skilled craftsman may want to guard their methods, but over-control hinders collaboration; earth thrives when skill is shared, not when it is kept secret." },
  "66_68": { vi: "Ba Tiền và Năm Tiền: công trình giữa khó khăn — tiếp tục xây dựng dù nguồn lực hạn chế; những công trình được hoàn thành trong thời gian thiếu thốn thường vững chắc hơn những gì được xây dựng trong sự tiện nghi.", en: "Three of Pentacles and Five of Pentacles: craft during hardship — continuing to build despite limited resources; works completed during times of scarcity are often more solid than those built in comfort." },
  "66_69": { vi: "Ba Tiền và Sáu Tiền: công việc và phần thưởng công bằng — sự hợp tác thực sự đòi hỏi sự phân chia công bằng những gì được tạo ra; khi người thợ được trả công xứng đáng, năng lượng tập thể của đất phát triển mạnh mẽ nhất.", en: "Three of Pentacles and Six of Pentacles: craft and fair reward — true collaboration requires fair division of what is created; when craftspeople are properly compensated, earth's collective energy thrives most fully." },
  "66_70": { vi: "Ba Tiền và Bảy Tiền: tay nghề cần đánh giá — dự án nhóm cần những khoảnh khắc kiểm tra định kỳ để đảm bảo công việc đang đi đúng hướng; bước lùi để nhìn nhận mang lại sự rõ ràng mà sự chú tâm hàng ngày không thể cung cấp.", en: "Three of Pentacles and Seven of Pentacles: craft needing assessment — team projects need periodic check-in moments to ensure the work is on track; stepping back to evaluate offers clarity that daily immersion cannot provide." },
  "66_71": { vi: "Ba Tiền và Tám Tiền: hai mặt của tay nghề — làm việc nhóm và làm việc một mình đều cần thiết trong sự phát triển nghề nghiệp; người thợ giỏi biết khi nào cần sự đóng góp của người khác và khi nào cần không gian im lặng để tập trung.", en: "Three of Pentacles and Eight of Pentacles: two faces of craft — teamwork and solitary work are both necessary in professional development; the skilled craftsman knows when to invite others' input and when to need silent space to focus." },
  "66_72": { vi: "Ba Tiền và Chín Tiền: hợp tác xây dựng sự độc lập — sự cống hiến cộng đồng và những kỹ năng được phát triển trong môi trường làm việc nhóm cuối cùng tạo ra nền tảng cho sự tự chủ cá nhân; không ai đến được vườn riêng mà không qua giai đoạn học hỏi từ người khác.", en: "Three of Pentacles and Nine of Pentacles: collaboration building independence — skills developed in collaborative environments ultimately create the foundation for personal autonomy; no one reaches their own garden without first learning from others." },
  "66_73": { vi: "Ba Tiền và Mười Tiền: nghề nghiệp xây dựng di sản — công trình được tạo ra cùng nhau, từng viên gạch một, hình thành nền tảng của sự thịnh vượng gia đình và cộng đồng qua các thế hệ; tay nghề truyền lại là di sản thực sự.", en: "Three of Pentacles and Ten of Pentacles: craft building legacy — works created together, brick by brick, forming the foundation of family and community prosperity across generations; passed-down craftsmanship is the real inheritance." },
  "66_74": { vi: "Ba Tiền và Trang Bị Tiền: người học trong môi trường nhóm — Trang Bị tham gia vào một dự án hợp tác và phát hiện ra rằng học từ những người thợ lành nghề xung quanh mình nhanh hơn nhiều so với học một mình.", en: "Three of Pentacles and Page of Pentacles: the learner in a team environment — the Page joining a collaborative project and discovering that learning from skilled craftspeople around them is far faster than learning alone." },
  "66_75": { vi: "Ba Tiền và Kỵ Sĩ Tiền: hợp tác kiên định — Kỵ Sĩ là thành viên nhóm đáng tin cậy nhất; bước tiến ổn định của anh ấy trong công việc nhóm không gây ấn tượng nhưng đảm bảo rằng thứ gì đó thực sự được xây dựng xong.", en: "Three of Pentacles and Knight of Pentacles: steady collaboration — the Knight is the most reliable team member; his steady progress in group work is unimpressive but ensures that something actually gets completed." },
  "66_76": { vi: "Ba Tiền và Nữ Hoàng Tiền: người giám hộ của công trình — Nữ Hoàng không chỉ đóng góp vào công việc nhóm mà còn nuôi dưỡng môi trường làm cho công việc đó thành công; bà hiểu rằng đất phát triển tốt nhất khi được chăm sóc đúng cách.", en: "Three of Pentacles and Queen of Pentacles: guardian of the work — the Queen not only contributes to team effort but nurtures the environment that makes the work succeed; she understands earth thrives best when properly tended." },
  "66_77": { vi: "Ba Tiền và Vua Tiền: lãnh đạo công trình vĩ đại — Vua biết cách tổ chức tài năng tập thể để tạo ra điều gì đó to lớn hơn bất kỳ cá nhân nào; kiến trúc sư của các tổ chức biết cách làm cho mỗi viên gạch đúng chỗ.", en: "Three of Pentacles and King of Pentacles: leader of great works — the King knowing how to organize collective talent to create something larger than any individual; architects of organizations know how to place each brick in the right place." },

  "67_68": { vi: "Bốn Tiền và Năm Tiền: tích lũy trước hoặc sau mất mát — nắm chặt những gì mình có vì sợ nghèo, hoặc nghèo vì đã nắm chặt quá lâu; lằn ranh giữa sự thận trọng và sự keo kiệt mỏng hơn người ta nghĩ.", en: "Four of Pentacles and Five of Pentacles: hoarding before or after loss — clinging to what one has out of fear of poverty, or impoverished because one held on too long; the line between prudence and miserliness is thinner than people think." },
  "67_69": { vi: "Bốn Tiền và Sáu Tiền: kiểm soát đối lập với sự chia sẻ — bám chặt gặp sự lưu thông tự do; sức căng giữa bảo vệ những gì mình có và chia sẻ sự giàu có là một trong những câu hỏi trung tâm của đất.", en: "Four of Pentacles and Six of Pentacles: control opposing sharing — clinging meeting free circulation; the tension between protecting what one has and sharing wealth is one of earth's central questions." },
  "67_70": { vi: "Bốn Tiền và Bảy Tiền: kiểm soát và sự kiên nhẫn — cả hai đều dừng lại, nhưng Bốn bám chặt và Bảy quan sát; sự khác biệt nằm ở liệu sự dừng lại là từ nỗi sợ mất mát hay từ sự khôn ngoan về thời gian.", en: "Four of Pentacles and Seven of Pentacles: control and patience — both pause, but the Four clings and the Seven observes; the difference lies in whether the pause comes from fear of loss or from wisdom about timing." },
  "67_71": { vi: "Bốn Tiền và Tám Tiền: tích lũy và tay nghề — tích góp của cải có thể làm mù quáng con người đến nỗi bỏ lỡ giá trị của kỹ năng; ngược lại, tập trung vào tay nghề mà không quan tâm đến tài chính cũng có thể là một cái bẫy.", en: "Four of Pentacles and Eight of Pentacles: accumulation and craft — hoarding wealth can blind one to the value of skill; conversely, focusing on craft without caring for finances can be its own trap." },
  "67_72": { vi: "Bốn Tiền và Chín Tiền: kiểm soát và sự độc lập — cả hai đều liên quan đến việc có đủ cho bản thân, nhưng Chín được xây dựng trên sự sung túc tự chủ trong khi Bốn được xây dựng trên nỗi sợ; một loại có cửa, loại kia có tường.", en: "Four of Pentacles and Nine of Pentacles: control and independence — both concern having enough for oneself, but the Nine is built on self-cultivated abundance while the Four is built on fear; one kind has doors, the other has walls." },
  "67_73": { vi: "Bốn Tiền và Mười Tiền: sự tích lũy cá nhân và di sản gia đình — giữ chặt cho bản thân đối lập với sự thịnh vượng được chia sẻ qua các thế hệ; những gia đình xây dựng di sản thực sự học cách buông tay đúng lúc và đúng cách.", en: "Four of Pentacles and Ten of Pentacles: personal accumulation versus family legacy — holding tight for oneself opposing prosperity shared across generations; families that build real legacy learn to release at the right time and in the right way." },
  "67_74": { vi: "Bốn Tiền và Trang Bị Tiền: sự kiểm soát được Trang Bị thách thức — người học hỏi, với những câu hỏi mới mẻ, làm lung lay sự chắc chắn của người nắm chặt; đôi khi nhìn qua đôi mắt tươi mới nhất chính là thứ làm cho đất bắt đầu sinh sôi trở lại.", en: "Four of Pentacles and Page of Pentacles: control challenged by the Page — the learner, with fresh questions, unsettles the certainty of one who clings; sometimes looking through the freshest eyes is what makes earth begin to grow again." },
  "67_75": { vi: "Bốn Tiền và Kỵ Sĩ Tiền: sự kiểm soát gặp sự kiên định — cả hai đều cẩn thận với nguồn lực, nhưng Kỵ Sĩ tiến về phía trước trong khi Bốn đứng im; sự kiên định hiệu quả hơn sự đứng yên vì nó xây dựng thứ gì đó thực sự.", en: "Four of Pentacles and Knight of Pentacles: control meeting steadiness — both are careful with resources, but the Knight moves forward while the Four stands still; steady movement is more effective than frozen stillness because it builds something real." },
  "67_76": { vi: "Bốn Tiền và Nữ Hoàng Tiền: sự kiểm soát được chuyển hóa bởi sự nuôi dưỡng — Nữ Hoàng biết rằng của cải chỉ tăng trưởng khi được chia sẻ đúng cách; sự tích trữ quá mức có thể được xoa dịu bởi bàn tay ân cần biết cách trân trọng sự phong phú.", en: "Four of Pentacles and Queen of Pentacles: control transformed by nurturing — the Queen knowing that wealth only grows when properly shared; over-hoarding can be softened by the generous hand that knows how to honor abundance." },
  "67_77": { vi: "Bốn Tiền và Vua Tiền: hai hình thức bảo vệ tài sản — Bốn giữ chặt vì sợ, Vua giữ chặt vì khôn ngoan; sự khác biệt là Vua biết khi nào đầu tư và khi nào giữ, trong khi Bốn không thể phân biệt.", en: "Four of Pentacles and King of Pentacles: two forms of protecting wealth — the Four holds tight from fear, the King holds tight from wisdom; the difference is the King knows when to invest and when to keep, while the Four cannot distinguish." },

  "68_69": { vi: "Năm Tiền và Sáu Tiền: từ nghèo khó đến sự hào phóng — sự cứu trợ đến từ bên ngoài khi bản thân không đủ khả năng; nhận sự giúp đỡ là bài học của đất cũng quan trọng như biết cách cho đi.", en: "Five of Pentacles and Six of Pentacles: from hardship to generosity — relief coming from outside when one cannot manage alone; receiving help is an earth lesson as important as knowing how to give." },
  "68_70": { vi: "Năm Tiền và Bảy Tiền: khó khăn đòi hỏi sự kiên nhẫn — trong khi đang thiếu thốn, phải tiếp tục chờ đợi mùa thu hoạch đến; không từ bỏ trong thời điểm khắc nghiệt nhất là hình thức dũng cảm thực tế nhất của đất.", en: "Five of Pentacles and Seven of Pentacles: hardship requiring patience — while in scarcity, one must continue waiting for harvest time; not giving up during the hardest moments is earth's most practical form of courage." },
  "68_71": { vi: "Năm Tiền và Tám Tiền: nghèo khó khuyến khích tay nghề — khi không có nhiều, kỹ năng là tài sản quý giá nhất; những người phát triển thành thạo trong thời điểm thiếu thốn thường trở thành những người tạo ra giá trị bền vững nhất.", en: "Five of Pentacles and Eight of Pentacles: hardship inspiring craft — when there is little, skill is the most valuable asset; those who develop mastery during times of scarcity often become the most sustainably valuable creators." },
  "68_72": { vi: "Năm Tiền và Chín Tiền: từ khốn khó đến sung túc — hai thái cực của đất; hành trình từ thiếu thốn đến tự chủ không ngắn cũng không dễ nhưng hoàn toàn có thể thực hiện được với sự kiên trì và kỹ năng.", en: "Five of Pentacles and Nine of Pentacles: from hardship to abundance — the two poles of earth; the journey from scarcity to autonomy is neither short nor easy but entirely achievable with perseverance and skill." },
  "68_73": { vi: "Năm Tiền và Mười Tiền: khó khăn trước di sản — ngay cả những gia đình thịnh vượng nhất cũng có trong lịch sử của mình những khoảng thời gian thiếu thốn; sự thịnh vượng được trân trọng nhất bởi những người nhớ khi không có gì.", en: "Five of Pentacles and Ten of Pentacles: hardship before legacy — even the most prosperous families have in their history periods of scarcity; prosperity is most appreciated by those who remember having nothing." },
  "68_74": { vi: "Năm Tiền và Trang Bị Tiền: người học trong hoàn cảnh khó khăn — Trang Bị tiếp tục theo đuổi kiến thức ngay cả khi điều kiện vật chất không ủng hộ; sự tò mò và quyết tâm là nguồn tài nguyên không thể bị nghèo khó lấy đi.", en: "Five of Pentacles and Page of Pentacles: the learner in difficult circumstances — the Page continuing to pursue knowledge even when material conditions are unsupportive; curiosity and determination are resources that hardship cannot take away." },
  "68_75": { vi: "Năm Tiền và Kỵ Sĩ Tiền: kiên định trong gian khó — Kỵ Sĩ tiếp tục đi ngay cả khi con đường khó khăn; sự kiên trì mà không bị lung lay bởi tình trạng thiếu thốn tạm thời là bản chất sâu nhất của đất ở trạng thái tốt nhất.", en: "Five of Pentacles and Knight of Pentacles: steadiness in hardship — the Knight continuing on even when the road is difficult; perseverance not shaken by temporary scarcity is earth's deepest nature at its best." },
  "68_76": { vi: "Năm Tiền và Nữ Hoàng Tiền: sự chăm sóc trong khó khăn — Nữ Hoàng biết cách tạo ra sự phong phú từ sự khan hiếm và chưa bao giờ để người thân của bà thiếu ăn; kỹ năng của bà biến những nguồn lực nhỏ bé thành sự ấm áp và đủ đầy.", en: "Five of Pentacles and Queen of Pentacles: care in hardship — the Queen knowing how to create abundance from scarcity and never letting those she tends go without; her skill transforms meager resources into warmth and sufficiency." },
  "68_77": { vi: "Năm Tiền và Vua Tiền: thẩm quyền gặp khốn khó — Vua hiểu rằng sự giàu có thực sự bao gồm việc biết cách giúp đỡ những người đang thiếu thốn trong lãnh địa của mình; một đế chế được xây dựng tốt không để ai trong phạm vi của nó bị bỏ lại phía sau.", en: "Five of Pentacles and King of Pentacles: authority meeting hardship — the King understanding that true wealth includes knowing how to assist those in scarcity within his domain; a well-built empire does not leave anyone within its reach behind." },

  "69_70": { vi: "Sáu Tiền và Bảy Tiền: cho đi trong khi chờ đợi — sự hào phóng không ngừng ngay cả trong những thời điểm đánh giá lại; biết cách chia sẻ trong khi kiên nhẫn với kết quả của mình là sự trưởng thành thực sự của đất.", en: "Six of Pentacles and Seven of Pentacles: giving while waiting — generosity not pausing even during periods of reassessment; knowing how to share while being patient with one's own results is earth's real maturity." },
  "69_71": { vi: "Sáu Tiền và Tám Tiền: sự hào phóng và tay nghề — trả công xứng đáng cho công việc được thực hiện tốt; khi giá trị của kỹ năng được ghi nhận và đền bù đúng cách, toàn bộ nền kinh tế của đất trở nên lành mạnh hơn.", en: "Six of Pentacles and Eight of Pentacles: generosity and craft — fairly compensating work done well; when the value of skill is recognized and properly rewarded, earth's entire economy becomes healthier." },
  "69_72": { vi: "Sáu Tiền và Chín Tiền: sự chia sẻ và sự tự chủ — biết cách cho đi từ nơi sung túc mà không đánh mất sự độc lập; người đã đạt được sự đủ đầy của riêng mình có thể cho đi một cách tự do mà không lo sợ về việc mất mát.", en: "Six of Pentacles and Nine of Pentacles: sharing and autonomy — knowing how to give from a place of abundance without losing independence; one who has achieved their own sufficiency can give freely without fear of loss." },
  "69_73": { vi: "Sáu Tiền và Mười Tiền: sự lưu thông xây dựng di sản — của cải được chia sẻ và lưu thông trong cộng đồng tạo ra sự thịnh vượng bền vững hơn nhiều so với những gì được tích trữ; di sản gia đình được nuôi dưỡng bởi sự hào phóng theo từng thế hệ.", en: "Six of Pentacles and Ten of Pentacles: circulation building legacy — wealth shared and circulated within community creates far more sustainable prosperity than anything hoarded; family legacy is nurtured by generosity across each generation." },
  "69_74": { vi: "Sáu Tiền và Trang Bị Tiền: người trẻ học về sự trao và nhận — Trang Bị khám phá ra rằng sự phong phú thực sự không phải là về việc tích lũy mà là về việc tham gia vào dòng chảy của sự trao đổi giá trị.", en: "Six of Pentacles and Page of Pentacles: the young person learning about giving and receiving — the Page discovering that real abundance is not about accumulation but about participating in the flow of value exchange." },
  "69_75": { vi: "Sáu Tiền và Kỵ Sĩ Tiền: sự hào phóng ổn định — Kỵ Sĩ hỗ trợ người khác một cách đáng tin cậy và nhất quán; sự hào phóng không cần phải ầm ĩ hoặc kịch tính để có ý nghĩa, đôi khi sự đáng tin cậy là hình thức quan tâm nhất.", en: "Six of Pentacles and Knight of Pentacles: steady generosity — the Knight supporting others reliably and consistently; generosity does not need to be loud or dramatic to be meaningful, sometimes reliability is the most caring form." },
  "69_76": { vi: "Sáu Tiền và Nữ Hoàng Tiền: sự chăm sóc hào phóng — Nữ Hoàng cho đi một cách tự nhiên và không mệt mỏi; khả năng nuôi dưỡng của bà không bị cạn kiệt bởi sự trao đi vì bà hiểu rằng chăm sóc người khác cũng nuôi dưỡng chính bản thân mình.", en: "Six of Pentacles and Queen of Pentacles: generous care — the Queen giving naturally and tirelessly; her nurturing capacity is not depleted by giving because she understands that caring for others also nourishes oneself." },
  "69_77": { vi: "Sáu Tiền và Vua Tiền: thịnh vượng được phân phối bởi thẩm quyền — Vua sử dụng ảnh hưởng của mình để đảm bảo rằng sự giàu có được lưu thông hợp lý trong lãnh địa; trách nhiệm của sự giàu có là sử dụng nó để xây dựng điều gì đó lớn hơn bản thân.", en: "Six of Pentacles and King of Pentacles: prosperity distributed by authority — the King using his influence to ensure wealth circulates properly through the domain; the responsibility of wealth is using it to build something greater than oneself." },

  "70_71": { vi: "Bảy Tiền và Tám Tiền: đánh giá và tập trung — biết liệu công việc hiện tại có xứng đáng tiếp tục không, sau đó cam kết hoàn toàn nếu câu trả lời là có; sự thành thạo đòi hỏi cả sự xem xét trung thực lẫn sự cống hiến không mệt mỏi.", en: "Seven of Pentacles and Eight of Pentacles: assessment and focus — honestly deciding if current work deserves to continue, then committing fully if the answer is yes; mastery requires both honest evaluation and tireless dedication." },
  "70_72": { vi: "Bảy Tiền và Chín Tiền: sự kiên nhẫn và sự sung túc — đánh giá lại dẫn đến sự phong phú được vun trồng cẩn thận; khi người ta biết những gì đang thực sự hoạt động và tập trung vào đó, vườn riêng của mình cuối cùng cũng trở nên đầy đủ.", en: "Seven of Pentacles and Nine of Pentacles: patience and abundance — honest reassessment leading to carefully cultivated richness; when one knows what is actually working and focuses on that, one's own garden eventually becomes full." },
  "70_73": { vi: "Bảy Tiền và Mười Tiền: đánh giá dẫn đến di sản — các cuộc kiểm tra định kỳ của tiến trình, được thực hiện một cách trung thực, là điều tạo nên sự khác biệt giữa sự thịnh vượng bình thường và di sản kéo dài qua nhiều thế hệ.", en: "Seven of Pentacles and Ten of Pentacles: assessment leading to legacy — periodic honest reviews of progress are what create the difference between ordinary prosperity and a legacy that lasts across generations." },
  "70_74": { vi: "Bảy Tiền và Trang Bị Tiền: học cách đánh giá tiến trình — Trang Bị học một trong những kỹ năng khó nhất của đất: sự kiên nhẫn để chờ đợi kết quả và sự trung thực để đánh giá chúng một cách khách quan.", en: "Seven of Pentacles and Page of Pentacles: learning to assess progress — the Page learning one of earth's hardest skills: the patience to wait for results and the honesty to evaluate them objectively." },
  "70_75": { vi: "Bảy Tiền và Kỵ Sĩ Tiền: kiên nhẫn xây dựng trên sự kiên định — cả hai đều là những đức tính của đất, nhưng Bảy dừng lại để đánh giá trong khi Kỵ Sĩ tiếp tục tiến về phía trước; kết hợp cả hai là trí tuệ đích thực của đất.", en: "Seven of Pentacles and Knight of Pentacles: patience built on steadiness — both are earth virtues, but the Seven pauses to assess while the Knight continues forward; combining both is earth's genuine wisdom." },
  "70_76": { vi: "Bảy Tiền và Nữ Hoàng Tiền: sự đánh giá khôn ngoan — Nữ Hoàng biết khi nào cần dừng lại, nhìn lại khu vườn của mình và đưa ra những điều chỉnh cần thiết; sự thực tế ân cần của bà bao gồm cả sự kiên nhẫn và tầm nhìn dài hạn.", en: "Seven of Pentacles and Queen of Pentacles: wise assessment — the Queen knowing when to pause, look over her garden, and make necessary adjustments; her tender practicality includes both patience and long-term vision." },
  "70_77": { vi: "Bảy Tiền và Vua Tiền: đánh giá chiến lược — Vua xem xét định kỳ toàn bộ đế chế của mình không phải để lo lắng mà để tối ưu hóa; sự hiểu biết của ông về chu kỳ và thời điểm là lợi thế chiến lược lớn nhất trong kinh doanh.", en: "Seven of Pentacles and King of Pentacles: strategic assessment — the King periodically reviewing his entire empire not to worry but to optimize; his understanding of cycles and timing is the greatest strategic advantage in enterprise." },

  "71_72": { vi: "Tám Tiền và Chín Tiền: tay nghề dẫn đến sung túc — sự cống hiến không mệt mỏi cho kỹ năng cuối cùng tạo ra loại sự độc lập mà chỉ có thể được vun trồng, không thể được mua; đây là con đường đất dạy cho những người kiên nhẫn nhất.", en: "Eight of Pentacles and Nine of Pentacles: craft leading to abundance — tireless dedication to skill eventually creating the kind of independence that can only be cultivated, never bought; this is the path earth teaches its most patient students." },
  "71_73": { vi: "Tám Tiền và Mười Tiền: tay nghề xây dựng di sản — kỹ năng được phát triển trong nhiều thập kỷ tạo ra nền tảng cho di sản gia đình; những người thợ giỏi nhất thường để lại những di sản sâu sắc nhất, dù tên họ có được ghi nhớ hay không.", en: "Eight of Pentacles and Ten of Pentacles: craft building legacy — skill developed over decades creating the foundation for family legacy; the most skilled craftspeople often leave the deepest legacies, whether or not their names are remembered." },
  "71_74": { vi: "Tám Tiền và Trang Bị Tiền: người học cống hiến cho tay nghề — Trang Bị tiếp cận việc học với sự chú tâm và cam kết mà mọi nghề thủ công đều đòi hỏi; đây là sự bắt đầu của một con đường có thể kéo dài cả một đời.", en: "Eight of Pentacles and Page of Pentacles: the learner devoted to craft — the Page approaching learning with the attention and commitment that every craft demands; this is the beginning of a path that can last a lifetime." },
  "71_75": { vi: "Tám Tiền và Kỵ Sĩ Tiền: sự cống hiến và sự kiên định — cả hai lá bài đều miêu tả sự làm việc chăm chỉ mà không phàn nàn; khi kỷ luật gặp sự kiên trì, không có kỹ năng nào không thể được phát triển theo thời gian.", en: "Eight of Pentacles and Knight of Pentacles: dedication and steadiness — both cards describe working hard without complaint; when discipline meets perseverance, there is no skill that cannot be developed over time." },
  "71_76": { vi: "Tám Tiền và Nữ Hoàng Tiền: tay nghề và sự nuôi dưỡng — sự thành thạo kỹ thuật gặp sự chăm sóc bản năng; cả hai đều là hình thức cống hiến cho đất, một qua bàn tay và một qua trái tim, và cả hai đều tạo ra điều gì đó thực sự có giá trị.", en: "Eight of Pentacles and Queen of Pentacles: craft and nurturing — technical mastery meeting instinctive care; both are forms of dedication to earth, one through hands and one through heart, and both create something genuinely valuable." },
  "71_77": { vi: "Tám Tiền và Vua Tiền: tay nghề gặp đế chế — kỹ năng cá nhân được điều khiển bởi tầm nhìn chiến lược; Vua đã từng là người thợ học việc trước khi trở thành vị vua, và hiểu rằng mọi sự vĩ đại thực sự đều được xây dựng từ tay nghề đích thực.", en: "Eight of Pentacles and King of Pentacles: craft meeting empire — individual skill directed by strategic vision; the King was once the apprentice before becoming the king, and understands that all true greatness is built from genuine craftsmanship." },

  "72_73": { vi: "Chín Tiền và Mười Tiền: sung túc cá nhân và di sản gia đình — hai đỉnh cao của đất, một cái hoàn toàn cho bản thân, một cái được chia sẻ; bước từ sự phong phú cá nhân sang sự thịnh vượng gia đình là một sự mở rộng trái tim cũng như ví tiền.", en: "Nine of Pentacles and Ten of Pentacles: personal abundance and family legacy — the two peaks of earth, one fully for oneself and one shared; stepping from personal richness to family prosperity is an expansion of the heart as much as the wallet." },
  "72_74": { vi: "Chín Tiền và Trang Bị Tiền: sự độc lập truyền cảm hứng cho người học — Trang Bị nhìn thấy kết quả của sự kiên trì và sự tự lực được thể hiện trong Chín và bắt đầu hình dung ra con đường dẫn đến vườn của riêng mình.", en: "Nine of Pentacles and Page of Pentacles: independence inspiring the learner — the Page seeing the fruits of perseverance and self-reliance embodied in the Nine and beginning to envision the path to their own garden." },
  "72_75": { vi: "Chín Tiền và Kỵ Sĩ Tiền: sự sung túc được xây dựng bởi sự kiên định — Kỵ Sĩ đang trên hành trình mà Chín đã đến được; sự tiến bộ đều đặn của anh ấy, ngày qua ngày, là con đường đơn giản nhất và đáng tin cậy nhất đến sự độc lập vật chất.", en: "Nine of Pentacles and Knight of Pentacles: abundance built by steadiness — the Knight on the journey the Nine has already completed; his steady daily progress is the simplest and most reliable path to material independence." },
  "72_76": { vi: "Chín Tiền và Nữ Hoàng Tiền: hai hình thức của sự tự chủ nữ tính — Chín là sự độc lập hoàn toàn, Nữ Hoàng là sự sung túc được chia sẻ; cả hai đều biểu hiện của đất ở trạng thái tốt nhất, một là vườn cá nhân, một là khu vườn dành cho tất cả.", en: "Nine of Pentacles and Queen of Pentacles: two forms of feminine autonomy — the Nine is complete independence, the Queen is shared abundance; both are earth at its best, one a personal garden, one a garden for all." },
  "72_77": { vi: "Chín Tiền và Vua Tiền: sự sung túc cá nhân gặp đế chế — Chín có đủ cho bản thân, Vua có đủ cho cả vương quốc; cả hai đều là những biểu hiện của đất đã thành thục, chỉ khác nhau về quy mô và trách nhiệm đi kèm.", en: "Nine of Pentacles and King of Pentacles: personal abundance meeting empire — the Nine has enough for oneself, the King has enough for the entire kingdom; both are expressions of matured earth, differing only in scale and the responsibility that comes with it." },

  "73_74": { vi: "Mười Tiền và Trang Bị Tiền: di sản được trao cho thế hệ mới — Trang Bị bước vào sự thịnh vượng gia đình và bắt đầu học cách mang vác, tiếp nối và một ngày nào đó truyền lại nó; mọi di sản đều cần người học trò xứng đáng.", en: "Ten of Pentacles and Page of Pentacles: legacy passed to the new generation — the Page stepping into family prosperity and beginning to learn how to carry, continue, and one day pass it on; every legacy needs a worthy student." },
  "73_75": { vi: "Mười Tiền và Kỵ Sĩ Tiền: di sản được duy trì bởi sự kiên định — Kỵ Sĩ là người giữ gìn và phát triển di sản gia đình thông qua sự làm việc đáng tin cậy; không có sự thịnh vượng lâu dài nào tồn tại mà không có những người như anh ấy ở trung tâm của nó.", en: "Ten of Pentacles and Knight of Pentacles: legacy maintained by steadiness — the Knight is the guardian and developer of family legacy through reliable work; no lasting prosperity survives without people like him at its center." },
  "73_76": { vi: "Mười Tiền và Nữ Hoàng Tiền: di sản được nuôi dưỡng bởi trái tim — Nữ Hoàng là linh hồn của gia đình thịnh vượng; sự giàu có vật chất tồn tại qua nhiều thế hệ vì có những bàn tay ân cần chăm sóc không chỉ của cải mà còn những mối quan hệ làm cho của cải đó có ý nghĩa.", en: "Ten of Pentacles and Queen of Pentacles: legacy nurtured by heart — the Queen is the soul of the prosperous family; material wealth endures across generations because tender hands tend not only the wealth but the relationships that make that wealth meaningful." },
  "73_77": { vi: "Mười Tiền và Vua Tiền: hai biểu tượng vĩ đại nhất của đất — di sản gia đình và thẩm quyền vật chất cao nhất; khi cả hai hiện diện, sự thịnh vượng không chỉ là của cải mà là một thế giới hoàn chỉnh được xây dựng trên nền tảng của đất.", en: "Ten of Pentacles and King of Pentacles: the two greatest symbols of earth — family legacy and the highest material authority; when both are present, prosperity is not only wealth but a complete world built on earth's most solid foundation." },

  "74_75": { vi: "Trang Bị Tiền và Kỵ Sĩ Tiền: người học và người thực hiện của đất — Trang Bị đặt câu hỏi và khám phá trong khi Kỵ Sĩ đi và xây dựng; cả hai cần nhau — sự tò mò cần hành động, và sự kiên định cần định hướng tươi mới.", en: "Page of Pentacles and Knight of Pentacles: the learner and the doer of earth — the Page questions and explores while the Knight walks and builds; both need each other — curiosity needs action, and steadiness needs fresh direction." },
  "74_76": { vi: "Trang Bị Tiền và Nữ Hoàng Tiền: học trò và bậc thầy của đất — Nữ Hoàng dạy Trang Bị không chỉ kỹ thuật trồng trọt mà còn nghệ thuật sống dồi dào; bà là hiện thân của những gì sự kiên nhẫn và sự chăm sóc có thể tạo ra theo thời gian.", en: "Page of Pentacles and Queen of Pentacles: student and master of earth — the Queen teaching the Page not only the techniques of cultivation but the art of living abundantly; she embodies what patience and care can create over time." },
  "74_77": { vi: "Trang Bị Tiền và Vua Tiền: tâm trí trẻ học từ đế chế — Trang Bị tiếp xúc với tầm nhìn chiến lược và quy mô lớn của Vua; học cách suy nghĩ về sự thịnh vượng không chỉ cho bản thân mà cho toàn bộ cộng đồng là bài học lớn nhất mà đất có thể dạy.", en: "Page of Pentacles and King of Pentacles: young mind learning from empire — the Page exposed to the King's strategic vision and large scale; learning to think about prosperity not only for oneself but for an entire community is the greatest lesson earth can teach." },

  "75_76": { vi: "Kỵ Sĩ Tiền và Nữ Hoàng Tiền: sự kiên định và sự nuôi dưỡng — hai đức tính nền tảng của đất cùng hiện diện; Kỵ Sĩ xây dựng trong khi Nữ Hoàng nuôi dưỡng, và cùng nhau họ tạo ra loại sự thịnh vượng vừa bền vững vừa đầy sức sống.", en: "Knight of Pentacles and Queen of Pentacles: steadiness and nurturing — two foundational virtues of earth present together; the Knight builds while the Queen nurtures, and together they create the kind of prosperity that is both durable and full of life." },
  "75_77": { vi: "Kỵ Sĩ Tiền và Vua Tiền: người thực hiện trung thành và người lãnh đạo chiến lược — Kỵ Sĩ hiện thực hóa tầm nhìn của Vua thông qua công việc đáng tin cậy hàng ngày; đây là sự cộng tác hoàn hảo của đất: một người chỉ đạo, một người xây dựng.", en: "Knight of Pentacles and King of Pentacles: the loyal doer and the strategic leader — the Knight realizing the King's vision through daily reliable work; this is earth's perfect collaboration: one directs, one builds." },

  "76_77": { vi: "Nữ Hoàng Tiền và Vua Tiền: hai thẩm quyền vĩ đại của đất — sự nuôi dưỡng ân cần và thẩm quyền chiến lược kết hợp; khi cả hai cùng hiện diện, đất đạt đến hình thức đầy đủ nhất của sự thịnh vượng: không chỉ giàu có mà còn ấm áp, không chỉ ổn định mà còn sinh sôi.", en: "Queen of Pentacles and King of Pentacles: the two great authorities of earth — tender nurturing and strategic authority combined; when both are present, earth reaches its fullest form of prosperity: not only wealthy but warm, not only stable but flourishing." },

  // ─── TIER 5: Minor × Minor, Cross-Suit (~1,176 pairs) ──────────────────────
  // ── Tier 5a-1: Wands × Cups, fire×water (Wands 22–28 × Cups 36–49, 98 pairs) ──
  "22_36": { vi: "Át Gậy và Át Cốc: lửa thuần khiết gặp nước thuần khiết — hai nguồn năng lượng nguyên thủy đối diện nhau; đam mê và tình yêu đều ở trạng thái khởi đầu hoàn toàn, không có gì định hình họ ngoài tiềm năng vô hạn.", en: "Ace of Wands and Ace of Cups: pure fire meeting pure water — two primal energies facing each other; passion and love both in their completely nascent state, shaped by nothing but unlimited potential." },
  "22_37": { vi: "Át Gậy và Hai Cốc: ngọn lửa sáng tạo thắp sáng một mối kết nối sâu sắc — sự chủ động của lửa tạo ra không gian cho tình yêu hỗ tương; khi bắt đầu táo bạo gặp sự nhận ra lẫn nhau, điều gì đó thực sự quý giá được hình thành.", en: "Ace of Wands and Two of Cups: creative spark igniting a deep mutual connection — fire's initiative creating space for reciprocal love; when bold beginning meets mutual recognition, something genuinely precious is formed." },
  "22_38": { vi: "Át Gậy và Ba Cốc: năng lượng sáng tạo gặp niềm vui cộng đồng — lửa mang đến sự phấn khởi, nước mang đến sự thuộc về; khi cả hai hòa nhịp cùng nhau trong một buổi tụ họp, năng lượng của niềm vui trở nên không thể cưỡng lại.", en: "Ace of Wands and Three of Cups: creative energy meeting communal joy — fire brings excitement, water brings belonging; when both resonate together in a gathering, the energy of celebration becomes irresistible." },
  "22_39": { vi: "Át Gậy và Bốn Cốc: đam mê bị chặn bởi sự rút lui cảm xúc — ngọn lửa đầy nhiệt huyết gặp trái tim đã quay vào trong; thử thách là khơi dậy lại sự tham gia mà không đốt cháy những gì còn lại của sự nhạy cảm.", en: "Ace of Wands and Four of Cups: passion blocked by emotional withdrawal — the enthusiastic flame meeting a heart that has turned inward; the challenge is reigniting engagement without burning what remains of sensitivity." },
  "22_40": { vi: "Át Gậy và Năm Cốc: năng lượng sáng tạo gặp nỗi đau mất mát — lửa muốn bắt đầu trong khi nước đang than thở; đôi khi điều cần thiết nhất là chờ đợi trước khi đốt lên ngọn lửa mới, vì sự đau buồn cần không gian của riêng nó.", en: "Ace of Wands and Five of Cups: creative energy meeting the pain of loss — fire wants to begin while water is still grieving; sometimes the most necessary thing is to wait before lighting the new flame, since grief needs its own space." },
  "22_41": { vi: "Át Gậy và Sáu Cốc: lửa mới gặp sự ấm áp của hoài niệm — năng lượng sáng tạo được nuôi dưỡng bởi những ký ức ngọt ngào; điều đã từng tốt đẹp có thể là nguồn nhiên liệu cho điều sắp tới nếu nó không trở thành một nơi trú ẩn.", en: "Ace of Wands and Six of Cups: new fire meeting the warmth of nostalgia — creative energy nourished by sweet memories; what was once good can be fuel for what is coming if it does not become a refuge instead." },
  "22_42": { vi: "Át Gậy và Bảy Cốc: đam mê phải chọn một giấc mơ — lửa cần sự tập trung trong khi nước cung cấp quá nhiều khả năng; sức mạnh của ý chí là điều duy nhất có thể biến một trong vô số ảo ảnh thành hành động thực sự.", en: "Ace of Wands and Seven of Cups: passion needing to choose one dream — fire needs focus while water offers too many possibilities; the strength of will is the only thing that can turn one of countless illusions into real action." },
  "22_43": { vi: "Át Gậy và Tám Cốc: khởi đầu mới truyền cảm hứng ra đi — năng lượng của lửa cho nước dũng khí để rời bỏ những gì không còn nuôi dưỡng tâm hồn; đây là sự kết hợp của sự bắt đầu và sự rời xa cùng một lúc.", en: "Ace of Wands and Eight of Cups: new beginning inspiring departure — fire's energy giving water the courage to leave what no longer nourishes the soul; this is the combination of beginning and leaving at the same time." },
  "22_44": { vi: "Át Gậy và Chín Cốc: tia lửa sáng tạo gặp sự thỏa mãn sâu sắc — khi đam mê của lửa hướng đúng với điều mà trái tim thực sự mong muốn, kết quả không chỉ là thành công mà là niềm hạnh phúc thực sự.", en: "Ace of Wands and Nine of Cups: creative spark meeting deep satisfaction — when fire's passion is pointed at what the heart genuinely desires, the result is not only success but real happiness." },
  "22_45": { vi: "Át Gậy và Mười Cốc: hạt giống đam mê được trồng trong khu vườn của tình yêu gia đình — lửa bắt đầu và nước hoàn thiện; tiềm năng thuần khiết nhất của lửa tìm thấy ngôi nhà cuối cùng trong sự hài hòa cảm xúc trọn vẹn nhất của nước.", en: "Ace of Wands and Ten of Cups: the seed of passion planted in the garden of family love — fire begins and water completes; fire's purest potential finding its ultimate home in water's most complete emotional harmony." },
  "22_46": { vi: "Át Gậy và Trang Bị Cốc: hai dạng năng lượng trẻ trung của lửa và nước — sự tò mò sáng tạo gặp sự tò mò cảm xúc; cả hai đang khám phá bản thân mình và thế giới, một qua hành động và một qua cảm nhận.", en: "Ace of Wands and Page of Cups: two youthful energies of fire and water — creative curiosity meeting emotional curiosity; both are exploring themselves and the world, one through action and one through feeling." },
  "22_47": { vi: "Át Gậy và Kỵ Sĩ Cốc: tia lửa khởi đầu và sự lãng mạn xông pha — lửa ở điểm bắt đầu gặp nước đang trên hành trình; cả hai đều cháy bỏng theo cách của mình, một với sức sáng tạo và một với trái tim lý tưởng hóa.", en: "Ace of Wands and Knight of Cups: the igniting spark and the romantic charge — fire at the starting point meeting water in motion; both are burning in their own way, one with creative force and one with an idealized heart." },
  "22_48": { vi: "Át Gậy và Nữ Hoàng Cốc: đam mê thô sơ được định hướng bởi sự khôn ngoan cảm xúc — Nữ Hoàng không dập tắt ngọn lửa mà hướng dẫn nó; sự sâu sắc của bà cho lửa chiều sâu mà nó chưa có, và lửa cho bà sức sống mà đôi khi nước cần.", en: "Ace of Wands and Queen of Cups: raw passion guided by emotional wisdom — the Queen does not extinguish the flame but channels it; her depth gives fire a dimension it did not yet have, and fire gives her a vitality that water sometimes needs." },
  "22_49": { vi: "Át Gậy và Vua Cốc: tiềm năng sáng tạo gặp thẩm quyền cảm xúc — Vua Cốc biết cách giữ ngọn lửa đủ ấm mà không làm nó tắt; dưới sự giám hộ của ông, đam mê được nuôi dưỡng thành điều gì đó lâu dài và có chiều sâu.", en: "Ace of Wands and King of Cups: creative potential meeting emotional authority — the King of Cups knows how to keep the flame warm without letting it go out; under his guardianship, passion is cultivated into something lasting and deep." },

  "23_36": { vi: "Hai Gậy và Át Cốc: tầm nhìn gặp cảm xúc thuần khiết — người lên kế hoạch bằng lửa gặp một làn sóng tình cảm hoàn toàn mới; ý tưởng lớn bắt đầu đẹp hơn khi chúng được nuôi dưỡng bởi trái tim thực sự cảm nhận.", en: "Two of Wands and Ace of Cups: vision meeting pure emotion — the fire planner encountering a completely new wave of feeling; big ideas begin more beautifully when nurtured by a heart that genuinely feels." },
  "23_37": { vi: "Hai Gậy và Hai Cốc: tầm nhìn cá nhân gặp mối liên kết sâu sắc — người lập kế hoạch một mình khám phá ra sức mạnh của việc lập kế hoạch cùng với người bạn đồng hành thực sự; kết nối hỗ tương làm cho tầm nhìn của lửa trở nên phong phú hơn.", en: "Two of Wands and Two of Cups: personal vision meeting deep partnership — the lone planner discovering the power of planning with a true companion; mutual connection enriches fire's vision in ways solitude cannot." },
  "23_38": { vi: "Hai Gậy và Ba Cốc: tham vọng được chào đón bởi cộng đồng — kế hoạch lớn của lửa nhận được sự hỗ trợ ấm áp từ mạng lưới tình cảm của nước; sự cổ vũ của những người thân yêu biến kế hoạch thành cam kết.", en: "Two of Wands and Three of Cups: ambition welcomed by community — fire's grand plans receiving warm support from water's emotional network; the encouragement of loved ones transforms plans into commitments." },
  "23_39": { vi: "Hai Gậy và Bốn Cốc: tham vọng bị cản trở bởi sự trì trệ cảm xúc — kế hoạch của lửa không thể tiến về phía trước khi nước không có năng lượng để tham gia; đôi khi đợi người kia sẵn sàng là sự kiên nhẫn khôn ngoan.", en: "Two of Wands and Four of Cups: ambition hindered by emotional stagnation — fire's plans unable to move forward when water has no energy to engage; sometimes waiting for the other to be ready is the wisest patience." },
  "23_40": { vi: "Hai Gậy và Năm Cốc: kế hoạch gặp nỗi đau buồn — lửa muốn nhìn về phía trước nhưng nước vẫn đang nhìn lại những gì đã mất; tầm nhìn không thể bỏ qua sự đau buồn mà phải học cách tích hợp nó vào hành trình tiếp theo.", en: "Two of Wands and Five of Cups: plans meeting grief — fire wants to look forward but water is still looking back at what was lost; vision cannot bypass grief but must learn to integrate it into the continuing journey." },
  "23_41": { vi: "Hai Gậy và Sáu Cốc: hướng đến tương lai trong khi bị kéo về quá khứ — tham vọng của lửa cạnh tranh với hoài niệm của nước; cả hai đều có giá trị nhưng chỉ một trong hai có thể là la bàn chính dẫn đường.", en: "Two of Wands and Six of Cups: looking toward the future while drawn to the past — fire's ambition competing with water's nostalgia; both have value but only one can be the primary compass pointing the way." },
  "23_42": { vi: "Hai Gậy và Bảy Cốc: quá nhiều lựa chọn làm khó khăn cho kế hoạch — tầm nhìn rõ ràng của lửa bị phủ mờ bởi sự dư thừa các khả năng của nước; kỷ luật của lửa cần thiết để chắt lọc những giấc mơ thành một hướng đi duy nhất.", en: "Two of Wands and Seven of Cups: too many options complicating the plan — fire's clear vision clouded by water's excess of possibilities; fire's discipline is needed to distill dreams into a single direction." },
  "23_43": { vi: "Hai Gậy và Tám Cốc: lên kế hoạch cho một hành trình có ý nghĩa — tầm nhìn của lửa cung cấp hướng đi cho quyết định của nước để ra đi; khi biết nơi mình đang đến, việc rời bỏ nơi mình đang ở trở nên ít đau hơn.", en: "Two of Wands and Eight of Cups: planning a meaningful journey — fire's vision providing direction for water's decision to leave; when one knows where they are going, leaving where they are becomes less painful." },
  "23_44": { vi: "Hai Gậy và Chín Cốc: kế hoạch tham vọng gặp sự thỏa mãn — tầm nhìn lớn của lửa phù hợp với điều mà trái tim thực sự mong muốn; khi tham vọng và mong ước cùng chỉ một hướng, sự thành công trở thành điều tất nhiên.", en: "Two of Wands and Nine of Cups: ambitious plans meeting satisfaction — fire's big vision aligning with what the heart genuinely desires; when ambition and wish point in the same direction, success becomes inevitable." },
  "23_45": { vi: "Hai Gậy và Mười Cốc: tầm nhìn cá nhân bao gồm cả hạnh phúc gia đình — kế hoạch lớn nhất bao hàm cả những người thân yêu; lửa nhìn ra đường chân trời nhưng biết rằng niềm vui thực sự là đưa cả gia đình cùng đến đó.", en: "Two of Wands and Ten of Cups: personal vision encompassing family happiness — the grandest plan includes loved ones; fire looks to the horizon but knows real joy is bringing the whole family there together." },
  "23_46": { vi: "Hai Gậy và Trang Bị Cốc: người lên kế hoạch gặp người mang tin cảm xúc — lửa nhận được một thông điệp bất ngờ từ nước gợi ý một hướng đi mới; đôi khi chính những tín hiệu cảm xúc nhỏ bé nhất lại định hình lại kế hoạch lớn nhất.", en: "Two of Wands and Page of Cups: the planner meeting the emotional messenger — fire receiving an unexpected message from water suggesting a new direction; sometimes the smallest emotional signals reshape the grandest plans." },
  "23_47": { vi: "Hai Gậy và Kỵ Sĩ Cốc: tham vọng và sự theo đuổi lãng mạn — cả hai đều tìm kiếm những chân trời, lửa lên kế hoạch và nước cảm nhận; khi tầm nhìn và trái tim cùng hướng về phía trước, năng lượng trở nên nhân đôi.", en: "Two of Wands and Knight of Cups: ambition and romantic pursuit — both seek horizons, fire through planning and water through feeling; when vision and heart both face forward, energy becomes doubled." },
  "23_48": { vi: "Hai Gậy và Nữ Hoàng Cốc: kế hoạch chiến lược được làm phong phú bởi trí tuệ cảm xúc — Nữ Hoàng giúp lửa hiểu rằng những kế hoạch tốt nhất phải tính đến yếu tố con người; không có chiến lược nào thành công nếu nó bỏ qua nhu cầu của trái tim.", en: "Two of Wands and Queen of Cups: strategic plans enriched by emotional intelligence — the Queen helping fire understand that the best plans must account for the human element; no strategy succeeds if it overlooks the heart's needs." },
  "23_49": { vi: "Hai Gậy và Vua Cốc: tầm nhìn táo bạo được cân bằng bởi sự kiên định cảm xúc — Vua cho lửa thấy rằng những kế hoạch lớn nhất đòi hỏi sự kiên nhẫn không chỉ về mặt chiến lược mà còn về mặt tình cảm.", en: "Two of Wands and King of Cups: bold vision balanced by emotional steadiness — the King showing fire that the greatest plans require patience not only strategically but emotionally as well." },

  "24_36": { vi: "Ba Gậy và Át Cốc: sự mở rộng gặp tình yêu thuần khiết — lửa đang vươn ra ngoài và gặp một làn sóng cảm xúc hoàn toàn mới; sự tăng trưởng đẹp nhất xảy ra khi mở rộng đi cùng với sự mở ra của trái tim.", en: "Three of Wands and Ace of Cups: expansion meeting pure love — fire reaching outward and encountering a completely fresh wave of emotion; the most beautiful growth happens when expansion accompanies an opening of the heart." },
  "24_37": { vi: "Ba Gậy và Hai Cốc: mở rộng kinh doanh gặp mối liên kết cá nhân — tăng trưởng của lửa và kết nối sâu sắc của nước tăng cường lẫn nhau; khi đối tác thực sự cũng là người đồng hành thực sự, cả sự nghiệp lẫn mối quan hệ đều phát triển.", en: "Three of Wands and Two of Cups: business expansion meeting personal connection — fire's growth and water's deep bond reinforcing each other; when a true partner is also a true companion, both career and relationship flourish." },
  "24_38": { vi: "Ba Gậy và Ba Cốc: mở rộng được ăn mừng bởi cộng đồng — thành công của lửa được khuếch đại bởi niềm vui tập thể của nước; không có sự tăng trưởng nào ý nghĩa hơn khi được chia sẻ với những người quan tâm đến bạn.", en: "Three of Wands and Three of Cups: expansion celebrated by community — fire's success amplified by water's collective joy; no growth is more meaningful than when it is shared with those who genuinely care for you." },
  "24_39": { vi: "Ba Gậy và Bốn Cốc: nhìn ra đường chân trời nhưng nước vẫn trì trệ — tham vọng của lửa bị kéo lại bởi sự mất hứng của nước; muốn tiến về phía trước nhưng tâm trạng không sẵn sàng là căng thẳng đặc trưng của sự kết hợp này.", en: "Three of Wands and Four of Cups: looking to the horizon while water remains stagnant — fire's ambition held back by water's disengagement; wanting to move forward while the emotional state is not ready is this combination's characteristic tension." },
  "24_40": { vi: "Ba Gậy và Năm Cốc: sự mở rộng bị lu mờ bởi mất mát — kế hoạch tăng trưởng của lửa phải tính đến nỗi đau buồn của nước; khai triển mà không thừa nhận những gì đã bị mất là xây dựng trên nền móng không ổn định.", en: "Three of Wands and Five of Cups: expansion shadowed by loss — fire's growth plans must account for water's grief; expanding without acknowledging what has been lost is building on an unstable foundation." },
  "24_41": { vi: "Ba Gậy và Sáu Cốc: mở rộng nuôi dưỡng bởi gốc rễ — lửa vươn ra ngoài được tăng sức mạnh khi biết mình đến từ đâu; hoài niệm không ngăn cản sự tăng trưởng mà cho nó chiều sâu và tính xác thực.", en: "Three of Wands and Six of Cups: expansion nourished by roots — fire reaching outward strengthened by knowing where it came from; nostalgia does not hinder growth but gives it depth and authenticity." },
  "24_42": { vi: "Ba Gậy và Bảy Cốc: tầm nhìn rõ ràng cần thiết giữa biển ảo mộng — lửa nhìn ra xa gặp nước chìm đắm trong những khả năng hấp dẫn nhưng không rõ ràng; sức mạnh của lửa là khả năng lựa chọn một con đường cụ thể.", en: "Three of Wands and Seven of Cups: clear vision needed among a sea of illusions — fire looking far encountering water lost in appealing but unclear possibilities; fire's strength is the capacity to choose a specific path." },
  "24_43": { vi: "Ba Gậy và Tám Cốc: mở rộng và rời bỏ — cả hai đều đang trên hành trình đến một nơi khác; lửa vươn ra tìm kiếm lãnh thổ mới trong khi nước để lại những gì không còn đủ; cùng nhau, chúng mô tả sự chuyển đổi can đảm.", en: "Three of Wands and Eight of Cups: expansion and departure — both are on journeys toward somewhere else; fire reaching to find new territory while water leaves what is no longer enough; together they describe a courageous transition." },
  "24_44": { vi: "Ba Gậy và Chín Cốc: thành công mở rộng gặp ước nguyện được thực hiện — lửa đang thực hiện tầm nhìn và nước đang tận hưởng kết quả; đây là hình ảnh của việc làm việc và tận hưởng cuộc sống cùng một lúc.", en: "Three of Wands and Nine of Cups: expanding success meeting fulfilled wishes — fire carrying out the vision and water enjoying the results; this is the image of working and living well at the same time." },
  "24_45": { vi: "Ba Gậy và Mười Cốc: thành công vươn xa dẫn đến hạnh phúc gia đình — lửa xây dựng điều gì đó bền vững và nước mang đến ý nghĩa cho nó; sự thịnh vượng bên ngoài tìm thấy linh hồn của nó trong tình yêu và sự thuộc về bên trong.", en: "Three of Wands and Ten of Cups: far-reaching success leading to family happiness — fire builds something durable and water gives it meaning; external achievement finds its soul in the love and belonging within." },
  "24_46": { vi: "Ba Gậy và Trang Bị Cốc: người khai phá và người mộng mơ — lửa lên đường khám phá trong khi nước mang những thông điệp cảm xúc bất ngờ; đôi khi chính những nguồn cảm hứng kỳ lạ nhất lại định hình lại chuyến hành trình theo những cách hoàn toàn tốt đẹp.", en: "Three of Wands and Page of Cups: the explorer and the dreamer — fire setting out to discover while water carries unexpected emotional messages; sometimes the strangest inspirations reshape the journey in entirely beautiful ways." },
  "24_47": { vi: "Ba Gậy và Kỵ Sĩ Cốc: hai người khám phá của lửa và nước — một lên kế hoạch cuộc thám hiểm và một lên ngựa với trái tim rộng mở; cùng nhau, chúng mô tả một chuyến phiêu lưu đầy cả tham vọng lẫn cảm hứng.", en: "Three of Wands and Knight of Cups: two explorers of fire and water — one planning the expedition and one riding out with an open heart; together they describe an adventure full of both ambition and inspiration." },
  "24_48": { vi: "Ba Gậy và Nữ Hoàng Cốc: sự mở rộng táo bạo được hướng dẫn bởi chiều sâu cảm xúc — Nữ Hoàng nhắc nhở lửa rằng những thành công bền vững nhất được xây dựng trên sự hiểu biết về con người; tăng trưởng mà không có sự đồng cảm là mỏng manh.", en: "Three of Wands and Queen of Cups: bold expansion guided by emotional depth — the Queen reminding fire that the most durable successes are built on understanding people; growth without empathy is fragile." },
  "24_49": { vi: "Ba Gậy và Vua Cốc: tầm nhìn xa rộng được cân bằng bởi sự bình tĩnh nội tâm — Vua dạy lửa rằng ngay cả trong những khoảnh khắc mở rộng lớn nhất, sự ổn định cảm xúc bên trong là điều làm cho mọi thứ có thể.", en: "Three of Wands and King of Cups: far-reaching vision balanced by inner calm — the King teaching fire that even in the greatest moments of expansion, inner emotional stability is what makes everything possible." },

  "25_36": { vi: "Bốn Gậy và Át Cốc: lễ kỷ niệm gặp tình yêu thuần túy — ngọn lửa vui mừng gặp làn sóng cảm xúc trong lành nhất; đây là hình ảnh của một buổi tiệc tràn đầy tình cảm chân thành, nơi niềm vui và tình yêu không thể phân biệt được.", en: "Four of Wands and Ace of Cups: celebration meeting pure love — joyful fire meeting the freshest wave of emotion; this is the image of a gathering overflowing with genuine feeling, where joy and love become indistinguishable." },
  "25_37": { vi: "Bốn Gậy và Hai Cốc: ăn mừng một mối liên kết — ngọn lửa vui mừng về một cột mốc và nước nhận ra sự kết nối sâu sắc; đây là những gì lễ đính hôn, đám cưới và những buổi tụ họp đặc biệt được tạo ra.", en: "Four of Wands and Two of Cups: celebrating a bond — fire joyful over a milestone and water recognizing a deep connection; this is what engagements, weddings, and special reunions are made of." },
  "25_38": { vi: "Bốn Gậy và Ba Cốc: niềm vui kép — lễ mừng thành tích và sự hội tụ của những trái tim; khi lửa và nước cùng hòa nhịp trong một buổi tụ họp, năng lượng tập thể của niềm vui không thể cưỡng lại.", en: "Four of Wands and Three of Cups: double celebration — fire's achievement milestone and water's gathering of hearts; when fire and water harmonize in a gathering, the collective energy of joy is irresistible." },
  "25_39": { vi: "Bốn Gậy và Bốn Cốc: bữa tiệc mà ai đó ngồi một mình — ngọn lửa tập thể không thể xuyên qua sự rút lui nội tâm của nước; đây là hình ảnh quen thuộc về sự cô đơn giữa đám đông.", en: "Four of Wands and Four of Cups: the party where someone sits apart — fire's communal joy unable to penetrate water's inner withdrawal; this is the familiar image of loneliness in the middle of a crowd." },
  "25_40": { vi: "Bốn Gậy và Năm Cốc: lễ kỷ niệm bị lu mờ bởi nỗi đau — niềm vui bên ngoài không thể chữa lành vết thương bên trong; đôi khi cả thế giới có thể đang ăn mừng trong khi trái tim vẫn đang than thở cho những gì đã mất.", en: "Four of Wands and Five of Cups: celebration shadowed by inner pain — external joy cannot heal internal wounds; sometimes the entire world can be celebrating while a heart is still mourning what was lost." },
  "25_41": { vi: "Bốn Gậy và Sáu Cốc: lễ hội trở về nhà — ngọn lửa vui mừng gặp sự ấm áp ngọt ngào của hoài niệm; ngày lễ gia đình và những buổi tụ họp trở thành dịp để các ký ức quý giá được sống lại.", en: "Four of Wands and Six of Cups: the homecoming festival — joyful fire meeting the sweet warmth of nostalgia; family holidays and reunions becoming occasions for precious memories to live again." },
  "25_42": { vi: "Bốn Gậy và Bảy Cốc: ăn mừng trong khi mộng mơ — ngọn lửa vui mừng gặp nước đang tưởng tượng những khả năng hấp dẫn; buổi lễ có thể trở thành cơ hội để lập kế hoạch ước mơ nếu sự kỳ ảo được nối đất bởi kỷ luật của lửa.", en: "Four of Wands and Seven of Cups: celebrating while daydreaming — joyful fire meeting water imagining alluring possibilities; the celebration can become an opportunity for dream-planning if fantasy is grounded by fire's discipline." },
  "25_43": { vi: "Bốn Gậy và Tám Cốc: lễ kỷ niệm trước khi ra đi — ngọn lửa đánh dấu một cột mốc trở thành chất xúc tác cho hành trình tiếp theo của nước; đôi khi đỉnh cao là thời điểm hoàn hảo để bắt đầu điều tiếp theo.", en: "Four of Wands and Eight of Cups: celebration before departure — fire's milestone becoming the catalyst for water's next journey; sometimes the peak is the perfect moment to begin what comes next." },
  "25_44": { vi: "Bốn Gậy và Chín Cốc: niềm vui tập thể gặp sự thỏa mãn cá nhân — khi cả lửa lẫn nước đều tràn đầy, không gian tập thể và không gian nội tâm đều cộng hưởng với sự sung túc; đây là đỉnh cao của cả hai nguyên tố.", en: "Four of Wands and Nine of Cups: communal joy meeting personal contentment — when both fire and water are full, collective space and inner space both resonate with abundance; this is the peak of both elements." },
  "25_45": { vi: "Bốn Gậy và Mười Cốc: đỉnh cao của niềm vui — ngọn lửa ăn mừng cột mốc và nước mang lại sự hòa hợp cảm xúc hoàn chỉnh; hiếm có sự kết hợp nào đạt đến mức vui mừng và yêu thương như thế này trong cùng một khoảnh khắc.", en: "Four of Wands and Ten of Cups: the peak of joy — fire celebrating a milestone and water bringing complete emotional harmony; few combinations reach this level of rejoicing and love in the same moment." },
  "25_46": { vi: "Bốn Gậy và Trang Bị Cốc: lễ hội với một sự hiện diện trẻ trung tràn đầy cảm xúc — ngọn lửa vui mừng được làm sống động bởi trí tưởng tượng và sự nhạy cảm tươi mới của nước; thanh niên mang đến điều kỳ diệu cho bất kỳ buổi tụ họp nào.", en: "Four of Wands and Page of Cups: festival with a young emotionally alive presence — fire's joy enlivened by water's fresh imagination and sensitivity; youth brings wonder to any gathering." },
  "25_47": { vi: "Bốn Gậy và Kỵ Sĩ Cốc: lễ hội vui tươi với tinh thần lãng mạn — ngọn lửa hoan hỉ thu hút trái tim lý tưởng của nước; không khí của buổi lễ trở nên điện khí với sự kết hợp của niềm vui tập thể và đam mê cá nhân.", en: "Four of Wands and Knight of Cups: joyful festival with a romantic spirit — fire's joyful energy attracting water's idealistic heart; the celebration's atmosphere becoming electric with the combination of collective joy and personal passion." },
  "25_48": { vi: "Bốn Gậy và Nữ Hoàng Cốc: lễ kỷ niệm được giữ gìn bởi sự ấm áp — Nữ Hoàng làm cho mọi buổi tụ họp cảm thấy như một ngôi nhà thực sự; sự kết hợp của năng lượng lễ hội của lửa và sự nuôi dưỡng của nước tạo ra một điều gì đó ít ai quên.", en: "Four of Wands and Queen of Cups: celebration held by warmth — the Queen making every gathering feel like a real home; the combination of fire's festive energy and water's nurturing creates something few forget." },
  "25_49": { vi: "Bốn Gậy và Vua Cốc: cột mốc được chứng kiến bởi thẩm quyền cảm xúc — Vua tạo cho buổi lễ tính hợp pháp và chiều sâu; sự hiện diện của ông chuyển đổi một buổi ăn mừng đơn giản thành một nghi lễ có ý nghĩa thực sự.", en: "Four of Wands and King of Cups: milestone witnessed by emotional authority — the King giving the celebration legitimacy and depth; his presence transforms a simple party into a ceremony of genuine significance." },

  "26_36": { vi: "Năm Gậy và Át Cốc: xung đột gặp tình yêu thuần khiết — ngọn lửa chiến đấu gặp một làn sóng cảm xúc chưa có áo giáp; điều chưa được bảo vệ nhất dễ bị tổn thương nhất bởi sự hỗn loạn, nhưng cũng là điều có thể xoa dịu nó.", en: "Five of Wands and Ace of Cups: conflict meeting pure love — fighting fire encountering emotion that has no armor yet; the most unguarded thing is most vulnerable to chaos, but also the thing most capable of soothing it." },
  "26_37": { vi: "Năm Gậy và Hai Cốc: xung đột và kết nối — ngọn lửa xung đột tìm thấy sự hòa giải thông qua sự nhận ra lẫn nhau; nhiều tranh chấp tan biến khi hai bên thực sự nhìn thấy nhau, không phải như đối thủ mà như con người.", en: "Five of Wands and Two of Cups: conflict and connection — conflicting fire finding resolution through mutual recognition; many disputes dissolve when two sides truly see each other not as opponents but as human beings." },
  "26_38": { vi: "Năm Gậy và Ba Cốc: sự hỗn loạn được xoa dịu bởi cộng đồng — năng lượng cạnh tranh của lửa tìm thấy sự nhẹ nhõm trong sự ấm áp tập thể của nước; tình bạn và sự thuộc về có sức mạnh hóa giải những mâu thuẫn mà tranh luận không thể giải quyết.", en: "Five of Wands and Three of Cups: chaos soothed by community — fire's competitive energy finding relief in water's collective warmth; friendship and belonging have the power to dissolve conflicts that argument cannot resolve." },
  "26_39": { vi: "Năm Gậy và Bốn Cốc: xung đột đẩy nước sâu hơn vào sự rút lui — sự hung hăng của lửa khiến nước ngày càng tách biệt; khi sự đối đầu gặp sự không tham gia, không bên nào cảm thấy được nghe.", en: "Five of Wands and Four of Cups: conflict pushing water deeper into withdrawal — fire's aggression causing water to become increasingly disengaged; when confrontation meets disengagement, neither side feels heard." },
  "26_40": { vi: "Năm Gậy và Năm Cốc: hai hình thức đau khổ — xung đột bên ngoài và đau buồn bên trong cùng một lúc; khi lửa và nước đều ở trạng thái khó khăn nhất của chúng, phong cảnh trở nên thách thức nhưng sự giải thoát thường đến từ sự kết hợp bất ngờ nhất.", en: "Five of Wands and Five of Cups: two forms of difficulty — external conflict and internal grief at the same time; when fire and water are both in their hardest states, the landscape is challenging but release often comes from the most unexpected combination." },
  "26_41": { vi: "Năm Gậy và Sáu Cốc: xung đột tìm kiếm sự an ủi trong quá khứ — ngọn lửa hỗn loạn tìm kiếm sự ổn định trong những ký ức đơn giản hơn; đôi khi nhớ lại bản thân mình là ai trước đây có thể khôi phục sự bình tĩnh giữa những bất đồng.", en: "Five of Wands and Six of Cups: conflict seeking comfort in the past — chaotic fire looking for stability in simpler memories; sometimes remembering who one was before can restore calm amid disagreements." },
  "26_42": { vi: "Năm Gậy và Bảy Cốc: sự hỗn loạn và sự mơ mộng — xung đột phân tán của lửa gặp sự bất định mộng mơ của nước; khi cả hai nguyên tố đều không rõ ràng về hướng đi, cần có sự lãnh đạo bên ngoài để thiết lập trật tự.", en: "Five of Wands and Seven of Cups: chaos and daydreaming — fire's scattered conflict meeting water's dreamy uncertainty; when both elements are unclear about direction, outside leadership is needed to establish order." },
  "26_43": { vi: "Năm Gậy và Tám Cốc: xung đột trở thành lý do để ra đi — cuộc tranh cãi trở nên lý do cuối cùng để rời bỏ; khi lửa tiếp tục chiến đấu và nước đã thấy đủ, cái ra đi trở thành sự lựa chọn khôn ngoan nhất.", en: "Five of Wands and Eight of Cups: conflict becoming reason to leave — the struggle becoming the final reason to depart; when fire keeps fighting and water has seen enough, departure becomes the wisest choice." },
  "26_44": { vi: "Năm Gậy và Chín Cốc: xung đột và sự bình yên bên cạnh nhau — sự hỗn loạn của lửa tương phản với sự thỏa mãn nội tâm của nước; người ta có thể đang trong giữa cuộc xung đột bên ngoài và vẫn mang bình yên bên trong.", en: "Five of Wands and Nine of Cups: conflict and inner peace side by side — fire's chaos contrasted with water's inner contentment; one can be in the middle of external conflict and still carry peace within." },
  "26_45": { vi: "Năm Gậy và Mười Cốc: xung đột trong gia đình hoặc cộng đồng — ngọn lửa cạnh tranh thử thách sức mạnh của sợi dây tình cảm của nước; những gia đình lành mạnh không tránh xung đột mà học cách vượt qua nó mà không mất đi tình yêu.", en: "Five of Wands and Ten of Cups: conflict within family or community — fire's competitive energy testing the strength of water's emotional bonds; healthy families do not avoid conflict but learn to move through it without losing love." },
  "26_46": { vi: "Năm Gậy và Trang Bị Cốc: xung đột gặp sự cởi mở cảm xúc — ngọn lửa chiến đấu gặp trái tim chưa bị chai lì; sự mong manh và tính xác thực của nước đôi khi có thể hạ thấp vũ khí của lửa theo cách mà sức mạnh không thể làm được.", en: "Five of Wands and Page of Cups: conflict meeting emotional openness — fighting fire encountering a heart not yet hardened; water's vulnerability and authenticity can sometimes lower fire's weapons in ways that strength cannot." },
  "26_47": { vi: "Năm Gậy và Kỵ Sĩ Cốc: lửa chiến đấu và nước lãng mạn đối lập nhau — một đang đánh nhau và một đang theo đuổi; cả hai đều đam mê nhưng theo những hướng hoàn toàn khác nhau, tạo ra sự va chạm thú vị giữa hai dạng nhiệt huyết.", en: "Five of Wands and Knight of Cups: fighting fire and romantic water at cross-purposes — one is battling and one is pursuing; both are passionate but in entirely different directions, creating an interesting clash of two forms of fervor." },
  "26_48": { vi: "Năm Gậy và Nữ Hoàng Cốc: xung đột được điều chỉnh bởi sự khôn ngoan — Nữ Hoàng không bị ảnh hưởng bởi xung đột của lửa và cũng không phớt lờ nó; bà biết cách giữ không gian cho cả sự gay gắt lẫn sự hòa giải.", en: "Five of Wands and Queen of Cups: conflict moderated by wisdom — the Queen neither inflamed by fire's conflict nor ignoring it; she knows how to hold space for both the tension and the reconciliation." },
  "26_49": { vi: "Năm Gậy và Vua Cốc: lửa tranh cãi được kiềm chế bởi thẩm quyền bình tĩnh — Vua không cần hét to hơn lửa để kiểm soát nó; sự điềm tĩnh của ông là đủ để hướng năng lượng cạnh tranh vào một kênh hữu ích.", en: "Five of Wands and King of Cups: squabbling fire reined in by calm authority — the King does not need to shout louder than fire to control it; his equanimity is enough to redirect competitive energy into a useful channel." },

  "27_36": { vi: "Sáu Gậy và Át Cốc: chiến thắng và tình yêu thuần khiết — vinh quang của lửa gặp một làn sóng cảm xúc hoàn toàn mới; chiến thắng đẹp nhất là những chiến thắng được kỷ niệm với trái tim rộng mở.", en: "Six of Wands and Ace of Cups: victory and pure love — fire's glory meeting a completely fresh wave of emotion; the most beautiful victories are those celebrated with an open heart." },
  "27_37": { vi: "Sáu Gậy và Hai Cốc: thành công công khai gặp kết nối riêng tư — sự thừa nhận của lửa trở nên phong phú hơn khi có sự hiện diện của một người bạn đồng hành thực sự; chiến thắng chia sẻ với người phù hợp là một loại chiến thắng hoàn toàn khác.", en: "Six of Wands and Two of Cups: public success meeting private connection — fire's recognition made richer by the presence of a true companion; victory shared with the right person is an entirely different kind of triumph." },
  "27_38": { vi: "Sáu Gậy và Ba Cốc: chiến thắng được tôn vinh bởi cộng đồng — thành công của lửa được khuếch đại bởi niềm vui tập thể; đây là sự kết hợp hoàn hảo của thành tích cá nhân và sự ăn mừng tập thể.", en: "Six of Wands and Three of Cups: triumph honored by community — fire's success amplified by collective joy; this is the perfect combination of individual achievement and communal celebration." },
  "27_39": { vi: "Sáu Gậy và Bốn Cốc: chiến thắng khi ai đó không chú ý — thành công của lửa không thể xuyên qua sự thờ ơ của nước; đôi khi sự hoàn thành tốt nhất đến đúng lúc khi người liên quan nhất lại ít chú ý nhất.", en: "Six of Wands and Four of Cups: victory when someone is not paying attention — fire's success unable to penetrate water's indifference; sometimes the finest accomplishment arrives at exactly the moment the most relevant person is least attentive." },
  "27_40": { vi: "Sáu Gậy và Năm Cốc: chiến thắng mang bóng của mất mát — ngay cả thành công cũng mang trọng tải của những gì đã phải từ bỏ để đạt được nó; lửa chiến thắng nhưng nước nhớ những gì đã bị hy sinh trên đường.", en: "Six of Wands and Five of Cups: triumph carrying the shadow of loss — even success bears the weight of what had to be given up to achieve it; fire wins but water remembers what was sacrificed along the way." },
  "27_41": { vi: "Sáu Gậy và Sáu Cốc: chiến thắng kết nối với gốc rễ — sự thành công của lửa gợi lại những ký ức đẹp từ quá khứ; đạt được điều gì đó lớn lao đôi khi mang về những người và những kỷ niệm đã hình thành nên bạn.", en: "Six of Wands and Six of Cups: triumph reconnecting with roots — fire's success stirring beautiful memories from the past; achieving something great sometimes brings back the people and memories that shaped who you are." },
  "27_42": { vi: "Sáu Gậy và Bảy Cốc: chiến thắng mở ra vô số khả năng — thành công của lửa tạo ra nhiều cơ hội mới, nhưng sự phán đoán cần thiết để chọn đúng con đường tiếp theo; không phải mọi giấc mơ sau chiến thắng đều xứng đáng theo đuổi.", en: "Six of Wands and Seven of Cups: victory opening countless possibilities — fire's success creating many new opportunities, but discernment is needed to choose the right next path; not every dream after victory deserves to be pursued." },
  "27_43": { vi: "Sáu Gậy và Tám Cốc: đỉnh cao là điểm khởi hành — thành công của lửa trở thành cột mốc trước khi nước bước vào chặng tiếp theo; đôi khi thời điểm tốt nhất để ra đi chính là sau khi đã hoàn thành điều gì đó thực sự có ý nghĩa.", en: "Six of Wands and Eight of Cups: the peak as departure point — fire's success becoming the milestone before water steps into the next chapter; sometimes the best time to leave is after having completed something truly meaningful." },
  "27_44": { vi: "Sáu Gậy và Chín Cốc: thành công kép — vinh quang công khai của lửa gặp sự thỏa mãn nội tâm của nước; khi cả thế giới bên ngoài lẫn bên trong đều hài hòa, cuộc sống đang ở đỉnh cao của mình.", en: "Six of Wands and Nine of Cups: double triumph — fire's public glory meeting water's inner contentment; when both the outer and inner worlds are aligned, life is at its peak." },
  "27_45": { vi: "Sáu Gậy và Mười Cốc: thành công chảy vào hạnh phúc hoàn toàn — vinh quang của lửa tìm thấy ý nghĩa sâu sắc nhất trong sự hài hòa gia đình của nước; những gì được tích lũy bên ngoài trở nên có giá trị thực sự khi được chia sẻ với những người thân yêu.", en: "Six of Wands and Ten of Cups: success flowing into complete happiness — fire's glory finding its deepest meaning in water's family harmony; what is accumulated outside becomes genuinely valuable when shared with those one loves." },
  "27_46": { vi: "Sáu Gậy và Trang Bị Cốc: người chiến thắng và người mơ mộng — thành công của lửa truyền cảm hứng cho tâm hồn trẻ của nước bắt đầu hành trình của riêng mình; mỗi chiến thắng được chứng kiến là một ngọn đuốc thắp sáng cho những người tiếp theo.", en: "Six of Wands and Page of Cups: the victor and the dreamer — fire's success inspiring water's young spirit to begin its own journey; every witnessed victory is a torch lighting the way for those who follow." },
  "27_47": { vi: "Sáu Gậy và Kỵ Sĩ Cốc: vinh quang và theo đuổi — cả hai đang trên đà tiến về phía trước; lửa đã đạt được điều gì đó trong khi nước vẫn đang trên đường; cùng nhau, chúng mô tả sự chuyển động hướng đến điều gì đó lớn hơn.", en: "Six of Wands and Knight of Cups: glory and pursuit — both are in forward momentum; fire has achieved something while water is still on the way; together they describe movement toward something greater." },
  "27_48": { vi: "Sáu Gậy và Nữ Hoàng Cốc: chiến thắng được vinh danh bởi chiều sâu cảm xúc — Nữ Hoàng đảm bảo rằng thành công của lửa được ghi nhận không chỉ bởi thế giới mà còn bởi trái tim; bà mang đến sự ấm áp cho sự công nhận mà lẽ ra có thể khô khan.", en: "Six of Wands and Queen of Cups: victory honored by emotional depth — the Queen ensuring fire's success is recognized not only by the world but by the heart; she brings warmth to an acknowledgment that might otherwise be dry." },
  "27_49": { vi: "Sáu Gậy và Vua Cốc: thành công công khai gặp thành thạo nội tâm — Vua nhận ra rằng vinh quang bên ngoài chỉ thực sự có ý nghĩa khi nó được nối đất trong sự trưởng thành cảm xúc; bậc thầy biết rằng chiến thắng thực sự là chiến thắng bên trong.", en: "Six of Wands and King of Cups: public success meeting inner mastery — the King recognizing that external glory only truly matters when grounded in emotional maturity; the master knows that real victory is the one within." },

  "28_36": { vi: "Bảy Gậy và Át Cốc: bảo vệ lãnh thổ trong khi tình yêu xuất hiện — lửa đang chiến đấu để giữ vững trong khi nước mang đến một làn sóng cảm xúc hoàn toàn mới; sự dễ bị tổn thương mới nhất có thể là điều giải trừ vũ trang cho người chiến đấu nhất.", en: "Seven of Wands and Ace of Cups: defending ground while love emerges — fire fighting to hold position while water brings a completely fresh emotional wave; the newest vulnerability can be the very thing that disarms the hardest fighter." },
  "28_37": { vi: "Bảy Gậy và Hai Cốc: bảo vệ bản thân trong khi khao khát kết nối — lửa phòng thủ gặp lời mời kết nối hỗ tương của nước; ranh giới giữa sự bảo vệ cần thiết và sự phòng thủ quá mức là điều xác định liệu sự kết nối có thể được thực hiện.", en: "Seven of Wands and Two of Cups: defending while longing for connection — defensive fire meeting water's invitation to mutual connection; the line between necessary protection and excessive defensiveness determines whether connection can be made." },
  "28_38": { vi: "Bảy Gậy và Ba Cốc: đứng vững trong khi cộng đồng tụ họp — lửa phòng thủ tương phản với sự ấm áp bao gồm của nước; đôi khi buông bỏ tư thế chiến đấu và tham gia vào sự vui vẻ tập thể là hành động dũng cảm nhất.", en: "Seven of Wands and Three of Cups: holding firm while the community gathers — defensive fire contrasting with water's inclusive warmth; sometimes releasing the fighting stance and joining collective joy is the most courageous act." },
  "28_39": { vi: "Bảy Gậy và Bốn Cốc: hai hình thức rút lui — lửa rút lui để chiến đấu và nước rút lui để cảm nhận; không ai thực sự tiếp xúc với người kia, và điều đó cần phải thay đổi trước khi bất kỳ điều gì thực sự có thể được giải quyết.", en: "Seven of Wands and Four of Cups: two forms of withdrawal — fire withdrawing to fight and water withdrawing to feel; neither is truly engaging with the other, and that must change before anything real can be resolved." },
  "28_40": { vi: "Bảy Gậy và Năm Cốc: đấu tranh kép — xung đột bên ngoài của lửa gặp nỗi đau bên trong của nước; khi cả hai nguyên tố đều ở trạng thái khó khăn, điều quan trọng nhất là không để cái khó khăn bên ngoài làm mù quáng cái đau khổ bên trong cần được chú ý.", en: "Seven of Wands and Five of Cups: double struggle — fire's external fighting meeting water's internal pain; when both elements are in difficulty, the most important thing is not letting external hardship blind one to the internal suffering that needs attention." },
  "28_41": { vi: "Bảy Gậy và Sáu Cốc: lấy sức mạnh từ quá khứ — lửa giữ vững vị trí bằng cách nhớ lại những gì nó luôn đại diện; những ký ức về bản thân mình là ai có thể là nguồn sức mạnh mạnh mẽ nhất trong cuộc đối đầu.", en: "Seven of Wands and Six of Cups: drawing strength from the past — fire holding its position by remembering what it has always stood for; memories of who one is can be the most powerful source of strength in any confrontation." },
  "28_42": { vi: "Bảy Gậy và Bảy Cốc: bảo vệ bản thân khỏi sự mập mờ — lửa cần sự rõ ràng khi nước cung cấp quá nhiều cảnh báo và khả năng hấp dẫn; khi đứng vững, người ta cần biết chính xác điều gì đáng được bảo vệ và điều gì chỉ là sự sợ hãi.", en: "Seven of Wands and Seven of Cups: defending against ambiguity — fire needing clarity when water offers too many warnings and enticing possibilities; when taking a stand, one must know exactly what is worth defending and what is only fear." },
  "28_43": { vi: "Bảy Gậy và Tám Cốc: đứng vững rồi rời đi — lửa tạo ra nền tảng cho cuộc ra đi của nước; đôi khi trước khi ra đi, cần phải bảo vệ những gì quan trọng một lần cuối, sau đó mới có thể thực sự để lại nó.", en: "Seven of Wands and Eight of Cups: standing firm then leaving — fire creating the foundation for water's departure; sometimes before leaving, one must defend what matters one final time, and only then can it truly be left behind." },
  "28_44": { vi: "Bảy Gậy và Chín Cốc: đấu tranh và sự bình yên — sự vất vả bên ngoài của lửa tương phản với sự thỏa mãn bên trong của nước; người ta có thể đang chiến đấu với thế giới trong khi trái tim hoàn toàn bình yên với chính mình.", en: "Seven of Wands and Nine of Cups: struggle and contentment — fire's external effort contrasted with water's inner satisfaction; one can be fighting the world while the heart is completely at peace with itself." },
  "28_45": { vi: "Bảy Gậy và Mười Cốc: bảo vệ điều mình yêu nhất — lửa đứng chiến đấu vì những sợi dây tình cảm và sự hài hòa gia đình của nước; sự sẵn sàng bảo vệ tình yêu là hình thức dũng cảm đẹp đẽ nhất của lửa.", en: "Seven of Wands and Ten of Cups: defending what one loves most — fire taking a stand to protect water's emotional bonds and family harmony; the willingness to defend love is fire's most beautiful form of courage." },
  "28_46": { vi: "Bảy Gậy và Trang Bị Cốc: lửa phòng thủ gặp trái tim cởi mở — sự dễ bị tổn thương và tính xác thực của nước đôi khi có thể hạ vũ khí của lửa theo cách mà không có lực lượng nào khác làm được; sự cởi mở là sức mạnh bất ngờ nhất.", en: "Seven of Wands and Page of Cups: defensive fire meeting the open heart — water's vulnerability and authenticity can sometimes disarm fire in ways no other force can; openness is the most unexpected strength." },
  "28_47": { vi: "Bảy Gậy và Kỵ Sĩ Cốc: lửa phòng thủ và nước lãng mạn — một đang chiến đấu để ở lại và một đang cưỡi đến; cả hai đều đam mê nhưng theo những cách hoàn toàn khác nhau, và sự va chạm hoặc sự kết hợp của chúng có thể là điều thú vị.", en: "Seven of Wands and Knight of Cups: defensive fire and romantic water — one is fighting to stay and one is riding to find; both are passionate but in entirely different ways, and their collision or combination can be something remarkable." },
  "28_48": { vi: "Bảy Gậy và Nữ Hoàng Cốc: lửa phòng thủ gặp sự từ bi sâu sắc — Nữ Hoàng không đánh lửa bằng cách phán xét hay đối đầu mà bằng cách đề nghị một cái gì đó khác hoàn toàn; đôi khi tư thế chiến đấu tan biến khi được nhìn thấy và được hiểu thực sự.", en: "Seven of Wands and Queen of Cups: defensive fire meeting deep compassion — the Queen does not challenge fire by judging or confronting but by offering something entirely different; sometimes the fighting stance dissolves when one is truly seen and understood." },
  "28_49": { vi: "Bảy Gậy và Vua Cốc: kiên định gặp thẩm quyền bình tĩnh — Vua dạy lửa rằng sức mạnh thực sự không yêu cầu tư thế chiến đấu; người làm chủ hoàn toàn cảm xúc của mình không bao giờ cần phải chứng minh điều gì.", en: "Seven of Wands and King of Cups: determination meeting calm authority — the King teaching fire that true strength does not require a fighting stance; one who completely masters their emotions never needs to prove anything." },
  // ── Tier 5a-2: Wands × Cups, fire×water (Wands 29–35 × Cups 36–49, 98 pairs) ──
  "29_36": { vi: "Tám Gậy và Át Cốc: tốc độ gặp khởi đầu cảm xúc — lửa di chuyển nhanh mang tin tức về tình yêu và cảm hứng mới; khi nhịp độ đúng, khoảnh khắc trái tim mở ra có thể đến bất ngờ và rực rỡ như tia sét.", en: "Eight of Wands and Ace of Cups: speed meeting emotional beginning — fire moving fast carrying news of new love and inspiration; when the timing is right, the moment the heart opens can arrive as suddenly and brilliantly as lightning." },
  "29_37": { vi: "Tám Gậy và Hai Cốc: động lực gặp kết nối — lửa chuyển động nhanh tìm thấy điểm đích trong sự hòa hợp của nước; hai trái tim đang hướng về nhau và tốc độ của sự kiện chỉ làm cho cuộc gặp gỡ thêm không thể tránh khỏi.", en: "Eight of Wands and Two of Cups: momentum meeting connection — fast-moving fire finding its destination in water's harmony; two hearts are moving toward each other and the speed of events only makes the meeting more inevitable." },
  "29_38": { vi: "Tám Gậy và Ba Cốc: lửa nhanh nhẹn thổi bùng niềm vui tập thể — tin tức tốt lan truyền nhanh chóng trong cộng đồng, và năng lượng của khoảnh khắc kéo mọi người lại với nhau để ăn mừng điều gì đó đang nở rộ.", en: "Eight of Wands and Three of Cups: swift fire fanning collective joy — good news spreading quickly through a community, and the energy of the moment drawing people together to celebrate something blossoming." },
  "29_39": { vi: "Tám Gậy và Bốn Cốc: chuyển động gặp tĩnh lặng — lửa đang di chuyển và nước đang ngồi im; đôi khi tốc độ và trạng thái rút lui đối nghịch nhau nhắc nhở rằng cả hai đều hợp lệ và cả hai đều có thể dạy điều gì đó cho nhau.", en: "Eight of Wands and Four of Cups: movement meeting stillness — fire is in motion and water is sitting quietly; sometimes speed and withdrawal are opposing reminders that both are valid and each can teach something to the other." },
  "29_40": { vi: "Tám Gậy và Năm Cốc: vượt qua đau thương — lửa chuyển động nhanh đôi khi là cách nước chạy trốn khỏi nỗi mất mát, nhưng đôi khi đó là năng lượng cần thiết để cuối cùng rời khỏi nơi đau đớn và tiến về phía trước.", en: "Eight of Wands and Five of Cups: moving through grief — fast-moving fire is sometimes how water flees from loss, but sometimes it is the energy needed to finally leave the place of pain and move forward." },
  "29_41": { vi: "Tám Gậy và Sáu Cốc: tốc độ và hoài niệm — lửa di chuyển về phía trước trong khi nước nhìn về phía sau; sự tương phản này nhắc nhở rằng chúng ta có thể mang theo ký ức ngọt ngào nhất trong khi vẫn đang lao về phía tương lai.", en: "Eight of Wands and Six of Cups: speed and nostalgia — fire moving forward while water looks backward; this contrast reminds that one can carry the sweetest memories while still rushing toward the future." },
  "29_42": { vi: "Tám Gậy và Bảy Cốc: di chuyển quá nhanh qua vùng ảo tưởng — lửa nhanh nhẹn không dừng lại để phân tích từng lựa chọn mà nước cung cấp; đây có thể là sự khôn ngoan hoặc sự bốc đồng, tùy thuộc vào hướng di chuyển.", en: "Eight of Wands and Seven of Cups: moving too fast through illusion — swift fire not pausing to examine every option water offers; this can be wisdom or impulsiveness, depending entirely on which direction one is moving." },
  "29_43": { vi: "Tám Gậy và Tám Cốc: sự ra đi nhanh chóng — khi nước quyết định rời đi, lửa cung cấp năng lượng cho sự ra đi đó; rời bỏ điều không còn phục vụ mình có thể được thực hiện với sự quyết đoán và tốc độ khi tâm trí đã được quyết định.", en: "Eight of Wands and Eight of Cups: the swift departure — when water decides to leave, fire provides the energy for that leaving; walking away from what no longer serves can be done with decisiveness and speed when the mind is made up." },
  "29_44": { vi: "Tám Gậy và Chín Cốc: đến nhanh chóng với sự thỏa mãn — lửa di chuyển nhanh về phía điều nước đã tích lũy; đôi khi ước muốn được thực hiện không phải sau một hành trình dài mà sau khi bạn đủ dũng cảm để di chuyển thật nhanh về phía nó.", en: "Eight of Wands and Nine of Cups: arriving swiftly at satisfaction — fire moving fast toward what water has accumulated; sometimes wishes are fulfilled not after a long journey but after you are brave enough to move toward them quickly." },
  "29_45": { vi: "Tám Gậy và Mười Cốc: tin tức tốt đến với gia đình — lửa mang thông điệp nhanh chóng về niềm vui và sự hoàn hảo; khi tốc độ và tình yêu kết hợp, khoảnh khắc hạnh phúc có thể đến trước khi bạn kịp chuẩn bị cho chúng.", en: "Eight of Wands and Ten of Cups: good news arriving for the family — fire carrying swift messages of joy and completion; when speed and love combine, moments of happiness can arrive before you have time to prepare for them." },
  "29_46": { vi: "Tám Gậy và Trang Bị Cốc: lửa nhanh nhẹn gặp trái tim tò mò — hai năng lượng trẻ trung tiếp cận nhau theo những cách bất ngờ; thông điệp cảm xúc đến nhanh và người nhận cần đủ sự tò mò để hiểu chúng trọn vẹn.", en: "Eight of Wands and Page of Cups: swift fire meeting the curious heart — two youthful energies approaching each other in unexpected ways; emotional messages arriving fast and the receiver needing enough curiosity to understand them fully." },
  "29_47": { vi: "Tám Gậy và Kỵ Sĩ Cốc: hai kỵ sĩ của hai nguyên tố — lửa di chuyển nhanh và nước theo đuổi lãng mạn; khi hai nguồn năng lượng này gặp nhau, kết quả có thể là một cuộc tình nồng nhiệt hoặc hai con đường đi song song không bao giờ thực sự giao nhau.", en: "Eight of Wands and Knight of Cups: two riders of different elements — fire moving swiftly and water pursuing romance; when these two energies meet, the result can be a passionate encounter or two parallel paths that never quite cross." },
  "29_48": { vi: "Tám Gậy và Nữ Hoàng Cốc: tốc độ gặp chiều sâu — lửa di chuyển nhanh nhưng nước biết rằng cảm xúc thực sự không thể bị vội vã; đây là sự nhắc nhở rằng đôi khi những điều quan trọng nhất đòi hỏi phải chậm lại dù lửa muốn tiến về phía trước.", en: "Eight of Wands and Queen of Cups: speed meeting depth — fire moving swiftly but water knowing that true emotion cannot be rushed; a reminder that sometimes the most important things require slowing down even when fire wants to press forward." },
  "29_49": { vi: "Tám Gậy và Vua Cốc: tốc độ được điều hướng bởi sự khôn ngoan — Vua Cốc không ngăn chặn lửa di chuyển nhưng giúp nó hiểu rằng tốc độ mà không có hướng dẫn cảm xúc có thể gây hại; sự kết hợp của cả hai tạo ra hành động nhanh nhưng sâu sắc.", en: "Eight of Wands and King of Cups: speed guided by wisdom — the King of Cups does not stop fire from moving but helps it understand that speed without emotional guidance can cause harm; their combination creates action that is swift yet deeply considered." },
  "30_36": { vi: "Chín Gậy và Át Cốc: mệt mỏi nhưng trái tim vẫn mở — người đã chiến đấu nhiều cũng có thể đón nhận tình yêu mới khi nó đến; vết thương cũ không ngăn cản khởi đầu mới mà đôi khi chính là nền tảng cho sự trân trọng sâu sắc hơn.", en: "Nine of Wands and Ace of Cups: battle-weary but the heart still opens — one who has fought much can still receive new love when it arrives; old wounds do not prevent new beginnings but sometimes become the foundation for deeper appreciation." },
  "30_37": { vi: "Chín Gậy và Hai Cốc: trái tim canh chừng tìm thấy kết nối — kẻ bảo vệ bản thân cũng khát khao được kết nối; khi sự tin tưởng được xây dựng dần dần và nước kiên nhẫn, thậm chí lửa cảnh giác nhất cũng có thể hạ tường phòng thủ.", en: "Nine of Wands and Two of Cups: the guarded heart finding connection — the one who protects themselves also longs for connection; when trust is built slowly and water is patient, even the most guarded fire can lower its defenses." },
  "30_38": { vi: "Chín Gậy và Ba Cốc: kiệt sức giữa niềm vui — người đã đứng gác quá lâu có thể thấy khó khi tham gia vào lễ kỷ niệm; nhưng đôi khi niềm vui tập thể là liều thuốc tốt nhất cho sự mệt mỏi của tinh thần chiến binh.", en: "Nine of Wands and Three of Cups: exhaustion amid celebration — one who has stood watch too long may find it hard to join the festivities; but sometimes collective joy is the best medicine for the weariness of the warrior spirit." },
  "30_39": { vi: "Chín Gậy và Bốn Cốc: hai sự rút lui khác nhau — lửa rút lui vì cảnh giác và nước rút lui vì chán nản; cả hai đều đứng ngoài rìa của cuộc sống, nhưng con đường trở về khác nhau và sự hiểu biết lẫn nhau có thể là bước đầu tiên.", en: "Nine of Wands and Four of Cups: two different withdrawals — fire retreating from vigilance and water retreating from boredom; both standing at the edge of life, but the paths back differ and mutual understanding can be the first step." },
  "30_40": { vi: "Chín Gậy và Năm Cốc: kiên cường dù mất mát — lửa đứng vững sau nhiều trận đấu và nước đang đau thương; bài học ở đây là sự kiên cường không có nghĩa là không có cảm giác đau, mà là đứng dậy ngay cả khi đau.", en: "Nine of Wands and Five of Cups: resilience despite loss — fire standing firm after many battles and water in grief; the lesson here is that resilience does not mean not feeling pain, but standing again even while it hurts." },
  "30_41": { vi: "Chín Gậy và Sáu Cốc: vết thương cũ và ký ức ngọt ngào — người đã chịu đựng nhiều đau khổ cũng có thể có những kỷ niệm đẹp; đôi khi chính những ký ức ngây thơ đó là thứ duy nhất giữ cho ngọn lửa tiếp tục cháy trong những khoảnh khắc tối nhất.", en: "Nine of Wands and Six of Cups: old wounds and sweet memories — one who has endured much suffering also carries beautiful memories; sometimes those innocent memories are the only thing keeping the flame burning in the darkest moments." },
  "30_42": { vi: "Chín Gậy và Bảy Cốc: cảnh giác chống lại ảo tưởng — lửa đã bị thương biết không được tin vào mọi thứ ngay lập tức; sự hoài nghi của người chiến binh có thể thực sự là tài sản khi đối mặt với những lựa chọn hấp dẫn nhưng không thực tế của nước.", en: "Nine of Wands and Seven of Cups: vigilance against illusion — wounded fire knows not to trust everything at once; the warrior's skepticism can actually be an asset when facing water's alluring but impractical options." },
  "30_43": { vi: "Chín Gậy và Tám Cốc: biết khi nào nên buông tay — lửa đã đứng canh quá lâu và nước biết lúc nào phải rời đi; cả hai cùng nhau dạy rằng sự kiên trì và sự buông bỏ đều là dũng khí, và ranh giới giữa chúng chỉ mình ta mới thực sự biết.", en: "Nine of Wands and Eight of Cups: knowing when to let go — fire that has stood watch too long and water that knows when to leave; together they teach that both perseverance and release are courage, and only you truly know the line between them." },
  "30_44": { vi: "Chín Gậy và Chín Cốc: sự kiên trì dẫn đến mãn nguyện — lửa không từ bỏ cuối cùng được thưởng bằng những gì nước tích lũy; sự kết hợp của hai con chín cho thấy rằng sau những trận đấu gian khổ, sự bình an và no đủ thực sự đang chờ đón.", en: "Nine of Wands and Nine of Cups: perseverance leading to contentment — fire that does not give up finally receives what water has accumulated; the union of two nines suggests that after difficult battles, genuine peace and fulfillment are waiting." },
  "30_45": { vi: "Chín Gậy và Mười Cốc: bảo vệ những gì thiêng liêng nhất — lửa chiến binh đứng gác ở cổng và bên trong là tất cả tình yêu và sự hài hòa của nước; không có gì đáng để chiến đấu hơn là sự hạnh phúc của những người ta yêu thương.", en: "Nine of Wands and Ten of Cups: guarding what is most sacred — the warrior fire standing watch at the gate with all of water's love and harmony inside; nothing is more worth fighting for than the happiness of those you love." },
  "30_46": { vi: "Chín Gậy và Trang Bị Cốc: chiến binh mệt mỏi và sứ giả trẻ tuổi — lửa đã từng thơ ngây như nước đang là và nước có thể học từ những vết thương của lửa mà không cần phải tự mình gánh chịu; sự dịu dàng của tuổi trẻ có thể hàn gắn ngay cả những phòng thủ kiên cố nhất.", en: "Nine of Wands and Page of Cups: the weary warrior and the young messenger — fire was once as innocent as water is now and water can learn from fire's wounds without having to suffer them; the gentleness of youth can heal even the most fortified defenses." },
  "30_47": { vi: "Chín Gậy và Kỵ Sĩ Cốc: chiến binh và kỵ sĩ lãng mạn — lửa đã chứng kiến quá nhiều và nước lãng mạn vẫn đang đuổi theo ước mơ; cả hai cần nhau — kinh nghiệm của lửa bảo vệ nước khỏi lý tưởng ngây thơ và nhiệt tình của nước nhắc lửa rằng vẫn còn điều đáng theo đuổi.", en: "Nine of Wands and Knight of Cups: the veteran and the romantic rider — battle-worn fire and romantic water still chasing dreams; each needs the other — fire's experience protecting water from naive idealism and water's enthusiasm reminding fire there is still something worth pursuing." },
  "30_48": { vi: "Chín Gậy và Nữ Hoàng Cốc: sự từ bi chữa lành người chiến binh — Nữ Hoàng Cốc không phán xét vết thương mà ngồi với chúng; đôi khi sự chữa lành không đến từ việc đứng dậy mà từ khi cuối cùng được phép ngồi xuống và được chăm sóc.", en: "Nine of Wands and Queen of Cups: compassion healing the warrior — the Queen of Cups does not judge the wounds but sits with them; sometimes healing comes not from standing up again but from finally being allowed to sit down and be cared for." },
  "30_49": { vi: "Chín Gậy và Vua Cốc: hai người bậc thầy — lửa dày dạn kinh nghiệm gặp nước làm chủ cảm xúc; cả hai hiểu sự kiên trì và cả hai biết rằng sức mạnh thực sự không bao giờ cần phải chứng tỏ, chỉ cần được thể hiện qua sự tồn tại bình tĩnh và vững chắc của mình.", en: "Nine of Wands and King of Cups: two masters — battle-hardened fire meeting emotionally mastered water; both understand perseverance and both know that true strength never needs proving, only expressing through one's calm and steady presence." },
  "31_36": { vi: "Mười Gậy và Át Cốc: gánh nặng và tình yêu mới — người đang mang quá nhiều vẫn có thể được tình yêu chạm đến; đôi khi một trái tim mới mở ra đúng lúc khi gánh nặng trở nên nặng nhất, nhắc nhở rằng không phải tất cả đều phải được gánh một mình.", en: "Ten of Wands and Ace of Cups: burden and new love — one carrying too much can still be touched by love; sometimes a heart opens at exactly the moment the burden becomes heaviest, reminding that not everything must be carried alone." },
  "31_37": { vi: "Mười Gậy và Hai Cốc: gánh nặng được chia sẻ trong sự kết nối — lửa mang quá nhiều một mình và nước nhắc rằng sự kết nối thực sự bao gồm chia sẻ trọng tải; đây là lời mời để buông bỏ một phần và tin tưởng rằng người khác có thể cùng mang.", en: "Ten of Wands and Two of Cups: burden shared in partnership — fire carrying too much alone and water reminding that true connection includes sharing the load; this is an invitation to release some weight and trust that another can carry it together." },
  "31_38": { vi: "Mười Gậy và Ba Cốc: kiệt sức cố gắng tham dự lễ hội — người đang oằn lưng dưới gánh nặng khó tìm thấy sự nhẹ nhàng để ăn mừng; nhưng đôi khi chính cộng đồng vui vẻ có thể giúp người đó đặt gánh nặng xuống dù chỉ một lúc.", en: "Ten of Wands and Three of Cups: exhaustion trying to attend the celebration — one bowed under burden finds it hard to find lightness in festivity; but sometimes the joyful community itself can help them set the weight down, if only for a moment." },
  "31_39": { vi: "Mười Gậy và Bốn Cốc: quá tải dẫn đến rút lui — khi gánh nặng trở nên không thể chịu đựng được, đôi khi sự rút lui mà nước thể hiện là phản ứng lành mạnh duy nhất; không ai có thể tiếp tục mang vác mọi thứ mà không có giai đoạn nghỉ ngơi và suy ngẫm.", en: "Ten of Wands and Four of Cups: overload leading to withdrawal — when the burden becomes unbearable, sometimes the retreat water embodies is the only healthy response; no one can keep carrying everything without periods of rest and contemplation." },
  "31_40": { vi: "Mười Gậy và Năm Cốc: áp đảo và đau thương — cả hai năng lượng đều đang ở trạng thái khó khăn; gánh nặng của lửa và nỗi đau của nước cùng tồn tại và đôi khi điều cần thiết nhất là thừa nhận rằng cả hai đều thực và cả hai đều cần được ghi nhận.", en: "Ten of Wands and Five of Cups: overwhelm and grief — both energies are in a difficult state; fire's burden and water's pain coexisting, and sometimes what is most needed is acknowledging that both are real and both deserve recognition." },
  "31_41": { vi: "Mười Gậy và Sáu Cốc: hoài niệm cho khi gánh nặng nhẹ hơn — người đang mang quá nhiều nhớ lại một thời đơn giản hơn khi mọi thứ đều tươi sáng và nhẹ nhàng; những ký ức đó không phải là sự trốn tránh mà là lời nhắc rằng trạng thái đó có thể được tìm lại.", en: "Ten of Wands and Six of Cups: nostalgia for when the burden was lighter — one carrying too much remembering a simpler time when everything was bright and easy; those memories are not escape but reminders that such a state can be found again." },
  "31_42": { vi: "Mười Gậy và Bảy Cốc: quá tải tránh né quyết định — người đang mang quá nhiều khó có thể đối mặt với thêm những lựa chọn phức tạp mà nước cung cấp; đây là lời nhắc về việc ưu tiên và đặt xuống những thứ không thiết yếu trước khi thêm bất cứ điều gì khác.", en: "Ten of Wands and Seven of Cups: overload avoiding decisions — one carrying too much finds it hard to face the additional complex choices water offers; a reminder about prioritizing and setting down the non-essential before adding anything else." },
  "31_43": { vi: "Mười Gậy và Tám Cốc: quyết định đặt gánh nặng xuống — đây là sự kết hợp về sự buông bỏ; lửa mang quá nhiều và nước biết cách ra đi; khi cả hai gặp nhau, điều dũng cảm nhất có thể là đặt hết xuống và bắt đầu bước đi nhẹ nhàng hơn.", en: "Ten of Wands and Eight of Cups: the decision to put down the burden — this is a combination about release; fire carrying too much and water knowing how to leave; when both meet, the bravest thing may be setting it all down and beginning to walk lighter." },
  "31_44": { vi: "Mười Gậy và Chín Cốc: mang gánh nặng hướng tới sự thỏa mãn — lửa đang làm việc chăm chỉ hướng tới những gì nước đã tích lũy; đây là sự kết hợp của nỗ lực và phần thưởng, nhưng cũng là lời nhắc nhở rằng đôi khi gánh nặng không cần thiết để đạt được hạnh phúc.", en: "Ten of Wands and Nine of Cups: carrying the burden toward satisfaction — fire working hard toward what water has accumulated; a combination of effort and reward, but also a reminder that sometimes the burden is not necessary to achieve happiness." },
  "31_45": { vi: "Mười Gậy và Mười Cốc: mang tất cả vì gia đình — lửa đang gánh chịu mọi thứ để bảo vệ tình yêu và sự hòa hợp bên trong; sự hy sinh này đẹp nhưng cũng là lời cảnh báo rằng ngay cả khi yêu thương, cần phải biết giới hạn của những gì một người có thể mang.", en: "Ten of Wands and Ten of Cups: carrying everything for the family — fire shouldering all things to protect the love and harmony within; this sacrifice is beautiful but also a warning that even in love, one must know the limit of what one person can carry." },
  "31_46": { vi: "Mười Gậy và Trang Bị Cốc: gánh nặng gặp tâm hồn trẻ tuổi — thông điệp cảm xúc của nước đến với người đang quá bận bịu để chú ý; đây là lời nhắc nhở rằng ngay cả khi đang bận rộn nhất, đôi khi điều quan trọng nhất lại đến với dạng nhỏ bé và bất ngờ nhất.", en: "Ten of Wands and Page of Cups: burden meeting the young soul — water's emotional message arriving for one too occupied to notice; a reminder that even at one's busiest, sometimes the most important thing arrives in the smallest and most unexpected form." },
  "31_47": { vi: "Mười Gậy và Kỵ Sĩ Cốc: gánh nặng và sự đuổi theo lãng mạn — người đang oằn lưng nhìn người kỵ sĩ lãng mạn phóng đi và tự hỏi khi nào mình có thể tự do như vậy; đây là sự nhắc nhở rằng gánh nặng không phải là vĩnh cửu và lý tưởng vẫn có giá trị theo đuổi.", en: "Ten of Wands and Knight of Cups: burden and romantic pursuit — one bowed under weight watching the romantic rider gallop free, wondering when they will be so unencumbered; a reminder that burden is not permanent and ideals are still worth pursuing." },
  "31_48": { vi: "Mười Gậy và Nữ Hoàng Cốc: nhân chứng từ bi cho người đang kiệt sức — Nữ Hoàng Cốc không lấy gánh nặng đi nhưng ngồi cạnh người đang mang; đôi khi chỉ cần được nhìn thấy trong sự vất vả của mình là đã đủ để tìm lại sức mạnh tiếp tục.", en: "Ten of Wands and Queen of Cups: compassionate witness to the exhausted — the Queen of Cups does not remove the burden but sits beside the one carrying it; sometimes merely being seen in one's struggle is enough to find the strength to continue." },
  "31_49": { vi: "Mười Gậy và Vua Cốc: lời khuyên khôn ngoan cho người quá tải — Vua Cốc có thể nhìn thấy điều lửa không thể thấy khi đang cúi đầu dưới gánh nặng; rằng không phải tất cả trách nhiệm đều là của mình và sức mạnh thực sự đôi khi là biết cách ủy thác và buông bỏ.", en: "Ten of Wands and King of Cups: wise counsel for the overloaded — the King of Cups can see what fire cannot see when bowed under burden; that not all responsibility is theirs to carry and that true strength is sometimes knowing how to delegate and release." },
  "32_36": { vi: "Trang Bị Gậy và Át Cốc: hai khởi đầu — lửa trẻ tuổi đầy tò mò gặp tình yêu mới nở; khi cả hai đang ở điểm xuất phát, mọi thứ đều có thể và niềm hứng khởi là nhiên liệu hoàn hảo cho sự nảy sinh của tình cảm.", en: "Page of Wands and Ace of Cups: two beginnings — curious young fire meeting newly blossomed love; when both are at their starting point, everything is possible and enthusiasm is the perfect fuel for the emergence of feeling." },
  "32_37": { vi: "Trang Bị Gậy và Hai Cốc: lửa trẻ khám phá kết nối — lần đầu tiên tìm hiểu về mối quan hệ thực sự là điều kỳ diệu và đáng sợ; tâm hồn tò mò của lửa muốn hiểu mọi thứ và nước nhẫn nại với hai cốc chào đón sự khám phá đó.", en: "Page of Wands and Two of Cups: young fire discovering connection — learning about true partnership for the first time is both wondrous and frightening; fire's curious soul wanting to understand everything and water's patient two of cups welcoming that exploration." },
  "32_38": { vi: "Trang Bị Gậy và Ba Cốc: tinh thần trẻ tuổi trong lễ hội — lửa tò mò thấy mình hoàn toàn ở đúng chỗ giữa sự ăn mừng và niềm vui tập thể; đây là sự kết hợp của năng lượng sống động và niềm vui chung tạo ra những kỷ niệm đẹp đẽ nhất.", en: "Page of Wands and Three of Cups: the young spirit in celebration — curious fire finding itself entirely in its element amid festivities and collective joy; a combination of vibrant energy and shared happiness creating the most beautiful memories." },
  "32_39": { vi: "Trang Bị Gậy và Bốn Cốc: nhiệt tình gặp thờ ơ — lửa trẻ không hiểu tại sao nước lại ngồi yên khi thế giới đang vẫy gọi; nhưng đây cũng là cơ hội học hỏi — rằng đôi khi sự dừng lại và chờ đợi cũng quan trọng như sự hành động.", en: "Page of Wands and Four of Cups: enthusiasm meeting apathy — young fire not understanding why water sits still when the world is calling; but also an opportunity to learn — that sometimes pausing and waiting matters as much as acting." },
  "32_40": { vi: "Trang Bị Gậy và Năm Cốc: tâm hồn trẻ đối mặt với mất mát lần đầu — lửa chưa biết cách ứng phó với nỗi đau của nước; đây là khoảnh khắc trưởng thành quan trọng khi lòng can đảm và sự tò mò của lửa phải học cách ngồi với nỗi buồn thay vì chạy khỏi nó.", en: "Page of Wands and Five of Cups: the young soul facing loss for the first time — fire not yet knowing how to respond to water's pain; a critical maturation moment when fire's courage and curiosity must learn to sit with sadness instead of running from it." },
  "32_41": { vi: "Trang Bị Gậy và Sáu Cốc: hai tâm hồn ngây thơ — cả hai đều mang vẻ trong sáng của người chưa bị thế giới làm cứng lại; khi gặp nhau, họ tạo ra một không gian an toàn nơi niềm vui thuần khiết và sự kỳ diệu vẫn còn tồn tại.", en: "Page of Wands and Six of Cups: two innocent souls — both carrying the purity of one not yet hardened by the world; when they meet, they create a safe space where pure joy and wonder still exist." },
  "32_42": { vi: "Trang Bị Gậy và Bảy Cốc: lửa trẻ tuổi theo đuổi quá nhiều ảo tưởng — nhiệt tình của lửa gặp những viễn cảnh hấp dẫn của nước là sự kết hợp thú vị nhưng cũng dễ bị lạc hướng; đây là lời nhắc nhở quan trọng về sự tập trung và phân biệt giữa giấc mơ thực và ảo tưởng.", en: "Page of Wands and Seven of Cups: young fire chasing too many illusions — fire's enthusiasm meeting water's alluring visions is exciting but also easily misled; an important reminder about focus and distinguishing between genuine dreams and empty fantasies." },
  "32_43": { vi: "Trang Bị Gậy và Tám Cốc: tâm hồn tò mò hỏi tại sao người khác ra đi — lửa trẻ chưa hiểu rằng đôi khi rời đi là dũng cảm nhất; câu hỏi của lửa là một phần của sự trưởng thành, học rằng không phải mọi sự ra đi đều là sự từ bỏ.", en: "Page of Wands and Eight of Cups: the curious soul asking why someone is leaving — young fire not yet understanding that sometimes leaving is the bravest act; fire's questioning is part of growing up, learning that not every departure is abandonment." },
  "32_44": { vi: "Trang Bị Gậy và Chín Cốc: niềm vui trẻ tuổi và sự thỏa mãn — lửa tò mò bước vào không gian của nước đã đạt được và cảm nhận điều đó như một kỳ quan; đây là sự kết hợp của niềm vui học hỏi và sự sung mãn có được từ những khoảnh khắc hoàn hảo.", en: "Page of Wands and Nine of Cups: youthful joy and contentment — curious fire stepping into water's space of attainment and feeling it as a wonder; a combination of the joy of learning and the fullness that comes from perfect moments." },
  "32_45": { vi: "Trang Bị Gậy và Mười Cốc: tâm hồn trẻ tuổi trong gia đình hạnh phúc — lửa trẻ đang học thế nào là tình yêu thực sự và sự thuộc về; những gì nước có thể tạo ra — gia đình hòa thuận và tình yêu thương đích thực — là điều lửa sẽ tiếp tục theo đuổi suốt cuộc đời.", en: "Page of Wands and Ten of Cups: the young soul in a happy family — young fire learning what true love and belonging look like; what water can create — harmonious family and genuine love — is what fire will continue pursuing throughout life." },
  "32_46": { vi: "Trang Bị Gậy và Trang Bị Cốc: hai trang bị từ hai nguyên tố — lửa tò mò và nước mộng mơ; khi hai người trẻ của hai thế giới khác nhau gặp nhau, điều ma thuật có thể xảy ra — một cái nhìn mới về những gì có thể tồn tại khi lửa và nước học hỏi lẫn nhau.", en: "Page of Wands and Page of Cups: two pages from two elements — curious fire and dreaming water; when two young ones from different worlds meet, something magical can happen — a new vision of what is possible when fire and water learn from each other." },
  "32_47": { vi: "Trang Bị Gậy và Kỵ Sĩ Cốc: học trò ngưỡng mộ kỵ sĩ — lửa trẻ nhìn kỵ sĩ nước với sự ngưỡng mộ vì sự lãng mạn và lòng dũng cảm của nó; đây là sự kết hợp của sự truyền cảm hứng khi người trẻ tuổi thấy điều mình muốn trở thành được hiện thân trong người khác.", en: "Page of Wands and Knight of Cups: the apprentice admiring the knight — young fire watching the water knight with admiration for its romance and bravery; a combination of inspiration when the young one sees what they want to become embodied in another." },
  "32_48": { vi: "Trang Bị Gậy và Nữ Hoàng Cốc: tâm hồn trẻ được nuôi dưỡng bởi sự từ bi — Nữ Hoàng Cốc đón nhận lửa tò mò với trái tim rộng mở; sự hỗ trợ của bà không dập tắt ngọn lửa mà bao bọc nó trong tình yêu thương để nó có thể phát triển theo cách riêng của mình.", en: "Page of Wands and Queen of Cups: the young soul nurtured by compassion — the Queen of Cups receiving curious fire with an open heart; her support does not extinguish the flame but wraps it in love so it can grow in its own way." },
  "32_49": { vi: "Trang Bị Gậy và Vua Cốc: tò mò gặp sự khôn ngoan — lửa trẻ đặt câu hỏi và Vua Cốc có sự bình tĩnh để trả lời từ kinh nghiệm chứ không phải từ lý thuyết; đây là mối quan hệ thầy trò tốt nhất khi nhiệt tình của lửa được hướng dẫn bởi chiều sâu cảm xúc của nước.", en: "Page of Wands and King of Cups: curiosity meeting wisdom — young fire asking questions and the King of Cups having the stillness to answer from experience rather than theory; this is the best mentor relationship when fire's enthusiasm is guided by water's emotional depth." },
  "33_36": { vi: "Kỵ Sĩ Gậy và Át Cốc: cuộc phiêu lưu dũng cảm hướng tới tình yêu mới — lửa đang phi nước đại về phía khởi đầu cảm xúc; khi sự táo bạo và tình yêu mới nở gặp nhau, kết quả là sự đam mê ở dạng thuần khiết nhất và đẹp đẽ nhất.", en: "Knight of Wands and Ace of Cups: bold adventure riding toward new love — fire galloping at full speed toward the emotional beginning; when boldness and newly bloomed love meet, the result is passion in its purest and most beautiful form." },
  "33_37": { vi: "Kỵ Sĩ Gậy và Hai Cốc: kỵ sĩ táo bạo tìm thấy kết nối — lửa không dừng lại vì nhiều thứ nhưng sự hòa hợp thực sự của nước có thể khiến nó dừng lại; đây là sự kết hợp của đam mê và kết nối sâu sắc, khi năng lượng mạnh mẽ nhất tìm được nơi để neo đậu.", en: "Knight of Wands and Two of Cups: the bold knight finding connection — fire does not stop for much but water's true harmony can make it pause; a combination of passion and deep connection, when the strongest energy finds somewhere to anchor." },
  "33_38": { vi: "Kỵ Sĩ Gậy và Ba Cốc: tinh thần phiêu lưu giữa lễ hội — lửa táo bạo mang năng lượng bùng nổ vào buổi ăn mừng của nước; khi cả hai cùng có mặt, không khí trở nên điện khí và kỷ niệm được tạo ra không thể nào quên.", en: "Knight of Wands and Three of Cups: the adventurous spirit amid celebration — bold fire bringing explosive energy into water's celebration; when both are present, the atmosphere becomes electric and unforgettable memories are made." },
  "33_39": { vi: "Kỵ Sĩ Gậy và Bốn Cốc: bất an gặp sự trầm lặng — lửa không thể hiểu tại sao nước ngồi yên khi có quá nhiều thứ để làm và khám phá; nhưng đây cũng là lời nhắc rằng không phải lúc nào cũng nên chạy — đôi khi dừng lại chính là hành động khôn ngoan nhất.", en: "Knight of Wands and Four of Cups: restlessness meeting stillness — fire unable to understand why water sits still when there is so much to do and explore; but also a reminder that one should not always run — sometimes stopping is the wisest action of all." },
  "33_40": { vi: "Kỵ Sĩ Gậy và Năm Cốc: vượt qua nỗi đau bằng hành động — lửa có xu hướng phi nước đại khỏi những gì đau đớn thay vì đối mặt với nó; đây là sự cảnh báo rằng tốc độ không phải lúc nào cũng là sự chữa lành và đôi khi cần phải dừng lại và để cho nỗi đau được cảm nhận.", en: "Knight of Wands and Five of Cups: galloping past grief — fire tends to ride hard away from what is painful rather than facing it; a warning that speed is not always healing and sometimes one must stop and allow grief to be fully felt." },
  "33_41": { vi: "Kỵ Sĩ Gậy và Sáu Cốc: kỵ sĩ lửa và ký ức ngọt ngào — người đang lao về phía tương lai nhìn qua vai và thấy khoảng thời gian đẹp đẽ trong quá khứ; đây không phải là sự hoài niệm tê liệt mà là sự nhớ lại nhanh chóng làm phong phú thêm hành trình phía trước.", en: "Knight of Wands and Six of Cups: the fire rider and sweet memory — one riding hard toward the future glancing back to see a beautiful past; this is not paralyzing nostalgia but a swift recollection enriching the journey ahead." },
  "33_42": { vi: "Kỵ Sĩ Gậy và Bảy Cốc: lửa táo bạo đuổi theo nhiều ảo tưởng — kỵ sĩ nhanh nhẹn nhảy từ ảo mộng này sang ảo mộng khác mà không bao giờ hoàn thành bất kỳ điều gì; đây là sự cảnh báo rằng năng lượng và nhiệt tình cần được hướng dẫn nếu không muốn lãng phí vào những ảo tưởng đẹp nhưng rỗng.", en: "Knight of Wands and Seven of Cups: bold fire chasing many illusions — the swift rider leaping from dream to dream without completing anything; a warning that energy and enthusiasm need direction or they will be wasted on beautiful but empty fantasies." },
  "33_43": { vi: "Kỵ Sĩ Gậy và Tám Cốc: kỵ sĩ không nhìn lại — cả hai đều là những người ra đi; lửa rời đi vì hành động và nước rời đi vì sự buồn bã; khi cả hai kết hợp, sự ra đi trở nên mạnh mẽ và dứt khoát nhất, không để lại gì phía sau ngoài bụi đường.", en: "Knight of Wands and Eight of Cups: the rider who does not look back — both are those who leave; fire leaving because of action and water leaving because of sorrow; when both combine, the departure becomes the strongest and most decisive, leaving nothing behind but road dust." },
  "33_44": { vi: "Kỵ Sĩ Gậy và Chín Cốc: phi về phía niềm vui — lửa táo bạo đang di chuyển nhanh chóng về phía điều nước đã đạt được; đây là sự kết hợp của nhiệt tình đang hướng tới đúng đích — không phải ảo tưởng mà là sự thỏa mãn thực sự đang chờ đợi.", en: "Knight of Wands and Nine of Cups: riding toward joy — bold fire moving rapidly toward what water has attained; a combination of enthusiasm aimed at the right destination — not illusion but genuine satisfaction waiting ahead." },
  "33_45": { vi: "Kỵ Sĩ Gậy và Mười Cốc: kỵ sĩ lửa phi về nhà — sau tất cả những cuộc phiêu lưu, ngọn lửa nhận ra điều quan trọng nhất đang chờ ở nhà; sự ấm áp và tình yêu của gia đình là mục tiêu xứng đáng nhất cho tất cả năng lượng và lòng dũng cảm của lửa.", en: "Knight of Wands and Ten of Cups: the fire rider galloping home — after all the adventures, fire realizes the most important thing is waiting at home; the warmth and love of family is the most worthy destination for all of fire's energy and courage." },
  "33_46": { vi: "Kỵ Sĩ Gậy và Trang Bị Cốc: kỵ sĩ dạy người trẻ — lửa táo bạo truyền cảm hứng cho trang bị nước về những gì có thể đạt được với lòng dũng cảm; người trẻ của nước mang thông điệp này và đặt câu hỏi về những gì trái tim họ thực sự muốn theo đuổi.", en: "Knight of Wands and Page of Cups: the knight inspiring the young one — bold fire inspiring the water page about what can be achieved with courage; water's young one receiving this message and questioning what their heart truly wishes to pursue." },
  "33_47": { vi: "Kỵ Sĩ Gậy và Kỵ Sĩ Cốc: hai kỵ sĩ, hai nguyên tố — lửa và nước đều đang đi tìm điều gì đó nhưng theo những cách hoàn toàn khác nhau; lửa hành động bốc đồng và nước theo đuổi lý tưởng; khi họ gặp nhau, cuộc gặp gỡ là bất ngờ, thú vị và đầy tiềm năng.", en: "Knight of Wands and Knight of Cups: two knights, two elements — fire and water both seeking something but in entirely different ways; fire acting impulsively and water pursuing ideals; when they meet, the encounter is surprising, exciting and full of potential." },
  "33_48": { vi: "Kỵ Sĩ Gậy và Nữ Hoàng Cốc: lửa bốc đồng gặp sự từ bi sâu sắc — Nữ Hoàng Cốc không cố kiểm soát kỵ sĩ lửa nhưng cung cấp chiều sâu mà lửa thiếu; sự dịu dàng của nước có thể là điều duy nhất thực sự chạm đến và làm mềm lòng người đang di chuyển không ngừng.", en: "Knight of Wands and Queen of Cups: impulsive fire meeting deep compassion — the Queen of Cups does not try to control the fire knight but offers the depth fire lacks; water's tenderness may be the one thing that truly touches and softens the one in perpetual motion." },
  "33_49": { vi: "Kỵ Sĩ Gậy và Vua Cốc: năng lượng bốc đồng được hướng dẫn bởi sự thành thạo — Vua Cốc không phán xét sự táo bạo của lửa mà nhận ra tiềm năng bên trong nó; với sự hướng dẫn khôn ngoan và bình tĩnh, lửa bốc đồng có thể trở thành lửa có mục đích.", en: "Knight of Wands and King of Cups: impulsive energy guided by mastery — the King of Cups does not judge fire's boldness but recognizes the potential within it; with wise and calm guidance, impulsive fire can become purposeful fire." },
  "34_36": { vi: "Nữ Hoàng Gậy và Át Cốc: sự rực rỡ chào đón tình yêu mới — lửa tự tin và lôi cuốn mở ra không gian cho cảm xúc mới nảy sinh; Nữ Hoàng Gậy biết rằng sức mạnh của mình không loại trừ tình yêu mà thực sự thu hút nó.", en: "Queen of Wands and Ace of Cups: radiance welcoming new love — confident and charismatic fire opening space for new emotion to blossom; the Queen of Wands knowing that her strength does not exclude love but actually attracts it." },
  "34_37": { vi: "Nữ Hoàng Gậy và Hai Cốc: hai nữ hoàng gặp nhau trong mối kết nối — lửa tự tin và nước hài hòa tạo nên một mối quan hệ của sự bình đẳng thực sự; không ai trong số họ cần người kia để hoàn chỉnh bản thân, nhưng họ chọn nhau vì sự lựa chọn đó làm phong phú thêm cả hai.", en: "Queen of Wands and Two of Cups: two powers meeting in connection — confident fire and harmonious water creating a relationship of true equality; neither needing the other to complete themselves, but choosing each other because that choice enriches both." },
  "34_38": { vi: "Nữ Hoàng Gậy và Ba Cốc: lửa rực rỡ trong lễ hội — Nữ Hoàng Gậy không chỉ tham dự bữa tiệc mà còn làm cho nó trở nên sống động hơn; năng lượng của bà nâng cao niềm vui tập thể và sự hiện diện của bà khiến mọi người cảm thấy được chào đón và được nhìn thấy.", en: "Queen of Wands and Three of Cups: radiant fire in celebration — the Queen of Wands does not merely attend the party but makes it more alive; her energy elevates collective joy and her presence makes everyone feel welcomed and seen." },
  "34_39": { vi: "Nữ Hoàng Gậy và Bốn Cốc: sự sôi nổi gặp sự thờ ơ — lửa tràn đầy năng lượng nhìn nước đang thờ ơ và cảm thấy khó chịu; nhưng Nữ Hoàng Gậy khôn ngoan biết rằng đôi khi sự dừng lại của người khác không phải là sự yếu đuối mà là quá trình xử lý sâu sắc đang diễn ra bên trong.", en: "Queen of Wands and Four of Cups: vibrancy meeting apathy — energetic fire looking at indifferent water and feeling impatient; but the wise Queen of Wands knows that sometimes another's pause is not weakness but deep processing happening within." },
  "34_40": { vi: "Nữ Hoàng Gậy và Năm Cốc: sức mạnh nhân từ trong nỗi đau — Nữ Hoàng Gậy không giả vờ nỗi đau không tồn tại mà đứng cùng với người đang đau trong sức mạnh và tình yêu thương; bà biết cách giữ không gian cho cả sự mất mát và sự vươn lên.", en: "Queen of Wands and Five of Cups: compassionate strength in pain — the Queen of Wands does not pretend pain does not exist but stands with the grieving in strength and love; she knows how to hold space for both loss and rising." },
  "34_41": { vi: "Nữ Hoàng Gậy và Sáu Cốc: trở lại với sự ấm áp — lửa tự tin nhìn lại quá khứ không phải để ở lại đó mà để lấy lại sự ấm áp và sự vô tư từ thời thơ ấu; Nữ Hoàng Gậy mang năng lượng của hoài niệm vào hiện tại như một nguồn tài nguyên, không phải như một gánh nặng.", en: "Queen of Wands and Six of Cups: returning to warmth — confident fire looking to the past not to stay there but to reclaim the warmth and innocence of childhood; the Queen of Wands bringing nostalgic energy into the present as a resource, not a burden." },
  "34_42": { vi: "Nữ Hoàng Gậy và Bảy Cốc: lửa sáng suốt cắt qua ảo tưởng — Nữ Hoàng Gậy có đủ tự tin để không bị lung lay bởi những khả năng hấp dẫn nhưng không thực tế; bà nhìn qua những ảo tưởng mà nước tạo ra và chọn những gì thực sự phù hợp với sức mạnh và mục đích của mình.", en: "Queen of Wands and Seven of Cups: discerning fire cutting through illusion — the Queen of Wands confident enough not to be swayed by alluring but impractical possibilities; she sees through water's illusions and chooses only what truly aligns with her strength and purpose." },
  "34_43": { vi: "Nữ Hoàng Gậy và Tám Cốc: lửa tự tin biết khi nào cần rời đi — Nữ Hoàng Gậy không rời đi vì yếu đuối mà vì bà biết giá trị của mình đủ để không ở lại nơi không xứng đáng; sự ra đi của bà là hành động tự trọng và sức mạnh.", en: "Queen of Wands and Eight of Cups: confident fire knowing when to leave — the Queen of Wands does not leave from weakness but because she knows her worth enough not to stay where she is not valued; her departure is an act of self-respect and strength." },
  "34_44": { vi: "Nữ Hoàng Gậy và Chín Cốc: hai năng lượng sung mãn — lửa rực rỡ và nước thỏa mãn; khi hai nguồn năng lượng đầy đủ này gặp nhau, không ai cần gì từ người kia mà cả hai đơn giản là tận hưởng sự hiện diện của nhau trong sự phong phú và niềm vui.", en: "Queen of Wands and Nine of Cups: two abundant energies — radiant fire and satisfied water; when these two full energies meet, neither needing anything from the other, both simply enjoying each other's presence in abundance and joy." },
  "34_45": { vi: "Nữ Hoàng Gậy và Mười Cốc: ngọn lửa rực rỡ và gia đình hạnh phúc — Nữ Hoàng Gậy mang sức sống và niềm đam mê vào không gian tình yêu và hài hòa của nước; sự kết hợp này tạo ra một cuộc sống gia đình không chỉ ổn định mà còn rực rỡ và đầy cảm hứng.", en: "Queen of Wands and Ten of Cups: radiant fire and the happy family — the Queen of Wands bringing vitality and passion into water's space of love and harmony; this combination creating a family life that is not merely stable but brilliant and inspiring." },
  "34_46": { vi: "Nữ Hoàng Gậy và Trang Bị Cốc: nữ hoàng khuyến khích người trẻ sáng tạo — lửa tự tin nhìn thấy tiềm năng trong tâm hồn nhạy cảm và sáng tạo của nước; Nữ Hoàng Gậy biết cách nuôi dưỡng tài năng đang nảy sinh mà không áp đặt con đường của mình lên nó.", en: "Queen of Wands and Page of Cups: the queen encouraging the young creative — confident fire seeing the potential in water's sensitive and creative soul; the Queen of Wands knowing how to nurture emerging talent without imposing her own path upon it." },
  "34_47": { vi: "Nữ Hoàng Gậy và Kỵ Sĩ Cốc: lửa rực rỡ và kỵ sĩ lãng mạn — cả hai đều có sức quyến rũ riêng và khi gặp nhau, sức hút có thể rất mạnh; nhưng đây cũng là lời nhắc rằng sự đam mê và lãng mạn chỉ đơn thuần là không đủ — chiều sâu và cam kết mới là điều tạo nên tình yêu bền lâu.", en: "Queen of Wands and Knight of Cups: radiant fire and the romantic knight — both possessing their own magnetism and when they meet the attraction can be powerful; but also a reminder that passion and romance alone are not enough — depth and commitment are what create lasting love." },
  "34_48": { vi: "Nữ Hoàng Gậy và Nữ Hoàng Cốc: hai nữ hoàng của hai nguyên tố — lửa và nước mỗi người là bậc thầy về vương quốc của mình; khi họ gặp nhau, đây là cuộc gặp gỡ của hai loại sức mạnh khác nhau nhưng bình đẳng — sự tự tin rực rỡ của lửa và sự từ bi sâu thẳm của nước.", en: "Queen of Wands and Queen of Cups: two queens of two elements — fire and water each mastering their own realm; when they meet, this is an encounter of two different but equal kinds of power — fire's brilliant confidence and water's deep compassion." },
  "34_49": { vi: "Nữ Hoàng Gậy và Vua Cốc: lửa rực rỡ và nước thành thạo — cả hai đều là những người lãnh đạo đã trưởng thành đủ để nhận ra sức mạnh trong sự khác biệt; Nữ Hoàng Gậy đưa ra đam mê và hành động trong khi Vua Cốc cung cấp chiều sâu cảm xúc và sự khôn ngoan, cùng nhau tạo nên sự hoàn chỉnh.", en: "Queen of Wands and King of Cups: radiant fire and mastered water — both mature leaders who have grown enough to recognize strength in difference; the Queen of Wands bringing passion and action while the King of Cups offers emotional depth and wisdom, together creating wholeness." },
  "35_36": { vi: "Vua Gậy và Át Cốc: tầm nhìn lớn chào đón tình yêu mới — lửa lãnh đạo không sợ cảm xúc mới mà đón nhận nó như nguồn lực; Vua Gậy biết rằng trái tim mở không phải là điểm yếu mà là sức mạnh dẫn đường cho những ai dám yêu và tạo ra.", en: "King of Wands and Ace of Cups: great vision welcoming new love — leading fire not fearing new emotion but receiving it as a resource; the King of Wands knowing that an open heart is not weakness but the guiding strength for those who dare to love and create." },
  "35_37": { vi: "Vua Gậy và Hai Cốc: nhà lãnh đạo trong mối quan hệ bình đẳng — Vua Gậy học rằng lãnh đạo tốt nhất không phải là cai trị mà là đối tác; sự kết nối của nước không yêu cầu lửa từ bỏ tầm nhìn mà mời lửa chia sẻ nó với người có thể thực sự hiểu.", en: "King of Wands and Two of Cups: the leader in equal partnership — the King of Wands learning that the best leadership is not ruling but partnering; water's connection not requiring fire to abandon its vision but inviting fire to share it with someone who can truly understand." },
  "35_38": { vi: "Vua Gậy và Ba Cốc: nhà lãnh đạo hào phóng trong lễ hội — Vua Gậy cung cấp năng lượng và sự hào phóng cho buổi ăn mừng của nước; lãnh đạo tốt biết khi nào cần mở cửa và ăn mừng với cộng đồng của mình, không chỉ khi làm việc mà còn khi vui chơi.", en: "King of Wands and Three of Cups: the generous leader in celebration — the King of Wands bringing energy and generosity to water's celebration; good leadership knowing when to open the doors and celebrate with its community, not only in work but also in joy." },
  "35_39": { vi: "Vua Gậy và Bốn Cốc: nhà lãnh đạo quyết đoán gặp sự rút lui — Vua Gậy có thể không hiểu tại sao nước rút lui, nhưng lãnh đạo khôn ngoan biết tôn trọng không gian người khác cần để xử lý và tìm lại sự rõ ràng của mình.", en: "King of Wands and Four of Cups: decisive leader meeting withdrawal — the King of Wands may not understand why water retreats, but wise leadership knows to respect the space others need to process and rediscover their own clarity." },
  "35_40": { vi: "Vua Gậy và Năm Cốc: sức mạnh lãnh đạo trong mất mát — Vua Gậy không giả vờ mất mát không tồn tại mà đứng với nỗi đau trong phẩm giá và sức mạnh; bài học của nhà lãnh đạo thực sự không phải là không bao giờ ngã mà là đứng lên sau khi ngã với sự duyên dáng.", en: "King of Wands and Five of Cups: leadership strength in loss — the King of Wands does not pretend loss does not exist but stands with pain in dignity and strength; the true leader's lesson is not never falling but rising after falling with grace." },
  "35_41": { vi: "Vua Gậy và Sáu Cốc: nhà lãnh đạo nhớ về nguồn gốc — Vua Gậy biết tầm nhìn của mình không từ trên trời rơi xuống mà được hình thành từ những kỷ niệm và nền tảng của tuổi thơ; sự kết nối với nguồn gốc là điều giúp nhà lãnh đạo lớn tiếp tục đứng vững.", en: "King of Wands and Six of Cups: the leader remembering origins — the King of Wands knowing his vision did not fall from the sky but was shaped by memories and the foundations of childhood; connection to origins is what helps the great leader continue standing firm." },
  "35_42": { vi: "Vua Gậy và Bảy Cốc: tầm nhìn lớn nhìn xuyên qua ảo tưởng — Vua Gậy không bị lung lay bởi những lựa chọn hấp dẫn mà không thực tế của nước; lãnh đạo với tầm nhìn rõ ràng biết phân biệt giữa những điều thực sự quan trọng và những điều chỉ trông có vẻ hấp dẫn.", en: "King of Wands and Seven of Cups: great vision seeing through illusion — the King of Wands not swayed by water's alluring but impractical options; leadership with clear vision knowing how to distinguish between what truly matters and what merely appears attractive." },
  "35_43": { vi: "Vua Gậy và Tám Cốc: nhà lãnh đạo ra quyết định dứt khoát — Vua Gậy biết khi nào cần tiến lên và khi nào cần rời đi; quyết định rời bỏ điều không còn phục vụ tầm nhìn là một trong những điều khó khăn nhất nhưng cần thiết nhất mà nhà lãnh đạo thực sự phải làm.", en: "King of Wands and Eight of Cups: the leader making the decisive departure — the King of Wands knowing when to press forward and when to leave; the decision to walk away from what no longer serves the vision is one of the hardest but most necessary things a true leader must do." },
  "35_44": { vi: "Vua Gậy và Chín Cốc: nhà lãnh đạo và sự mãn nguyện — Vua Gậy biết rằng tầm nhìn không phải là để chạy mãi mãi mà là để đạt đến điểm khi nhìn lại tất cả và cảm thấy thỏa mãn; khi lửa và nước cùng nhau ở sự mãn nguyện, đó là điểm đỉnh của cả hai.", en: "King of Wands and Nine of Cups: the leader and contentment — the King of Wands knowing that vision is not to run forever but to reach the point of looking back at all and feeling satisfied; when fire and water together reach contentment, that is the apex of both." },
  "35_45": { vi: "Vua Gậy và Mười Cốc: nhà lãnh đạo lớn và gia đình hạnh phúc — Vua Gậy xây dựng không chỉ đế chế bên ngoài mà cả vương quốc bên trong gia đình; tất cả tầm nhìn và sức mạnh của lửa cuối cùng có ý nghĩa nhất khi được chia sẻ với những người mình yêu thương nhất.", en: "King of Wands and Ten of Cups: the great leader and the happy family — the King of Wands building not only an external empire but the kingdom within the family; all fire's vision and strength ultimately means the most when shared with those one loves most." },
  "35_46": { vi: "Vua Gậy và Trang Bị Cốc: nhà lãnh đạo và người học trò — Vua Gậy nhìn thấy tài năng trong tâm hồn trẻ tuổi và nhạy cảm của nước; lãnh đạo tốt biết cách nuôi dưỡng điều mình chưa từng có bản thân — chiều sâu cảm xúc và sự tò mò sáng tạo.", en: "King of Wands and Page of Cups: the leader and the apprentice — the King of Wands seeing talent in water's young and sensitive soul; good leadership knowing how to nurture what one has not always possessed oneself — emotional depth and creative curiosity." },
  "35_47": { vi: "Vua Gậy và Kỵ Sĩ Cốc: nhà lãnh đạo lớn và kỵ sĩ lãng mạn — Vua Gậy nhìn thấy sự nhiệt tình của kỵ sĩ nước và nhớ lại khi mình còn như vậy; không phán xét mà hướng dẫn, lửa lớn tuổi có thể giúp lửa trẻ tuổi hướng lãng mạn của mình vào mục đích có ý nghĩa.", en: "King of Wands and Knight of Cups: the great leader and the romantic rider — the King of Wands seeing water knight's enthusiasm and remembering when he was the same; not judging but guiding, mature fire can help younger fire channel its romance into meaningful purpose." },
  "35_48": { vi: "Vua Gậy và Nữ Hoàng Cốc: vua lửa và nữ hoàng nước — hai bậc thầy của hai vương quốc; một cai trị bằng tầm nhìn và hành động, người kia cai trị bằng từ bi và chiều sâu; khi cả hai làm việc cùng nhau, không gì là không thể đạt được cả về thế giới bên ngoài và bên trong.", en: "King of Wands and Queen of Cups: king of fire and queen of water — two masters of two realms; one governing by vision and action, the other by compassion and depth; when both work together, nothing is beyond reach in both the outer and inner world." },
  "35_49": { vi: "Vua Gậy và Vua Cốc: hai vị vua, hai nguyên tố — lửa và nước ở đỉnh cao của sự trưởng thành; Vua Gậy mang tầm nhìn, quyết tâm và sức mạnh hành động trong khi Vua Cốc mang sự khôn ngoan cảm xúc và sự bình tĩnh sâu sắc; cùng nhau họ thể hiện lãnh đạo hoàn chỉnh nhất.", en: "King of Wands and King of Cups: two kings, two elements — fire and water at the apex of maturity; the King of Wands bringing vision, determination and strength of action while the King of Cups brings emotional wisdom and profound calm; together they embody the most complete form of leadership." },
  // ── Tier 5b-1: Wands × Swords, fire×air (Wands 22–28 × Swords 50–63, 98 pairs) ──
  "22_50": { vi: "Át Gậy và Át Kiếm: hai khởi đầu của lửa và không khí — cảm hứng thuần khiết gặp sự sáng suốt thuần khiết; khi ý tưởng sắc bén và đam mê nguyên thủy kết hợp từ điểm xuất phát, tiềm năng trí tuệ và sáng tạo đạt đến mức không giới hạn.", en: "Ace of Wands and Ace of Swords: two beginnings of fire and air — pure inspiration meeting pure clarity; when sharp ideas and primal passion combine from their starting point, intellectual and creative potential reaches an unlimited level." },
  "22_51": { vi: "Át Gậy và Hai Kiếm: cảm hứng mới gặp sự bế tắc — lửa muốn hành động nhưng không khí đang do dự và chặn hướng nhìn; đây là lời nhắc rằng đôi khi ngay cả nguồn cảm hứng mạnh mẽ nhất cũng cần sự rõ ràng trong quyết định trước khi có thể tiến lên.", en: "Ace of Wands and Two of Swords: new inspiration meeting stalemate — fire wanting to act but air hesitating and blocking the view; a reminder that even the strongest inspiration sometimes needs clarity in decision before it can move forward." },
  "22_52": { vi: "Át Gậy và Ba Kiếm: ngọn lửa mới giữa nỗi đau — cảm hứng đến ngay khi trái tim đang rỉ máu; điều này không phải là sự vô cảm mà là bằng chứng rằng sức sáng tạo có thể nảy sinh từ những khoảnh khắc tối nhất và tạo ra điều gì đó có ý nghĩa từ đau thương.", en: "Ace of Wands and Three of Swords: new flame amid heartbreak — inspiration arriving right when the heart is bleeding; this is not callousness but proof that creative force can arise from the darkest moments and make something meaningful from pain." },
  "22_53": { vi: "Át Gậy và Bốn Kiếm: ngọn lửa cần sự nghỉ ngơi — cảm hứng mới đến ngay khi không khí đang phục hồi; đây là sự nhắc nhở rằng không phải lúc nào cũng nên lao vào hành động ngay lập tức — đôi khi sự chuẩn bị và nghỉ ngơi là nền tảng cho cảm hứng được thực hiện trọn vẹn.", en: "Ace of Wands and Four of Swords: the new flame needing rest — fresh inspiration arriving just as air is recovering; a reminder that one should not always rush into action immediately — sometimes preparation and rest are the foundation for inspiration to be fully realized." },
  "22_54": { vi: "Át Gậy và Năm Kiếm: cảm hứng trong xung đột — lửa mới bước vào không gian đã bị ô nhiễm bởi chiến thắng rỗng tuếch và sự phản bội; điều quan trọng là lửa giữ được sự trong sáng của mình và không để bị lôi cuốn vào những cuộc tranh cãi không đáng.", en: "Ace of Wands and Five of Swords: inspiration amid conflict — new fire stepping into a space already contaminated by hollow victory and betrayal; what matters is that fire keeps its purity and does not get drawn into unworthy battles." },
  "22_55": { vi: "Át Gậy và Sáu Kiếm: cảm hứng dẫn đường qua chuyển tiếp — không khí đang di chuyển đến bờ bình yên hơn và lửa thắp sáng con đường đó; khi ý chí mới và sự chuyển mình nhẹ nhàng cùng xuất hiện, hành trình đến nơi tốt hơn trở nên có phương hướng và đầy hy vọng.", en: "Ace of Wands and Six of Swords: inspiration lighting the way through transition — air moving toward calmer shores and fire illuminating that path; when fresh will and gentle transition appear together, the journey to a better place gains direction and hope." },
  "22_56": { vi: "Át Gậy và Bảy Kiếm: cảm hứng ngây thơ gặp mưu kế — lửa mới chưa biết rằng trong bóng tối đang có chiến lược ẩn; đây là lời cảnh báo để không để sự trong sáng của cảm hứng bị lợi dụng bởi những ai di chuyển với dụng ý che giấu.", en: "Ace of Wands and Seven of Swords: innocent inspiration meeting cunning — new fire not yet knowing that hidden strategies lurk in the shadows; a warning not to let the purity of inspiration be taken advantage of by those who move with concealed intentions." },
  "22_57": { vi: "Át Gậy và Tám Kiếm: ngọn lửa gặp sự trói buộc — cảm hứng bùng lên nhưng không khí bị giam cầm trong chính những giới hạn do mình tạo ra; điều quan trọng là nhận ra rằng lửa không thể bị giam cầm mãi mãi — ánh sáng của nó cuối cùng sẽ cho thấy cách thoát ra.", en: "Ace of Wands and Eight of Swords: the new flame meeting bondage — inspiration igniting but air imprisoned in self-created limitations; what matters is recognizing that fire cannot be truly caged — its light will eventually reveal the way out." },
  "22_58": { vi: "Át Gậy và Chín Kiếm: ánh sáng trong đêm tối nhất — cảm hứng đến vào lúc không khí đang chìm trong lo âu và ác mộng; đây không phải là ngẫu nhiên mà là bằng chứng rằng tiềm năng sáng tạo luôn tồn tại ngay cả trong những khoảnh khắc đen tối nhất của tâm trí.", en: "Ace of Wands and Nine of Swords: light in the darkest night — inspiration arriving just as air is drowning in anxiety and nightmares; not coincidence but proof that creative potential always exists even in the mind's darkest moments." },
  "22_59": { vi: "Át Gậy và Mười Kiếm: khởi đầu từ đống đổ nát — lửa bừng sáng ngay trên nơi không khí vừa chạm đáy; đây là một trong những sự kết hợp mạnh mẽ nhất về sự phục sinh, khi sự kết thúc hoàn toàn tạo ra không gian trống rỗng hoàn hảo để điều gì đó hoàn toàn mới ra đời.", en: "Ace of Wands and Ten of Swords: beginning from the ruins — fire blazing right where air has just bottomed out; one of the most powerful combinations of rebirth, when complete ending creates the perfect empty space for something entirely new to be born." },
  "22_60": { vi: "Át Gậy và Trang Bị Kiếm: hai tâm hồn trẻ, hai nguyên tố — cảm hứng mới và sự tò mò trí tuệ mới; khi lửa và không khí gặp nhau ở điểm khởi đầu của cả hai, năng lượng tạo ra là điện khí và đầy tiềm năng nhưng cần sự định hướng.", en: "Ace of Wands and Page of Swords: two young souls, two elements — fresh inspiration and fresh intellectual curiosity; when fire and air meet at both their starting points, the energy generated is electric and full of potential but needs direction." },
  "22_61": { vi: "Át Gậy và Kỵ Sĩ Kiếm: ngọn lửa thuần khiết và lưỡi kiếm nhanh — cảm hứng nguyên thủy gặp trí tuệ sắc bén đang lao về phía trước; sự kết hợp này có thể tạo ra sức mạnh sáng tạo chưa từng có hoặc sự phá hủy hỗn loạn tùy thuộc vào hướng mà cả hai cùng hướng tới.", en: "Ace of Wands and Knight of Swords: pure flame and swift blade — primal inspiration meeting sharp intellect charging forward; this combination can create unprecedented creative force or chaotic destruction depending on the direction both are pointed toward." },
  "22_62": { vi: "Át Gậy và Nữ Hoàng Kiếm: cảm hứng gặp sự sáng suốt — lửa mới nảy sinh và không khí với tâm trí sắc bén nhìn thấy rõ ràng tiềm năng và cả rủi ro; Nữ Hoàng Kiếm không dập tắt ngọn lửa mà giúp nó hiểu hướng đi đúng nhất để đạt đến mục tiêu.", en: "Ace of Wands and Queen of Swords: inspiration meeting discernment — new fire arising and air's sharp mind seeing clearly both the potential and the risk; the Queen of Swords does not extinguish the flame but helps it understand the best direction to reach its goal." },
  "22_63": { vi: "Át Gậy và Vua Kiếm: cảm hứng gặp thẩm quyền trí tuệ — lửa thuần khiết đứng trước không khí với sự phán xét sắc sảo và quyền lực; khi nhà lãnh đạo logic nhận ra tầm quan trọng của cảm hứng nguyên thủy, lửa được trao con đường và mục đích rõ ràng để cháy.", en: "Ace of Wands and King of Swords: inspiration meeting intellectual authority — pure fire standing before air with sharp judgment and power; when the logical leader recognizes the importance of primal inspiration, fire is given a clear path and purpose to burn." },
  "23_50": { vi: "Hai Gậy và Át Kiếm: tầm nhìn và sự sáng suốt mới — lửa đang lên kế hoạch với đôi mắt nhìn ra chân trời và không khí cung cấp một ý tưởng sắc bén để định hướng tầm nhìn đó; đây là sự kết hợp lý tưởng của hoạch định và sự rõ ràng vừa xuất hiện đúng lúc.", en: "Two of Wands and Ace of Swords: vision and new clarity — fire planning with eyes on the horizon and air offering a sharp idea to give that vision direction; an ideal combination of planning and clarity arriving at exactly the right moment." },
  "23_51": { vi: "Hai Gậy và Hai Kiếm: tầm nhìn gặp sự lưỡng lự — lửa đang đứng với thế giới trong tay nhưng không khí đang nhắm mắt lại và từ chối nhìn; sự kết hợp này nhắc nhở rằng tầm nhìn vĩ đại nhất cũng không thể tiến lên nếu quyết định bị trì hoãn vô tận.", en: "Two of Wands and Two of Swords: vision meeting hesitation — fire standing with the world in hand but air closing its eyes and refusing to look; this combination reminds that even the greatest vision cannot move forward if decisions are endlessly deferred." },
  "23_52": { vi: "Hai Gậy và Ba Kiếm: kế hoạch táo bạo qua nỗi đau — lửa nhìn về phía tương lai ngay cả khi không khí đang mang vết thương; đây là sự nhắc nhở rằng tầm nhìn dài hạn đôi khi là điều duy nhất giúp chúng ta tiếp tục bước đi khi hiện tại quá đau đớn.", en: "Two of Wands and Three of Swords: bold plans through pain — fire looking toward the future even as air carries wounds; a reminder that long-term vision is sometimes the only thing that keeps us walking when the present is too painful." },
  "23_53": { vi: "Hai Gậy và Bốn Kiếm: hoạch định trong giai đoạn nghỉ ngơi — lửa muốn lập kế hoạch ngay lập tức nhưng không khí đang phục hồi và cần tĩnh lặng; đây là bài học về sự kiên nhẫn — kế hoạch tốt nhất đôi khi được hình thành trong trạng thái nghỉ ngơi có ý thức.", en: "Two of Wands and Four of Swords: planning during recovery — fire wanting to plan immediately but air recovering and needing silence; a lesson in patience — the best plans are sometimes formed in conscious stillness." },
  "23_54": { vi: "Hai Gậy và Năm Kiếm: tầm nhìn giữa xung đột — lửa đang lên kế hoạch cho tương lai trong khi không khí đang bị ô nhiễm bởi tranh cãi và chiến thắng rỗng tuếch; đây là thách thức giữ sự tập trung vào tầm nhìn dài hạn khi môi trường xung quanh đang đầy hỗn loạn.", en: "Two of Wands and Five of Swords: vision amid conflict — fire planning for the future while air is contaminated by disputes and hollow victories; the challenge of maintaining focus on long-term vision when the surrounding environment is full of chaos." },
  "23_55": { vi: "Hai Gậy và Sáu Kiếm: kế hoạch dẫn đến bình yên — lửa đang định hướng hành trình và không khí đang di chuyển đến nơi tĩnh lặng hơn; khi tầm nhìn của lửa và sự chuyển dịch bình yên của không khí cùng nhau, hành trình có thể được thực hiện với cả mục đích và sự nhẹ nhàng.", en: "Two of Wands and Six of Swords: plans leading toward peace — fire charting the journey and air moving toward quieter shores; when fire's vision and air's peaceful transition work together, the journey can be undertaken with both purpose and gentleness." },
  "23_56": { vi: "Hai Gậy và Bảy Kiếm: chiến lược gặp chiến lược — lửa lên kế hoạch công khai trong khi không khí hành động trong bóng tối; đây là sự đối đầu giữa hai loại mưu lược và lời nhắc rằng kế hoạch trong sáng không phải lúc nào cũng chiến thắng trước chiến thuật không minh bạch.", en: "Two of Wands and Seven of Swords: strategy meeting strategy — fire planning openly while air acts in shadow; a confrontation between two kinds of cunning and a reminder that transparent planning does not always prevail against opaque tactics." },
  "23_57": { vi: "Hai Gậy và Tám Kiếm: tầm nhìn rộng lớn bị kiềm hãm — lửa đứng trên ngọn tháp nhìn ra đại dương trong khi không khí bị trói buộc và bịt mắt; sự tương phản này nhắc nhở rằng những kế hoạch vĩ đại nhất không thể thực hiện được khi người thực thi không thể nhìn thấy hoặc di chuyển tự do.", en: "Two of Wands and Eight of Swords: grand vision constrained — fire standing on the tower looking at the ocean while air is bound and blindfolded; this contrast reminds that even the grandest plans cannot be executed when the one executing them cannot see or move freely." },
  "23_58": { vi: "Hai Gậy và Chín Kiếm: kế hoạch táo bạo và lo âu — lửa nhìn về phía trước nhưng không khí tỉnh dậy lúc nửa đêm với nỗi sợ hãi; đây là lời nhắc rằng tầm nhìn và lo lắng không loại trừ nhau — người dám mơ lớn cũng thường là người mang lo âu lớn nhất.", en: "Two of Wands and Nine of Swords: bold plans and anxiety — fire looking forward but air waking at midnight with fear; a reminder that vision and worry are not mutually exclusive — those who dare to dream big are often those who carry the greatest anxiety." },
  "23_59": { vi: "Hai Gậy và Mười Kiếm: kế hoạch sau thất bại hoàn toàn — lửa vẫn giữ thế giới trong tay kể cả khi không khí vừa bị đánh ngã; đây là sức mạnh của tầm nhìn — nó tồn tại ngay cả sau thất bại hoàn toàn và là thứ đầu tiên giúp người ta đứng dậy.", en: "Two of Wands and Ten of Swords: plans after total defeat — fire still holding the world in hand even as air has just been struck down; this is the strength of vision — it persists even after complete failure and is the first thing that helps one rise again." },
  "23_60": { vi: "Hai Gậy và Trang Bị Kiếm: nhà hoạch định và người quan sát sắc sảo — lửa có tầm nhìn dài hạn và không khí trẻ tuổi có con mắt tinh nhanh nhận thấy những điều người khác bỏ qua; đây là sự hợp tác tốt — tầm nhìn được bổ sung bởi sự quan sát chi tiết.", en: "Two of Wands and Page of Swords: the planner and the sharp observer — fire holding long-term vision and young air with quick eyes noticing what others miss; a good collaboration — vision supplemented by detailed observation." },
  "23_61": { vi: "Hai Gậy và Kỵ Sĩ Kiếm: tầm nhìn và hành động nhanh — lửa lên kế hoạch và không khí lao về phía trước trước khi kế hoạch được hoàn thiện; đây là năng lượng mạnh mẽ nhưng cũng là rủi ro — không phải lúc nào sự nhanh nhẹn của không khí cũng chờ đợi chiều sâu của lửa.", en: "Two of Wands and Knight of Swords: vision and swift action — fire planning and air charging forward before the plan is complete; powerful energy but also a risk — air's quickness does not always wait for fire's depth." },
  "23_62": { vi: "Hai Gậy và Nữ Hoàng Kiếm: hoạch định gặp sự phân tích sắc bén — Nữ Hoàng Kiếm nhìn thẳng vào kế hoạch của lửa và chỉ ra chính xác điều gì thiếu sót; đây không phải là sự chỉ trích phá hoại mà là sự hỗ trợ cần thiết để tầm nhìn lớn trở thành thực tế đứng vững.", en: "Two of Wands and Queen of Swords: planning meeting sharp analysis — the Queen of Swords looking directly at fire's plan and pointing out exactly what is lacking; not destructive criticism but the necessary support for great vision to become standing reality." },
  "23_63": { vi: "Hai Gậy và Vua Kiếm: tầm nhìn lửa và thẩm quyền không khí — lửa đang nhìn ra chân trời và không khí đang xét xử kế hoạch từ ngai vị trí tuệ; khi cả hai cùng hướng tới mục tiêu chung, kết quả là một chiến lược không chỉ táo bạo mà còn được xây dựng vững chắc.", en: "Two of Wands and King of Swords: fire's vision and air's authority — fire looking toward the horizon and air judging the plan from its throne of intellect; when both are aimed at a common goal, the result is a strategy that is not only bold but solidly built." },
  "24_50": { vi: "Ba Gậy và Át Kiếm: sự mở rộng và sự rõ ràng mới — lửa đang chờ đợi kết quả của những gì mình đã gieo trồng và không khí mang đến một ý tưởng sắc bén để định hướng việc tiếp theo; khi tầm nhìn xa và tư duy sắc nét cùng nhau, con đường phía trước trở nên rõ ràng đặc biệt.", en: "Three of Wands and Ace of Swords: expansion and new clarity — fire waiting for the results of what it has sown and air bringing a sharp idea to direct what comes next; when foresight and keen thinking combine, the path ahead becomes especially clear." },
  "24_51": { vi: "Ba Gậy và Hai Kiếm: tầm nhìn xa bị chặn bởi lưỡng lự — lửa đang trông ngóng những con tàu của mình trở về nhưng không khí không thể đưa ra quyết định về bước tiếp theo; đây là sự căng thẳng giữa sự kiên nhẫn chiến lược và sự do dự làm chậm mọi sự tiến bộ.", en: "Three of Wands and Two of Swords: far-seeing vision blocked by hesitation — fire watching for its ships to return but air unable to decide the next step; tension between strategic patience and hesitation slowing all progress." },
  "24_52": { vi: "Ba Gậy và Ba Kiếm: mở rộng qua nỗi đau — lửa đang nhìn về phía tương lai ngay cả khi không khí mang ba vết thương sâu; đây là bằng chứng rằng tầm nhìn không biến mất với đau thương mà đôi khi trở nên mạnh mẽ hơn khi đã hiểu được cái giá của ước mơ.", en: "Three of Wands and Three of Swords: expansion through pain — fire looking toward the future even as air carries three deep wounds; proof that vision does not disappear with heartbreak but sometimes grows stronger after understanding the price of dreams." },
  "24_53": { vi: "Ba Gậy và Bốn Kiếm: doanh nghiệp dừng lại để phục hồi — lửa đang chờ đợi và không khí đang nghỉ ngơi sau giai đoạn vất vả; đây không phải là thất bại mà là sự khôn ngoan của việc biết rằng con đường dài nhất không thể đi hết trong một hơi thở mà không cần dừng lại.", en: "Three of Wands and Four of Swords: enterprise pausing for recovery — fire waiting and air resting after a difficult period; not failure but the wisdom of knowing the longest journey cannot be completed in one breath without stopping to rest." },
  "24_54": { vi: "Ba Gậy và Năm Kiếm: mở rộng gặp xung đột — lửa đang gửi đi những con tàu trong khi không khí đang ô nhiễm bởi những kẻ chiến thắng rỗng tuếch; đây là lời cảnh báo rằng không phải tất cả những người bạn gặp trên đường mở rộng đều đang hành động vì lợi ích chung.", en: "Three of Wands and Five of Swords: expansion meeting conflict — fire sending its ships while air is contaminated by hollow winners; a warning that not all those encountered on the path of expansion are acting in good faith." },
  "24_55": { vi: "Ba Gậy và Sáu Kiếm: tầm nhìn dẫn đến cuộc hành trình bình yên — lửa biết những con tàu sẽ đến bến bờ nào và không khí đang nhẹ nhàng trôi đến đó; khi kế hoạch chiến lược và sự chuyển dịch thuận lợi cùng một hướng, hành trình trở nên gần như không thể cản trở.", en: "Three of Wands and Six of Swords: vision leading to a peaceful journey — fire knowing which shore its ships will reach and air gently drifting there; when strategic planning and favorable transition point the same direction, the journey becomes nearly unstoppable." },
  "24_56": { vi: "Ba Gậy và Bảy Kiếm: mở rộng gặp âm mưu — trong khi lửa nhìn chân trời rộng lớn, không khí đang lén lút lấy đi những gì chưa thuộc về mình; đây là lời nhắc tỉnh táo rằng khi đang mở rộng và chú tâm vào tương lai, cần đủ chú ý để bảo vệ những gì đang có.", en: "Three of Wands and Seven of Swords: expansion meeting scheming — while fire watches the broad horizon, air is stealthily taking what is not yet its own; a sobering reminder that while expanding and focused on the future, one needs enough attention to protect what is already in hand." },
  "24_57": { vi: "Ba Gậy và Tám Kiếm: tầm nhìn gặp sự trói buộc — lửa đang trông ngóng những con tàu tự do của mình trong khi không khí bị giam cầm trong những giới hạn tự tạo; sự tương phản này chỉ ra rằng đôi khi người nhìn thấy rõ ràng nhất từ xa cũng là người chưa thoát khỏi giới hạn của mình.", en: "Three of Wands and Eight of Swords: vision meeting bondage — fire watching its free ships while air is trapped in self-made limitations; this contrast reveals that sometimes the one who sees most clearly from afar is also the one who has not yet broken free from their own boundaries." },
  "24_58": { vi: "Ba Gậy và Chín Kiếm: tầm nhìn xa và lo âu đêm khuya — lửa đang đứng vững với kế hoạch dài hạn trong khi không khí đang bị kéo xuống bởi những nỗi sợ hãi trong bóng tối; đây là lời nhắc rằng ngay cả những người có tầm nhìn sáng nhất cũng có thể bị ám ảnh bởi những lo lắng khi trời tối.", en: "Three of Wands and Nine of Swords: far-seeing vision and late-night anxiety — fire standing firm with long-term plans while air is pulled down by fears in the dark; even those with the brightest vision can be haunted by worries when the light fades." },
  "24_59": { vi: "Ba Gậy và Mười Kiếm: tầm nhìn sống sót sau sự sụp đổ — lửa vẫn chờ đợi những con tàu ngay cả khi không khí vừa chạm đáy; điều này nhắc nhở rằng chiến lược dài hạn là thứ vẫn còn đó sau khi mọi thứ khác sụp đổ và là nền tảng của sự tái thiết.", en: "Three of Wands and Ten of Swords: vision surviving collapse — fire still watching for its ships even as air has just bottomed out; long-term strategy is what remains standing after everything else collapses and is the foundation for rebuilding." },
  "24_60": { vi: "Ba Gậy và Trang Bị Kiếm: tầm nhìn dài hạn và sự quan sát nhanh nhạy — lửa trông ngóng chân trời còn lại và không khí trẻ tuổi để ý những chi tiết mà người đứng xa có thể bỏ qua; sự kết hợp giữa quan điểm chiến lược và sự tỉnh táo chi tiết là bộ đôi lý tưởng.", en: "Three of Wands and Page of Swords: long-range vision and sharp observation — fire watching the far horizon and young air noticing details that someone standing far away might miss; the combination of strategic perspective and detailed alertness is an ideal pairing." },
  "24_61": { vi: "Ba Gậy và Kỵ Sĩ Kiếm: tầm nhìn xa và sức mạnh nhanh nhẹn — lửa đứng yên và trông xa còn không khí lao về phía trước với lưỡi kiếm rút ra; khi tầm nhìn chiến lược được hỗ trợ bởi hành động tốc độ cao, điều không thể đạt được một mình trở thành có thể.", en: "Three of Wands and Knight of Swords: far-reaching vision and swift force — fire standing still and watching afar while air charges forward with blade drawn; when strategic vision is backed by high-speed action, what was impossible alone becomes achievable." },
  "24_62": { vi: "Ba Gậy và Nữ Hoàng Kiếm: tầm nhìn được kiểm tra bởi sự sáng suốt — lửa đang nhìn ra biển lớn và Nữ Hoàng Kiếm đang đánh giá mọi khía cạnh của kế hoạch đó; sự kết hợp này tạo ra chiến lược không chỉ có tầm nhìn mà còn được kiểm tra kỹ lưỡng và vững chắc.", en: "Three of Wands and Queen of Swords: vision tested by discernment — fire looking out to sea and the Queen of Swords evaluating every aspect of the plan; this combination creates strategy that is not only visionary but also rigorously tested and solid." },
  "24_63": { vi: "Ba Gậy và Vua Kiếm: doanh nghiệp lửa và thẩm quyền không khí — lửa đang xây dựng đế chế thương mại trong khi không khí cầm quyền bằng trí tuệ và pháp lý; sự hợp tác giữa hai nguyên tố này tạo ra những gì vừa có sức sáng tạo vừa có kết cấu vững bền nhất.", en: "Three of Wands and King of Swords: fire's enterprise and air's authority — fire building its commercial empire while air governs with intellect and law; collaboration between these two elements creates what is both most creatively inspired and most durably structured." },
  "25_50": { vi: "Bốn Gậy và Át Kiếm: lễ kỷ niệm và sự rõ ràng mới — lửa đang ăn mừng sự ổn định trong khi không khí mang đến một ý tưởng sắc bén mới; đây là thời điểm tốt để mở rộng — từ nền tảng bền vững và với sự rõ ràng về hướng đi tiếp theo.", en: "Four of Wands and Ace of Swords: celebration and new clarity — fire celebrating stability while air brings a fresh sharp idea; this is a good moment to expand — from a secure foundation and with clarity about the next direction." },
  "25_51": { vi: "Bốn Gậy và Hai Kiếm: mái ấm và sự lưỡng lự — lửa đã tạo ra nơi ổn định và ấm áp nhưng không khí vẫn chưa quyết định bước tiếp theo; đây là lời nhắc rằng sự ổn định của ngôi nhà không tự động giải quyết sự do dự trong tâm trí.", en: "Four of Wands and Two of Swords: home and hesitation — fire has created a stable warm place but air still cannot decide the next step; a reminder that the stability of home does not automatically resolve the hesitation of the mind." },
  "25_52": { vi: "Bốn Gậy và Ba Kiếm: lễ hội và nỗi đau nội tâm — lửa đang mời mọi người ăn mừng trong khi không khí đang mang vết thương riêng của mình; đây là sự nhắc nhở rằng không phải lúc nào những người có vẻ ngoài vui vẻ nhất cũng không có nỗi đau bên trong.", en: "Four of Wands and Three of Swords: celebration and inner pain — fire inviting everyone to celebrate while air carries its private wounds; a reminder that those who appear the most joyful on the outside do not always lack pain within." },
  "25_53": { vi: "Bốn Gậy và Bốn Kiếm: hai sự tĩnh lặng — lửa ổn định trong niềm vui và không khí ổn định trong sự nghỉ ngơi; cả hai số bốn này tạo ra một không gian hiếm có của sự bình yên thực sự, nơi cả hoạt động bên ngoài và bên trong đều được phép lắng xuống.", en: "Four of Wands and Four of Swords: two stillnesses — fire stable in joy and air stable in rest; these two fours create a rare space of genuine peace, where both outer and inner activity are allowed to settle." },
  "25_54": { vi: "Bốn Gậy và Năm Kiếm: sự ổn định bị đe dọa bởi xung đột — lửa đã xây dựng nơi ấm áp nhưng không khí đang mang theo hậu quả của những trận chiến rỗng tuếch; đây là lời nhắc rằng không gian ổn định cần được bảo vệ khỏi những người mang năng lượng độc hại từ bên ngoài.", en: "Four of Wands and Five of Swords: stability threatened by conflict — fire has built a warm place but air is carrying the aftermath of hollow battles; a reminder that a stable space needs to be protected from those who bring toxic energy from outside." },
  "25_55": { vi: "Bốn Gậy và Sáu Kiếm: mái ấm và sự chuyển tiếp bình yên — lửa cung cấp nền tảng ổn định trong khi không khí nhẹ nhàng di chuyển đến bờ bình lặng hơn; đây là sự kết hợp của sự an toàn và sự phát triển, khi ngôi nhà vẫn là ngôi nhà dù người chủ của nó đang thay đổi.", en: "Four of Wands and Six of Swords: home and peaceful transition — fire providing the stable foundation while air gently moves to calmer shores; a combination of security and growth, when home remains home even as its owner is changing." },
  "25_56": { vi: "Bốn Gậy và Bảy Kiếm: cộng đồng và kẻ trộm trong đêm — lửa đang ăn mừng trong khi không khí đang lén lút mang đi điều không thuộc về mình; đây là lời cảnh báo rằng không gian ăn mừng cũng cần sự chú ý — kẻ cơ hội luôn có mặt ở những nơi mọi người đang không để ý.", en: "Four of Wands and Seven of Swords: community and the night thief — fire celebrating while air is sneaking away with what does not belong to it; a warning that celebratory spaces also need attention — opportunists are always present where people are not paying close attention." },
  "25_57": { vi: "Bốn Gậy và Tám Kiếm: cổng chào đón và người bị trói buộc — lửa đang ăn mừng sự tự do trong khi không khí không thể di chuyển; sự đối lập này nhắc nhở rằng đôi khi những người ở ngoài cổng đang chiến đấu với những xiềng xích mà chỉ họ mới có thể nhìn thấy.", en: "Four of Wands and Eight of Swords: the welcoming gate and the bound one — fire celebrating freedom while air cannot move; this opposition reminds that sometimes those standing outside the gate are fighting chains that only they can see." },
  "25_58": { vi: "Bốn Gậy và Chín Kiếm: lễ hội bên ngoài và lo âu bên trong — lửa đang mời mọi người đến ăn mừng nhưng không khí đang thức giấc lúc nửa đêm với nỗi sợ; sự tương phản này nhắc nhở rằng biểu hiện bên ngoài và trải nghiệm bên trong không phải lúc nào cũng khớp với nhau.", en: "Four of Wands and Nine of Swords: outer celebration and inner anxiety — fire inviting everyone to celebrate but air waking at midnight with fear; this contrast reminds that outer appearance and inner experience do not always match." },
  "25_59": { vi: "Bốn Gậy và Mười Kiếm: nền tảng vững chắc sau sự sụp đổ — lửa đã xây dựng không gian ổn định và không khí vừa chạm đáy; đây là sự kết hợp của hy vọng và thực tế — nền tảng vẫn còn đó sau thất bại và đó chính là điểm bắt đầu của sự tái thiết.", en: "Four of Wands and Ten of Swords: solid foundation after collapse — fire has built a stable space and air has just hit bottom; a combination of hope and reality — the foundation is still there after failure and that is exactly the starting point of rebuilding." },
  "25_60": { vi: "Bốn Gậy và Trang Bị Kiếm: mái ấm chào đón trí tò mò — lửa tạo ra không gian an toàn và không khí trẻ tuổi mang theo những câu hỏi và quan sát sắc bén; đây là sự kết hợp lý tưởng khi một nơi ổn định và ấm áp là không gian hoàn hảo cho trí tuệ trẻ trung phát triển.", en: "Four of Wands and Page of Swords: home welcoming curiosity — fire creating a safe space and young air bringing sharp questions and observations; an ideal combination when a stable warm place is the perfect space for youthful intellect to flourish." },
  "25_61": { vi: "Bốn Gậy và Kỵ Sĩ Kiếm: nền tảng và hành động nhanh — lửa đã tạo ra cơ sở ổn định và không khí đang lao về phía trước với tốc độ cao; đây là sự kết hợp tốt khi hành động quyết liệt xuất phát từ nơi an toàn thay vì từ sự hỗn loạn.", en: "Four of Wands and Knight of Swords: foundation and swift action — fire has created a stable base and air is charging forward at high speed; a good combination when decisive action comes from a place of security rather than from chaos." },
  "25_62": { vi: "Bốn Gậy và Nữ Hoàng Kiếm: sự ấm áp và sự rõ ràng — lửa tạo ra không gian ăn mừng và Nữ Hoàng Kiếm mang đến sự sắc bén và trung thực; đây là sự kết hợp của hai loại sức mạnh — sức ấm của cộng đồng và sự rõ ràng của tư duy — có thể tạo ra điều lâu bền.", en: "Four of Wands and Queen of Swords: warmth and clarity — fire creating a celebratory space and the Queen of Swords bringing sharpness and honesty; a combination of two kinds of strength — the warmth of community and the clarity of thought — that can create something lasting." },
  "25_63": { vi: "Bốn Gậy và Vua Kiếm: cộng đồng và thẩm quyền — lửa tạo ra nơi mọi người cùng tụ họp và không khí cai trị bằng pháp lý và trật tự; khi nền tảng cộng đồng và thẩm quyền trí tuệ cùng nhau, điều được tạo ra là một xã hội có tâm hồn lẫn cấu trúc.", en: "Four of Wands and King of Swords: community and authority — fire creating the place where people gather and air governing with law and order; when communal foundation and intellectual authority work together, what is created is a society with both soul and structure." },
  "26_50": { vi: "Năm Gậy và Át Kiếm: hỗn loạn và sự sáng suốt đột ngột — sự tranh cãi và cạnh tranh của lửa bị cắt ngang bởi một ý tưởng sắc bén của không khí; đôi khi sự rõ ràng đột ngột là điều duy nhất có thể chấm dứt sự hỗn loạn — một câu hỏi đúng có thể dừng mọi cuộc cãi vã.", en: "Five of Wands and Ace of Swords: chaos and sudden clarity — fire's conflict and competition cut through by air's sharp idea; sometimes sudden clarity is the only thing that can end chaos — the right question can stop any argument." },
  "26_51": { vi: "Năm Gậy và Hai Kiếm: xung đột bên ngoài và bế tắc bên trong — lửa đang chiến đấu với mọi người trong khi không khí không thể nhìn thấy rõ ràng để đưa ra quyết định; đây là sự kết hợp đặc biệt mệt mỏi khi cả ngoài lẫn trong đều bị bế tắc.", en: "Five of Wands and Two of Swords: external conflict and inner stalemate — fire fighting everyone while air cannot see clearly enough to decide; a particularly exhausting combination when both inside and outside are stuck." },
  "26_52": { vi: "Năm Gậy và Ba Kiếm: xung đột kép — lửa đang chiến đấu bên ngoài và không khí đang mang vết thương tình cảm sâu sắc; khi cả đấu tranh bên ngoài và nỗi đau bên trong cùng tồn tại, sự suy kiệt là không thể tránh khỏi nếu không tìm được cách giải phóng một trong hai.", en: "Five of Wands and Three of Swords: double conflict — fire fighting externally and air carrying deep emotional wounds; when both outer struggle and inner pain coexist, exhaustion is unavoidable if a way to release at least one is not found." },
  "26_53": { vi: "Năm Gậy và Bốn Kiếm: hỗn loạn cần nghỉ ngơi — lửa đang đánh nhau tứ phía trong khi không khí nhắc nhở rằng phục hồi không phải là sự yếu đuối mà là chiến thuật; đây là lời kêu gọi tạm dừng chiến đấu để lấy lại sức mạnh trước khi tiếp tục.", en: "Five of Wands and Four of Swords: chaos needing rest — fire fighting on all sides while air reminds that recovery is not weakness but strategy; a call to pause the fighting and regain strength before continuing." },
  "26_54": { vi: "Năm Gậy và Năm Kiếm: hai con năm — xung đột chồng xung đột — lửa tranh cãi và cạnh tranh trong khi không khí đang đấu tranh không công bằng; khi cả hai sự xung đột này gặp nhau, tốt nhất là thoát ra khỏi trận chiến hoàn toàn thay vì leo thang thêm.", en: "Five of Wands and Five of Swords: two fives — conflict upon conflict — fire arguing and competing while air fights unfairly; when both conflicts meet, the wisest move is to exit the battle entirely rather than escalate further." },
  "26_55": { vi: "Năm Gậy và Sáu Kiếm: từ hỗn loạn đến bình yên — lửa đang trong tình trạng hỗn độn và không khí đang dẫn đường ra khỏi nó; đây là sự kết hợp của vấn đề và giải pháp — sự xung đột của lửa cuối cùng có thể dẫn đến sự chuyển tiếp bình yên nếu biết lắng nghe hướng dẫn.", en: "Five of Wands and Six of Swords: from chaos to peace — fire in disarray and air charting the way out; a combination of problem and solution — fire's conflict can eventually lead to peaceful transition if one knows how to follow the guidance." },
  "26_56": { vi: "Năm Gậy và Bảy Kiếm: xung đột công khai và mưu kế ẩn — lửa đang chiến đấu một cách hiển nhiên trong khi không khí đang lợi dụng sự hỗn loạn đó để âm thầm lấy đi những gì có giá trị; sự hỗn loạn của đám đông thường là môi trường tốt nhất cho kẻ gian hoạt động.", en: "Five of Wands and Seven of Swords: open conflict and hidden cunning — fire fighting openly while air takes advantage of that chaos to quietly take what has value; the chaos of a crowd is often the best environment for the dishonest to operate." },
  "26_57": { vi: "Năm Gậy và Tám Kiếm: hỗn loạn bên ngoài và tự trói buộc bên trong — lửa đang bị kéo vào mọi hướng trong khi không khí không thể nhìn thấy con đường ra; đây là một trong những tình huống khó khăn nhất khi cả áp lực bên ngoài lẫn giới hạn bên trong đều hoạt động cùng lúc.", en: "Five of Wands and Eight of Swords: outer chaos and inner self-binding — fire being pulled in every direction while air cannot see the way out; one of the most difficult situations when both external pressure and internal limitation are operating simultaneously." },
  "26_58": { vi: "Năm Gậy và Chín Kiếm: xung đột bên ngoài và khủng hoảng bên trong — lửa đang chiến đấu với thế giới trong khi không khí đang chìm trong bóng tối của lo âu; đây là lời kêu gọi khẩn cấp dừng lại và tìm sự hỗ trợ trước khi một hoặc cả hai tình trạng leo thang đến mức không thể kiểm soát.", en: "Five of Wands and Nine of Swords: outer conflict and inner crisis — fire fighting the world while air is sinking into anxiety's darkness; an urgent call to stop and seek support before one or both conditions escalate beyond control." },
  "26_59": { vi: "Năm Gậy và Mười Kiếm: cuộc chiến dẫn đến sự sụp đổ — lửa đang tham gia vào một cuộc tranh cãi không cần thiết dẫn không khí đến sự kết thúc đau đớn; đây là hình ảnh của cái giá thực sự của những cuộc xung đột tưởng như nhỏ nhặt nhưng tích lũy đến điểm không thể phục hồi.", en: "Five of Wands and Ten of Swords: battle leading to collapse — fire engaging in unnecessary conflict that leads air to a painful ending; this is the image of the true cost of conflicts that seem minor but accumulate to a point of no return." },
  "26_60": { vi: "Năm Gậy và Trang Bị Kiếm: tranh cãi và người quan sát nhanh nhạy — lửa đang chiến đấu và không khí trẻ tuổi đang xem xét tình hình từ mọi góc độ; trang bị kiếm có thể thấy điều mà những người đang chiến đấu không thể thấy và lời nói đúng lúc có thể thay đổi toàn bộ tình huống.", en: "Five of Wands and Page of Swords: argument and the sharp observer — fire fighting and young air examining the situation from every angle; the page may see what those fighting cannot, and the right words at the right moment can change the entire situation." },
  "26_61": { vi: "Năm Gậy và Kỵ Sĩ Kiếm: hai lực lượng chiến đấu — lửa hỗn loạn và không khí lao về phía trước; khi hai năng lượng tấn công gặp nhau, sự va chạm có thể mạnh đến mức phá hoại hoặc mạnh đến mức tạo ra điều gì đó hoàn toàn mới từ sự tàn phá.", en: "Five of Wands and Knight of Swords: two fighting forces — chaotic fire and charging air; when two offensive energies meet, the collision can be destructive enough to destroy or powerful enough to create something entirely new from the wreckage." },
  "26_62": { vi: "Năm Gậy và Nữ Hoàng Kiếm: hỗn loạn gặp sự phán xét rõ ràng — Nữ Hoàng Kiếm không tham gia vào cuộc tranh cãi của lửa mà đứng ngoài và nhìn thấy chính xác điều gì đang xảy ra; một câu nhận xét sắc bén từ bà có thể chấm dứt sự hỗn loạn ngay lập tức.", en: "Five of Wands and Queen of Swords: chaos meeting clear judgment — the Queen of Swords does not join fire's argument but stands outside and sees exactly what is happening; one sharp observation from her can end the chaos immediately." },
  "26_63": { vi: "Năm Gậy và Vua Kiếm: xung đột gặp thẩm quyền — lửa đang tranh cãi và Vua Kiếm nắm quyền xét xử; không ai muốn thách thức thẩm quyền trí tuệ và pháp lý của không khí, và đôi khi sự hiện diện của uy quyền là đủ để chấm dứt mọi xung đột nhỏ nhặt.", en: "Five of Wands and King of Swords: conflict meeting authority — fire arguing and the King of Swords holding the power of judgment; no one wishes to challenge air's intellectual and legal authority, and sometimes the mere presence of that authority is enough to end all petty conflict." },
  "27_50": { vi: "Sáu Gậy và Át Kiếm: chiến thắng và sự sáng suốt mới — lửa đang được tôn vinh và không khí mang đến một ý tưởng mới để xây dựng trên nền tảng thành công đó; đây là thời điểm lý tưởng — từ điểm cao nhất của chiến thắng, hướng tiếp theo trở nên rõ ràng hơn bao giờ hết.", en: "Six of Wands and Ace of Swords: victory and new clarity — fire being recognized and air bringing a fresh idea to build on that success; an ideal moment — from the highest point of victory, the next direction becomes clearer than ever." },
  "27_51": { vi: "Sáu Gậy và Hai Kiếm: chiến thắng công khai và do dự riêng tư — lửa nhận được sự tôn vinh bên ngoài trong khi không khí vẫn đang đấu tranh để đưa ra quyết định bên trong; đây là sự nhắc nhở rằng sự công nhận bên ngoài không tự động giải quyết sự lưỡng lự bên trong.", en: "Six of Wands and Two of Swords: public victory and private hesitation — fire receiving external recognition while air is still struggling to decide within; a reminder that external recognition does not automatically resolve inner hesitation." },
  "27_52": { vi: "Sáu Gậy và Ba Kiếm: vinh quang và nỗi đau nội tâm — người được đám đông tôn vinh cũng có thể đang mang vết thương sâu trong lòng; chiến thắng bên ngoài không chữa lành được tất cả và đôi khi chính những người thành công nhất lại mang nỗi đau cô đơn nhất.", en: "Six of Wands and Three of Swords: glory and inner pain — one celebrated by the crowd can also carry deep wounds within; external victory does not heal everything and sometimes the most successful people carry the loneliest pain." },
  "27_53": { vi: "Sáu Gậy và Bốn Kiếm: chiến thắng cần nghỉ ngơi — lửa đang ở trên đỉnh cao nhưng không khí nhắc rằng người chiến thắng cũng cần phục hồi; biết nghỉ ngơi sau thành công là dấu hiệu của sự trưởng thành và là cách bảo toàn năng lượng cho những chiến thắng tiếp theo.", en: "Six of Wands and Four of Swords: victory needing rest — fire at the peak but air reminding that winners also need recovery; knowing how to rest after success is a mark of maturity and the way to preserve energy for future victories." },
  "27_54": { vi: "Sáu Gậy và Năm Kiếm: hai mặt của kết quả — lửa đang ăn mừng chiến thắng và không khí đang đứng với những kẻ thua cuộc; đây là lời nhắc nhở rằng mỗi chiến thắng đều có ai đó ở phía thua và cách nhà vô địch đối xử với kẻ thua cuộc cho thấy phẩm cách thực sự của họ.", en: "Six of Wands and Five of Swords: two sides of an outcome — fire celebrating victory and air standing with those who lost; a reminder that every victory has someone on the losing side and how champions treat those they defeat reveals their true character." },
  "27_55": { vi: "Sáu Gậy và Sáu Kiếm: hai con sáu — chiến thắng và chuyển tiếp — lửa đang di chuyển về phía trước trong vinh quang và không khí đang dần hướng tới bình yên; khi thành công và sự chuyển dịch bình yên cùng nhau, hành trình tiếp theo có thể được thực hiện từ điểm xuất phát cao nhất.", en: "Six of Wands and Six of Swords: two sixes — victory and transition — fire moving forward in triumph and air gradually sailing toward peace; when success and peaceful transition work together, the next journey can begin from the highest starting point." },
  "27_56": { vi: "Sáu Gậy và Bảy Kiếm: chiến thắng và kẻ cơ hội — lửa đang ăn mừng trong khi không khí đang lợi dụng khoảnh khắc sao lãng của chiến thắng; đây là lời nhắc rằng ngay cả ở đỉnh cao của thành công, cần giữ sự tỉnh táo vì kẻ gian thường hành động khi người khác đang mất cảnh giác nhất.", en: "Six of Wands and Seven of Swords: victory and the opportunist — fire celebrating while air takes advantage of the distraction that triumph creates; a reminder that even at the height of success, vigilance is needed because the dishonest often act when others are most off-guard." },
  "27_57": { vi: "Sáu Gậy và Tám Kiếm: vinh quang và người bị giam cầm — lửa đang kỵ mã giữa sự hoan hô trong khi không khí đang đứng bịt mắt và bị trói; đây là sự tương phản mạnh mẽ nhắc nhở rằng tự do và trói buộc có thể cùng tồn tại ngay trong cùng một không gian.", en: "Six of Wands and Eight of Swords: glory and the imprisoned — fire riding amid cheers while air stands blindfolded and bound; a powerful contrast reminding that freedom and bondage can coexist in the very same space." },
  "27_58": { vi: "Sáu Gậy và Chín Kiếm: thành công bên ngoài và khổ đau bên trong — người đang được mọi người ngưỡng mộ cũng có thể đang tỉnh giấc lúc nửa đêm với lo âu; danh tiếng không bảo vệ khỏi bóng tối của tâm trí và đôi khi sự công nhận làm nặng thêm trách nhiệm đến mức đau đớn.", en: "Six of Wands and Nine of Swords: external success and inner suffering — the one admired by all may also be waking at midnight with anxiety; fame does not protect against the mind's darkness and sometimes recognition makes responsibility heavy enough to cause pain." },
  "27_59": { vi: "Sáu Gậy và Mười Kiếm: chiến thắng trước sự sụp đổ cuối cùng — lửa đang ở đỉnh cao ngay trước khi không khí chạm đáy; đây là hình ảnh của sự bấp bênh của thành công — đỉnh cao hôm nay không đảm bảo cho ngày mai, và sự khiêm tốn là điều duy nhất giúp người ta chuẩn bị.", en: "Six of Wands and Ten of Swords: victory before the final collapse — fire at its peak right before air hits bottom; the image of success's precariousness — today's height does not guarantee tomorrow, and humility is the only thing that helps one prepare." },
  "27_60": { vi: "Sáu Gậy và Trang Bị Kiếm: chiến thắng và người quan sát trẻ tuổi — lửa đang được tôn vinh và không khí trẻ tuổi đang quan sát và học hỏi; người trẻ nhìn người thành công không chỉ để ngưỡng mộ mà để hiểu những gì đằng sau chiến thắng mà đám đông không thấy.", en: "Six of Wands and Page of Swords: victory and the young observer — fire being honored and young air watching and learning; the young one looks at the successful not only to admire but to understand what lies behind the victory that the crowd cannot see." },
  "27_61": { vi: "Sáu Gậy và Kỵ Sĩ Kiếm: chiến thắng và tốc độ — lửa đang được tôn vinh và không khí đang lao về phía thách thức tiếp theo; đây là sự kết hợp của người chiến thắng trên đỉnh cao và người đang hướng tới chiến thắng tiếp theo — năng lượng của cả hai là không thể ngăn cản.", en: "Six of Wands and Knight of Swords: victory and speed — fire being honored and air charging toward the next challenge; a combination of the winner at the peak and the one heading toward the next victory — the energy of both is unstoppable." },
  "27_62": { vi: "Sáu Gậy và Nữ Hoàng Kiếm: sự công nhận và sự đánh giá rõ ràng — Nữ Hoàng Kiếm nhìn chiến thắng của lửa không phải với sự hâm mộ mù quáng mà với sự đánh giá thực chất; bà biết chính xác điều gì tạo nên thành công đó và đó là sự kính trọng chân thực hơn bất kỳ lời hoan hô nào.", en: "Six of Wands and Queen of Swords: recognition and clear evaluation — the Queen of Swords looks at fire's victory not with blind admiration but with genuine assessment; she knows exactly what created that success and that is more genuine respect than any cheering crowd." },
  "27_63": { vi: "Sáu Gậy và Vua Kiếm: vinh quang và thẩm quyền — lửa đang được tôn vinh và không khí đang cai trị từ ngai vàng trí tuệ; khi chiến thắng của lửa được thừa nhận bởi không khí có thẩm quyền, sự công nhận đó trở nên có trọng lượng và ý nghĩa thực sự vượt xa lời hoan hô của đám đông.", en: "Six of Wands and King of Swords: glory and authority — fire being honored and air ruling from the intellectual throne; when fire's victory is acknowledged by authoritative air, that recognition carries weight and meaning far beyond the crowd's cheering." },
  "28_50": { vi: "Bảy Gậy và Át Kiếm: phòng thủ và sự rõ ràng mới — lửa đang giữ vững lập trường và không khí cung cấp một ý tưởng sắc bén mới; khi người đang chiến đấu để bảo vệ điều mình tin nhận được sự sáng suốt rõ ràng về lý do tại sao mình đang chiến đấu, lập trường đó trở nên bất khả xâm phạm.", en: "Seven of Wands and Ace of Swords: defense and new clarity — fire holding its ground and air providing a sharp new idea; when the one fighting to defend what they believe in receives clear understanding of why they are fighting, that stance becomes unassailable." },
  "28_51": { vi: "Bảy Gậy và Hai Kiếm: đứng vững và bế tắc — lửa đang chiến đấu để bảo vệ vị trí của mình trong khi không khí không thể đưa ra quyết định; sự kết hợp này tạo ra một sự đình trệ kỳ lạ — lửa đang di chuyển nhưng không khí đang tạo ra bức tường vô hình ngăn cản tiến bộ.", en: "Seven of Wands and Two of Swords: standing firm and stalemate — fire fighting to defend its position while air cannot make a decision; this combination creates a strange stagnation — fire moving but air creating an invisible wall blocking progress." },
  "28_52": { vi: "Bảy Gậy và Ba Kiếm: chiến đấu qua nỗi đau — lửa đứng vững ngay cả khi không khí mang những vết thương tình cảm sâu; đây là hình ảnh của người không để nỗi đau của mình ngăn cản họ bảo vệ điều quan trọng, dù rằng cả hai đều rỉ máu từ bên trong.", en: "Seven of Wands and Three of Swords: fighting through heartbreak — fire standing firm even as air carries deep emotional wounds; this is the image of one who does not let their pain prevent them from defending what matters, even as both bleed from within." },
  "28_53": { vi: "Bảy Gậy và Bốn Kiếm: phòng thủ cần nghỉ ngơi — lửa đang đứng chiến đấu lâu đến mức không không nhận ra rằng mình cần phục hồi; không khí nhắc nhở rằng ngay cả người bảo vệ cũng cần tạm dừng — sức mạnh được bảo toàn qua nghỉ ngơi tốt hơn là sức mạnh bị kiệt sức không biết dừng.", en: "Seven of Wands and Four of Swords: defense needing rest — fire standing and fighting so long that it no longer recognizes its own need for recovery; air reminding that even the defender needs to pause — strength preserved through rest is better than strength exhausted by not knowing when to stop." },
  "28_54": { vi: "Bảy Gậy và Năm Kiếm: đứng vững trước kẻ không trung thực — lửa đang bảo vệ lập trường của mình trong khi không khí đang chiến đấu bằng chiến thuật không công bằng; đây là một trong những thách thức khó nhất — giữ vững đạo đức khi kẻ đối diện không có cùng quy tắc.", en: "Seven of Wands and Five of Swords: standing firm before the dishonest — fire defending its position while air fights with unfair tactics; one of the hardest challenges — maintaining ethical standing when the opponent plays by no rules at all." },
  "28_55": { vi: "Bảy Gậy và Sáu Kiếm: giữ lập trường và chuyển hướng — lửa đứng vững và không khí đang chuyển dịch bình yên; đây là lời nhắc rằng không phải mọi sự bảo vệ đều phải kết thúc bằng trận chiến — đôi khi phòng thủ tốt nhất là giữ vị trí đủ lâu cho đến khi tình huống tự tháo gỡ.", en: "Seven of Wands and Six of Swords: holding the position while transitioning — fire standing firm and air peacefully shifting away; a reminder that not every defense must end in battle — sometimes the best defense is holding position long enough for the situation to dissolve on its own." },
  "28_56": { vi: "Bảy Gậy và Bảy Kiếm: hai con bảy — phòng thủ và mưu kế — lửa đứng chiến đấu trực tiếp trong khi không khí đang hành động gián tiếp; đây là sự đối đầu của hai loại chiến lược và lời nhắc rằng người chiến đấu trực tiếp không phải lúc nào cũng nhận ra kẻ đang hành động từ sau lưng.", en: "Seven of Wands and Seven of Swords: two sevens — defense and cunning — fire fighting directly while air acts indirectly; a confrontation of two kinds of strategy and a reminder that one who fights openly does not always notice the one acting from behind." },
  "28_57": { vi: "Bảy Gậy và Tám Kiếm: người bảo vệ và người bị giam cầm — lửa đứng vững trong khi không khí bị trói buộc bởi chính sự sợ hãi của mình; đây là lời nhắc rằng đôi khi những người cần được bảo vệ nhất không phải là những người đang bị tấn công từ bên ngoài mà là những người đang bị giam cầm từ bên trong.", en: "Seven of Wands and Eight of Swords: the defender and the imprisoned — fire standing firm while air is bound by its own fear; a reminder that sometimes those who most need defending are not those being attacked from outside but those imprisoned from within." },
  "28_58": { vi: "Bảy Gậy và Chín Kiếm: phòng thủ bên ngoài và lo âu bên trong — lửa đang chiến đấu với thế giới trong khi không khí đang bị kéo xuống bởi những ác mộng trong tâm trí; đây là hình ảnh của sự kiệt sức kép khi cả hai mặt trận đều đang hoạt động cùng lúc.", en: "Seven of Wands and Nine of Swords: outer defense and inner anxiety — fire fighting the world while air is pulled down by mental nightmares; the image of double exhaustion when both fronts are active simultaneously." },
  "28_59": { vi: "Bảy Gậy và Mười Kiếm: cuộc chiến cuối cùng trước sự kết thúc — lửa đứng vững trong trận chiến cuối cùng ngay trước khi không khí chạm đáy hoàn toàn; đây là khoảnh khắc then chốt khi sự kiên trì có thể ngăn sự sụp đổ hoặc khi biết buông tay mới là hành động dũng cảm thực sự.", en: "Seven of Wands and Ten of Swords: the last stand before the ending — fire holding firm in the final battle right before air hits absolute bottom; the pivotal moment when perseverance might prevent collapse or when knowing to release is the truly courageous act." },
  "28_60": { vi: "Bảy Gậy và Trang Bị Kiếm: người bảo vệ và người quan sát sắc sảo — lửa đứng chiến đấu và không khí trẻ tuổi đang quan sát tất cả; người trẻ của không khí có thể thấy những góc mà người đang chiến đấu không thể thấy và thông tin đó có thể là chìa khóa thay đổi kết cục.", en: "Seven of Wands and Page of Swords: the defender and the sharp observer — fire standing in combat and young air watching everything; the young air one can see angles the fighter cannot and that information can be the key that changes the outcome." },
  "28_61": { vi: "Bảy Gậy và Kỵ Sĩ Kiếm: hai chiến binh khác phong cách — lửa phòng thủ giữ vững vị trí trong khi không khí tấn công lao về phía trước; khi hai năng lượng chiến đấu khác nhau này gặp nhau, trận chiến phụ thuộc vào ai có thể thích nghi với phong cách của đối phương nhanh hơn.", en: "Seven of Wands and Knight of Swords: two warriors of different styles — defensive fire holding position while attacking air charges forward; when these two different fighting energies meet, the battle depends on who can adapt to the opponent's style faster." },
  "28_62": { vi: "Bảy Gậy và Nữ Hoàng Kiếm: phòng thủ gặp sự sắc bén — Nữ Hoàng Kiếm không tấn công lửa bằng vũ lực mà bằng sự rõ ràng không thể bác bỏ; đôi khi đối thủ đáng sợ nhất không phải là người tấn công ta từ bên ngoài mà là người nhìn thấy và nói ra sự thật mà ta đang bảo vệ mình khỏi.", en: "Seven of Wands and Queen of Swords: defense meeting sharpness — the Queen of Swords does not attack fire with force but with undeniable clarity; sometimes the most formidable opponent is not the one attacking from outside but the one who sees and speaks the truth one is defending oneself from." },
  "28_63": { vi: "Bảy Gậy và Vua Kiếm: lập trường và phán quyết tối cao — lửa đứng vững bảo vệ điều mình tin và không khí có quyền phán xét tối hậu; khi trường hợp của lửa được trình bày trước Vua Kiếm, sự chuẩn bị và sức mạnh đạo đức là những gì quyết định liệu lửa có thể tiếp tục đứng hay không.", en: "Seven of Wands and King of Swords: standing ground and supreme judgment — fire holding firm defending what it believes and air holding the ultimate power of judgment; when fire's case is presented before the King of Swords, preparation and moral strength are what determine whether fire may continue standing." },
  // ── Tier 5b-2: Wands × Swords, fire×air (Wands 29–35 × Swords 50–63, 98 pairs) ──
  "29_50": { vi: "Tám Gậy và Át Kiếm: tốc độ và sự sáng suốt — lửa đang di chuyển nhanh chóng và không khí cung cấp một ý tưởng sắc bén; khi tốc độ của lửa được định hướng bởi sự rõ ràng đột ngột của không khí, hành động nhanh mà đúng là kết quả mạnh mẽ nhất có thể đạt được.", en: "Eight of Wands and Ace of Swords: speed and clarity — fire moving swiftly and air providing a sharp idea; when fire's speed is directed by air's sudden clarity, fast yet accurate action is the most powerful result achievable." },
  "29_51": { vi: "Tám Gậy và Hai Kiếm: chuyển động gặp bế tắc — lửa đang di chuyển nhanh nhưng không khí đang chặn tầm nhìn và từ chối quyết định; đây là sự va chạm đặc biệt bực bội khi năng lượng hành động cao nhưng không có hướng đi rõ ràng để phóng thích.", en: "Eight of Wands and Two of Swords: movement meeting stalemate — fire moving fast but air blocking the view and refusing to decide; a particularly frustrating collision when action energy is high but there is no clear direction in which to release it." },
  "29_52": { vi: "Tám Gậy và Ba Kiếm: tin tức nhanh về nỗi đau — đôi khi thông điệp đến nhanh nhất là thông điệp đau đớn nhất; lửa mang tin tức và không khí phải hứng chịu sự va chạm của những gì nó mang theo, không có thời gian để chuẩn bị.", en: "Eight of Wands and Three of Swords: news arriving fast about pain — sometimes the message that arrives fastest is the most painful one; fire carrying news and air having to absorb the impact of what it brings with no time to prepare." },
  "29_53": { vi: "Tám Gậy và Bốn Kiếm: tốc độ cần sự dừng lại — lửa đang di chuyển liên tục nhưng không khí đang nằm nghỉ và phục hồi; đây là lời nhắc quan trọng rằng cơ thể và tâm trí cần những giai đoạn nghỉ ngơi để có thể tiếp nhận và xử lý tất cả những gì đang di chuyển qua chúng.", en: "Eight of Wands and Four of Swords: speed needing stillness — fire moving continuously but air lying still and recovering; an important reminder that body and mind need periods of rest to receive and process everything moving through them." },
  "29_54": { vi: "Tám Gậy và Năm Kiếm: tốc độ trong xung đột không công bằng — lửa đang di chuyển nhanh trong khi không khí đang chơi bẩn; đây là lời cảnh báo rằng tốc độ không bảo vệ khỏi sự phản bội và đôi khi chạy nhanh vào một tình huống mà không quan sát kỹ có thể gây hại nhiều hơn.", en: "Eight of Wands and Five of Swords: speed in unfair conflict — fire moving fast while air plays dirty; a warning that speed does not protect against betrayal and sometimes rushing into a situation without careful observation causes more harm than good." },
  "29_55": { vi: "Tám Gậy và Sáu Kiếm: lửa nhanh nhẹn dẫn đường qua chuyển tiếp — không khí đang di chuyển đến nơi bình lặng hơn và lửa cung cấp năng lượng cho cuộc hành trình đó; khi tốc độ và sự chuyển dịch cùng chiều, vượt qua những giai đoạn khó khăn trở nên nhanh chóng và có mục đích.", en: "Eight of Wands and Six of Swords: swift fire leading through transition — air moving toward calmer waters and fire providing the energy for that journey; when speed and transition flow in the same direction, passing through difficult periods becomes fast and purposeful." },
  "29_56": { vi: "Tám Gậy và Bảy Kiếm: tốc độ và mưu kế — lửa đang di chuyển nhanh trong khi không khí đang lén lút; khi tốc độ gặp sự gian xảo, kẻ đủ nhanh để nhận ra trò chơi trước và đủ khôn để thay đổi hướng là người có lợi thế thực sự.", en: "Eight of Wands and Seven of Swords: speed and cunning — fire moving fast while air moves stealthily; when speed meets deceit, the one fast enough to recognize the game first and wise enough to change direction holds the real advantage." },
  "29_57": { vi: "Tám Gậy và Tám Kiếm: chuyển động và sự giam cầm — lửa đang bay nhanh trong khi không khí bị trói buộc và mù quáng; đây là sự tương phản của tự do và giới hạn, nhắc nhở rằng không phải tất cả sự tự do đều có thể được trao — một số phải được giành lấy từ bên trong.", en: "Eight of Wands and Eight of Swords: movement and imprisonment — fire flying fast while air is bound and blind; the contrast of freedom and limitation, reminding that not all freedom can be given — some must be won from within." },
  "29_58": { vi: "Tám Gậy và Chín Kiếm: chuyển động và lo âu — lửa có thể di chuyển nhanh nhưng không thể vượt khỏi những suy nghĩ lo lắng mà không khí đang mang; đây là lời nhắc rằng tốc độ vật lý không giải quyết được tốc độ tâm lý và đôi khi dừng lại mới là cách duy nhất để thoát khỏi lo âu.", en: "Eight of Wands and Nine of Swords: movement and anxiety — fire can move fast but cannot outrun the worrying thoughts air is carrying; speed of body does not resolve speed of mind and sometimes stopping is the only way to escape anxiety." },
  "29_59": { vi: "Tám Gậy và Mười Kiếm: chuyển động qua đống đổ nát — lửa bay qua vùng đất nơi không khí vừa chạm đáy; đây có thể là sự thoát khỏi nhanh chóng của những gì vừa kết thúc hoặc là thông điệp cần thiết để bắt đầu lại — đôi khi tin tức đến nhanh là điều duy nhất có thể thúc đẩy sự tái thiết.", en: "Eight of Wands and Ten of Swords: movement through the ruins — fire flying over the land where air has just bottomed out; a swift escape from what has just ended or the necessary message to begin again — sometimes fast news is the only thing that can catalyze rebuilding." },
  "29_60": { vi: "Tám Gậy và Trang Bị Kiếm: tốc độ và quan sát nhanh nhạy — lửa di chuyển nhanh và không khí trẻ tuổi đang để mắt đến mọi thứ; khi hai nguồn năng lượng nhanh nhẹn này hợp tác, không gì có thể xảy ra mà không được nhận thấy và không gì có thể bị bỏ lỡ.", en: "Eight of Wands and Page of Swords: speed and sharp observation — fire moving fast and young air keeping an eye on everything; when these two quick energies cooperate, nothing can happen without being noticed and nothing can be missed." },
  "29_61": { vi: "Tám Gậy và Kỵ Sĩ Kiếm: hai lực nhanh nhẹn — lửa và không khí đều đang di chuyển với tốc độ cao; khi hai năng lượng nhanh nhất trong bộ bài gặp nhau, kết quả là sức mạnh không thể ngăn cản hoặc sự hỗn loạn không thể kiểm soát tùy thuộc vào hướng chúng đang cùng nhau hướng đến.", en: "Eight of Wands and Knight of Swords: two swift forces — fire and air both moving at high speed; when the two fastest energies in the deck meet, the result is unstoppable force or uncontrollable chaos depending entirely on what direction they are both headed." },
  "29_62": { vi: "Tám Gậy và Nữ Hoàng Kiếm: tốc độ gặp sự phán xét — lửa đang di chuyển nhanh và Nữ Hoàng Kiếm nhìn thấy chính xác những gì đang xảy ra và những gì còn thiếu; đây là sự kết hợp tốt khi sự rõ ràng của không khí có thể định hướng tốc độ của lửa trước khi nó di chuyển quá xa theo hướng sai.", en: "Eight of Wands and Queen of Swords: speed meeting judgment — fire moving fast and the Queen of Swords seeing exactly what is happening and what is lacking; a good combination when air's clarity can direct fire's speed before it moves too far in the wrong direction." },
  "29_63": { vi: "Tám Gậy và Vua Kiếm: năng lượng nhanh nhẹn được kiểm soát bởi thẩm quyền — Vua Kiếm không ngăn lửa di chuyển nhưng xác định rõ giới hạn và hướng đi hợp lệ; khi tốc độ và thẩm quyền trí tuệ cùng nhau, hành động nhanh và có mục đích rõ ràng là kết quả mạnh mẽ nhất.", en: "Eight of Wands and King of Swords: swift energy controlled by authority — the King of Swords does not stop fire from moving but clearly defines valid limits and direction; when speed and intellectual authority work together, fast action with clear purpose is the strongest result." },
  "30_50": { vi: "Chín Gậy và Át Kiếm: người chiến binh dày dạn và sự sáng suốt mới — lửa đã chiến đấu nhiều và không khí mang một ý tưởng mới sắc bén; đôi khi sau nhiều trận chiến, một quan điểm hoàn toàn mới là điều duy nhất có thể làm thay đổi cách lửa tiếp cận những thách thức tiếp theo.", en: "Nine of Wands and Ace of Swords: the battle-worn warrior and new clarity — fire having fought much and air bringing a fresh sharp idea; sometimes after many battles, a completely new perspective is the only thing that can change how fire approaches the next challenges." },
  "30_51": { vi: "Chín Gậy và Hai Kiếm: người canh gác và sự bế tắc — lửa đứng phòng thủ trong khi không khí không thể đưa ra quyết định; khi cả sự kiên trì mệt mỏi và sự do dự gặp nhau, cần có điều gì đó từ bên ngoài để phá vỡ sự đình trệ này trước khi nó ăn mòn cả hai.", en: "Nine of Wands and Two of Swords: the sentinel and the stalemate — fire standing guard while air cannot decide; when both weary perseverance and hesitation meet, something from outside is needed to break this stagnation before it erodes both." },
  "30_52": { vi: "Chín Gậy và Ba Kiếm: vết thương chồng vết thương — người đã chịu đựng nhiều gặp thêm nỗi đau tình cảm; đây là thời điểm thực sự thử thách sức mạnh — không phải loại sức mạnh từ chối đau đớn mà loại sức mạnh cho phép bản thân cảm nhận đau và vẫn tiếp tục đứng.", en: "Nine of Wands and Three of Swords: wound upon wound — one who has endured much meeting yet more emotional pain; the moment that truly tests strength — not the kind that refuses pain but the kind that allows itself to feel pain and still remains standing." },
  "30_53": { vi: "Chín Gậy và Bốn Kiếm: chiến binh cần nghỉ ngơi — lửa đã đứng canh quá lâu và không khí đang nhắc nhở về giá trị của sự phục hồi; đây là bài học mà người kiên cường khó học nhất — rằng nghỉ ngơi không phải là sự đầu hàng mà là sự chuẩn bị cho giai đoạn tiếp theo.", en: "Nine of Wands and Four of Swords: the warrior needing rest — fire having stood watch too long and air reminding of recovery's value; the hardest lesson for the resilient to learn — that rest is not surrender but preparation for the next phase." },
  "30_54": { vi: "Chín Gậy và Năm Kiếm: kiên cường gặp sự bất công — lửa đã chiến đấu nhiều và không khí đang áp dụng chiến thuật không công bằng; người đã dày dạn kinh nghiệm biết rằng không phải mọi cuộc chiến đều đáng tham gia và đôi khi rời đi là hành động khôn ngoan nhất.", en: "Nine of Wands and Five of Swords: resilience meeting unfairness — fire having fought much and air applying unfair tactics; the battle-hardened one knows that not every fight is worth joining and sometimes walking away is the wisest action of all." },
  "30_55": { vi: "Chín Gậy và Sáu Kiếm: sức chịu đựng và sự chuyển tiếp bình yên — người đã giữ vững lập trường cuối cùng tìm thấy con đường đến nơi yên tĩnh hơn; không khí đang dẫn đường và lửa cuối cùng có thể đặt vũ khí xuống và để cuộc hành trình xảy ra.", en: "Nine of Wands and Six of Swords: endurance and peaceful transition — the one who has held firm finally finding the path to quieter waters; air charting the course and fire finally able to set down its weapons and let the journey happen." },
  "30_56": { vi: "Chín Gậy và Bảy Kiếm: người canh phòng và kẻ lén lút — kinh nghiệm của lửa đã dạy nó nhận ra dấu hiệu của sự gian dối; người đã bị tổn thương nhiều lần có bản năng tốt hơn để nhận biết khi nào không khí đang di chuyển với dụng ý che giấu.", en: "Nine of Wands and Seven of Swords: the guard and the stealthy one — fire's experience having taught it to recognize the signs of deception; one who has been wounded many times develops better instincts for when air is moving with hidden intentions." },
  "30_57": { vi: "Chín Gậy và Tám Kiếm: người kiên cường và người bị giam cầm — lửa đứng vững trong khi không khí bị trói buộc bởi chính những giới hạn của mình; cả hai đều đang bị hạn chế theo những cách khác nhau và đây là lời nhắc rằng cả phòng thủ liên tục và tự giam cầm đều là những nhà tù riêng.", en: "Nine of Wands and Eight of Swords: the resilient and the imprisoned — fire standing firm while air is bound by its own limitations; both constrained in different ways, a reminder that both constant defensiveness and self-imprisonment are prisons of their own." },
  "30_58": { vi: "Chín Gậy và Chín Kiếm: sự kiên trì và lo âu đêm tối — lửa không bỏ cuộc dù mệt mỏi trong khi không khí bị ám ảnh bởi những nỗi sợ hãi trong bóng tối; hai con chín này cùng nhau vẽ nên hình ảnh của người đang chiến đấu trên hai mặt trận cùng một lúc — cả bên ngoài lẫn bên trong.", en: "Nine of Wands and Nine of Swords: perseverance and dark-night anxiety — fire not giving up despite exhaustion while air is haunted by fears in the dark; these two nines together paint the image of one fighting on two fronts simultaneously — both outside and within." },
  "30_59": { vi: "Chín Gậy và Mười Kiếm: người bảo vệ đứng trước sự sụp đổ hoàn toàn — lửa đã giữ vững nhưng không khí vẫn chạm đáy; đây là bài học về ranh giới của sự kiên trì và lúc nào đó cần thừa nhận rằng một số sự kết thúc là không thể ngăn chặn — và đó không phải là thất bại của người bảo vệ.", en: "Nine of Wands and Ten of Swords: the defender standing before total collapse — fire having held firm but air still hitting bottom; a lesson about the limits of perseverance and when one must acknowledge that some endings cannot be prevented — and that is not the defender's failure." },
  "30_60": { vi: "Chín Gậy và Trang Bị Kiếm: chiến binh già dặn và sứ giả tò mò — lửa đã thấy quá nhiều và không khí trẻ tuổi đang đặt câu hỏi về mọi thứ; đây là sự gặp gỡ của kinh nghiệm và sự tò mò — cả hai đều cần nhau, dù người dày dạn kinh nghiệm có thể không nhận ra điều đó ngay lập tức.", en: "Nine of Wands and Page of Swords: the weathered warrior and the curious messenger — fire having seen too much and young air questioning everything; a meeting of experience and curiosity — both needing each other, even if the battle-worn one may not immediately recognize it." },
  "30_61": { vi: "Chín Gậy và Kỵ Sĩ Kiếm: người kiên trì và người lao về phía trước — lửa đang giữ vững trong khi không khí đang xông về phía trước; hai phong cách chiến đấu rất khác nhau gặp nhau — một dạy về việc giữ vững, một dạy về việc tấn công và cả hai bài học đều cần thiết.", en: "Nine of Wands and Knight of Swords: the persistent and the charger — fire holding firm while air charges forward; two very different fighting styles meeting — one teaching about holding ground, one about attacking, and both lessons being necessary." },
  "30_62": { vi: "Chín Gậy và Nữ Hoàng Kiếm: người canh phòng gặp sự sáng suốt — Nữ Hoàng Kiếm có thể nhìn thấy điều mà lửa đã quá mệt mỏi để nhận ra; sự rõ ràng của không khí đôi khi là thứ giúp người kiên cường nhất nhận ra khi nào đã đến lúc thay đổi chiến thuật.", en: "Nine of Wands and Queen of Swords: the sentinel meeting discernment — the Queen of Swords can see what fire is too exhausted to recognize; air's clarity is sometimes what helps even the most resilient one realize when it is time to change tactics." },
  "30_63": { vi: "Chín Gậy và Vua Kiếm: sức chịu đựng và thẩm quyền — Vua Kiếm nhận ra giá trị của người không bỏ cuộc; đây là sự gặp gỡ của hai loại sức mạnh — sức bền của lửa và sự phán xét của không khí — và cùng nhau họ tạo ra một loại thẩm quyền không thể bị lung lay.", en: "Nine of Wands and King of Swords: endurance and authority — the King of Swords recognizing the value of one who does not give up; a meeting of two kinds of strength — fire's resilience and air's judgment — and together they create an authority that cannot be shaken." },
  "31_50": { vi: "Mười Gậy và Át Kiếm: gánh nặng và sự sáng suốt giải phóng — không khí mang đến một ý tưởng sắc bén có thể chỉ ra chính xác điều gì cần được buông bỏ; đôi khi sự rõ ràng đơn giản của một câu hỏi đúng là điều duy nhất cần thiết để người đang mang quá nhiều nhận ra con đường thoát ra.", en: "Ten of Wands and Ace of Swords: burden and liberating clarity — air bringing a sharp idea that can point out exactly what needs to be released; sometimes the simple clarity of the right question is all that is needed for the one carrying too much to see the way out." },
  "31_51": { vi: "Mười Gậy và Hai Kiếm: quá tải và bế tắc — lửa đang oằn lưng dưới gánh nặng trong khi không khí không thể đưa ra quyết định về những gì cần làm tiếp theo; khi cả sự kiệt sức và sự do dự cùng tồn tại, cần có sự can thiệp bên ngoài để phá vỡ chu kỳ này.", en: "Ten of Wands and Two of Swords: overload and stalemate — fire bowed under burden while air cannot decide what to do next; when both exhaustion and hesitation coexist, outside intervention is needed to break this cycle." },
  "31_52": { vi: "Mười Gậy và Ba Kiếm: gánh nặng và nỗi đau — cả hai đều ở trạng thái khó khăn nhất và đây là sự kết hợp đặc biệt nặng nề; điều cần nhất trong khoảnh khắc này không phải là giải pháp ngay lập tức mà là sự thừa nhận rằng cả hai đều thực và cả hai đều cần được chú ý.", en: "Ten of Wands and Three of Swords: burden and heartbreak — both in their most difficult state, a particularly heavy combination; what is most needed in this moment is not an immediate solution but acknowledgment that both are real and both deserve attention." },
  "31_53": { vi: "Mười Gậy và Bốn Kiếm: người quá tải cần nghỉ ngơi — lửa đang mang quá nhiều và không khí đang nằm nghỉ để phục hồi; đây là sự nhắc nhở thiết thực nhất — trước khi có thể tiếp tục, cần đặt gánh nặng xuống và cho phép bản thân phục hồi hoàn toàn.", en: "Ten of Wands and Four of Swords: the overloaded one needing rest — fire carrying too much and air lying still to recover; the most practical reminder — before continuing, one must set the burden down and allow oneself to fully recover." },
  "31_54": { vi: "Mười Gậy và Năm Kiếm: gánh nặng trong môi trường xung đột — lửa đang mang quá nhiều trong khi không khí đang tạo ra thêm vấn đề với sự gian dối và cạnh tranh không công bằng; đây là lời cảnh báo về việc tham gia vào những cuộc chiến không cần thiết khi đã ở giới hạn sức chịu đựng.", en: "Ten of Wands and Five of Swords: burden in a conflicted environment — fire carrying too much while air is creating more problems with deception and unfair competition; a warning about engaging in unnecessary battles when already at one's limit." },
  "31_55": { vi: "Mười Gậy và Sáu Kiếm: gánh nặng trên hành trình ra đi — không khí đang dẫn đường đến nơi bình lặng hơn và lửa đang mang tất cả những gì nó nghĩ là cần thiết; đây là lời nhắc rằng hành trình đến nơi tốt hơn trở nên nhẹ nhàng hơn khi bạn để lại những gánh nặng không cần thiết trước khi lên thuyền.", en: "Ten of Wands and Six of Swords: burden on the departing journey — air charting the way to calmer shores and fire carrying everything it thinks is needed; a reminder that the journey to a better place becomes lighter when unnecessary burdens are set down before boarding." },
  "31_56": { vi: "Mười Gậy và Bảy Kiếm: người quá tải và kẻ cơ hội — lửa đang oằn lưng và không khí đang lợi dụng sự mất tập trung đó để lấy đi những gì không thuộc về mình; người đang mang quá nhiều cũng thường là người dễ bị tổn thương nhất trước sự lợi dụng.", en: "Ten of Wands and Seven of Swords: the overloaded and the opportunist — fire bowed under burden and air exploiting that distraction to take what does not belong to it; those carrying too much are often also the most vulnerable to exploitation." },
  "31_57": { vi: "Mười Gậy và Tám Kiếm: hai lớp giam cầm — lửa bị giam cầm bởi trách nhiệm quá nhiều và không khí bị giam cầm bởi giới hạn tự tạo; đây là lời kêu gọi khẩn cấp nhìn lại xem điều gì trong cả hai có thể được buông bỏ vì không ai có thể di chuyển tự do khi mang quá nhiều xiềng xích.", en: "Ten of Wands and Eight of Swords: two layers of imprisonment — fire imprisoned by too much responsibility and air imprisoned by self-made limitations; an urgent call to examine what in both can be released because no one can move freely while carrying too many chains." },
  "31_58": { vi: "Mười Gậy và Chín Kiếm: gánh nặng và lo âu — lửa đang kiệt sức về thể chất và không khí đang kiệt sức về tinh thần; đây là sự kết hợp yêu cầu sự chăm sóc khẩn cấp từ bên ngoài vì không ai trong trạng thái này có thể tự giải cứu mình mà không có sự giúp đỡ.", en: "Ten of Wands and Nine of Swords: burden and anxiety — fire physically exhausted and air mentally exhausted; a combination requiring urgent outside care because no one in this state can self-rescue without help." },
  "31_59": { vi: "Mười Gậy và Mười Kiếm: sụp đổ hoàn toàn — lửa mang quá nhiều đến điểm gãy và không khí chạm đáy hoàn toàn; khi cả hai con mười gặp nhau theo cách này, đây là tín hiệu rõ ràng nhất rằng một chu kỳ đã kết thúc và điều duy nhất còn lại là bắt đầu lại hoàn toàn từ đầu.", en: "Ten of Wands and Ten of Swords: total collapse — fire carrying too much to the breaking point and air hitting complete bottom; when both tens meet this way, the clearest signal that a cycle has ended and the only thing remaining is to begin entirely anew." },
  "31_60": { vi: "Mười Gậy và Trang Bị Kiếm: gánh nặng và thông điệp quan trọng — không khí trẻ tuổi mang thông tin có thể thay đổi cách lửa hiểu về gánh nặng của mình; đôi khi một quan sát tươi mới từ người ngoài cuộc là điều đầu tiên làm cho người đang mang quá nhiều dừng lại và suy nghĩ lại.", en: "Ten of Wands and Page of Swords: burden and an important message — young air carrying information that can change how fire understands its own burden; sometimes a fresh observation from an outsider is the first thing that makes the one carrying too much stop and reconsider." },
  "31_61": { vi: "Mười Gậy và Kỵ Sĩ Kiếm: gánh nặng và hành động nhanh — lửa đang oằn lưng và không khí đang lao về phía trước; đây có thể là sự giúp đỡ khi kỵ sĩ kiếm đến để giải quyết những gì đang chặn đường, hoặc là sự mâu thuẫn khi tốc độ của không khí bỏ lại lửa đang mang quá nhiều đứng một mình.", en: "Ten of Wands and Knight of Swords: burden and swift action — fire bowed under weight and air charging forward; this can be help when the sword knight arrives to clear what is blocking the path, or conflict when air's speed leaves overburdened fire standing alone." },
  "31_62": { vi: "Mười Gậy và Nữ Hoàng Kiếm: gánh nặng và sự phân tích sắc bén — Nữ Hoàng Kiếm nhìn thẳng vào tình huống của lửa và nói rõ điều mà lửa không muốn nghe: rằng không phải tất cả những gì đang được mang đều thuộc về người đang mang chúng.", en: "Ten of Wands and Queen of Swords: burden and sharp analysis — the Queen of Swords looking directly at fire's situation and stating clearly what fire does not want to hear: that not everything being carried actually belongs to the one carrying it." },
  "31_63": { vi: "Mười Gậy và Vua Kiếm: trách nhiệm quá mức và thẩm quyền sáng suốt — Vua Kiếm nhìn thấy chính xác điều gì đang được mang và điều gì có thể được ủy thác; lời khuyên của thẩm quyền trí tuệ là hãy phân phối trách nhiệm đúng cách thay vì cố gắng tự gánh tất cả một mình.", en: "Ten of Wands and King of Swords: excessive responsibility and wise authority — the King of Swords seeing exactly what is being carried and what could be delegated; the intellectual authority's counsel is to distribute responsibility properly rather than trying to carry everything alone." },
  "32_50": { vi: "Trang Bị Gậy và Át Kiếm: tâm hồn tò mò và ý tưởng sắc bén — hai nguồn năng lượng trẻ trung đang ở điểm khởi đầu của hai nguyên tố; khi nhiệt tình của lửa và sự sắc bén của không khí gặp nhau cùng một lúc, điều được tạo ra là loại năng lượng sáng tạo thuần khiết nhất.", en: "Page of Wands and Ace of Swords: curious soul and sharp idea — two young energies at the starting point of two elements; when fire's enthusiasm and air's sharpness meet simultaneously, what is created is the purest form of creative energy." },
  "32_51": { vi: "Trang Bị Gậy và Hai Kiếm: nhiệt tình gặp sự lưỡng lự — lửa trẻ muốn khám phá mọi thứ trong khi không khí đang chặn tầm nhìn và từ chối quyết định; đây là sự đình trệ bực bội cho tâm hồn nhiệt huyết nhất — bị giữ lại bởi sự do dự ở đúng khoảnh khắc muốn tiến lên.", en: "Page of Wands and Two of Swords: enthusiasm meeting hesitation — young fire wanting to explore everything while air blocks the view and refuses to decide; a frustrating stagnation for the most enthusiastic soul — held back by hesitation at exactly the moment of wanting to advance." },
  "32_52": { vi: "Trang Bị Gậy và Ba Kiếm: tâm hồn trẻ tuổi học về nỗi đau — lửa ngây thơ chưa từng trải qua nỗi đau của ba kiếm và khi gặp nó, đây là khoảnh khắc trưởng thành quan trọng; không có cách nào bảo vệ ai đó hoàn toàn khỏi nỗi đau và tốt nhất là học cách đứng dậy từ nó.", en: "Page of Wands and Three of Swords: the young soul learning about pain — innocent fire having never experienced the pain of three swords and when meeting it, a critical maturation moment; there is no way to fully protect someone from pain and the best is learning how to rise from it." },
  "32_53": { vi: "Trang Bị Gậy và Bốn Kiếm: sự nhiệt tình học cách dừng lại — lửa trẻ không hiểu tại sao cần nghỉ ngơi khi có quá nhiều điều để khám phá; nhưng chính sự nghỉ ngơi có ý thức dạy cho tâm hồn năng động nhất rằng chiều sâu đến từ sự tĩnh lặng, không chỉ từ hành động.", en: "Page of Wands and Four of Swords: enthusiasm learning to pause — young fire not understanding why rest is needed when there is so much to explore; but conscious rest teaches even the most active soul that depth comes from stillness, not only from action." },
  "32_54": { vi: "Trang Bị Gậy và Năm Kiếm: tâm hồn ngây thơ gặp sự không trung thực — lửa chưa học được những dấu hiệu của kẻ đang hành động vì lợi ích cá nhân; đây là bài học cần thiết — không để sự nhiệt tình trở thành sự ngây thơ dễ bị lợi dụng.", en: "Page of Wands and Five of Swords: innocent soul meeting dishonesty — fire not yet having learned the signs of one acting for personal gain; a necessary lesson — not allowing enthusiasm to become the naivety that is easily exploited." },
  "32_55": { vi: "Trang Bị Gậy và Sáu Kiếm: tâm hồn trẻ trên hành trình bình yên — lửa đang sẵn sàng cho chuyến phiêu lưu và không khí đang dẫn đường đến vùng nước êm hơn; đây là sự kết hợp tốt lành khi sự nhiệt tình của lửa được dẫn dắt theo hướng dịu dàng và không khói lửa.", en: "Page of Wands and Six of Swords: young soul on a peaceful journey — fire ready for adventure and air guiding toward calmer waters; a gentle combination when fire's enthusiasm is channeled in a smooth and undramatic direction." },
  "32_56": { vi: "Trang Bị Gậy và Bảy Kiếm: sự ngây thơ và mưu kế — lửa trẻ tuổi chưa có kinh nghiệm nhận biết khi nào người khác đang di chuyển với dụng ý che giấu; đây là lời cảnh báo để phát triển sự tinh tế mà không mất đi sự nhiệt tình — hai điều không loại trừ nhau.", en: "Page of Wands and Seven of Swords: innocence and cunning — young fire not yet experienced enough to recognize when others move with hidden intent; a warning to develop discernment without losing enthusiasm — two things that do not exclude each other." },
  "32_57": { vi: "Trang Bị Gậy và Tám Kiếm: nhiệt tình gặp sự tự giam cầm — lửa trẻ không thể hiểu tại sao người khác không thể di chuyển khi thế giới đang rộng mở; nhưng đây là bài học về sự đồng cảm — rằng không phải mọi giới hạn đều hiển thị và không phải mọi nhà tù đều có tường.", en: "Page of Wands and Eight of Swords: enthusiasm meeting self-imprisonment — young fire unable to understand why others cannot move when the world is wide open; a lesson in empathy — that not every limitation is visible and not every prison has walls." },
  "32_58": { vi: "Trang Bị Gậy và Chín Kiếm: sự hứng khởi và lo âu đêm khuya — lửa đang háo hức về ngày mai trong khi không khí đang bị ám ảnh bởi những nỗi sợ trong bóng tối; đây là sự tương phản nhắc nhở rằng cùng một thực tế có thể được trải nghiệm theo những cách hoàn toàn khác nhau.", en: "Page of Wands and Nine of Swords: excitement and midnight anxiety — fire eager about tomorrow while air is haunted by fears in the dark; a contrast reminding that the same reality can be experienced in completely different ways." },
  "32_59": { vi: "Trang Bị Gậy và Mười Kiếm: tâm hồn trẻ và sự kết thúc đau đớn — lửa đang ở điểm bắt đầu trong khi không khí vừa chạm đáy; đây là sự gặp gỡ của hai đầu của một chu kỳ và nhắc nhở rằng mỗi sự kết thúc mang trong nó một sự khởi đầu hoàn toàn mới.", en: "Page of Wands and Ten of Swords: young soul and painful ending — fire at a beginning while air has just hit bottom; a meeting of the two ends of a cycle, reminding that every ending carries within it a completely new beginning." },
  "32_60": { vi: "Trang Bị Gậy và Trang Bị Kiếm: hai trang bị từ hai nguyên tố — lửa tò mò và không khí quan sát; khi hai năng lượng trẻ tuổi từ lửa và không khí gặp nhau, sự trao đổi giữa nhiệt tình và sự sắc sảo có thể tạo ra điều kỳ diệu mà không nguyên tố nào có thể làm một mình.", en: "Page of Wands and Page of Swords: two pages from two elements — curious fire and observant air; when two young energies from fire and air meet, the exchange between enthusiasm and sharpness can create something wondrous that neither element could manage alone." },
  "32_61": { vi: "Trang Bị Gậy và Kỵ Sĩ Kiếm: học trò nhìn kỵ sĩ — lửa trẻ thấy không khí đang lao về phía trước với tốc độ và sự quyết đoán mà lửa đang học để đạt được; đây là nguồn cảm hứng nhưng cũng là lời nhắc rằng sức mạnh của kỵ sĩ đến sau nhiều năm tập luyện.", en: "Page of Wands and Knight of Swords: the apprentice watching the knight — young fire seeing air charging forward with the speed and decisiveness fire is learning to achieve; an inspiration but also a reminder that the knight's power comes after years of practice." },
  "32_62": { vi: "Trang Bị Gậy và Nữ Hoàng Kiếm: tâm hồn trẻ học từ sự sáng suốt — Nữ Hoàng Kiếm nhìn lửa trẻ với con mắt thực tế và nói sự thật mà không ai khác nói; đây là sự hướng dẫn có giá trị nhất — không phải sự tâng bốc mà là sự thật sắc bén được nói từ vị trí của sự quan tâm thực sự.", en: "Page of Wands and Queen of Swords: young soul learning from discernment — the Queen of Swords looking at young fire with realistic eyes and speaking the truth no one else speaks; the most valuable mentoring — not flattery but sharp truth spoken from genuine care." },
  "32_63": { vi: "Trang Bị Gậy và Vua Kiếm: tâm hồn tò mò trước thẩm quyền trí tuệ — lửa trẻ đứng trước Vua Kiếm và học rằng câu hỏi đúng đặt ra đúng cách có thể mở ra những cánh cửa mà ngay cả kẻ có quyền lực cũng tôn trọng; sự hiếu kỳ được hướng dẫn bởi sự tôn trọng là một sức mạnh thực sự.", en: "Page of Wands and King of Swords: curious soul before intellectual authority — young fire standing before the King of Swords and learning that the right question asked the right way can open doors that even the powerful respect; curiosity guided by respect is a genuine power." },
  "33_50": { vi: "Kỵ Sĩ Gậy và Át Kiếm: hành động táo bạo và sự sáng suốt đột ngột — lửa đang lao về phía trước và không khí mang đến ý tưởng sắc bén làm thay đổi hướng đi; khi bản năng hành động nhanh được kết hợp với sự rõ ràng về mục tiêu, hành động đó trở nên mạnh mẽ hơn bội phần.", en: "Knight of Wands and Ace of Swords: bold action and sudden clarity — fire charging forward and air bringing a sharp idea that changes direction; when the instinct to act fast is combined with clarity about the goal, that action becomes many times more powerful." },
  "33_51": { vi: "Kỵ Sĩ Gậy và Hai Kiếm: hành động gặp bế tắc — lửa muốn xông vào nhưng không khí đang chặn hướng nhìn và không thể đưa ra quyết định; đây là sự căng thẳng của năng lượng bị nén lại — tốt nhất là tìm ra điều gì đang chặn sự rõ ràng trước khi lực thúc đẩy hành động bùng nổ theo hướng sai.", en: "Knight of Wands and Two of Swords: action meeting stalemate — fire wanting to charge but air blocking the view and unable to decide; the tension of compressed energy — best to discover what is blocking clarity before the drive to act explodes in the wrong direction." },
  "33_52": { vi: "Kỵ Sĩ Gậy và Ba Kiếm: phi ngựa qua nỗi đau — lửa táo bạo có xu hướng lao qua những khoảnh khắc khó khăn thay vì dừng lại; đây không phải lúc nào cũng là sự trốn tránh — đôi khi hành động tiến về phía trước chính là cách tốt nhất để xử lý nỗi đau, tùy theo bản chất của người đó.", en: "Knight of Wands and Three of Swords: riding through pain — bold fire tending to charge through difficult moments rather than pausing; not always avoidance — sometimes moving forward is genuinely the best way to process pain, depending on the person's nature." },
  "33_53": { vi: "Kỵ Sĩ Gậy và Bốn Kiếm: bốc đồng cần nghỉ ngơi — lửa đang muốn lao về phía trước nhưng không khí đang phục hồi và cần tĩnh lặng; bài học khó nhất cho kỵ sĩ bốc đồng là học cách nhận ra khi nào dừng lại không phải là sự thất bại mà là sự tôn trọng bản thân.", en: "Knight of Wands and Four of Swords: impulsiveness needing rest — fire wanting to charge forward but air recovering and needing stillness; the hardest lesson for the impulsive knight is learning to recognize when pausing is not failure but self-respect." },
  "33_54": { vi: "Kỵ Sĩ Gậy và Năm Kiếm: lửa táo bạo gặp chiến lược bẩn — kỵ sĩ lửa chiến đấu ngay thẳng trong khi không khí sử dụng chiến thuật không công bằng; người lao về phía trước với lòng dũng cảm cần đủ sự khôn ngoan để nhận biết khi nào kẻ địch không tuân theo quy tắc tương tự.", en: "Knight of Wands and Five of Swords: bold fire meeting dirty strategy — fire knight fighting straightforwardly while air uses unfair tactics; the one who charges with courage needs enough wisdom to recognize when the opponent is not following the same rules." },
  "33_55": { vi: "Kỵ Sĩ Gậy và Sáu Kiếm: kỵ sĩ lửa trên hành trình chuyển tiếp — lửa đang lao về phía trước và không khí đang dẫn đường đến nơi bình lặng hơn; khi bản năng hành động và hướng dẫn bình yên cùng hướng, hành trình trở nên nhanh chóng và gần như dễ dàng không thể tin được.", en: "Knight of Wands and Six of Swords: the fire knight on a transition journey — fire charging forward and air guiding toward calmer shores; when action instinct and peaceful guidance align, the journey becomes swift and almost unbelievably easy." },
  "33_56": { vi: "Kỵ Sĩ Gậy và Bảy Kiếm: hành động táo bạo và mưu kế ẩn — lửa lao về phía trước mà không kiểm tra xung quanh trong khi không khí đang di chuyển lén lút; đây là lời cảnh báo rằng người hành động với quá nhiều tiếng ồn đôi khi không chú ý đến những gì đang xảy ra yên lặng ở xung quanh mình.", en: "Knight of Wands and Seven of Swords: bold action and hidden scheming — fire charging without checking around while air moves stealthily; a warning that the one who acts with too much noise sometimes misses what is happening quietly all around them." },
  "33_57": { vi: "Kỵ Sĩ Gậy và Tám Kiếm: kỵ sĩ tự do và người bị trói buộc — lửa phi nước đại trong sự tự do hoàn toàn trong khi không khí đứng bị giam cầm bởi chính những suy nghĩ của mình; sự tương phản này nhắc nhở rằng tự do đích thực thường nằm ở tâm trí hơn là ở hoàn cảnh bên ngoài.", en: "Knight of Wands and Eight of Swords: the free rider and the imprisoned — fire galloping in complete freedom while air stands imprisoned by its own thoughts; this contrast reminds that true freedom usually lies in the mind more than in external circumstances." },
  "33_58": { vi: "Kỵ Sĩ Gậy và Chín Kiếm: hành động và lo âu — lửa lao về phía trước trong khi không khí bị kéo xuống bởi những suy nghĩ lo lắng; cả hai cần nhau — hành động của lửa có thể phá vỡ sự tê liệt của lo âu và sự tỉnh táo của không khí có thể ngăn lửa khỏi những hành động bất cẩn.", en: "Knight of Wands and Nine of Swords: action and anxiety — fire charging while air is pulled down by worrying thoughts; both need each other — fire's action can break anxiety's paralysis and air's awareness can prevent fire from reckless acts." },
  "33_59": { vi: "Kỵ Sĩ Gậy và Mười Kiếm: kỵ sĩ đến sau trận chiến cuối cùng — lửa đang lao về phía nơi không khí vừa chạm đáy hoàn toàn; đây có thể là sự đến quá muộn để cứu hoặc chính xác đúng lúc để bắt đầu lại — tùy thuộc vào việc lửa có nhận ra đây là thời điểm xây dựng lại không phải chiến đấu.", en: "Knight of Wands and Ten of Swords: the knight arriving after the final battle — fire charging toward where air has just completely bottomed out; this can be arriving too late to save or exactly right to begin again — depending on whether fire recognizes this as a moment for rebuilding not fighting." },
  "33_60": { vi: "Kỵ Sĩ Gậy và Trang Bị Kiếm: kỵ sĩ và người quan sát sắc sảo — lửa đang lao về phía trước và không khí trẻ tuổi đang theo dõi tất cả; trang bị kiếm có thể thấy những gì kỵ sĩ bỏ qua trong cơn say sưa của hành động và thông tin đó đôi khi là điều quyết định thắng thua.", en: "Knight of Wands and Page of Swords: the knight and the sharp observer — fire charging forward and young air watching everything; the page can see what the knight misses in the rush of action, and that information is sometimes what decides victory or defeat." },
  "33_61": { vi: "Kỵ Sĩ Gậy và Kỵ Sĩ Kiếm: hai kỵ sĩ từ hai nguyên tố — lửa bốc đồng và không khí quyết đoán; khi hai lực tấn công mạnh nhất trong bộ bài gặp nhau, kết quả phụ thuộc vào mục tiêu — nếu cùng hướng, không gì có thể chống đỡ; nếu đối lập, cần ai đó đủ khôn để dừng lại.", en: "Knight of Wands and Knight of Swords: two knights from two elements — impulsive fire and decisive air; when the deck's two strongest attacking forces meet, the result depends on direction — if aligned, nothing can resist; if opposed, someone needs wisdom enough to stop." },
  "33_62": { vi: "Kỵ Sĩ Gậy và Nữ Hoàng Kiếm: hành động bốc đồng gặp sự phán xét sắc bén — Nữ Hoàng Kiếm không ngăn kỵ sĩ hành động nhưng nhìn thẳng vào hướng đi và chỉ ra chính xác điều gì có thể sai; đôi khi một lời nhận xét chuẩn xác từ người đứng ngoài có thể thay đổi toàn bộ kết cục.", en: "Knight of Wands and Queen of Swords: impulsive action meeting sharp judgment — the Queen of Swords does not stop the knight from acting but looks directly at the direction and points out exactly what could go wrong; sometimes one precise observation from an outsider changes the entire outcome." },
  "33_63": { vi: "Kỵ Sĩ Gậy và Vua Kiếm: năng lượng bốc đồng trước thẩm quyền tối cao — Vua Kiếm không bị ấn tượng bởi tốc độ hay sự táo bạo mà chỉ bởi sự rõ ràng của mục đích; kỵ sĩ lửa học rằng không phải sức mạnh hay tốc độ mà chính sự chính xác của lý do là điều thực sự được tôn trọng.", en: "Knight of Wands and King of Swords: impulsive energy before supreme authority — the King of Swords is not impressed by speed or boldness but only by clarity of purpose; the fire knight learning that not strength or speed but the precision of reason is what truly commands respect." },
  "34_50": { vi: "Nữ Hoàng Gậy và Át Kiếm: sự tự tin rực rỡ và sự sáng suốt mới — lửa đang tỏa sáng và không khí mang đến ý tưởng sắc bén; khi sức mạnh của Nữ Hoàng Gậy được bổ sung bởi sự rõ ràng của Át Kiếm, bà biết chính xác bước tiếp theo cần thực hiện và có đủ sức mạnh để thực hiện nó.", en: "Queen of Wands and Ace of Swords: radiant confidence and new clarity — fire shining and air bringing a sharp idea; when the Queen of Wands' strength is supplemented by the Ace of Swords' clarity, she knows exactly the next step needed and has the strength to take it." },
  "34_51": { vi: "Nữ Hoàng Gậy và Hai Kiếm: sức mạnh gặp sự lưỡng lự — lửa tự tin đứng vững trong khi không khí đang chặn tầm nhìn và do dự; Nữ Hoàng Gậy không để sự do dự của người khác dừng chân mình nhưng hiểu rằng đôi khi người ta cần không gian để đưa ra quyết định của chính họ.", en: "Queen of Wands and Two of Swords: strength meeting hesitation — confident fire standing firm while air blocks its own view and hesitates; the Queen of Wands does not let others' hesitation stop her but understands that sometimes people need space to reach their own decisions." },
  "34_52": { vi: "Nữ Hoàng Gậy và Ba Kiếm: sức mạnh trong nỗi đau — Nữ Hoàng Gậy không giả vờ nỗi đau không tồn tại mà đứng với nó bằng sức mạnh và phẩm giá; bà biết rằng sự rực rỡ không có nghĩa là không bao giờ đau mà là dám đau mà không để nỗi đau định nghĩa mình.", en: "Queen of Wands and Three of Swords: strength in pain — the Queen of Wands does not pretend pain does not exist but stands with it in strength and dignity; she knows that radiance does not mean never hurting but daring to hurt without letting pain define oneself." },
  "34_53": { vi: "Nữ Hoàng Gậy và Bốn Kiếm: lửa tỏa sáng biết lúc nào cần nghỉ ngơi — không ai có thể duy trì sự rực rỡ mà không có những giai đoạn phục hồi; Nữ Hoàng Gậy khôn ngoan biết rằng nghỉ ngơi không làm mờ đi ánh sáng mà làm cho nó trở nên sáng hơn khi trở lại.", en: "Queen of Wands and Four of Swords: radiant fire knowing when to rest — no one can maintain radiance without periods of recovery; the wise Queen of Wands knowing that rest does not dim the light but makes it brighter upon return." },
  "34_54": { vi: "Nữ Hoàng Gậy và Năm Kiếm: sức mạnh gặp sự không trung thực — Nữ Hoàng Gậy không dễ bị đánh lừa; sự tự tin và sự tỉnh táo của bà khiến bà nhận ra nhanh chóng khi không khí đang hành động vì lợi ích cá nhân và bà biết cách tự bảo vệ mình mà không cần hạ thấp mình.", en: "Queen of Wands and Five of Swords: strength meeting dishonesty — the Queen of Wands is not easily deceived; her confidence and alertness help her quickly recognize when air is acting for personal gain, and she knows how to protect herself without diminishing herself." },
  "34_55": { vi: "Nữ Hoàng Gậy và Sáu Kiếm: lửa tự tin dẫn đường qua chuyển tiếp — Nữ Hoàng Gậy không chỉ trải qua sự chuyển dịch mà dẫn đầu nó với sự tự tin và ân sủng; bà biết cách làm cho hành trình đến nơi tốt hơn trở nên đẹp đẽ và đầy ý nghĩa cho cả những người đi cùng bà.", en: "Queen of Wands and Six of Swords: confident fire leading through transition — the Queen of Wands not merely undergoing transition but leading it with confidence and grace; she knows how to make the journey to a better place beautiful and meaningful for those traveling with her too." },
  "34_56": { vi: "Nữ Hoàng Gậy và Bảy Kiếm: sự rực rỡ và mưu kế — Nữ Hoàng Gậy đủ tự tin để không cần che giấu ý định và đủ thông minh để nhận ra khi người khác đang làm vậy; bà không chơi trò gian dối nhưng đủ sắc bén để không trở thành nạn nhân của nó.", en: "Queen of Wands and Seven of Swords: radiance and cunning — the Queen of Wands confident enough not to need concealing her intentions and smart enough to recognize when others are doing so; she does not play deceptive games but is sharp enough not to become a victim of them." },
  "34_57": { vi: "Nữ Hoàng Gậy và Tám Kiếm: ánh sáng và bóng tối giam cầm — lửa tỏa sáng tự do trong khi không khí đứng bịt mắt và bị trói; Nữ Hoàng Gậy có thể không giải phóng ai bằng sức mạnh nhưng ánh sáng của bà đôi khi là thứ giúp người bị giam cầm nhận ra rằng họ có thể tự bước ra.", en: "Queen of Wands and Eight of Swords: light and imprisoning darkness — fire shining freely while air stands blindfolded and bound; the Queen of Wands may not liberate anyone by force but her light is sometimes what helps the imprisoned realize they can step out on their own." },
  "34_58": { vi: "Nữ Hoàng Gậy và Chín Kiếm: ánh sáng trong đêm lo âu — sự rực rỡ và sự tự tin của lửa là đối trọng tự nhiên của những lo lắng mà không khí mang trong bóng tối; nhưng cần nhớ rằng sự lạc quan thực sự không phải là phủ nhận lo âu mà là đủ sức mạnh để ở bên cạnh nó.", en: "Queen of Wands and Nine of Swords: light in the night of anxiety — fire's radiance and confidence the natural counterweight to the worries air carries in darkness; but remember that genuine optimism is not denying anxiety but having enough strength to be present beside it." },
  "34_59": { vi: "Nữ Hoàng Gậy và Mười Kiếm: ánh sáng sau sự kết thúc — lửa tỏa sáng ngay trên điểm mà không khí đã chạm đáy hoàn toàn; Nữ Hoàng Gậy là một trong những bài có thể đứng vững sau thất bại hoàn toàn và trở thành ngọn đèn cho sự bắt đầu lại.", en: "Queen of Wands and Ten of Swords: light after the ending — fire shining right above the point where air has completely bottomed out; the Queen of Wands is one who can stand firm after total defeat and become a beacon for beginning again." },
  "34_60": { vi: "Nữ Hoàng Gậy và Trang Bị Kiếm: nữ hoàng lửa và người học trò của không khí — Nữ Hoàng Gậy nhìn thấy sự sắc bén và tiềm năng trong trang bị kiếm trẻ tuổi; bà không nuôi dưỡng theo cách của mình mà theo cách phù hợp với bản chất của người trẻ đó.", en: "Queen of Wands and Page of Swords: fire queen and air's young apprentice — the Queen of Wands seeing the sharpness and potential in the young sword page; nurturing not in her own way but in the way that suits the young one's own nature." },
  "34_61": { vi: "Nữ Hoàng Gậy và Kỵ Sĩ Kiếm: lửa tự tin và không khí quyết đoán — cả hai đều là những người hành động mạnh mẽ nhưng theo cách khác nhau; Nữ Hoàng Gậy hành động từ trung tâm của sức mạnh trong khi Kỵ Sĩ Kiếm hành động từ sức mạnh của tốc độ và quyết tâm.", en: "Queen of Wands and Knight of Swords: confident fire and decisive air — both strong actors but in different ways; the Queen of Wands acting from the center of her own power while the Knight of Swords acts from the strength of speed and determination." },
  "34_62": { vi: "Nữ Hoàng Gậy và Nữ Hoàng Kiếm: hai nữ hoàng từ hai nguyên tố — lửa tự tin và nước sắc bén; khi hai người phụ nữ mạnh mẽ này gặp nhau, không ai nhượng bộ một cách không cần thiết nhưng cả hai đều đủ khôn ngoan để nhận ra sức mạnh trong sự khác biệt của người kia.", en: "Queen of Wands and Queen of Swords: two queens from two elements — confident fire and sharp air; when these two strong women meet, neither yields unnecessarily but both are wise enough to recognize the strength in the other's difference." },
  "34_63": { vi: "Nữ Hoàng Gậy và Vua Kiếm: nữ hoàng lửa và vua không khí — hai người cai trị với phong cách hoàn toàn khác nhau; một dẫn đầu bằng cảm hứng và sức sống còn một dẫn đầu bằng logic và trật tự; khi cả hai tôn trọng sự khác biệt của nhau, kết quả là một loại quyền lực cân bằng hiếm có.", en: "Queen of Wands and King of Swords: fire queen and air king — two rulers with completely different styles; one leading with inspiration and vitality while the other leads with logic and order; when both respect their differences, the result is a rare and balanced form of power." },
  "35_50": { vi: "Vua Gậy và Át Kiếm: tầm nhìn lãnh đạo và sự sáng suốt mới — lửa đang lãnh đạo với sức mạnh và không khí mang đến ý tưởng sắc bén làm tươi mới chiến lược; nhà lãnh đạo thực sự luôn chào đón sự rõ ràng mới và sẵn sàng điều chỉnh tầm nhìn khi thông tin mới xuất hiện.", en: "King of Wands and Ace of Swords: leadership vision and new clarity — fire leading with strength and air bringing a sharp idea that refreshes strategy; the true leader always welcomes new clarity and is ready to adjust the vision when new information emerges." },
  "35_51": { vi: "Vua Gậy và Hai Kiếm: quyết đoán gặp bế tắc — lửa hành động với sự quyết tâm trong khi không khí đang chặn tầm nhìn và không thể quyết định; Vua Gậy có thể cung cấp sự quyết đoán mà không khí đang thiếu, nhưng chỉ nếu người đó thực sự sẵn sàng nghe.", en: "King of Wands and Two of Swords: decisiveness meeting stalemate — fire acting with determination while air blocks its own view and cannot decide; the King of Wands can provide the decisiveness air is lacking, but only if that person is truly ready to listen." },
  "35_52": { vi: "Vua Gậy và Ba Kiếm: sức mạnh lãnh đạo trong nỗi đau — Vua Gậy không giả vờ nỗi đau không tồn tại nhưng cũng không để nó làm tê liệt mình; bài học của nhà lãnh đạo thực sự là dẫn đầu ngay cả trong khoảng thời gian khó khăn nhất với phẩm giá và sức mạnh nguyên vẹn.", en: "King of Wands and Three of Swords: leadership strength in pain — the King of Wands does not pretend pain does not exist but also does not let it paralyze him; the true leader's lesson is to lead even in the most difficult times with dignity and undiminished strength." },
  "35_53": { vi: "Vua Gậy và Bốn Kiếm: nhà lãnh đạo biết nghỉ ngơi — Vua Gậy hiểu rằng hiệu quả lãnh đạo đòi hỏi phục hồi; nhà lãnh đạo vĩ đại không chứng minh sức mạnh bằng cách không bao giờ nghỉ ngơi mà bằng cách biết khi nào cần bổ sung năng lượng để tiếp tục lãnh đạo ở mức cao nhất.", en: "King of Wands and Four of Swords: the leader who knows how to rest — the King of Wands understanding that leadership effectiveness requires recovery; the great leader proves strength not by never resting but by knowing when to replenish energy to continue leading at the highest level." },
  "35_54": { vi: "Vua Gậy và Năm Kiếm: lãnh đạo và sự cạnh tranh không lành mạnh — Vua Gậy không tham gia vào những trò chơi bẩn nhưng cũng không ngây thơ về sự tồn tại của chúng; nhà lãnh đạo thực sự xây dựng hệ thống ngăn ngừa sự gian dối hơn là chỉ phản ứng sau khi nó xảy ra.", en: "King of Wands and Five of Swords: leadership and unhealthy competition — the King of Wands does not engage in dirty games but is not naive about their existence; the true leader builds systems that prevent dishonesty rather than only reacting after it occurs." },
  "35_55": { vi: "Vua Gậy và Sáu Kiếm: nhà lãnh đạo dẫn đường qua chuyển tiếp — Vua Gậy không chỉ đi qua sự chuyển dịch mà hướng dẫn những người khác qua đó với sự tự tin và tầm nhìn rõ ràng; lãnh đạo thực sự sáng lên nhất trong những khoảnh khắc thay đổi khi người khác đang tìm kiếm phương hướng.", en: "King of Wands and Six of Swords: the leader guiding through transition — the King of Wands not merely passing through change but guiding others through it with confidence and clear vision; true leadership shines brightest in moments of change when others are seeking direction." },
  "35_56": { vi: "Vua Gậy và Bảy Kiếm: lãnh đạo và mưu kế — Vua Gậy đủ kinh nghiệm để nhận biết khi nào người khác đang hành động không trung thực; nhà lãnh đạo vĩ đại không bị lung lay bởi mưu kế vì sự rõ ràng về mục đích của mình khiến bất kỳ âm mưu nào cũng không thể bám vào.", en: "King of Wands and Seven of Swords: leadership and scheming — the King of Wands experienced enough to recognize when others are acting dishonestly; the great leader is not shaken by scheming because clarity of purpose makes any conspiracy unable to take hold." },
  "35_57": { vi: "Vua Gậy và Tám Kiếm: tầm nhìn tự do và người bị giam cầm — Vua Gậy có tầm nhìn mở rộng đến tận chân trời trong khi không khí đứng bịt mắt; nhà lãnh đạo khôn ngoan nhận ra những người bị giam cầm trong chính tâm trí của họ và biết rằng sự giải phóng phải đến từ bên trong.", en: "King of Wands and Eight of Swords: free vision and the imprisoned — the King of Wands with vision extending to the horizon while air stands blindfolded; the wise leader recognizing those imprisoned in their own minds and knowing that liberation must come from within." },
  "35_58": { vi: "Vua Gậy và Chín Kiếm: lãnh đạo và lo âu — ngay cả người có tầm nhìn và sức mạnh lãnh đạo cũng không miễn nhiễm với lo âu; sự khác biệt là Vua Gậy đủ kinh nghiệm để biết rằng những nỗi sợ ban đêm hiếm khi phản ánh thực tế ban ngày.", en: "King of Wands and Nine of Swords: leadership and anxiety — even the one with vision and leadership strength is not immune to anxiety; the difference is the King of Wands experienced enough to know that nighttime fears rarely reflect the daylight reality." },
  "35_59": { vi: "Vua Gậy và Mười Kiếm: lãnh đạo sau sự sụp đổ hoàn toàn — Vua Gậy đứng trước điểm kết thúc của không khí với sức mạnh và tầm nhìn nguyên vẹn; đây là thời điểm nhà lãnh đạo thực sự sáng lên nhất — không phải khi mọi thứ đang tốt mà khi cần ai đó dẫn đầu cuộc tái thiết từ đống đổ nát.", en: "King of Wands and Ten of Swords: leadership after total collapse — the King of Wands standing before air's ending point with vision and strength intact; the moment true leaders shine brightest — not when everything is going well but when someone is needed to lead rebuilding from the ruins." },
  "35_60": { vi: "Vua Gậy và Trang Bị Kiếm: nhà lãnh đạo và người học trò sắc sảo — Vua Gậy nhìn thấy trong trang bị kiếm sự tò mò và sắc sảo có thể phát triển thành điều mạnh mẽ; lãnh đạo tốt biết cách nuôi dưỡng những tài năng hoàn toàn khác với mình mà không cố biến họ thành bản sao của mình.", en: "King of Wands and Page of Swords: the leader and the sharp apprentice — the King of Wands seeing in the sword page a curiosity and sharpness that can grow into something powerful; good leadership knowing how to nurture talents completely different from oneself without trying to make them copies of oneself." },
  "35_61": { vi: "Vua Gậy và Kỵ Sĩ Kiếm: hai nhà hành động mạnh mẽ — lửa lãnh đạo với tầm nhìn và không khí lao về phía trước với tốc độ; khi cả hai cùng hướng về mục tiêu chung, họ là sự kết hợp đáng sợ nhất — tầm nhìn được hỗ trợ bởi sức mạnh hành động nhanh nhất.", en: "King of Wands and Knight of Swords: two powerful actors — fire leading with vision and air charging with speed; when both are aimed at a common goal they are the most formidable combination — vision backed by the fastest acting force." },
  "35_62": { vi: "Vua Gậy và Nữ Hoàng Kiếm: vua lửa và nữ hoàng không khí — hai người cai trị đủ mạnh để không cần thống trị người kia; cả hai hiểu sức mạnh theo những cách khác nhau và khi họ làm việc cùng nhau, sự kết hợp của cảm hứng và sự rõ ràng tạo ra điều không thể ngăn cản.", en: "King of Wands and Queen of Swords: fire king and air queen — two rulers strong enough not to need to dominate each other; both understanding power in different ways and when they work together, the combination of inspiration and clarity creates something unstoppable." },
  "35_63": { vi: "Vua Gậy và Vua Kiếm: hai vua, hai nguyên tố — lửa và không khí ở đỉnh cao của sự trưởng thành; Vua Gậy mang tầm nhìn, cảm hứng và sức mạnh hành động trong khi Vua Kiếm mang sự logic, công lý và thẩm quyền trí tuệ; cùng nhau họ thể hiện sự lãnh đạo ở dạng hoàn chỉnh và đáng kính nhất.", en: "King of Wands and King of Swords: two kings, two elements — fire and air at the apex of maturity; the King of Wands bringing vision, inspiration and strength of action while the King of Swords brings logic, justice and intellectual authority; together they embody leadership in its most complete and formidable form." },
  // ── Tier 5c-1: Wands × Pentacles, fire×earth (Wands 22–28 × Pentacles 64–77, 98 pairs) ──
  "22_64": { vi: "Át Gậy và Át Tiền: hai khởi đầu — lửa và đất ở điểm xuất phát nguyên thủy của chúng; cảm hứng thuần khiết gặp cơ hội vật chất thuần khiết và khi cả hai cùng xuất hiện, tiềm năng biến ý tưởng thành thực tế hữu hình là lớn nhất có thể.", en: "Ace of Wands and Ace of Pentacles: two beginnings — fire and earth at their primal starting points; pure inspiration meeting pure material opportunity, and when both appear together, the potential to transform ideas into tangible reality is at its greatest." },
  "22_65": { vi: "Át Gậy và Hai Tiền: cảm hứng mới gặp sự cân bằng nguồn lực — lửa muốn bùng cháy ngay lập tức trong khi đất đang tung hứng nhiều thứ cùng một lúc; đây là lời nhắc rằng ý tưởng tuyệt vời cần được ra đời vào đúng thời điểm khi nguồn lực có thể hỗ trợ nó.", en: "Ace of Wands and Two of Pentacles: fresh inspiration meeting resource juggling — fire wanting to blaze immediately while earth manages multiple things at once; a reminder that great ideas need to arrive at the right moment when resources can actually support them." },
  "22_66": { vi: "Át Gậy và Ba Tiền: ngọn lửa mới trong tay thợ thủ công — cảm hứng nguyên thủy gặp sự khéo léo và làm việc nhóm có tổ chức; khi lửa cung cấp ý tưởng và đất cung cấp kỹ năng, những điều được tạo ra có cả hồn và chất lượng.", en: "Ace of Wands and Three of Pentacles: the new flame in the craftsman's hands — primal inspiration meeting skilled craftsmanship and organized teamwork; when fire provides the idea and earth provides the skill, what is created has both soul and quality." },
  "22_67": { vi: "Át Gậy và Bốn Tiền: cảm hứng gặp sự nắm giữ chặt — lửa muốn chuyển động và tạo ra trong khi đất đang ôm chặt những gì mình có; đây là sự căng thẳng giữa tiềm năng sáng tạo và nỗi sợ hãi của việc để mất đi những gì an toàn đang cầm trong tay.", en: "Ace of Wands and Four of Pentacles: inspiration meeting tight holding — fire wanting to move and create while earth clutches what it has; the tension between creative potential and the fear of losing what is safely in hand." },
  "22_68": { vi: "Át Gậy và Năm Tiền: ngọn lửa mới giữa cơ hàn — cảm hứng đến vào lúc thiếu thốn nhất; đây không phải là sự tàn nhẫn mà là bằng chứng rằng sức sáng tạo không cần điều kiện hoàn hảo — đôi khi chính sự túng thiếu là chất xúc tác cho những ý tưởng đẹp nhất.", en: "Ace of Wands and Five of Pentacles: new flame amid hardship — inspiration arriving at the moment of greatest lack; not cruelty but proof that creative force does not require perfect conditions — sometimes scarcity itself is the catalyst for the most beautiful ideas." },
  "22_69": { vi: "Át Gậy và Sáu Tiền: cảm hứng và sự hào phóng vật chất — lửa thuần khiết gặp năng lượng của sự cho đi và nhận lại; khi cảm hứng được hỗ trợ bởi sự hào phóng hoặc chia sẻ giữa những người cùng chí hướng, ý tưởng mới nảy sinh có thể nuôi dưỡng nhiều người.", en: "Ace of Wands and Six of Pentacles: inspiration and material generosity — pure fire meeting the energy of giving and receiving; when inspiration is supported by generosity or sharing among like-minded people, the new idea that emerges can nourish many." },
  "22_70": { vi: "Át Gậy và Bảy Tiền: tia lửa và sự kiên nhẫn dài hạn — lửa muốn bùng sáng ngay lập tức nhưng đất đang đánh giá cẩn thận về sự tăng trưởng dài hạn; đây là sự kết hợp của hai quan điểm thời gian khác nhau nhắc nhở rằng ý tưởng tốt cần cả cảm hứng ban đầu lẫn sự nuôi dưỡng kiên nhẫn.", en: "Ace of Wands and Seven of Pentacles: the spark and long-term patience — fire wanting to blaze immediately but earth carefully assessing long-term growth; a combination of two different time perspectives reminding that good ideas need both initial inspiration and patient nurturing." },
  "22_71": { vi: "Át Gậy và Tám Tiền: cảm hứng gặp sự tận tụy — lửa mang ý tưởng và đất mang đôi tay lành nghề sẵn sàng biến nó thành thực tế; đây là sự kết hợp lý tưởng nhất của hai nguyên tố — khi cảm hứng được kết đôi với sự luyện tập chăm chỉ, điều không thể trở thành có thể.", en: "Ace of Wands and Eight of Pentacles: inspiration meeting dedication — fire bringing the idea and earth bringing skilled hands ready to make it real; the most ideal combination of two elements — when inspiration is paired with diligent practice, the impossible becomes possible." },
  "22_72": { vi: "Át Gậy và Chín Tiền: ngọn lửa mới trên nền tảng phong phú — cảm hứng nguyên thủy gặp sự tự túc và sung túc mà đất đã tích lũy; đây là thời điểm lý tưởng để bắt đầu vì nền tảng vững chắc đã có sẵn và nguồn cảm hứng chỉ cần được phép chạm vào nó.", en: "Ace of Wands and Nine of Pentacles: new flame on a foundation of abundance — primal inspiration meeting the self-sufficiency and prosperity earth has accumulated; the ideal moment to begin because the solid foundation already exists and inspiration only needs to be allowed to touch it." },
  "22_73": { vi: "Át Gậy và Mười Tiền: cảm hứng gặp di sản — lửa thuần khiết đứng trước thứ đất đã xây dựng qua nhiều thế hệ; ý tưởng mới bùng lên trong bối cảnh của truyền thống lâu dài và câu hỏi là liệu cảm hứng sẽ đổi mới hay thách thức di sản đó.", en: "Ace of Wands and Ten of Pentacles: inspiration meeting legacy — pure fire standing before what earth has built across generations; a new idea sparking in the context of long tradition, and the question is whether inspiration will renew or challenge that heritage." },
  "22_74": { vi: "Át Gậy và Trang Bị Tiền: hai tâm hồn trẻ tuổi từ hai nguyên tố — cảm hứng chưa được hình thành gặp sự ham học hỏi và tham vọng vật chất; cả hai đều đang ở điểm bắt đầu và khi lửa và đất trẻ tuổi gặp nhau, sự kết hợp của mơ ước và thực tế tạo ra những khả năng kỳ diệu.", en: "Ace of Wands and Page of Pentacles: two young souls from two elements — unformed inspiration meeting the love of learning and material ambition; both at their starting point, and when young fire and earth meet, the combination of dreaming and practicality creates wonderful possibilities." },
  "22_75": { vi: "Át Gậy và Kỵ Sĩ Tiền: tia lửa và sự bền bỉ — lửa bùng lên nhanh chóng trong khi đất tiến lên chậm rãi và đáng tin cậy; đây là sự kết hợp của hai tốc độ — cảm hứng đến nhanh nhưng sự thể hiện thực sự đòi hỏi sự kiên định và nhịp độ đều đặn của đất.", en: "Ace of Wands and Knight of Pentacles: the spark and endurance — fire igniting quickly while earth advances slowly and reliably; a combination of two speeds — inspiration arriving fast but true manifestation requiring earth's steadiness and consistent pace." },
  "22_76": { vi: "Át Gậy và Nữ Hoàng Tiền: cảm hứng được nuôi dưỡng bởi đất — Nữ Hoàng Tiền không dập tắt ngọn lửa mà tạo ra điều kiện đất đai cho nó phát triển; bà biết rằng cảm hứng thuần khiết cần sự chăm sóc thực tế để trở thành điều gì đó tồn tại lâu dài trong thế giới hữu hình.", en: "Ace of Wands and Queen of Pentacles: inspiration nurtured by earth — the Queen of Pentacles does not extinguish the flame but creates the fertile conditions for it to grow; she knows that pure inspiration needs practical care to become something that endures in the tangible world." },
  "22_77": { vi: "Át Gậy và Vua Tiền: cảm hứng gặp sự làm chủ vật chất — lửa thuần khiết đứng trước người đã biến đổi đất thành đế chế; Vua Tiền nhìn ngọn lửa nguyên thủy và hiểu rằng đây là nơi mọi thứ bắt đầu — mọi đế chế vật chất đều từng là một tia cảm hứng thuần khiết.", en: "Ace of Wands and King of Pentacles: inspiration meeting material mastery — pure fire standing before one who has transformed earth into empire; the King of Pentacles looking at the primal flame and understanding this is where everything begins — every material empire was once a spark of pure inspiration." },
  "23_64": { vi: "Hai Gậy và Át Tiền: tầm nhìn táo bạo gặp cơ hội vật chất mới — lửa đang lên kế hoạch với thế giới trong tay và đất mang đến cơ hội cụ thể để bắt đầu hiện thực hóa những kế hoạch đó; đây là khoảnh khắc khi tầm nhìn và điều kiện vật chất cuối cùng gặp nhau.", en: "Two of Wands and Ace of Pentacles: bold vision meeting new material opportunity — fire planning with the world in hand and earth bringing a concrete opportunity to begin manifesting those plans; the moment when vision and material conditions finally meet." },
  "23_65": { vi: "Hai Gậy và Hai Tiền: kế hoạch chiến lược và sự cân bằng nguồn lực — lửa đang nhìn xa trong khi đất đang quản lý những gì có sẵn hiện tại; đây là sự kết hợp của tư duy dài hạn và khả năng linh hoạt thực tế — cả hai đều cần thiết để bất kỳ kế hoạch lớn nào đứng vững.", en: "Two of Wands and Two of Pentacles: strategic planning and resource balancing — fire looking far ahead while earth manages what is available now; a combination of long-term thinking and practical flexibility — both necessary for any large plan to stand." },
  "23_66": { vi: "Hai Gậy và Ba Tiền: tầm nhìn lớn và sự cộng tác khéo léo — lửa có kế hoạch và đất có kỹ năng và tinh thần làm việc nhóm để thực hiện nó; khi nhà hoạch định gặp những thợ thủ công tận tâm, những gì được tạo ra vượt xa những gì bất kỳ ai trong số họ có thể làm một mình.", en: "Two of Wands and Three of Pentacles: grand vision and skilled collaboration — fire holding the plan and earth possessing the skill and teamwork spirit to execute it; when the planner meets dedicated craftspeople, what is created far exceeds what any one of them could do alone." },
  "23_67": { vi: "Hai Gậy và Bốn Tiền: tầm nhìn xa bị kéo lại bởi sự bám víu — lửa đang nhìn ra chân trời trong khi đất đang ôm chặt những gì đang có; đây là sự căng thẳng giữa tham vọng và sự an toàn — không phải lúc nào cũng cần chọn một bên nhưng cần thừa nhận sức kéo của cả hai.", en: "Two of Wands and Four of Pentacles: far vision pulled back by clinging — fire looking toward the horizon while earth holds tightly to what it has; tension between ambition and security — not always requiring choosing a side but acknowledging the pull of both." },
  "23_68": { vi: "Hai Gậy và Năm Tiền: kế hoạch táo bạo giữa cảnh thiếu thốn — lửa đang vạch ra tương lai rộng lớn trong khi đất đang đứng ngoài giá lạnh; đây là câu hỏi khó về việc liệu tầm nhìn dài hạn có thể tồn tại ngay cả khi những nhu cầu trước mắt chưa được đáp ứng.", en: "Two of Wands and Five of Pentacles: bold plans amid scarcity — fire mapping out the grand future while earth stands in the cold outside; the hard question of whether long-term vision can survive even when immediate needs are still unmet." },
  "23_69": { vi: "Hai Gậy và Sáu Tiền: tầm nhìn được hỗ trợ bởi sự hào phóng — lửa đang lên kế hoạch và đất đang chia sẻ nguồn lực; khi sự hào phóng và tầm nhìn cùng nhau, những ý tưởng lớn được hiện thực hóa nhanh hơn vì người có tầm nhìn không phải đi một mình.", en: "Two of Wands and Six of Pentacles: vision supported by generosity — fire planning and earth sharing resources; when generosity and vision work together, big ideas are realized faster because the visionary does not have to walk alone." },
  "23_70": { vi: "Hai Gậy và Bảy Tiền: chiến lược dài hạn và đánh giá cẩn thận — lửa đang lên kế hoạch táo bạo và đất đang kiên nhẫn đánh giá tiến độ; đây là sự kết hợp lý tưởng của tầm nhìn và sự điều chỉnh — biết nhìn xa nhưng cũng biết kiểm tra kết quả thực tế theo từng giai đoạn.", en: "Two of Wands and Seven of Pentacles: long-range strategy and careful assessment — fire planning boldly and earth patiently evaluating progress; the ideal combination of vision and adjustment — knowing how to look far but also how to check actual results at each stage." },
  "23_71": { vi: "Hai Gậy và Tám Tiền: tầm nhìn và sự tận tụy — lửa có kế hoạch và đất đang rèn giũa kỹ năng cần thiết để thực hiện nó; khi tham vọng chiến lược được hỗ trợ bởi sự luyện tập kiên định, không có khoảng cách nào giữa những gì được lên kế hoạch và những gì thực sự được xây dựng.", en: "Two of Wands and Eight of Pentacles: vision and dedication — fire holding the plan and earth honing the skills needed to execute it; when strategic ambition is backed by steadfast practice, there is no gap between what is planned and what is actually built." },
  "23_72": { vi: "Hai Gậy và Chín Tiền: kế hoạch táo bạo và sự tự túc — lửa đang nhìn ra chân trời và đất đã đạt được sự sung túc độc lập; khi người có tầm nhìn lớn cũng có đủ nguồn lực tự túc, kế hoạch của họ không bị ràng buộc bởi sự phụ thuộc vào người khác.", en: "Two of Wands and Nine of Pentacles: bold plans and self-sufficiency — fire looking toward the horizon and earth having achieved independent abundance; when the one with grand vision also has sufficient self-sufficiency, their plans are not constrained by dependence on others." },
  "23_73": { vi: "Hai Gậy và Mười Tiền: tầm nhìn hướng về di sản — lửa đang lên kế hoạch với đôi mắt nhìn về tương lai xa và đất nhắc nhở về sức nặng và tầm quan trọng của di sản; đây là sự kết hợp của tham vọng và truyền thống, khi tầm nhìn được đặt trong bối cảnh của những gì đã và sẽ tiếp nối.", en: "Two of Wands and Ten of Pentacles: vision aimed at legacy — fire planning with eyes on the far future and earth reminding of the weight and importance of heritage; ambition placed in the context of what has been and what will follow." },
  "23_74": { vi: "Hai Gậy và Trang Bị Tiền: nhà hoạch định và học trò đất — lửa có kế hoạch lớn và đất trẻ tuổi đang học cách biến kiến thức thành thực tế vật chất; đây là sự kết hợp tốt khi tầm nhìn chiến lược truyền cảm hứng cho người trẻ đang tích lũy kỹ năng để thực hiện nó.", en: "Two of Wands and Page of Pentacles: the planner and earth's student — fire holding big plans and young earth learning how to turn knowledge into material reality; a good combination when strategic vision inspires the young one accumulating skills to execute it." },
  "23_75": { vi: "Hai Gậy và Kỵ Sĩ Tiền: tầm nhìn xa và sự bền bỉ đáng tin cậy — lửa đang nhìn về chân trời và đất đang tiến lên từng bước một cách chắc chắn; khi người có tầm nhìn lớn được hỗ trợ bởi người thực thi đáng tin cậy, khoảng cách giữa kế hoạch và kết quả được thu hẹp dần đều.", en: "Two of Wands and Knight of Pentacles: far vision and reliable endurance — fire looking toward the horizon and earth advancing step by step with certainty; when the one with grand vision is supported by a reliable executor, the gap between plan and result steadily closes." },
  "23_76": { vi: "Hai Gậy và Nữ Hoàng Tiền: kế hoạch táo bạo và sự nuôi dưỡng thực tế — Nữ Hoàng Tiền không hỏi về tầm nhìn xa của lửa mà hỏi về những bước thực tế có thể thực hiện ngay bây giờ; lời khuyên thực chất của bà là thứ chuyển đổi kế hoạch trên giấy thành hiện thực sống động.", en: "Two of Wands and Queen of Pentacles: bold plans and practical nurturing — the Queen of Pentacles does not ask about fire's distant vision but about the practical steps that can be taken right now; her substantive advice is what transforms plans on paper into living reality." },
  "23_77": { vi: "Hai Gậy và Vua Tiền: tầm nhìn lửa và thẩm quyền đất — lửa đang nhìn ra thế giới với hoài bão lớn và Vua Tiền đã chứng minh rằng tham vọng đó có thể được thực hiện; bài học của Vua Tiền không phải là những gì cần mơ mà là những gì cần làm để biến giấc mơ thành tài sản thực sự.", en: "Two of Wands and King of Pentacles: fire's vision and earth's authority — fire looking at the world with great ambition and the King of Pentacles having proven that ambition can be executed; his lesson is not what to dream but what to do to transform the dream into genuine wealth." },
  "24_64": { vi: "Ba Gậy và Át Tiền: sự mở rộng và cơ hội vật chất mới — lửa đang chờ những con tàu của mình trở về và đất mang đến cơ hội cụ thể để mở rộng thêm; khi chiến lược dài hạn gặp điều kiện vật chất thuận lợi, sự tăng trưởng trở nên gần như không thể ngăn cản.", en: "Three of Wands and Ace of Pentacles: expansion and new material opportunity — fire watching for its ships to return and earth bringing a concrete opportunity to expand further; when long-range strategy meets favorable material conditions, growth becomes nearly unstoppable." },
  "24_65": { vi: "Ba Gậy và Hai Tiền: doanh nghiệp và sự linh hoạt nguồn lực — lửa đang điều hành sự mở rộng trong khi đất đang cân bằng dòng chảy của nguồn lực; đây là hình ảnh của việc quản lý doanh nghiệp thực tế nơi tầm nhìn xa phải cùng tồn tại với sự quản lý thực tế hàng ngày.", en: "Three of Wands and Two of Pentacles: enterprise and resource flexibility — fire overseeing expansion while earth balances the flow of resources; the image of practical business management where long-range vision must coexist with day-to-day practical administration." },
  "24_66": { vi: "Ba Gậy và Ba Tiền: hai con ba — sự mở rộng và sự cộng tác — lửa đang xây dựng đế chế thương mại và đất đang đưa kỹ năng và làm việc nhóm vào nó; khi tầm nhìn lớn được xây dựng bởi những người thợ thủ công tận tâm, kết quả vượt qua giới hạn của bất kỳ một cá nhân nào.", en: "Three of Wands and Three of Pentacles: two threes — expansion and collaboration — fire building a commercial empire and earth contributing skill and teamwork; when grand vision is built by dedicated craftspeople, the result exceeds the limits of any single individual." },
  "24_67": { vi: "Ba Gậy và Bốn Tiền: mở rộng gặp sự co rút — lửa đang gửi đi những con tàu để khám phá trong khi đất đang co cụm và bảo vệ những gì đang có; đây là sự căng thẳng giữa phát triển và an toàn, và câu hỏi là liệu sự sợ mất mát có đang ngăn cản sự tăng trưởng thực sự.", en: "Three of Wands and Four of Pentacles: expansion meeting contraction — fire sending ships to explore while earth huddles and protects what it has; tension between growth and safety, and the question of whether fear of loss is preventing genuine growth." },
  "24_68": { vi: "Ba Gậy và Năm Tiền: tầm nhìn xa và cơ hàn hiện tại — lửa đang nhìn về phía tương lai giàu có trong khi đất đang đứng trong giá lạnh ngay bây giờ; đây là sự căng thẳng giữa tầm nhìn dài hạn và nhu cầu ngắn hạn và sự khéo léo là tìm cách nuôi dưỡng cả hai cùng một lúc.", en: "Three of Wands and Five of Pentacles: far vision and current hardship — fire looking toward a prosperous future while earth stands in the cold right now; tension between long-term vision and short-term need, and the wisdom is finding how to nurture both simultaneously." },
  "24_69": { vi: "Ba Gậy và Sáu Tiền: sự mở rộng và sự hào phóng — lửa đang xây dựng đế chế thương mại và đất đang nhắc nhở rằng dòng chảy của sự cho và nhận là điều giữ cho cả hệ thống lưu thông; những doanh nhân vĩ đại nhất biết rằng sự hào phóng không làm giảm đi mà thường nhân lên những gì họ xây dựng.", en: "Three of Wands and Six of Pentacles: expansion and generosity — fire building its commercial empire and earth reminding that the flow of giving and receiving is what keeps the whole system circulating; the greatest entrepreneurs knowing that generosity does not diminish but usually multiplies what they build." },
  "24_70": { vi: "Ba Gậy và Bảy Tiền: tầm nhìn xa và sự đánh giá kiên nhẫn — lửa đang nhìn về tương lai và đất đang kiểm tra cẩn thận xem những gì đã được trồng có đang cho quả như kỳ vọng không; đây là sự kết hợp lý tưởng của hoạch định chiến lược và đánh giá thực tế có tính đến dài hạn.", en: "Three of Wands and Seven of Pentacles: far vision and patient assessment — fire looking toward the future and earth carefully examining whether what has been planted is yielding results as expected; the ideal combination of strategic planning and realistic evaluation accounting for the long term." },
  "24_71": { vi: "Ba Gậy và Tám Tiền: doanh nghiệp và sự tận tụy — lửa có tầm nhìn mở rộng và đất đang rèn giũa kỹ năng tỉ mỉ; khi những người thợ thủ công chuyên tâm phục vụ tầm nhìn lớn, điều được tạo ra không chỉ đạt chất lượng cao mà còn có thể mở rộng quy mô mà không mất đi bản sắc.", en: "Three of Wands and Eight of Pentacles: enterprise and dedication — fire with expanding vision and earth honing detailed skills; when dedicated craftspeople serve a grand vision, what is created is not only high quality but can scale without losing its essence." },
  "24_72": { vi: "Ba Gậy và Chín Tiền: mở rộng từ nền tảng sung túc — lửa đang gửi đi những con tàu từ bờ biển và đất đang đứng trong sự sung túc tự túc; đây là vị trí mạnh mẽ nhất để mở rộng — không từ sự thiếu thốn mà từ sự đầy đủ và sự tự tin vào những gì đã được xây dựng.", en: "Three of Wands and Nine of Pentacles: expanding from abundant foundation — fire sending ships from shore and earth standing in self-sufficient abundance; the strongest position from which to expand — not from scarcity but from fullness and confidence in what has already been built." },
  "24_73": { vi: "Ba Gậy và Mười Tiền: doanh nghiệp hướng đến di sản — lửa đang mở rộng với đôi mắt nhìn về tương lai và đất nhắc nhở về chiều sâu của những gì đang được xây dựng; những doanh nghiệp vĩ đại nhất không chỉ xây dựng cho thế hệ này mà còn để lại điều gì đó có ý nghĩa cho những thế hệ tiếp theo.", en: "Three of Wands and Ten of Pentacles: enterprise aimed at legacy — fire expanding with eyes on the future and earth reminding of the depth of what is being built; the greatest enterprises not merely building for this generation but leaving something meaningful for those that follow." },
  "24_74": { vi: "Ba Gậy và Trang Bị Tiền: doanh nghiệp truyền cảm hứng cho người học trò — lửa đang mở rộng và đất trẻ tuổi đang học hỏi chăm chỉ để trở thành một phần của điều đó; người trẻ nhìn thấy tầm nhìn của lửa và biến nó thành động lực để tích lũy kỹ năng thực tế cần thiết để đóng góp.", en: "Three of Wands and Page of Pentacles: enterprise inspiring the apprentice — fire expanding and young earth studying diligently to become part of it; the young one seeing fire's vision and transforming it into motivation to accumulate the practical skills needed to contribute." },
  "24_75": { vi: "Ba Gậy và Kỵ Sĩ Tiền: tầm nhìn xa và sự tiến lên chắc chắn — lửa đứng trên ngọn tháp nhìn ra đại dương trong khi đất tiến đều đặn từng bước một; đây là sự kết hợp của hai quan điểm thời gian cần thiết cho sự thành công thực sự — tầm nhìn xa và sự kiên trì bền bỉ.", en: "Three of Wands and Knight of Pentacles: far vision and steady advance — fire standing on the tower watching the ocean while earth advances steadily step by step; the necessary combination of two time perspectives for genuine success — far sight and persistent endurance." },
  "24_76": { vi: "Ba Gậy và Nữ Hoàng Tiền: sự mở rộng được nuôi dưỡng — lửa đang xây dựng đế chế thương mại và Nữ Hoàng Tiền đảm bảo rằng nền tảng vật chất và con người bên dưới được chăm sóc; sự thành công dài hạn của doanh nghiệp phụ thuộc vào sự quan tâm đến những chi tiết nuôi dưỡng mà bà mang lại.", en: "Three of Wands and Queen of Pentacles: expansion nurtured — fire building its commercial empire and the Queen of Pentacles ensuring the material and human foundations beneath are cared for; the long-term success of the enterprise depending on attention to the nurturing details she brings." },
  "24_77": { vi: "Ba Gậy và Vua Tiền: doanh nghiệp lửa và thẩm quyền đất — lửa đang mở rộng với tầm nhìn xa và Vua Tiền đang cai trị đế chế vật chất đã được xây dựng; khi tầm nhìn chiến lược của lửa gặp sự thành thạo kinh doanh của đất, kết quả là điều mà cả thế giới có thể nhìn thấy và kính trọng.", en: "Three of Wands and King of Pentacles: fire's enterprise and earth's authority — fire expanding with far vision and the King of Pentacles governing the material empire already built; when fire's strategic vision meets earth's business mastery, what results is something the entire world can see and respect." },
  "25_64": { vi: "Bốn Gậy và Át Tiền: lễ kỷ niệm và cơ hội vật chất mới — lửa đang ăn mừng sự ổn định và đất mang đến cơ hội cụ thể mới để phát triển từ nền tảng đó; đây là thời điểm lý tưởng để bắt đầu điều gì đó mới vì nền tảng ổn định đã có sẵn để đón nhận nó.", en: "Four of Wands and Ace of Pentacles: celebration and new material opportunity — fire celebrating stability and earth bringing a new concrete opportunity to grow from that foundation; the ideal moment to begin something new because the stable foundation is already in place to receive it." },
  "25_65": { vi: "Bốn Gậy và Hai Tiền: mái ấm và sự cân bằng tài chính — lửa đã xây dựng nơi ổn định và ấm áp trong khi đất đang quản lý các nguồn lực để giữ nơi đó hoạt động; đây là hình ảnh thực tế của cuộc sống gia đình nơi sự ấm áp cảm xúc và sự quản lý thực tế đều là cần thiết như nhau.", en: "Four of Wands and Two of Pentacles: home and financial balance — fire having built a stable warm place while earth manages resources to keep it functioning; the practical image of family life where emotional warmth and practical management are equally necessary." },
  "25_66": { vi: "Bốn Gậy và Ba Tiền: cộng đồng và sự khéo léo cộng tác — lửa tạo ra không gian để mọi người tụ họp và đất mang kỹ năng và tinh thần làm việc nhóm; khi nơi chốn ấm áp gặp kỹ năng tập thể, những điều đẹp đẽ nhất được xây dựng bởi nhiều bàn tay cùng hướng tới một mục tiêu.", en: "Four of Wands and Three of Pentacles: community and collaborative craftsmanship — fire creating the space for people to gather and earth bringing skill and teamwork spirit; when a warm place meets collective skill, the most beautiful things are built by many hands aimed at one goal." },
  "25_67": { vi: "Bốn Gậy và Bốn Tiền: hai sự ổn định — ổn định cộng đồng và ổn định vật chất; khi cả hai cùng xuất hiện, đây là nền tảng vững chắc nhất có thể — nhưng cũng là lời nhắc rằng sự ổn định quá mức có thể trở thành sự trì trệ nếu không có ai dám bước thêm một bước ra ngoài ranh giới an toàn.", en: "Four of Wands and Four of Pentacles: two stabilities — communal stability and material stability; when both appear together, the most solid foundation possible — but also a reminder that excessive stability can become stagnation if no one dares to step even one step beyond the safe boundary." },
  "25_68": { vi: "Bốn Gậy và Năm Tiền: bên trong ấm áp và bên ngoài lạnh giá — lửa đang ăn mừng trong khi ai đó đứng ngoài cửa trong sự thiếu thốn; đây là lời kêu gọi không để niềm vui của mình trở nên mù quáng trước những người đang gặp khó khăn ngay bên cạnh mình.", en: "Four of Wands and Five of Pentacles: warm inside and cold outside — fire celebrating while someone stands at the door in hardship; a call not to let one's own joy become blind to those struggling just beside." },
  "25_69": { vi: "Bốn Gậy và Sáu Tiền: cộng đồng và sự hào phóng — lửa tạo ra không gian ăn mừng và đất đang chia sẻ nguồn lực rộng rãi; khi sự hào phóng và niềm vui cộng đồng cùng nhau, không gian đó mở rộng để đón nhận nhiều người hơn và niềm vui được nhân lên.", en: "Four of Wands and Six of Pentacles: community and generosity — fire creating the celebratory space and earth sharing resources freely; when generosity and communal joy work together, that space expands to welcome more people and joy is multiplied." },
  "25_70": { vi: "Bốn Gậy và Bảy Tiền: nền tảng ổn định và sự đánh giá kiên nhẫn — lửa đã xây dựng ngôi nhà và đất đang kiên nhẫn đánh giá xem những gì đã được trồng xung quanh đó có đang phát triển như kỳ vọng không; đây là sự kết hợp của sự bảo đảm và sự tỉnh táo.", en: "Four of Wands and Seven of Pentacles: stable foundation and patient assessment — fire having built the home and earth patiently evaluating whether what has been planted around it is growing as expected; a combination of security and clear-eyed realism." },
  "25_71": { vi: "Bốn Gậy và Tám Tiền: ngôi nhà được xây dựng bởi bàn tay tận tụy — lửa tạo ra không gian ấm áp và đất đang rèn giũa từng chi tiết với sự chú tâm cao; đây là ngôi nhà không chỉ được xây dựng bằng tiền mà bằng tình yêu và sự khéo léo của người làm ra nó.", en: "Four of Wands and Eight of Pentacles: the home built by dedicated hands — fire creating the warm space and earth crafting every detail with full attention; a home built not merely with money but with the love and skill of the one who made it." },
  "25_72": { vi: "Bốn Gậy và Chín Tiền: lễ kỷ niệm và sự sung túc — lửa đang ăn mừng và đất đang đứng trong sự tự túc và giàu có; khi hai nguồn năng lượng phong phú này gặp nhau, không khí của buổi lễ trở nên thực sự sang trọng và đáng nhớ.", en: "Four of Wands and Nine of Pentacles: celebration and abundance — fire celebrating and earth standing in self-sufficiency and wealth; when these two abundant energies meet, the atmosphere of the occasion becomes genuinely luxurious and memorable." },
  "25_73": { vi: "Bốn Gậy và Mười Tiền: gia đình và di sản — lửa tạo ra nơi mọi người tụ họp và đất mang theo trọng lượng và sự giàu có của nhiều thế hệ; đây là khoảnh khắc khi ngôi nhà trở thành thứ gì đó lớn hơn — trung tâm của một câu chuyện gia đình kéo dài qua thời gian.", en: "Four of Wands and Ten of Pentacles: family and legacy — fire creating the place where people gather and earth carrying the weight and wealth of many generations; the moment when home becomes something larger — the center of a family story extending through time." },
  "25_74": { vi: "Bốn Gậy và Trang Bị Tiền: mái ấm chào đón người học trò chăm chỉ — lửa tạo ra không gian ổn định và đất trẻ tuổi đang học hỏi chăm chỉ để xây dựng điều gì đó tương tự; đây là sự kết hợp của sự an toàn và tham vọng — một môi trường nơi người trẻ có thể học hỏi và phát triển.", en: "Four of Wands and Page of Pentacles: home welcoming the diligent student — fire creating the stable space and young earth studying hard to build something similar; a combination of security and ambition — an environment where the young one can learn and grow." },
  "25_75": { vi: "Bốn Gậy và Kỵ Sĩ Tiền: sự ổn định và sự đáng tin cậy — lửa đã xây dựng nơi ấm áp và đất đang tiến lên đều đặn để bảo vệ và phục vụ nó; khi sự ổn định của lửa và sự đáng tin cậy của đất kết hợp, cộng đồng có được thứ quý giá nhất: niềm tin.", en: "Four of Wands and Knight of Pentacles: stability and reliability — fire having built the warm place and earth advancing steadily to protect and serve it; when fire's stability and earth's reliability combine, the community gains the most precious thing: trust." },
  "25_76": { vi: "Bốn Gậy và Nữ Hoàng Tiền: mái ấm và sự chăm sóc thực tế — lửa tạo ra không gian ấm áp và Nữ Hoàng Tiền đảm bảo rằng mọi nhu cầu thực tế của những người trong đó đều được đáp ứng; đây là sự kết hợp của nhiệt tình cộng đồng và sự nuôi dưỡng có căn cứ thực tế.", en: "Four of Wands and Queen of Pentacles: home and practical care — fire creating the warm space and the Queen of Pentacles ensuring every practical need of those within it is met; a combination of communal enthusiasm and practically grounded nurturing." },
  "25_77": { vi: "Bốn Gậy và Vua Tiền: cộng đồng và thẩm quyền vật chất — lửa tạo ra nơi mọi người tụ họp và Vua Tiền mang sự thịnh vượng và sự ổn định tài chính để giữ cho nơi đó tồn tại lâu dài; đây là sự kết hợp của hồn và tài nguyên trong việc xây dựng điều gì đó thực sự bền vững.", en: "Four of Wands and King of Pentacles: community and material authority — fire creating the gathering place and the King of Pentacles bringing the prosperity and financial stability to keep it enduring; a combination of soul and resources in building something genuinely lasting." },
  "26_64": { vi: "Năm Gậy và Át Tiền: hỗn loạn và cơ hội vật chất mới — sự tranh cãi và cạnh tranh của lửa bị gián đoạn bởi một cơ hội cụ thể từ đất; đôi khi một cơ hội mới xuất hiện ngay giữa hỗn loạn là tín hiệu để dừng tranh cãi và cùng hướng về điều gì đó xứng đáng hơn.", en: "Five of Wands and Ace of Pentacles: chaos and new material opportunity — fire's conflict and competition interrupted by a concrete opportunity from earth; sometimes a new opportunity appearing right amid chaos is the signal to stop arguing and point toward something more worthy together." },
  "26_65": { vi: "Năm Gậy và Hai Tiền: tranh cãi và sự tung hứng nguồn lực — lửa đang đánh nhau trong khi đất đang cố gắng duy trì sự cân bằng; khi sự hỗn loạn bên ngoài kết hợp với sự cân bằng mong manh về tài chính, áp lực tích lũy đến mức cần ai đó đủ khôn ngoan để nhường bước.", en: "Five of Wands and Two of Pentacles: conflict and resource juggling — fire fighting while earth tries to maintain balance; when outer chaos combines with fragile financial balance, pressure accumulates to the point where someone wise enough to yield is needed." },
  "26_66": { vi: "Năm Gậy và Ba Tiền: hỗn loạn và trật tự cộng tác — lửa đang tranh cãi vô tổ chức trong khi đất đang làm việc theo nhóm có phương pháp; đây là sự đối lập của hai cách tiếp cận tập thể và lời nhắc rằng tinh thần cạnh tranh không lành mạnh phá hủy những gì sự hợp tác chân thực có thể xây dựng.", en: "Five of Wands and Three of Pentacles: chaos and collaborative order — fire arguing without organization while earth works in methodical teamwork; the opposition of two collective approaches and a reminder that unhealthy competition destroys what genuine collaboration can build." },
  "26_67": { vi: "Năm Gậy và Bốn Tiền: xung đột và sự bám víu — lửa đang chiến đấu vì tài nguyên hoặc địa vị trong khi đất đang ôm chặt những gì mình có; khi cả sự tranh giành và sự bảo vệ quá mức cùng hoạt động, không khí tích lũy đến mức không ai có thể tiến về phía trước một cách tự nhiên.", en: "Five of Wands and Four of Pentacles: conflict and clinging — fire fighting for resources or status while earth clutches what it has; when both grabbing and over-protecting operate together, the atmosphere accumulates to where no one can move forward naturally." },
  "26_68": { vi: "Năm Gậy và Năm Tiền: hai con năm — xung đột chồng lên thiếu thốn; lửa đang tranh cãi về những mảnh vụn trong khi đất đang đứng ngoài giá lạnh; đây là hình ảnh của sự nghèo khó cả vật chất lẫn tinh thần và lời kêu gọi nhận ra rằng cả hai bên đều thua trong cuộc chiến này.", en: "Five of Wands and Five of Pentacles: two fives — conflict piled upon scarcity; fire arguing over scraps while earth stands in the cold outside; the image of poverty both material and spiritual, and a call to recognize that both sides are losing in this battle." },
  "26_69": { vi: "Năm Gậy và Sáu Tiền: hỗn loạn và sự hào phóng — đất đang chia sẻ nguồn lực một cách hào phóng trong khi lửa đang tranh cãi; đây là sự kết hợp thú vị khi sự hào phóng có thể cắt đứt sự xung đột bằng cách thay đổi hoàn toàn bản chất của câu hỏi đang được tranh cãi.", en: "Five of Wands and Six of Pentacles: chaos and generosity — earth sharing resources generously while fire is arguing; an interesting combination where generosity can cut through conflict by completely changing the nature of the question being disputed." },
  "26_70": { vi: "Năm Gậy và Bảy Tiền: tranh cãi và sự đánh giá kiên nhẫn — lửa đang tranh cãi về kết quả trong khi đất đang kiên nhẫn đánh giá những gì thực sự đang mọc lên; đây là sự tương phản của hai cách nhìn và lời nhắc rằng câu trả lời thực sự không nằm trong cuộc tranh luận mà trong những bằng chứng từ thực tế.", en: "Five of Wands and Seven of Pentacles: conflict and patient assessment — fire arguing about results while earth patiently evaluates what is actually growing; the contrast of two ways of seeing and a reminder that the real answer lies not in the argument but in the evidence from reality." },
  "26_71": { vi: "Năm Gậy và Tám Tiền: hỗn loạn và sự tập trung — lửa đang bị lôi cuốn vào mọi hướng trong khi đất đang tập trung vào một kỹ năng; đây là lời nhắc mạnh mẽ rằng người đang cúi đầu và làm việc chăm chỉ thường tiến xa hơn người đang tranh cãi về ai giỏi nhất.", en: "Five of Wands and Eight of Pentacles: chaos and focus — fire being pulled in every direction while earth concentrates on one skill; a powerful reminder that the one keeping their head down and working diligently usually progresses further than the one arguing about who is best." },
  "26_72": { vi: "Năm Gậy và Chín Tiền: tranh cãi và sự tự túc — lửa đang chiến đấu trong khi đất đứng trong vẻ đẹp của sự tự túc; Chín Tiền nhắc nhở rằng sự giàu có thực sự không phải là kết quả của việc đánh bại người khác mà của việc trồng và chăm sóc điều của riêng mình.", en: "Five of Wands and Nine of Pentacles: conflict and self-sufficiency — fire fighting while earth stands in the beauty of self-sufficiency; the Nine of Pentacles reminding that true wealth is not the result of defeating others but of planting and tending what is one's own." },
  "26_73": { vi: "Năm Gậy và Mười Tiền: cạnh tranh làm xói mòn di sản — lửa đang tranh giành trong khi đất mang trọng lượng của những gì nhiều thế hệ đã xây dựng; đây là lời cảnh báo rằng những cuộc chiến tranh vặt và sự cạnh tranh không lành mạnh có thể phá hủy những gì cần nhiều thế hệ để xây dựng.", en: "Five of Wands and Ten of Pentacles: competition eroding legacy — fire scrambling while earth carries the weight of what many generations have built; a warning that petty battles and unhealthy competition can destroy what took generations to construct." },
  "26_74": { vi: "Năm Gậy và Trang Bị Tiền: hỗn loạn xung quanh người học trò chăm chỉ — lửa đang tranh cãi và đất trẻ tuổi đang cúi đầu học hỏi; đây là hình ảnh của người trẻ thông minh biết rằng thời gian dùng để học hỏi thực sự có giá trị hơn thời gian dùng để tranh cãi về ai thông minh nhất.", en: "Five of Wands and Page of Pentacles: chaos around the diligent student — fire arguing and young earth keeping its head down and learning; the image of the wise young one knowing that time spent actually learning is more valuable than time spent arguing about who is smartest." },
  "26_75": { vi: "Năm Gậy và Kỵ Sĩ Tiền: hỗn loạn và sự bền bỉ — lửa đang tranh cãi tứ phía trong khi đất tiến lên chậm rãi và đáng tin cậy; kỵ sĩ tiền không tham gia vào cuộc tranh cãi mà tiếp tục tiến lên và thường chính sự bền bỉ đó là thứ cuối cùng đạt được mục tiêu.", en: "Five of Wands and Knight of Pentacles: chaos and endurance — fire arguing on all sides while earth advances slowly and reliably; the pentacles knight does not join the dispute but keeps moving forward, and it is usually that endurance that ultimately reaches the goal." },
  "26_76": { vi: "Năm Gậy và Nữ Hoàng Tiền: hỗn loạn gặp sự chăm sóc thực tế — Nữ Hoàng Tiền không bị cuốn vào cuộc tranh cãi của lửa mà tập trung vào những gì thực sự cần được chăm sóc; đôi khi người thực tế nhất trong phòng là người đứng ngoài cuộc tranh cãi và lo việc thực tế.", en: "Five of Wands and Queen of Pentacles: chaos meeting practical care — the Queen of Pentacles not being drawn into fire's argument but focusing on what actually needs tending; sometimes the most practical person in the room is the one who stands outside the argument and attends to what is real." },
  "26_77": { vi: "Năm Gậy và Vua Tiền: xung đột gặp thẩm quyền vật chất — Vua Tiền không tham gia vào cuộc tranh cãi nhỏ nhặt của lửa nhưng sự hiện diện của thẩm quyền tài chính và doanh nghiệp của ông đủ để thay đổi toàn bộ bầu khí quyển; không ai muốn tranh cãi khi người có đủ uy quyền và tài nguyên đang chú ý.", en: "Five of Wands and King of Pentacles: conflict meeting material authority — the King of Pentacles does not engage in fire's petty dispute but his presence of financial and business authority is enough to change the entire atmosphere; no one wishes to argue when one with sufficient authority and resources is paying attention." },
  "27_64": { vi: "Sáu Gậy và Át Tiền: chiến thắng và cơ hội vật chất mới — lửa đang được tôn vinh và đất mang đến cơ hội cụ thể để xây dựng trên nền tảng thành công đó; đây là khoảnh khắc khi sự công nhận bên ngoài và cơ hội vật chất cùng xuất hiện, tạo ra bệ phóng lý tưởng.", en: "Six of Wands and Ace of Pentacles: victory and new material opportunity — fire being honored and earth bringing a concrete opportunity to build on that success; the moment when external recognition and material opportunity appear together, creating the ideal launching point." },
  "27_65": { vi: "Sáu Gậy và Hai Tiền: thành công và sự quản lý linh hoạt — lửa đang ở đỉnh cao trong khi đất đang tung hứng nhiều thứ cùng lúc; chiến thắng không loại bỏ nhu cầu quản lý thực tế và người thành công thực sự là người biết rằng cả hai đều phải được duy trì cùng một lúc.", en: "Six of Wands and Two of Pentacles: success and flexible management — fire at the peak while earth juggles many things at once; victory does not eliminate the need for practical management and the truly successful one knows both must be maintained simultaneously." },
  "27_66": { vi: "Sáu Gậy và Ba Tiền: công nhận và kỹ năng cộng tác — lửa được tôn vinh và đất nhắc nhở rằng những thành tựu lớn hiếm khi là kết quả của một mình; sự công nhận tốt nhất không chỉ vinh danh người đứng đầu mà còn nhận ra những người thợ thủ công đã làm cho chiến thắng đó trở nên có thể.", en: "Six of Wands and Three of Pentacles: recognition and collaborative skill — fire being honored and earth reminding that great achievements are rarely the result of one person alone; the best recognition honors not only the one at the front but also the craftspeople who made that victory possible." },
  "27_67": { vi: "Sáu Gậy và Bốn Tiền: vinh quang và sự bám víu — lửa đang ăn mừng chiến thắng trong khi đất đang ôm chặt những gì mình có; đây là lời nhắc rằng sự thành công thực sự đòi hỏi cả sự dũng cảm để tận hưởng chiến thắng lẫn sự khôn ngoan để không trở nên bị ràng buộc bởi nỗi sợ mất đi nó.", en: "Six of Wands and Four of Pentacles: glory and clinging — fire celebrating victory while earth clutches what it has; a reminder that true success requires both courage to enjoy the victory and wisdom not to become bound by fear of losing it." },
  "27_68": { vi: "Sáu Gậy và Năm Tiền: thành công công khai và khó khăn riêng tư — lửa được đám đông tôn vinh trong khi đất đang đứng ngoài giá lạnh; đây là sự nhắc nhở rằng thành công nhìn thấy được không phải lúc nào cũng phản ánh tình trạng thực sự bên trong và bên ngoài của một người.", en: "Six of Wands and Five of Pentacles: public success and private hardship — fire celebrated by the crowd while earth stands in the cold outside; a reminder that visible success does not always reflect someone's true situation inside and out." },
  "27_69": { vi: "Sáu Gậy và Sáu Tiền: chiến thắng và sự hào phóng — lửa đứng trên đỉnh cao và đất đang chia sẻ rộng rãi; đây là sự kết hợp đẹp nhất — người chiến thắng sử dụng thành công của mình để tạo ra dòng chảy hào phóng cho cộng đồng xung quanh mình.", en: "Six of Wands and Six of Pentacles: victory and generosity — fire standing at the peak and earth sharing widely; the most beautiful combination — the victor using their success to create a generous flow for the community around them." },
  "27_70": { vi: "Sáu Gậy và Bảy Tiền: chiến thắng và sự đánh giá dài hạn — lửa đang ăn mừng kết quả và đất đang kiểm tra cẩn thận xem những gì đã được đầu tư đang cho ra thành quả như thế nào; đây là sự kết hợp của sự ăn mừng và sự tỉnh táo — chiến thắng hôm nay không thể thay thế cho việc đánh giá lại chiến lược dài hạn.", en: "Six of Wands and Seven of Pentacles: victory and long-term assessment — fire celebrating results and earth carefully examining how what has been invested is yielding; celebration and clear-headedness — today's victory cannot replace reassessing long-term strategy." },
  "27_71": { vi: "Sáu Gậy và Tám Tiền: thành công được xây dựng bằng sự tận tụy — lửa đứng ở đỉnh cao và đất nhắc nhở về những giờ luyện tập tỉ mỉ tạo ra thành công đó; sự công nhận là xứng đáng khi nó đến từ công việc thực sự và người chiến thắng thực sự nhớ điều đó.", en: "Six of Wands and Eight of Pentacles: success built through dedication — fire standing at the peak and earth reminding of the painstaking practice hours that created that success; recognition is deserved when it comes from genuine work and the true winner remembers this." },
  "27_72": { vi: "Sáu Gậy và Chín Tiền: vinh quang và sự sung túc — hai nguồn năng lượng phong phú; lửa đang được tôn vinh và đất đứng trong sự tự túc và giàu có; khi thành công bên ngoài và sự sung túc bên trong cùng tồn tại, đây là sự hoàn chỉnh hiếm có nhất.", en: "Six of Wands and Nine of Pentacles: glory and abundance — two abundant energies; fire being celebrated and earth standing in self-sufficiency and wealth; when external success and inner abundance coexist, this is the rarest form of completeness." },
  "27_73": { vi: "Sáu Gậy và Mười Tiền: chiến thắng và di sản — lửa đứng trong ánh hào quang của sự công nhận và đất mang trọng lượng của những thế hệ; đây là câu hỏi liệu chiến thắng này có thêm vào câu chuyện gia đình hoặc di sản hay không, và nếu có thì theo cách nào.", en: "Six of Wands and Ten of Pentacles: triumph and legacy — fire standing in the glow of recognition and earth carrying the weight of generations; the question of whether this victory adds to the family story or legacy, and if so, in what way." },
  "27_74": { vi: "Sáu Gậy và Trang Bị Tiền: chiến thắng truyền cảm hứng cho người học trò — lửa được tôn vinh và đất trẻ tuổi đang quan sát và học hỏi điều gì dẫn đến thành công đó; người trẻ nhìn chiến thắng không phải để ngưỡng mộ mà để hiểu con đường thực tế đã tạo ra nó.", en: "Six of Wands and Page of Pentacles: victory inspiring the student — fire being honored and young earth watching and learning what led to that success; the young one looking at victory not to admire but to understand the practical path that created it." },
  "27_75": { vi: "Sáu Gậy và Kỵ Sĩ Tiền: vinh quang và sự bền bỉ — lửa đứng ở đỉnh cao của sự công nhận và đất đang tiến lên đều đặn hướng tới chiến thắng của chính mình; đây là sự tương phản của hai phong cách — một đã đến và một đang trên đường — và cả hai đều xứng đáng theo cách riêng của mình.", en: "Six of Wands and Knight of Pentacles: glory and endurance — fire standing at the peak of recognition and earth steadily advancing toward its own victory; the contrast of two styles — one who has arrived and one who is on the way — both worthy in their own right." },
  "27_76": { vi: "Sáu Gậy và Nữ Hoàng Tiền: thành công và sự nuôi dưỡng thực tế — lửa đứng trong ánh hào quang và Nữ Hoàng Tiền đang lo lắng về những điều cụ thể cần được chăm sóc để duy trì thành công đó; sự công nhận của đám đông là thoáng qua nhưng nền tảng vật chất vững chắc là thứ giữ cho thành công tồn tại lâu dài.", en: "Six of Wands and Queen of Pentacles: success and practical nurturing — fire in the glow of glory and the Queen of Pentacles attending to the concrete things that need caring for to sustain that success; the crowd's recognition is fleeting but a solid material foundation is what keeps success lasting." },
  "27_77": { vi: "Sáu Gậy và Vua Tiền: vinh quang lửa và thịnh vượng đất — hai dạng thành công gặp nhau; lửa được tôn vinh vì những gì mình đã đạt được và đất cai trị đế chế vật chất đã xây dựng; khi cả hai gặp nhau, đây là điểm cao nhất của thành công có thể đo lường bằng bất kỳ thước đo nào.", en: "Six of Wands and King of Pentacles: fire's glory and earth's prosperity — two forms of success meeting; fire honored for what it has achieved and earth governing the material empire built; when both meet, this is the highest point of success measurable by any standard." },
  "28_64": { vi: "Bảy Gậy và Át Tiền: phòng thủ và cơ hội vật chất mới — lửa đứng vững bảo vệ lập trường và đất mang đến cơ hội mới; đây là lời nhắc rằng ngay cả trong khi chiến đấu để bảo vệ điều mình tin, vẫn cần để mắt đến những cơ hội mới xuất hiện ở rìa của tầm nhìn.", en: "Seven of Wands and Ace of Pentacles: defense and new material opportunity — fire standing firm defending its position and earth bringing a new opportunity; a reminder that even while fighting to protect what one believes in, one must still watch for new opportunities appearing at the edge of vision." },
  "28_65": { vi: "Bảy Gậy và Hai Tiền: đứng vững và cân bằng nguồn lực — lửa đang phòng thủ trong khi đất đang tung hứng nhiều thứ cùng lúc; đây là hình ảnh của sự căng thẳng kép khi cả việc giữ vững lập trường và quản lý nguồn lực đều đòi hỏi sự chú ý tối đa.", en: "Seven of Wands and Two of Pentacles: standing firm and balancing resources — fire defending while earth juggles multiple things; the image of double tension when both holding ground and managing resources demand maximum attention simultaneously." },
  "28_66": { vi: "Bảy Gậy và Ba Tiền: phòng thủ và sự cộng tác khéo léo — lửa đang chiến đấu một mình trong khi đất đang làm việc theo nhóm có tổ chức; đây là lời nhắc nhở quan trọng rằng đôi khi sức mạnh thực sự không phải là đứng một mình mà là biết cách xây dựng liên minh và làm việc cùng những người tài năng.", en: "Seven of Wands and Three of Pentacles: defense and skilled collaboration — fire fighting alone while earth works in organized teamwork; an important reminder that sometimes real strength is not standing alone but knowing how to build alliances and work alongside talented people." },
  "28_67": { vi: "Bảy Gậy và Bốn Tiền: hai dạng bảo vệ — lửa đứng vững bảo vệ lập trường của mình và đất ôm chặt bảo vệ tài sản của mình; cả hai đều đang bảo vệ nhưng theo những cách khác nhau và lời nhắc là hỏi xem điều nào đang được bảo vệ thực sự xứng đáng với chi phí đó.", en: "Seven of Wands and Four of Pentacles: two forms of protection — fire standing firm defending its position and earth holding tight protecting its assets; both defending but in different ways, and the reminder is to ask whether what is being protected is truly worth the cost." },
  "28_68": { vi: "Bảy Gậy và Năm Tiền: bảo vệ điều ít ỏi — lửa đứng vững bảo vệ lập trường trong khi đất đang đứng trong sự thiếu thốn; đây là hình ảnh của người đang chiến đấu để bảo vệ điều ít ỏi còn lại và lời nhắc rằng đôi khi sức mạnh thực sự là nhận ra cần tìm kiếm sự giúp đỡ.", en: "Seven of Wands and Five of Pentacles: defending the little that remains — fire holding firm while earth stands in hardship; the image of one fighting to protect what little is left, and a reminder that sometimes real strength is recognizing the need to seek help." },
  "28_69": { vi: "Bảy Gậy và Sáu Tiền: phòng thủ và sự hào phóng — lửa đang đứng vững bảo vệ và đất đang chia sẻ nguồn lực rộng rãi; đây là sự kết hợp bất ngờ nhắc nhở rằng đôi khi điều tốt nhất có thể làm để bảo vệ điều mình tin là chia sẻ nó rộng rãi hơn, không giữ nó chặt hơn.", en: "Seven of Wands and Six of Pentacles: defense and generosity — fire standing firm to protect and earth sharing resources widely; a surprising combination reminding that sometimes the best way to protect what one believes in is to share it more widely, not hold it more tightly." },
  "28_70": { vi: "Bảy Gậy và Bảy Tiền: hai con bảy — phòng thủ và kiên nhẫn; lửa đứng giữ vị trí và đất đang kiên nhẫn đánh giá những gì đang phát triển; cả hai đều cần thời gian và cả hai đều đòi hỏi sự kiên định — một trong cuộc chiến và một trong sự chăm sóc dài hạn.", en: "Seven of Wands and Seven of Pentacles: two sevens — defense and patience; fire holding position and earth patiently assessing what is growing; both requiring time and both demanding steadiness — one in battle and one in long-term tending." },
  "28_71": { vi: "Bảy Gậy và Tám Tiền: phòng thủ và làm việc tận tụy — lửa đang đứng vững bảo vệ trong khi đất đang cúi đầu rèn giũa kỹ năng; đây là sự kết hợp của hai loại kiên trì — một bảo vệ những gì đang có và một xây dựng những gì sẽ tạo ra sức mạnh tương lai.", en: "Seven of Wands and Eight of Pentacles: defense and dedicated work — fire holding firm while earth bows its head honing skills; a combination of two kinds of perseverance — one protecting what exists and one building what will create future strength." },
  "28_72": { vi: "Bảy Gậy và Chín Tiền: bảo vệ sự sung túc — lửa đứng vững để không ai có thể lấy đi những gì đất đã xây dựng; người đã đạt được sự sung túc tự túc cũng cần đủ can đảm để bảo vệ nó trước những ai muốn chiếm lấy những gì không thuộc về họ.", en: "Seven of Wands and Nine of Pentacles: protecting abundance — fire standing firm so no one can take what earth has built; one who has achieved self-sufficient abundance also needs the courage to protect it from those who would take what does not belong to them." },
  "28_73": { vi: "Bảy Gậy và Mười Tiền: bảo vệ di sản — lửa đứng canh gác trước những gì đất đã xây dựng qua nhiều thế hệ; đây là một trong những lý do xứng đáng nhất để chiến đấu — bảo vệ không chỉ những gì hiện tại mà còn những gì cha mẹ và tổ tiên đã đầu tư và những gì con cái sẽ thừa kế.", en: "Seven of Wands and Ten of Pentacles: protecting the legacy — fire standing guard before what earth has built across generations; one of the most worthy reasons to fight — protecting not only what is present but what parents and ancestors invested and what children will inherit." },
  "28_74": { vi: "Bảy Gậy và Trang Bị Tiền: người bảo vệ và người học trò — lửa đứng vững và đất trẻ tuổi đang học cách xây dựng; đây là sự kết hợp tốt khi người bảo vệ không chỉ bảo vệ điều hiện tại mà còn tạo ra không gian an toàn cho người trẻ học hỏi và phát triển.", en: "Seven of Wands and Page of Pentacles: the defender and the student — fire standing firm and young earth learning how to build; a good combination when the defender is not only protecting what exists but also creating a safe space for the young one to learn and grow." },
  "28_75": { vi: "Bảy Gậy và Kỵ Sĩ Tiền: hai người bảo vệ từ hai nguyên tố — lửa đứng vững và đất tiến lên đều đặn; khi cả hai cùng bảo vệ điều gì đó, họ làm điều đó theo những cách bổ sung nhau — lửa với sự quyết tâm hiển thị và đất với sự kiên định thầm lặng.", en: "Seven of Wands and Knight of Pentacles: two defenders from two elements — fire standing firm and earth advancing steadily; when both defend something together, they do so in complementary ways — fire with visible determination and earth with quiet steadiness." },
  "28_76": { vi: "Bảy Gậy và Nữ Hoàng Tiền: phòng thủ và sự nuôi dưỡng thực tế — lửa đứng canh gác bên ngoài và Nữ Hoàng Tiền chăm sóc mọi thứ bên trong; đây là sự phân công tốt nhất — người bảo vệ và người nuôi dưỡng mỗi người làm điều mình giỏi nhất để cộng đồng phát triển toàn diện.", en: "Seven of Wands and Queen of Pentacles: defense and practical nurturing — fire standing guard outside and the Queen of Pentacles tending everything within; the best division of roles — the defender and the nurturer each doing what they do best so the community can thrive fully." },
  "28_77": { vi: "Bảy Gậy và Vua Tiền: lập trường lửa trước thẩm quyền đất — lửa đứng vững bảo vệ điều mình tin và Vua Tiền có quyền lực vật chất và tài chính để đánh giá liệu điều đó có xứng đáng với cuộc chiến không; khi thẩm quyền vật chất đứng về phía người bảo vệ, lập trường đó trở nên bất khả xâm phạm.", en: "Seven of Wands and King of Pentacles: fire's stand before earth's authority — fire holding firm defending what it believes and the King of Pentacles holding material and financial power to assess whether it is worth the fight; when material authority stands with the defender, that position becomes unassailable." },
  // ── Tier 5c-2: Wands × Pentacles, fire×earth (Wands 29–35 × Pentacles 64–77, 98 pairs) ──
  "29_64": { vi: "Tám Gậy và Át Tiền: tốc độ lửa gặp khởi đầu đất — tin tức và hành động nhanh mở ra cơ hội vật chất mới; khi Tám Gậy đến cùng Át Tiền, khoảnh khắc hành động chính là khoảnh khắc gieo hạt giống cho thịnh vượng.", en: "Eight of Wands and Ace of Pentacles: fire's speed meets earth's beginning — swift news and action opening a new material opportunity; when the Eight of Wands arrives with the Ace of Pentacles, the moment of action is the moment of planting the seed of prosperity." },
  "29_65": { vi: "Tám Gậy và Hai Tiền: tốc độ lửa gặp sự cân bằng đất — hành động nhanh có thể làm xáo trộn sự cân bằng mà Hai Tiền đang duy trì; thách thức là tiến nhanh trong khi vẫn giữ được sự linh hoạt cần thiết để quản lý nhiều trách nhiệm cùng lúc.", en: "Eight of Wands and Two of Pentacles: fire's speed meets earth's balance — swift action can disrupt the equilibrium the Two of Pentacles is maintaining; the challenge is moving quickly while still keeping the flexibility needed to juggle multiple responsibilities at once." },
  "29_66": { vi: "Tám Gậy và Ba Tiền: tốc độ và sự cộng tác — lửa đẩy tiến độ và đất xây dựng chất lượng; khi cả hai cùng xuất hiện, dự án có thể tiến nhanh mà không mất chất lượng thủ công nếu nhóm phối hợp tốt và mỗi người làm phần việc của mình.", en: "Eight of Wands and Three of Pentacles: speed and collaboration — fire pushing progress and earth building quality; when both appear, projects can move fast without losing craftsmanship quality if the team coordinates well and each person does their part." },
  "29_67": { vi: "Tám Gậy và Bốn Tiền: tốc độ lửa gặp sự kiểm soát đất — hành động nhanh va chạm với người đang giữ chặt những gì họ có; đây có thể là căng thẳng giữa cơ hội đang bay qua và sự thận trọng quá mức ngăn cản việc nắm bắt nó.", en: "Eight of Wands and Four of Pentacles: fire's speed meets earth's control — swift action colliding with someone holding tightly to what they have; this can be the tension between an opportunity flying past and excessive caution preventing it from being grasped." },
  "29_68": { vi: "Tám Gậy và Năm Tiền: hành động nhanh trong hoàn cảnh thiếu thốn — lửa muốn tiến nhanh nhưng đất đang trải qua khó khăn vật chất; khi cả hai xuất hiện, câu hỏi là liệu hành động nhanh chóng này có thể tạo ra lối thoát khỏi tình trạng thiếu thốn hay sẽ chỉ làm tình hình tệ hơn.", en: "Eight of Wands and Five of Pentacles: swift action amid material hardship — fire wanting to move fast while earth is experiencing material difficulty; when both appear, the question is whether this quick action can create an exit from scarcity or will only make things worse." },
  "29_69": { vi: "Tám Gậy và Sáu Tiền: tốc độ lửa gặp sự hào phóng đất — hành động nhanh kết hợp với sự chia sẻ nguồn lực có thể tạo ra làn sóng tích cực; tin tức về sự hỗ trợ đến nhanh, hoặc việc hành động ngay lập tức là cách tốt nhất để giúp đỡ người khác.", en: "Eight of Wands and Six of Pentacles: fire's speed meets earth's generosity — swift action combined with sharing resources can create positive waves; news of support arriving quickly, or taking immediate action being the best way to help others." },
  "29_70": { vi: "Tám Gậy và Bảy Tiền: tốc độ lửa gặp sự kiên nhẫn đất — đây là căng thẳng giữa muốn tiến nhanh và hiểu rằng một số kết quả tốt cần thời gian để chín muồi; bài học là biết khi nào nên đẩy nhanh và khi nào nên để mọi thứ phát triển theo nhịp tự nhiên.", en: "Eight of Wands and Seven of Pentacles: fire's speed meets earth's patience — the tension between wanting to move fast and understanding that some good outcomes need time to ripen; the lesson is knowing when to accelerate and when to let things develop at their natural pace." },
  "29_71": { vi: "Tám Gậy và Tám Tiền: tốc độ gặp sự chuyên tâm — lửa tiến nhanh và đất rèn giũa kỹ năng; khi cả hai cùng xuất hiện, đây là gợi ý về việc đẩy nhanh sự phát triển chuyên môn — thực hành tập trung kết hợp với đà tiến mạnh có thể nâng cao kỹ năng rất nhanh.", en: "Eight of Wands and Eight of Pentacles: speed meets dedication — fire moving fast and earth honing skills; when both appear, a suggestion about accelerating professional development — focused practice combined with strong momentum can elevate skills very quickly." },
  "29_72": { vi: "Tám Gậy và Chín Tiền: tốc độ lửa gặp sự độc lập đất — hành động nhanh có thể dẫn đến thịnh vượng tự lập; tin tức tốt đến và nó liên quan đến tài chính, sự tự túc, hoặc một bước tiến quan trọng hướng đến cuộc sống mà mình đã xây dựng một mình.", en: "Eight of Wands and Nine of Pentacles: fire's speed meets earth's independence — swift action can lead to self-made prosperity; good news arriving and it relates to finances, self-sufficiency, or an important step toward the life one has built alone." },
  "29_73": { vi: "Tám Gậy và Mười Tiền: tốc độ lửa gặp di sản đất — hành động nhanh có tác động đến gia đình hoặc di sản lâu dài; tin tức liên quan đến tài sản gia đình, thừa kế, hoặc sự kiện quan trọng trong cộng đồng đến nhanh và đòi hỏi phản ứng kịp thời.", en: "Eight of Wands and Ten of Pentacles: fire's speed meets earth's legacy — swift action impacting family or long-term legacy; news regarding family property, inheritance, or an important community event arriving quickly and demanding a timely response." },
  "29_74": { vi: "Tám Gậy và Trang Bị Tiền: tốc độ lửa gặp sự tò mò đất — hành động nhanh có thể là lúc để người trẻ hoặc người mới bắt đầu nhảy vào cơ hội học hỏi; tin tức về chương trình học, học bổng, hoặc cơ hội thực tập có thể đến bất ngờ và cần quyết định nhanh.", en: "Eight of Wands and Page of Pentacles: fire's speed meets earth's curiosity — swift action may be the moment for a young or new person to jump into a learning opportunity; news about programs, scholarships, or internship opportunities may arrive unexpectedly and require quick decisions." },
  "29_75": { vi: "Tám Gậy và Kỵ Sĩ Tiền: tốc độ lửa gặp sự kiên định đất — hai loại tiến lên cùng xuất hiện: lửa tiến nhanh và đất tiến chắc; kết hợp lý tưởng là lấy tốc độ của Tám Gậy nhưng duy trì sự kỹ lưỡng của Kỵ Sĩ Tiền để đảm bảo không bỏ sót chi tiết quan trọng.", en: "Eight of Wands and Knight of Pentacles: fire's speed meets earth's steadiness — two types of forward movement appearing together: fire advancing fast and earth advancing sure; the ideal blend is taking the Eight of Wands's speed while maintaining the Knight of Pentacles's thoroughness to ensure no important detail is missed." },
  "29_76": { vi: "Tám Gậy và Nữ Hoàng Tiền: tốc độ lửa gặp sự nuôi dưỡng đất — hành động nhanh được định hướng bởi sự thực tế ấm áp; Nữ Hoàng Tiền có thể giúp hướng đà tiến nhanh chóng vào những nơi nó thực sự tạo ra sự khác biệt vật chất và cảm xúc cho những người xung quanh.", en: "Eight of Wands and Queen of Pentacles: fire's speed meets earth's nurturing — swift action guided by warm practicality; the Queen of Pentacles can help channel rapid momentum into places where it genuinely makes a material and emotional difference for those around." },
  "29_77": { vi: "Tám Gậy và Vua Tiền: tốc độ lửa gặp thẩm quyền đất — hành động nhanh trong lĩnh vực tài chính hoặc vật chất dưới sự giám sát của người có kinh nghiệm; Vua Tiền có thể nhanh chóng đánh giá xem hành động nhanh này là cơ hội thực sự hay chỉ là vội vàng không cần thiết.", en: "Eight of Wands and King of Pentacles: fire's speed meets earth's authority — swift action in financial or material domains under the oversight of an experienced person; the King of Pentacles can quickly assess whether this rapid action is a genuine opportunity or merely unnecessary haste." },
  "30_64": { vi: "Chín Gậy và Át Tiền: sức chịu đựng lửa gặp khởi đầu đất — người đã qua nhiều thử thách đang đứng trước cơ hội vật chất mới; Chín Gậy mang sức mạnh của kinh nghiệm và Át Tiền hứa hẹn một khởi đầu mới, và kết hợp này nói rằng người đã đấu tranh xứng đáng với phần thưởng.", en: "Nine of Wands and Ace of Pentacles: fire's endurance meets earth's beginning — someone who has faced many trials standing before a new material opportunity; the Nine of Wands brings the strength of experience and the Ace of Pentacles promises a fresh start, and together they say the one who has fought deserves the reward." },
  "30_65": { vi: "Chín Gậy và Hai Tiền: sức chịu đựng lửa gặp sự cân bằng đất — người mệt mỏi nhưng vẫn đứng vững đang phải duy trì sự cân bằng giữa nhiều thứ; thách thức là không để sự kiệt sức làm mất đi sự linh hoạt cần thiết để quản lý cuộc sống hằng ngày một cách hiệu quả.", en: "Nine of Wands and Two of Pentacles: fire's endurance meets earth's balance — someone weary but still standing who must maintain balance among many things; the challenge is not letting exhaustion erode the flexibility needed to manage daily life effectively." },
  "30_66": { vi: "Chín Gậy và Ba Tiền: kiên trì lửa gặp sự hợp tác đất — người đã đấu tranh một mình có thể tìm thấy sức mạnh mới trong việc làm việc cùng người khác; hãy tin tưởng vào đội nhóm và sự cộng tác, đôi khi sức mạnh thực sự đến từ việc nhận sự giúp đỡ thay vì đứng một mình.", en: "Nine of Wands and Three of Pentacles: fire's perseverance meets earth's collaboration — someone who has fought alone may find new strength in working with others; trust the team and collaboration, for sometimes true strength comes from accepting help rather than standing alone." },
  "30_67": { vi: "Chín Gậy và Bốn Tiền: sức chịu đựng lửa gặp sự kiểm soát đất — người bảo vệ ranh giới của mình và người bảo vệ tài sản của mình; cả hai đang phòng thủ nhưng theo những cách khác nhau, và đôi khi sự cẩn thận kép này là cần thiết để bảo vệ những gì đã được xây dựng qua khó khăn.", en: "Nine of Wands and Four of Pentacles: fire's endurance meets earth's control — the one defending their boundaries and the one protecting their resources; both are defensive but in different ways, and sometimes this double caution is necessary to protect what was built through difficulty." },
  "30_68": { vi: "Chín Gậy và Năm Tiền: kiên trì qua thử thách kép — lửa đứng vững trong khi đất đang trải qua thiếu thốn; đây là hình ảnh của sự khó khăn kép, nhưng cũng là lời nhắc nhở rằng người đã sống sót qua nhiều thử thách có sức mạnh bên trong để vượt qua ngay cả hoàn cảnh tối tăm nhất.", en: "Nine of Wands and Five of Pentacles: perseverance through double challenge — fire standing firm while earth is experiencing scarcity; an image of compounded difficulty, but also a reminder that someone who has survived many trials has the inner strength to push through even the darkest circumstances." },
  "30_69": { vi: "Chín Gậy và Sáu Tiền: kiên trì lửa gặp sự hào phóng đất — người đã đứng vững qua gian khó có thể nhận được sự hỗ trợ vật chất đúng lúc; sự cho và nhận giúp người kiệt sức phục hồi, hoặc người đã đấu tranh dài lâu được công nhận và đền bù xứng đáng.", en: "Nine of Wands and Six of Pentacles: fire's perseverance meets earth's generosity — someone who has stood firm through hardship may receive timely material support; the giving and receiving helps the weary one recover, or one who has long fought receives recognition and fair reward." },
  "30_70": { vi: "Chín Gậy và Bảy Tiền: kiên trì lửa gặp sự kiên nhẫn đất — hai loại kiên nhẫn kết hợp; Chín Gậy đứng chờ kết thúc trận chiến và Bảy Tiền chờ đợi kết quả của công sức — kết hợp này đòi hỏi sự nhẫn nại sâu sắc và tin tưởng rằng mọi nỗ lực sẽ được đền đáp đúng lúc.", en: "Nine of Wands and Seven of Pentacles: fire's perseverance meets earth's patience — two forms of patience combined; the Nine of Wands standing guard waiting for the battle to end and the Seven of Pentacles waiting for the fruits of labor — this combination demands deep patience and trust that all effort will be rewarded in time." },
  "30_71": { vi: "Chín Gậy và Tám Tiền: kiên trì lửa gặp sự chuyên tâm đất — người đã đứng vững qua thử thách đang tiếp tục rèn giũa kỹ năng; sự kết hợp của sức chịu đựng và kỷ luật chuyên môn tạo ra những nghệ nhân thực sự — những người không bao giờ bỏ cuộc và không bao giờ ngừng cải thiện.", en: "Nine of Wands and Eight of Pentacles: fire's perseverance meets earth's dedication — someone who has stood firm through trials continuing to hone their skills; the combination of endurance and professional discipline creates true craftsmen — those who never give up and never stop improving." },
  "30_72": { vi: "Chín Gậy và Chín Tiền: hai con số chín — kiên trì lửa gặp sự sung túc đất; người đã đứng vững qua nhiều thử thách có thể đạt đến sự độc lập và thịnh vượng tự xây dựng; đây là phần thưởng xứng đáng cho người không bao giờ bỏ cuộc dù mọi thứ trở nên khó khăn.", en: "Nine of Wands and Nine of Pentacles: two nines — fire's perseverance meets earth's abundance; someone who has stood firm through many trials may reach the self-built independence and prosperity they deserve; this is the rightful reward for one who never gave up even when things became hard." },
  "30_73": { vi: "Chín Gậy và Mười Tiền: kiên trì lửa gặp di sản đất — người đã đứng vững qua gian khó đang bảo vệ những gì quan trọng cho gia đình và thế hệ tương lai; mọi thử thách đã vượt qua đều có ý nghĩa khi nhìn trong bối cảnh di sản và những gì được truyền lại cho con cháu.", en: "Nine of Wands and Ten of Pentacles: fire's perseverance meets earth's legacy — someone who has stood firm through hardship protecting what matters for family and future generations; every challenge overcome gains meaning when viewed in the context of legacy and what is passed down to those who come after." },
  "30_74": { vi: "Chín Gậy và Trang Bị Tiền: kiên trì lửa gặp sự học hỏi đất — người dày dạn kinh nghiệm gặp người trẻ đang bắt đầu; Chín Gậy có thể dạy Trang Bị Tiền về sức chịu đựng và cách đứng vững, trong khi Trang Bị Tiền nhắc người chiến binh mệt mỏi về sự tươi mới và nhiệt huyết của người mới bắt đầu.", en: "Nine of Wands and Page of Pentacles: fire's perseverance meets earth's learning — the battle-hardened veteran meeting the young beginner; the Nine of Wands can teach the Page about endurance and how to stand firm, while the Page reminds the weary warrior of the freshness and enthusiasm of someone just starting out." },
  "30_75": { vi: "Chín Gậy và Kỵ Sĩ Tiền: kiên trì lửa gặp sự kiên định đất — hai chiến binh với phong cách khác nhau; Chín Gậy đứng canh gác sau nhiều trận và Kỵ Sĩ Tiền tiến lên từng bước chắc chắn; kết hợp của sự cảnh giác cao độ và sự kiên định phương pháp tạo ra sức mạnh phòng thủ không thể phá vỡ.", en: "Nine of Wands and Knight of Pentacles: fire's perseverance meets earth's steadiness — two warriors with different styles; the Nine of Wands standing guard after many battles and the Knight of Pentacles advancing step by sure step; the combination of heightened vigilance and methodical steadiness creates an unbreakable defensive strength." },
  "30_76": { vi: "Chín Gậy và Nữ Hoàng Tiền: kiên trì lửa gặp sự nuôi dưỡng đất — người đã đứng canh gác quá lâu cần được chăm sóc; Nữ Hoàng Tiền cung cấp sự ấm áp thực tế, thức ăn, và sự quan tâm vật chất có thể giúp người chiến binh mệt mỏi phục hồi đủ để tiếp tục.", en: "Nine of Wands and Queen of Pentacles: fire's perseverance meets earth's nurturing — someone who has stood guard too long needs care; the Queen of Pentacles provides the warmth, sustenance, and practical attention that can help the weary warrior recover enough to carry on." },
  "30_77": { vi: "Chín Gậy và Vua Tiền: kiên trì lửa gặp thẩm quyền đất — chiến binh mệt mỏi trước mặt nhà lãnh đạo ổn định; Vua Tiền có tầm nhìn dài hạn để thấy liệu trận chiến đang được tiến hành có đáng tiếp tục không; đôi khi người có thẩm quyền thực sự nói cho ta biết khi nào nên nghỉ ngơi và khi nào nên tiếp tục.", en: "Nine of Wands and King of Pentacles: fire's perseverance meets earth's authority — the weary warrior before the stable leader; the King of Pentacles has the long-term vision to see whether the battle being fought is worth continuing; sometimes the one with true authority is the one who tells us when to rest and when to press on." },
  "31_64": { vi: "Mười Gậy và Át Tiền: gánh nặng lửa gặp khởi đầu đất — người đang mang quá nhiều đang được trao một cơ hội mới; câu hỏi quan trọng là liệu họ có thể đặt xuống một số gánh nặng để tận dụng Át Tiền, hay họ sẽ tiếp tục mang tất cả và bỏ lỡ cơ hội.", en: "Ten of Wands and Ace of Pentacles: fire's burden meets earth's beginning — someone carrying too much being offered a new opportunity; the crucial question is whether they can set down some of their load to take advantage of the Ace of Pentacles, or whether they will keep carrying everything and miss the chance." },
  "31_65": { vi: "Mười Gậy và Hai Tiền: gánh nặng kép — lửa mang quá nhiều và đất đang tung hứng; đây là hình ảnh của người đang cố gắng làm quá nhiều thứ cùng một lúc và có nguy cơ đánh mất tất cả; lời khuyên là phải ưu tiên và giảm bớt trước khi sự kiệt sức hoàn toàn xảy ra.", en: "Ten of Wands and Two of Pentacles: double burden — fire carrying too much and earth already juggling; an image of someone trying to do too many things at once and at risk of losing everything; the advice is to prioritize and reduce before complete exhaustion arrives." },
  "31_66": { vi: "Mười Gậy và Ba Tiền: gánh nặng lửa gặp sự cộng tác đất — người mang quá nhiều cần học cách ủy thác; Ba Tiền nhắc nhở rằng không ai phải làm tất cả một mình, và việc chia sẻ gánh nặng trong nhóm không phải là yếu đuối mà là trí tuệ lãnh đạo thực sự.", en: "Ten of Wands and Three of Pentacles: fire's burden meets earth's collaboration — the one carrying too much needs to learn to delegate; the Three of Pentacles reminds us that no one must do everything alone, and sharing the load within a team is not weakness but genuine leadership wisdom." },
  "31_67": { vi: "Mười Gậy và Bốn Tiền: gánh nặng lửa gặp sự giữ chặt đất — người đang ôm quá nhiều trách nhiệm không thể buông tay; đôi khi sợ mất kiểm soát khiến người ta tiếp tục mang gánh nặng dù đã kiệt sức; bài học là buông bỏ không có nghĩa là mất đi, đôi khi là lấy lại.", en: "Ten of Wands and Four of Pentacles: fire's burden meets earth's clinging — the one bearing too much responsibility unable to let go; sometimes the fear of losing control keeps people carrying burdens even in exhaustion; the lesson is that letting go does not mean losing, and sometimes means regaining." },
  "31_68": { vi: "Mười Gậy và Năm Tiền: gánh nặng và thiếu thốn — lửa đang kiệt sức và đất đang khó khăn; đây là sự kết hợp nặng nề nhất, nhưng nó cũng là lời kêu gọi hành động — đây là lúc cần giúp đỡ, và việc tìm kiếm sự hỗ trợ không phải là thất bại mà là bước đầu tiên ra khỏi khủng hoảng.", en: "Ten of Wands and Five of Pentacles: burden and scarcity — fire exhausted and earth struggling; the heaviest combination, but also a call to action — this is the moment to seek help, and reaching out for support is not failure but the first step out of crisis." },
  "31_69": { vi: "Mười Gậy và Sáu Tiền: gánh nặng lửa gặp sự hào phóng đất — ai đó đang mang quá nhiều có thể nhận được sự giúp đỡ; Sáu Tiền cung cấp sự cân bằng và chia sẻ, và khi hào phóng được trao cho người đang kiệt sức, nó có thể giảm bớt gánh nặng đủ để họ tìm lại chính mình.", en: "Ten of Wands and Six of Pentacles: fire's burden meets earth's generosity — someone carrying too much may receive help; the Six of Pentacles offers balance and sharing, and when generosity is extended to the exhausted one, it can lighten the load enough for them to find themselves again." },
  "31_70": { vi: "Mười Gậy và Bảy Tiền: gánh nặng lửa gặp sự kiên nhẫn đất — người kiệt sức đang chờ đợi kết quả; đây là thời điểm khó khăn nhất — đã bỏ ra quá nhiều công sức và vẫn chưa thấy phần thưởng; nhưng Bảy Tiền nhắc nhở rằng kết quả đang đến, chỉ cần thêm một ít kiên nhẫn nữa.", en: "Ten of Wands and Seven of Pentacles: fire's burden meets earth's patience — the exhausted one waiting for results; the hardest moment — having invested too much effort and still not seeing the reward; but the Seven of Pentacles reminds that results are coming, just a little more patience needed." },
  "31_71": { vi: "Mười Gậy và Tám Tiền: gánh nặng lửa gặp sự chuyên tâm đất — người đang làm việc quá sức đang cố gắng hoàn thiện kỹ năng; đây có thể là dấu hiệu của chủ nghĩa hoàn hảo quá mức hoặc là sự đầu tư thực sự; bài học là kỷ luật chuyên môn không nên trở thành xiềng xích làm kiệt sức bản thân.", en: "Ten of Wands and Eight of Pentacles: fire's burden meets earth's dedication — someone overworking while trying to perfect skills; this can be a sign of excessive perfectionism or genuine investment; the lesson is that professional discipline should not become the shackles that exhaust oneself." },
  "31_72": { vi: "Mười Gậy và Chín Tiền: gánh nặng lửa gặp sự sung túc đất — người đang mang quá nhiều trên đường đến thịnh vượng; câu hỏi là liệu họ có thể đặt xuống gánh nặng khi đến đích không, hay họ sẽ tiếp tục mang nó ngay cả khi không còn cần thiết vì đã quen với việc làm như vậy.", en: "Ten of Wands and Nine of Pentacles: fire's burden meets earth's abundance — someone carrying too much on the road to prosperity; the question is whether they can set down the burden when they arrive, or whether they will keep carrying it even when no longer necessary because they have grown so used to doing so." },
  "31_73": { vi: "Mười Gậy và Mười Tiền: gánh nặng lửa gặp di sản đất — người đang mang gánh nặng vì gia đình và di sản; đây có thể là ý nghĩa đẹp đẽ nhất của Mười Gậy — hy sinh cho những người yêu thương và cho tương lai con cháu; nhưng cũng cần nhớ rằng sức khỏe của bạn cũng là một phần của di sản đó.", en: "Ten of Wands and Ten of Pentacles: fire's burden meets earth's legacy — someone bearing burdens for family and legacy; perhaps the most meaningful expression of the Ten of Wands — sacrificing for loved ones and for the future of descendants; but also remember that your own wellbeing is part of that legacy." },
  "31_74": { vi: "Mười Gậy và Trang Bị Tiền: gánh nặng lửa gặp sự tò mò đất — người kiệt sức có thể học từ sự nhẹ nhàng và nhiệt huyết của người mới bắt đầu; Trang Bị Tiền nhắc nhở người đã mang gánh nặng quá lâu rằng có những cách tiếp cận mới, nhẹ nhàng hơn với công việc và cuộc sống.", en: "Ten of Wands and Page of Pentacles: fire's burden meets earth's curiosity — the exhausted one can learn from the lightness and enthusiasm of the beginner; the Page of Pentacles reminds someone who has carried burdens too long that there are new, lighter ways of approaching work and life." },
  "31_75": { vi: "Mười Gậy và Kỵ Sĩ Tiền: gánh nặng lửa gặp sự kiên định đất — hai người làm việc chăm chỉ theo những cách khác nhau; Kỵ Sĩ Tiền tiến chậm và chắc còn Mười Gậy mang tất cả vội vã về đích; đôi khi phong cách kỹ lưỡng và từ từ của Kỵ Sĩ Tiền là lời khuyên tốt nhất cho người đang kiệt sức.", en: "Ten of Wands and Knight of Pentacles: fire's burden meets earth's steadiness — two hard workers with different styles; the Knight of Pentacles advances slow and sure while the Ten of Wands carries everything hurrying to the finish; sometimes the Knight's thorough, unhurried style is the best advice for the exhausted one." },
  "31_76": { vi: "Mười Gậy và Nữ Hoàng Tiền: gánh nặng lửa gặp sự nuôi dưỡng đất — người kiệt sức cần được chăm sóc từ người thực tế và ấm áp; Nữ Hoàng Tiền không chỉ cung cấp sự thoải mái cảm xúc mà còn giúp tổ chức và quản lý gánh nặng sao cho không còn nặng nề như trước.", en: "Ten of Wands and Queen of Pentacles: fire's burden meets earth's nurturing — the exhausted one needing care from someone practical and warm; the Queen of Pentacles provides not only emotional comfort but also helps organize and manage the burden so it no longer feels as heavy as before." },
  "31_77": { vi: "Mười Gậy và Vua Tiền: gánh nặng lửa gặp thẩm quyền đất — người đang kiệt sức trước mặt nhà lãnh đạo có tầm nhìn; Vua Tiền có thể nhìn thấy điều mà người mang gánh nặng không thể thấy — đâu là trách nhiệm cần thiết và đâu là những thứ có thể ủy thác hoặc buông bỏ hoàn toàn.", en: "Ten of Wands and King of Pentacles: fire's burden meets earth's authority — the exhausted one before the visionary leader; the King of Pentacles can see what the burden-bearer cannot — which responsibilities are truly necessary and which can be delegated or released entirely." },
  "32_64": { vi: "Trang Bị Gậy và Át Tiền: người trẻ lửa gặp khởi đầu đất — nhiệt huyết sáng tạo gặp cơ hội vật chất đầu tiên; đây là khoảnh khắc mà một ý tưởng đam mê có thể trở thành dự án thực sự, và sự kết hợp này khuyến khích người trẻ tuổi tin vào tiềm năng của mình và dám bước những bước đầu tiên.", en: "Page of Wands and Ace of Pentacles: young fire meets earth's beginning — creative enthusiasm meeting the first material opportunity; the moment when a passionate idea can become a real project, and this combination encourages the young one to believe in their potential and dare to take the first steps." },
  "32_65": { vi: "Trang Bị Gậy và Hai Tiền: người trẻ lửa gặp sự cân bằng đất — nhiệt huyết sáng tạo cần học cách quản lý nhiều thứ; Hai Tiền dạy Trang Bị Gậy rằng đam mê cần được cân bằng với thực tế hằng ngày, và việc học cách tung hứng các trách nhiệm là kỹ năng quan trọng để biến ước mơ thành hiện thực lâu dài.", en: "Page of Wands and Two of Pentacles: young fire meets earth's balance — creative enthusiasm needing to learn how to manage many things; the Two of Pentacles teaches the Page that passion must be balanced with daily reality, and learning to juggle responsibilities is an important skill for turning dreams into lasting reality." },
  "32_66": { vi: "Trang Bị Gậy và Ba Tiền: người trẻ lửa gặp sự cộng tác đất — nhiệt huyết sáng tạo trong môi trường học hỏi và làm việc nhóm; đây là sự kết hợp hoàn hảo cho người mới bắt đầu — mang đam mê vào dự án nhóm và học hỏi từ những người có kinh nghiệm hơn trong khi đóng góp năng lượng tươi mới.", en: "Page of Wands and Three of Pentacles: young fire meets earth's collaboration — creative enthusiasm within a learning and teamwork environment; a perfect combination for the beginner — bringing passion into a group project and learning from those more experienced while contributing fresh energy." },
  "32_67": { vi: "Trang Bị Gậy và Bốn Tiền: người trẻ lửa gặp sự giữ chặt đất — nhiệt huyết bị hạn chế bởi sự thận trọng hoặc sự kiểm soát quá mức; đây có thể là căng thẳng giữa người trẻ muốn thử nghiệm và người lớn hoặc hệ thống đang giữ chặt các nguồn lực; bài học là tìm cách thương lượng hơn là đối đầu.", en: "Page of Wands and Four of Pentacles: young fire meets earth's clinging — enthusiasm constrained by excessive caution or control; the tension between a young person wanting to experiment and an adult or system holding resources tightly; the lesson is to find ways to negotiate rather than confront." },
  "32_68": { vi: "Trang Bị Gậy và Năm Tiền: nhiệt huyết lửa gặp thiếu thốn đất — người trẻ đầy đam mê nhưng thiếu nguồn lực vật chất; đây không phải lý do để từ bỏ ước mơ mà là thách thức để sáng tạo hơn và tìm ra cách thực hiện ước mơ với nguồn lực ít ỏi — nhiều điều vĩ đại đã được xây dựng từ hoàn cảnh như vậy.", en: "Page of Wands and Five of Pentacles: fire's enthusiasm meets earth's scarcity — a young person full of passion but lacking material resources; not a reason to abandon dreams but a challenge to be more creative and find ways to pursue those dreams with limited resources — many great things have been built from such circumstances." },
  "32_69": { vi: "Trang Bị Gậy và Sáu Tiền: người trẻ lửa gặp sự hào phóng đất — nhiệt huyết nhận được sự hỗ trợ; Sáu Tiền có thể đại diện cho học bổng, tài trợ, hoặc người cố vấn sẵn sàng đầu tư vào tài năng trẻ; sự hào phóng đúng thời điểm có thể biến một ý tưởng đầy đam mê thành dự án thực sự.", en: "Page of Wands and Six of Pentacles: young fire meets earth's generosity — enthusiasm receiving support; the Six of Pentacles can represent scholarships, grants, or a mentor willing to invest in young talent; timely generosity can transform a passionate idea into a real project." },
  "32_70": { vi: "Trang Bị Gậy và Bảy Tiền: nhiệt huyết lửa gặp sự kiên nhẫn đất — người trẻ đầy đam mê cần học bài học về kiên nhẫn; Bảy Tiền dạy rằng những kết quả tốt nhất đến sau một thời gian dài gieo hạt và chờ đợi, và học cách kiên nhẫn sớm trong cuộc đời là một trong những bài học quý giá nhất.", en: "Page of Wands and Seven of Pentacles: fire's enthusiasm meets earth's patience — the passionate young one needing to learn the lesson of patience; the Seven of Pentacles teaches that the best results come after a long period of planting and waiting, and learning patience early in life is one of the most valuable lessons." },
  "32_71": { vi: "Trang Bị Gậy và Tám Tiền: nhiệt huyết lửa gặp sự chuyên tâm đất — hai người đang học hỏi và phát triển; đây là sự kết hợp của người mới bắt đầu đầy đam mê và người đang rèn giũa kỹ năng kiên trì; cả hai đều đang trên con đường phát triển và sự kết hợp này khuyến khích việc học cùng nhau.", en: "Page of Wands and Eight of Pentacles: fire's enthusiasm meets earth's dedication — two people learning and growing; the combination of the passionate beginner and the diligent skill-sharpener; both are on a path of development and this combination encourages learning together." },
  "32_72": { vi: "Trang Bị Gậy và Chín Tiền: người trẻ lửa gặp sự sung túc đất — nhiệt huyết nhìn về phía tương lai mà mình muốn xây dựng; Chín Tiền là hình ảnh về sự thành công độc lập và tự lập, và Trang Bị Gậy được khuyến khích bởi viễn cảnh đó để tiếp tục nuôi dưỡng đam mê và xây dựng hướng đến mục tiêu dài hạn.", en: "Page of Wands and Nine of Pentacles: young fire meets earth's abundance — enthusiasm looking toward the future one wants to build; the Nine of Pentacles is a vision of independent self-made success, and the Page of Wands is encouraged by that vision to keep nurturing passion and building toward long-term goals." },
  "32_73": { vi: "Trang Bị Gậy và Mười Tiền: người trẻ lửa gặp di sản đất — nhiệt huyết trong bối cảnh gia đình và cộng đồng; Trang Bị Gậy mang năng lượng sáng tạo vào di sản gia đình, hoặc chính di sản đó truyền cảm hứng cho người trẻ tìm ra con đường riêng của mình trong khi vẫn kết nối với nguồn gốc.", en: "Page of Wands and Ten of Pentacles: young fire meets earth's legacy — enthusiasm within the context of family and community; the Page of Wands bringing creative energy into family legacy, or the legacy itself inspiring the young one to find their own path while remaining connected to their roots." },
  "32_74": { vi: "Trang Bị Gậy và Trang Bị Tiền: hai trang bị từ hai nguyên tố — lửa và đất đều ở điểm khởi đầu học hỏi của chúng; đây là sự gặp gỡ của hai người mới bắt đầu với những tài năng bổ sung nhau — một người mang đam mê và sáng tạo, người kia mang sự thực tế và ham học hỏi; cùng nhau họ có thể xây dựng điều phi thường.", en: "Page of Wands and Page of Pentacles: two pages from two elements — fire and earth both at their learning beginnings; the meeting of two beginners with complementary gifts — one bringing passion and creativity, the other bringing practicality and eagerness to learn; together they can build something extraordinary." },
  "32_75": { vi: "Trang Bị Gậy và Kỵ Sĩ Tiền: nhiệt huyết lửa gặp sự kiên định đất — người trẻ đầy đam mê học hỏi từ người có phương pháp; Kỵ Sĩ Tiền có thể dạy Trang Bị Gậy cách biến ý tưởng thành hành động thực tế từng bước một, trong khi Trang Bị Gậy nhắc Kỵ Sĩ rằng nhiệt huyết và đam mê cũng quan trọng không kém phương pháp.", en: "Page of Wands and Knight of Pentacles: fire's enthusiasm meets earth's steadiness — the passionate young one learning from the methodical one; the Knight of Pentacles can teach the Page how to turn ideas into practical action step by step, while the Page reminds the Knight that enthusiasm and passion matter just as much as method." },
  "32_76": { vi: "Trang Bị Gậy và Nữ Hoàng Tiền: người trẻ lửa gặp sự nuôi dưỡng đất — nhiệt huyết được định hướng bởi sự khôn ngoan thực tế và ấm áp; Nữ Hoàng Tiền có thể là người cố vấn lý tưởng cho Trang Bị Gậy — không dập tắt đam mê mà giúp định hướng nó theo những cách tạo ra kết quả thực sự.", en: "Page of Wands and Queen of Pentacles: young fire meets earth's nurturing — enthusiasm guided by practical and warm wisdom; the Queen of Pentacles can be the ideal mentor for the Page of Wands — not extinguishing passion but helping direct it in ways that produce real results." },
  "32_77": { vi: "Trang Bị Gậy và Vua Tiền: người trẻ lửa gặp thẩm quyền đất — nhiệt huyết và ý tưởng trình bày trước người có kinh nghiệm và quyền lực vật chất; Vua Tiền có thể nhìn thấy liệu nhiệt huyết của Trang Bị Gậy có đủ nền tảng thực tế không, và đánh giá của ông là bài kiểm tra quan trọng giúp ý tưởng trở nên vững chắc hơn.", en: "Page of Wands and King of Pentacles: young fire meets earth's authority — enthusiasm and ideas presented before someone experienced and materially powerful; the King of Pentacles can see whether the Page's enthusiasm has sufficient practical foundation, and his assessment is the crucial test that makes the idea more solid." },
  "33_64": { vi: "Kỵ Sĩ Gậy và Át Tiền: hành động lửa gặp khởi đầu đất — đà tiến nhanh mở ra cơ hội vật chất; Kỵ Sĩ Gậy là người tiên phong và Át Tiền là cơ hội đang chờ được khai thác; sự kết hợp này là dấu hiệu tốt để tiến nhanh về phía cơ hội — ngần ngại quá lâu có thể làm mất thời điểm tốt.", en: "Knight of Wands and Ace of Pentacles: fire's action meets earth's beginning — bold momentum opening a material opportunity; the Knight of Wands is the pioneer and the Ace of Pentacles is the opportunity waiting to be seized; this combination is a good sign to move decisively toward the opportunity — hesitating too long may miss the moment." },
  "33_65": { vi: "Kỵ Sĩ Gậy và Hai Tiền: hành động lửa gặp sự cân bằng đất — tiến nhanh trong khi duy trì sự cân bằng là thách thức; Kỵ Sĩ Gậy muốn phóng về phía trước còn Hai Tiền cảnh báo về sự mất cân bằng; bài học là học cách di chuyển nhanh mà không để mọi thứ rơi vỡ — cần linh hoạt nhưng có kiểm soát.", en: "Knight of Wands and Two of Pentacles: fire's action meets earth's balance — moving fast while maintaining balance is the challenge; the Knight of Wands wants to charge forward while the Two of Pentacles warns of imbalance; the lesson is learning to move quickly without letting things fall apart — needing flexibility but with control." },
  "33_66": { vi: "Kỵ Sĩ Gậy và Ba Tiền: hành động lửa gặp sự cộng tác đất — người tiên phong làm việc trong nhóm; Kỵ Sĩ Gậy mang năng lượng và đà tiến, và Ba Tiền mang sự cộng tác và chất lượng; kết hợp tốt nhất là khi Kỵ Sĩ Gậy dẫn đầu nhưng biết lắng nghe ý kiến đóng góp của những người chuyên môn trong nhóm.", en: "Knight of Wands and Three of Pentacles: fire's action meets earth's collaboration — the pioneer working within a team; the Knight of Wands brings energy and momentum and the Three of Pentacles brings collaboration and quality; the best combination is when the Knight leads but knows how to listen to the expert contributions of team members." },
  "33_67": { vi: "Kỵ Sĩ Gậy và Bốn Tiền: hành động lửa gặp sự kiểm soát đất — người muốn tiến nhanh gặp người hoặc hệ thống đang giữ chặt; đây có thể là sự thất vọng khi Kỵ Sĩ Gậy bị ngăn lại bởi những quy tắc hoặc người không muốn thay đổi; nhưng đôi khi sự thận trọng của Bốn Tiền là điều cần thiết để không làm hỏng những gì đã được xây dựng.", en: "Knight of Wands and Four of Pentacles: fire's action meets earth's control — the one wanting to charge forward meeting a person or system holding tight; the frustration of the Knight of Wands being blocked by rules or those resistant to change; but sometimes the caution of the Four of Pentacles is what prevents destroying what has been built." },
  "33_68": { vi: "Kỵ Sĩ Gậy và Năm Tiền: hành động lửa gặp thiếu thốn đất — tiến nhanh trong hoàn cảnh khó khăn; Kỵ Sĩ Gậy có thể là người đến giải cứu hoặc là người đang tìm lối thoát bằng hành động táo bạo; trong cả hai trường hợp, năng lượng và quyết tâm là điều cần thiết để vượt qua tình trạng thiếu thốn.", en: "Knight of Wands and Five of Pentacles: fire's action meets earth's scarcity — moving boldly through difficult circumstances; the Knight of Wands may be the one arriving to help or the one seeking a way out through bold action; in both cases, energy and determination are what is needed to overcome scarcity." },
  "33_69": { vi: "Kỵ Sĩ Gậy và Sáu Tiền: hành động lửa gặp sự hào phóng đất — người tiên phong chia sẻ khi tiến lên; Sáu Tiền gợi ý rằng sự tiến lên của Kỵ Sĩ Gậy không chỉ vì bản thân mà còn mang lại lợi ích cho người khác; đây là hình ảnh đẹp của lãnh đạo hào phóng — tiến lên nhanh và kéo người khác lên cùng.", en: "Knight of Wands and Six of Pentacles: fire's action meets earth's generosity — the pioneer sharing while advancing; the Six of Pentacles suggests the Knight's forward movement benefits others and not only themselves; a beautiful image of generous leadership — advancing fast and pulling others up along the way." },
  "33_70": { vi: "Kỵ Sĩ Gậy và Bảy Tiền: hành động lửa gặp sự kiên nhẫn đất — người tiến nhanh cần học bài học về chờ đợi kết quả; Bảy Tiền nhắc nhở Kỵ Sĩ Gậy rằng không phải mọi kết quả đều có thể được đẩy nhanh bằng hành động — một số thứ cần thời gian để chín muồi và cố gắng ép buộc sẽ chỉ làm hỏng quá trình.", en: "Knight of Wands and Seven of Pentacles: fire's action meets earth's patience — the fast mover needing to learn the lesson of waiting for results; the Seven of Pentacles reminds the Knight that not every result can be rushed by action — some things need time to ripen and forcing them only damages the process." },
  "33_71": { vi: "Kỵ Sĩ Gậy và Tám Tiền: hành động lửa gặp sự chuyên tâm đất — người tiên phong rèn giũa kỹ năng; đây là sự kết hợp tốt khi năng lượng và sự nhiệt huyết của Kỵ Sĩ Gậy được kênh hóa vào kỷ luật thực hành liên tục của Tám Tiền; kết quả là người hành động nhanh nhưng cũng làm tốt.", en: "Knight of Wands and Eight of Pentacles: fire's action meets earth's dedication — the pioneer honing skills; a good combination when the Knight of Wands's energy and enthusiasm are channeled into the Eight of Pentacles's disciplined continuous practice; the result is someone who acts fast but also does it well." },
  "33_72": { vi: "Kỵ Sĩ Gậy và Chín Tiền: hành động lửa gặp sự sung túc đất — người tiên phong đang tiến đến thành công; Chín Tiền là đích đến và Kỵ Sĩ Gậy đang phóng về phía nó; đây là dấu hiệu tích cực rằng hành động táo bạo đang dẫn đến sự độc lập và thịnh vượng thực sự.", en: "Knight of Wands and Nine of Pentacles: fire's action meets earth's abundance — the pioneer advancing toward success; the Nine of Pentacles is the destination and the Knight of Wands is charging toward it; a positive sign that bold action is leading toward genuine independence and prosperity." },
  "33_73": { vi: "Kỵ Sĩ Gậy và Mười Tiền: hành động lửa gặp di sản đất — người tiên phong xây dựng cho gia đình và tương lai; Mười Tiền là di sản và Kỵ Sĩ Gậy là năng lượng xây dựng nó; đây là sự kết hợp của người hành động quyết đoán với tầm nhìn dài hạn về những gì mình đang xây dựng cho thế hệ tiếp theo.", en: "Knight of Wands and Ten of Pentacles: fire's action meets earth's legacy — the pioneer building for family and the future; the Ten of Pentacles is the legacy and the Knight of Wands is the energy building it; the combination of decisive action with long-term vision about what one is building for the next generation." },
  "33_74": { vi: "Kỵ Sĩ Gậy và Trang Bị Tiền: hành động lửa gặp sự học hỏi đất — người tiên phong gặp người mới bắt đầu; Kỵ Sĩ Gậy có thể là người cố vấn đầy nhiệt huyết cho Trang Bị Tiền — dạy cách hành động táo bạo trong khi Trang Bị Tiền dạy Kỵ Sĩ tầm quan trọng của việc học hỏi từng bước một.", en: "Knight of Wands and Page of Pentacles: fire's action meets earth's learning — the pioneer meeting the beginner; the Knight of Wands can be an enthusiastic mentor to the Page of Pentacles — teaching bold action while the Page teaches the Knight the importance of learning step by step." },
  "33_75": { vi: "Kỵ Sĩ Gậy và Kỵ Sĩ Tiền: hai kỵ sĩ từ hai nguyên tố — lửa phóng nhanh và đất tiến chậm chắc; đây là sự gặp gỡ của hai phong cách hành động hoàn toàn khác nhau; kết hợp tốt nhất là khi họ bổ sung cho nhau — lửa mang tốc độ và nhiệt huyết, đất mang sự kỹ lưỡng và độ bền.", en: "Knight of Wands and Knight of Pentacles: two knights from two elements — fire charging fast and earth advancing slow and sure; the meeting of two completely different action styles; the ideal blend is when they complement each other — fire bringing speed and enthusiasm, earth bringing thoroughness and endurance." },
  "33_76": { vi: "Kỵ Sĩ Gậy và Nữ Hoàng Tiền: hành động lửa gặp sự nuôi dưỡng đất — người tiên phong và người nuôi dưỡng; Nữ Hoàng Tiền có thể là người tạo ra môi trường ổn định và ấm áp nơi Kỵ Sĩ Gậy có thể xuất phát và quay về; đây là sự cân bằng tốt giữa sự phiêu lưu và sự ổn định trong cuộc sống.", en: "Knight of Wands and Queen of Pentacles: fire's action meets earth's nurturing — the pioneer and the nurturer; the Queen of Pentacles can be the one who creates the stable and warm environment from which the Knight of Wands departs and returns; a good balance between adventure and stability in life." },
  "33_77": { vi: "Kỵ Sĩ Gậy và Vua Tiền: hành động lửa gặp thẩm quyền đất — người tiên phong trước mặt nhà lãnh đạo ổn định; Vua Tiền có thể đánh giá liệu hành động của Kỵ Sĩ Gậy có mang lại kết quả thực sự hay chỉ là sự vội vàng không cần thiết; khi thẩm quyền đất hỗ trợ năng lượng lửa, sự kết hợp đó trở nên rất mạnh mẽ.", en: "Knight of Wands and King of Pentacles: fire's action meets earth's authority — the pioneer before the stable leader; the King of Pentacles can assess whether the Knight's action produces genuine results or is merely unnecessary haste; when earth's authority backs fire's energy, the combination becomes very powerful." },
  "34_64": { vi: "Nữ Hoàng Gậy và Át Tiền: nữ vương lửa gặp khởi đầu đất — sức lãnh đạo sáng tạo gặp cơ hội vật chất mới; Nữ Hoàng Gậy có trực giác nhận ra ngay đây là cơ hội đáng theo đuổi, và sự kết hợp của tầm nhìn sáng tạo với cơ hội vật chất thực sự là nền tảng cho thành công bền vững.", en: "Queen of Wands and Ace of Pentacles: fire's queen meets earth's beginning — creative leadership meeting a new material opportunity; the Queen of Wands intuitively recognizes this as an opportunity worth pursuing, and the combination of creative vision with a real material opportunity is the foundation for lasting success." },
  "34_65": { vi: "Nữ Hoàng Gậy và Hai Tiền: nữ vương lửa gặp sự cân bằng đất — lãnh đạo sáng tạo quản lý nhiều thứ cùng lúc; Nữ Hoàng Gậy có khả năng tự nhiên để truyền cảm hứng và đồng thời duy trì sự cân bằng thực tế; đây là sự kết hợp của người phụ nữ đa năng có thể làm nhiều việc mà vẫn giữ được phong thái và hiệu quả.", en: "Queen of Wands and Two of Pentacles: fire's queen meets earth's balance — creative leadership managing many things at once; the Queen of Wands has a natural ability to inspire while simultaneously maintaining practical balance; the combination of the versatile woman who can do many things while maintaining grace and effectiveness." },
  "34_66": { vi: "Nữ Hoàng Gậy và Ba Tiền: nữ vương lửa gặp sự cộng tác đất — lãnh đạo sáng tạo trong môi trường cộng tác; Nữ Hoàng Gậy là người lãnh đạo bằng cách truyền cảm hứng, và Ba Tiền nhắc nhở rằng ngay cả người mạnh mẽ nhất cũng cần đội nhóm; sự kết hợp này tạo ra môi trường làm việc đầy sáng tạo và hiệu quả.", en: "Queen of Wands and Three of Pentacles: fire's queen meets earth's collaboration — creative leadership within a collaborative environment; the Queen of Wands is a leader who inspires by example, and the Three of Pentacles reminds that even the strongest need a team; this combination creates a highly creative and effective working environment." },
  "34_67": { vi: "Nữ Hoàng Gậy và Bốn Tiền: nữ vương lửa gặp sự kiểm soát đất — sức sáng tạo đối mặt với sự giữ chặt; Nữ Hoàng Gậy có thể cảm thấy bị hạn chế bởi ai đó hoặc một hệ thống đang kiểm soát nguồn lực quá chặt; hoặc chính bản thân có thể đang giữ chặt nguồn lực khi cần phóng thích để sáng tạo thực sự.", en: "Queen of Wands and Four of Pentacles: fire's queen meets earth's control — creative energy facing tight holding; the Queen of Wands may feel constrained by someone or a system controlling resources too tightly; or one may be holding resources tightly themselves when they need to be released for genuine creativity." },
  "34_68": { vi: "Nữ Hoàng Gậy và Năm Tiền: nữ vương lửa gặp thiếu thốn đất — lãnh đạo sáng tạo trong hoàn cảnh khó khăn; Nữ Hoàng Gậy không dễ bị đánh gục bởi hoàn cảnh khó khăn — sức mạnh nội tâm và khả năng truyền cảm hứng của bà có thể giúp những người xung quanh vượt qua thiếu thốn bằng tinh thần và sự sáng tạo.", en: "Queen of Wands and Five of Pentacles: fire's queen meets earth's scarcity — creative leadership amid difficult circumstances; the Queen of Wands is not easily brought down by hardship — her inner strength and ability to inspire can help those around her overcome scarcity through spirit and creativity." },
  "34_69": { vi: "Nữ Hoàng Gậy và Sáu Tiền: nữ vương lửa gặp sự hào phóng đất — lãnh đạo sáng tạo kết hợp với sự cho đi; Nữ Hoàng Gậy hào phóng với năng lượng và sự truyền cảm hứng, và khi kết hợp với Sáu Tiền, sự hào phóng đó mở rộng đến cả nguồn lực vật chất; đây là người lãnh đạo cho đi cả tâm hồn lẫn sự hỗ trợ thực tế.", en: "Queen of Wands and Six of Pentacles: fire's queen meets earth's generosity — creative leadership combined with giving; the Queen of Wands is generous with energy and inspiration, and when combined with the Six of Pentacles, that generosity extends to material resources; this is the leader who gives both spirit and practical support." },
  "34_70": { vi: "Nữ Hoàng Gậy và Bảy Tiền: nữ vương lửa gặp sự kiên nhẫn đất — lãnh đạo sáng tạo trong giai đoạn chờ đợi kết quả; Nữ Hoàng Gậy có thể thiếu kiên nhẫn với sự chờ đợi nhưng Bảy Tiền dạy rằng một số mùa thu hoạch cần thời gian dài hơn; bài học là duy trì năng lượng và sự nhiệt huyết ngay cả khi kết quả chưa hiện ra.", en: "Queen of Wands and Seven of Pentacles: fire's queen meets earth's patience — creative leadership during a period of waiting for results; the Queen of Wands may lack patience for waiting but the Seven of Pentacles teaches that some harvests need more time; the lesson is maintaining energy and enthusiasm even when results have not yet appeared." },
  "34_71": { vi: "Nữ Hoàng Gậy và Tám Tiền: nữ vương lửa gặp sự chuyên tâm đất — lãnh đạo sáng tạo và kỷ luật chuyên môn; Nữ Hoàng Gậy mang nhiệt huyết và tầm nhìn, Tám Tiền mang sự kiên trì và kỹ lưỡng; kết hợp lý tưởng là khi sự sáng tạo đầy đam mê được hỗ trợ bởi nền tảng kỹ năng vững chắc được xây dựng qua thực hành.", en: "Queen of Wands and Eight of Pentacles: fire's queen meets earth's dedication — creative leadership and professional discipline; the Queen of Wands brings enthusiasm and vision, the Eight of Pentacles brings persistence and thoroughness; the ideal combination is when passionate creativity is supported by a solid skill foundation built through practice." },
  "34_72": { vi: "Nữ Hoàng Gậy và Chín Tiền: nữ vương lửa gặp sự sung túc đất — hai hình ảnh mạnh mẽ về sự độc lập và thành công của người phụ nữ; Nữ Hoàng Gậy đại diện cho sức mạnh sáng tạo và Chín Tiền đại diện cho sự thịnh vượng tự xây dựng; khi cả hai cùng xuất hiện, đây là sự khẳng định mạnh mẽ về sự tự lập và thành công thực sự.", en: "Queen of Wands and Nine of Pentacles: fire's queen meets earth's abundance — two powerful images of feminine independence and success; the Queen of Wands represents creative strength and the Nine of Pentacles represents self-made prosperity; when both appear together, this is a powerful affirmation of genuine self-reliance and success." },
  "34_73": { vi: "Nữ Hoàng Gậy và Mười Tiền: nữ vương lửa gặp di sản đất — lãnh đạo sáng tạo trong bối cảnh gia đình và di sản; Nữ Hoàng Gậy mang nhiệt huyết và sự gắn kết vào gia đình, và Mười Tiền là di sản bền vững mà bà đang bảo vệ và xây dựng cho thế hệ tiếp theo với tình yêu thương và sức mạnh.", en: "Queen of Wands and Ten of Pentacles: fire's queen meets earth's legacy — creative leadership within the context of family and legacy; the Queen of Wands brings warmth and connection to family, and the Ten of Pentacles is the lasting legacy she is protecting and building for the next generation with love and strength." },
  "34_74": { vi: "Nữ Hoàng Gậy và Trang Bị Tiền: nữ vương lửa gặp người học trò đất — người cố vấn và người được hướng dẫn; Nữ Hoàng Gậy là người cố vấn lý tưởng cho Trang Bị Tiền — truyền cảm hứng, chia sẻ kinh nghiệm thực tế, và khuyến khích sự phát triển của tài năng trẻ với sự ấm áp và sức mạnh đặc trưng của bà.", en: "Queen of Wands and Page of Pentacles: fire's queen meets earth's student — the mentor and the guided one; the Queen of Wands is the ideal mentor for the Page of Pentacles — inspiring, sharing practical experience, and encouraging the development of young talent with her characteristic warmth and strength." },
  "34_75": { vi: "Nữ Hoàng Gậy và Kỵ Sĩ Tiền: nữ vương lửa gặp sự kiên định đất — lãnh đạo sáng tạo và người thực hiện kỹ lưỡng; Nữ Hoàng Gậy cung cấp tầm nhìn và đam mê, Kỵ Sĩ Tiền cung cấp sự kiên định và tỉ mỉ trong thực hiện; khi cả hai làm việc cùng nhau, ý tưởng lớn được biến thành hành động cụ thể một cách hiệu quả nhất.", en: "Queen of Wands and Knight of Pentacles: fire's queen meets earth's steadiness — creative leadership and the thorough executor; the Queen of Wands provides vision and passion, the Knight of Pentacles provides steady and detailed execution; when both work together, big ideas are turned into concrete action most effectively." },
  "34_76": { vi: "Nữ Hoàng Gậy và Nữ Hoàng Tiền: hai nữ hoàng từ hai nguyên tố — lửa và đất đều ở đỉnh cao trí tuệ và quyền lực của chúng; đây là sự gặp gỡ của hai người phụ nữ mạnh mẽ với những phẩm chất bổ sung nhau hoàn hảo — một người mang nhiệt huyết và sáng tạo, người kia mang sự thực tế và nuôi dưỡng; cùng nhau họ có thể đạt được bất cứ điều gì.", en: "Queen of Wands and Queen of Pentacles: two queens from two elements — fire and earth both at the peak of their wisdom and power; the meeting of two powerful women with perfectly complementary qualities — one bringing passion and creativity, the other bringing practicality and nurturing; together they can achieve anything." },
  "34_77": { vi: "Nữ Hoàng Gậy và Vua Tiền: nữ vương lửa gặp vua đất — hai nhà lãnh đạo mạnh mẽ từ hai nguyên tố bổ sung nhau; Nữ Hoàng Gậy mang sức sáng tạo và đam mê, Vua Tiền mang sự ổn định và thẩm quyền vật chất; khi cả hai cùng xuất hiện, họ đại diện cho sự kết hợp lý tưởng giữa tầm nhìn và nền tảng.", en: "Queen of Wands and King of Pentacles: fire's queen meets earth's king — two powerful leaders from complementary elements; the Queen of Wands brings creative energy and passion, the King of Pentacles brings stability and material authority; when both appear together, they represent the ideal blend of vision and foundation." },
  "35_64": { vi: "Vua Gậy và Át Tiền: vua lửa gặp khởi đầu đất — lãnh đạo có tầm nhìn gặp cơ hội vật chất đầu tiên; Vua Gậy có kinh nghiệm và tầm nhìn để nhận ra ngay Át Tiền là cơ hội xứng đáng được đầu tư, và quyết định táo bạo của ông để theo đuổi nó có thể tạo ra di sản bền vững.", en: "King of Wands and Ace of Pentacles: fire's king meets earth's beginning — the visionary leader meeting the first material opportunity; the King of Wands has the experience and vision to immediately recognize the Ace of Pentacles as an opportunity worth investing in, and his bold decision to pursue it can create a lasting legacy." },
  "35_65": { vi: "Vua Gậy và Hai Tiền: vua lửa gặp sự cân bằng đất — lãnh đạo có tầm nhìn quản lý nhiều ưu tiên; Vua Gậy biết cách phân bổ nguồn lực và sự chú ý một cách khéo léo, và Hai Tiền nhắc nhở rằng ngay cả nhà lãnh đạo giỏi nhất cũng cần duy trì sự linh hoạt trong khi cân bằng nhiều yêu cầu đồng thời.", en: "King of Wands and Two of Pentacles: fire's king meets earth's balance — the visionary leader managing multiple priorities; the King of Wands knows how to allocate resources and attention skillfully, and the Two of Pentacles reminds that even the best leader must maintain flexibility while balancing many demands simultaneously." },
  "35_66": { vi: "Vua Gậy và Ba Tiền: vua lửa gặp sự cộng tác đất — lãnh đạo tầm nhìn trong môi trường cộng tác; Vua Gậy là người lãnh đạo bằng cách truyền cảm hứng và đặt hướng đi, và Ba Tiền nhắc nhở rằng sức mạnh thực sự của người lãnh đạo giỏi nằm ở chỗ tập hợp và điều phối những tài năng khác nhau cùng hướng đến mục tiêu chung.", en: "King of Wands and Three of Pentacles: fire's king meets earth's collaboration — visionary leadership within a collaborative environment; the King of Wands is a leader who inspires and sets direction, and the Three of Pentacles reminds that the true strength of a great leader lies in gathering and coordinating different talents toward a shared goal." },
  "35_67": { vi: "Vua Gậy và Bốn Tiền: vua lửa gặp sự kiểm soát đất — lãnh đạo tầm nhìn gặp sự thận trọng quá mức; khi Vua Gậy cần nguồn lực để thực hiện tầm nhìn của mình nhưng Bốn Tiền giữ chặt, có thể xảy ra xung đột; bài học là đàm phán và tìm cách thuyết phục người kiểm soát nguồn lực thay vì cố gắng phá vỡ rào cản.", en: "King of Wands and Four of Pentacles: fire's king meets earth's control — visionary leadership meeting excessive caution; when the King of Wands needs resources to execute his vision but the Four of Pentacles holds tight, conflict can arise; the lesson is to negotiate and find ways to persuade the resource controller rather than trying to break through barriers." },
  "35_68": { vi: "Vua Gậy và Năm Tiền: lãnh đạo lửa gặp thiếu thốn đất — nhà lãnh đạo có tầm nhìn trong hoàn cảnh khó khăn; Vua Gậy không bị đánh gục bởi nghịch cảnh — sức mạnh lãnh đạo thực sự thể hiện qua khả năng dẫn dắt người khác qua giai đoạn khó khăn và tìm ra con đường vượt qua thiếu thốn bằng sự sáng tạo và quyết tâm.", en: "King of Wands and Five of Pentacles: fire's leadership meets earth's scarcity — the visionary leader amid difficult circumstances; the King of Wands is not brought down by adversity — true leadership strength shows in the ability to guide others through difficult times and find a path through scarcity through creativity and determination." },
  "35_69": { vi: "Vua Gậy và Sáu Tiền: vua lửa gặp sự hào phóng đất — lãnh đạo hào phóng với cả tầm nhìn và nguồn lực; Sáu Tiền nâng cao Vua Gậy thành hình ảnh của nhà lãnh đạo không chỉ truyền cảm hứng mà còn cho đi rộng rãi, chia sẻ thành công với những người đã giúp xây dựng nên thành công đó.", en: "King of Wands and Six of Pentacles: fire's king meets earth's generosity — leadership generous with both vision and resources; the Six of Pentacles elevates the King of Wands into the image of the leader who not only inspires but also gives generously, sharing success with those who helped build it." },
  "35_70": { vi: "Vua Gậy và Bảy Tiền: vua lửa gặp sự kiên nhẫn đất — nhà lãnh đạo tầm nhìn trong giai đoạn chờ đợi kết quả; Vua Gậy đủ khôn ngoan để hiểu rằng một số thành quả lớn nhất cần thời gian dài để chín muồi, và Bảy Tiền nhắc nhở rằng đây là lúc để đánh giá và cân nhắc có chiến lược hơn là vội vàng.", en: "King of Wands and Seven of Pentacles: fire's king meets earth's patience — the visionary leader during a period of waiting for results; the King of Wands is wise enough to understand that some of the greatest achievements need a long time to ripen, and the Seven of Pentacles reminds that this is a time for strategic assessment and consideration rather than haste." },
  "35_71": { vi: "Vua Gậy và Tám Tiền: vua lửa gặp sự chuyên tâm đất — lãnh đạo tầm nhìn đánh giá cao kỷ luật chuyên môn; Vua Gậy biết rằng tầm nhìn mà không có kỹ năng chỉ là giấc mơ, và Tám Tiền đại diện cho sự cam kết với chất lượng và sự hoàn thiện mà người lãnh đạo giỏi phải nuôi dưỡng trong tổ chức của mình.", en: "King of Wands and Eight of Pentacles: fire's king meets earth's dedication — visionary leadership that values professional discipline; the King of Wands knows that vision without skill is merely a dream, and the Eight of Pentacles represents the commitment to quality and excellence that a great leader must cultivate within their organization." },
  "35_72": { vi: "Vua Gậy và Chín Tiền: vua lửa gặp sự sung túc đất — lãnh đạo có tầm nhìn và sự thịnh vượng; đây là hình ảnh của người đã dùng sức mạnh lãnh đạo để xây dựng sự thịnh vượng bền vững, và Chín Tiền đại diện cho kết quả của nhiều năm nỗ lực và tầm nhìn chiến lược của Vua Gậy.", en: "King of Wands and Nine of Pentacles: fire's king meets earth's abundance — visionary leadership and prosperity; the image of someone who has used leadership strength to build lasting prosperity, and the Nine of Pentacles represents the result of many years of effort and strategic vision by the King of Wands." },
  "35_73": { vi: "Vua Gậy và Mười Tiền: vua lửa gặp di sản đất — lãnh đạo có tầm nhìn xây dựng di sản bền vững; đây là sự kết hợp mạnh mẽ nhất của lửa và đất: tầm nhìn lãnh đạo kết hợp với sự ổn định gia đình tạo ra di sản thực sự có thể tồn tại qua nhiều thế hệ và tiếp tục truyền cảm hứng cho con cháu.", en: "King of Wands and Ten of Pentacles: fire's king meets earth's legacy — visionary leadership building a lasting legacy; the most powerful combination of fire and earth: leadership vision combined with family stability creating a genuine legacy that can endure across many generations and continue inspiring descendants." },
  "35_74": { vi: "Vua Gậy và Trang Bị Tiền: vua lửa gặp người học trò đất — nhà lãnh đạo và người mới bắt đầu; Vua Gậy có nhiều điều để dạy Trang Bị Tiền về tầm nhìn, quyết đoán, và lãnh đạo bằng ví dụ; trong khi đó Trang Bị Tiền nhắc nhở nhà lãnh đạo về sự quan trọng của việc nuôi dưỡng tài năng trẻ và đầu tư vào thế hệ tiếp theo.", en: "King of Wands and Page of Pentacles: fire's king meets earth's student — the leader and the beginner; the King of Wands has much to teach the Page of Pentacles about vision, decisiveness, and leading by example; meanwhile the Page reminds the leader of the importance of nurturing young talent and investing in the next generation." },
  "35_75": { vi: "Vua Gậy và Kỵ Sĩ Tiền: vua lửa gặp sự kiên định đất — lãnh đạo tầm nhìn và người thực hiện kiên định; Vua Gậy cung cấp hướng đi và truyền cảm hứng, Kỵ Sĩ Tiền thực hiện từng bước cẩn thận và kỹ lưỡng; đây là cặp đôi lý tưởng — người nghĩ ra ý tưởng và người biến ý tưởng thành hiện thực một cách bền vững.", en: "King of Wands and Knight of Pentacles: fire's king meets earth's steadiness — visionary leadership and the steady executor; the King of Wands provides direction and inspiration, the Knight of Pentacles executes step by careful and thorough step; the ideal pair — the one who conceives the idea and the one who turns it into lasting reality." },
  "35_76": { vi: "Vua Gậy và Nữ Hoàng Tiền: vua lửa gặp nữ hoàng đất — hai nhà lãnh đạo từ hai nguyên tố; Vua Gậy mang tầm nhìn và đam mê, Nữ Hoàng Tiền mang sự thực tế và sự nuôi dưỡng; khi cả hai cùng xuất hiện, họ đại diện cho sự lãnh đạo hoàn chỉnh — vừa có khả năng truyền cảm hứng vừa có khả năng chăm sóc và duy trì.", en: "King of Wands and Queen of Pentacles: fire's king meets earth's queen — two leaders from two elements; the King of Wands brings vision and passion, the Queen of Pentacles brings practicality and nurturing; when both appear together, they represent complete leadership — both the capacity to inspire and the capacity to care for and sustain." },
  "35_77": { vi: "Vua Gậy và Vua Tiền: hai vua từ hai nguyên tố — lửa và đất ở đỉnh cao thẩm quyền và trí tuệ của chúng; đây là sự gặp gỡ của hai nhà lãnh đạo với phẩm chất bổ sung nhau hoàn hảo: lửa mang tầm nhìn, đam mê và truyền cảm hứng; đất mang sự ổn định, thực tế và di sản; cùng nhau họ có thể xây dựng và duy trì những thứ phi thường.", en: "King of Wands and King of Pentacles: two kings from two elements — fire and earth at the peak of their authority and wisdom; the meeting of two leaders with perfectly complementary qualities: fire bringing vision, passion, and inspiration; earth bringing stability, practicality, and legacy; together they can build and sustain extraordinary things." },
  // ── Tier 5d-1: Cups × Swords, water×air (Cups 36–42 × Swords 50–63, 98 pairs) ──
  "36_50": { vi: "Át Cốc và Át Kiếm: hai khởi đầu — nước và khí ở điểm xuất phát nguyên thủy; cảm xúc thuần khiết gặp sự rõ ràng thuần khiết, và khi cả hai cùng xuất hiện, đây là khoảnh khắc mà trái tim và tâm trí đều sẵn sàng bắt đầu một điều gì đó thực sự mới.", en: "Ace of Cups and Ace of Swords: two beginnings — water and air at their primal starting points; pure emotion meeting pure clarity, and when both appear together, this is the moment when heart and mind are both ready to begin something genuinely new." },
  "36_51": { vi: "Át Cốc và Hai Kiếm: cảm xúc mới mẻ gặp sự do dự của tâm trí — trái tim đang mở ra trong khi tâm trí vẫn còn do dự chưa quyết; thách thức là để cảm xúc chân thật hướng dẫn sự phân tích thay vì để sự phân tích quá mức kìm hãm trái tim đang nở rộ.", en: "Ace of Cups and Two of Swords: new emotion meeting mental hesitation — the heart opening while the mind still waits undecided; the challenge is letting genuine feeling guide analysis rather than letting over-analysis restrain the blossoming heart." },
  "36_52": { vi: "Át Cốc và Ba Kiếm: tình cảm mới gặp nỗi đau — tình yêu hoặc sự kết nối mới đến trong thời điểm đau lòng; Át Cốc hứa hẹn sự chữa lành và Ba Kiếm thừa nhận vết thương còn đó, và đôi khi chính tình cảm mới là thứ giúp chúng ta vượt qua nỗi đau cũ.", en: "Ace of Cups and Three of Swords: new feeling meeting heartache — a new love or connection arriving during a time of grief; the Ace of Cups promises healing and the Three of Swords acknowledges wounds still present, and sometimes a new feeling is exactly what helps us move through old pain." },
  "36_53": { vi: "Át Cốc và Bốn Kiếm: tình cảm mới gặp sự nghỉ ngơi tâm trí — trái tim sẵn sàng mở ra nhưng tâm trí cần thêm thời gian phục hồi; đây là lời nhắc nhở rằng đôi khi điều tốt nhất dành cho một tình cảm mới là cho nó không gian và sự yên tĩnh để phát triển một cách tự nhiên.", en: "Ace of Cups and Four of Swords: new feeling meeting mental rest — the heart ready to open but the mind needing more recovery time; a reminder that sometimes the best thing for a new feeling is to give it space and quiet to grow naturally." },
  "36_54": { vi: "Át Cốc và Năm Kiếm: tình cảm mới gặp xung đột — trái tim muốn kết nối trong khi môi trường xung quanh đang tranh chấp; Át Cốc khuyến khích sự cởi mở nhưng Năm Kiếm cảnh báo về những người hoặc tình huống có thể lợi dụng sự dễ bị tổn thương của trái tim đang mở.", en: "Ace of Cups and Five of Swords: new feeling meeting conflict — the heart wanting connection while the surrounding environment is contentious; the Ace of Cups encourages openness but the Five of Swords warns of people or situations that may exploit the vulnerability of an opening heart." },
  "36_55": { vi: "Át Cốc và Sáu Kiếm: tình cảm mới gặp sự chuyển đổi — trái tim mở ra trong khi tâm trí đang rời bỏ điều cũ; đây là sự kết hợp của người đang trong hành trình chuyển đổi và mang theo tình cảm mới làm bạn đồng hành — hy vọng và chuyển động cùng tiến về phía trước.", en: "Ace of Cups and Six of Swords: new feeling meeting transition — the heart opening while the mind is leaving the old behind; the combination of someone on a journey of change carrying new feeling as a companion — hope and movement advancing together toward calmer waters." },
  "36_56": { vi: "Át Cốc và Bảy Kiếm: tình cảm mới gặp sự thận trọng — trái tim muốn tin tưởng nhưng tâm trí nhận thấy điều gì đó không ổn; đây là lúc cần cân bằng giữa sự cởi mở của cảm xúc và sự tỉnh táo của tư duy — không đóng cửa hoàn toàn nhưng cũng không mù quáng tin tưởng.", en: "Ace of Cups and Seven of Swords: new feeling meeting wariness — the heart wanting to trust while the mind notices something off; the moment requiring balance between emotional openness and mental alertness — not closing entirely but also not trusting blindly." },
  "36_57": { vi: "Át Cốc và Tám Kiếm: tình cảm mới gặp sự bị giam cầm tâm trí — trái tim đang mở ra nhưng tâm trí bị kẹt trong những suy nghĩ giới hạn; Át Cốc có thể là chìa khóa để phá vỡ xiềng xích tự áp đặt — đôi khi chính cảm xúc chân thật mới có thể giải phóng chúng ta khỏi tù ngục tư duy.", en: "Ace of Cups and Eight of Swords: new feeling meeting mental imprisonment — the heart opening but the mind trapped in limiting thoughts; the Ace of Cups may be the key to breaking self-imposed chains — sometimes genuine emotion is precisely what frees us from the prison of thought." },
  "36_58": { vi: "Át Cốc và Chín Kiếm: tình cảm mới gặp lo âu đêm khuya — trái tim đang mở ra trong khi tâm trí bị tra tấn bởi lo lắng; Át Cốc mang hy vọng và khả năng chữa lành, và khi cảm xúc yêu thương được đưa vào không gian lo âu, nó có thể bắt đầu làm dịu những cơn bão suy nghĩ.", en: "Ace of Cups and Nine of Swords: new feeling meeting night anxiety — the heart opening while the mind is tormented by worry; the Ace of Cups brings hope and the possibility of healing, and when loving emotion is brought into anxious space, it can begin to soothe the storms of thought." },
  "36_59": { vi: "Át Cốc và Mười Kiếm: tình cảm mới sau kết thúc — trái tim mở ra sau khi một chu kỳ cũ đã hoàn toàn kết thúc; đây là sự kết hợp của sự hồi sinh — Mười Kiếm đánh dấu kết thúc tuyệt đối và Át Cốc hứa hẹn rằng sau đêm tối dài nhất, một tình cảm mới có thể nở rộ.", en: "Ace of Cups and Ten of Swords: new feeling after endings — the heart opening after an old cycle has completely ended; the combination of rebirth — the Ten of Swords marking absolute completion and the Ace of Cups promising that after the longest night, a new feeling can bloom." },
  "36_60": { vi: "Át Cốc và Trang Bị Kiếm: tình cảm mới gặp tâm trí tò mò — trái tim mở ra và tâm trí trẻ trung muốn tìm hiểu; đây là sự kết hợp của người đang khám phá cả cảm xúc lẫn ý tưởng mới, và sự kết hợp này khuyến khích cả hai — hãy cảm nhận và hãy tư duy, không cần chọn một.", en: "Ace of Cups and Page of Swords: new feeling meeting a curious mind — the heart opening and a young mind wanting to understand; the combination of someone exploring both new emotions and new ideas, encouraging both — feel and think, no need to choose one over the other." },
  "36_61": { vi: "Át Cốc và Kỵ Sĩ Kiếm: tình cảm mới gặp hành động tư duy — trái tim mở ra trong khi tâm trí đang tiến về phía trước nhanh chóng; thách thức là không để tốc độ của tư duy qua mặt cảm xúc — tình cảm mới cần không gian để phát triển, không phải bị phân tích hoặc đẩy nhanh quá sớm.", en: "Ace of Cups and Knight of Swords: new feeling meeting swift thought — the heart opening while the mind charges forward quickly; the challenge is not letting the speed of thought outpace emotion — new feeling needs space to grow, not to be analyzed or rushed too early." },
  "36_62": { vi: "Át Cốc và Nữ Hoàng Kiếm: tình cảm mới gặp trí tuệ sắc bén — trái tim mở ra trước người có tư duy rõ ràng và sắc bén; Nữ Hoàng Kiếm không bác bỏ cảm xúc nhưng đòi hỏi sự chân thật — và khi tình cảm mới đối mặt với sự chân thật đó, chỉ những thứ thực sự mới tồn tại được.", en: "Ace of Cups and Queen of Swords: new feeling meeting sharp intellect — the heart opening before someone with clear and incisive thinking; the Queen of Swords does not dismiss emotion but demands authenticity — and when new feeling faces that truth, only what is genuine survives." },
  "36_63": { vi: "Át Cốc và Vua Kiếm: tình cảm mới gặp thẩm quyền tư duy — trái tim mở ra trước người có thẩm quyền trí tuệ và sự công bằng; Vua Kiếm đánh giá tình cảm bằng tiêu chuẩn của sự hợp lý và chân thật, và tình cảm nào vượt qua được bài kiểm tra đó là tình cảm thực sự xứng đáng được theo đuổi.", en: "Ace of Cups and King of Swords: new feeling meeting intellectual authority — the heart opening before someone of intellectual authority and fairness; the King of Swords evaluates feeling by the standards of reason and truth, and any feeling that passes that test is one genuinely worth pursuing." },
  "37_50": { vi: "Hai Cốc và Át Kiếm: kết nối cảm xúc gặp sự rõ ràng mới — mối quan hệ hoặc sự kết nối đang được nhìn nhận với đôi mắt rõ ràng hơn; Át Kiếm mang sự thật vào không gian của Hai Cốc và đôi khi sự thật đó củng cố kết nối, đôi khi nó buộc phải đối mặt với những điều chưa được nói.", en: "Two of Cups and Ace of Swords: emotional connection meeting new clarity — a relationship or connection being seen with clearer eyes; the Ace of Swords brings truth into the space of the Two of Cups and sometimes that truth strengthens the connection, sometimes it forces facing what has gone unsaid." },
  "37_51": { vi: "Hai Cốc và Hai Kiếm: kết nối cảm xúc gặp sự bế tắc tư duy — mối quan hệ cần quyết định nhưng tâm trí đang do dự; Hai Cốc nhắc nhở rằng có sự kết nối thực sự ở đây trong khi Hai Kiếm cho thấy cả hai bên đang né tránh nói chuyện thực sự — bước đầu tiên là đặt xuống kiếm và giao tiếp.", en: "Two of Cups and Two of Swords: emotional connection meeting mental deadlock — a relationship needing a decision but the mind hesitating; the Two of Cups reminds that genuine connection exists here while the Two of Swords shows both sides avoiding real conversation — the first step is putting down the swords and communicating." },
  "37_52": { vi: "Hai Cốc và Ba Kiếm: kết nối cảm xúc gặp nỗi đau tim — mối quan hệ đang trải qua hoặc đã trải qua sự tổn thương; Hai Cốc nhắc nhở về kết nối thực sự từng có trong khi Ba Kiếm thừa nhận vết thương — cả hai cùng xuất hiện đặt câu hỏi liệu kết nối đó có đủ mạnh để vượt qua nỗi đau không.", en: "Two of Cups and Three of Swords: emotional connection meeting heartbreak — a relationship experiencing or having experienced hurt; the Two of Cups recalls genuine connection that once existed while the Three of Swords acknowledges wounds — both appearing together asks whether that connection is strong enough to survive the pain." },
  "37_53": { vi: "Hai Cốc và Bốn Kiếm: kết nối cảm xúc gặp sự nghỉ ngơi — mối quan hệ đang trong giai đoạn tạm dừng hoặc cần không gian; đây không nhất thiết là xấu — đôi khi mối quan hệ mạnh mẽ nhất là những mối quan hệ biết cho nhau không gian để phục hồi và trở về với nhau được tươi mới hơn.", en: "Two of Cups and Four of Swords: emotional connection meeting rest — a relationship in a pause or needing space; this is not necessarily bad — sometimes the strongest relationships are those that know how to give each other space to recover and return renewed." },
  "37_54": { vi: "Hai Cốc và Năm Kiếm: kết nối cảm xúc gặp xung đột — mối quan hệ đang bị thử thách bởi tranh chấp hoặc cạnh tranh; thách thức là liệu cả hai bên có thể vượt qua cái tôi và chiến thắng để bảo vệ kết nối, hay cuộc chiến giành chiến thắng sẽ phá hủy chính mối quan hệ mà họ tranh đấu vì nó.", en: "Two of Cups and Five of Swords: emotional connection meeting conflict — a relationship being tested by dispute or competition; the challenge is whether both sides can move past ego and winning to protect the connection, or whether the fight to win will destroy the very relationship they are fighting over." },
  "37_55": { vi: "Hai Cốc và Sáu Kiếm: kết nối cảm xúc gặp sự chuyển đổi — mối quan hệ đang trải qua một giai đoạn chuyển đổi quan trọng; Sáu Kiếm cho thấy sự di chuyển từ vùng nước động sang yên tĩnh hơn, và Hai Cốc đảm bảo rằng kết nối cảm xúc vẫn còn đó trong suốt cuộc hành trình thay đổi.", en: "Two of Cups and Six of Swords: emotional connection meeting transition — a relationship going through an important period of change; the Six of Swords shows movement from turbulent toward calmer waters, and the Two of Cups assures that emotional connection remains present throughout the journey of change." },
  "37_56": { vi: "Hai Cốc và Bảy Kiếm: kết nối cảm xúc gặp sự không trung thực — mối quan hệ có thể đang bị ảnh hưởng bởi sự lừa dối hoặc che giấu; Hai Cốc đòi hỏi sự chân thật để kết nối thực sự, và khi Bảy Kiếm xuất hiện, đây là lời cảnh báo rằng bí mật hoặc sự không thành thật đang đe dọa nền tảng của mối quan hệ.", en: "Two of Cups and Seven of Swords: emotional connection meeting dishonesty — a relationship potentially being undermined by deception or concealment; the Two of Cups requires honesty for genuine connection, and when the Seven of Swords appears, it warns that secrets or dishonesty are threatening the foundation of the relationship." },
  "37_57": { vi: "Hai Cốc và Tám Kiếm: kết nối cảm xúc gặp sự tự giam cầm — một trong hai hoặc cả hai người trong mối quan hệ đang bị giới hạn bởi niềm tin sai lầm về bản thân; Hai Cốc nhắc nhở rằng kết nối thực sự có thể là sức mạnh giúp phá vỡ những giới hạn tự áp đặt đó.", en: "Two of Cups and Eight of Swords: emotional connection meeting self-imprisonment — one or both people in the relationship being limited by false beliefs about themselves; the Two of Cups reminds that genuine connection can be the very force that breaks through those self-imposed limitations." },
  "37_58": { vi: "Hai Cốc và Chín Kiếm: kết nối cảm xúc gặp lo âu — ai đó trong mối quan hệ đang bị tra tấn bởi lo lắng và sợ hãi; Hai Cốc gợi ý rằng sự kết nối và hỗ trợ từ người thân yêu có thể là liều thuốc tốt nhất cho lo âu — chúng ta không cần đối mặt với bóng tối một mình.", en: "Two of Cups and Nine of Swords: emotional connection meeting anxiety — someone in the relationship being tormented by worry and fear; the Two of Cups suggests that the connection and support of a loved one may be the best medicine for anxiety — we do not need to face darkness alone." },
  "37_59": { vi: "Hai Cốc và Mười Kiếm: kết nối cảm xúc sau sự sụp đổ — mối quan hệ đang hoặc đã trải qua một kết thúc đau đớn; Hai Cốc hỏi liệu kết nối cảm xúc còn đó có đủ sức mạnh để xây dựng lại, hay Mười Kiếm đánh dấu một kết thúc thực sự cần được tôn trọng để cả hai bên có thể tiến về phía trước.", en: "Two of Cups and Ten of Swords: emotional connection after collapse — a relationship experiencing or having experienced a painful ending; the Two of Cups asks whether the connection still there has sufficient strength to rebuild, or whether the Ten of Swords marks a true ending that must be honored so both can move forward." },
  "37_60": { vi: "Hai Cốc và Trang Bị Kiếm: kết nối cảm xúc gặp tâm trí tò mò trẻ — mối quan hệ đang được quan sát hoặc tham gia bởi người trẻ hoặc người mới; sự tò mò trí tuệ của Trang Bị Kiếm có thể làm phong phú thêm mối quan hệ bằng những góc nhìn mới, hoặc đặt ra những câu hỏi giúp cả hai hiểu sâu hơn về kết nối của mình.", en: "Two of Cups and Page of Swords: emotional connection meeting young curious mind — a relationship being observed or joined by someone young or new; the Page of Swords' intellectual curiosity can enrich the relationship with fresh perspectives, or raise questions that help both understand their connection more deeply." },
  "37_61": { vi: "Hai Cốc và Kỵ Sĩ Kiếm: kết nối cảm xúc gặp hành động quyết đoán — mối quan hệ đang đối mặt với sự quyết định nhanh chóng; Kỵ Sĩ Kiếm có thể làm xáo trộn sự bình yên của Hai Cốc bằng sự vội vàng, nhưng đôi khi chính sự quyết đoán đó là điều cần thiết để phá vỡ bế tắc trong mối quan hệ.", en: "Two of Cups and Knight of Swords: emotional connection meeting decisive action — a relationship facing swift decisions; the Knight of Swords may disrupt the peace of the Two of Cups with haste, but sometimes that very decisiveness is what is needed to break through stagnation in the relationship." },
  "37_62": { vi: "Hai Cốc và Nữ Hoàng Kiếm: kết nối cảm xúc gặp trí tuệ độc lập — mối quan hệ với người phụ nữ có tư duy sắc bén và độc lập; Nữ Hoàng Kiếm mang sự rõ ràng và chân thật vào mối quan hệ — không phải lạnh lùng mà là thực tế, và kết nối mạnh nhất với bà là kết nối có thể chịu đựng được sự thật.", en: "Two of Cups and Queen of Swords: emotional connection meeting independent intellect — a relationship with a woman of sharp and independent thinking; the Queen of Swords brings clarity and honesty to the relationship — not cold but clear-eyed, and the strongest connection with her is one that can withstand truth." },
  "37_63": { vi: "Hai Cốc và Vua Kiếm: kết nối cảm xúc gặp thẩm quyền trí tuệ — mối quan hệ với người có thẩm quyền và nguyên tắc; Vua Kiếm đánh giá cao sự trung thực và công bằng trong mối quan hệ, và Hai Cốc đảm bảo rằng kết nối cảm xúc thực sự là nền tảng — không chỉ là nghĩa vụ hay thỏa thuận.", en: "Two of Cups and King of Swords: emotional connection meeting intellectual authority — a relationship with someone of authority and principle; the King of Swords values honesty and fairness in relationships, and the Two of Cups ensures genuine emotional connection is the foundation — not merely obligation or arrangement." },
  "38_50": { vi: "Ba Cốc và Át Kiếm: sự ăn mừng gặp sự rõ ràng mới — niềm vui cộng đồng gặp một sự thật mới đột phá vào; Át Kiếm có thể mang tin tức hoặc nhận thức làm thay đổi động lực nhóm, và thách thức là tiếp nhận sự thật đó với sự cởi mở thay vì để nó phá vỡ tinh thần cộng đồng.", en: "Three of Cups and Ace of Swords: celebration meeting new clarity — communal joy meeting a new truth breaking through; the Ace of Swords may bring news or realization that changes the group dynamic, and the challenge is receiving that truth with openness rather than letting it fracture the community spirit." },
  "38_51": { vi: "Ba Cốc và Hai Kiếm: niềm vui cộng đồng gặp sự bế tắc — nhóm bạn hoặc cộng đồng đang đối mặt với quyết định khó khăn cần sự đồng thuận; Hai Kiếm cho thấy có sự lảng tránh đối thoại khó khăn, và Ba Cốc nhắc nhở rằng sức mạnh của nhóm nằm ở khả năng cùng nhau đối mặt với điều khó khăn.", en: "Three of Cups and Two of Swords: communal joy meeting deadlock — a group of friends or community facing a difficult decision needing consensus; the Two of Swords shows avoidance of difficult dialogue, and the Three of Cups reminds that the group's strength lies in its capacity to face difficulty together." },
  "38_52": { vi: "Ba Cốc và Ba Kiếm: niềm vui gặp nỗi đau — cộng đồng hoặc tình bạn đang trải qua một mất mát hoặc sự rạn nứt; đây là hình ảnh của những người bạn đến bên nhau trong thời điểm đau buồn, và Ba Cốc nhắc nhở rằng cộng đồng là nơi chúng ta nên tìm đến khi nỗi đau cần được chia sẻ.", en: "Three of Cups and Three of Swords: joy meeting grief — a community or friendship experiencing loss or fracture; the image of friends coming together in a moment of sorrow, and the Three of Cups reminds that community is where we should turn when pain needs to be shared." },
  "38_53": { vi: "Ba Cốc và Bốn Kiếm: ăn mừng gặp sự nghỉ ngơi — niềm vui cộng đồng bị tạm hoãn hoặc một người trong nhóm cần thời gian nghỉ ngơi; Bốn Kiếm không phải là từ chối cộng đồng mà là sự thừa nhận rằng đôi khi chúng ta cần rút lui để hồi phục trước khi có thể tham gia đầy đủ trở lại.", en: "Three of Cups and Four of Swords: celebration meeting rest — communal joy temporarily paused or one person in the group needing recovery time; the Four of Swords is not rejection of community but acknowledgment that sometimes we need to withdraw and recover before we can participate fully again." },
  "38_54": { vi: "Ba Cốc và Năm Kiếm: niềm vui cộng đồng gặp xung đột — sự bất hòa hoặc cạnh tranh phá vỡ sự hòa thuận của nhóm; đây là lời cảnh báo về những người trong nhóm đặt chiến thắng cá nhân lên trên phúc lợi tập thể, và Ba Cốc nhắc nhở rằng cộng đồng thực sự được xây dựng trên sự hỗ trợ lẫn nhau chứ không phải cạnh tranh.", en: "Three of Cups and Five of Swords: communal joy meeting conflict — discord or competition fracturing the group's harmony; a warning about people in the group placing personal winning above collective wellbeing, and the Three of Cups reminds that genuine community is built on mutual support not competition." },
  "38_55": { vi: "Ba Cốc và Sáu Kiếm: cộng đồng gặp sự chuyển đổi — nhóm đang trải qua một giai đoạn thay đổi cùng nhau; Sáu Kiếm cho thấy sự di chuyển đến nơi bình yên hơn và Ba Cốc đảm bảo rằng cộng đồng vẫn gắn kết trong suốt cuộc hành trình — những thay đổi tốt nhất là những thay đổi được chia sẻ cùng những người thân yêu.", en: "Three of Cups and Six of Swords: community meeting transition — a group going through a period of change together; the Six of Swords shows movement toward calmer waters and the Three of Cups ensures the community remains bonded throughout the journey — the best changes are those shared with loved ones." },
  "38_56": { vi: "Ba Cốc và Bảy Kiếm: niềm vui cộng đồng gặp sự không trung thực — có ai đó trong nhóm không hoàn toàn thành thật hoặc đang hành động vì lợi ích cá nhân che giấu; Ba Cốc nhắc nhở về giá trị của sự tin tưởng trong cộng đồng và Bảy Kiếm cảnh báo rằng sự dối trá có thể phá hủy điều đó nếu không được nhận ra.", en: "Three of Cups and Seven of Swords: communal joy meeting dishonesty — someone in the group not being fully honest or acting from hidden self-interest; the Three of Cups recalls the value of trust in community and the Seven of Swords warns that deception can destroy it if not recognized." },
  "38_57": { vi: "Ba Cốc và Tám Kiếm: cộng đồng gặp sự cô lập — ai đó cảm thấy bị mắc kẹt hoặc bị giam cầm bởi hoàn cảnh trong khi cộng đồng xung quanh đang ăn mừng; Ba Cốc nhắc nhở rằng cộng đồng thực sự không để ai lại phía sau — nếu thấy người bị bỏ lại, hãy mời họ trở về.", en: "Three of Cups and Eight of Swords: community meeting isolation — someone feeling trapped or imprisoned by circumstances while the surrounding community celebrates; the Three of Cups reminds that genuine community leaves no one behind — if you see someone left out, invite them back." },
  "38_58": { vi: "Ba Cốc và Chín Kiếm: niềm vui gặp lo âu đêm khuya — ai đó đang mỉm cười trong cộng đồng nhưng đau khổ trong bóng tối; Ba Cốc có thể là nơi che giấu sự lo lắng thực sự, và điều này nhắc nhở rằng những kết nối cộng đồng cần đủ sâu để mọi người có thể nói thật khi cần, không chỉ chia sẻ niềm vui.", en: "Three of Cups and Nine of Swords: joy meeting night anxiety — someone smiling within community but suffering in the dark; the Three of Cups can be a place where real worry is hidden, and this reminds that community connections need to be deep enough for people to speak truth when needed, not only share celebration." },
  "38_59": { vi: "Ba Cốc và Mười Kiếm: ăn mừng gặp kết thúc — cộng đồng đang trải qua hoặc đã trải qua một sự kết thúc lớn; Mười Kiếm đánh dấu sự kết thúc của một chu kỳ và Ba Cốc gợi ý rằng cộng đồng có thể giúp nhau vượt qua giai đoạn chuyển tiếp này — cùng nhau đau buồn và cùng nhau bắt đầu lại.", en: "Three of Cups and Ten of Swords: celebration meeting endings — a community experiencing or having experienced a major ending; the Ten of Swords marks the close of a cycle and the Three of Cups suggests that community can help one another through this transition — grieving together and beginning again together." },
  "38_60": { vi: "Ba Cốc và Trang Bị Kiếm: cộng đồng gặp trí tò mò trẻ — nhóm đang chào đón người mới hoặc người trẻ với góc nhìn mới; Trang Bị Kiếm mang năng lượng tươi mới và câu hỏi thử thách vào cộng đồng, và Ba Cốc đảm bảo rằng không gian cộng đồng đủ ấm áp để sự tò mò đó được nuôi dưỡng.", en: "Three of Cups and Page of Swords: community meeting young curiosity — the group welcoming someone new or young with a fresh perspective; the Page of Swords brings fresh energy and challenging questions into the community, and the Three of Cups ensures the communal space is warm enough for that curiosity to be nurtured." },
  "38_61": { vi: "Ba Cốc và Kỵ Sĩ Kiếm: niềm vui cộng đồng gặp hành động quyết đoán — ai đó trong nhóm đang thúc đẩy hành động nhanh chóng; Kỵ Sĩ Kiếm có thể mang lại sự phấn khích và đà tiến cho cộng đồng, hoặc có thể làm gián đoạn sự hài hòa nếu tốc độ và quyết đoán của họ không được cân bằng với sự đồng thuận của nhóm.", en: "Three of Cups and Knight of Swords: communal joy meeting decisive action — someone in the group pushing for swift action; the Knight of Swords can bring excitement and momentum to the community, or can disrupt harmony if their speed and decisiveness is not balanced with group consensus." },
  "38_62": { vi: "Ba Cốc và Nữ Hoàng Kiếm: cộng đồng gặp trí tuệ độc lập — nhóm được định hướng bởi người phụ nữ có tư duy sắc bén; Nữ Hoàng Kiếm có thể là người lãnh đạo cộng đồng mang lại sự rõ ràng và trung thực, và khi trí tuệ sắc bén kết hợp với tinh thần cộng đồng ấm áp, đó là sự lãnh đạo mạnh mẽ nhất.", en: "Three of Cups and Queen of Swords: community meeting independent intellect — the group being guided by a woman of sharp thinking; the Queen of Swords can be the community leader who brings clarity and honesty, and when sharp intellect combines with warm community spirit, that is the strongest form of leadership." },
  "38_63": { vi: "Ba Cốc và Vua Kiếm: cộng đồng gặp thẩm quyền — nhóm dưới sự lãnh đạo của người có thẩm quyền trí tuệ và nguyên tắc; Vua Kiếm có thể đặt ra các quy tắc và chuẩn mực giúp cộng đồng vận hành công bằng và hiệu quả, và khi thẩm quyền đó được đặt trong dịch vụ cho cộng đồng, đó là sức mạnh thực sự.", en: "Three of Cups and King of Swords: community meeting authority — the group under the leadership of someone of intellectual authority and principle; the King of Swords can establish rules and standards that help the community operate fairly and effectively, and when that authority is placed in service of community, that is genuine strength." },
  "39_50": { vi: "Bốn Cốc và Át Kiếm: sự chán nản gặp sự rõ ràng mới — người đang thờ ơ và không hài lòng được trao một sự thật mới hoặc cơ hội mới; Át Kiếm có thể là cú sốc nhận thức cần thiết để lay chuyển Bốn Cốc ra khỏi sự trì trệ — đôi khi chính sự rõ ràng đau đớn là thứ duy nhất phá vỡ sự thờ ơ.", en: "Four of Cups and Ace of Swords: apathy meeting new clarity — someone disengaged and dissatisfied being offered a new truth or new opportunity; the Ace of Swords can be the cognitive jolt needed to shake the Four of Cups from stagnation — sometimes painful clarity is the only thing that breaks through apathy." },
  "39_51": { vi: "Bốn Cốc và Hai Kiếm: thờ ơ gặp bế tắc — hai loại trì trệ kết hợp; người đang chán nản cũng đang né tránh quyết định khó khăn; đây là hình ảnh của sự tê liệt kép, và lối thoát đòi hỏi bước ra khỏi vùng an toàn của sự thờ ơ và đối mặt thẳng với những gì cần được quyết định.", en: "Four of Cups and Two of Swords: apathy meeting deadlock — two forms of stagnation combined; someone disengaged is also avoiding a difficult decision; the image of double paralysis, and the way out requires stepping outside the comfort zone of apathy and facing directly what needs deciding." },
  "39_52": { vi: "Bốn Cốc và Ba Kiếm: thờ ơ gặp nỗi đau — sự chán nản có thể là phản ứng với nỗi đau cảm xúc; đôi khi chúng ta rút lui vào sự thờ ơ như một cơ chế bảo vệ khỏi nỗi đau của Ba Kiếm; nhận ra điều này là bước đầu tiên — sự thờ ơ không chữa lành nỗi đau, chỉ trì hoãn nó.", en: "Four of Cups and Three of Swords: apathy meeting grief — disengagement may be a response to emotional pain; sometimes we retreat into apathy as a protective mechanism from the hurt of the Three of Swords; recognizing this is the first step — apathy does not heal pain, only delays it." },
  "39_53": { vi: "Bốn Cốc và Bốn Kiếm: hai lá bốn — sự rút lui nội tâm kép; cả cảm xúc lẫn tâm trí đều đang trong trạng thái tạm dừng và nghỉ ngơi; đây có thể là giai đoạn tĩnh lặng cần thiết hoặc là dấu hiệu của sự trì trệ quá mức — câu hỏi là liệu đây là sự phục hồi có chủ ý hay là sự né tránh vô thức.", en: "Four of Cups and Four of Swords: two fours — double inner withdrawal; both emotion and mind in a state of pause and rest; this may be a necessary period of stillness or a sign of excessive stagnation — the question is whether this is intentional recovery or unconscious avoidance." },
  "39_54": { vi: "Bốn Cốc và Năm Kiếm: thờ ơ gặp xung đột — người đang rút lui cảm xúc phải đối mặt với xung đột bên ngoài; Bốn Cốc muốn tránh né nhưng Năm Kiếm không cho phép — đây là lúc phải chọn: tiếp tục rút lui hay đứng lên đối mặt với những gì đang xảy ra xung quanh.", en: "Four of Cups and Five of Swords: apathy meeting conflict — someone emotionally withdrawn being confronted with external conflict; the Four of Cups wants to avoid but the Five of Swords does not allow it — the moment to choose: continue withdrawing or stand up and face what is happening around." },
  "39_55": { vi: "Bốn Cốc và Sáu Kiếm: thờ ơ gặp sự chuyển đổi — người đang trong trạng thái thờ ơ đang trải qua sự chuyển đổi dù họ có nhận ra hay không; Sáu Kiếm di chuyển về phía trước bất kể Bốn Cốc có muốn hay không, và đôi khi chính sự chuyển đổi bên ngoài là thứ lay chuyển chúng ta ra khỏi sự trì trệ.", en: "Four of Cups and Six of Swords: apathy meeting transition — someone in a state of disengagement undergoing transition whether they recognize it or not; the Six of Swords moves forward regardless of whether the Four of Cups wants to, and sometimes external transition is what shakes us out of stagnation." },
  "39_56": { vi: "Bốn Cốc và Bảy Kiếm: thờ ơ gặp mưu kế — người đang thờ ơ có thể đang bị lợi dụng bởi người có mục đích ẩn; Bốn Cốc không chú ý đủ để nhận ra Bảy Kiếm đang tiến hành, và sự thờ ơ này có thể trở thành cái giá đắt nếu không tỉnh giấc kịp thời.", en: "Four of Cups and Seven of Swords: apathy meeting scheming — someone disengaged may be taken advantage of by someone with hidden agenda; the Four of Cups is not paying enough attention to notice the Seven of Swords in action, and this disengagement can carry a high price if not awakened in time." },
  "39_57": { vi: "Bốn Cốc và Tám Kiếm: thờ ơ và tự giam cầm — hai hình thức trạng thái bị mắc kẹt cùng xuất hiện; cả hai đều có thể được tự tạo ra và cả hai đều có thể được phá vỡ từ bên trong; nhận ra rằng rào cản thực sự không phải là bên ngoài mà là trong nhận thức và thái độ của chính mình.", en: "Four of Cups and Eight of Swords: apathy and self-imprisonment — two forms of being stuck appearing together; both can be self-created and both can be broken from within; recognizing that the real barriers are not external but within one's own perception and attitude." },
  "39_58": { vi: "Bốn Cốc và Chín Kiếm: thờ ơ và lo âu — người đang thờ ơ bên ngoài nhưng bị tra tấn bởi lo lắng bên trong; Bốn Cốc có thể là mặt nạ che giấu Chín Kiếm bên dưới, và điều cần làm không phải là đẩy cảm xúc xuống sâu hơn mà là mang chúng ra ánh sáng để được xử lý.", en: "Four of Cups and Nine of Swords: apathy and anxiety — someone outwardly disengaged but inwardly tormented by worry; the Four of Cups may be a mask hiding the Nine of Swords beneath, and what is needed is not pushing feelings deeper but bringing them to light to be processed." },
  "39_59": { vi: "Bốn Cốc và Mười Kiếm: thờ ơ gặp kết thúc — giai đoạn thờ ơ đang đến điểm kết thúc buộc phải thay đổi; Mười Kiếm đánh dấu sự kết thúc của một giai đoạn và có thể là cú sốc cuối cùng làm thức tỉnh Bốn Cốc — đôi khi chúng ta cần chạm đến đáy trước khi sẵn sàng mở mắt nhìn về phía trước.", en: "Four of Cups and Ten of Swords: apathy meeting endings — a period of disengagement reaching a point of forced change; the Ten of Swords marks the end of a phase and may be the final shock that awakens the Four of Cups — sometimes we need to touch bottom before being ready to open our eyes and look forward." },
  "39_60": { vi: "Bốn Cốc và Trang Bị Kiếm: thờ ơ gặp tâm trí tò mò — ai đó đang thờ ơ gặp người trẻ đầy câu hỏi; Trang Bị Kiếm có thể kéo Bốn Cốc ra khỏi sự thờ ơ bằng những câu hỏi và quan điểm mới — đôi khi chính sự nhiệt huyết của người khác là thứ nhắc nhở chúng ta về những gì chúng ta đã mất đi.", en: "Four of Cups and Page of Swords: apathy meeting curious mind — someone disengaged encountering a young person full of questions; the Page of Swords can pull the Four of Cups from apathy through new questions and perspectives — sometimes the enthusiasm of others is what reminds us of what we have lost touch with." },
  "39_61": { vi: "Bốn Cốc và Kỵ Sĩ Kiếm: thờ ơ gặp năng lượng quyết đoán — người đang rút lui cảm xúc bị kéo vào vòng xoáy hành động của người khác; Kỵ Sĩ Kiếm không chờ đợi sự sẵn sàng của Bốn Cốc — và đôi khi bị kéo vào hành động trước khi sẵn sàng chính là điều cần thiết để phá vỡ sự trì trệ.", en: "Four of Cups and Knight of Swords: apathy meeting decisive energy — someone emotionally withdrawn being pulled into another's vortex of action; the Knight of Swords does not wait for the Four of Cups to be ready — and sometimes being pulled into action before feeling ready is exactly what is needed to break stagnation." },
  "39_62": { vi: "Bốn Cốc và Nữ Hoàng Kiếm: thờ ơ gặp trí tuệ sắc bén — người đang thờ ơ đối mặt với người có sự rõ ràng và sắc bén; Nữ Hoàng Kiếm không có sự kiên nhẫn với sự tự thương hại hoặc sự trì trệ không cần thiết, và sự thẳng thắn của bà đôi khi là thứ người đang thờ ơ cần nghe nhất.", en: "Four of Cups and Queen of Swords: apathy meeting sharp intellect — someone disengaged facing someone of clarity and incisiveness; the Queen of Swords has no patience for self-pity or unnecessary stagnation, and her directness is sometimes exactly what the disengaged person most needs to hear." },
  "39_63": { vi: "Bốn Cốc và Vua Kiếm: thờ ơ gặp thẩm quyền — người đang thờ ơ đứng trước người có thẩm quyền và sự rõ ràng; Vua Kiếm có thể nhìn thấy qua sự thờ ơ đến nguyên nhân thực sự bên dưới, và khả năng phân tích khách quan của ông có thể giúp người đang thờ ơ hiểu được tại sao họ đang trốn tránh và cần phải làm gì.", en: "Four of Cups and King of Swords: apathy meeting authority — someone disengaged standing before someone of authority and clarity; the King of Swords can see through apathy to the real cause beneath, and his objective analytical ability can help the disengaged person understand why they are avoiding and what needs to be done." },
  "40_50": { vi: "Năm Cốc và Át Kiếm: mất mát gặp sự rõ ràng mới — nỗi buồn và tiếc nuối đang được nhìn nhận với đôi mắt rõ ràng hơn; Át Kiếm có thể mang sự thật làm đau nhưng cần thiết — nhận ra những gì đã mất là thật và những gì vẫn còn là thật, và với sự rõ ràng đó, có thể bắt đầu tiến về phía trước.", en: "Five of Cups and Ace of Swords: loss meeting new clarity — grief and regret being seen with clearer eyes; the Ace of Swords may bring a painful but necessary truth — recognizing what has been lost is real and what remains is real, and with that clarity, moving forward can begin." },
  "40_51": { vi: "Năm Cốc và Hai Kiếm: mất mát gặp bế tắc — người đang đau buồn đang né tránh đối mặt với quyết định về những gì còn lại; Hai Kiếm có thể đại diện cho sự từ chối nhìn nhận thực tại mất mát, và Năm Cốc nhắc nhở rằng vẫn còn những cốc chưa bị đổ phía sau — nhưng chỉ khi quay lại mới thấy được.", en: "Five of Cups and Two of Swords: loss meeting deadlock — someone grieving avoiding facing decisions about what remains; the Two of Swords may represent refusal to look at the reality of loss, and the Five of Cups reminds that there are still cups standing behind — but only visible by turning around." },
  "40_52": { vi: "Năm Cốc và Ba Kiếm: nỗi buồn kép — mất mát cảm xúc và nỗi đau tim đến cùng nhau; đây là giai đoạn đặc biệt khó khăn nhưng cũng là giai đoạn cần sự thành thật về chiều sâu của nỗi đau — không có gì sai khi thừa nhận rằng đây là giai đoạn đau đớn thực sự và cần sự hỗ trợ.", en: "Five of Cups and Three of Swords: compounded sorrow — emotional loss and heartbreak arriving together; a particularly difficult period but also one requiring honesty about the depth of pain — nothing wrong with acknowledging that this is a genuinely painful time and that support is needed." },
  "40_53": { vi: "Năm Cốc và Bốn Kiếm: đau buồn gặp nghỉ ngơi — người đang mang nỗi mất mát cần thời gian phục hồi; Bốn Kiếm cho phép người đang đau buồn thở và không phải giả vờ ổn trước khi thực sự ổn — sự phục hồi từ mất mát cần thời gian và không gian, và đó là điều hợp lý.", en: "Five of Cups and Four of Swords: grief meeting rest — someone carrying loss needing recovery time; the Four of Swords allows the grieving person to breathe and not pretend to be okay before they are — recovery from loss needs time and space, and that is entirely reasonable." },
  "40_54": { vi: "Năm Cốc và Năm Kiếm: mất mát gặp xung đột — nỗi đau đang bị phức tạp thêm bởi tranh cãi hoặc trách móc; đây là hoàn cảnh đặc biệt khó khăn khi nỗi buồn và xung đột cùng tồn tại, và điều quan trọng nhất là tránh để việc trách móc trở thành cách xử lý nỗi đau.", en: "Five of Cups and Five of Swords: loss meeting conflict — grief being complicated by argument or blame; a particularly difficult circumstance when sorrow and conflict coexist, and the most important thing is avoiding letting blame become the way of processing pain." },
  "40_55": { vi: "Năm Cốc và Sáu Kiếm: mất mát gặp chuyển đổi — người đang đau buồn đang di chuyển về phía trước dù cảm thấy chưa sẵn sàng; Sáu Kiếm không nói rằng nỗi đau đã hết mà nói rằng hành trình tiếp tục — và đôi khi chỉ cần cho phép bản thân bước tiếp là bước đầu tiên của sự chữa lành.", en: "Five of Cups and Six of Swords: loss meeting transition — someone grieving moving forward even while not feeling ready; the Six of Swords does not say the pain is gone but that the journey continues — and sometimes simply allowing oneself to take the next step is the first act of healing." },
  "40_56": { vi: "Năm Cốc và Bảy Kiếm: mất mát gặp mưu kế — ai đó có thể đang lợi dụng sự đau buồn của người khác; khi chúng ta đang đau buồn, chúng ta dễ bị tổn thương hơn và Bảy Kiếm cảnh báo về những người có thể lợi dụng khoảng thời gian dễ bị tổn thương này để phục vụ lợi ích cá nhân của họ.", en: "Five of Cups and Seven of Swords: loss meeting scheming — someone may be taking advantage of another's grief; when grieving we are more vulnerable and the Seven of Swords warns of those who may exploit this period of vulnerability to serve their own interests." },
  "40_57": { vi: "Năm Cốc và Tám Kiếm: mất mát gặp tự giam cầm — người đang đau buồn đang bị kẹt trong vòng lặp của sự tiếc nuối; cả hai lá đều liên quan đến việc không thể tiến về phía trước, và bước đầu tiên là nhận ra rằng mình đang tự giam cầm bằng cách tập trung vào những gì đã mất thay vì những gì còn lại.", en: "Five of Cups and Eight of Swords: loss meeting self-imprisonment — someone grieving trapped in a loop of regret; both cards involve inability to move forward, and the first step is recognizing that one is self-imprisoning by focusing on what was lost rather than what remains." },
  "40_58": { vi: "Năm Cốc và Chín Kiếm: mất mát và lo âu đêm khuya — nỗi đau ban ngày trở thành sự tra tấn ban đêm; đây là sự kết hợp của hai nỗi đau sâu sắc nhất, và điều quan trọng là nhận ra rằng cả hai đều có thể được chữa lành — không nhất thiết phải chịu đựng một mình trong bóng tối.", en: "Five of Cups and Nine of Swords: loss and night anxiety — daytime pain becoming nighttime torment; the combination of two of the deepest forms of hurt, and the important thing is recognizing that both can be healed — there is no need to endure either alone in the dark." },
  "40_59": { vi: "Năm Cốc và Mười Kiếm: mất mát gặp kết thúc tuyệt đối — nỗi đau của mất mát kết hợp với sự kết thúc hoàn toàn; đây là điểm thấp nhất, nhưng cũng là điểm mà mọi con đường đều đi về phía trước — khi không còn gì để mất, chúng ta buộc phải đối mặt với những cốc vẫn còn đứng phía sau và bắt đầu lại.", en: "Five of Cups and Ten of Swords: loss meeting absolute ending — the pain of loss combined with complete conclusion; the lowest point, but also the point from which every path leads forward — when nothing more can be lost, we are forced to face the cups still standing behind us and begin again." },
  "40_60": { vi: "Năm Cốc và Trang Bị Kiếm: mất mát gặp tâm trí tò mò — người đang đau buồn gặp ai đó muốn hiểu và hỏi; Trang Bị Kiếm có thể là người bạn trẻ đặt câu hỏi về nỗi đau, và đôi khi chính những câu hỏi chân thật đó giúp chúng ta bắt đầu đặt tên cho những gì chúng ta đang cảm nhận và tiến đến sự chữa lành.", en: "Five of Cups and Page of Swords: loss meeting curious mind — someone grieving encountering someone who wants to understand and asks; the Page of Swords may be the young friend who asks about the pain, and sometimes those genuine questions help us begin naming what we feel and moving toward healing." },
  "40_61": { vi: "Năm Cốc và Kỵ Sĩ Kiếm: mất mát gặp hành động nhanh — người đang đau buồn bị đẩy hoặc thúc ép phải tiến về phía trước trước khi sẵn sàng; đôi khi chúng ta cần người thúc đẩy, nhưng đôi khi sự thúc đẩy quá nhanh chỉ đẩy đau buồn xuống sâu hơn thay vì xử lý nó thực sự.", en: "Five of Cups and Knight of Swords: loss meeting swift action — someone grieving being pushed or urged to move forward before ready; sometimes we need someone to motivate us, but sometimes pushing too quickly only drives grief deeper rather than genuinely processing it." },
  "40_62": { vi: "Năm Cốc và Nữ Hoàng Kiếm: mất mát gặp trí tuệ sắc bén — người đang đau buồn nhận được sự rõ ràng từ người thẳng thắn; Nữ Hoàng Kiếm có thể đặt tên chính xác cho những gì đã xảy ra mà không làm trầm trọng thêm, và đôi khi sự rõ ràng không cảm xúc là điều chúng ta cần nhất khi chìm đắm trong cảm xúc.", en: "Five of Cups and Queen of Swords: loss meeting sharp intellect — someone grieving receiving clarity from someone direct; the Queen of Swords can name exactly what happened without dramatizing, and sometimes unemotional clarity is what we need most when drowning in feeling." },
  "40_63": { vi: "Năm Cốc và Vua Kiếm: mất mát gặp thẩm quyền công bằng — người đang đau buồn tìm đến người có thẩm quyền để được hướng dẫn; Vua Kiếm có thể cung cấp quan điểm khách quan về mất mát — không lạnh lùng mà công bằng — và giúp người đang đau buồn thấy con đường tiến về phía trước một cách rõ ràng.", en: "Five of Cups and King of Swords: loss meeting fair authority — someone grieving turning to someone of authority for guidance; the King of Swords can provide an objective perspective on loss — not cold but fair — and help the grieving person see the path forward clearly." },
  "41_50": { vi: "Sáu Cốc và Át Kiếm: ký ức gặp sự rõ ràng mới — quá khứ đang được nhìn nhận với cái nhìn rõ ràng hơn; Át Kiếm có thể mang sự thật về những ký ức đẹp — nhận ra điều gì thực sự tốt, điều gì được lý tưởng hóa, và điều gì thực sự cần được mang theo vào tương lai.", en: "Six of Cups and Ace of Swords: memory meeting new clarity — the past being seen with clearer eyes; the Ace of Swords may bring truth about cherished memories — recognizing what was genuinely good, what was idealized, and what truly needs to be carried forward into the future." },
  "41_51": { vi: "Sáu Cốc và Hai Kiếm: ký ức gặp bế tắc — đang bị mắc kẹt giữa quá khứ và tương lai, không thể quyết định; Sáu Cốc kéo về phía những ngày qua và Hai Kiếm tê liệt trước quyết định — để tiến về phía trước, phải chấp nhận rằng quá khứ là quá khứ và đặt xuống gánh nặng của cả hai.", en: "Six of Cups and Two of Swords: memory meeting deadlock — stuck between past and future, unable to decide; the Six of Cups pulls toward former days and the Two of Swords paralyzes before decisions — to move forward, one must accept that the past is past and set down the burden of both." },
  "41_52": { vi: "Sáu Cốc và Ba Kiếm: ký ức đẹp gặp nỗi đau — những kỷ niệm tốt đẹp bị tô màu bởi nỗi đau hiện tại hoặc nhận ra sự thật về quá khứ đó; đôi khi chính những ký ức tươi đẹp nhất là những thứ đau nhất khi chúng bị mất, và Ba Kiếm thừa nhận nỗi đau thực sự của sự tương phản đó.", en: "Six of Cups and Three of Swords: beautiful memory meeting pain — good memories colored by present pain or recognition of truth about that past; sometimes the most beautiful memories are the most painful when lost, and the Three of Swords acknowledges the real hurt of that contrast." },
  "41_53": { vi: "Sáu Cốc và Bốn Kiếm: ký ức gặp sự nghỉ ngơi — đang tạm thời rút lui vào những kỷ niệm cũ như một nơi nghỉ ngơi; Bốn Kiếm cho phép điều này như một giai đoạn phục hồi nhưng nhắc nhở rằng không nên ở lại trong ký ức quá lâu — nghỉ ngơi trong quá khứ là tốt, nhưng cuộc sống đang ở phía trước.", en: "Six of Cups and Four of Swords: memory meeting rest — temporarily withdrawing into old memories as a resting place; the Four of Swords permits this as a recovery phase but reminds that one should not stay in memory too long — resting in the past is fine, but life lies ahead." },
  "41_54": { vi: "Sáu Cốc và Năm Kiếm: ký ức gặp xung đột — tranh cãi về quá khứ hoặc những kỷ niệm cũ đang gây ra xung đột hiện tại; Năm Kiếm cảnh báo về việc dùng quá khứ như vũ khí trong tranh luận — ký ức có thể được hiểu rất khác nhau bởi những người khác nhau và đây không phải là cuộc chiến đáng để chiến đấu.", en: "Six of Cups and Five of Swords: memory meeting conflict — arguing about the past or old memories causing present conflict; the Five of Swords warns about using the past as a weapon in argument — memories can be understood very differently by different people and this is not a battle worth fighting." },
  "41_55": { vi: "Sáu Cốc và Sáu Kiếm: ký ức và sự chuyển đổi — đang rời xa quá khứ để tiến về tương lai trong khi vẫn mang theo những ký ức quý giá; đây là sự chuyển đổi lành mạnh nhất — không chối bỏ quá khứ mà học từ nó và mang những bài học tốt nhất theo hành trình mới.", en: "Six of Cups and Six of Swords: memory and transition — moving away from the past toward the future while carrying precious memories; the healthiest form of transition — not denying the past but learning from it and carrying the best lessons into the new journey." },
  "41_56": { vi: "Sáu Cốc và Bảy Kiếm: ký ức gặp mưu kế — có ai đó đang sử dụng sự gắn bó với quá khứ của bạn để lợi dụng bạn; hoặc chính bạn đang sử dụng ký ức để lừa dối bản thân về thực tế hiện tại — cả hai đều cần sự tỉnh táo để nhận ra.", en: "Six of Cups and Seven of Swords: memory meeting scheming — someone using your attachment to the past to take advantage of you; or you yourself using memory to deceive yourself about present reality — both require clear-eyed awareness to recognize." },
  "41_57": { vi: "Sáu Cốc và Tám Kiếm: ký ức và tự giam cầm — bị mắc kẹt trong quá khứ đến mức không thể thấy những lựa chọn hiện tại; Tám Kiếm nhắc nhở rằng những hạn chế thường là tự áp đặt — và bám víu vào ký ức quá khứ có thể là cái blindfold ngăn chúng ta nhìn thấy con đường phía trước.", en: "Six of Cups and Eight of Swords: memory and self-imprisonment — so stuck in the past that present options cannot be seen; the Eight of Swords reminds that limitations are often self-imposed — and clinging to past memories can be the blindfold preventing us from seeing the path ahead." },
  "41_58": { vi: "Sáu Cốc và Chín Kiếm: ký ức gặp lo âu đêm khuya — những kỷ niệm cũ đang nuôi dưỡng lo lắng và hối hận; Chín Kiếm thường liên quan đến những suy nghĩ dồn dập về quá khứ, và Sáu Cốc nhắc nhở rằng không phải mọi điều trong quá khứ đều xấu — hãy tìm lại những ký ức chữa lành thay vì chỉ những ký ức gây đau.", en: "Six of Cups and Nine of Swords: memory meeting night anxiety — old memories feeding worry and regret; the Nine of Swords often involves racing thoughts about the past, and the Six of Cups reminds that not everything in the past was bad — seek out healing memories rather than only the painful ones." },
  "41_59": { vi: "Sáu Cốc và Mười Kiếm: ký ức gặp kết thúc — một chương cũ đã thực sự kết thúc và chỉ còn ký ức; Mười Kiếm đánh dấu sự hoàn tất và Sáu Cốc giữ lại những gì đẹp — đây là quá trình lành mạnh của sự kết thúc: thừa nhận nó đã qua, trân trọng những gì tốt đẹp, và buông tay với sự biết ơn.", en: "Six of Cups and Ten of Swords: memory meeting endings — an old chapter truly ended and only memories remain; the Ten of Swords marks completion and the Six of Cups preserves what was beautiful — the healthy process of ending: acknowledging it is over, honoring what was good, and releasing with gratitude." },
  "41_60": { vi: "Sáu Cốc và Trang Bị Kiếm: ký ức gặp tâm trí trẻ tò mò — chia sẻ ký ức và câu chuyện với người trẻ; Trang Bị Kiếm muốn học hỏi và Sáu Cốc có câu chuyện để kể — đây là sự kết hợp đẹp khi kinh nghiệm được truyền đạt với sự chân thật và người trẻ nhận nó với sự tò mò và cởi mở.", en: "Six of Cups and Page of Swords: memory meeting young curious mind — sharing memories and stories with someone young; the Page of Swords wants to learn and the Six of Cups has stories to tell — a beautiful combination when experience is shared with honesty and the young person receives it with curiosity and openness." },
  "41_61": { vi: "Sáu Cốc và Kỵ Sĩ Kiếm: ký ức gặp hành động quyết đoán — ai đó đang cố gắng kéo bạn ra khỏi ký ức quá khứ bằng hành động hiện tại; Kỵ Sĩ Kiếm không muốn nhìn về phía sau và Sáu Cốc không muốn nhìn về phía trước — sự căng thẳng này có thể là lực đẩy cần thiết hoặc là sự đụng độ không mong muốn.", en: "Six of Cups and Knight of Swords: memory meeting decisive action — someone trying to pull you out of past memories through present action; the Knight of Swords does not want to look back and the Six of Cups does not want to look forward — this tension can be the necessary push or an unwelcome clash." },
  "41_62": { vi: "Sáu Cốc và Nữ Hoàng Kiếm: ký ức gặp trí tuệ sắc bén — nhìn lại quá khứ với đôi mắt rõ ràng và không lãng mạn hóa; Nữ Hoàng Kiếm giúp tách biệt những gì thực sự tốt đẹp trong quá khứ với những gì chỉ là sự lý tưởng hóa, và sự rõ ràng đó là cần thiết để học đúng bài học từ ký ức.", en: "Six of Cups and Queen of Swords: memory meeting sharp intellect — looking back at the past with clear eyes and no romanticization; the Queen of Swords helps separate what was genuinely good in the past from what was merely idealized, and that clarity is necessary for learning the right lessons from memory." },
  "41_63": { vi: "Sáu Cốc và Vua Kiếm: ký ức gặp thẩm quyền — quá khứ đang được đánh giá bởi người có quan điểm công bằng và khách quan; Vua Kiếm có thể giúp hiểu những gì thực sự xảy ra trong quá khứ mà không bị cảm xúc làm mờ, và từ đó đưa ra những bài học thực sự hữu ích cho hiện tại và tương lai.", en: "Six of Cups and King of Swords: memory meeting authority — the past being assessed by someone with fair and objective perspective; the King of Swords can help understand what truly happened in the past without emotion clouding it, and from that draw genuinely useful lessons for the present and future." },
  "42_50": { vi: "Bảy Cốc và Át Kiếm: ảo tưởng gặp sự rõ ràng — tâm trí đang chìm đắm trong nhiều khả năng và ước mơ được đưa đến bước ngoặt của sự rõ ràng; Át Kiếm cắt qua màn sương của Bảy Cốc và hỏi: trong tất cả những điều bạn mơ ước, điều nào là thật và điều nào là sự trốn tránh?", en: "Seven of Cups and Ace of Swords: illusion meeting clarity — a mind lost in many possibilities and dreams being brought to a turning point of clarity; the Ace of Swords cuts through the Seven of Cups' fog and asks: among all you dream of, which is real and which is avoidance?" },
  "42_51": { vi: "Bảy Cốc và Hai Kiếm: ảo tưởng gặp bế tắc — đang bị choáng ngợp bởi quá nhiều lựa chọn đến mức tê liệt hoàn toàn; cả Bảy Cốc lẫn Hai Kiếm đều không thúc đẩy hành động — kết hợp này là cảnh báo mạnh về sự tê liệt phân tích và nhu cầu chọn một hướng đi dù chưa hoàn hảo.", en: "Seven of Cups and Two of Swords: illusion meeting deadlock — overwhelmed by too many options to the point of complete paralysis; neither the Seven of Cups nor the Two of Swords pushes toward action — this combination is a strong warning about analysis paralysis and the need to choose a direction even if imperfect." },
  "42_52": { vi: "Bảy Cốc và Ba Kiếm: ảo tưởng gặp nỗi đau — giấc mơ và ảo tưởng bị phá vỡ bởi thực tế đau đớn; Ba Kiếm đâm vào bong bóng của Bảy Cốc và dù đau, đây là bước cần thiết để nhìn nhận thực tế thay vì trốn vào những ước mơ không bao giờ trở thành sự thật.", en: "Seven of Cups and Three of Swords: illusion meeting pain — dreams and illusions being shattered by painful reality; the Three of Swords bursts the Seven of Cups' bubble and while painful, this is the necessary step toward seeing reality rather than taking refuge in dreams that will never materialize." },
  "42_53": { vi: "Bảy Cốc và Bốn Kiếm: ảo tưởng gặp nghỉ ngơi — tâm trí cần nghỉ ngơi khỏi những ảo tưởng đang quay vòng; Bốn Kiếm gợi ý rằng bước ra khỏi vòng quay của Bảy Cốc và cho phép tâm trí được yên tĩnh có thể giúp thấy rõ hơn những gì thực sự quan trọng khi trở lại.", en: "Seven of Cups and Four of Swords: illusion meeting rest — the mind needing rest from the spinning illusions; the Four of Swords suggests that stepping out of the Seven of Cups' carousel and allowing the mind to be quiet may reveal what truly matters more clearly upon return." },
  "42_54": { vi: "Bảy Cốc và Năm Kiếm: ảo tưởng gặp xung đột — tranh chấp hoặc thất bại trong thực tế làm tan vỡ ảo tưởng; Năm Kiếm mang sự thất vọng và Bảy Cốc bị buộc phải đối mặt với thực tế sau khi ảo tưởng bị phá vỡ — điều này đau nhưng cũng là cơ hội để xây dựng lại kỳ vọng dựa trên nền tảng thực tế.", en: "Seven of Cups and Five of Swords: illusion meeting conflict — dispute or defeat in reality shattering illusions; the Five of Swords brings disillusionment and the Seven of Cups is forced to confront reality after illusions are broken — this hurts but is also the opportunity to rebuild expectations on a realistic foundation." },
  "42_55": { vi: "Bảy Cốc và Sáu Kiếm: ảo tưởng gặp sự chuyển đổi — đang rời bỏ thế giới của ảo tưởng để tiến về thực tế bình yên hơn; Sáu Kiếm mang hành trình từ ảo tưởng đến sự rõ ràng và đây là một trong những chuyển đổi lành mạnh nhất — không bị ép buộc bởi khủng hoảng mà được hướng dẫn bởi sự sẵn sàng bên trong.", en: "Seven of Cups and Six of Swords: illusion meeting transition — leaving the world of illusion toward calmer reality; the Six of Swords carries the journey from illusion toward clarity and this is one of the healthiest transitions — not forced by crisis but guided by inner readiness." },
  "42_56": { vi: "Bảy Cốc và Bảy Kiếm: ảo tưởng gặp mưu kế — đây là sự kết hợp nguy hiểm nhất; ai đó đang bị che mắt bởi ảo tưởng trong khi người khác đang lợi dụng điều đó; hoặc chính bạn đang tự lừa dối và đồng thời lừa dối người khác — cần sự trung thực triệt để với chính mình.", en: "Seven of Cups and Seven of Swords: illusion meeting scheming — the most dangerous combination; someone blinded by illusion while another exploits it; or you yourself both self-deceiving and deceiving others — radical honesty with oneself is required." },
  "42_57": { vi: "Bảy Cốc và Tám Kiếm: ảo tưởng và tự giam cầm — bị mắc kẹt trong thế giới ảo tưởng tự tạo; cả hai lá đều liên quan đến sự tự đặt ra giới hạn — Bảy Cốc che giấu thực tế bằng giấc mơ và Tám Kiếm bị bao quanh bởi nỗi sợ tự tạo; lối thoát là nhìn thẳng vào thực tế dù nó có vẻ đáng sợ.", en: "Seven of Cups and Eight of Swords: illusion and self-imprisonment — trapped in a self-created world of illusion; both cards relate to self-imposed limitations — the Seven of Cups hiding reality with dreams and the Eight of Swords surrounded by self-created fears; the way out is looking directly at reality even if it seems frightening." },
  "42_58": { vi: "Bảy Cốc và Chín Kiếm: ảo tưởng và lo âu đêm khuya — tâm trí đang chạy trốn vào ảo tưởng ban ngày và bị tra tấn bởi lo lắng ban đêm; hai thái cực của cùng một vấn đề — tâm trí không thể định vị bản thân trong thực tế và do đó dao động giữa mơ mộng và kinh hoàng.", en: "Seven of Cups and Nine of Swords: illusion and night anxiety — the mind escaping into daytime illusion and being tormented by nighttime worry; two extremes of the same problem — a mind unable to anchor itself in reality and so oscillating between fantasy and terror." },
  "42_59": { vi: "Bảy Cốc và Mười Kiếm: ảo tưởng gặp kết thúc tuyệt đối — ảo tưởng bị phá vỡ hoàn toàn bởi một kết thúc không thể phủ nhận; Mười Kiếm không cho phép Bảy Cốc tiếp tục mơ mộng nữa — đây là thời điểm đối mặt với thực tế hoàn toàn, và dù đau đớn, đây là điểm xuất phát của sự thức tỉnh thực sự.", en: "Seven of Cups and Ten of Swords: illusion meeting absolute ending — illusions completely shattered by an undeniable conclusion; the Ten of Swords does not permit the Seven of Cups to continue dreaming — the moment of full confrontation with reality, and while painful, this is the starting point of genuine awakening." },
  "42_60": { vi: "Bảy Cốc và Trang Bị Kiếm: ảo tưởng gặp tâm trí tò mò trẻ — ai đó còn trẻ đang khám phá thế giới của ảo tưởng và khả năng; Trang Bị Kiếm có thể giúp Bảy Cốc bằng cách đặt những câu hỏi thực tế về những gì thực sự có thể đạt được, giúp chắt lọc giấc mơ thành những mục tiêu cụ thể.", en: "Seven of Cups and Page of Swords: illusion meeting young curious mind — someone young exploring the world of illusion and possibility; the Page of Swords can help the Seven of Cups by asking practical questions about what is actually achievable, helping distill dreams into specific goals." },
  "42_61": { vi: "Bảy Cốc và Kỵ Sĩ Kiếm: ảo tưởng gặp hành động quyết đoán — ai đó đang chạy về phía trước mà không rõ ràng về mục tiêu; Kỵ Sĩ Kiếm mang năng lượng và quyết đoán nhưng nếu không có mục tiêu rõ ràng từ việc chắt lọc Bảy Cốc, năng lượng đó có thể bị lãng phí vào những hướng sai.", en: "Seven of Cups and Knight of Swords: illusion meeting decisive action — someone charging forward without clarity about the destination; the Knight of Swords brings energy and decisiveness but without a clear goal distilled from the Seven of Cups, that energy may be wasted in wrong directions." },
  "42_62": { vi: "Bảy Cốc và Nữ Hoàng Kiếm: ảo tưởng gặp trí tuệ sắc bén — người đang chìm đắm trong ảo tưởng gặp người có thể nhìn thấy thực tế rõ ràng; Nữ Hoàng Kiếm không tàn nhẫn nhưng thẳng thắn — bà có thể giúp chắt lọc những gì thực sự có thể từ biển ảo tưởng và đưa ra con đường thực tế để tiến về phía trước.", en: "Seven of Cups and Queen of Swords: illusion meeting sharp intellect — someone lost in illusion encountering someone who sees reality clearly; the Queen of Swords is not cruel but direct — she can help distill what is genuinely possible from the sea of illusion and offer a practical path forward." },
  "42_63": { vi: "Bảy Cốc và Vua Kiếm: ảo tưởng gặp thẩm quyền — giấc mơ và ảo tưởng được đánh giá bởi người có tư duy chiến lược và công bằng; Vua Kiếm không phải kẻ giết giấc mơ mà là người giúp xác định những giấc mơ nào đáng đầu tư và những giấc mơ nào là sự trốn tránh — sự phán xét của ông có giá trị chính xác vì nó không bị thiên vị bởi cảm xúc.", en: "Seven of Cups and King of Swords: illusion meeting authority — dreams and illusions assessed by someone of strategic and fair thinking; the King of Swords is not a dream-killer but someone who helps identify which dreams are worth investing in and which are avoidance — his judgment is valuable precisely because it is unbiased by emotion." },
  // ── Tier 5d-2: Cups × Swords, water×air (Cups 43–49 × Swords 50–63, 98 pairs) ──
  "43_50": { vi: "Tám Cốc và Át Kiếm: rời bỏ điều quen thuộc để đón nhận sự rõ ràng mới — nước chảy ra khỏi cốc cũ, khí mang theo lưỡi kiếm bắt đầu hành trình sáng suốt.", en: "Eight of Cups and Ace of Swords: leaving the familiar to embrace new clarity — water flowing from old cups, air carrying the sword's fresh beginning toward illuminated journey." },
  "43_51": { vi: "Tám Cốc và Hai Kiếm: rút lui để tránh quyết định khó khăn — nước tìm kiếm bình yên khi khí đứng giữa ngã rẽ, hai bên cùng đóng băng chưa sẵn sàng chọn lựa.", en: "Eight of Cups and Two of Swords: retreating to avoid a difficult decision — water seeking peace while air stands at the crossroads, both sides frozen not yet ready to choose." },
  "43_52": { vi: "Tám Cốc và Ba Kiếm: rời bỏ điều gây đau — nước chảy đi khỏi nỗi đau cũ, khí cắt đứt sợi dây buộc chặt trái tim tổn thương không còn lành mạnh.", en: "Eight of Cups and Three of Swords: walking away from what caused pain — water flowing from old hurt, air severing the ties that kept the wounded heart from healing." },
  "43_53": { vi: "Tám Cốc và Bốn Kiếm: rút lui vào nghỉ ngơi sau khi rời bỏ — nước tìm không gian mới, khí lặng yên phục hồi trước chương tiếp theo của cuộc hành trình.", en: "Eight of Cups and Four of Swords: retreating into rest after departure — water finding new space, air resting quietly before the next chapter of the journey unfolds." },
  "43_54": { vi: "Tám Cốc và Năm Kiếm: bỏ đi sau thất bại — nước rút lui khỏi trận thua, khí mang theo bài học đắt giá của cuộc xung đột không cần thiết đã qua.", en: "Eight of Cups and Five of Swords: walking away after defeat — water retreating from a lost battle, air carrying the costly lesson of unnecessary conflict now behind." },
  "43_55": { vi: "Tám Cốc và Sáu Kiếm: hành trình rời bỏ dẫn đến vùng nước bình yên hơn — nước và khí cùng chuyển sang bến bờ mới với sự nhẹ nhõm chậm rãi dần dần.", en: "Eight of Cups and Six of Swords: the departure journey leads to calmer waters — water and air crossing together to new shores with gradual and growing relief." },
  "43_56": { vi: "Tám Cốc và Bảy Kiếm: rời bỏ lén lút hay chân thành — nước trốn khỏi điều không còn phù hợp, khí mang theo bí mật chưa được nói ra trong suốt cuộc rời đi.", en: "Eight of Cups and Seven of Swords: departing secretly or honestly — water escaping what no longer fits, air carrying unspoken secrets along throughout the departure." },
  "43_57": { vi: "Tám Cốc và Tám Kiếm: bị giữ lại dù muốn rời đi — nước khao khát chảy xa, khí trói buộc trong những giới hạn tự tạo chưa sẵn sàng để buông bỏ.", en: "Eight of Cups and Eight of Swords: wanting to leave but feeling bound — water longing to flow away, air caught in self-made limitations not yet ready to release." },
  "43_58": { vi: "Tám Cốc và Chín Kiếm: rời bỏ trong đêm lo âu — nước chảy đi trong bóng tối, khí mang những nỗi sợ đeo bám theo từng bước chân rời xa không dứt.", en: "Eight of Cups and Nine of Swords: departing in anxious darkness — water flowing away in shadow, air carrying lingering fears along every retreating step taken." },
  "43_59": { vi: "Tám Cốc và Mười Kiếm: rời bỏ sau điểm tận cùng — nước chảy từ đáy vực, khí đánh dấu kết thúc đau đớn nhường chỗ cho buổi bình minh hoàn toàn mới.", en: "Eight of Cups and Ten of Swords: leaving after hitting rock bottom — water flowing from the lowest point, air marking the painful end that gives way to entirely new dawn." },
  "43_60": { vi: "Tám Cốc và Trang Bị Kiếm: rời bỏ với tư duy sắc bén mới mẻ — nước tìm con đường khác, khí trẻ trung đặt câu hỏi trước khi dấn bước vào bước tiếp theo.", en: "Eight of Cups and Page of Swords: departing with fresh sharp thinking — water seeking another path, youthful air questioning carefully before taking the next step forward." },
  "43_61": { vi: "Tám Cốc và Kỵ Sĩ Kiếm: rời bỏ nhanh chóng và dứt khoát — nước bỏ lại đằng sau, khí xông tới phía trước với tốc độ không cho phép nhìn lại đường cũ.", en: "Eight of Cups and Knight of Swords: departing swiftly and decisively — water left behind, air charging forward at a speed that allows no looking back at old roads." },
  "43_62": { vi: "Tám Cốc và Nữ Hoàng Kiếm: rời bỏ với cái đầu lạnh — nước hiểu rằng đây là thời điểm, khí phán xét rõ ràng dù trái tim vẫn còn lưu luyến điều cũ.", en: "Eight of Cups and Queen of Swords: departing with a clear head — water knowing this is the moment, air judging clearly even as the heart still lingers on what was." },
  "43_63": { vi: "Tám Cốc và Vua Kiếm: quyết định rời bỏ từ lý trí — nước tuân theo tâm trí sáng suốt, khí hoàng gia phán xét rằng tiếp tục ở lại không còn phục vụ mục đích nào.", en: "Eight of Cups and King of Swords: the decision to leave comes from reason — water following clear-minded authority, royal air judging that staying further serves no meaningful purpose." },
  "44_50": { vi: "Chín Cốc và Át Kiếm: thỏa mãn cảm xúc gặp khởi đầu trí tuệ — nước chứa đầy ước muốn thành hiện thực, khí mang đến câu hỏi mới cho những điều đã đạt được.", en: "Nine of Cups and Ace of Swords: emotional satisfaction meets intellectual beginning — water brimming with wishes fulfilled, air bringing new questions to what has been achieved." },
  "44_51": { vi: "Chín Cốc và Hai Kiếm: hài lòng nhưng tránh nhìn nhận sự thật — nước đầy mà không muốn xáo trộn, khí đứng yên che đi câu trả lời mà lòng không muốn nghe.", en: "Nine of Cups and Two of Swords: content but avoiding truth — water full yet unwilling to be disturbed, air standing still to block answers the heart doesn't want to hear." },
  "44_52": { vi: "Chín Cốc và Ba Kiếm: hạnh phúc bị đau làm nứt vỡ — nước đầy ắp gặp lưỡi kiếm đâm xuyên, nhắc rằng thỏa mãn không che chắn được nỗi đau bất ngờ ập đến.", en: "Nine of Cups and Three of Swords: happiness cracked by pain — water overflowing meets piercing blades, reminding that contentment cannot shield against unexpected sorrow arriving." },
  "44_53": { vi: "Chín Cốc và Bốn Kiếm: nghỉ ngơi trong sự mãn nguyện — nước đầy lặng yên, khí hồi phục sức mạnh trước khi bước tiếp với trái tim no đủ và bình an.", en: "Nine of Cups and Four of Swords: resting in contentment — water still and full, air restoring strength before moving forward with a satisfied and deeply grateful heart." },
  "44_54": { vi: "Chín Cốc và Năm Kiếm: mãn nguyện bị phá vỡ bởi xung đột — nước đầy ắp bị khuấy động, khí xung đột cướp đi cảm giác đủ đầy từng tưởng bền vững lâu dài.", en: "Nine of Cups and Five of Swords: contentment shattered by conflict — water overflowing disturbed by strife, air's conflict stealing the sense of fullness once thought permanent." },
  "44_55": { vi: "Chín Cốc và Sáu Kiếm: mang sự mãn nguyện sang bến bờ mới — nước đầy và bình yên di chuyển, khí dẫn lối tới không gian bình thản hơn phía trước với niềm tin.", en: "Nine of Cups and Six of Swords: carrying contentment to new shores — water full and peaceful in motion, air guiding toward calmer space ahead with quiet confidence." },
  "44_56": { vi: "Chín Cốc và Bảy Kiếm: thỏa mãn che giấu điều gì đó — nước đầy mà không hoàn toàn trung thực, khí lén lút gợi ý rằng có điều chưa nói sau nụ cười hài lòng.", en: "Nine of Cups and Seven of Swords: satisfaction concealing something — water full but not entirely honest, sly air suggesting something unsaid behind the contented smile." },
  "44_57": { vi: "Chín Cốc và Tám Kiếm: mãn nguyện bên ngoài, giam cầm bên trong — nước đầy ắp nhưng khí trói chặt, cảm giác thỏa mãn bề ngoài che đi sự bất an sâu thẳm bên trong.", en: "Nine of Cups and Eight of Swords: outward contentment, inner captivity — water overflowing but air binding tight, surface satisfaction masking deeper unease lurking within." },
  "44_58": { vi: "Chín Cốc và Chín Kiếm: hạnh phúc ngày không xua tan lo âu đêm — nước đầy dưới ánh sáng, khí tra tấn trong bóng tối khi mọi người đã chìm vào giấc ngủ.", en: "Nine of Cups and Nine of Swords: daytime happiness that doesn't dispel nighttime anxiety — water full in daylight, air tormenting in darkness when all else is asleep." },
  "44_59": { vi: "Chín Cốc và Mười Kiếm: đỉnh cao mãn nguyện trước khi sụp đổ — nước đầy tràn đến giây phút cuối, khí đánh dấu kết thúc đau đớn của chu kỳ thỏa mãn vừa qua.", en: "Nine of Cups and Ten of Swords: peak contentment before collapse — water overflowing until the final moment, air marking the painful end of the satisfaction cycle." },
  "44_60": { vi: "Chín Cốc và Trang Bị Kiếm: mãn nguyện khơi dậy tò mò — nước đầy ắp nhưng trí trẻ muốn khám phá thêm, khí đặt câu hỏi về điều gì nằm ngoài cảm giác đủ đầy.", en: "Nine of Cups and Page of Swords: contentment sparking curiosity — water brimming but young air wanting to explore more, questioning what lies beyond the feeling of enough." },
  "44_61": { vi: "Chín Cốc và Kỵ Sĩ Kiếm: thỏa mãn không giữ chân được tinh thần xông pha — nước đầy mà khí xốc nổi cần tiếp tục tiến, kỵ sĩ ham chinh phục chưa thể bằng lòng dừng lại.", en: "Nine of Cups and Knight of Swords: satisfaction cannot hold the charging spirit — water full but impulsive air needing to push forward, the conquering knight unable to stay content." },
  "44_62": { vi: "Chín Cốc và Nữ Hoàng Kiếm: mãn nguyện từ góc nhìn trí tuệ — nước đầy được nữ hoàng đánh giá công bằng, khí rõ ràng xác nhận rằng hạnh phúc này là thật và xứng đáng.", en: "Nine of Cups and Queen of Swords: contentment assessed with intellectual clarity — water full evaluated fairly by the queen, clear air confirming this happiness is real and deserved." },
  "44_63": { vi: "Chín Cốc và Vua Kiếm: mãn nguyện được khẳng định bởi quyền uy — nước đầy ắp nhận được sự công nhận của trí tuệ chủ quyền, hạnh phúc đúng đắn được vua kiếm phê chuẩn.", en: "Nine of Cups and King of Swords: contentment affirmed by sovereign authority — overflowing water receiving the recognition of masterful intellect, rightful happiness approved by the king." },
  "45_50": { vi: "Mười Cốc và Át Kiếm: hạnh phúc viên mãn gặp khởi đầu sắc bén — nước tràn đầy yêu thương gia đình, khí mang đến sự rõ ràng mới cho những gì đã trọn vẹn và hoàn chỉnh.", en: "Ten of Cups and Ace of Swords: complete happiness meets sharp beginning — water overflowing with family love, air bringing fresh clarity to what is already whole and perfect." },
  "45_51": { vi: "Mười Cốc và Hai Kiếm: hài hòa gia đình gặp quyết định khó — nước bình yên nhưng khí đứng giữa ngã rẽ, sự viên mãn bị thử thách khi phải chọn lựa mà không ai muốn.", en: "Ten of Cups and Two of Swords: family harmony meets a difficult choice — water peaceful but air at crossroads, completeness tested when choices must be made that no one wants." },
  "45_52": { vi: "Mười Cốc và Ba Kiếm: đau làm nứt hạnh phúc gia đình — nước đầy yêu thương bị ba lưỡi kiếm xé toạc, nhắc rằng không mái nhà nào tránh khỏi cơn bão trái tim.", en: "Ten of Cups and Three of Swords: pain cracking family happiness — water full of love pierced by three blades, reminding that no home is entirely shielded from heartbreak." },
  "45_53": { vi: "Mười Cốc và Bốn Kiếm: nghỉ ngơi trong hạnh phúc viên mãn — nước gia đình lặng yên, khí hồi phục bình thản trong không gian yêu thương đã hoàn chỉnh và bình an.", en: "Ten of Cups and Four of Swords: resting within complete happiness — family water still and peaceful, air recovering quietly within a space of love already whole and serene." },
  "45_54": { vi: "Mười Cốc và Năm Kiếm: xung đột đe dọa sự hòa hợp — nước gia đình viên mãn bị khuấy động, khí xung đột kiểm tra liệu tình yêu thật sự có thể chịu đựng áp lực hay không.", en: "Ten of Cups and Five of Swords: conflict threatening harmony — complete family water disturbed by strife, air's conflict testing whether true love can genuinely withstand the pressure." },
  "45_55": { vi: "Mười Cốc và Sáu Kiếm: dẫn gia đình đến bến bờ bình yên hơn — nước viên mãn di chuyển cùng nhau, khí dẫn lối qua thời kỳ chuyển tiếp đến không gian an lành phía trước.", en: "Ten of Cups and Six of Swords: guiding the family to calmer shores — complete water moving together, air leading through transition to peaceful space waiting ahead with promise." },
  "45_56": { vi: "Mười Cốc và Bảy Kiếm: có điều gì đó bị che giấu trong hạnh phúc — nước gia đình đầy đủ nhưng khí lén lút gợi rằng bề mặt bình yên không phải toàn bộ câu chuyện.", en: "Ten of Cups and Seven of Swords: something hidden within happiness — full family water but sly air suggesting the peaceful surface isn't the entire story of what's within." },
  "45_57": { vi: "Mười Cốc và Tám Kiếm: hạnh phúc bên ngoài, trói buộc bên trong — nước gia đình viên mãn che đi ai đó đang bị giam cầm, bầu trời cầu vồng không thuộc về tất cả mọi người.", en: "Ten of Cups and Eight of Swords: outward happiness, inner captivity — complete family water concealing someone bound, the rainbow sky not belonging equally to everyone present." },
  "45_58": { vi: "Mười Cốc và Chín Kiếm: niềm vui ban ngày, lo âu ban đêm — nước gia đình ấm áp nhưng khí tra tấn trong đêm khuya, hạnh phúc chung không xua được nỗi sợ riêng.", en: "Ten of Cups and Nine of Swords: daytime joy, nighttime anxiety — warm family water but air tormenting in the deep night, shared happiness unable to chase away private fears." },
  "45_59": { vi: "Mười Cốc và Mười Kiếm: kết thúc chu kỳ hạnh phúc gia đình — nước viên mãn đến điểm cuối, khí đánh dấu sự chuyển hóa đau đớn trước khi bình minh gia đình mới bắt đầu.", en: "Ten of Cups and Ten of Swords: the family happiness cycle reaching its end — complete water at the final point, air marking painful transformation before a new family dawn begins." },
  "45_60": { vi: "Mười Cốc và Trang Bị Kiếm: hạnh phúc gia đình khơi dậy tò mò trẻ thơ — nước viên mãn nuôi dưỡng trí tuệ non trẻ, khí trẻ đặt câu hỏi về thế giới từ nền tảng yêu thương.", en: "Ten of Cups and Page of Swords: family happiness nurturing young curiosity — complete water nourishing youthful intellect, young air questioning the world from a foundation of love." },
  "45_61": { vi: "Mười Cốc và Kỵ Sĩ Kiếm: gia đình viên mãn nhưng ai đó cần lên đường — nước đầy ắp tình thương nhưng khí xốc nổi cần chinh phục, hạnh phúc nhà không giữ được bước chân phiêu lưu.", en: "Ten of Cups and Knight of Swords: complete family but someone must ride out — water full of love but impulsive air needing conquest, home happiness unable to hold the adventurous spirit." },
  "45_62": { vi: "Mười Cốc và Nữ Hoàng Kiếm: hạnh phúc gia đình được nhìn bằng con mắt trí tuệ — nước viên mãn được nữ hoàng đánh giá thực tế, khí rõ ràng xác nhận tình yêu thật sự đứng vững.", en: "Ten of Cups and Queen of Swords: family happiness viewed with intellectual eyes — complete water assessed realistically by the queen, clear air confirming true love genuinely stands firm." },
  "45_63": { vi: "Mười Cốc và Vua Kiếm: gia đình viên mãn dưới sự lãnh đạo công minh — nước hạnh phúc được bảo vệ bởi trí tuệ quyền uy, hòa hợp gia đình đứng vững trong cấu trúc rõ ràng.", en: "Ten of Cups and King of Swords: complete family under fair leadership — happy water protected by authoritative intellect, family harmony standing firm within clear and just structure." },
  "46_50": { vi: "Trang Bị Cốc và Át Kiếm: trái tim non trẻ gặp sự rõ ràng mới — nước cảm xúc tươi mới đón nhận lưỡi kiếm khai mở, sự ngây thơ của tình cảm gặp độ sắc bén của tư duy.", en: "Page of Cups and Ace of Swords: young heart meets new clarity — fresh emotional water receiving the opening blade, innocence of feeling meeting the sharpness of clear thought." },
  "46_51": { vi: "Trang Bị Cốc và Hai Kiếm: trái tim non ngại đưa ra quyết định — nước cảm xúc trẻ thơ đứng trước ngã rẽ của khí, sự nhạy cảm và lý trí cùng đóng băng trước lựa chọn.", en: "Page of Cups and Two of Swords: young heart hesitant to decide — youthful emotional water before air's crossroads, sensitivity and reason both frozen before the necessary choice." },
  "46_52": { vi: "Trang Bị Cốc và Ba Kiếm: trái tim trẻ bị đau lần đầu — nước cảm xúc non nớt gặp ba lưỡi kiếm, bài học đau đớn đầu tiên về việc yêu thương và mất mát trong cuộc đời.", en: "Page of Cups and Three of Swords: young heart experiencing pain for the first time — tender emotional water meeting three blades, the first painful lesson about loving and losing." },
  "46_53": { vi: "Trang Bị Cốc và Bốn Kiếm: trái tim trẻ cần nghỉ ngơi — nước cảm xúc ngây thơ tạm lắng, khí nghỉ ngơi giúp tâm hồn non nớt phục hồi trước những trải nghiệm cảm xúc tiếp theo.", en: "Page of Cups and Four of Swords: young heart needing rest — innocent emotional water settling, air's rest helping the tender soul recover before the next emotional experiences arrive." },
  "46_54": { vi: "Trang Bị Cốc và Năm Kiếm: trái tim trẻ học bài học xung đột — nước cảm xúc non nớt gặp sự xung đột, bài học quan trọng về ranh giới và việc không phải ai cũng đáng tin tưởng.", en: "Page of Cups and Five of Swords: young heart learning lessons of conflict — tender emotional water meeting strife, an important lesson about boundaries and not everyone being trustworthy." },
  "46_55": { vi: "Trang Bị Cốc và Sáu Kiếm: trái tim trẻ vượt qua thời khó — nước cảm xúc ngây thơ di chuyển sang bình thản, khí dẫn tâm hồn nhỏ qua giai đoạn chuyển tiếp nhẹ nhàng hơn.", en: "Page of Cups and Six of Swords: young heart moving through difficulty — innocent emotional water transitioning to calmer space, air guiding the young soul through gentler passage." },
  "46_56": { vi: "Trang Bị Cốc và Bảy Kiếm: trái tim trẻ học sự lừa dối — nước cảm xúc ngây thơ gặp khí láu cá, bài học đắt giá về sự không trung thực và cần giữ ranh giới rõ ràng.", en: "Page of Cups and Seven of Swords: young heart learning about deception — innocent emotional water meeting sly air, a costly lesson about dishonesty and the need for clear boundaries." },
  "46_57": { vi: "Trang Bị Cốc và Tám Kiếm: trái tim trẻ cảm thấy bị giam cầm — nước cảm xúc non nớt bị trói buộc bởi những giới hạn chưa hiểu, khí giam cầm tâm hồn nhạy cảm trong vô thức.", en: "Page of Cups and Eight of Swords: young heart feeling trapped — tender emotional water bound by misunderstood limits, air imprisoning the sensitive soul within unconscious self-restriction." },
  "46_58": { vi: "Trang Bị Cốc và Chín Kiếm: trái tim trẻ bị lo âu làm phiền — nước cảm xúc ngây thơ gặp những nỗi sợ đêm khuya, tâm hồn non nớt học cách đối diện với bóng tối bên trong.", en: "Page of Cups and Nine of Swords: young heart troubled by anxiety — innocent emotional water meeting nighttime fears, tender soul learning to face the darkness lurking within itself." },
  "46_59": { vi: "Trang Bị Cốc và Mười Kiếm: trái tim trẻ đối mặt với kết thúc — nước cảm xúc non nớt gặp đáy của khí, bài học sâu sắc rằng những kết thúc đau đớn cũng mang theo bình minh mới.", en: "Page of Cups and Ten of Swords: young heart facing an ending — tender emotional water meeting air's lowest point, a profound lesson that painful endings also carry new dawns within." },
  "46_60": { vi: "Trang Bị Cốc và Trang Bị Kiếm: hai tâm hồn trẻ gặp nhau — nước cảm xúc ngây thơ và khí tò mò sắc bén cùng khám phá thế giới, sự kết hợp tươi mới của trái tim và trí tuệ.", en: "Page of Cups and Page of Swords: two young souls meeting — innocent emotional water and sharp curious air exploring the world together, a fresh combination of heart and intellect." },
  "46_61": { vi: "Trang Bị Cốc và Kỵ Sĩ Kiếm: trái tim trẻ bị cuốn vào cuộc phiêu lưu nhanh — nước cảm xúc ngây thơ bị xốc nổi của khí kéo đi, tốc độ kỵ sĩ thách thức độ sâu cảm xúc.", en: "Page of Cups and Knight of Swords: young heart swept into a fast adventure — innocent emotional water pulled by air's impulsiveness, the knight's speed challenging emotional depth." },
  "46_62": { vi: "Trang Bị Cốc và Nữ Hoàng Kiếm: trái tim trẻ học từ người phụ nữ minh mẫn — nước cảm xúc non nớt được nữ hoàng khí hướng dẫn, sự rõ ràng của bà giúp tâm hồn trẻ hiểu cảm xúc sâu hơn.", en: "Page of Cups and Queen of Swords: young heart learning from a clear-minded woman — tender emotional water guided by the queen of air, her clarity helping the young soul understand feelings more deeply." },
  "46_63": { vi: "Trang Bị Cốc và Vua Kiếm: trái tim trẻ trước quyền uy trí tuệ — nước cảm xúc ngây thơ gặp khí quyền uy, vua kiếm dạy trang bị cốc rằng cảm xúc cần được định hướng bởi sự rõ ràng.", en: "Page of Cups and King of Swords: young heart before intellectual authority — innocent emotional water meeting authoritative air, the king teaching the page that feelings need clarity's guidance." },
  "47_50": { vi: "Kỵ Sĩ Cốc và Át Kiếm: người lãng mạn gặp lưỡi kiếm rõ ràng — nước cảm xúc hào hoa đón nhận khởi đầu sắc bén, sự lãng mạn được thử thách bởi sự thật chưa mềm mại.", en: "Knight of Cups and Ace of Swords: the romantic meets the clear blade — gallant emotional water receiving the sharp beginning, romance challenged by truth not yet softened by feeling." },
  "47_51": { vi: "Kỵ Sĩ Cốc và Hai Kiếm: người lãng mạn đứng trước quyết định — nước cảm xúc hào hoa gặp ngã rẽ của khí, trái tim muốn theo cảm xúc nhưng lý trí đứng yên như bức tường.", en: "Knight of Cups and Two of Swords: the romantic facing a decision — gallant emotional water at air's crossroads, heart wanting to follow feeling but reason standing still like a wall." },
  "47_52": { vi: "Kỵ Sĩ Cốc và Ba Kiếm: trái tim lãng mạn bị đau — nước cảm xúc hào hoa gặp ba lưỡi kiếm, nỗi đau của kỵ sĩ cốc khi lý tưởng gặp thực tế phũ phàng không khoan nhượng.", en: "Knight of Cups and Three of Swords: the romantic heart in pain — gallant emotional water meeting three blades, the knight's heartbreak when ideals collide with harsh unforgiving reality." },
  "47_53": { vi: "Kỵ Sĩ Cốc và Bốn Kiếm: người lãng mạn dừng lại hồi phục — nước cảm xúc hào hoa tạm lắng, khí nghỉ ngơi giúp kỵ sĩ cốc nạp lại năng lượng tình cảm trước cuộc hành trình mới.", en: "Knight of Cups and Four of Swords: the romantic pausing to recover — gallant emotional water settling, air's rest helping the knight recharge emotional energy before a new journey begins." },
  "47_54": { vi: "Kỵ Sĩ Cốc và Năm Kiếm: người lãng mạn trong xung đột — nước cảm xúc hào hoa gặp khí chiến thắng bằng mọi giá, lý tưởng kỵ sĩ cốc bị thử thách bởi người không có nguyên tắc.", en: "Knight of Cups and Five of Swords: the romantic in conflict — gallant emotional water meeting win-at-all-costs air, the knight's ideals challenged by someone without principles or honor." },
  "47_55": { vi: "Kỵ Sĩ Cốc và Sáu Kiếm: người lãng mạn dẫn đến bình yên — nước cảm xúc hào hoa di chuyển sang bờ bình thản, khí dẫn lối giúp kỵ sĩ vượt qua giai đoạn khó đến không gian ôn hòa.", en: "Knight of Cups and Six of Swords: the romantic moving toward peace — gallant emotional water transitioning to calmer shores, air guiding the knight through difficulty to gentle space." },
  "47_56": { vi: "Kỵ Sĩ Cốc và Bảy Kiếm: người lãng mạn và sự lừa dối — nước cảm xúc hào hoa gặp khí láu cá, kỵ sĩ cốc bị lừa bởi ai đó có vẻ ngoài quyến rũ nhưng thiếu trung thực.", en: "Knight of Cups and Seven of Swords: the romantic and deception — gallant emotional water meeting sly air, the romantic knight deceived by someone appealing on the surface yet dishonest." },
  "47_57": { vi: "Kỵ Sĩ Cốc và Tám Kiếm: người lãng mạn cảm thấy bị giam cầm — nước cảm xúc hào hoa bị trói buộc bởi khí giam cầm, lý tưởng lãng mạn không thể thoát khỏi giới hạn tự tạo.", en: "Knight of Cups and Eight of Swords: the romantic feeling trapped — gallant emotional water bound by imprisoning air, romantic ideals unable to escape from self-created limitations." },
  "47_58": { vi: "Kỵ Sĩ Cốc và Chín Kiếm: người lãng mạn bị lo âu ám ảnh — nước cảm xúc hào hoa bị khí lo âu đêm khuya quấy nhiễu, lý tưởng đẹp không bảo vệ kỵ sĩ khỏi nỗi sợ tối.", en: "Knight of Cups and Nine of Swords: the romantic haunted by anxiety — gallant emotional water disturbed by nighttime anxiety, beautiful ideals unable to protect the knight from dark fears." },
  "47_59": { vi: "Kỵ Sĩ Cốc và Mười Kiếm: người lãng mạn đối mặt kết thúc — nước cảm xúc hào hoa gặp đáy đau đớn của khí, kết thúc chu kỳ lãng mạn dọn đường cho sự trưởng thành thực sự.", en: "Knight of Cups and Ten of Swords: the romantic facing an ending — gallant emotional water meeting air's painful lowest point, end of the romantic cycle clearing the way for true maturity." },
  "47_60": { vi: "Kỵ Sĩ Cốc và Trang Bị Kiếm: người lãng mạn gặp trí tuệ trẻ — nước cảm xúc hào hoa gặp khí tò mò sắc bén, sự kết hợp của lý tưởng lãng mạn và câu hỏi thám tử tươi mới.", en: "Knight of Cups and Page of Swords: the romantic meets young intellect — gallant emotional water meeting sharp curious air, a fresh combination of romantic ideals and detective questioning." },
  "47_61": { vi: "Kỵ Sĩ Cốc và Kỵ Sĩ Kiếm: hai kỵ sĩ đối lập gặp nhau — nước hào hoa lãng mạn và khí xốc nổi quyết đoán, trái tim và lý trí đua nhau với tốc độ và mục tiêu hoàn toàn khác biệt.", en: "Knight of Cups and Knight of Swords: two opposing knights meeting — gallant romantic water and impulsive decisive air, heart and reason racing with entirely different speeds and goals." },
  "47_62": { vi: "Kỵ Sĩ Cốc và Nữ Hoàng Kiếm: người lãng mạn gặp người phụ nữ minh mẫn — nước cảm xúc hào hoa gặp khí rõ ràng của nữ hoàng, sự lãng mạn được thử thách và làm sắc nét bởi trí tuệ.", en: "Knight of Cups and Queen of Swords: the romantic meets the clear-minded woman — gallant emotional water meeting the queen's clear air, romance challenged and sharpened by intellect." },
  "47_63": { vi: "Kỵ Sĩ Cốc và Vua Kiếm: người lãng mạn trước quyền uy trí tuệ — nước cảm xúc hào hoa gặp khí quyền uy tối cao, vua kiếm hỏi kỵ sĩ liệu lý tưởng có đứng vững trước thực tế không.", en: "Knight of Cups and King of Swords: the romantic before supreme intellectual authority — gallant emotional water meeting supreme authoritative air, the king asking whether the knight's ideals withstand reality." },
  "48_50": { vi: "Nữ Hoàng Cốc và Át Kiếm: sự thấu cảm gặp sự rõ ràng mới — nước trực giác sâu sắc đón nhận lưỡi kiếm khai mở, nữ hoàng cảm xúc tìm thấy sức mạnh mới trong sự thật sắc bén.", en: "Queen of Cups and Ace of Swords: empathy meets new clarity — deeply intuitive water receiving the opening blade, the emotional queen finding new strength in sharp truth presented clearly." },
  "48_51": { vi: "Nữ Hoàng Cốc và Hai Kiếm: sự thấu cảm đứng trước quyết định khó — nước trực giác sâu sắc gặp ngã rẽ của khí, nữ hoàng biết điều gì đúng nhưng cần dũng khí để chọn lựa.", en: "Queen of Cups and Two of Swords: empathy before a difficult decision — deeply intuitive water at air's crossroads, the queen knowing what is right but needing courage to choose." },
  "48_52": { vi: "Nữ Hoàng Cốc và Ba Kiếm: sự thấu cảm đối mặt đau thương — nước trực giác sâu sắc gặp ba lưỡi kiếm, nữ hoàng ôm ấp nỗi đau của người khác lẫn của chính mình với tình thương.", en: "Queen of Cups and Three of Swords: empathy facing heartbreak — deeply intuitive water meeting three blades, the queen holding both others' pain and her own with equal compassion." },
  "48_53": { vi: "Nữ Hoàng Cốc và Bốn Kiếm: sự thấu cảm cần phục hồi — nước trực giác sâu sắc tạm lắng, khí nghỉ ngơi cho phép nữ hoàng nạp lại nguồn cảm xúc đã cho đi quá nhiều.", en: "Queen of Cups and Four of Swords: empathy needing recovery — deeply intuitive water settling, air's rest allowing the queen to replenish emotional reserves she has too generously given away." },
  "48_54": { vi: "Nữ Hoàng Cốc và Năm Kiếm: sự thấu cảm trong xung đột — nước trực giác sâu sắc gặp khí xung đột, nữ hoàng phải đối mặt với những người lợi dụng sự tốt bụng của bà.", en: "Queen of Cups and Five of Swords: empathy in conflict — deeply intuitive water meeting conflict's air, the queen confronting those who exploit her kindness without remorse." },
  "48_55": { vi: "Nữ Hoàng Cốc và Sáu Kiếm: sự thấu cảm dẫn đến bình yên — nước trực giác sâu sắc di chuyển nhẹ nhàng, khí dẫn nữ hoàng cảm xúc qua thời kỳ chuyển tiếp đến không gian bình thản hơn.", en: "Queen of Cups and Six of Swords: empathy moving toward peace — deeply intuitive water moving gently, air guiding the emotional queen through transition to a more serene and peaceful space." },
  "48_56": { vi: "Nữ Hoàng Cốc và Bảy Kiếm: sự thấu cảm nhận ra sự lừa dối — nước trực giác sâu sắc cảm nhận điều gì đó không đúng, nữ hoàng dùng trực giác nhận ra bộ mặt thật sau vẻ ngoài dối trá.", en: "Queen of Cups and Seven of Swords: empathy sensing deception — deeply intuitive water feeling something is wrong, the queen using intuition to see the true face behind the deceptive exterior." },
  "48_57": { vi: "Nữ Hoàng Cốc và Tám Kiếm: sự thấu cảm bị giam cầm — nước trực giác sâu sắc bị trói buộc bởi những giới hạn cảm xúc, nữ hoàng mắc kẹt trong sự nhạy cảm quá mức của chính mình.", en: "Queen of Cups and Eight of Swords: empathy imprisoned — deeply intuitive water bound by emotional limitations, the queen of cups trapped within her own overwhelming emotional sensitivity." },
  "48_58": { vi: "Nữ Hoàng Cốc và Chín Kiếm: sự thấu cảm bị lo âu nhấn chìm — nước trực giác sâu sắc gặp khí lo âu ban đêm, nữ hoàng mang gánh nặng nỗi đau người khác đến điểm kiệt sức.", en: "Queen of Cups and Nine of Swords: empathy overwhelmed by anxiety — deeply intuitive water meeting nighttime anxiety, the queen carrying the weight of others' pain to the point of exhaustion." },
  "48_59": { vi: "Nữ Hoàng Cốc và Mười Kiếm: sự thấu cảm ở điểm tận cùng — nước trực giác sâu sắc gặp đáy đau đớn của khí, nữ hoàng học buông bỏ để tiếp tục phục vụ từ nơi đã được phục hồi.", en: "Queen of Cups and Ten of Swords: empathy at the lowest point — deeply intuitive water meeting air's painful bottom, the queen learning to release in order to continue serving from a restored place." },
  "48_60": { vi: "Nữ Hoàng Cốc và Trang Bị Kiếm: sự thấu cảm hướng dẫn trí tuệ trẻ — nước trực giác sâu sắc nuôi dưỡng khí tò mò non nớt, nữ hoàng dạy trang bị kiếm rằng cảm xúc là nguồn tri thức.", en: "Queen of Cups and Page of Swords: empathy guiding young intellect — deeply intuitive water nurturing youthful curious air, the queen teaching the page that emotions are a source of knowledge." },
  "48_61": { vi: "Nữ Hoàng Cốc và Kỵ Sĩ Kiếm: sự thấu cảm làm chậm tốc độ — nước trực giác sâu sắc giúp kỵ sĩ khí xốc nổi dừng lại, nữ hoàng nhắc rằng tốc độ không thay thế được sự thấu hiểu.", en: "Queen of Cups and Knight of Swords: empathy slowing the pace — deeply intuitive water helping the impulsive air knight pause, the queen reminding that speed cannot replace true understanding." },
  "48_62": { vi: "Nữ Hoàng Cốc và Nữ Hoàng Kiếm: hai nữ hoàng đối lập gặp nhau — nước trực giác sâu sắc và khí rõ ràng sắc bén, trái tim và lý trí ở đỉnh cao gặp nhau với sức mạnh ngang bằng.", en: "Queen of Cups and Queen of Swords: two opposing queens meeting — deeply intuitive water and sharp clear air, heart and reason at their peaks meeting with equal strength and sovereign authority." },
  "48_63": { vi: "Nữ Hoàng Cốc và Vua Kiếm: sự thấu cảm gặp quyền uy trí tuệ — nước trực giác sâu sắc gặp khí quyền uy tối cao, hai nguyên lý tối cao đối thoại: tình cảm và lý trí cùng tìm tiếng nói chung.", en: "Queen of Cups and King of Swords: empathy meeting intellectual authority — deeply intuitive water meeting supreme authoritative air, two supreme principles in dialogue: feeling and reason seeking common ground." },
  "49_50": { vi: "Vua Cốc và Át Kiếm: bậc thầy cảm xúc gặp khởi đầu rõ ràng — nước cảm xúc làm chủ đón nhận lưỡi kiếm khai mở, quyền uy tình cảm chào đón sự rõ ràng mới với sự chín chắn.", en: "King of Cups and Ace of Swords: emotional mastery meets clear beginning — masterful emotional water receiving the opening blade, emotional authority welcoming new clarity with calm maturity." },
  "49_51": { vi: "Vua Cốc và Hai Kiếm: bậc thầy cảm xúc trước quyết định — nước cảm xúc làm chủ gặp ngã rẽ của khí, vua cốc dùng sự khôn ngoan để chọn lựa mà không để cảm xúc lấn át lý trí.", en: "King of Cups and Two of Swords: emotional mastery before a decision — masterful emotional water at air's crossroads, the king using wisdom to choose without letting emotion override sound reason." },
  "49_52": { vi: "Vua Cốc và Ba Kiếm: bậc thầy cảm xúc đối mặt đau thương — nước cảm xúc làm chủ gặp ba lưỡi kiếm, vua cốc xử lý nỗi đau với sự bình thản và ân sủng của người đã trưởng thành.", en: "King of Cups and Three of Swords: emotional mastery facing heartbreak — masterful emotional water meeting three blades, the king processing pain with the composure and grace of hard-won maturity." },
  "49_53": { vi: "Vua Cốc và Bốn Kiếm: bậc thầy cảm xúc nghỉ ngơi có chủ đích — nước cảm xúc làm chủ tạm lắng, vua cốc biết khi nào cần hồi phục để tiếp tục lãnh đạo với trái tim tràn đầy.", en: "King of Cups and Four of Swords: emotional mastery resting with intention — masterful emotional water settling deliberately, the king knowing when to restore himself to continue leading fully." },
  "49_54": { vi: "Vua Cốc và Năm Kiếm: bậc thầy cảm xúc trong xung đột — nước cảm xúc làm chủ gặp khí xung đột, vua cốc không bị kích động mà điều hướng xung đột bằng sự bình tĩnh và uy quyền.", en: "King of Cups and Five of Swords: emotional mastery in conflict — masterful emotional water meeting conflict's air, the king remaining unrattled and steering conflict with composure and authority." },
  "49_55": { vi: "Vua Cốc và Sáu Kiếm: bậc thầy cảm xúc dẫn đến bình yên — nước cảm xúc làm chủ di chuyển điềm tĩnh, vua cốc dẫn dắt người khác qua giai đoạn chuyển tiếp đến không gian bình thản hơn.", en: "King of Cups and Six of Swords: emotional mastery moving toward peace — masterful emotional water moving calmly, the king guiding others through transition to more serene and settled space." },
  "49_56": { vi: "Vua Cốc và Bảy Kiếm: bậc thầy cảm xúc nhận ra sự lừa dối — nước cảm xúc làm chủ cảm nhận điều gì đó không đúng, vua cốc dùng trực giác dày dặn nhận ra sự không trung thực dù được che giấu khéo.", en: "King of Cups and Seven of Swords: emotional mastery recognizing deception — masterful emotional water sensing something wrong, the king's seasoned intuition detecting dishonesty even when cleverly concealed." },
  "49_57": { vi: "Vua Cốc và Tám Kiếm: bậc thầy cảm xúc bị giam cầm — nước cảm xúc làm chủ bị trói buộc, vua cốc đối mặt nghịch lý khi quyền uy cảm xúc bị giam cầm bởi giới hạn tự áp đặt.", en: "King of Cups and Eight of Swords: emotional mastery imprisoned — masterful emotional water bound, the king facing the paradox of emotional authority imprisoned by self-imposed limitations not yet released." },
  "49_58": { vi: "Vua Cốc và Chín Kiếm: bậc thầy cảm xúc đối mặt lo âu — nước cảm xúc làm chủ gặp khí lo âu, ngay cả vua cốc đôi khi bị nỗi sợ đêm khuya làm phiền — trưởng thành không nghĩa là miễn nhiễm.", en: "King of Cups and Nine of Swords: emotional mastery facing anxiety — masterful emotional water meeting anxious air, even the king sometimes troubled by nighttime fears — maturity doesn't mean immunity." },
  "49_59": { vi: "Vua Cốc và Mười Kiếm: bậc thầy cảm xúc ở điểm tận cùng — nước cảm xúc làm chủ gặp đáy đau đớn của khí, vua cốc vượt qua kết thúc với phẩm giá và mang theo bài học cho hành trình tiếp theo.", en: "King of Cups and Ten of Swords: emotional mastery at the lowest point — masterful emotional water meeting air's painful bottom, the king moving through the ending with dignity and carrying lessons forward." },
  "49_60": { vi: "Vua Cốc và Trang Bị Kiếm: bậc thầy cảm xúc hướng dẫn trí tuệ trẻ — nước cảm xúc làm chủ nuôi dưỡng khí tò mò non nớt, vua cốc dạy trang bị kiếm rằng cảm xúc và lý trí không phải đối nghịch.", en: "King of Cups and Page of Swords: emotional mastery guiding young intellect — masterful emotional water nurturing youthful curious air, the king teaching the page that emotion and intellect are not opposites." },
  "49_61": { vi: "Vua Cốc và Kỵ Sĩ Kiếm: bậc thầy cảm xúc kiềm chế tinh thần xông pha — nước cảm xúc làm chủ điều hướng khí xốc nổi, vua cốc giúp kỵ sĩ biết khi nào tốc độ là sức mạnh và khi nào là điểm yếu.", en: "King of Cups and Knight of Swords: emotional mastery channeling the charging spirit — masterful emotional water directing impulsive air, the king helping the knight know when speed is strength versus weakness." },
  "49_62": { vi: "Vua Cốc và Nữ Hoàng Kiếm: bậc thầy cảm xúc gặp quyền uy trí tuệ — nước cảm xúc làm chủ và khí trí tuệ tối cao gặp nhau với sự tôn trọng ngang bằng, hai loại quyền uy bổ sung cho nhau.", en: "King of Cups and Queen of Swords: emotional mastery meets intellectual authority — masterful emotional water and supreme intellectual air meeting with equal respect, two forms of authority complementing each other." },
  "49_63": { vi: "Vua Cốc và Vua Kiếm: hai vị vua gặp nhau — nước cảm xúc làm chủ và khí trí tuệ tối cao đối thoại, trái tim và lý trí ở đỉnh cao quyền uy cùng tìm kiếm sự cân bằng giữa hai nguyên lý vĩ đại.", en: "King of Cups and King of Swords: two kings meeting — masterful emotional water and supreme intellectual air in dialogue, heart and reason at the peak of authority seeking balance between two great principles." },
  // ── Tier 5e-1: Cups × Pentacles, water×earth (Cups 36–42 × Pentacles 64–77, 98 pairs) ──
  "36_64": { vi: "Át Cốc và Át Tiền: hai khởi đầu — nước và đất ở điểm xuất phát nguyên thủy; cảm xúc thuần khiết gặp tiềm năng vật chất, tình yêu và sự phồn thịnh cùng nảy mầm.", en: "Ace of Cups and Ace of Pentacles: two beginnings — water and earth at their primal starting points; pure emotion meeting material potential, love and prosperity sprouting together." },
  "36_65": { vi: "Át Cốc và Hai Tiền: cảm xúc tươi mới gặp sự cân bằng thực tế — nước thuần khiết đối mặt với khả năng xoay sở, tình yêu ban đầu học cách thích nghi với đòi hỏi của cuộc sống.", en: "Ace of Cups and Two of Pentacles: fresh emotion meets practical balance — pure water facing the ability to adapt, new love learning to adjust alongside the demands of everyday life." },
  "36_66": { vi: "Át Cốc và Ba Tiền: cảm xúc khởi sinh gặp sự hợp tác — nước thuần khiết kết hợp với đất làm việc nhóm, tình yêu mới nảy nở trong môi trường được xây dựng bởi bàn tay cộng đồng.", en: "Ace of Cups and Three of Pentacles: nascent emotion meets collaboration — pure water joining earth's teamwork, new love blossoming in an environment built by communal hands together." },
  "36_67": { vi: "Át Cốc và Bốn Tiền: cảm xúc tươi mới gặp sự tích lũy — nước thuần khiết chạm vào đất giữ chặt, tình yêu ban đầu bị thử thách bởi người quá bám víu vào an toàn vật chất.", en: "Ace of Cups and Four of Pentacles: fresh emotion meets accumulation — pure water touching earth holding tight, new love challenged by someone clinging too tightly to material security." },
  "36_68": { vi: "Át Cốc và Năm Tiền: tình yêu thuần khiết gặp hoàn cảnh thiếu thốn — nước tươi mát trong thời điểm khan hiếm, cảm xúc chân thành nảy sinh ngay cả khi nền tảng vật chất chưa vững chắc.", en: "Ace of Cups and Five of Pentacles: pure love meets scarcity — fresh water in a time of lack, genuine emotion arising even when the material foundation is not yet stable." },
  "36_69": { vi: "Át Cốc và Sáu Tiền: cảm xúc tươi mới gặp sự hào phóng — nước thuần khiết chảy vào đất chia sẻ, tình yêu ban đầu được nuôi dưỡng bởi sự cho đi và nhận lại cân bằng.", en: "Ace of Cups and Six of Pentacles: fresh emotion meets generosity — pure water flowing into sharing earth, new love nourished by balanced giving and receiving from both sides." },
  "36_70": { vi: "Át Cốc và Bảy Tiền: cảm xúc khởi sinh gặp sự kiên nhẫn — nước tươi mới chờ đợi cùng đất đánh giá, tình yêu ban đầu học bài học rằng những điều có giá trị cần thời gian để nảy nở.", en: "Ace of Cups and Seven of Pentacles: nascent emotion meets patience — fresh water waiting alongside assessing earth, new love learning that things of true value need time to fully bloom." },
  "36_71": { vi: "Át Cốc và Tám Tiền: cảm xúc tươi mới gặp sự cần cù — nước thuần khiết chảy vào đất siêng năng, tình yêu ban đầu phát triển trong môi trường của sự tận tâm và kỷ luật.", en: "Ace of Cups and Eight of Pentacles: fresh emotion meets diligence — pure water flowing into industrious earth, new love growing in an environment of dedication and disciplined craft." },
  "36_72": { vi: "Át Cốc và Chín Tiền: cảm xúc tươi mới gặp sự sung túc — nước thuần khiết chảy vào đất phong phú, tình yêu ban đầu nảy nở trong không gian của sự tự lập và hài lòng vật chất.", en: "Ace of Cups and Nine of Pentacles: fresh emotion meets abundance — pure water flowing into prosperous earth, new love blossoming in a space of self-sufficiency and material contentment." },
  "36_73": { vi: "Át Cốc và Mười Tiền: cảm xúc tươi mới gặp sự viên mãn vật chất — nước thuần khiết chảy vào đất gia đình, tình yêu ban đầu bước vào không gian của di sản và sự ổn định lâu dài.", en: "Ace of Cups and Ten of Pentacles: fresh emotion meets material completion — pure water flowing into family earth, new love stepping into the space of legacy and lasting stability." },
  "36_74": { vi: "Át Cốc và Trang Bị Tiền: cảm xúc tươi mới gặp trí tuệ vật chất non trẻ — nước thuần khiết và đất tò mò cùng khám phá, tình yêu ban đầu và ham học hỏi thực tế song hành.", en: "Ace of Cups and Page of Pentacles: fresh emotion meets youthful material intellect — pure water and curious earth exploring together, new love and practical curiosity walking alongside." },
  "36_75": { vi: "Át Cốc và Kỵ Sĩ Tiền: cảm xúc tươi mới gặp sự kiên trì thực tế — nước thuần khiết và đất vững chắc cùng tiến, tình yêu ban đầu được bảo vệ bởi tinh thần trách nhiệm và bền bỉ.", en: "Ace of Cups and Knight of Pentacles: fresh emotion meets steady practicality — pure water and solid earth moving forward together, new love protected by a spirit of responsibility." },
  "36_76": { vi: "Át Cốc và Nữ Hoàng Tiền: cảm xúc tươi mới gặp sự chăm sóc thực tế — nước thuần khiết được nữ hoàng đất nuôi dưỡng ân cần, tình yêu ban đầu đặt nền trong bàn tay ấm áp và thực tế.", en: "Ace of Cups and Queen of Pentacles: fresh emotion meets practical nurturing — pure water tenderly cared for by the earth queen, new love grounded in warm and practical hands." },
  "36_77": { vi: "Át Cốc và Vua Tiền: cảm xúc tươi mới gặp quyền uy vật chất — nước thuần khiết đặt vào nền đất vững chắc của vua, tình yêu ban đầu được đảm bảo bởi sự ổn định và bảo vệ lâu dài.", en: "Ace of Cups and King of Pentacles: fresh emotion meets material authority — pure water set upon the king's solid earth foundation, new love assured by lasting stability and protection." },
  "37_64": { vi: "Hai Cốc và Át Tiền: sự kết nối cảm xúc gặp khởi đầu vật chất — nước đôi lứa đón nhận mầm đất mới, mối quan hệ chân thật xây dựng nền tảng thịnh vượng từ đầu.", en: "Two of Cups and Ace of Pentacles: emotional connection meets material beginning — partnered water receiving new earth's seed, genuine relationship building a prosperous foundation from the start." },
  "37_65": { vi: "Hai Cốc và Hai Tiền: kết nối cảm xúc gặp cân bằng thực tế — nước đôi lứa và đất xoay sở, mối quan hệ học cách cân bằng giữa tình cảm và đòi hỏi thực tiễn cuộc sống.", en: "Two of Cups and Two of Pentacles: emotional connection meets practical balance — partnered water and juggling earth, the relationship learning to balance feeling and the demands of practical life." },
  "37_66": { vi: "Hai Cốc và Ba Tiền: kết nối cảm xúc gặp hợp tác — nước đôi lứa kết hợp với đất làm việc nhóm, tình yêu đôi lứa phát triển khi cùng nhau xây dựng điều gì đó có ý nghĩa.", en: "Two of Cups and Three of Pentacles: emotional connection meets collaboration — partnered water joining earth's teamwork, romantic love flourishing when building something meaningful together." },
  "37_67": { vi: "Hai Cốc và Bốn Tiền: kết nối cảm xúc gặp sự tích trữ — nước đôi lứa chạm vào đất giữ chặt, mối quan hệ bị thử thách khi một người bám víu tài nguyên hơn là chia sẻ yêu thương.", en: "Two of Cups and Four of Pentacles: emotional connection meets hoarding — partnered water touching clinging earth, the relationship challenged when one clings to resources rather than sharing love." },
  "37_68": { vi: "Hai Cốc và Năm Tiền: tình yêu đôi lứa trong hoàn cảnh khó khăn — nước kết nối trong thời gian thiếu thốn, mối quan hệ được thử thách và củng cố bởi những giai đoạn cùng vượt qua khó khăn.", en: "Two of Cups and Five of Pentacles: romantic love in difficult circumstances — connected water in times of scarcity, the relationship tested and strengthened by periods of overcoming hardship together." },
  "37_69": { vi: "Hai Cốc và Sáu Tiền: kết nối cảm xúc gặp sự hào phóng — nước đôi lứa và đất chia sẻ, tình yêu lớn dậy trong bầu không khí cho đi và nhận lại cân bằng giữa hai người.", en: "Two of Cups and Six of Pentacles: emotional connection meets generosity — partnered water and sharing earth, love growing in an atmosphere of balanced giving and receiving between two people." },
  "37_70": { vi: "Hai Cốc và Bảy Tiền: kết nối cảm xúc gặp sự kiên nhẫn chờ đợi — nước đôi lứa và đất đánh giá, tình yêu học rằng những điều đáng giá nhất cần thời gian để chín muồi đúng lúc.", en: "Two of Cups and Seven of Pentacles: emotional connection meets patient waiting — partnered water and assessing earth, love learning that the most worthwhile things need time to ripen." },
  "37_71": { vi: "Hai Cốc và Tám Tiền: kết nối cảm xúc gặp sự cần cù — nước đôi lứa và đất siêng năng, tình yêu lớn mạnh khi cả hai cùng dành tâm huyết vào việc xây dựng cuộc sống chung.", en: "Two of Cups and Eight of Pentacles: emotional connection meets diligence — partnered water and industrious earth, love growing strong when both invest wholeheartedly in building life together." },
  "37_72": { vi: "Hai Cốc và Chín Tiền: kết nối cảm xúc gặp sự sung túc — nước đôi lứa và đất phong phú, tình yêu nảy nở trong không gian của sự tự lập và sung mãn vật chất.", en: "Two of Cups and Nine of Pentacles: emotional connection meets abundance — partnered water and prosperous earth, love blossoming in a space of self-sufficiency and material comfort." },
  "37_73": { vi: "Hai Cốc và Mười Tiền: kết nối cảm xúc gặp sự viên mãn gia đình — nước đôi lứa và đất di sản, tình yêu lứa đôi tiến đến không gian của sự ổn định và truyền thống lâu dài.", en: "Two of Cups and Ten of Pentacles: emotional connection meets family completion — partnered water and legacy earth, romantic love moving toward the space of lasting stability and tradition." },
  "37_74": { vi: "Hai Cốc và Trang Bị Tiền: kết nối cảm xúc gặp trí tuệ thực tế trẻ — nước đôi lứa và đất tò mò non nớt, tình yêu và ham học hỏi thực tế cùng nảy sinh và phát triển song song.", en: "Two of Cups and Page of Pentacles: emotional connection meets youthful practical curiosity — partnered water and young curious earth, love and practical curiosity arising and developing in parallel." },
  "37_75": { vi: "Hai Cốc và Kỵ Sĩ Tiền: kết nối cảm xúc gặp sự bền bỉ thực tế — nước đôi lứa và đất kiên trì, tình yêu được bảo vệ bởi tinh thần trách nhiệm và kiên nhẫn của kỵ sĩ đất.", en: "Two of Cups and Knight of Pentacles: emotional connection meets steady perseverance — partnered water and persistent earth, love protected by the knight's spirit of responsibility and patience." },
  "37_76": { vi: "Hai Cốc và Nữ Hoàng Tiền: kết nối cảm xúc gặp sự chăm sóc thực tế — nước đôi lứa được nữ hoàng đất bảo bọc ân cần, tình yêu sinh trưởng trong bàn tay ấm áp và thực dụng.", en: "Two of Cups and Queen of Pentacles: emotional connection meets practical nurturing — partnered water tenderly sheltered by the earth queen, love growing in warm and practically grounded hands." },
  "37_77": { vi: "Hai Cốc và Vua Tiền: kết nối cảm xúc gặp quyền uy vật chất — nước đôi lứa được vua đất bảo vệ, tình yêu phát triển trên nền tảng ổn định và an toàn lâu dài do vua tạo ra.", en: "Two of Cups and King of Pentacles: emotional connection meets material authority — partnered water sheltered by the earth king, love developing on the stable and enduring foundation the king creates." },
  "38_64": { vi: "Ba Cốc và Át Tiền: niềm vui cộng đồng gặp khởi đầu vật chất — nước lễ hội đón nhận mầm đất mới, sự ăn mừng và tiềm năng thịnh vượng cùng được gieo trồng trong cộng đồng.", en: "Three of Cups and Ace of Pentacles: communal joy meets material beginning — festive water receiving the new earth's seed, celebration and prosperous potential sown together within the community." },
  "38_65": { vi: "Ba Cốc và Hai Tiền: niềm vui cộng đồng gặp sự cân bằng thực tế — nước lễ hội và đất xoay sở, sự vui vẻ cần được cân bằng với trách nhiệm thực tế không thể bỏ qua.", en: "Three of Cups and Two of Pentacles: communal joy meets practical balance — festive water and juggling earth, joy needing to be balanced with practical responsibilities that cannot be ignored." },
  "38_66": { vi: "Ba Cốc và Ba Tiền: niềm vui cộng đồng gặp hợp tác — nước lễ hội và đất làm việc nhóm, vui mừng được tăng cường khi cùng nhau tạo ra điều gì đó có giá trị trong cộng đồng.", en: "Three of Cups and Three of Pentacles: communal joy meets collaboration — festive water and earth's teamwork, joy amplified when creating something of value together within the community." },
  "38_67": { vi: "Ba Cốc và Bốn Tiền: niềm vui cộng đồng gặp sự tích trữ — nước lễ hội chạm đất giữ chặt, sự vui mừng bị hạn chế khi ai đó bám víu tài nguyên thay vì tham gia chia sẻ.", en: "Three of Cups and Four of Pentacles: communal joy meets hoarding — festive water touching clinging earth, joy constrained when someone grips resources tightly instead of joining the sharing." },
  "38_68": { vi: "Ba Cốc và Năm Tiền: niềm vui gặp hoàn cảnh thiếu thốn — nước lễ hội trong thời gian khó khăn, cộng đồng tìm thấy lý do để ăn mừng ngay cả khi nguồn lực vật chất eo hẹp.", en: "Three of Cups and Five of Pentacles: joy meeting scarcity — festive water in difficult times, community finding reasons to celebrate even when material resources are stretched thin." },
  "38_69": { vi: "Ba Cốc và Sáu Tiền: niềm vui cộng đồng gặp sự hào phóng — nước lễ hội và đất chia sẻ, vui mừng được khuếch đại khi tài nguyên được phân phối công bằng trong cộng đồng.", en: "Three of Cups and Six of Pentacles: communal joy meets generosity — festive water and sharing earth, joy amplified when resources are distributed fairly throughout the community." },
  "38_70": { vi: "Ba Cốc và Bảy Tiền: niềm vui cộng đồng gặp sự kiên nhẫn — nước lễ hội và đất đánh giá, sự ăn mừng ngắn hạn nhắc nhở rằng thành quả lâu dài cần thời gian và kiên nhẫn.", en: "Three of Cups and Seven of Pentacles: communal joy meets patience — festive water and assessing earth, short-term celebration reminding that lasting results require time and patient investment." },
  "38_71": { vi: "Ba Cốc và Tám Tiền: niềm vui cộng đồng gặp sự cần cù — nước lễ hội và đất siêng năng, niềm vui của việc hoàn thành được chia sẻ bởi những người cùng nhau làm việc chăm chỉ.", en: "Three of Cups and Eight of Pentacles: communal joy meets diligence — festive water and industrious earth, the joy of completion shared by those who worked together with dedication." },
  "38_72": { vi: "Ba Cốc và Chín Tiền: niềm vui cộng đồng gặp sự sung túc — nước lễ hội và đất phong phú, sự ăn mừng được tổ chức trong không gian của sự sung mãn và hài lòng vật chất.", en: "Three of Cups and Nine of Pentacles: communal joy meets abundance — festive water and prosperous earth, celebration held within a space of material plenty and deep contentment." },
  "38_73": { vi: "Ba Cốc và Mười Tiền: niềm vui cộng đồng gặp sự viên mãn gia đình — nước lễ hội và đất di sản, sự ăn mừng của cộng đồng kết nối với truyền thống gia đình và di sản lâu dài.", en: "Three of Cups and Ten of Pentacles: communal joy meets family completion — festive water and legacy earth, communal celebration connecting with family tradition and lasting generational legacy." },
  "38_74": { vi: "Ba Cốc và Trang Bị Tiền: niềm vui cộng đồng gặp trí tuệ thực tế trẻ — nước lễ hội và đất non nớt tò mò, niềm vui của cộng đồng khuyến khích người trẻ học hỏi điều mới.", en: "Three of Cups and Page of Pentacles: communal joy meets youthful practical intellect — festive water and young curious earth, communal joy encouraging the young to learn and explore new things." },
  "38_75": { vi: "Ba Cốc và Kỵ Sĩ Tiền: niềm vui cộng đồng gặp sự bền bỉ — nước lễ hội và đất kiên trì, sự ăn mừng cân bằng với trách nhiệm thực tế mà kỵ sĩ đất luôn gánh vác.", en: "Three of Cups and Knight of Pentacles: communal joy meets perseverance — festive water and persistent earth, celebration balanced with practical responsibility the earth knight always carries." },
  "38_76": { vi: "Ba Cốc và Nữ Hoàng Tiền: niềm vui cộng đồng gặp sự chăm sóc thực tế — nước lễ hội được nữ hoàng đất tổ chức ân cần, niềm vui cộng đồng được nuôi dưỡng bởi bàn tay thực tế ấm áp.", en: "Three of Cups and Queen of Pentacles: communal joy meets practical nurturing — festive water organized tenderly by the earth queen, communal joy nourished by warm and practically grounded hands." },
  "38_77": { vi: "Ba Cốc và Vua Tiền: niềm vui cộng đồng gặp quyền uy vật chất — nước lễ hội được vua đất bảo trợ, sự thịnh vượng của vị vua tạo điều kiện cho cộng đồng ăn mừng phồn thịnh.", en: "Three of Cups and King of Pentacles: communal joy meets material authority — festive water patronized by the earth king, the king's prosperity enabling the community to celebrate abundance." },
  "39_64": { vi: "Bốn Cốc và Át Tiền: thờ ơ gặp cơ hội vật chất — nước đóng kín bỏ lỡ mầm đất mới, sự chán nản cảm xúc có thể khiến ta không nhận ra tiềm năng thịnh vượng đang hiện hữu.", en: "Four of Cups and Ace of Pentacles: apathy meets material opportunity — closed water missing the new earth seed, emotional boredom potentially causing one to miss prosperous potential right before them." },
  "39_65": { vi: "Bốn Cốc và Hai Tiền: thờ ơ gặp sự xoay sở — nước đóng kín và đất cân bằng, sự thụ động cảm xúc trong khi cuộc sống vật chất đòi hỏi sự linh hoạt và thích ứng liên tục.", en: "Four of Cups and Two of Pentacles: apathy meets juggling — closed water and balancing earth, emotional passivity while practical life demands flexibility and constant adaptation." },
  "39_66": { vi: "Bốn Cốc và Ba Tiền: thờ ơ gặp hợp tác — nước đóng kín và đất làm việc nhóm, sự rút lui cảm xúc có thể cản trở sự đóng góp vào các dự án cộng đồng cần sự tham gia.", en: "Four of Cups and Three of Pentacles: apathy meets collaboration — closed water and teamwork earth, emotional withdrawal potentially blocking contribution to communal projects that need participation." },
  "39_67": { vi: "Bốn Cốc và Bốn Tiền: thờ ơ gặp sự tích trữ — nước đóng kín và đất giữ chặt, hai loại co rút khác nhau: một bên cảm xúc đóng lại, một bên vật chất bám víu không buông.", en: "Four of Cups and Four of Pentacles: apathy meets hoarding — closed water and clinging earth, two different forms of withdrawal: one emotionally shut down, one materially gripping tight." },
  "39_68": { vi: "Bốn Cốc và Năm Tiền: thờ ơ trong thiếu thốn — nước đóng kín trong thời gian khan hiếm, sự thụ động cảm xúc khiến hoàn cảnh khó khăn trở nên nặng nề hơn thực tế cần phải như vậy.", en: "Four of Cups and Five of Pentacles: apathy in scarcity — closed water in times of lack, emotional passivity making difficult circumstances feel even heavier than they actually need to be." },
  "39_69": { vi: "Bốn Cốc và Sáu Tiền: thờ ơ gặp sự hào phóng — nước đóng kín và đất chia sẻ, sự chán nản cảm xúc có thể ngăn ta nhận ra và đón nhận sự hào phóng đang được trao tặng.", en: "Four of Cups and Six of Pentacles: apathy meets generosity — closed water and sharing earth, emotional boredom potentially preventing one from noticing and receiving generosity being offered." },
  "39_70": { vi: "Bốn Cốc và Bảy Tiền: thờ ơ gặp sự kiên nhẫn — nước đóng kín và đất chờ đợi, hai dạng đình trệ khác nhau: một dạng cảm xúc rỗng tuếch, một dạng kiên nhẫn chủ động mang hy vọng.", en: "Four of Cups and Seven of Pentacles: apathy meets patience — closed water and waiting earth, two different forms of stillness: one emotionally empty, one actively patient and carrying hope." },
  "39_71": { vi: "Bốn Cốc và Tám Tiền: thờ ơ gặp sự cần cù — nước đóng kín và đất siêng năng, sự thụ động cảm xúc đối lập hoàn toàn với tinh thần chăm chỉ của tám tiền đang miệt mài.", en: "Four of Cups and Eight of Pentacles: apathy meets diligence — closed water and industrious earth, emotional passivity standing in direct contrast to the Eight of Pentacles' dedicated and focused craft." },
  "39_72": { vi: "Bốn Cốc và Chín Tiền: thờ ơ gặp sự sung túc — nước đóng kín trong không gian phồn thịnh, sự chán nản cảm xúc ngay cả khi vật chất dư dả nhắc rằng đủ đầy bên ngoài không đảm bảo hài lòng bên trong.", en: "Four of Cups and Nine of Pentacles: apathy meets abundance — closed water in a space of prosperity, emotional boredom despite material plenty reminding that outer sufficiency doesn't guarantee inner contentment." },
  "39_73": { vi: "Bốn Cốc và Mười Tiền: thờ ơ gặp sự viên mãn gia đình — nước đóng kín trong không gian di sản, sự chán nản cảm xúc giữa lòng gia đình hạnh phúc nhắc rằng cảm giác trống rỗng không phụ thuộc hoàn cảnh.", en: "Four of Cups and Ten of Pentacles: apathy meets family completion — closed water in a legacy space, emotional emptiness within a happy family reminding that inner void doesn't depend on circumstances." },
  "39_74": { vi: "Bốn Cốc và Trang Bị Tiền: thờ ơ gặp trí tuệ thực tế trẻ — nước đóng kín và đất non nớt tò mò, sự hăng hái của trang bị tiền có thể là tia sáng kéo bốn cốc ra khỏi vỏ bọc.", en: "Four of Cups and Page of Pentacles: apathy meets youthful practical curiosity — closed water and young curious earth, the page's enthusiasm potentially being the spark that draws Four of Cups out of its shell." },
  "39_75": { vi: "Bốn Cốc và Kỵ Sĩ Tiền: thờ ơ gặp sự kiên trì — nước đóng kín và đất bền bỉ, tinh thần có trách nhiệm và ổn định của kỵ sĩ đất có thể giúp bốn cốc tìm lại động lực dần dần.", en: "Four of Cups and Knight of Pentacles: apathy meets perseverance — closed water and persistent earth, the knight's responsible and stable spirit potentially helping Four of Cups gradually regain motivation." },
  "39_76": { vi: "Bốn Cốc và Nữ Hoàng Tiền: thờ ơ gặp sự chăm sóc thực tế — nước đóng kín gặp nữ hoàng đất ân cần, sự chăm chút thực tế và ấm áp của bà có thể giúp cảm xúc đóng băng tan chảy.", en: "Four of Cups and Queen of Pentacles: apathy meets practical nurturing — closed water meeting the tender earth queen, her warm practical care potentially helping the frozen emotional state slowly thaw." },
  "39_77": { vi: "Bốn Cốc và Vua Tiền: thờ ơ gặp quyền uy vật chất — nước đóng kín gặp vua đất uy quyền, sự ổn định và bảo đảm của vua có thể tạo nền tảng an toàn để bốn cốc mở lòng trở lại.", en: "Four of Cups and King of Pentacles: apathy meets material authority — closed water meeting the authoritative earth king, the king's stability and assurance potentially creating safe ground for Four of Cups to reopen." },
  "40_64": { vi: "Năm Cốc và Át Tiền: mất mát cảm xúc gặp khởi đầu vật chất — nước đau buồn đón nhận mầm đất mới, cơ hội thịnh vượng xuất hiện ngay khi trái tim đang đau, nhắc nhở nhìn về phía trước.", en: "Five of Cups and Ace of Pentacles: emotional loss meets material beginning — grieving water receiving the new earth seed, prosperous opportunity appearing just as the heart aches, reminding to look forward." },
  "40_65": { vi: "Năm Cốc và Hai Tiền: mất mát cảm xúc gặp sự xoay sở — nước đau buồn và đất cân bằng, cuộc sống đòi hỏi phải tiếp tục xoay sở ngay cả khi trái tim còn đang đau từng ngày.", en: "Five of Cups and Two of Pentacles: emotional loss meets juggling — grieving water and balancing earth, life demanding continued adaptation even while the heart is still aching day after day." },
  "40_66": { vi: "Năm Cốc và Ba Tiền: mất mát cảm xúc gặp hợp tác — nước đau buồn và đất làm việc nhóm, sự hỗ trợ của cộng đồng có thể giúp chữa lành khi ta sẵn sàng tiếp nhận bàn tay giúp đỡ.", en: "Five of Cups and Three of Pentacles: emotional loss meets collaboration — grieving water and teamwork earth, community support able to help healing when one is ready to receive helping hands." },
  "40_67": { vi: "Năm Cốc và Bốn Tiền: mất mát cảm xúc gặp sự tích trữ — nước đau buồn và đất giữ chặt, nỗi đau mất mát khiến người ta bám víu tài nguyên vật chất như phao cứu sinh cảm xúc.", en: "Five of Cups and Four of Pentacles: emotional loss meets hoarding — grieving water and clinging earth, the pain of loss causing one to grip material resources tightly as an emotional lifeline." },
  "40_68": { vi: "Năm Cốc và Năm Tiền: mất mát cảm xúc và vật chất cùng lúc — nước đau buồn và đất thiếu thốn, hai loại khó khăn gặp nhau đòi hỏi sức mạnh nội tâm lớn để vượt qua cùng lúc.", en: "Five of Cups and Five of Pentacles: emotional and material loss at once — grieving water and lacking earth, two forms of difficulty meeting together requiring great inner strength to overcome simultaneously." },
  "40_69": { vi: "Năm Cốc và Sáu Tiền: mất mát cảm xúc gặp sự hào phóng — nước đau buồn và đất chia sẻ, sự hào phóng từ người khác có thể mang lại nguồn an ủi trong giai đoạn đau thương cảm xúc.", en: "Five of Cups and Six of Pentacles: emotional loss meets generosity — grieving water and sharing earth, generosity from others able to bring comfort during the period of emotional grief and mourning." },
  "40_70": { vi: "Năm Cốc và Bảy Tiền: mất mát cảm xúc gặp sự kiên nhẫn — nước đau buồn và đất chờ đợi, thời gian và kiên nhẫn là liều thuốc chữa lành cho trái tim đau, dù không phải lúc nào cũng thấy rõ.", en: "Five of Cups and Seven of Pentacles: emotional loss meets patience — grieving water and waiting earth, time and patience being the healing medicine for the aching heart, even when not always visible." },
  "40_71": { vi: "Năm Cốc và Tám Tiền: mất mát cảm xúc gặp sự cần cù — nước đau buồn và đất siêng năng, dồn tâm huyết vào công việc có thể trở thành liệu pháp chữa lành khi trái tim đang trong giai đoạn đau thương.", en: "Five of Cups and Eight of Pentacles: emotional loss meets diligence — grieving water and industrious earth, channeling energy into craft potentially becoming healing therapy when the heart is in grief." },
  "40_72": { vi: "Năm Cốc và Chín Tiền: mất mát cảm xúc gặp sự sung túc — nước đau buồn trong không gian phồn thịnh, nhắc nhở rằng tài nguyên vật chất không thể bù đắp hoàn toàn những mất mát trong tình cảm.", en: "Five of Cups and Nine of Pentacles: emotional loss meets abundance — grieving water in a space of prosperity, reminding that material resources cannot fully compensate for losses in emotional life." },
  "40_73": { vi: "Năm Cốc và Mười Tiền: mất mát cảm xúc gặp sự viên mãn gia đình — nước đau buồn trong không gian di sản, đau mất mát cá nhân ngay giữa gia đình đầy đủ cho thấy nỗi đau không chọn thời điểm.", en: "Five of Cups and Ten of Pentacles: emotional loss meets family completion — grieving water in a legacy space, personal grief within an otherwise complete family showing that pain chooses no moment." },
  "40_74": { vi: "Năm Cốc và Trang Bị Tiền: mất mát cảm xúc gặp trí tuệ thực tế trẻ — nước đau buồn và đất non nớt, sự tươi trẻ và hồn nhiên của trang bị tiền đôi khi là ánh sáng trong thời gian đau buồn.", en: "Five of Cups and Page of Pentacles: emotional loss meets young practical intellect — grieving water and young earth, the page's freshness and innocence sometimes being a small light during times of grief." },
  "40_75": { vi: "Năm Cốc và Kỵ Sĩ Tiền: mất mát cảm xúc gặp sự kiên trì — nước đau buồn và đất bền bỉ, tinh thần trách nhiệm và ổn định của kỵ sĩ tiền hỗ trợ người đang đau qua từng bước tiến dần.", en: "Five of Cups and Knight of Pentacles: emotional loss meets perseverance — grieving water and persistent earth, the knight's responsible and steady spirit supporting the grieving person step by slow step." },
  "40_76": { vi: "Năm Cốc và Nữ Hoàng Tiền: mất mát cảm xúc gặp sự chăm sóc thực tế — nước đau buồn gặp nữ hoàng đất ân cần, sự chăm chút thực tế ấm áp là hình thức chữa lành mà trái tim đau cần nhất.", en: "Five of Cups and Queen of Pentacles: emotional loss meets practical nurturing — grieving water meeting the tender earth queen, warm practical care being the form of healing the aching heart most needs." },
  "40_77": { vi: "Năm Cốc và Vua Tiền: mất mát cảm xúc gặp quyền uy vật chất — nước đau buồn gặp vua đất uy quyền, sự ổn định và bảo vệ của vua tạo nền an toàn để trái tim có thể bắt đầu chữa lành.", en: "Five of Cups and King of Pentacles: emotional loss meets material authority — grieving water meeting the authoritative earth king, the king's stability and protection creating safe ground for the heart to begin healing." },
  "41_64": { vi: "Sáu Cốc và Át Tiền: hoài niệm gặp khởi đầu vật chất — nước ký ức ngọt ngào đón nhận mầm đất mới, quá khứ tươi đẹp truyền cảm hứng cho việc xây dựng tương lai thịnh vượng phía trước.", en: "Six of Cups and Ace of Pentacles: nostalgia meets material beginning — sweet memory water receiving the new earth seed, beautiful past inspiring the building of a prosperous future ahead." },
  "41_65": { vi: "Sáu Cốc và Hai Tiền: hoài niệm gặp sự cân bằng thực tế — nước ký ức ngọt ngào và đất xoay sở, cân bằng giữa trân trọng quá khứ và đáp ứng đòi hỏi thực tế của hiện tại.", en: "Six of Cups and Two of Pentacles: nostalgia meets practical balance — sweet memory water and juggling earth, balancing appreciation of the past with meeting the practical demands of the present." },
  "41_66": { vi: "Sáu Cốc và Ba Tiền: hoài niệm gặp hợp tác — nước ký ức ngọt ngào và đất làm việc nhóm, chia sẻ ký ức tốt đẹp xây dựng nền tảng tin cậy cho sự cộng tác trong cộng đồng.", en: "Six of Cups and Three of Pentacles: nostalgia meets collaboration — sweet memory water and teamwork earth, sharing good memories building a foundation of trust for collaboration within the community." },
  "41_67": { vi: "Sáu Cốc và Bốn Tiền: hoài niệm gặp sự tích trữ — nước ký ức ngọt ngào và đất giữ chặt, bám víu vào quá khứ lẫn tài sản tạo ra rào cản cho sự phát triển và đổi mới cần thiết.", en: "Six of Cups and Four of Pentacles: nostalgia meets hoarding — sweet memory water and clinging earth, holding onto both the past and possessions creating barriers to growth and necessary renewal." },
  "41_68": { vi: "Sáu Cốc và Năm Tiền: hoài niệm gặp thiếu thốn — nước ký ức ngọt ngào trong thời gian khó khăn, nhớ về thời kỳ sung túc hơn vừa là nguồn an ủi vừa là thách thức cảm xúc.", en: "Six of Cups and Five of Pentacles: nostalgia meets scarcity — sweet memory water in difficult times, remembering more prosperous periods being both a source of comfort and an emotional challenge." },
  "41_69": { vi: "Sáu Cốc và Sáu Tiền: hoài niệm gặp sự hào phóng — nước ký ức ngọt ngào và đất chia sẻ, truyền thống hào phóng từ quá khứ truyền cảm hứng cho sự cho đi trong hiện tại.", en: "Six of Cups and Six of Pentacles: nostalgia meets generosity — sweet memory water and sharing earth, generous traditions from the past inspiring continued giving and sharing in the present." },
  "41_70": { vi: "Sáu Cốc và Bảy Tiền: hoài niệm gặp sự kiên nhẫn — nước ký ức ngọt ngào và đất chờ đợi, bài học từ quá khứ giúp kiên nhẫn trong hiện tại khi kết quả chưa rõ ràng.", en: "Six of Cups and Seven of Pentacles: nostalgia meets patience — sweet memory water and waiting earth, lessons from the past helping maintain patience in the present when results are not yet visible." },
  "41_71": { vi: "Sáu Cốc và Tám Tiền: hoài niệm gặp sự cần cù — nước ký ức ngọt ngào và đất siêng năng, tình yêu với công việc thủ công thường có nguồn gốc từ những ký ức và truyền thống tốt đẹp.", en: "Six of Cups and Eight of Pentacles: nostalgia meets diligence — sweet memory water and industrious earth, love for handcraft often rooted in beautiful memories and cherished traditions from the past." },
  "41_72": { vi: "Sáu Cốc và Chín Tiền: hoài niệm gặp sự sung túc — nước ký ức ngọt ngào và đất phong phú, những kỷ niệm đẹp về sự sung mãn trong quá khứ nuôi dưỡng lòng biết ơn trong hiện tại.", en: "Six of Cups and Nine of Pentacles: nostalgia meets abundance — sweet memory water and prosperous earth, beautiful memories of past abundance nourishing gratitude and appreciation in the present moment." },
  "41_73": { vi: "Sáu Cốc và Mười Tiền: hoài niệm gặp sự viên mãn gia đình — nước ký ức ngọt ngào và đất di sản, sự gắn kết với ký ức gia đình nuôi dưỡng ý thức về di sản và trách nhiệm truyền đời.", en: "Six of Cups and Ten of Pentacles: nostalgia meets family completion — sweet memory water and legacy earth, connection to family memories nourishing a sense of heritage and responsibility across generations." },
  "41_74": { vi: "Sáu Cốc và Trang Bị Tiền: hoài niệm gặp trí tuệ thực tế trẻ — nước ký ức ngọt ngào và đất non nớt tò mò, chia sẻ trí tuệ từ quá khứ với thế hệ trẻ đang háo hức học hỏi.", en: "Six of Cups and Page of Pentacles: nostalgia meets youthful practical intellect — sweet memory water and young curious earth, sharing wisdom from the past with a younger generation eager to learn." },
  "41_75": { vi: "Sáu Cốc và Kỵ Sĩ Tiền: hoài niệm gặp sự kiên trì — nước ký ức ngọt ngào và đất bền bỉ, tinh thần trách nhiệm gắn với truyền thống là sức mạnh của kỵ sĩ đất trong hành trình.", en: "Six of Cups and Knight of Pentacles: nostalgia meets perseverance — sweet memory water and persistent earth, responsibility connected to tradition being the earth knight's strength along the journey." },
  "41_76": { vi: "Sáu Cốc và Nữ Hoàng Tiền: hoài niệm gặp sự chăm sóc thực tế — nước ký ức ngọt ngào và nữ hoàng đất ân cần, sự chăm chút ấm áp nhắc đến sự chăm sóc từ những người đã yêu thương ta trước đây.", en: "Six of Cups and Queen of Pentacles: nostalgia meets practical nurturing — sweet memory water and tender earth queen, her warm care evoking the nurturing of those who loved and cared for us in the past." },
  "41_77": { vi: "Sáu Cốc và Vua Tiền: hoài niệm gặp quyền uy vật chất — nước ký ức ngọt ngào và vua đất uy quyền, di sản được xây dựng bởi cha ông tạo nền tảng vững chắc mà vua tiền bảo vệ cho tương lai.", en: "Six of Cups and King of Pentacles: nostalgia meets material authority — sweet memory water and authoritative earth king, the legacy built by ancestors creating the solid foundation the king protects for the future." },
  "42_64": { vi: "Bảy Cốc và Át Tiền: ảo tưởng gặp khởi đầu vật chất — nước mơ mộng đối diện mầm đất thực tế, cơ hội thực sự yêu cầu buông bỏ ảo tưởng và bước vào hành động cụ thể có kết quả.", en: "Seven of Cups and Ace of Pentacles: illusion meets material beginning — dreaming water facing practical earth's seed, a real opportunity requiring letting go of illusion and stepping into concrete action." },
  "42_65": { vi: "Bảy Cốc và Hai Tiền: ảo tưởng gặp sự cân bằng thực tế — nước mơ mộng và đất xoay sở, quá nhiều lựa chọn tưởng tượng khiến khó cân bằng những đòi hỏi thực tế cụ thể của cuộc sống.", en: "Seven of Cups and Two of Pentacles: illusion meets practical balance — dreaming water and juggling earth, too many imagined choices making it hard to balance the specific practical demands of everyday life." },
  "42_66": { vi: "Bảy Cốc và Ba Tiền: ảo tưởng gặp hợp tác — nước mơ mộng và đất làm việc nhóm, kỹ năng biến ảo tưởng thành kế hoạch cụ thể là điều cần thiết để đóng góp thực sự cho nhóm.", en: "Seven of Cups and Three of Pentacles: illusion meets collaboration — dreaming water and teamwork earth, the skill of turning illusion into concrete plans being necessary to contribute meaningfully to the group." },
  "42_67": { vi: "Bảy Cốc và Bốn Tiền: ảo tưởng gặp sự tích trữ — nước mơ mộng và đất giữ chặt, ảo tưởng về sự giàu có vật chất hoặc bám víu vào kế hoạch không thực tế cản trở sự tăng trưởng thực sự.", en: "Seven of Cups and Four of Pentacles: illusion meets hoarding — dreaming water and clinging earth, illusions about material wealth or clinging to unrealistic plans blocking genuine growth and real progress." },
  "42_68": { vi: "Bảy Cốc và Năm Tiền: ảo tưởng trong hoàn cảnh thiếu thốn — nước mơ mộng trong thời gian khan hiếm, thoát vào thế giới ảo tưởng có thể là cơ chế bảo vệ hoặc cản trở giải quyết vấn đề thực tế.", en: "Seven of Cups and Five of Pentacles: illusion in times of scarcity — dreaming water in times of lack, escaping into illusion potentially being a protective mechanism or blocking practical problem-solving." },
  "42_69": { vi: "Bảy Cốc và Sáu Tiền: ảo tưởng gặp sự hào phóng — nước mơ mộng và đất chia sẻ, cần phân biệt giữa sự hào phóng thực sự và ảo tưởng về việc cho đi mà không thực sự hành động.", en: "Seven of Cups and Six of Pentacles: illusion meets generosity — dreaming water and sharing earth, needing to distinguish between genuine generosity and the illusion of giving without actually taking action." },
  "42_70": { vi: "Bảy Cốc và Bảy Tiền: ảo tưởng gặp sự kiên nhẫn — nước mơ mộng và đất chờ đợi, kiên nhẫn với kết quả thực tế khác với mơ mộng về điều chưa bắt đầu xây dựng từ nền tảng.", en: "Seven of Cups and Seven of Pentacles: illusion meets patience — dreaming water and waiting earth, patience with real results being different from dreaming of things not yet begun to build from the ground." },
  "42_71": { vi: "Bảy Cốc và Tám Tiền: ảo tưởng gặp sự cần cù — nước mơ mộng và đất siêng năng, sự tập trung và kỷ luật của tám tiền là liều thuốc đối kháng tốt nhất cho sự phân tán của bảy cốc.", en: "Seven of Cups and Eight of Pentacles: illusion meets diligence — dreaming water and industrious earth, the Eight's focus and discipline being the best antidote to the Seven of Cups' scattering of attention." },
  "42_72": { vi: "Bảy Cốc và Chín Tiền: ảo tưởng gặp sự sung túc — nước mơ mộng và đất phong phú, phân biệt giữa lòng biết ơn thực sự về những gì đã có và ảo tưởng về cuộc sống xa hoa chưa có.", en: "Seven of Cups and Nine of Pentacles: illusion meets abundance — dreaming water and prosperous earth, distinguishing between genuine gratitude for what exists and illusion about luxuries not yet attained." },
  "42_73": { vi: "Bảy Cốc và Mười Tiền: ảo tưởng gặp sự viên mãn gia đình — nước mơ mộng và đất di sản, lý tưởng hóa gia đình cần được cân bằng bởi sự đánh giá thực tế và trân trọng những gì thực sự có.", en: "Seven of Cups and Ten of Pentacles: illusion meets family completion — dreaming water and legacy earth, idealizing family needing to be balanced by realistic assessment and appreciation of what genuinely exists." },
  "42_74": { vi: "Bảy Cốc và Trang Bị Tiền: ảo tưởng gặp trí tuệ thực tế trẻ — nước mơ mộng và đất non nớt tò mò, học cách biến giấc mơ thành kế hoạch học tập thực tế là bài học cần thiết cho người trẻ.", en: "Seven of Cups and Page of Pentacles: illusion meets young practical intellect — dreaming water and young curious earth, learning to turn dreams into practical learning plans being a necessary lesson for the young." },
  "42_75": { vi: "Bảy Cốc và Kỵ Sĩ Tiền: ảo tưởng gặp sự kiên trì thực tế — nước mơ mộng và đất bền bỉ, tinh thần thực tế của kỵ sĩ tiền giúp chọn lọc ảo tưởng nào xứng đáng được theo đuổi kiên trì.", en: "Seven of Cups and Knight of Pentacles: illusion meets steady perseverance — dreaming water and persistent earth, the knight's practical spirit helping discern which dreams are worth pursuing with patient commitment." },
  "42_76": { vi: "Bảy Cốc và Nữ Hoàng Tiền: ảo tưởng gặp sự chăm sóc thực tế — nước mơ mộng gặp nữ hoàng đất thực tế, sự khôn ngoan thực dụng của bà giúp chắt lọc những gì thực sự có thể nuôi dưỡng trong cuộc sống.", en: "Seven of Cups and Queen of Pentacles: illusion meets practical nurturing — dreaming water meeting the practical earth queen, her pragmatic wisdom helping distill what can genuinely be nourished in real life." },
  "42_77": { vi: "Bảy Cốc và Vua Tiền: ảo tưởng gặp quyền uy vật chất — nước mơ mộng gặp vua đất thực tế, vua tiền hỏi những giấc mơ nào có giá trị đầu tư và những giấc mơ nào chỉ là sự trốn tránh.", en: "Seven of Cups and King of Pentacles: illusion meets material authority — dreaming water meeting the practical earth king, the king asking which dreams are worth investing in and which are merely avoidance." },
  // ── Tier 5e-2: Cups × Pentacles, water×earth (Cups 43–49 × Pentacles 64–77, 98 pairs) ──
  "43_64": { vi: "Tám Cốc và Át Tiền: rời bỏ điều cũ để đón nhận khởi đầu vật chất — nước chảy đi khỏi những gì đã qua, mầm đất mới mở ra tiềm năng thịnh vượng cho hành trình phía trước.", en: "Eight of Cups and Ace of Pentacles: leaving the old to embrace material beginning — water flowing away from what has passed, the new earth seed opening prosperous potential for the journey ahead." },
  "43_65": { vi: "Tám Cốc và Hai Tiền: rời bỏ trong khi vẫn phải xoay sở — nước chảy đi trong khi đất cân bằng tiếp tục, hành trình rời bỏ không miễn cho ta khỏi những đòi hỏi thực tế hàng ngày.", en: "Eight of Cups and Two of Pentacles: departing while still juggling — water flowing away while balancing earth continues, the departure journey not exempting one from daily practical demands." },
  "43_66": { vi: "Tám Cốc và Ba Tiền: rời bỏ để tìm cộng đồng mới — nước chảy từ nơi không còn phù hợp đến nơi có sự hợp tác thực sự, hành trình tìm kiếm môi trường xây dựng có ý nghĩa.", en: "Eight of Cups and Three of Pentacles: departing to find new community — water flowing from where it no longer fits toward genuine collaboration, a journey seeking a meaningful and constructive environment." },
  "43_67": { vi: "Tám Cốc và Bốn Tiền: rời bỏ nhưng bám víu vào an toàn vật chất — nước muốn chảy đi nhưng đất giữ chặt, nỗi sợ mất đi sự an toàn tài chính cản trở quyết định ra đi cần thiết.", en: "Eight of Cups and Four of Pentacles: wanting to leave but clinging to material security — water wanting to flow but earth holding tight, fear of losing financial security blocking the necessary departure." },
  "43_68": { vi: "Tám Cốc và Năm Tiền: rời bỏ vào hoàn cảnh thiếu thốn — nước chảy đi trong khi đất khan hiếm, sự dũng cảm rời bỏ điều không còn phù hợp ngay cả khi chưa biết điều gì chờ đợi phía trước.", en: "Eight of Cups and Five of Pentacles: departing into scarcity — water flowing while earth is scarce, the courage to leave what no longer fits even when uncertain what awaits on the other side." },
  "43_69": { vi: "Tám Cốc và Sáu Tiền: rời bỏ với lòng hào phóng — nước chảy đi sau khi đã cho đi những gì có thể, sự hào phóng trong giai đoạn chuyển tiếp làm nhẹ lòng và mở đường cho tương lai mới.", en: "Eight of Cups and Six of Pentacles: departing with generosity — water flowing after giving what it can, generosity during transition lightening the heart and opening the path to a new future." },
  "43_70": { vi: "Tám Cốc và Bảy Tiền: rời bỏ sau khi đánh giá — nước chảy đi sau khi đã chờ đợi và nhìn thấy rõ ràng, sự kiên nhẫn quan sát giúp ra đi vào đúng thời điểm thay vì bốc đồng.", en: "Eight of Cups and Seven of Pentacles: departing after assessment — water flowing after patient observation has brought clarity, patient watching helping to leave at the right moment rather than impulsively." },
  "43_71": { vi: "Tám Cốc và Tám Tiền: rời bỏ để tìm công việc có ý nghĩa hơn — nước chảy đi từ điều không còn nuôi dưỡng, đất siêng năng chờ đợi ở nơi kỹ năng và tâm huyết được trân trọng thực sự.", en: "Eight of Cups and Eight of Pentacles: departing to find more meaningful work — water flowing from what no longer nourishes, industrious earth waiting where skills and dedication are truly valued." },
  "43_72": { vi: "Tám Cốc và Chín Tiền: rời bỏ để đến với sự sung túc thực sự — nước chảy đi từ điều chỉ đủ đầy bề ngoài, đất phong phú ở phía trước hứa hẹn sự sung mãn thực sự và tự do.", en: "Eight of Cups and Nine of Pentacles: departing toward genuine abundance — water flowing from what is only outwardly sufficient, prosperous earth ahead promising true plenty and authentic freedom." },
  "43_73": { vi: "Tám Cốc và Mười Tiền: rời bỏ gia đình để tìm chính mình — nước chảy đi từ không gian gia đình viên mãn nhưng không còn phù hợp, hành trình cá nhân không mâu thuẫn với tình yêu gia đình.", en: "Eight of Cups and Ten of Pentacles: leaving family space to find oneself — water flowing from a complete family space that no longer fits, personal journey not contradicting love for family." },
  "43_74": { vi: "Tám Cốc và Trang Bị Tiền: rời bỏ với tinh thần học hỏi — nước chảy đi mang theo sự tò mò, đất non nớt ở phía trước đón nhận người học hỏi bằng cả trái tim và bàn tay thực tế.", en: "Eight of Cups and Page of Pentacles: departing with a learning spirit — water flowing with curiosity, young earth ahead welcoming the learner with both heart and practically grounded hands." },
  "43_75": { vi: "Tám Cốc và Kỵ Sĩ Tiền: rời bỏ với tinh thần trách nhiệm — nước chảy đi nhưng không bỏ lại nghĩa vụ, kỵ sĩ đất đảm bảo hành trình rời xa được thực hiện với sự tôn trọng và trách nhiệm.", en: "Eight of Cups and Knight of Pentacles: departing with a spirit of responsibility — water flowing without abandoning obligations, the earth knight ensuring the departure is carried out with respect and responsibility." },
  "43_76": { vi: "Tám Cốc và Nữ Hoàng Tiền: rời bỏ với sự chăm sóc thực tế — nước chảy đi được nữ hoàng đất đồng hành, sự khôn ngoan thực dụng giúp hành trình rời bỏ được thực hiện với ân sủng và kế hoạch.", en: "Eight of Cups and Queen of Pentacles: departing with practical care — water flowing accompanied by the earth queen, pragmatic wisdom helping the departure be carried out with grace and a clear plan." },
  "43_77": { vi: "Tám Cốc và Vua Tiền: rời bỏ dưới sự chúc phúc của quyền uy — nước chảy đi với sự chấp thuận của vua đất, quyết định ra đi được củng cố bởi sự ổn định đã xây dựng và nền tảng vững chắc.", en: "Eight of Cups and King of Pentacles: departing with authority's blessing — water flowing with the earth king's approval, the decision to leave reinforced by stability already built and a solid foundation." },
  "44_64": { vi: "Chín Cốc và Át Tiền: mãn nguyện gặp khởi đầu thịnh vượng — nước đầy ắp ước nguyện đón nhận mầm đất mới, sự thỏa mãn cảm xúc kết hợp tiềm năng vật chất tạo ra nền tảng cuộc sống trọn vẹn.", en: "Nine of Cups and Ace of Pentacles: contentment meets prosperous beginning — water brimming with wishes fulfilled receiving the new earth seed, emotional satisfaction combining with material potential creating a complete life foundation." },
  "44_65": { vi: "Chín Cốc và Hai Tiền: mãn nguyện gặp sự cân bằng thực tế — nước đầy ắp và đất xoay sở, sự hài lòng cảm xúc không loại trừ việc phải tiếp tục cân bằng những đòi hỏi thực tế.", en: "Nine of Cups and Two of Pentacles: contentment meets practical balance — water brimming and earth juggling, emotional satisfaction not exempting one from continuing to balance practical demands of life." },
  "44_66": { vi: "Chín Cốc và Ba Tiền: mãn nguyện gặp hợp tác — nước đầy ắp và đất làm việc nhóm, sự hài lòng cảm xúc tăng thêm khi được chia sẻ trong cộng đồng cùng nhau xây dựng điều có giá trị.", en: "Nine of Cups and Three of Pentacles: contentment meets collaboration — water brimming and teamwork earth, emotional satisfaction amplified when shared within a community building something valuable together." },
  "44_67": { vi: "Chín Cốc và Bốn Tiền: mãn nguyện gặp sự tích trữ — nước đầy ắp và đất giữ chặt, sự hài lòng thực sự không đến từ tích lũy mà từ trải nghiệm sống và kết nối với người khác.", en: "Nine of Cups and Four of Pentacles: contentment meets hoarding — water brimming and clinging earth, true satisfaction not coming from accumulation but from lived experience and connection with others." },
  "44_68": { vi: "Chín Cốc và Năm Tiền: mãn nguyện cảm xúc trong hoàn cảnh thiếu thốn vật chất — nước đầy trong thời khan hiếm, hạnh phúc nội tâm có thể tồn tại ngay cả khi nguồn lực bên ngoài eo hẹp.", en: "Nine of Cups and Five of Pentacles: emotional contentment amid material scarcity — water full in times of lack, inner happiness able to exist even when external resources are stretched thin." },
  "44_69": { vi: "Chín Cốc và Sáu Tiền: mãn nguyện gặp sự hào phóng — nước đầy ắp và đất chia sẻ, sự thỏa mãn trở nên đầy đủ hơn khi được chia sẻ với người khác một cách rộng rãi và vô tư.", en: "Nine of Cups and Six of Pentacles: contentment meets generosity — water brimming and sharing earth, satisfaction becoming more complete when shared generously and selflessly with others around." },
  "44_70": { vi: "Chín Cốc và Bảy Tiền: mãn nguyện gặp sự đánh giá — nước đầy ắp và đất kiểm tra kết quả, sự hài lòng được đánh giá thực tế: liệu những gì đã đạt được có tương xứng với nỗ lực đã bỏ ra.", en: "Nine of Cups and Seven of Pentacles: contentment meets assessment — water brimming and earth evaluating results, satisfaction assessed practically: whether what has been achieved matches the effort invested." },
  "44_71": { vi: "Chín Cốc và Tám Tiền: mãn nguyện gặp sự cần cù — nước đầy ắp và đất siêng năng, hạnh phúc được xây dựng qua sự cần cù bền bỉ là loại thỏa mãn sâu sắc và bền vững nhất.", en: "Nine of Cups and Eight of Pentacles: contentment meets diligence — water brimming and industrious earth, happiness built through persistent diligence being the deepest and most lasting form of satisfaction." },
  "44_72": { vi: "Chín Cốc và Chín Tiền: hai loại sung mãn gặp nhau — nước đầy ắp cảm xúc và đất phong phú vật chất, sự thỏa mãn từ bên trong và từ bên ngoài cùng hiện diện tạo ra trạng thái viên mãn toàn diện.", en: "Nine of Cups and Nine of Pentacles: two forms of abundance meeting — emotionally brimming water and materially prosperous earth, inner and outer satisfaction both present creating a state of complete fulfillment." },
  "44_73": { vi: "Chín Cốc và Mười Tiền: mãn nguyện cá nhân gặp viên mãn gia đình — nước đầy ắp và đất di sản, hạnh phúc cá nhân được nhân lên khi đặt trong bối cảnh ổn định và kế thừa lâu dài.", en: "Nine of Cups and Ten of Pentacles: personal contentment meets family completion — water brimming and legacy earth, individual happiness multiplied when placed in the context of lasting stability and inheritance." },
  "44_74": { vi: "Chín Cốc và Trang Bị Tiền: mãn nguyện gặp trí tuệ thực tế trẻ — nước đầy ắp và đất non nớt tò mò, sự hài lòng của chín cốc truyền cảm hứng cho trang bị tiền rằng nỗ lực thực tế mang lại phần thưởng xứng đáng.", en: "Nine of Cups and Page of Pentacles: contentment meets young practical intellect — water brimming and young curious earth, the satisfaction of Nine inspiring the page that practical effort brings worthy rewards." },
  "44_75": { vi: "Chín Cốc và Kỵ Sĩ Tiền: mãn nguyện gặp sự kiên trì — nước đầy ắp và đất bền bỉ, sự hài lòng thực sự là phần thưởng cho những ai kiên trì theo đuổi mục tiêu với trách nhiệm và bền bỉ.", en: "Nine of Cups and Knight of Pentacles: contentment meets perseverance — water brimming and persistent earth, true satisfaction being the reward for those who pursue goals persistently with responsibility." },
  "44_76": { vi: "Chín Cốc và Nữ Hoàng Tiền: mãn nguyện gặp sự chăm sóc thực tế — nước đầy ắp được nữ hoàng đất bảo bọc, sự thỏa mãn cảm xúc được nuôi dưỡng bởi môi trường ấm áp và thực tế.", en: "Nine of Cups and Queen of Pentacles: contentment meets practical nurturing — water brimming sheltered by the earth queen, emotional satisfaction nourished by a warm and practically grounded environment." },
  "44_77": { vi: "Chín Cốc và Vua Tiền: mãn nguyện gặp quyền uy vật chất — nước đầy ắp được vua đất bảo vệ, sự thỏa mãn cảm xúc được đặt trên nền tảng vật chất vững chắc tạo ra cuộc sống thực sự đủ đầy.", en: "Nine of Cups and King of Pentacles: contentment meets material authority — water brimming protected by the earth king, emotional satisfaction set upon a solid material foundation creating a truly complete life." },
  "45_64": { vi: "Mười Cốc và Át Tiền: hạnh phúc gia đình gặp khởi đầu thịnh vượng — nước viên mãn yêu thương đón nhận mầm đất mới, gia đình hạnh phúc đặt nền cho thịnh vượng vật chất cùng nảy sinh.", en: "Ten of Cups and Ace of Pentacles: family happiness meets prosperous beginning — complete loving water receiving the new earth seed, a happy family laying the foundation for material prosperity to arise together." },
  "45_65": { vi: "Mười Cốc và Hai Tiền: hạnh phúc gia đình gặp sự cân bằng thực tế — nước viên mãn và đất xoay sở, gia đình hạnh phúc vẫn cần cân bằng những đòi hỏi tài chính và thực tế mỗi ngày.", en: "Ten of Cups and Two of Pentacles: family happiness meets practical balance — complete water and juggling earth, a happy family still needing to balance financial and practical demands every day." },
  "45_66": { vi: "Mười Cốc và Ba Tiền: hạnh phúc gia đình gặp hợp tác — nước viên mãn và đất làm việc nhóm, gia đình hạnh phúc phát triển khi các thành viên cùng nhau đóng góp xây dựng cuộc sống chung.", en: "Ten of Cups and Three of Pentacles: family happiness meets collaboration — complete water and teamwork earth, a happy family flourishing when members contribute together in building their shared life." },
  "45_67": { vi: "Mười Cốc và Bốn Tiền: hạnh phúc gia đình gặp sự tích trữ — nước viên mãn và đất giữ chặt, hạnh phúc gia đình bị thử thách khi sự bám víu tài chính lấn át sự chia sẻ và kết nối.", en: "Ten of Cups and Four of Pentacles: family happiness meets hoarding — complete water and clinging earth, family happiness challenged when financial clinging overshadows sharing and genuine connection." },
  "45_68": { vi: "Mười Cốc và Năm Tiền: hạnh phúc gia đình trong hoàn cảnh khó khăn — nước viên mãn trong thời khan hiếm, tình yêu gia đình là nguồn sức mạnh lớn nhất khi nguồn lực vật chất trở nên eo hẹp.", en: "Ten of Cups and Five of Pentacles: family happiness in difficult times — complete water in scarcity, family love being the greatest source of strength when material resources become stretched thin." },
  "45_69": { vi: "Mười Cốc và Sáu Tiền: hạnh phúc gia đình gặp sự hào phóng — nước viên mãn và đất chia sẻ, gia đình hạnh phúc lan tỏa sự hào phóng ra cộng đồng xung quanh một cách tự nhiên và chân thành.", en: "Ten of Cups and Six of Pentacles: family happiness meets generosity — complete water and sharing earth, a happy family naturally and sincerely extending generosity outward to the surrounding community." },
  "45_70": { vi: "Mười Cốc và Bảy Tiền: hạnh phúc gia đình gặp sự kiên nhẫn — nước viên mãn và đất đánh giá, hạnh phúc gia đình là kết quả của nhiều năm đầu tư kiên nhẫn vào tình yêu và sự gắn bó.", en: "Ten of Cups and Seven of Pentacles: family happiness meets patience — complete water and assessing earth, family happiness being the result of years of patient investment in love and enduring connection." },
  "45_71": { vi: "Mười Cốc và Tám Tiền: hạnh phúc gia đình gặp sự cần cù — nước viên mãn và đất siêng năng, hạnh phúc gia đình được xây dựng và duy trì qua sự cần cù đóng góp của từng thành viên.", en: "Ten of Cups and Eight of Pentacles: family happiness meets diligence — complete water and industrious earth, family happiness built and maintained through the diligent contribution of each member." },
  "45_72": { vi: "Mười Cốc và Chín Tiền: hạnh phúc gia đình gặp sự sung túc — nước viên mãn và đất phong phú, hạnh phúc cảm xúc và sự sung mãn vật chất cùng hiện diện tạo ra cuộc sống viên mãn toàn diện.", en: "Ten of Cups and Nine of Pentacles: family happiness meets abundance — complete water and prosperous earth, emotional happiness and material plenty both present creating a completely fulfilled life." },
  "45_73": { vi: "Mười Cốc và Mười Tiền: hai loại viên mãn gặp nhau — nước hạnh phúc gia đình và đất di sản, tình yêu gia đình và di sản vật chất cùng hội tụ tạo ra nền tảng thế hệ bền vững nhất.", en: "Ten of Cups and Ten of Pentacles: two forms of completion meeting — family happiness water and legacy earth, family love and material heritage converging to create the most enduring generational foundation." },
  "45_74": { vi: "Mười Cốc và Trang Bị Tiền: hạnh phúc gia đình nuôi dưỡng trí tuệ trẻ — nước viên mãn và đất non nớt tò mò, gia đình hạnh phúc tạo môi trường an toàn cho người trẻ học hỏi và phát triển.", en: "Ten of Cups and Page of Pentacles: family happiness nurturing young intellect — complete water and young curious earth, a happy family creating a safe environment for the young to learn and grow." },
  "45_75": { vi: "Mười Cốc và Kỵ Sĩ Tiền: hạnh phúc gia đình và tinh thần trách nhiệm — nước viên mãn và đất bền bỉ, kỵ sĩ tiền gánh trách nhiệm thực tế để gia đình tiếp tục hưởng hạnh phúc và ổn định.", en: "Ten of Cups and Knight of Pentacles: family happiness and responsibility — complete water and persistent earth, the earth knight carrying practical responsibilities so the family continues to enjoy happiness and stability." },
  "45_76": { vi: "Mười Cốc và Nữ Hoàng Tiền: hạnh phúc gia đình gặp sự chăm sóc thực tế — nước viên mãn và nữ hoàng đất ân cần, sự chăm chút ấm áp của nữ hoàng là nền tảng vật chất của hạnh phúc gia đình.", en: "Ten of Cups and Queen of Pentacles: family happiness meets practical nurturing — complete water and tender earth queen, the queen's warm care being the material foundation of family happiness and wholeness." },
  "45_77": { vi: "Mười Cốc và Vua Tiền: hạnh phúc gia đình gặp quyền uy vật chất — nước viên mãn và vua đất uy quyền, sự bảo vệ và ổn định của vua tiền là điều kiện vật chất để hạnh phúc gia đình tồn tại bền vững.", en: "Ten of Cups and King of Pentacles: family happiness meets material authority — complete water and authoritative earth king, the king's protection and stability being the material condition for family happiness to endure." },
  "46_64": { vi: "Trang Bị Cốc và Át Tiền: trái tim non trẻ gặp khởi đầu thịnh vượng — nước cảm xúc ngây thơ đón nhận mầm đất mới, sự tươi mát của tình cảm và tiềm năng vật chất cùng nảy mầm từ đầu.", en: "Page of Cups and Ace of Pentacles: young heart meets prosperous beginning — innocent emotional water receiving the new earth seed, freshness of feeling and material potential sprouting together from the very start." },
  "46_65": { vi: "Trang Bị Cốc và Hai Tiền: trái tim non trẻ gặp sự cân bằng thực tế — nước cảm xúc ngây thơ và đất xoay sở, người trẻ học cách cân bằng giữa cảm xúc dồi dào và đòi hỏi thực tế cuộc sống.", en: "Page of Cups and Two of Pentacles: young heart meets practical balance — innocent emotional water and juggling earth, the young one learning to balance abundant feelings and the practical demands of life." },
  "46_66": { vi: "Trang Bị Cốc và Ba Tiền: trái tim non trẻ gặp hợp tác — nước cảm xúc ngây thơ và đất làm việc nhóm, người trẻ học cách đóng góp cảm xúc và thực tế vào những dự án cộng đồng chung.", en: "Page of Cups and Three of Pentacles: young heart meets collaboration — innocent emotional water and teamwork earth, the young one learning to contribute both emotionally and practically to shared communal projects." },
  "46_67": { vi: "Trang Bị Cốc và Bốn Tiền: trái tim non trẻ gặp sự tích trữ — nước cảm xúc ngây thơ và đất giữ chặt, người trẻ học bài học về sự cân bằng giữa hào phóng cảm xúc và an toàn vật chất.", en: "Page of Cups and Four of Pentacles: young heart meets hoarding — innocent emotional water and clinging earth, the young one learning the lesson of balance between emotional generosity and material security." },
  "46_68": { vi: "Trang Bị Cốc và Năm Tiền: trái tim non trẻ trong hoàn cảnh thiếu thốn — nước cảm xúc ngây thơ trong thời khan hiếm, người trẻ học cách duy trì tâm hồn tươi sáng ngay cả trong hoàn cảnh vật chất khó khăn.", en: "Page of Cups and Five of Pentacles: young heart in scarcity — innocent emotional water in times of lack, the young one learning to keep a bright spirit even in materially difficult circumstances." },
  "46_69": { vi: "Trang Bị Cốc và Sáu Tiền: trái tim non trẻ gặp sự hào phóng — nước cảm xúc ngây thơ và đất chia sẻ, người trẻ học cách cho đi và nhận lại một cách cân bằng và trân trọng.", en: "Page of Cups and Six of Pentacles: young heart meets generosity — innocent emotional water and sharing earth, the young one learning how to give and receive in a balanced and appreciative way." },
  "46_70": { vi: "Trang Bị Cốc và Bảy Tiền: trái tim non trẻ gặp sự kiên nhẫn — nước cảm xúc ngây thơ và đất chờ đợi, người trẻ học rằng những điều đáng giá nhất trong cuộc đời cần thời gian để trưởng thành.", en: "Page of Cups and Seven of Pentacles: young heart meets patience — innocent emotional water and waiting earth, the young one learning that the most worthwhile things in life need time to properly mature." },
  "46_71": { vi: "Trang Bị Cốc và Tám Tiền: trái tim non trẻ gặp sự cần cù — nước cảm xúc ngây thơ và đất siêng năng, người trẻ học rằng sự đam mê cảm xúc cần được hỗ trợ bởi kỷ luật và kỹ năng thực tế.", en: "Page of Cups and Eight of Pentacles: young heart meets diligence — innocent emotional water and industrious earth, the young one learning that emotional passion needs to be supported by discipline and practical skill." },
  "46_72": { vi: "Trang Bị Cốc và Chín Tiền: trái tim non trẻ gặp sự sung túc — nước cảm xúc ngây thơ và đất phong phú, người trẻ nảy sinh trong môi trường sung mãn, học cách trân trọng và không lãng phí.", en: "Page of Cups and Nine of Pentacles: young heart meets abundance — innocent emotional water and prosperous earth, the young one growing in an environment of plenty, learning to appreciate and not to waste." },
  "46_73": { vi: "Trang Bị Cốc và Mười Tiền: trái tim non trẻ trong gia đình viên mãn — nước cảm xúc ngây thơ và đất di sản, người trẻ lớn lên trong môi trường ổn định với ý thức về di sản và trách nhiệm.", en: "Page of Cups and Ten of Pentacles: young heart within a complete family — innocent emotional water and legacy earth, the young one growing up in a stable environment with a sense of heritage and responsibility." },
  "46_74": { vi: "Trang Bị Cốc và Trang Bị Tiền: hai trang bị gặp nhau — nước cảm xúc ngây thơ và đất thực tế non nớt, hai tâm hồn trẻ với những loại tò mò khác nhau cùng khám phá thế giới bên nhau.", en: "Page of Cups and Page of Pentacles: two pages meeting — innocent emotional water and young practical earth, two young souls with different kinds of curiosity exploring the world alongside each other." },
  "46_75": { vi: "Trang Bị Cốc và Kỵ Sĩ Tiền: trái tim non trẻ gặp tinh thần kiên trì — nước cảm xúc ngây thơ và đất bền bỉ, kỵ sĩ tiền làm gương cho trang bị cốc về ý nghĩa của trách nhiệm bền vững.", en: "Page of Cups and Knight of Pentacles: young heart meets steady perseverance — innocent emotional water and persistent earth, the earth knight modeling for the page the meaning of sustained responsibility." },
  "46_76": { vi: "Trang Bị Cốc và Nữ Hoàng Tiền: trái tim non trẻ được chăm sóc thực tế — nước cảm xúc ngây thơ được nữ hoàng đất nuôi dưỡng, sự chăm chút ấm áp của nữ hoàng giúp người trẻ phát triển toàn diện.", en: "Page of Cups and Queen of Pentacles: young heart practically nurtured — innocent emotional water nourished by the earth queen, her warm care helping the young one develop in a wholesome and complete way." },
  "46_77": { vi: "Trang Bị Cốc và Vua Tiền: trái tim non trẻ trước quyền uy vật chất — nước cảm xúc ngây thơ gặp vua đất uy quyền, vua tiền dạy trang bị cốc rằng cảm xúc cần được đặt trên nền tảng thực tế vững chắc.", en: "Page of Cups and King of Pentacles: young heart before material authority — innocent emotional water meeting the authoritative earth king, the king teaching the page that feelings need to be set on a solid practical foundation." },
  "47_64": { vi: "Kỵ Sĩ Cốc và Át Tiền: người lãng mạn gặp khởi đầu thịnh vượng — nước cảm xúc hào hoa đón nhận mầm đất mới, lý tưởng lãng mạn tìm thấy cơ hội để trở thành hiện thực vật chất.", en: "Knight of Cups and Ace of Pentacles: the romantic meets prosperous beginning — gallant emotional water receiving the new earth seed, romantic ideals finding the opportunity to become material reality." },
  "47_65": { vi: "Kỵ Sĩ Cốc và Hai Tiền: người lãng mạn gặp sự cân bằng thực tế — nước cảm xúc hào hoa và đất xoay sở, lý tưởng lãng mạn cần được cân bằng với những đòi hỏi thực tế không thể bỏ qua.", en: "Knight of Cups and Two of Pentacles: the romantic meets practical balance — gallant emotional water and juggling earth, romantic ideals needing to be balanced with practical demands that cannot be ignored." },
  "47_66": { vi: "Kỵ Sĩ Cốc và Ba Tiền: người lãng mạn gặp hợp tác — nước cảm xúc hào hoa và đất làm việc nhóm, lý tưởng lãng mạn được hiện thực hóa qua sự hợp tác và đóng góp thực tế trong cộng đồng.", en: "Knight of Cups and Three of Pentacles: the romantic meets collaboration — gallant emotional water and teamwork earth, romantic ideals materialized through collaboration and practical contribution within the community." },
  "47_67": { vi: "Kỵ Sĩ Cốc và Bốn Tiền: người lãng mạn gặp sự tích trữ — nước cảm xúc hào hoa và đất giữ chặt, lý tưởng lãng mạn bị thử thách bởi người đặt sự an toàn vật chất lên trên tất cả.", en: "Knight of Cups and Four of Pentacles: the romantic meets hoarding — gallant emotional water and clinging earth, romantic ideals challenged by someone who places material security above all else." },
  "47_68": { vi: "Kỵ Sĩ Cốc và Năm Tiền: người lãng mạn trong hoàn cảnh thiếu thốn — nước cảm xúc hào hoa trong thời khan hiếm, lý tưởng lãng mạn bị thử thách khi thiếu nền tảng vật chất để hỗ trợ.", en: "Knight of Cups and Five of Pentacles: the romantic in times of scarcity — gallant emotional water in lack, romantic ideals challenged when there is insufficient material foundation to support them." },
  "47_69": { vi: "Kỵ Sĩ Cốc và Sáu Tiền: người lãng mạn gặp sự hào phóng — nước cảm xúc hào hoa và đất chia sẻ, lý tưởng lãng mạn được nuôi dưỡng trong bầu không khí của sự cho đi và nhận lại.", en: "Knight of Cups and Six of Pentacles: the romantic meets generosity — gallant emotional water and sharing earth, romantic ideals nourished in an atmosphere of generous giving and gracious receiving." },
  "47_70": { vi: "Kỵ Sĩ Cốc và Bảy Tiền: người lãng mạn gặp sự kiên nhẫn — nước cảm xúc hào hoa và đất chờ đợi, lý tưởng lãng mạn được thử thách xem liệu có đủ kiên nhẫn để hiện thực hóa hay không.", en: "Knight of Cups and Seven of Pentacles: the romantic meets patience — gallant emotional water and waiting earth, romantic ideals tested as to whether there is enough patience to materialize them into reality." },
  "47_71": { vi: "Kỵ Sĩ Cốc và Tám Tiền: người lãng mạn gặp sự cần cù — nước cảm xúc hào hoa và đất siêng năng, lý tưởng lãng mạn được hiện thực hóa qua sự cần cù và kỷ luật bền bỉ theo thời gian.", en: "Knight of Cups and Eight of Pentacles: the romantic meets diligence — gallant emotional water and industrious earth, romantic ideals materialized through persistent and disciplined effort sustained over time." },
  "47_72": { vi: "Kỵ Sĩ Cốc và Chín Tiền: người lãng mạn gặp sự sung túc — nước cảm xúc hào hoa và đất phong phú, lý tưởng lãng mạn nảy nở trong không gian của sự tự lập và sung mãn vật chất.", en: "Knight of Cups and Nine of Pentacles: the romantic meets abundance — gallant emotional water and prosperous earth, romantic ideals blossoming in a space of self-sufficiency and material plenty." },
  "47_73": { vi: "Kỵ Sĩ Cốc và Mười Tiền: người lãng mạn gặp sự viên mãn gia đình — nước cảm xúc hào hoa và đất di sản, lý tưởng lãng mạn tìm thấy ý nghĩa sâu sắc hơn trong bối cảnh ổn định và di sản lâu dài.", en: "Knight of Cups and Ten of Pentacles: the romantic meets family completion — gallant emotional water and legacy earth, romantic ideals finding deeper meaning within the context of lasting stability and heritage." },
  "47_74": { vi: "Kỵ Sĩ Cốc và Trang Bị Tiền: người lãng mạn gặp trí tuệ thực tế trẻ — nước cảm xúc hào hoa và đất non nớt tò mò, lý tưởng lãng mạn và ham học hỏi thực tế kết hợp tạo ra tiềm năng phát triển.", en: "Knight of Cups and Page of Pentacles: the romantic meets young practical intellect — gallant emotional water and young curious earth, romantic ideals and practical curiosity combining to create growth potential." },
  "47_75": { vi: "Kỵ Sĩ Cốc và Kỵ Sĩ Tiền: hai kỵ sĩ gặp nhau — nước lãng mạn hào hoa và đất bền bỉ thực tế, lý tưởng và trách nhiệm đối thoại, mỗi bên học hỏi điều tốt nhất từ phong cách của nhau.", en: "Knight of Cups and Knight of Pentacles: two knights meeting — gallant romantic water and steady practical earth, ideals and responsibility in dialogue, each learning the best from the other's approach." },
  "47_76": { vi: "Kỵ Sĩ Cốc và Nữ Hoàng Tiền: người lãng mạn gặp sự chăm sóc thực tế — nước cảm xúc hào hoa và nữ hoàng đất ân cần, sự khôn ngoan thực tế của nữ hoàng giúp kỵ sĩ lãng mạn đặt chân xuống đất.", en: "Knight of Cups and Queen of Pentacles: the romantic meets practical nurturing — gallant emotional water and tender earth queen, the queen's practical wisdom helping the romantic knight place his feet firmly on the ground." },
  "47_77": { vi: "Kỵ Sĩ Cốc và Vua Tiền: người lãng mạn gặp quyền uy vật chất — nước cảm xúc hào hoa và vua đất uy quyền, vua tiền hỏi kỵ sĩ lãng mạn liệu giấc mơ có thể trở thành sự nghiệp bền vững không.", en: "Knight of Cups and King of Pentacles: the romantic meets material authority — gallant emotional water and authoritative earth king, the king asking the romantic knight whether the dream can become a sustainable livelihood." },
  "48_64": { vi: "Nữ Hoàng Cốc và Át Tiền: sự thấu cảm gặp khởi đầu thịnh vượng — nước trực giác sâu sắc đón nhận mầm đất mới, trực giác nhạy bén của nữ hoàng giúp nhận ra và nắm bắt cơ hội vật chất.", en: "Queen of Cups and Ace of Pentacles: empathy meets prosperous beginning — deeply intuitive water receiving the new earth seed, the queen's sharp intuition helping to recognize and seize material opportunity." },
  "48_65": { vi: "Nữ Hoàng Cốc và Hai Tiền: sự thấu cảm gặp sự cân bằng thực tế — nước trực giác sâu sắc và đất xoay sở, nữ hoàng cảm xúc học cân bằng giữa chăm sóc người khác và đáp ứng đòi hỏi thực tế.", en: "Queen of Cups and Two of Pentacles: empathy meets practical balance — deeply intuitive water and juggling earth, the emotional queen learning to balance caring for others and meeting practical demands." },
  "48_66": { vi: "Nữ Hoàng Cốc và Ba Tiền: sự thấu cảm gặp hợp tác — nước trực giác sâu sắc và đất làm việc nhóm, sự thấu cảm của nữ hoàng tăng cường sự gắn kết và hiệu quả trong môi trường hợp tác.", en: "Queen of Cups and Three of Pentacles: empathy meets collaboration — deeply intuitive water and teamwork earth, the queen's empathy strengthening cohesion and effectiveness in the collaborative environment." },
  "48_67": { vi: "Nữ Hoàng Cốc và Bốn Tiền: sự thấu cảm gặp sự tích trữ — nước trực giác sâu sắc và đất giữ chặt, nữ hoàng cảm xúc nhận ra nỗi sợ ẩn sau sự bám víu vật chất và có thể giúp chữa lành.", en: "Queen of Cups and Four of Pentacles: empathy meets hoarding — deeply intuitive water and clinging earth, the emotional queen perceiving the fear hidden behind material clinging and able to help heal it." },
  "48_68": { vi: "Nữ Hoàng Cốc và Năm Tiền: sự thấu cảm trong hoàn cảnh thiếu thốn — nước trực giác sâu sắc và đất khan hiếm, nữ hoàng cảm xúc mang lại sự ấm áp và an ủi trong những thời điểm vật chất khó khăn nhất.", en: "Queen of Cups and Five of Pentacles: empathy in scarcity — deeply intuitive water and scarce earth, the emotional queen bringing warmth and comfort during the most materially difficult times." },
  "48_69": { vi: "Nữ Hoàng Cốc và Sáu Tiền: sự thấu cảm gặp sự hào phóng — nước trực giác sâu sắc và đất chia sẻ, nữ hoàng cảm xúc cho đi từ trái tim thực sự và nhận lại bằng lòng biết ơn chân thành.", en: "Queen of Cups and Six of Pentacles: empathy meets generosity — deeply intuitive water and sharing earth, the emotional queen giving from the heart truly and receiving back with genuine gratitude." },
  "48_70": { vi: "Nữ Hoàng Cốc và Bảy Tiền: sự thấu cảm gặp sự kiên nhẫn — nước trực giác sâu sắc và đất chờ đợi, nữ hoàng cảm xúc kiên nhẫn chờ đợi kết quả với sự tin tưởng dựa trên trực giác sâu sắc.", en: "Queen of Cups and Seven of Pentacles: empathy meets patience — deeply intuitive water and waiting earth, the emotional queen waiting patiently for results with trust grounded in deep intuition." },
  "48_71": { vi: "Nữ Hoàng Cốc và Tám Tiền: sự thấu cảm gặp sự cần cù — nước trực giác sâu sắc và đất siêng năng, nữ hoàng cảm xúc dành tâm huyết vào công việc chăm sóc như một nghề thủ công đòi hỏi sự tinh xảo.", en: "Queen of Cups and Eight of Pentacles: empathy meets diligence — deeply intuitive water and industrious earth, the emotional queen dedicating herself to the craft of caring with the same diligence as skilled artisanry." },
  "48_72": { vi: "Nữ Hoàng Cốc và Chín Tiền: sự thấu cảm gặp sự sung túc — nước trực giác sâu sắc và đất phong phú, nữ hoàng cảm xúc nảy nở trong môi trường sung mãn nơi bà có thể chăm sóc từ nền tảng dư dả.", en: "Queen of Cups and Nine of Pentacles: empathy meets abundance — deeply intuitive water and prosperous earth, the emotional queen flourishing in an environment of plenty where she can care from a foundation of sufficiency." },
  "48_73": { vi: "Nữ Hoàng Cốc và Mười Tiền: sự thấu cảm gặp sự viên mãn gia đình — nước trực giác sâu sắc và đất di sản, nữ hoàng cảm xúc là trái tim của gia đình, giữ gìn di sản tình cảm qua nhiều thế hệ.", en: "Queen of Cups and Ten of Pentacles: empathy meets family completion — deeply intuitive water and legacy earth, the emotional queen being the heart of the family, preserving emotional heritage across generations." },
  "48_74": { vi: "Nữ Hoàng Cốc và Trang Bị Tiền: sự thấu cảm hướng dẫn trí tuệ trẻ — nước trực giác sâu sắc và đất non nớt tò mò, nữ hoàng chỉ dẫn trang bị tiền cách học hỏi với cả trái tim lẫn trí tuệ.", en: "Queen of Cups and Page of Pentacles: empathy guiding young practical intellect — deeply intuitive water and young curious earth, the queen guiding the page to learn with both heart and intellect together." },
  "48_75": { vi: "Nữ Hoàng Cốc và Kỵ Sĩ Tiền: sự thấu cảm gặp sự kiên trì — nước trực giác sâu sắc và đất bền bỉ, nữ hoàng cảm xúc và kỵ sĩ tiền bổ sung cho nhau: trái tim và trách nhiệm cùng hỗ trợ.", en: "Queen of Cups and Knight of Pentacles: empathy meets perseverance — deeply intuitive water and persistent earth, the emotional queen and earth knight complementing each other: heart and responsibility mutually supporting." },
  "48_76": { vi: "Nữ Hoàng Cốc và Nữ Hoàng Tiền: hai nữ hoàng gặp nhau — nước trực giác sâu sắc và đất thực tế ân cần, hai dạng chăm sóc tối cao gặp nhau: chăm sóc cảm xúc và chăm sóc vật chất cùng bổ sung.", en: "Queen of Cups and Queen of Pentacles: two queens meeting — deeply intuitive water and practically nurturing earth, two supreme forms of care meeting: emotional nurturing and material nurturing complementing each other." },
  "48_77": { vi: "Nữ Hoàng Cốc và Vua Tiền: sự thấu cảm gặp quyền uy vật chất — nước trực giác sâu sắc và vua đất uy quyền, hai nguyên lý quyền uy gặp nhau: tình cảm và vật chất đối thoại bình đẳng.", en: "Queen of Cups and King of Pentacles: empathy meets material authority — deeply intuitive water and authoritative earth king, two principles of authority meeting: emotional and material in equal dialogue." },
  "49_64": { vi: "Vua Cốc và Át Tiền: bậc thầy cảm xúc gặp khởi đầu thịnh vượng — nước cảm xúc làm chủ đón nhận mầm đất mới, trí tuệ cảm xúc chín muồi nhận ra và nắm bắt cơ hội vật chất đúng thời điểm.", en: "King of Cups and Ace of Pentacles: emotional mastery meets prosperous beginning — masterful emotional water receiving the new earth seed, mature emotional wisdom recognizing and seizing material opportunity at the right moment." },
  "49_65": { vi: "Vua Cốc và Hai Tiền: bậc thầy cảm xúc gặp sự cân bằng thực tế — nước cảm xúc làm chủ và đất xoay sở, vua cốc cân bằng giữa lãnh đạo cảm xúc và đòi hỏi thực tế với sự chín chắn.", en: "King of Cups and Two of Pentacles: emotional mastery meets practical balance — masterful emotional water and juggling earth, the king balancing emotional leadership and practical demands with seasoned maturity." },
  "49_66": { vi: "Vua Cốc và Ba Tiền: bậc thầy cảm xúc gặp hợp tác — nước cảm xúc làm chủ và đất làm việc nhóm, vua cốc tạo ra môi trường cảm xúc an toàn để mọi người hợp tác và phát huy tối đa năng lực.", en: "King of Cups and Three of Pentacles: emotional mastery meets collaboration — masterful emotional water and teamwork earth, the king creating emotionally safe environment for everyone to collaborate and reach full potential." },
  "49_67": { vi: "Vua Cốc và Bốn Tiền: bậc thầy cảm xúc gặp sự tích trữ — nước cảm xúc làm chủ và đất giữ chặt, vua cốc nhận ra sự bám víu vật chất thường che giấu nỗi bất an cảm xúc sâu bên trong.", en: "King of Cups and Four of Pentacles: emotional mastery meets hoarding — masterful emotional water and clinging earth, the king perceiving that material clinging often conceals deep emotional insecurity within." },
  "49_68": { vi: "Vua Cốc và Năm Tiền: bậc thầy cảm xúc trong hoàn cảnh thiếu thốn — nước cảm xúc làm chủ và đất khan hiếm, vua cốc duy trì sự bình tĩnh và ổn định cảm xúc ngay cả trong những thời điểm vật chất khó khăn.", en: "King of Cups and Five of Pentacles: emotional mastery in scarcity — masterful emotional water and scarce earth, the king maintaining calm and emotional stability even during the most materially difficult periods." },
  "49_69": { vi: "Vua Cốc và Sáu Tiền: bậc thầy cảm xúc gặp sự hào phóng — nước cảm xúc làm chủ và đất chia sẻ, vua cốc cho đi từ nơi sung mãn nội tâm, sự hào phóng của ông xuất phát từ sức mạnh chứ không từ nợ nần.", en: "King of Cups and Six of Pentacles: emotional mastery meets generosity — masterful emotional water and sharing earth, the king giving from inner abundance, his generosity coming from strength rather than obligation." },
  "49_70": { vi: "Vua Cốc và Bảy Tiền: bậc thầy cảm xúc gặp sự kiên nhẫn — nước cảm xúc làm chủ và đất chờ đợi, vua cốc kiên nhẫn với kết quả lâu dài bằng sự bình thản của người đã hiểu quy luật thời gian.", en: "King of Cups and Seven of Pentacles: emotional mastery meets patience — masterful emotional water and waiting earth, the king patient with long-term results with the composure of one who understands the laws of time." },
  "49_71": { vi: "Vua Cốc và Tám Tiền: bậc thầy cảm xúc gặp sự cần cù — nước cảm xúc làm chủ và đất siêng năng, vua cốc trân trọng sự cần cù thực tế như một biểu hiện của sự tôn trọng và trách nhiệm sâu sắc.", en: "King of Cups and Eight of Pentacles: emotional mastery meets diligence — masterful emotional water and industrious earth, the king valuing practical diligence as an expression of deep respect and profound responsibility." },
  "49_72": { vi: "Vua Cốc và Chín Tiền: bậc thầy cảm xúc gặp sự sung túc — nước cảm xúc làm chủ và đất phong phú, vua cốc nảy nở trong môi trường sung mãn, từ đó lãnh đạo với trái tim rộng mở và bình thản.", en: "King of Cups and Nine of Pentacles: emotional mastery meets abundance — masterful emotional water and prosperous earth, the king flourishing in an environment of plenty, leading from that place with open heart and equanimity." },
  "49_73": { vi: "Vua Cốc và Mười Tiền: bậc thầy cảm xúc gặp sự viên mãn gia đình — nước cảm xúc làm chủ và đất di sản, vua cốc là người gìn giữ di sản tình cảm của gia đình qua nhiều thế hệ.", en: "King of Cups and Ten of Pentacles: emotional mastery meets family completion — masterful emotional water and legacy earth, the king being the keeper of the family's emotional heritage across many generations." },
  "49_74": { vi: "Vua Cốc và Trang Bị Tiền: bậc thầy cảm xúc hướng dẫn trí tuệ trẻ — nước cảm xúc làm chủ và đất non nớt tò mò, vua cốc truyền dạy trang bị tiền rằng sự khôn ngoan thực sự kết hợp cả tim lẫn óc.", en: "King of Cups and Page of Pentacles: emotional mastery guiding young practical intellect — masterful emotional water and young curious earth, the king teaching the page that true wisdom combines both heart and mind." },
  "49_75": { vi: "Vua Cốc và Kỵ Sĩ Tiền: bậc thầy cảm xúc gặp tinh thần kiên trì — nước cảm xúc làm chủ và đất bền bỉ, vua cốc và kỵ sĩ tiền thể hiện hai loại sức mạnh bổ sung: chiều sâu cảm xúc và bền bỉ thực tế.", en: "King of Cups and Knight of Pentacles: emotional mastery meets steady perseverance — masterful emotional water and persistent earth, the king and knight embodying two complementary strengths: emotional depth and practical persistence." },
  "49_76": { vi: "Vua Cốc và Nữ Hoàng Tiền: bậc thầy cảm xúc gặp sự chăm sóc thực tế — nước cảm xúc làm chủ và đất thực tế ân cần, hai vị vua và nữ hoàng bổ sung cho nhau: trái tim và bàn tay thực tế cùng lãnh đạo.", en: "King of Cups and Queen of Pentacles: emotional mastery meets practical nurturing — masterful emotional water and practically nurturing earth, king and queen complementing each other: heart and practical hands leading together." },
  "49_77": { vi: "Vua Cốc và Vua Tiền: hai vị vua gặp nhau — nước cảm xúc làm chủ và đất vật chất quyền uy, trái tim và tài sản ở đỉnh cao cùng đối thoại, tìm kiếm sự cân bằng giữa sung mãn nội tâm và ngoại cảnh.", en: "King of Cups and King of Pentacles: two kings meeting — masterful emotional water and materially authoritative earth, heart and wealth at their peaks in dialogue, seeking balance between inner and outer abundance." },
  // ── Tier 5f-1: Swords × Pentacles, air×earth (Swords 50–56 × Pentacles 64–77, 98 pairs) ──
  "50_64": { vi: "Át Kiếm và Át Tiền: hai khởi đầu hội tụ — lưỡi kiếm tư duy sắc bén gặp hạt giống vật chất màu mỡ, một ý tưởng rõ ràng chạm đến cơ hội thực tế, tư duy và hành động cùng nở rộ.", en: "Ace of Swords and Ace of Pentacles: two beginnings converge — sharp mental clarity meets fertile material seed, a clear idea touching real opportunity, thought and action blooming together." },
  "50_65": { vi: "Át Kiếm và Hai Tiền: sự thật sắc bén gặp thế cân bằng linh hoạt — tâm trí rõ ràng giúp điều phối nhiều nguồn lực, một quyết định dứt khoát có thể phá vỡ thế tung hứng vật chất.", en: "Ace of Swords and Two of Pentacles: sharp truth meets flexible balance — clear thinking helps coordinate multiple resources, a decisive cut resolving the juggle of material demands." },
  "50_66": { vi: "Át Kiếm và Ba Tiền: ý tưởng đột phá gặp sự hợp tác thủ công — tư duy sắc bén định hướng công việc nhóm, sự rõ ràng về mục tiêu giúp kỹ năng tập thể phát huy tối đa.", en: "Ace of Swords and Three of Pentacles: breakthrough idea meets collaborative craft — sharp vision directing teamwork, clarity of purpose allowing collective skill to reach its full potential." },
  "50_67": { vi: "Át Kiếm và Bốn Tiền: tư duy sắc bén thách thức sự kiểm soát vật chất — lưỡi kiếm sự thật có thể cắt đứt sự bám víu, ý tưởng mới phá vỡ thói quen tích lũy và phòng thủ.", en: "Ace of Swords and Four of Pentacles: sharp thinking challenging material control — the sword of truth cutting through possessiveness, new ideas breaking patterns of hoarding and defensiveness." },
  "50_68": { vi: "Át Kiếm và Năm Tiền: sự rõ ràng tư duy giữa khó khăn vật chất — lưỡi kiếm chân lý chiếu sáng con đường thoát khỏi thiếu thốn, nhận ra vấn đề là bước đầu tiên để vượt qua nó.", en: "Ace of Swords and Five of Pentacles: mental clarity amid material hardship — the sword of truth illuminating a path through lack, naming the problem as the first step toward overcoming it." },
  "50_69": { vi: "Át Kiếm và Sáu Tiền: sự thật sắc bén gặp sự hào phóng công bằng — tư duy rõ ràng đảm bảo nguồn lực được phân phối công bằng, trí tuệ hướng dẫn lòng từ thiện đúng chỗ.", en: "Ace of Swords and Six of Pentacles: sharp truth meeting generous equity — clear thinking ensuring resources are distributed fairly, intellect guiding charity to where it is most needed." },
  "50_70": { vi: "Át Kiếm và Bảy Tiền: ý tưởng đột phá gặp sự kiên nhẫn đánh giá — tư duy sắc bén giúp đánh giá khách quan thành quả đang lớn dần, trí tuệ và thời gian cùng nhau định hình tương lai.", en: "Ace of Swords and Seven of Pentacles: breakthrough idea meeting patient assessment — sharp thinking enabling objective review of growing results, intellect and time together shaping the future." },
  "50_71": { vi: "Át Kiếm và Tám Tiền: tư duy sắc bén gặp sự chuyên cần rèn luyện — ý tưởng rõ ràng định hướng thực hành kỹ năng, trí tuệ và lao động kết hợp tạo nên sự thành thạo thực sự.", en: "Ace of Swords and Eight of Pentacles: sharp thinking meeting diligent practice — clear ideas directing skill-building, intellect and labor combined creating genuine mastery." },
  "50_72": { vi: "Át Kiếm và Chín Tiền: sự rõ ràng tư duy gặp sự độc lập sung mãn — trí tuệ sắc bén củng cố thành quả cá nhân, nhận thức rõ ràng về giá trị bản thân nuôi dưỡng sự tự chủ.", en: "Ace of Swords and Nine of Pentacles: mental clarity meeting abundant independence — sharp intellect reinforcing personal achievement, clear self-awareness nourishing true autonomy." },
  "50_73": { vi: "Át Kiếm và Mười Tiền: tư duy đột phá gặp di sản viên mãn — ý tưởng sắc bén tạo nền tảng cho sự giàu có lâu dài, trí tuệ được truyền đạt cùng tài sản qua các thế hệ.", en: "Ace of Swords and Ten of Pentacles: breakthrough thinking meeting lasting legacy — sharp ideas creating foundations for enduring wealth, intellect passed down alongside assets through generations." },
  "50_74": { vi: "Át Kiếm và Trang Bị Tiền: ý tưởng rõ ràng gặp người học trò tò mò vật chất — tư duy sắc bén khai sáng con đường nghiên cứu thực tiễn, lý thuyết gặp đam mê học hỏi cụ thể.", en: "Ace of Swords and Page of Pentacles: clear ideas meeting the materially curious student — sharp thinking illuminating a path of practical study, theory meeting the passion for tangible learning." },
  "50_75": { vi: "Át Kiếm và Kỵ Sĩ Tiền: tư duy sắc bén gặp sự kiên định vật chất — ý tưởng rõ ràng tiếp sức cho hành trình chậm mà chắc, trí tuệ định hướng sự bền bỉ đến đích.", en: "Ace of Swords and Knight of Pentacles: sharp thinking meeting steady material purpose — clear ideas fueling the slow but certain journey, intellect directing steadfast endurance toward the goal." },
  "50_76": { vi: "Át Kiếm và Nữ Hoàng Tiền: sự rõ ràng tư duy gặp sự chăm sóc thực tế — trí tuệ sắc bén hỗ trợ sự nuôi dưỡng vật chất, ý tưởng khôn ngoan chuyển hóa thành môi trường sống sung túc.", en: "Ace of Swords and Queen of Pentacles: mental clarity meeting practical nurturing — sharp intellect supporting material care-giving, wise ideas translating into a thriving and abundant environment." },
  "50_77": { vi: "Át Kiếm và Vua Tiền: tư duy đột phá gặp quyền uy vật chất — ý tưởng sắc bén phục vụ quyết sách kinh doanh khôn ngoan, trí tuệ và tài sản kết hợp tạo nên quyền lực thực sự.", en: "Ace of Swords and King of Pentacles: breakthrough thinking meeting material authority — sharp ideas serving wise business decisions, intellect and wealth combined creating genuine power." },
  "51_64": { vi: "Hai Kiếm và Át Tiền: thế bế tắc tâm trí gặp cơ hội vật chất mới — sự do dự quyết định có thể bỏ lỡ hạt giống màu mỡ, thoát khỏi thế giằng co để nắm lấy tiềm năng thực tế.", en: "Two of Swords and Ace of Pentacles: mental stalemate meeting a new material opportunity — indecision risking the loss of a fertile seed, breaking free from deadlock to grasp real potential." },
  "51_65": { vi: "Hai Kiếm và Hai Tiền: hai thế cân bằng song hành — tâm trí bị kẹt giữa hai lựa chọn trong khi tay phải tung hứng nguồn lực, căng thẳng kép cần sự linh hoạt để giải thoát.", en: "Two of Swords and Two of Pentacles: twin balancing acts running together — mind stuck between two choices while hands juggle resources, dual tension requiring flexibility to break free." },
  "51_66": { vi: "Hai Kiếm và Ba Tiền: sự do dự quyết định gặp tinh thần đồng đội — tập thể có thể giúp phá vỡ thế bế tắc nội tâm, chia sẻ quan điểm nhóm soi sáng con đường bị che khuất.", en: "Two of Swords and Three of Pentacles: indecision meeting collaborative spirit — the team's perspectives helping to break the inner stalemate, shared viewpoints illuminating the obscured path forward." },
  "51_67": { vi: "Hai Kiếm và Bốn Tiền: tâm trí bị kẹt gặp sự bám víu vật chất — cả hai đều từ chối buông bỏ, sợ hãi và kiểm soát tạo nên bức tường kép ngăn cản sự phát triển.", en: "Two of Swords and Four of Pentacles: stuck mind meeting material clinging — both refusing to let go, fear and control building a double wall that blocks growth and forward movement." },
  "51_68": { vi: "Hai Kiếm và Năm Tiền: thế bế tắc tâm trí giữa khó khăn vật chất — không thể quyết định khi đang thiếu thốn làm tình trạng tồi tệ thêm, cần dũng cảm nhìn nhận sự thật và hành động.", en: "Two of Swords and Five of Pentacles: mental deadlock amid material hardship — inability to decide while lacking resources compounds suffering, courage to face truth and act becoming essential." },
  "51_69": { vi: "Hai Kiếm và Sáu Tiền: sự do dự gặp sự hào phóng — quyết định cho hay nhận có thể phá vỡ thế giằng co, lòng tốt của người khác hoặc việc trao đi giúp tâm trí thoát khỏi vòng lặp.", en: "Two of Swords and Six of Pentacles: indecision meeting generosity — choosing to give or receive breaking the mental standoff, others' kindness or an act of giving unlocking the mind's loop." },
  "51_70": { vi: "Hai Kiếm và Bảy Tiền: tâm trí do dự gặp sự chờ đợi kiên nhẫn — cả hai đều ở trong giai đoạn tạm nghỉ, nhưng đất đang làm việc trong khi tâm trí đứng yên, thời gian sẽ ép buộc quyết định.", en: "Two of Swords and Seven of Pentacles: hesitant mind meeting patient waiting — both paused, but earth quietly working while mind stands still, time eventually forcing the needed decision." },
  "51_71": { vi: "Hai Kiếm và Tám Tiền: sự bế tắc quyết định gặp sự chuyên tâm làm việc — hành động thực hành có thể phá vỡ vòng lặp tư duy, đặt tay vào công việc giải phóng tâm trí khỏi thế giằng co.", en: "Two of Swords and Eight of Pentacles: decision deadlock meeting focused work — practical action breaking the mental loop, putting hands to work liberating the mind from its standoff." },
  "51_72": { vi: "Hai Kiếm và Chín Tiền: tâm trí bị kẹt gặp sự sung mãn tự chủ — sự độc lập vật chất đã đạt được có thể giúp can đảm đối mặt với quyết định khó khăn, an toàn bên ngoài hỗ trợ can đảm bên trong.", en: "Two of Swords and Nine of Pentacles: stuck mind meeting self-sufficient abundance — achieved material independence lending courage to face the difficult decision, outer security supporting inner bravery." },
  "51_73": { vi: "Hai Kiếm và Mười Tiền: sự do dự cá nhân gặp di sản gia đình — áp lực tập thể hoặc trách nhiệm truyền thống có thể phá vỡ hoặc củng cố thế bế tắc, gia đình vừa là gánh nặng vừa là neo đậu.", en: "Two of Swords and Ten of Pentacles: personal indecision meeting family legacy — collective pressure or traditional duty breaking or reinforcing the stalemate, family both a burden and an anchor." },
  "51_74": { vi: "Hai Kiếm và Trang Bị Tiền: tâm trí do dự gặp sự tò mò học hỏi — tìm kiếm thêm thông tin thực tế có thể phá vỡ bế tắc, sự ham hiểu biết của người mới bắt đầu thắp sáng con đường quyết định.", en: "Two of Swords and Page of Pentacles: hesitant mind meeting curious learning — seeking more practical information breaking the deadlock, the beginner's eagerness to understand lighting the path to decision." },
  "51_75": { vi: "Hai Kiếm và Kỵ Sĩ Tiền: tâm trí bế tắc gặp sự kiên định chậm rãi — đôi khi sự bền bỉ có phương pháp là câu trả lời, từng bước một vượt qua sự do dự thay vì chờ đợi quyết định hoàn hảo.", en: "Two of Swords and Knight of Pentacles: deadlocked mind meeting methodical steadiness — sometimes methodical persistence is the answer, moving step by step past indecision rather than waiting for perfect clarity." },
  "51_76": { vi: "Hai Kiếm và Nữ Hoàng Tiền: sự do dự tâm trí gặp sự chăm sóc thực tế — trí tuệ nuôi dưỡng của Nữ Hoàng có thể tạo không gian an toàn để quyết định chín muồi, sự ấm áp vật chất hóa giải căng thẳng.", en: "Two of Swords and Queen of Pentacles: mental hesitation meeting practical nurturing — the Queen's grounded wisdom creating safe space for decisions to ripen, material warmth dissolving inner tension." },
  "51_77": { vi: "Hai Kiếm và Vua Tiền: tâm trí giằng co gặp quyền uy vật chất vững chắc — sự ổn định tài chính có thể trao tự do để quyết định không vì sợ hãi, thực lực là nền tảng cho sự can đảm tư duy.", en: "Two of Swords and King of Pentacles: torn mind meeting solid material authority — financial stability lending freedom to decide without fear, real-world strength as foundation for mental courage." },
  "52_64": { vi: "Ba Kiếm và Át Tiền: nỗi đau tâm trí gặp cơ hội vật chất mới — sự mất mát có thể mở ra cánh cửa mới, hạt giống tiềm năng thực tế nảy mầm ngay giữa vết thương chưa lành.", en: "Three of Swords and Ace of Pentacles: heartbreak meeting a new material opportunity — loss sometimes opening unexpected doors, the seed of practical potential sprouting amid wounds not yet healed." },
  "52_65": { vi: "Ba Kiếm và Hai Tiền: nỗi đau lòng gặp thế cân bằng linh hoạt — phải tung hứng cuộc sống bên ngoài trong khi bên trong đang vỡ vụn, sự thích nghi vật chất đỡ đần khi cảm xúc chưa hồi phục.", en: "Three of Swords and Two of Pentacles: heartbreak meeting flexible balance — juggling outer life while inner world crumbles, practical adaptability providing support while emotions haven't yet healed." },
  "52_66": { vi: "Ba Kiếm và Ba Tiền: đau khổ tâm trí gặp sự hợp tác — chia sẻ nỗi đau với nhóm hoặc cộng đồng hỗ trợ chữa lành, sự thừa nhận tập thể biến nỗi buồn riêng tư thành sức mạnh chung.", en: "Three of Swords and Three of Pentacles: mental anguish meeting collaboration — sharing grief with a supportive group aiding healing, collective acknowledgment transforming private sorrow into shared strength." },
  "52_67": { vi: "Ba Kiếm và Bốn Tiền: nỗi đau lòng gặp sự ôm giữ chặt — bám víu vật chất như cơ chế chống đỡ cảm xúc, kiểm soát nguồn lực bên ngoài bù đắp cho cảm giác mất kiểm soát bên trong.", en: "Three of Swords and Four of Pentacles: heartbreak meeting material clinging — gripping possessions as an emotional coping mechanism, controlling outer resources compensating for lost control within." },
  "52_68": { vi: "Ba Kiếm và Năm Tiền: đau khổ kép — nỗi đau tâm trí và thiếu thốn vật chất cùng lúc, cảm giác bị bỏ rơi cả bên trong lẫn bên ngoài, tìm sự ấm áp và nơi trú ẩn giữa bão giông.", en: "Three of Swords and Five of Pentacles: compound suffering — mental heartbreak and material deprivation arriving together, feeling abandoned both within and without, seeking warmth and shelter amid the storm." },
  "52_69": { vi: "Ba Kiếm và Sáu Tiền: nỗi đau gặp lòng hào phóng — sự giúp đỡ vật chất không thể chữa lành vết thương tâm trí nhưng giảm bớt gánh nặng, được nhận lòng tốt trong lúc đau khổ là ân huệ quý giá.", en: "Three of Swords and Six of Pentacles: heartbreak meeting generosity — material help unable to heal the mental wound but easing the burden, receiving kindness during suffering a precious grace." },
  "52_70": { vi: "Ba Kiếm và Bảy Tiền: đau khổ gặp sự chờ đợi đánh giá — thời gian là liều thuốc chữa lành nỗi đau, kiên nhẫn nhìn nhận tổn thương như giai đoạn cần thiết trước khi thu hoạch sự bình yên.", en: "Three of Swords and Seven of Pentacles: sorrow meeting patient assessment — time as medicine for grief, patiently viewing the wound as a necessary stage before harvesting peace and wisdom." },
  "52_71": { vi: "Ba Kiếm và Tám Tiền: nỗi đau lòng gặp sự chuyên cần — đặt mình vào công việc như liệu pháp chữa lành, rèn kỹ năng và xây dựng điều gì đó cụ thể giúp tâm trí thoát khỏi vòng xoáy đau khổ.", en: "Three of Swords and Eight of Pentacles: heartbreak meeting diligence — immersing in work as healing therapy, building skills and creating something tangible helping the mind escape the spiral of grief." },
  "52_72": { vi: "Ba Kiếm và Chín Tiền: đau khổ gặp sự sung mãn tự chủ — sự độc lập vật chất đã xây dựng trước kia là nền tảng vững chắc khi trái tim tan vỡ, tự cung tự cấp là áo giáp trong giai đoạn hồi phục.", en: "Three of Swords and Nine of Pentacles: sorrow meeting self-sufficient abundance — material independence built earlier providing firm foundation when heartbreak arrives, self-sufficiency as armor during recovery." },
  "52_73": { vi: "Ba Kiếm và Mười Tiền: nỗi đau cá nhân gặp di sản gia đình — mất mát tình cảm trong bối cảnh ổn định gia đình, tập thể và truyền thống đóng vai trò chỗ dựa khi cá nhân đang chữa lành.", en: "Three of Swords and Ten of Pentacles: personal grief meeting family legacy — emotional loss within stable family context, collective and tradition serving as support structure while the individual heals." },
  "52_74": { vi: "Ba Kiếm và Trang Bị Tiền: nỗi đau tâm trí gặp sự học hỏi thực tiễn — khám phá kỹ năng hoặc sở thích mới như con đường chữa lành, biến nỗi đau thành bài học về những gì thực sự có giá trị.", en: "Three of Swords and Page of Pentacles: mental pain meeting practical learning — exploring new skills or interests as a healing path, transforming grief into lessons about what truly holds value." },
  "52_75": { vi: "Ba Kiếm và Kỵ Sĩ Tiền: đau khổ gặp sự bền bỉ có phương pháp — chữa lành không xảy ra trong một đêm, sự kiên định từng bước qua nỗi đau là cách duy nhất đến bờ bên kia.", en: "Three of Swords and Knight of Pentacles: sorrow meeting methodical persistence — healing doesn't happen overnight, steady step-by-step movement through grief being the only true path to the other side." },
  "52_76": { vi: "Ba Kiếm và Nữ Hoàng Tiền: nỗi đau lòng gặp sự chăm sóc nuôi dưỡng — sự ấm áp và thực tế của Nữ Hoàng bao bọc vết thương tâm trí, chăm sóc cơ thể và môi trường là cách chữa lành tâm hồn.", en: "Three of Swords and Queen of Pentacles: heartbreak meeting nurturing care — the Queen's warmth and practicality wrapping around the mental wound, tending body and environment as the path to healing the soul." },
  "52_77": { vi: "Ba Kiếm và Vua Tiền: nỗi đau tâm trí gặp quyền uy vật chất — sự ổn định tài chính không xóa được đau khổ nhưng tạo không gian an toàn để hồi phục, thực lực là nền tảng khi cảm xúc sụp đổ.", en: "Three of Swords and King of Pentacles: mental anguish meeting material authority — financial stability unable to erase grief but creating safe space to recover, real-world strength as foundation when emotions collapse." },
  "53_64": { vi: "Bốn Kiếm và Át Tiền: sự nghỉ ngơi tĩnh lặng gặp cơ hội mới — giai đoạn thu mình chuẩn bị năng lượng cho khởi đầu vật chất, sự tĩnh lặng là bước đệm để nắm bắt tiềm năng đang chờ.", en: "Four of Swords and Ace of Pentacles: quiet rest meeting new opportunity — the withdrawal period preparing energy for a material beginning, stillness as the runway for grasping waiting potential." },
  "53_65": { vi: "Bốn Kiếm và Hai Tiền: sự nghỉ ngơi phục hồi gặp thế cân bằng linh hoạt — tạm dừng để tái tổ chức trước khi tiếp tục tung hứng, sự nghỉ ngơi chiến lược giúp duy trì thăng bằng dài hạn.", en: "Four of Swords and Two of Pentacles: restorative rest meeting flexible balance — pausing to reorganize before resuming the juggle, strategic retreat enabling sustainable long-term equilibrium." },
  "53_66": { vi: "Bốn Kiếm và Ba Tiền: sự rút lui cá nhân gặp tinh thần đồng đội — nghỉ ngơi để phục hồi trước khi quay trở lại đóng góp cho nhóm, sự ổn định nội tâm làm nền tảng cho sự hợp tác hiệu quả.", en: "Four of Swords and Three of Pentacles: personal retreat meeting collaborative spirit — resting to restore before returning to contribute to the team, inner stability as foundation for effective collaboration." },
  "53_67": { vi: "Bốn Kiếm và Bốn Tiền: sự kiểm soát kép — tâm trí nghỉ ngơi và tài sản được giữ chặt, hai thứ giữ nguyên trạng có thể tạo ra sự an toàn nhưng cũng cản trở sự phát triển và luân chuyển.", en: "Four of Swords and Four of Pentacles: dual holding — resting mind and tightly held assets, two things kept in place creating safety but also blocking growth and healthy circulation." },
  "53_68": { vi: "Bốn Kiếm và Năm Tiền: sự nghỉ ngơi phục hồi giữa khó khăn vật chất — đôi khi rút lui tạm thời là cần thiết để tồn tại qua giai đoạn thiếu thốn, nghỉ ngơi là hành động khôn ngoan không phải yếu đuối.", en: "Four of Swords and Five of Pentacles: restorative rest amid material hardship — sometimes temporary withdrawal is necessary to survive scarcity, rest as wise action rather than weakness." },
  "53_69": { vi: "Bốn Kiếm và Sáu Tiền: sự tĩnh lặng gặp sự trao đổi hào phóng — nghỉ ngơi trước khi cho đi hoặc nhận lấy, thời gian hồi phục là điều kiện để sự hào phóng có thể tiếp tục bền vững.", en: "Four of Swords and Six of Pentacles: stillness meeting generous exchange — resting before giving or receiving, recovery time as the condition allowing generosity to continue sustainably." },
  "53_70": { vi: "Bốn Kiếm và Bảy Tiền: sự nghỉ ngơi gặp sự chờ đợi đánh giá — cả hai đều ở trong trạng thái tạm dừng có chủ đích, để đất và tâm trí cùng tích lũy sức mạnh cho giai đoạn tiếp theo.", en: "Four of Swords and Seven of Pentacles: rest meeting patient assessment — both held in purposeful pause, earth and mind gathering strength together in preparation for the next stage of growth." },
  "53_71": { vi: "Bốn Kiếm và Tám Tiền: sự nghỉ ngơi cần thiết gặp sự chăm chỉ liên tục — cân bằng giữa phục hồi và năng suất, nhận ra rằng nghỉ ngơi đúng lúc là một phần của quá trình hoàn thiện kỹ năng.", en: "Four of Swords and Eight of Pentacles: necessary rest meeting continuous diligence — balancing recovery with productivity, recognizing that timely rest is itself part of the skill-mastery process." },
  "53_72": { vi: "Bốn Kiếm và Chín Tiền: sự tĩnh lặng phục hồi gặp sự sung mãn tự chủ — nghỉ ngơi trong môi trường giàu có và bình yên, sự thịnh vượng tạo ra không gian để phục hồi trọn vẹn.", en: "Four of Swords and Nine of Pentacles: restorative stillness meeting self-sufficient abundance — resting within a prosperous and peaceful environment, material wealth creating the space for complete renewal." },
  "53_73": { vi: "Bốn Kiếm và Mười Tiền: sự nghỉ ngơi cá nhân gặp di sản bền vững — gia đình và truyền thống tạo ra bối cảnh an toàn để nghỉ ngơi và tái sinh, nền tảng tập thể hỗ trợ quá trình hồi phục cá nhân.", en: "Four of Swords and Ten of Pentacles: individual rest meeting enduring legacy — family and tradition creating safe context for rest and renewal, collective foundation supporting personal recovery." },
  "53_74": { vi: "Bốn Kiếm và Trang Bị Tiền: sự tĩnh lặng phục hồi gặp sự học hỏi tò mò — nghỉ ngơi trước khi bắt đầu nghiên cứu mới, giai đoạn tĩnh lặng tích lũy sức sống cho cuộc khám phá thực tiễn tiếp theo.", en: "Four of Swords and Page of Pentacles: restorative stillness meeting curious learning — resting before beginning new study, the quiet phase accumulating vitality for the next practical exploration." },
  "53_75": { vi: "Bốn Kiếm và Kỵ Sĩ Tiền: sự nghỉ ngơi chiến lược gặp sự bền bỉ phương pháp — biết khi nào dừng lại để tiếp tục mạnh mẽ hơn, sự kiên định thực sự bao gồm cả nghỉ ngơi đúng lúc chứ không chỉ tiến bước không ngừng.", en: "Four of Swords and Knight of Pentacles: strategic rest meeting methodical persistence — knowing when to pause in order to continue stronger, true endurance including timely rest not just relentless forward motion." },
  "53_76": { vi: "Bốn Kiếm và Nữ Hoàng Tiền: sự tĩnh lặng phục hồi gặp sự chăm sóc thực tế — Nữ Hoàng tạo ra môi trường ấm áp để nghỉ ngơi và hồi phục, sự nuôi dưỡng vật chất chữa lành tâm trí mệt mỏi.", en: "Four of Swords and Queen of Pentacles: restorative stillness meeting practical care — the Queen creating a warm environment for rest and recovery, material nurturing healing the weary mind." },
  "53_77": { vi: "Bốn Kiếm và Vua Tiền: sự nghỉ ngơi tĩnh lặng gặp quyền uy vật chất — người lãnh đạo thực sự biết khi nào cần rút lui để tái tập trung, sức mạnh thực lực cho phép dừng lại mà không mất quyền kiểm soát.", en: "Four of Swords and King of Pentacles: quiet rest meeting material authority — a true leader knowing when to withdraw to refocus, real-world strength allowing pause without losing control." },
  "54_64": { vi: "Năm Kiếm và Át Tiền: chiến thắng rỗng tuếch gặp cơ hội mới — chiến thắng bằng sự xung đột để lại vết thương, liệu hạt giống vật chất mới có đủ sức chữa lành những gì đã mất trong cuộc chiến?", en: "Five of Swords and Ace of Pentacles: hollow victory meeting new opportunity — winning through conflict leaving wounds, whether the new material seed is strong enough to heal what was lost in the fight." },
  "54_65": { vi: "Năm Kiếm và Hai Tiền: xung đột gặp thế cân bằng mong manh — cuộc chiến làm mất đi sự thăng bằng, cần linh hoạt thích nghi sau tổn thất để tái lập thế cân bằng trong nguồn lực và mối quan hệ.", en: "Five of Swords and Two of Pentacles: conflict meeting fragile balance — fighting upsetting the equilibrium, needing flexible adaptation after loss to restore balance in resources and relationships." },
  "54_66": { vi: "Năm Kiếm và Ba Tiền: xung đột phá vỡ tinh thần đồng đội — sự cạnh tranh hoặc tham vọng cá nhân làm suy yếu nỗ lực tập thể, cần xây dựng lại lòng tin để tinh thần hợp tác hồi sinh.", en: "Five of Swords and Three of Pentacles: conflict fracturing team spirit — competition or individual ambition weakening collective effort, rebuilding trust necessary for collaborative spirit to revive." },
  "54_67": { vi: "Năm Kiếm và Bốn Tiền: chiến thắng bằng sức mạnh gặp sự kiểm soát vật chất — bảo vệ tài sản bằng mọi giá có thể dẫn đến xung đột phá hoại, giữ chặt quá mức tạo ra kẻ thù không cần thiết.", en: "Five of Swords and Four of Pentacles: won-by-force meeting material control — protecting assets at all costs risking destructive conflict, hoarding too tightly creating unnecessary enemies." },
  "54_68": { vi: "Năm Kiếm và Năm Tiền: xung đột kép — thua trận trong tâm trí và thiếu thốn vật chất cùng lúc, cảm giác thất bại toàn diện cần được thừa nhận trước khi có thể tìm thấy con đường vươn lên.", en: "Five of Swords and Five of Pentacles: compound loss — defeat in mind and material deprivation arriving together, the feeling of total failure needing acknowledgment before any path upward can be found." },
  "54_69": { vi: "Năm Kiếm và Sáu Tiền: chiến thắng gây tổn thất gặp sự hào phóng — việc trao đi sau chiến thắng có thể giảm nhẹ tổn hại, lòng hào phóng là cách chuộc lỗi sau khi hành xử thiếu danh dự.", en: "Five of Swords and Six of Pentacles: damaging victory meeting generosity — giving after winning potentially mitigating harm, generosity as a path to redemption after behaving dishonorably." },
  "54_70": { vi: "Năm Kiếm và Bảy Tiền: xung đột gặp sự đánh giá kiên nhẫn — nhìn lại hậu quả của cuộc chiến một cách trung thực, thời gian để nhận ra cái giá của chiến thắng và quyết định có tiếp tục con đường này không.", en: "Five of Swords and Seven of Pentacles: conflict meeting patient assessment — honestly reviewing the aftermath of the fight, time to recognize the true cost of the victory and decide whether to continue this path." },
  "54_71": { vi: "Năm Kiếm và Tám Tiền: xung đột cạnh tranh gặp sự rèn luyện kỹ năng — cuộc chiến thúc đẩy nâng cao năng lực, sự cạnh tranh lành mạnh có thể trở thành động lực rèn giũa kỹ năng thực sự.", en: "Five of Swords and Eight of Pentacles: competitive conflict meeting skill-building — the fight driving capability improvement, healthy competition potentially becoming the motivation to genuinely hone skills." },
  "54_72": { vi: "Năm Kiếm và Chín Tiền: xung đột gặp sự sung mãn tự chủ — sự thịnh vượng đã đạt được làm đệm cho tổn thất từ xung đột, hoặc ngược lại sự bảo vệ quá mức tài sản dẫn đến xung đột không cần thiết.", en: "Five of Swords and Nine of Pentacles: conflict meeting self-sufficient abundance — achieved prosperity cushioning losses from conflict, or conversely over-protection of wealth leading to unnecessary fighting." },
  "54_73": { vi: "Năm Kiếm và Mười Tiền: xung đột gia đình hoặc tổ chức gặp di sản — tranh chấp nội bộ đe dọa sự bền vững của tập thể, giải quyết xung đột vì lợi ích dài hạn của toàn gia đình hoặc cộng đồng.", en: "Five of Swords and Ten of Pentacles: internal conflict threatening collective legacy — family or organizational disputes endangering sustainability, resolving conflicts for the long-term benefit of the whole." },
  "54_74": { vi: "Năm Kiếm và Trang Bị Tiền: xung đột gặp sự học hỏi của người mới — người mới bắt đầu bị cuốn vào tranh chấp của người lớn, cần được bảo vệ khỏi xung đột để tập trung vào sự phát triển thực sự.", en: "Five of Swords and Page of Pentacles: conflict meeting the beginner's learning — a newcomer drawn into others' disputes, needing protection from conflict to focus on genuine growth and development." },
  "54_75": { vi: "Năm Kiếm và Kỵ Sĩ Tiền: xung đột thiếu danh dự gặp sự bền bỉ phương pháp — sự kiên định vật chất có thể thắng bằng lòng kiên nhẫn thay vì chiến đấu, bền bỉ đúng hướng đánh bại chiến thắng nhanh nhưng rỗng tuếch.", en: "Five of Swords and Knight of Pentacles: dishonorable conflict meeting methodical persistence — material steadiness winning through patience rather than fighting, endurance in the right direction defeating quick but hollow victories." },
  "54_76": { vi: "Năm Kiếm và Nữ Hoàng Tiền: xung đột gặp sự chăm sóc thực tế — Nữ Hoàng có thể chữa lành vết thương sau cuộc chiến, sự nuôi dưỡng và thực tế là đối trọng với sự tàn phá của xung đột.", en: "Five of Swords and Queen of Pentacles: conflict meeting practical nurturing — the Queen healing wounds after the battle, nurturing and practicality as the counterbalance to conflict's destruction." },
  "54_77": { vi: "Năm Kiếm và Vua Tiền: chiến thắng bằng quyền lực gặp quyền uy vật chất — hai người mạnh đối đầu, nhưng Vua Tiền thắng bằng sự bền vững dài hạn chứ không phải bằng sự hung hăng tức thời.", en: "Five of Swords and King of Pentacles: victory by power meeting material authority — two powerful forces facing each other, the King of Pentacles prevailing through long-term sustainability rather than immediate aggression." },
  "55_64": { vi: "Sáu Kiếm và Át Tiền: hành trình chuyển dịch gặp cơ hội vật chất mới — rời khỏi vùng hỗn loạn để hướng về vùng đất mới, hạt giống tiềm năng thực tế đợi sẵn ở nơi bình lặng phía trước.", en: "Six of Swords and Ace of Pentacles: transitional journey meeting new material opportunity — leaving turbulent waters toward calmer shores, a seed of practical potential awaiting in the peaceful land ahead." },
  "55_65": { vi: "Sáu Kiếm và Hai Tiền: quá trình chuyển dịch gặp thế cân bằng linh hoạt — di chuyển qua thay đổi đòi hỏi sự thích nghi, tung hứng nguồn lực trong khi hành trình vẫn đang tiếp diễn.", en: "Six of Swords and Two of Pentacles: transition meeting flexible balance — moving through change requiring adaptability, juggling resources while the journey is still underway and the destination not yet clear." },
  "55_66": { vi: "Sáu Kiếm và Ba Tiền: hành trình chuyển dịch gặp sự hợp tác — rời khỏi hỗn loạn cùng nhau, tập thể đồng hành qua quá trình thay đổi tạo ra sức mạnh mà cá nhân không có được.", en: "Six of Swords and Three of Pentacles: transitional journey meeting collaboration — leaving turbulence together, the collective moving through change creating strength unavailable to any individual alone." },
  "55_67": { vi: "Sáu Kiếm và Bốn Tiền: sự chuyển dịch gặp sự bám víu — khó rời đi khi đang ôm chặt những thứ quen thuộc, buông bỏ sự kiểm soát vật chất là điều kiện để hành trình chuyển dịch thực sự bắt đầu.", en: "Six of Swords and Four of Pentacles: transition meeting clinging — difficulty departing while tightly gripping the familiar, releasing material control the prerequisite for the transitional journey to truly begin." },
  "55_68": { vi: "Sáu Kiếm và Năm Tiền: hành trình thoát khỏi hỗn loạn gặp thiếu thốn vật chất — di chuyển đến nơi tốt hơn dù không có nhiều tài nguyên, hy vọng về phía trước là đủ để bước tiếp dù thiếu thốn.", en: "Six of Swords and Five of Pentacles: journey away from turbulence meeting material lack — moving toward something better despite limited resources, hope for what lies ahead enough to keep moving through deprivation." },
  "55_69": { vi: "Sáu Kiếm và Sáu Tiền: quá trình chuyển dịch gặp sự trao đổi công bằng — nhận sự hỗ trợ vật chất giúp hành trình trở nên khả thi, lòng hào phóng mở đường cho sự chuyển dịch an toàn.", en: "Six of Swords and Six of Pentacles: transition meeting equitable exchange — receiving material support making the journey feasible, generosity opening the way for safe passage through change." },
  "55_70": { vi: "Sáu Kiếm và Bảy Tiền: hành trình chuyển dịch gặp sự kiên nhẫn đánh giá — nhìn lại hành trình đã qua để đánh giá những gì đã trưởng thành, quá trình chuyển dịch là giai đoạn thu hoạch trí tuệ từ quá khứ.", en: "Six of Swords and Seven of Pentacles: transitional journey meeting patient assessment — looking back at the path traveled to evaluate what has matured, the transition itself a harvest of wisdom from the past." },
  "55_71": { vi: "Sáu Kiếm và Tám Tiền: quá trình chuyển dịch gặp sự rèn luyện kỹ năng — di chuyển đến lĩnh vực mới đòi hỏi học kỹ năng mới, hành trình chuyển dịch là cơ hội phát triển năng lực trong bối cảnh thay đổi.", en: "Six of Swords and Eight of Pentacles: transition meeting skill-building — moving into new territory requiring new skills, the transitional journey an opportunity to develop capabilities within the context of change." },
  "55_72": { vi: "Sáu Kiếm và Chín Tiền: hành trình chuyển dịch gặp sự sung mãn tự chủ — di chuyển hướng tới sự độc lập và thịnh vượng, hành trình bình lặng dẫn đến vùng đất của sự tự cung tự cấp.", en: "Six of Swords and Nine of Pentacles: transitional journey meeting self-sufficient abundance — moving toward independence and prosperity, the calming passage leading to the land of true self-sufficiency." },
  "55_73": { vi: "Sáu Kiếm và Mười Tiền: hành trình chuyển dịch gặp di sản bền vững — di chuyển hướng về di sản gia đình hoặc cộng đồng, hành trình qua thay đổi nhằm bảo tồn hoặc xây dựng nền tảng cho tương lai.", en: "Six of Swords and Ten of Pentacles: transitional journey meeting enduring legacy — moving toward family or community legacy, the journey through change aimed at preserving or building foundations for the future." },
  "55_74": { vi: "Sáu Kiếm và Trang Bị Tiền: hành trình chuyển dịch gặp sự học hỏi nhiệt thành — di chuyển đến môi trường mới để học hỏi và khám phá, sự thay đổi tạo ra bối cảnh phong phú cho việc tiếp thu kiến thức thực tế.", en: "Six of Swords and Page of Pentacles: transitional journey meeting eager learning — moving to a new environment to study and explore, the change creating a rich context for absorbing practical knowledge." },
  "55_75": { vi: "Sáu Kiếm và Kỵ Sĩ Tiền: hành trình chuyển dịch gặp sự bền bỉ phương pháp — di chuyển chậm nhưng chắc qua thay đổi, sự kiên định vật chất đảm bảo hành trình được hoàn thành dù mất bao lâu.", en: "Six of Swords and Knight of Pentacles: transitional journey meeting methodical persistence — moving slowly but surely through change, material steadiness ensuring the journey is completed however long it takes." },
  "55_76": { vi: "Sáu Kiếm và Nữ Hoàng Tiền: hành trình chuyển dịch gặp sự chăm sóc thực tế — di chuyển về phía sự ấm áp và nuôi dưỡng, Nữ Hoàng tạo ra đích đến an toàn cho những ai vừa qua vùng hỗn loạn.", en: "Six of Swords and Queen of Pentacles: transitional journey meeting practical nurturing — moving toward warmth and care, the Queen creating a safe destination for those who have just passed through turbulent waters." },
  "55_77": { vi: "Sáu Kiếm và Vua Tiền: hành trình chuyển dịch gặp quyền uy vật chất — di chuyển hướng tới sự ổn định và quyền lực thực tế, hành trình vượt qua hỗn loạn nhằm đạt đến vị trí thẩm quyền và thịnh vượng.", en: "Six of Swords and King of Pentacles: transitional journey meeting material authority — moving toward stability and real-world power, the passage through turbulence aimed at reaching a position of authority and prosperity." },
  "56_64": { vi: "Bảy Kiếm và Át Tiền: sự xảo quyệt gặp cơ hội mới — chiến lược và mưu mô có thể mở ra cánh cửa vật chất, nhưng liệu hạt giống thịnh vượng được gieo bằng sự gian dối có thể sinh hoa trái lành mạnh?", en: "Seven of Swords and Ace of Pentacles: cunning meeting new opportunity — strategy and stealth potentially opening material doors, but whether prosperity sown through deception can bear healthy fruit." },
  "56_65": { vi: "Bảy Kiếm và Hai Tiền: sự gian dối gặp thế cân bằng linh hoạt — tung hứng bí mật cùng lúc với nguồn lực vật chất, sự lừa dối làm phức tạp thêm hành trình duy trì thăng bằng đang mong manh.", en: "Seven of Swords and Two of Pentacles: deception meeting flexible balance — juggling secrets alongside material resources, dishonesty further complicating the already delicate act of maintaining equilibrium." },
  "56_66": { vi: "Bảy Kiếm và Ba Tiền: sự gian dối gặp sự hợp tác — ai đó trong nhóm đang che giấu động cơ thực sự, sự lừa dối ngầm phá hoại nền tảng tin tưởng mà mọi công việc tập thể đều cần có.", en: "Seven of Swords and Three of Pentacles: deception within collaboration — someone in the team concealing their true motives, hidden dishonesty undermining the foundation of trust that all collective work requires." },
  "56_67": { vi: "Bảy Kiếm và Bốn Tiền: sự xảo quyệt gặp sự kiểm soát chặt — dùng mưu mô để bảo vệ hoặc tích lũy tài sản, chiến lược bí mật như lá chắn cho sự bám víu, nguy cơ sụp đổ khi bí mật bị lộ.", en: "Seven of Swords and Four of Pentacles: cunning meeting tight control — using strategy and stealth to protect or accumulate assets, secret maneuvering as a shield for hoarding, risk of collapse when secrets are revealed." },
  "56_68": { vi: "Bảy Kiếm và Năm Tiền: sự gian dối giữa thiếu thốn — mưu mô sinh ra từ sự tuyệt vọng vật chất, hoặc bị ai đó lừa dối khi đang dễ tổn thương, cần phân biệt chiến lược chính đáng với sự lừa lọc.", en: "Seven of Swords and Five of Pentacles: deception amid deprivation — cunning born from material desperation, or being deceived when most vulnerable, needing to distinguish legitimate strategy from outright dishonesty." },
  "56_69": { vi: "Bảy Kiếm và Sáu Tiền: sự gian dối gặp sự hào phóng — lòng từ thiện bị lợi dụng hoặc dùng như màn che, sự hào phóng cần đi kèm với sự sáng suốt để không trở thành công cụ của kẻ xảo quyệt.", en: "Seven of Swords and Six of Pentacles: deception meeting generosity — charity being exploited or used as a cover, generosity needing to be paired with discernment to avoid becoming a tool for the cunning." },
  "56_70": { vi: "Bảy Kiếm và Bảy Tiền: chiến lược bí mật gặp sự đánh giá kiên nhẫn — xem xét kỹ lưỡng kết quả có thể phơi bày sự gian dối, hoặc mưu mô được lên kế hoạch cẩn thận trong thời gian chờ đợi.", en: "Seven of Swords and Seven of Pentacles: covert strategy meeting patient assessment — careful review of results potentially exposing deception, or cunning plans carefully laid during a period of patient waiting." },
  "56_71": { vi: "Bảy Kiếm và Tám Tiền: sự xảo quyệt gặp sự chăm chỉ rèn luyện — liệu kỹ năng được xây dựng bằng sự trung thực hay có sự gian dối nào ẩn sau thành tích? trí tuệ thực sự không cần đến sự lừa dối.", en: "Seven of Swords and Eight of Pentacles: cunning meeting diligent practice — whether skills are built honestly or deception hides behind achievement, true mastery not requiring dishonesty to validate itself." },
  "56_72": { vi: "Bảy Kiếm và Chín Tiền: sự gian dối gặp sự sung mãn tự chủ — sự thịnh vượng đạt được có thực sự là thành quả của nỗ lực bản thân hay ẩn chứa bí mật tối? sự độc lập đích thực không cần đến sự lừa dối.", en: "Seven of Swords and Nine of Pentacles: deception meeting self-sufficient abundance — whether prosperity is truly earned or conceals dark secrets, genuine independence not requiring deception to sustain." },
  "56_73": { vi: "Bảy Kiếm và Mười Tiền: sự gian dối đe dọa di sản gia đình — bí mật gia đình hoặc sự lừa dối trong kinh doanh có thể làm sụp đổ thành quả tập thể nhiều thế hệ, sự thật cuối cùng luôn được phơi bày.", en: "Seven of Swords and Ten of Pentacles: deception threatening family legacy — family secrets or business dishonesty potentially collapsing multi-generational achievement, truth eventually always being brought to light." },
  "56_74": { vi: "Bảy Kiếm và Trang Bị Tiền: sự gian dối gặp người học trò — người mới bắt đầu dễ bị lừa bởi vẻ ngoài hào nhoáng, cần học cách phân biệt thật giả trong hành trình khám phá thực tế.", en: "Seven of Swords and Page of Pentacles: deception meeting the student — a beginner easily misled by superficial appearances, needing to learn how to distinguish genuine from false on the journey of practical discovery." },
  "56_75": { vi: "Bảy Kiếm và Kỵ Sĩ Tiền: chiến lược bí mật gặp sự bền bỉ trung thực — sự kiên định phương pháp của Kỵ Sĩ cuối cùng phơi bày sự gian dối, sự nhất quán và trung thực thắng hơn sự xảo quyệt về lâu dài.", en: "Seven of Swords and Knight of Pentacles: covert strategy meeting honest persistence — the Knight's methodical consistency eventually exposing deception, steadfastness and honesty winning over cunning in the long run." },
  "56_76": { vi: "Bảy Kiếm và Nữ Hoàng Tiền: sự gian dối gặp trí tuệ thực tế — Nữ Hoàng khó bị lừa bởi sự xảo quyệt, sự am hiểu thực tế và bản năng nuôi dưỡng của bà nhận ra sự không thành thật.", en: "Seven of Swords and Queen of Pentacles: deception meeting practical wisdom — the Queen difficult to fool by cunning, her practical understanding and nurturing instinct detecting insincerity and hidden motives." },
  "56_77": { vi: "Bảy Kiếm và Vua Tiền: mưu mô gặp quyền uy vật chất vững chắc — sự gian dối khó qua mắt người nắm quyền kinh tế, trí tuệ thực tế của Vua Tiền nhận ra chiến lược bí mật và đòi hỏi sự minh bạch.", en: "Seven of Swords and King of Pentacles: cunning meeting solid material authority — deception struggling to slip past those who hold economic power, the King's practical intelligence recognizing covert strategy and demanding transparency." },
  // ── Tier 5f-2: Swords × Pentacles, air×earth (Swords 57–63 × Pentacles 64–77, 98 pairs) ──
  "57_64": { vi: "Tám Kiếm và Át Tiền: tâm trí bị giam cầm gặp cơ hội mới — sự tự giới hạn bản thân ngăn cản việc nắm bắt tiềm năng vật chất, chỉ cần tháo bịt mắt mới thấy rằng con đường thoát vẫn đang mở sẵn.", en: "Eight of Swords and Ace of Pentacles: imprisoned mind meeting new opportunity — self-limitation blocking the grasp of material potential, only removing the blindfold revealing the escape path has been open all along." },
  "57_65": { vi: "Tám Kiếm và Hai Tiền: sự giam cầm tâm trí gặp thế tung hứng linh hoạt — cảm thấy bị trói buộc trong khi thực tế vẫn đang xoay vần, nhận ra rằng bản thân có nhiều khả năng thích nghi hơn tưởng tượng.", en: "Eight of Swords and Two of Pentacles: mental imprisonment meeting flexible juggling — feeling bound while reality keeps moving, recognizing that one has far more adaptive capacity than imagined." },
  "57_66": { vi: "Tám Kiếm và Ba Tiền: tâm trí bị giam cầm gặp sự hợp tác — nhóm có thể giúp tháo gỡ sự giới hạn tự áp đặt, góc nhìn từ bên ngoài thường đủ để phá vỡ lồng tưởng tượng.", en: "Eight of Swords and Three of Pentacles: mental imprisonment meeting collaboration — the group able to help dismantle self-imposed limitations, an outside perspective often enough to break the imaginary cage." },
  "57_67": { vi: "Tám Kiếm và Bốn Tiền: sự giam cầm kép — tâm trí tự trói buộc và tay ôm chặt tài sản, cả hai đều sợ hãi và kiểm soát, cần buông bỏ để tự do khỏi những xiềng xích tự tạo.", en: "Eight of Swords and Four of Pentacles: dual imprisonment — mind self-bound and hands gripping assets tightly, both driven by fear and control, release necessary to break free from self-made chains." },
  "57_68": { vi: "Tám Kiếm và Năm Tiền: sự giam cầm tâm trí giữa thiếu thốn vật chất — bị giới hạn cả trong lẫn ngoài, nhưng sự thiếu thốn vật chất là thực còn sự giam cầm tâm trí là tự áp đặt, có thể giải phóng một trong hai.", en: "Eight of Swords and Five of Pentacles: mental imprisonment amid material deprivation — constrained within and without, but material lack being real while mental imprisonment is self-imposed, one can be freed." },
  "57_69": { vi: "Tám Kiếm và Sáu Tiền: tâm trí bị giam gặp sự hào phóng — sự giúp đỡ vật chất có thể phá vỡ cảm giác bị mắc kẹt, lòng tốt từ bên ngoài nhắc nhở rằng có người sẵn sàng hỗ trợ nếu ta sẵn sàng nhận.", en: "Eight of Swords and Six of Pentacles: trapped mind meeting generosity — material help potentially breaking the sense of being stuck, kindness from outside reminding that support is available if one is willing to receive it." },
  "57_70": { vi: "Tám Kiếm và Bảy Tiền: sự giam cầm tâm trí gặp sự chờ đợi đánh giá — đứng yên không phải vì kiên nhẫn mà vì tâm lý bị trói buộc, đất vẫn đang phát triển trong khi tâm trí từ chối nhìn thấy sự tiến triển.", en: "Eight of Swords and Seven of Pentacles: mental imprisonment meeting patient waiting — standing still not from patience but from psychological binding, earth still growing while mind refuses to see the progress." },
  "57_71": { vi: "Tám Kiếm và Tám Tiền: tâm trí bị giới hạn gặp sự chuyên cần — tập trung vào công việc thủ công là cách thoát khỏi sự giam cầm tâm trí, bàn tay làm việc giải phóng tâm trí khỏi vòng lặp tự hạn chế.", en: "Eight of Swords and Eight of Pentacles: self-limited mind meeting diligent craft — focusing on hands-on work as a way out of mental imprisonment, the working hands liberating the mind from self-limiting loops." },
  "57_72": { vi: "Tám Kiếm và Chín Tiền: tâm trí bị giam cầm gặp sự sung mãn tự chủ — nghịch lý của sự thịnh vượng bên ngoài và sự trói buộc bên trong, sự độc lập vật chất sẵn có nhưng tâm trí chưa thể tận hưởng nó.", en: "Eight of Swords and Nine of Pentacles: imprisoned mind meeting self-sufficient abundance — the paradox of outer prosperity and inner bondage, material independence available but the mind not yet able to enjoy it." },
  "57_73": { vi: "Tám Kiếm và Mười Tiền: tâm trí tự giới hạn giữa di sản gia đình — kỳ vọng của gia đình hoặc truyền thống là chiếc lồng vô hình, sự giam cầm tâm trí ẩn trong cấu trúc tập thể cần được nhận diện.", en: "Eight of Swords and Ten of Pentacles: self-limiting mind amid family legacy — family expectations or tradition as invisible cage, mental imprisonment hidden within collective structure needing to be recognized." },
  "57_74": { vi: "Tám Kiếm và Trang Bị Tiền: tâm trí bị giam gặp sự học hỏi tò mò — sự tò mò thực tiễn có thể tìm thấy con đường mà tâm trí bị trói buộc không thấy, sự ham học kéo người ra khỏi sự tự giới hạn.", en: "Eight of Swords and Page of Pentacles: imprisoned mind meeting curious learning — practical curiosity able to find paths the bound mind cannot see, eagerness to learn pulling one out of self-limitation." },
  "57_75": { vi: "Tám Kiếm và Kỵ Sĩ Tiền: tâm trí bị trói gặp sự bền bỉ phương pháp — sự kiên định có phương pháp từng bước giải phóng sự giam cầm tâm trí, hành động đều đặn là giải thuốc cho sự tê liệt tư duy.", en: "Eight of Swords and Knight of Pentacles: bound mind meeting methodical persistence — step-by-step steadfast action gradually freeing the mental imprisonment, regular movement as antidote to cognitive paralysis." },
  "57_76": { vi: "Tám Kiếm và Nữ Hoàng Tiền: tâm trí bị giam gặp sự chăm sóc thực tế — sự nuôi dưỡng ấm áp của Nữ Hoàng tạo ra không gian an toàn để tháo gỡ sự tự trói buộc, sự quan tâm thực tế giải phóng hơn là bất kỳ lý lẽ nào.", en: "Eight of Swords and Queen of Pentacles: imprisoned mind meeting practical care — the Queen's warm nurturing creating safe space to untie self-binding, practical compassion liberating more than any argument." },
  "57_77": { vi: "Tám Kiếm và Vua Tiền: tâm trí bị giam gặp quyền uy vật chất — sức mạnh thực lực của Vua nhắc nhở rằng quyền lực thực sự không đến từ sự sợ hãi, sự tự tin vật chất có thể là chìa khóa giải phóng tâm trí.", en: "Eight of Swords and King of Pentacles: imprisoned mind meeting material authority — the King's real-world strength reminding that true power doesn't come from fear, material confidence potentially the key to mental liberation." },
  "58_64": { vi: "Chín Kiếm và Át Tiền: lo âu tâm trí gặp cơ hội mới — nỗi sợ hãi về tương lai có thể che khuất hạt giống tiềm năng đang nảy mầm, bước ra khỏi bóng tối lo lắng để nhìn thấy cơ hội thực tế đang chờ.", en: "Nine of Swords and Ace of Pentacles: mental anxiety meeting new opportunity — fear about the future potentially obscuring the sprouting seed of potential, stepping out of the shadow of worry to see real opportunity waiting." },
  "58_65": { vi: "Chín Kiếm và Hai Tiền: lo âu tâm trí gặp thế tung hứng linh hoạt — sự lo lắng về quá nhiều trách nhiệm vật chất là một phần của nỗi sợ hãi đêm khuya, học cách tung hứng nhẹ nhàng hơn để giảm bớt lo âu.", en: "Nine of Swords and Two of Pentacles: mental anxiety meeting flexible juggling — worry about too many material responsibilities part of the midnight fear, learning to juggle more lightly as a way to reduce anxiety." },
  "58_66": { vi: "Chín Kiếm và Ba Tiền: lo âu tâm trí gặp sự hợp tác — nỗi sợ hãi thường lớn nhất khi ta đối mặt một mình, chia sẻ lo lắng với nhóm làm việc tin cậy có thể giảm bớt gánh nặng đang đè trên vai.", en: "Nine of Swords and Three of Pentacles: mental anxiety meeting collaboration — fear often largest when faced alone, sharing worries with a trusted working group potentially lightening the burden pressing down." },
  "58_67": { vi: "Chín Kiếm và Bốn Tiền: lo âu tâm trí gặp sự bám víu vật chất — sự ôm chặt tài sản sinh ra từ nỗi sợ mất mát, lo lắng đêm khuya nuôi dưỡng thói quen tích trữ và kiểm soát vật chất quá mức.", en: "Nine of Swords and Four of Pentacles: mental anxiety meeting material clinging — gripping possessions born from fear of loss, midnight worries feeding habits of hoarding and excessive material control." },
  "58_68": { vi: "Chín Kiếm và Năm Tiền: lo âu kép — nỗi sợ hãi tâm trí và thiếu thốn vật chất cùng lúc, sự kiệt sức tinh thần và vật chất tạo ra vòng xoáy đi xuống cần sự hỗ trợ từ bên ngoài để phá vỡ.", en: "Nine of Swords and Five of Pentacles: dual anxiety — mental anguish and material deprivation together, mental and material exhaustion creating a downward spiral needing outside support to break." },
  "58_69": { vi: "Chín Kiếm và Sáu Tiền: lo âu tâm trí gặp sự hào phóng — nhận sự giúp đỡ vật chất có thể xoa dịu nỗi lo lắng, lòng từ bi thực tế từ người khác giảm bớt gánh nặng đêm tối tâm trí.", en: "Nine of Swords and Six of Pentacles: mental anxiety meeting generosity — receiving material help potentially soothing the worry, practical compassion from others lightening the midnight burden of the mind." },
  "58_70": { vi: "Chín Kiếm và Bảy Tiền: lo âu tâm trí gặp sự chờ đợi kiên nhẫn — lo lắng về thành quả chưa đến là trung tâm của nỗi đau đêm tối, tin tưởng vào quá trình tăng trưởng tự nhiên là thuốc giải cho sự lo âu.", en: "Nine of Swords and Seven of Pentacles: mental anxiety meeting patient waiting — worrying about results not yet arrived at the center of midnight pain, trusting natural growth processes as antidote to anxiety." },
  "58_71": { vi: "Chín Kiếm và Tám Tiền: lo âu tâm trí gặp sự chuyên cần — đổ mình vào công việc có ý nghĩa là cách xoa dịu nỗi lo lắng, sự tập trung vào kỹ năng thực tế đưa tâm trí ra khỏi vòng lặp lo âu.", en: "Nine of Swords and Eight of Pentacles: mental anxiety meeting diligent craft — immersing in meaningful work as a way to soothe worry, focusing on practical skill drawing the mind out of anxiety loops." },
  "58_72": { vi: "Chín Kiếm và Chín Tiền: lo âu tâm trí gặp sự sung mãn tự chủ — sự thịnh vượng bên ngoài không ngăn được nỗi lo lắng bên trong, cần học cách hưởng thụ thành quả đã đạt được thay vì liên tục lo sợ mất nó.", en: "Nine of Swords and Nine of Pentacles: mental anxiety meeting self-sufficient abundance — outer prosperity unable to prevent inner worry, needing to learn to enjoy achieved results rather than constantly fearing their loss." },
  "58_73": { vi: "Chín Kiếm và Mười Tiền: lo âu tâm trí gặp di sản gia đình — áp lực duy trì tài sản và danh tiếng gia đình là nguồn gốc của lo lắng đêm tối, trách nhiệm tập thể đôi khi trở thành gánh nặng tâm trí.", en: "Nine of Swords and Ten of Pentacles: mental anxiety meeting family legacy — pressure to maintain family wealth and reputation as a source of midnight worry, collective responsibility sometimes becoming a mental burden." },
  "58_74": { vi: "Chín Kiếm và Trang Bị Tiền: lo âu tâm trí gặp sự học hỏi tò mò — nỗi sợ hãi về tương lai có thể kìm hãm sự khám phá, nhưng tinh thần học hỏi thực tế là phương thuốc chống lo âu hiệu quả.", en: "Nine of Swords and Page of Pentacles: mental anxiety meeting curious learning — fear about the future potentially inhibiting exploration, but the Page of Pentacles' practical learning spirit as medicine against anxiety." },
  "58_75": { vi: "Chín Kiếm và Kỵ Sĩ Tiền: lo âu tâm trí gặp sự bền bỉ phương pháp — lo lắng đêm khuya nhưng vẫn tiến bước mỗi ngày, hành động đều đặn của Kỵ Sĩ là cách chứng minh cho tâm trí rằng lo âu là không cần thiết.", en: "Nine of Swords and Knight of Pentacles: mental anxiety meeting methodical persistence — worrying at midnight but still moving forward each day, the Knight's regular action proving to the mind that worry is unnecessary." },
  "58_76": { vi: "Chín Kiếm và Nữ Hoàng Tiền: lo âu tâm trí gặp sự chăm sóc thực tế — Nữ Hoàng biết rằng cơ thể và môi trường là liều thuốc tốt nhất cho lo lắng tâm trí, sự chăm sóc thực tế và ấm áp xoa dịu nỗi sợ hãi đêm khuya.", en: "Nine of Swords and Queen of Pentacles: mental anxiety meeting practical care — the Queen knowing that body and environment are the best medicine for mental worry, practical warmth and care soothing midnight fears." },
  "58_77": { vi: "Chín Kiếm và Vua Tiền: lo âu tâm trí gặp quyền uy vật chất — sự ổn định tài chính vững chắc không loại bỏ được lo lắng nhưng tạo ra nền tảng để đối mặt với nó, thực lực là điểm tựa khi tâm trí bất an.", en: "Nine of Swords and King of Pentacles: mental anxiety meeting material authority — solid financial stability unable to eliminate worry but creating foundation to face it, real-world strength as anchor when mind is troubled." },
  "59_64": { vi: "Mười Kiếm và Át Tiền: điểm tận cùng gặp khởi đầu mới — kết thúc đau đớn không phải là tất cả, hạt giống tiềm năng mới mọc lên từ đất sau khi chu kỳ cũ hoàn toàn khép lại.", en: "Ten of Swords and Ace of Pentacles: rock bottom meeting new beginning — a painful ending not being the whole story, a seed of new potential rising from the earth after the old cycle has completely closed." },
  "59_65": { vi: "Mười Kiếm và Hai Tiền: điểm tận cùng gặp thế cân bằng linh hoạt — sau khi chạm đáy cần sắp xếp lại nguồn lực, sự thích nghi linh hoạt là chìa khóa để tái cân bằng sau sự sụp đổ.", en: "Ten of Swords and Two of Pentacles: rock bottom meeting flexible balance — after hitting the lowest point needing to rearrange resources, flexible adaptability key to rebalancing after the collapse." },
  "59_66": { vi: "Mười Kiếm và Ba Tiền: kết thúc đau đớn gặp sự hợp tác — xây dựng lại cùng nhau sau sự sụp đổ, cộng đồng và kỹ năng tập thể là nền tảng cho sự tái sinh sau điểm tận cùng.", en: "Ten of Swords and Three of Pentacles: painful ending meeting collaboration — rebuilding together after the collapse, community and collective skill as the foundation for renewal after rock bottom." },
  "59_67": { vi: "Mười Kiếm và Bốn Tiền: điểm tận cùng gặp sự bám víu — giữ chặt tàn dư của cái đã chết chỉ trì hoãn sự tái sinh, buông bỏ điều đã kết thúc là bước đầu tiên để bảo vệ những gì còn lại.", en: "Ten of Swords and Four of Pentacles: rock bottom meeting clinging — holding tightly to remnants of what has died only delaying rebirth, releasing what has ended as the first step to protecting what remains." },
  "59_68": { vi: "Mười Kiếm và Năm Tiền: điểm tận cùng gặp thiếu thốn vật chất — sự sụp đổ toàn diện cả tinh thần lẫn vật chất, nhưng bình minh luôn đến sau đêm tối nhất, cần tìm kiếm sự hỗ trợ bên ngoài để vượt qua.", en: "Ten of Swords and Five of Pentacles: rock bottom meeting material deprivation — total collapse both mentally and materially, but dawn always following the darkest night, outside support needed to survive through it." },
  "59_69": { vi: "Mười Kiếm và Sáu Tiền: điểm tận cùng gặp sự hào phóng — nhận sự giúp đỡ sau khi chạm đáy là hành động dũng cảm không phải yếu đuối, lòng từ thiện thực tế là cánh tay đỡ lấy khi tất cả sụp đổ.", en: "Ten of Swords and Six of Pentacles: rock bottom meeting generosity — accepting help after hitting the lowest is courage not weakness, practical charity as the helping hand when everything has collapsed." },
  "59_70": { vi: "Mười Kiếm và Bảy Tiền: kết thúc gặp sự đánh giá kiên nhẫn — nhìn lại những gì đã dẫn đến điểm tận cùng để học hỏi, thời gian và sự phân tích trung thực biến thất bại thành trí tuệ cho chu kỳ tiếp theo.", en: "Ten of Swords and Seven of Pentacles: painful ending meeting patient assessment — looking back at what led to rock bottom to learn, time and honest analysis transforming failure into wisdom for the next cycle." },
  "59_71": { vi: "Mười Kiếm và Tám Tiền: điểm tận cùng gặp sự chuyên cần — xây dựng lại từ đầu bằng đôi bàn tay và kỹ năng sau khi tất cả sụp đổ, sự chăm chỉ kiên nhẫn là con đường duy nhất từ tro tàn đến thành thạo.", en: "Ten of Swords and Eight of Pentacles: rock bottom meeting diligent craft — rebuilding from scratch through hands and skill after everything collapses, patient diligence as the only path from ashes to mastery." },
  "59_72": { vi: "Mười Kiếm và Chín Tiền: điểm tận cùng gặp sự sung mãn tự chủ — sự thịnh vượng đã đạt được trước kia làm đệm cho cú ngã, hoặc mất đi sự độc lập là điểm tận cùng thúc đẩy xây dựng lại tự chủ thực sự.", en: "Ten of Swords and Nine of Pentacles: rock bottom meeting self-sufficient abundance — previously achieved prosperity cushioning the fall, or losing independence being the rock bottom motivating rebuilding of true self-sufficiency." },
  "59_73": { vi: "Mười Kiếm và Mười Tiền: kết thúc đau đớn gặp di sản bền vững — sự sụp đổ cá nhân trong bối cảnh gia đình hoặc thể chế vẫn đứng vững, nền tảng tập thể hỗ trợ cá nhân vượt qua điểm tận cùng.", en: "Ten of Swords and Ten of Pentacles: painful ending meeting enduring legacy — personal collapse within a still-standing family or institution, collective foundation supporting the individual through rock bottom." },
  "59_74": { vi: "Mười Kiếm và Trang Bị Tiền: điểm tận cùng gặp sự học hỏi nhiệt thành — thất bại hoàn toàn là bài học sâu sắc nhất, tinh thần tò mò thực tiễn biến điểm tận cùng thành điểm khởi đầu của sự khám phá mới.", en: "Ten of Swords and Page of Pentacles: rock bottom meeting eager learning — complete failure as the deepest lesson, practical curiosity transforming rock bottom into the starting point of fresh discovery." },
  "59_75": { vi: "Mười Kiếm và Kỵ Sĩ Tiền: điểm tận cùng gặp sự bền bỉ phương pháp — không còn con đường nào khác ngoài tiến bước từng bước một sau khi chạm đáy, sự kiên định phương pháp là cách duy nhất xây dựng lại.", en: "Ten of Swords and Knight of Pentacles: rock bottom meeting methodical persistence — no path forward except one step at a time after hitting the lowest, methodical steadiness as the only way to rebuild." },
  "59_76": { vi: "Mười Kiếm và Nữ Hoàng Tiền: điểm tận cùng gặp sự chăm sóc thực tế — Nữ Hoàng chăm sóc những ai đã chạm đáy mà không phán xét, sự nuôi dưỡng vật chất và tinh thần thực tế là nền tảng cho sự phục hồi.", en: "Ten of Swords and Queen of Pentacles: rock bottom meeting practical care — the Queen tending to those who have hit bottom without judgment, practical material and emotional nurturing as foundation for recovery." },
  "59_77": { vi: "Mười Kiếm và Vua Tiền: điểm tận cùng gặp quyền uy vật chất — thực lực vật chất vững chắc là nền tảng để xây dựng lại từ đầu, Vua Tiền nhìn nhận sự sụp đổ là cơ hội để cấu trúc lại thực sự bền vững hơn.", en: "Ten of Swords and King of Pentacles: rock bottom meeting material authority — solid material strength as foundation for rebuilding from scratch, the King viewing collapse as opportunity to restructure truly more durably." },
  "60_64": { vi: "Trang Bị Kiếm và Át Tiền: tinh thần tò mò sắc bén gặp cơ hội vật chất mới — tư duy nhạy bén của người mới bắt đầu tìm kiếm ý tưởng đột phá gặp hạt giống tiềm năng thực tế sẵn sàng nảy mầm.", en: "Page of Swords and Ace of Pentacles: sharp curious spirit meeting new material opportunity — the newcomer's keen thinking seeking breakthrough ideas meeting the seed of practical potential ready to sprout." },
  "60_65": { vi: "Trang Bị Kiếm và Hai Tiền: sự tò mò sắc bén gặp thế cân bằng linh hoạt — tâm trí nhanh nhẹn học cách tung hứng nhiều nguồn lực, sự lanh lợi tư duy giúp điều phối các yêu cầu đang xung đột.", en: "Page of Swords and Two of Pentacles: sharp curiosity meeting flexible balance — the quick mind learning to juggle multiple resources, mental agility helping coordinate competing demands." },
  "60_66": { vi: "Trang Bị Kiếm và Ba Tiền: tinh thần nhạy bén gặp sự hợp tác thủ công — đặt câu hỏi thông minh và quan sát sắc bén đóng góp cho nhóm làm việc, năng lượng của người trẻ sáng tạo tăng thêm sức sống cho tập thể.", en: "Page of Swords and Three of Pentacles: sharp spirit meeting collaborative craft — intelligent questioning and keen observation contributing to the working group, youthful creative energy adding vitality to the collective." },
  "60_67": { vi: "Trang Bị Kiếm và Bốn Tiền: sự tò mò sắc bén gặp sự bám víu kiểm soát — tinh thần tò mò thách thức thói quen tích trữ và kiểm soát, câu hỏi sắc bén phơi bày sự sợ hãi ẩn sau thói quen ôm chặt.", en: "Page of Swords and Four of Pentacles: sharp curiosity meeting controlling grip — the curious spirit challenging habits of hoarding and control, pointed questions exposing the fear hidden behind the possessive habit." },
  "60_68": { vi: "Trang Bị Kiếm và Năm Tiền: tinh thần lanh lợi gặp thiếu thốn vật chất — tư duy sắc bén tìm kiếm giải pháp sáng tạo trong tình trạng thiếu thốn, năng lượng tò mò biến khó khăn thành bài toán cần giải.", en: "Page of Swords and Five of Pentacles: agile spirit meeting material deprivation — sharp thinking seeking creative solutions within scarcity, curious energy transforming hardship into a problem needing solving." },
  "60_69": { vi: "Trang Bị Kiếm và Sáu Tiền: tinh thần tò mò gặp sự hào phóng — khám phá cách cho và nhận cân bằng, đặt câu hỏi về sự công bằng trong phân phối nguồn lực với tinh thần cởi mở muốn học hỏi.", en: "Page of Swords and Six of Pentacles: curious spirit meeting generosity — exploring how giving and receiving balance out, questioning equity in resource distribution with an open spirit eager to learn." },
  "60_70": { vi: "Trang Bị Kiếm và Bảy Tiền: tinh thần lanh lợi gặp sự kiên nhẫn đánh giá — học cách chờ đợi và quan sát thay vì hành động vội vàng, sự tò mò kết hợp với sự kiên nhẫn tạo nên người quan sát sắc sảo.", en: "Page of Swords and Seven of Pentacles: agile spirit meeting patient assessment — learning to wait and observe rather than act impulsively, curiosity combined with patience creating a genuinely sharp observer." },
  "60_71": { vi: "Trang Bị Kiếm và Tám Tiền: tinh thần tò mò gặp sự chuyên cần rèn luyện — đặt câu hỏi về mọi kỹ thuật để hiểu sâu hơn, sự kết hợp của trí tuệ lanh lợi và thực hành kiên nhẫn tạo nên sự thành thạo thực sự.", en: "Page of Swords and Eight of Pentacles: curious spirit meeting diligent practice — questioning every technique to understand more deeply, the combination of agile intellect and patient practice creating genuine mastery." },
  "60_72": { vi: "Trang Bị Kiếm và Chín Tiền: tinh thần nhạy bén gặp sự sung mãn tự chủ — người trẻ tò mò học hỏi từ sự thịnh vượng của người đã thành công tự lập, sự quan sát sắc bén tiếp thu bài học từ sự độc lập.", en: "Page of Swords and Nine of Pentacles: sharp spirit meeting self-sufficient abundance — the curious young one learning from the prosperity of those who have achieved self-sufficiency, keen observation absorbing lessons from independence." },
  "60_73": { vi: "Trang Bị Kiếm và Mười Tiền: tinh thần tò mò gặp di sản gia đình — người trẻ đặt câu hỏi về truyền thống và kỳ vọng của gia đình, sự lanh lợi có thể thách thức hoặc làm mới di sản tập thể.", en: "Page of Swords and Ten of Pentacles: curious spirit meeting family legacy — the young one questioning family traditions and expectations, agility of mind potentially challenging or renewing the collective inheritance." },
  "60_74": { vi: "Trang Bị Kiếm và Trang Bị Tiền: hai người học trò gặp nhau — trí tuệ nhanh nhẹn và sự tò mò thực tiễn cùng khám phá, không khí và đất học hỏi từ nhau tạo nên sự cân bằng giữa tư duy và hành động.", en: "Page of Swords and Page of Pentacles: two students meeting — quick intellect and practical curiosity exploring together, air and earth learning from each other creating balance between thinking and doing." },
  "60_75": { vi: "Trang Bị Kiếm và Kỵ Sĩ Tiền: tinh thần lanh lợi gặp sự kiên định có phương pháp — tốc độ tư duy và sự bền bỉ hành động bổ trợ nhau, không khí và đất học được điều quý giá từ nhịp độ khác nhau của nhau.", en: "Page of Swords and Knight of Pentacles: agile spirit meeting methodical steadiness — speed of thought and persistence of action complementing each other, air and earth learning something valuable from each other's different pace." },
  "60_76": { vi: "Trang Bị Kiếm và Nữ Hoàng Tiền: tinh thần tò mò gặp trí tuệ thực tế dày dặn — Nữ Hoàng hướng dẫn năng lượng tò mò vào ứng dụng thực tiễn có ý nghĩa, kinh nghiệm nuôi dưỡng tâm trí lanh lợi đang trưởng thành.", en: "Page of Swords and Queen of Pentacles: curious spirit meeting seasoned practical wisdom — the Queen channeling curious energy into meaningful practical application, experience nurturing the maturing agile mind." },
  "60_77": { vi: "Trang Bị Kiếm và Vua Tiền: tinh thần lanh lợi gặp quyền uy vật chất — Vua nhận ra tiềm năng trong tinh thần tò mò và định hướng nó, tư duy sắc bén tìm được con đường biểu đạt trong cấu trúc vật chất đã được xây dựng.", en: "Page of Swords and King of Pentacles: agile spirit meeting material authority — the King recognizing potential in the curious spirit and directing it, sharp thinking finding its path of expression within the established material structure." },
  "61_64": { vi: "Kỵ Sĩ Kiếm và Át Tiền: tốc độ tư duy gặp cơ hội vật chất mới — sự xông xáo và quyết đoán nắm bắt hạt giống tiềm năng trước khi người khác nhìn thấy, năng lượng hành động nhanh biến ý tưởng thành hiện thực.", en: "Knight of Swords and Ace of Pentacles: speed of thought meeting new material opportunity — boldness and decisiveness grasping the seed of potential before others see it, fast-acting energy turning ideas into reality." },
  "61_65": { vi: "Kỵ Sĩ Kiếm và Hai Tiền: tốc độ xung kích gặp thế cân bằng linh hoạt — năng lượng nhanh nhẹn có thể làm mất đi thế thăng bằng hoặc giúp tung hứng hiệu quả hơn, tốc độ cần được điều phối bởi sự linh hoạt thực tế.", en: "Knight of Swords and Two of Pentacles: charging speed meeting flexible balance — fast-moving energy potentially disrupting equilibrium or enabling more efficient juggling, speed needing to be modulated by practical flexibility." },
  "61_66": { vi: "Kỵ Sĩ Kiếm và Ba Tiền: sự xông xáo gặp tinh thần đồng đội — năng lượng nhanh mạnh cần được định hướng bởi sự hợp tác, lực đẩy cá nhân có thể tăng thêm hoặc phá vỡ nhịp độ làm việc nhóm.", en: "Knight of Swords and Three of Pentacles: boldness meeting collaborative spirit — strong fast energy needing to be directed by collaboration, individual drive potentially enhancing or disrupting the working team's rhythm." },
  "61_67": { vi: "Kỵ Sĩ Kiếm và Bốn Tiền: sự xung kích gặp sự ôm giữ chặt — tốc độ và sự kiểm soát đối đầu nhau, Kỵ Sĩ muốn tiến bước trong khi Bốn Tiền muốn giữ nguyên, xung đột giữa hành động và an toàn.", en: "Knight of Swords and Four of Pentacles: charging force meeting tight grip — speed and control in opposition, the Knight wanting to advance while Four of Pentacles wants to hold still, conflict between action and security." },
  "61_68": { vi: "Kỵ Sĩ Kiếm và Năm Tiền: sự xông xáo gặp thiếu thốn vật chất — năng lượng mạnh mẽ nhưng không có nguồn lực để duy trì, hoặc quyết tâm xông xáo thoát khỏi tình trạng thiếu thốn bằng hành động táo bạo.", en: "Knight of Swords and Five of Pentacles: charging energy meeting material deprivation — powerful energy but lacking resources to sustain it, or fierce determination to escape deprivation through bold decisive action." },
  "61_69": { vi: "Kỵ Sĩ Kiếm và Sáu Tiền: sự xung kích gặp sự hào phóng — trao đi hoặc nhận lấy nhanh chóng và quyết đoán, năng lượng Kỵ Sĩ có thể là sức mạnh thúc đẩy sự hào phóng hoặc sự bốc đồng chi tiêu không cân nhắc.", en: "Knight of Swords and Six of Pentacles: charging energy meeting generosity — giving or receiving quickly and decisively, the Knight's energy potentially driving powerful generosity or impulsive unthinking spending." },
  "61_70": { vi: "Kỵ Sĩ Kiếm và Bảy Tiền: sự xung kích gặp sự kiên nhẫn chờ đợi — hai nhịp độ hoàn toàn đối lập, cần học khi nào dừng lại để đánh giá và khi nào cần tiến bước, tốc độ và kiên nhẫn đều có lúc cần thiết.", en: "Knight of Swords and Seven of Pentacles: charging force meeting patient waiting — two completely opposing tempos, needing to learn when to stop and assess and when to advance, speed and patience both necessary at different times." },
  "61_71": { vi: "Kỵ Sĩ Kiếm và Tám Tiền: tốc độ hành động gặp sự chăm chỉ rèn luyện — năng lượng Kỵ Sĩ có thể tăng tốc rèn luyện kỹ năng hoặc đốt cháy giai đoạn xây dựng nền tảng, cân bằng tốc độ với độ sâu là thách thức.", en: "Knight of Swords and Eight of Pentacles: fast action meeting diligent craft — the Knight's energy potentially accelerating skill development or burning through foundation-building, balancing speed with depth as the challenge." },
  "61_72": { vi: "Kỵ Sĩ Kiếm và Chín Tiền: sự xung kích gặp sự sung mãn tự chủ — năng lượng nhanh mạnh có thể bảo vệ hoặc phá vỡ sự độc lập đã đạt được, Kỵ Sĩ cần học từ sự điềm tĩnh tự chủ của Chín Tiền.", en: "Knight of Swords and Nine of Pentacles: charging force meeting self-sufficient abundance — strong fast energy potentially protecting or disrupting achieved independence, the Knight needing to learn from Nine of Pentacles' calm self-possession." },
  "61_73": { vi: "Kỵ Sĩ Kiếm và Mười Tiền: sự xung kích gặp di sản bền vững — năng lượng nhanh nhẹn có thể tạo ra di sản mới hoặc đe dọa những gì đã được xây dựng, câu hỏi là liệu tốc độ có phục vụ cho lợi ích dài hạn không.", en: "Knight of Swords and Ten of Pentacles: charging energy meeting enduring legacy — fast-moving energy potentially creating new legacy or threatening what has been built, the question being whether speed serves long-term benefit." },
  "61_74": { vi: "Kỵ Sĩ Kiếm và Trang Bị Tiền: sự xung kích gặp sự tò mò thực tiễn — năng lượng Kỵ Sĩ có thể truyền cảm hứng cho người học trò hoặc làm họ bị choáng ngợp, tốc độ và sự tỉ mỉ tìm cách bổ trợ nhau.", en: "Knight of Swords and Page of Pentacles: charging force meeting practical curiosity — the Knight's energy potentially inspiring the student or overwhelming them, speed and thoroughness finding ways to complement each other." },
  "61_75": { vi: "Kỵ Sĩ Kiếm và Kỵ Sĩ Tiền: hai Kỵ Sĩ gặp nhau — gió nhanh và đất chậm, tốc độ tư duy và sự bền bỉ thực tế, hai nhịp điệu cần nhau để tạo nên hành động vừa có lực vừa có chiều sâu.", en: "Knight of Swords and Knight of Pentacles: two knights meeting — fast wind and slow earth, speed of thought and practical persistence, two rhythms needing each other to create action that is both powerful and deep." },
  "61_76": { vi: "Kỵ Sĩ Kiếm và Nữ Hoàng Tiền: sự xung kích gặp trí tuệ nuôi dưỡng — Nữ Hoàng định hướng năng lượng nhanh của Kỵ Sĩ vào mục tiêu thực tế có ý nghĩa, sự ổn định vật chất là bến đỗ cho năng lượng đang lao nhanh.", en: "Knight of Swords and Queen of Pentacles: charging force meeting nurturing wisdom — the Queen directing the Knight's fast energy toward meaningful practical goals, material stability as a harbor for rapidly moving energy." },
  "61_77": { vi: "Kỵ Sĩ Kiếm và Vua Tiền: năng lượng xung kích gặp quyền uy vật chất — Vua Tiền kiểm soát năng lượng nhanh nhẹn của Kỵ Sĩ với sự khôn ngoan thực tế, tốc độ được định hướng bởi kinh nghiệm tạo nên kết quả bền vững.", en: "Knight of Swords and King of Pentacles: charging energy meeting material authority — the King of Pentacles harnessing the Knight's swift energy with practical wisdom, speed directed by experience creating durable results." },
  "62_64": { vi: "Nữ Hoàng Kiếm và Át Tiền: trí tuệ sắc bén gặp cơ hội vật chất mới — sự rõ ràng và sắc bén của Nữ Hoàng đánh giá hạt giống tiềm năng một cách khách quan, quyết định tỉnh táo nắm lấy hay bỏ qua cơ hội.", en: "Queen of Swords and Ace of Pentacles: sharp intellect meeting new material opportunity — the Queen's clarity and discernment objectively evaluating the seed of potential, clear-eyed decision to seize or pass on the opportunity." },
  "62_65": { vi: "Nữ Hoàng Kiếm và Hai Tiền: trí tuệ sắc sảo gặp thế cân bằng linh hoạt — sự rõ ràng tư duy giúp điều phối nhiều yêu cầu một cách hiệu quả, ranh giới rõ ràng của Nữ Hoàng giúp quản lý thế tung hứng vật chất.", en: "Queen of Swords and Two of Pentacles: sharp intellect meeting flexible balance — mental clarity helping coordinate multiple demands efficiently, the Queen's clear boundaries helping manage the juggling of material responsibilities." },
  "62_66": { vi: "Nữ Hoàng Kiếm và Ba Tiền: trí tuệ sắc bén gặp sự hợp tác — Nữ Hoàng định hướng và cố vấn cho nhóm với sự rõ ràng và thẳng thắn, phản hồi trực tiếp của bà nâng cao chất lượng công việc tập thể.", en: "Queen of Swords and Three of Pentacles: sharp intellect meeting collaboration — the Queen directing and advising the group with clarity and directness, her straightforward feedback elevating the quality of collective work." },
  "62_67": { vi: "Nữ Hoàng Kiếm và Bốn Tiền: trí tuệ sắc sảo gặp sự bám víu kiểm soát — Nữ Hoàng thách thức sự ôm chặt bằng câu hỏi trực tiếp, sự rõ ràng tư duy phơi bày nỗi sợ hãi ẩn sau thói quen kiểm soát vật chất.", en: "Queen of Swords and Four of Pentacles: sharp intellect meeting controlling grip — the Queen challenging the clinging with direct questions, mental clarity exposing the fear hidden behind habits of material control." },
  "62_68": { vi: "Nữ Hoàng Kiếm và Năm Tiền: trí tuệ sắc bén gặp thiếu thốn vật chất — sự rõ ràng lạnh lùng nhìn thẳng vào thực tế khó khăn mà không phủ nhận, tư duy sắc bén trong hoàn cảnh thiếu thốn là vũ khí mạnh nhất.", en: "Queen of Swords and Five of Pentacles: sharp intellect meeting material deprivation — cool clarity looking directly at hard reality without denial, sharp thinking in conditions of scarcity as the most powerful weapon." },
  "62_69": { vi: "Nữ Hoàng Kiếm và Sáu Tiền: trí tuệ sắc sảo gặp sự hào phóng — sự rõ ràng về điều kiện trong giao dịch cho nhận, Nữ Hoàng đảm bảo sự hào phóng được thực hiện công bằng không bị lợi dụng.", en: "Queen of Swords and Six of Pentacles: sharp intellect meeting generosity — clarity about conditions in giving and receiving transactions, the Queen ensuring generosity is carried out fairly and not exploited." },
  "62_70": { vi: "Nữ Hoàng Kiếm và Bảy Tiền: trí tuệ sắc sảo gặp sự đánh giá kiên nhẫn — sự đánh giá lạnh lùng khách quan của Nữ Hoàng kết hợp với thời gian kiên nhẫn để đánh giá đúng thành quả, không bị cảm xúc làm mờ phán đoán.", en: "Queen of Swords and Seven of Pentacles: sharp intellect meeting patient assessment — the Queen's cold objective evaluation combined with patient timing to judge results accurately, judgment not clouded by emotion." },
  "62_71": { vi: "Nữ Hoàng Kiếm và Tám Tiền: trí tuệ sắc sảo gặp sự chuyên cần rèn luyện — Nữ Hoàng xác định kỹ năng nào đáng đầu tư thời gian và công sức, sự rõ ràng chiến lược hướng dẫn việc xây dựng năng lực có chủ đích.", en: "Queen of Swords and Eight of Pentacles: sharp intellect meeting diligent practice — the Queen identifying which skills are worth investing time and effort, strategic clarity guiding the intentional building of capability." },
  "62_72": { vi: "Nữ Hoàng Kiếm và Chín Tiền: trí tuệ sắc bén gặp sự sung mãn tự chủ — hai người phụ nữ độc lập mạnh mẽ gặp nhau, không khí tư duy và đất thực tế cùng đứng vững trong quyền lực của mình.", en: "Queen of Swords and Nine of Pentacles: sharp intellect meeting self-sufficient abundance — two strong independent women meeting, air of thought and earth of abundance both standing powerfully in their own authority." },
  "62_73": { vi: "Nữ Hoàng Kiếm và Mười Tiền: trí tuệ sắc bén gặp di sản gia đình — Nữ Hoàng thách thức truyền thống bằng sự rõ ràng, câu hỏi thẳng thắn làm rõ di sản nào xứng đáng được bảo tồn và điều gì cần thay đổi.", en: "Queen of Swords and Ten of Pentacles: sharp intellect meeting family legacy — the Queen challenging tradition with clarity, direct questions clarifying which aspects of legacy deserve preservation and what needs to change." },
  "62_74": { vi: "Nữ Hoàng Kiếm và Trang Bị Tiền: trí tuệ sắc bén gặp sự học hỏi tò mò — Nữ Hoàng là người thầy đòi hỏi cao nhưng rõ ràng, tinh thần học hỏi thực tiễn của Trang Bị Tiền trưởng thành dưới sự hướng dẫn sắc bén.", en: "Queen of Swords and Page of Pentacles: sharp intellect meeting curious learning — the Queen as a demanding but clear teacher, the Page of Pentacles' practical learning spirit maturing under sharp and honest guidance." },
  "62_75": { vi: "Nữ Hoàng Kiếm và Kỵ Sĩ Tiền: trí tuệ sắc bén gặp sự kiên định phương pháp — sự rõ ràng chiến lược của Nữ Hoàng định hướng sự bền bỉ của Kỵ Sĩ, không khí và đất hợp tác tạo nên sự hiệu quả có chiều sâu.", en: "Queen of Swords and Knight of Pentacles: sharp intellect meeting methodical steadiness — the Queen's strategic clarity directing the Knight's persistence, air and earth collaborating to create effective work with depth." },
  "62_76": { vi: "Nữ Hoàng Kiếm và Nữ Hoàng Tiền: hai Nữ Hoàng gặp nhau — trí tuệ sắc bén và sự chăm sóc thực tế, không khí và đất ở đỉnh cao quyền uy của mình, hai cách tiếp cận bổ sung nhau tạo nên sức mạnh hoàn chỉnh.", en: "Queen of Swords and Queen of Pentacles: two queens meeting — sharp intellect and practical nurturing, air and earth at the peak of their authority, two complementary approaches creating complete strength." },
  "62_77": { vi: "Nữ Hoàng Kiếm và Vua Tiền: trí tuệ sắc bén gặp quyền uy vật chất — hai người nắm quyền uy ở lĩnh vực khác nhau gặp nhau bình đẳng, không khí tư duy và đất vật chất cùng đối thoại ở đỉnh cao thẩm quyền.", en: "Queen of Swords and King of Pentacles: sharp intellect meeting material authority — two authority figures meeting as equals in different domains, air of thought and earth of material engaging in dialogue at the peak of their mastery." },
  "63_64": { vi: "Vua Kiếm và Át Tiền: thẩm quyền tư duy gặp cơ hội vật chất mới — trí tuệ có thẩm quyền đánh giá và định hướng hạt giống tiềm năng, quyết định chiến lược khôn ngoan từ điểm xuất phát xác định hướng đi dài hạn.", en: "King of Swords and Ace of Pentacles: intellectual authority meeting new material opportunity — authoritative intellect evaluating and directing the seed of potential, wise strategic decision from the starting point determining long-term direction." },
  "63_65": { vi: "Vua Kiếm và Hai Tiền: thẩm quyền tư duy gặp thế cân bằng linh hoạt — trí tuệ chiến lược điều phối nhiều nguồn lực và yêu cầu cạnh tranh, phán đoán sắc bén định hướng thế cân bằng trong tình huống phức tạp.", en: "King of Swords and Two of Pentacles: intellectual authority meeting flexible balance — strategic intellect coordinating multiple resources and competing demands, sharp judgment directing balance within complex situations." },
  "63_66": { vi: "Vua Kiếm và Ba Tiền: thẩm quyền tư duy gặp sự hợp tác — người lãnh đạo trí tuệ định hướng nhóm với sự rõ ràng chiến lược, phán quyết công bằng và thẳng thắn nâng cao chất lượng công việc tập thể.", en: "King of Swords and Three of Pentacles: intellectual authority meeting collaboration — the intellectual leader directing the group with strategic clarity, fair and direct judgment elevating the quality of collective work." },
  "63_67": { vi: "Vua Kiếm và Bốn Tiền: thẩm quyền tư duy gặp sự kiểm soát vật chất — trí tuệ chiến lược thách thức sự bám víu vô ích, phán quyết sắc bén phân biệt sự an toàn thực sự và sự sợ hãi vô căn cứ ẩn sau thói quen tích trữ.", en: "King of Swords and Four of Pentacles: intellectual authority meeting material control — strategic intellect challenging unproductive clinging, sharp judgment distinguishing genuine security from groundless fear hidden behind hoarding." },
  "63_68": { vi: "Vua Kiếm và Năm Tiền: thẩm quyền tư duy gặp thiếu thốn vật chất — trí tuệ có thẩm quyền phân tích nguyên nhân gốc rễ của sự thiếu thốn, phán đoán chiến lược tìm ra con đường thoát khỏi hoàn cảnh khó khăn.", en: "King of Swords and Five of Pentacles: intellectual authority meeting material deprivation — authoritative intellect analyzing the root causes of scarcity, strategic judgment finding the path out of difficult circumstances." },
  "63_69": { vi: "Vua Kiếm và Sáu Tiền: thẩm quyền tư duy gặp sự hào phóng — tư duy chiến lược đảm bảo nguồn lực được phân phối với sự công bằng và hiệu quả, phán quyết sắc bén định hướng lòng hào phóng đến nơi cần nhất.", en: "King of Swords and Six of Pentacles: intellectual authority meeting generosity — strategic thinking ensuring resources are distributed with fairness and efficiency, sharp judgment directing generosity to where it is most needed." },
  "63_70": { vi: "Vua Kiếm và Bảy Tiền: thẩm quyền tư duy gặp sự đánh giá kiên nhẫn — phán đoán chiến lược kết hợp với thời gian đúng lúc để đánh giá kết quả, trí tuệ và kinh nghiệm cùng đợi đến khi đủ dữ liệu để phán quyết.", en: "King of Swords and Seven of Pentacles: intellectual authority meeting patient assessment — strategic judgment combined with right timing to evaluate results, intellect and experience waiting until sufficient data exists to render a verdict." },
  "63_71": { vi: "Vua Kiếm và Tám Tiền: thẩm quyền tư duy gặp sự chuyên cần rèn luyện — trí tuệ có thẩm quyền xác định con đường thành thạo có chiều sâu, chiến lược rõ ràng hướng dẫn việc xây dựng kỹ năng với ý định và mục đích.", en: "King of Swords and Eight of Pentacles: intellectual authority meeting diligent practice — authoritative intellect defining the path to deep mastery, clear strategy guiding the building of skills with intention and purpose." },
  "63_72": { vi: "Vua Kiếm và Chín Tiền: thẩm quyền tư duy gặp sự sung mãn tự chủ — trí tuệ và sự thịnh vượng cùng đứng ở đỉnh cao thẩm quyền của mình, không khí và đất đều tự lập và tự tin trong lĩnh vực của mình.", en: "King of Swords and Nine of Pentacles: intellectual authority meeting self-sufficient abundance — intellect and prosperity both standing at the peak of their authority, air and earth both independent and confident in their respective domains." },
  "63_73": { vi: "Vua Kiếm và Mười Tiền: thẩm quyền tư duy gặp di sản bền vững — trí tuệ có thẩm quyền bảo vệ và định hướng di sản tập thể, phán đoán sắc bén đảm bảo những gì được truyền đạt là khôn ngoan chứ không chỉ là vật chất.", en: "King of Swords and Ten of Pentacles: intellectual authority meeting enduring legacy — authoritative intellect protecting and directing collective legacy, sharp judgment ensuring what is passed down includes wisdom not just material wealth." },
  "63_74": { vi: "Vua Kiếm và Trang Bị Tiền: thẩm quyền tư duy gặp sự học hỏi tò mò — Vua Kiếm là người thầy nghiêm khắc nhưng công bằng, tinh thần học hỏi thực tiễn của Trang Bị Tiền trưởng thành dưới sự hướng dẫn trí tuệ nghiêm cẩn.", en: "King of Swords and Page of Pentacles: intellectual authority meeting curious learning — the King of Swords as a strict but fair teacher, the Page of Pentacles' practical learning spirit maturing under serious intellectual guidance." },
  "63_75": { vi: "Vua Kiếm và Kỵ Sĩ Tiền: thẩm quyền tư duy gặp sự bền bỉ phương pháp — chiến lược sắc bén của Vua Kiếm định hướng sự kiên định của Kỵ Sĩ, không khí và đất hợp tác tạo nên kế hoạch vừa khôn ngoan vừa khả thi.", en: "King of Swords and Knight of Pentacles: intellectual authority meeting methodical persistence — the King's sharp strategy directing the Knight's steadiness, air and earth collaborating to create plans that are both wise and executable." },
  "63_76": { vi: "Vua Kiếm và Nữ Hoàng Tiền: thẩm quyền tư duy gặp trí tuệ thực tế — hai người nắm quyền uy gặp nhau, trí tuệ sắc bén và sự chăm sóc thực tế bổ trợ nhau, không khí và đất ở đỉnh cao tạo nên sự lãnh đạo cân bằng.", en: "King of Swords and Queen of Pentacles: intellectual authority meeting practical wisdom — two authority figures meeting, sharp intellect and practical care complementing each other, air and earth at their heights creating balanced leadership." },
  "63_77": { vi: "Vua Kiếm và Vua Tiền: hai vị vua gặp nhau — thẩm quyền tư duy và quyền uy vật chất ở đỉnh cao, không khí và đất cùng nắm quyền lực, sự kết hợp của chiến lược khôn ngoan và thực lực vật chất tạo nên quyền uy hoàn chỉnh.", en: "King of Swords and King of Pentacles: two kings meeting — intellectual authority and material authority at their heights, air and earth both holding power, the combination of wise strategy and real-world strength creating complete mastery." },

};
